(globalThis.TURBOPACK||(globalThis.TURBOPACK=[])).push(["object"==typeof document?document.currentScript:void 0,98455,(e,i,r)=>{i.exports=JSON.parse('[{"id":"idoine","mot":"idoine","nature":"adjectif","definitions":["Qui convient parfaitement à un usage, à une situation."],"phonetique":"/i.dwan/","etymologie":"Du latin idoneus, « propre à, capable de ».","registre":"soutenu","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["adéquat","approprié","convenable","pertinent"],"antonymes":["inadapté","inapproprié","impropre"],"exemplesCorrects":["Il a trouvé l\'endroit idoine pour installer son atelier.","Ce n\'est pas le moment idoine pour aborder ce sujet délicat.","Elle attendait la personne idoine pour reprendre l\'affaire familiale."],"exemplesIncorrects":["Cette tarte est vraiment idoine, je vais en reprendre une part.","Il s\'est montré idoine envers ses collègues hier soir."],"distracteurs":["anodin","indolent","indigne","idiomatique"],"anecdote":"Le mot, longtemps confiné au vocabulaire juridique et administratif, a connu un regain d\'usage chez les chroniqueurs des années 2000."},{"id":"saugrenu","mot":"saugrenu","nature":"adjectif","definitions":["Qui est à la fois inattendu, absurde et un peu ridicule."],"phonetique":"/so.ɡʁə.ny/","etymologie":"Composé de « sau- » (sel) et de « grenu », littéralement « assaisonné de gros sel », d\'où « grossier, déplaisant ».","registre":"courant","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["absurde","loufoque","extravagant","biscornu"],"antonymes":["sensé","raisonnable","logique"],"exemplesCorrects":["Il a eu l\'idée saugrenue de partir camper en plein hiver.","Sa proposition saugrenue a déclenché un éclat de rire général.","On l\'a regardé avec surprise tant sa question paraissait saugrenue."],"exemplesIncorrects":["Le repas était délicieux mais un peu saugrenu pour mon goût.","Il a remporté la médaille avec une performance saugrenue."],"distracteurs":["sagace","salutaire","sanguin","sournois"],"anecdote":"Le mot était dès le XVIIᵉ siècle utilisé par Molière, qui adorait les sonorités qui prêtent à rire."},{"id":"melancolie","mot":"mélancolie","nature":"nom féminin","definitions":["Tristesse vague et douce, souvent teintée de rêverie."],"phonetique":"/me.lɑ̃.kɔ.li/","etymologie":"Du grec mélas (noir) et kholê (bile) : la « bile noire », l\'une des quatre humeurs de la médecine antique.","registre":"courant","niveau":1,"themes":["emotions","litteraire"],"synonymes":["spleen","nostalgie","vague à l\'âme","neurasthénie"],"antonymes":["allégresse","gaieté","enthousiasme"],"exemplesCorrects":["Une douce mélancolie l\'envahissait chaque automne, au moment où les feuilles tombaient.","Il regardait les photos anciennes avec une mélancolie souriante.","Cette chanson porte en elle toute la mélancolie d\'une époque révolue."],"exemplesIncorrects":["Il a couru le marathon avec mélancolie et a battu son record.","Sa mélancolie était si éclatante qu\'on l\'entendait rire à l\'autre bout du couloir."],"distracteurs":["amertume","lassitude","morosité"],"anecdote":"Baudelaire faisait de la mélancolie l\'un des moteurs essentiels de la création poétique moderne."},{"id":"crepuscule","mot":"crépuscule","nature":"nom masculin","definitions":["Lumière incertaine qui suit le coucher du soleil ou, plus rarement, qui précède l\'aurore.","Au figuré : déclin, fin d\'une époque, d\'une vie."],"phonetique":"/kʁe.pys.kyl/","etymologie":"Du latin crepusculum, dérivé de creper « obscur ».","registre":"courant","niveau":1,"themes":["nature","litteraire"],"synonymes":["tombée du jour","brune","soir","déclin"],"antonymes":["aurore","aube","matin"],"exemplesCorrects":["Le crépuscule embrasait l\'horizon d\'un rouge profond.","Au crépuscule, les chauves-souris quittèrent leur abri.","Cet écrivain au crépuscule de sa vie publia son œuvre la plus tendre."],"exemplesIncorrects":["Le crépuscule éclatant de midi nous obligea à chercher l\'ombre.","Elle s\'est levée à l\'aube, au crépuscule, pour aller pêcher."],"distracteurs":["pénombre","obscurité","horizon","firmament"],"anecdote":"On parle de « crépuscule civil », « nautique » et « astronomique » pour distinguer trois moments précis selon la position du soleil sous l\'horizon."},{"id":"quiproquo","mot":"quiproquo","nature":"nom masculin","definitions":["Méprise qui consiste à prendre une personne ou une chose pour une autre, souvent à l\'origine de situations comiques."],"phonetique":"/ki.pʁɔ.ko/","etymologie":"Du latin qui pro quo, « qui à la place de quoi ».","registre":"courant","niveau":1,"themes":["quotidien","litteraire"],"synonymes":["malentendu","méprise","confusion","imbroglio"],"antonymes":["entente","accord","compréhension"],"exemplesCorrects":["Toute la pièce repose sur un quiproquo savamment entretenu jusqu\'au dernier acte.","Le quiproquo s\'est dissipé dès qu\'ils ont échangé deux mots.","Un simple quiproquo téléphonique l\'a privé d\'un rendez-vous important."],"exemplesIncorrects":["Ils ont signé le quiproquo devant le notaire ce matin.","Le quiproquo de cette tarte est un secret de famille."],"distracteurs":["stratagème","subterfuge","quolibet","quidam"],"anecdote":"Le quiproquo est un ressort comique central chez Marivaux et Feydeau, qui en ont fait un art à part entière."},{"id":"tergiverser","mot":"tergiverser","nature":"verbe","definitions":["User de détours, de faux-fuyants pour éviter de prendre une décision."],"phonetique":"/tɛʁ.ʒi.vɛʁ.se/","etymologie":"Du latin tergiversari, « tourner le dos », de tergum (dos) et versare (tourner).","registre":"soutenu","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["atermoyer","hésiter","louvoyer","biaiser"],"antonymes":["trancher","décider","agir"],"exemplesCorrects":["Cesse de tergiverser, il faut donner une réponse aujourd\'hui.","Le ministre a tergiversé pendant des semaines avant de se prononcer.","Plutôt que de tergiverser, elle prit le premier billet disponible."],"exemplesIncorrects":["Il a tergiversé son adversaire d\'un seul mot tranchant.","Nous avons tergiversé la salle de la cave au grenier."],"distracteurs":["vaciller","transiger","transgresser","tergir"],"anecdote":"On reproche souvent à la diplomatie de tergiverser, mais c\'est aussi sa manière d\'éviter les conflits prématurés."},{"id":"plethore","mot":"pléthore","nature":"nom féminin","definitions":["Excès, abondance considérée comme nuisible ou superflue."],"phonetique":"/ple.tɔʁ/","etymologie":"Du grec plêthôrê, « plénitude excessive ».","registre":"soutenu","niveau":1,"themes":["abstrait","quotidien"],"synonymes":["surabondance","profusion","foison","excès"],"antonymes":["pénurie","manque","rareté"],"exemplesCorrects":["Une pléthore de candidatures rendit le tri particulièrement délicat.","Il y a pléthore de cafés dans ce quartier, c\'en est presque comique.","On déplorait la pléthore de réformes annoncées sans jamais être appliquées."],"exemplesIncorrects":["La pléthore manquait cruellement après une saison aussi sèche.","Cette pléthore de monnaie ne pèse rien dans ma poche."],"distracteurs":["pénurie","myriade","carence","panoplie"],"anecdote":"À l\'origine terme médical désignant un excès de sang, le mot a glissé vers son sens figuré dès le XIXᵉ siècle."},{"id":"desuet","mot":"désuet","nature":"adjectif","definitions":["Qui n\'est plus en usage, tombé en désuétude ; vieilli, démodé."],"phonetique":"/de.zɥɛ/","etymologie":"Du latin desuetus, « déshabitué », de desuescere « perdre l\'habitude ».","registre":"courant","niveau":1,"themes":["quotidien","litteraire"],"synonymes":["suranné","démodé","obsolète","vieillot"],"antonymes":["moderne","actuel","en vogue"],"exemplesCorrects":["Ce vocabulaire désuet donne du charme aux romans du XIXᵉ siècle.","Les costumes désuets du musée témoignaient d\'une élégance disparue.","Sa manière de saluer paraissait désuète mais charmante."],"exemplesIncorrects":["Ce nouveau modèle est si désuet qu\'il vient d\'arriver sur le marché.","Une connexion désuète permet aux ingénieurs de tester en temps réel."],"distracteurs":["vétuste","caduc","périmé"],"anecdote":"« Désuet » et « vétuste » ne sont pas exactement synonymes : « vétuste » s\'applique surtout à un bâtiment, « désuet » à un usage ou un style."},{"id":"vetuste","mot":"vétuste","nature":"adjectif","definitions":["Qui est en mauvais état parce qu\'ancien et mal entretenu."],"phonetique":"/ve.tyst/","etymologie":"Du latin vetustus, « vieux, ancien ».","registre":"courant","niveau":1,"themes":["quotidien"],"synonymes":["délabré","décrépit","branlant","défraîchi"],"antonymes":["neuf","flambant","moderne","rénové"],"exemplesCorrects":["Ils ont retapé une vétuste ferme normande pour en faire leur maison de campagne.","L\'ascenseur vétuste ne fonctionnait plus depuis longtemps.","On accédait à la bibliothèque par un escalier vétuste qui grinçait à chaque pas."],"exemplesIncorrects":["Cet immeuble vétuste sort tout juste de terre.","Son sourire vétuste illuminait la pièce."],"distracteurs":["lugubre","obsolète","frêle"],"anecdote":"Le droit immobilier français parle de « vétusté » pour désigner l\'usure normale d\'un logement, distincte des dégradations."},{"id":"insipide","mot":"insipide","nature":"adjectif","definitions":["Qui n\'a pas de saveur, sans goût.","Au figuré : sans intérêt, sans relief, ennuyeux."],"phonetique":"/ɛ̃.si.pid/","etymologie":"Du latin insipidus, formé du préfixe in- (privatif) et sapidus (qui a du goût).","registre":"courant","niveau":1,"themes":["quotidien","litteraire"],"synonymes":["fade","terne","morne","plat"],"antonymes":["savoureux","piquant","captivant"],"exemplesCorrects":["Ce potage est insipide, il manque cruellement de sel.","Le roman se traîne dans une intrigue insipide sur des centaines de pages.","Elle trouvait insipide tout discours de circonstance."],"exemplesIncorrects":["Ce plat est tellement insipide que ses arômes dansent sur la langue.","Son humour insipide faisait rire tout le monde aux éclats."],"distracteurs":["anodin","mièvre","intrépide","instable"],"anecdote":"« Sapide » existe encore comme antonyme savant d\'« insipide », mais on ne l\'utilise plus guère qu\'en œnologie."},{"id":"lambiner","mot":"lambiner","nature":"verbe","definitions":["Agir avec une lenteur excessive, traîner."],"phonetique":"/lɑ̃.bi.ne/","etymologie":"Dérivé de « lambin », attesté au XVIIᵉ siècle, peut-être d\'un croisement avec « lambeau ».","registre":"familier","niveau":2,"themes":["quotidien"],"synonymes":["traîner","musarder","lanterner","flâner"],"antonymes":["se hâter","se dépêcher","filer"],"exemplesCorrects":["Ne lambine pas, le train part dans dix minutes.","Il a lambiné toute la matinée au lieu de réviser.","Elle a tendance à lambiner devant les vitrines."],"exemplesIncorrects":["Il a lambiné l\'épreuve en un temps record.","Tu lambineras très fort à ce concours, j\'en suis sûr."],"distracteurs":["tergiverser","vaciller","louvoyer"],"anecdote":"« Lambin » a longtemps servi de surnom moqueur dans les fables et chansons populaires."},{"id":"inopine","mot":"inopiné","nature":"adjectif","definitions":["Qui arrive sans qu\'on s\'y attende, imprévu."],"phonetique":"/i.nɔ.pi.ne/","etymologie":"Du latin inopinatus, « auquel on ne pense pas ».","registre":"soutenu","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["imprévu","fortuit","inattendu","subit"],"antonymes":["prévu","attendu","planifié"],"exemplesCorrects":["Une visite inopinée du contrôleur les prit au dépourvu.","L\'arrivée inopinée de la pluie gâcha le pique-nique.","Il fit une rencontre inopinée à la sortie du cinéma."],"exemplesIncorrects":["Nous avions tout organisé pour rendre cet anniversaire parfaitement inopiné.","Le rendez-vous inopiné figurait depuis trois semaines à son agenda."],"distracteurs":["soudain","incongru","intempestif"],"anecdote":"Dans l\'administration française, un « contrôle inopiné » désigne précisément une inspection annoncée à la dernière minute."},{"id":"bigarre","mot":"bigarré","nature":"adjectif","definitions":["Qui présente des couleurs ou des éléments variés, contrastés.","Au figuré : d\'une grande diversité, hétéroclite."],"phonetique":"/bi.ɡa.ʁe/","etymologie":"Dérivé de l\'ancien français « garre » (bariolé), d\'origine obscure.","registre":"soutenu","niveau":2,"themes":["nature","litteraire"],"synonymes":["bariolé","hétéroclite","panaché","chamarré"],"antonymes":["uniforme","monochrome","uni"],"exemplesCorrects":["La foule bigarrée du carnaval déferlait sur les boulevards.","Un parterre bigarré de fleurs sauvages bordait le chemin.","Sa garde-robe bigarrée trahissait un goût prononcé pour les couleurs vives."],"exemplesIncorrects":["Ses cheveux bigarrés étaient d\'un noir uniforme et profond.","Le brouillard bigarré rendait toute la rue invisible."],"distracteurs":["tacheté","ombragé","bigot","bigle"],"anecdote":"« Bigarré » s\'employait dès le XVIᵉ siècle pour décrire des tissus aux motifs irréguliers, avant de s\'appliquer à des foules ou à des paysages."},{"id":"diaphane","mot":"diaphane","nature":"adjectif","definitions":["Qui laisse passer la lumière sans être tout à fait transparent.","Au figuré : d\'une grande finesse, d\'une pâleur délicate."],"phonetique":"/dja.fan/","etymologie":"Du grec diaphanês, « qui se laisse voir à travers ».","registre":"soutenu","niveau":2,"themes":["nature","litteraire"],"synonymes":["translucide","transparent","vaporeux","ténu"],"antonymes":["opaque","épais","trouble"],"exemplesCorrects":["La porcelaine diaphane laissait deviner la flamme à travers la paroi.","Elle avait un teint diaphane qui semblait éclairé de l\'intérieur.","Le brouillard diaphane voilait à peine les contours de la ville."],"exemplesIncorrects":["Le mur de béton diaphane bloquait toute la lumière.","Le tissu diaphane était si épais qu\'il pesait dans les bras."],"distracteurs":["limpide","cristallin","didactique","diaprée"],"anecdote":"Les médecins de la Renaissance qualifiaient de « diaphanes » les tissus humains assez fins pour être traversés par la lumière, comme la membrane de l\'œil."},{"id":"suranne","mot":"suranné","nature":"adjectif","definitions":["Qui a perdu son actualité, son charme par effet du temps ; vieillot, démodé."],"phonetique":"/sy.ʁa.ne/","etymologie":"De l\'ancien français « sur an », « au-delà d\'un an », d\'où « périmé ».","registre":"soutenu","niveau":2,"themes":["litteraire","quotidien"],"synonymes":["désuet","démodé","vieillot","passé"],"antonymes":["moderne","contemporain","actuel"],"exemplesCorrects":["Ses manières surannées rappelaient les salons d\'autrefois.","Elle écrivait dans un style suranné qui charmait ses lecteurs.","Le mobilier suranné de la pension lui donnait un cachet hors du temps."],"exemplesIncorrects":["Cette innovation surannée vient de révolutionner l\'industrie.","Son enthousiasme suranné débordait dans chacun de ses gestes."],"distracteurs":["vétuste","caduc","obsolète"],"anecdote":"Le mot a particulièrement séduit les écrivains symbolistes, qui en aimaient la sonorité légèrement décalée."},{"id":"imbroglio","mot":"imbroglio","nature":"nom masculin","definitions":["Situation confuse, embrouillée, dont il est difficile de se sortir."],"phonetique":"/ɛ̃.bʁɔ.ljo/","etymologie":"De l\'italien imbroglio, de imbrogliare « emmêler ».","registre":"courant","niveau":2,"themes":["emprunts","quotidien"],"synonymes":["embrouillamini","écheveau","complication"],"antonymes":["clarté","simplicité","limpidité"],"exemplesCorrects":["L\'imbroglio juridique a duré plus de dix ans avant qu\'un accord soit trouvé.","Personne ne comprenait plus rien à cet imbroglio diplomatique.","Il s\'est retrouvé pris dans un imbroglio dont il a eu peine à se dégager."],"exemplesIncorrects":["Tout s\'est déroulé dans un imbroglio parfaitement limpide.","Cet imbroglio se mange chaud, accompagné d\'un bon vin."],"distracteurs":["quiproquo","labyrinthe","stratagème","subterfuge"],"anecdote":"Le mot, emprunté à l\'italien au XVIIᵉ siècle, désignait d\'abord une intrigue de théâtre embrouillée à dessein."},{"id":"mansuetude","mot":"mansuétude","nature":"nom féminin","definitions":["Indulgence, douceur de caractère envers ceux qui ont commis une faute."],"phonetique":"/mɑ̃.sɥe.tyd/","etymologie":"Du latin mansuetudo, « douceur, bienveillance », formé sur manus (main) et suescere (s\'habituer) : « habitué à la main ».","registre":"soutenu","niveau":2,"themes":["emotions","abstrait"],"synonymes":["clémence","indulgence","bienveillance","magnanimité"],"antonymes":["sévérité","rigueur","intransigeance"],"exemplesCorrects":["Le juge fit preuve de mansuétude envers ce jeune coupable.","Elle racontait ses bêtises d\'enfance avec la mansuétude de l\'âge mûr.","On loua sa mansuétude à l\'égard des élèves les plus dissipés."],"exemplesIncorrects":["Sa mansuétude implacable terrorisa l\'assemblée.","Pris d\'une mansuétude colérique, il claqua la porte."],"distracteurs":["longanimité","déférence","mansion","manuscrit"],"anecdote":"L\'étymologie évoque l\'animal sauvage apprivoisé, qui s\'habitue à la main de l\'homme — image latine de la douceur acquise."},{"id":"atermoyer","mot":"atermoyer","nature":"verbe","definitions":["Remettre à plus tard, différer par hésitation ou par calcul."],"phonetique":"/a.tɛʁ.mwa.je/","etymologie":"De l\'ancien français « atermoier », de « terme » au sens de délai.","registre":"soutenu","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["tergiverser","temporiser","différer","louvoyer"],"antonymes":["trancher","agir","se résoudre"],"exemplesCorrects":["Il ne sert à rien d\'atermoyer : la décision doit tomber ce soir.","Le gouvernement a longuement atermoyé avant d\'annoncer la mesure.","Elle atermoya plusieurs semaines avant d\'accepter le poste."],"exemplesIncorrects":["Il a atermoyé son verre d\'une main ferme.","Elle a atermoyé brillamment ce concours difficile."],"distracteurs":["transiger","esquiver","ajourner"],"anecdote":"« Atermoiement » est aujourd\'hui plus courant que le verbe, sans doute parce qu\'il est utile aux journalistes pour qualifier les hésitations politiques."},{"id":"sempiternel","mot":"sempiternel","nature":"adjectif","definitions":["Qui dure toujours, qui se répète sans cesse, souvent avec une nuance de lassitude."],"phonetique":"/sɑ̃.pi.tɛʁ.nɛl/","etymologie":"Du latin sempiternus, contraction de semper (toujours) et aeternus (éternel).","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["perpétuel","éternel","incessant","chronique"],"antonymes":["éphémère","passager","fugace"],"exemplesCorrects":["Il nous infligeait ses sempiternelles plaintes à chaque dîner.","Cette sempiternelle dispute au sujet du chauffage finit par lasser tout le monde.","On retrouvait dans ses discours les sempiternels lieux communs."],"exemplesIncorrects":["Ce sempiternel feu d\'artifice a duré quelques secondes à peine.","Son humeur sempiternelle changeait du tout au tout chaque heure."],"distracteurs":["lancinant","récurrent","permanent"],"anecdote":"Le mot a une coloration légèrement péjorative : on s\'en sert souvent pour railler ce qui se répète à l\'excès."},{"id":"velleite","mot":"velléité","nature":"nom féminin","definitions":["Intention timide ou passagère qui ne se traduit pas en acte."],"phonetique":"/ve.le.i.te/","etymologie":"Du latin scolastique velleitas, dérivé de velle « vouloir ».","registre":"soutenu","niveau":3,"themes":["abstrait","emotions"],"synonymes":["envie passagère","élan","esquisse de volonté","tentation"],"antonymes":["détermination","résolution","volonté"],"exemplesCorrects":["Il a eu quelques velléités de départ, mais il est resté.","Ses velléités de réforme se sont éteintes dès la première difficulté.","Elle reconnaît avoir eu des velléités d\'écrire, sans jamais s\'y mettre vraiment."],"exemplesIncorrects":["Avec une velléité de fer, il dirigea l\'entreprise pendant trente ans.","Sa velléité indomptable lui a permis de remporter le championnat."],"distracteurs":["intention","résolution","impulsion"],"anecdote":"Le terme vient d\'un débat médiéval entre théologiens scolastiques sur les degrés du « vouloir » humain."},{"id":"truculent","mot":"truculent","nature":"adjectif","definitions":["Qui est haut en couleur, d\'une vivacité expressive, parfois jusqu\'à l\'outrance."],"phonetique":"/tʁy.ky.lɑ̃/","etymologie":"Du latin truculentus, « farouche, sauvage », à l\'origine sens beaucoup plus rude.","registre":"soutenu","niveau":3,"themes":["litteraire","quotidien"],"synonymes":["pittoresque","savoureux","haut en couleur","rabelaisien"],"antonymes":["fade","terne","insipide"],"exemplesCorrects":["Ce personnage truculent dominait toutes les pages du roman.","Il racontait ses voyages dans un style truculent qui ravissait l\'assistance.","La truculente boulangère du quartier connaissait tous les ragots."],"exemplesIncorrects":["Cette pièce truculente plongeait la salle dans un silence morne.","Le commentaire truculent du juge fut d\'une neutralité parfaite."],"distracteurs":["verveux","facétieux","truchement","turbulent"],"anecdote":"« Truculent » a glissé du sens latin de « féroce » vers son sens moderne de « savoureux » grâce aux critiques littéraires du XIXᵉ siècle."},{"id":"ineffable","mot":"ineffable","nature":"adjectif","definitions":["Qui ne peut être exprimé par des mots, tant il dépasse les ressources du langage."],"phonetique":"/i.nɛ.fabl/","etymologie":"Du latin ineffabilis, formé sur effari « énoncer », précédé du préfixe privatif in-.","registre":"littéraire","niveau":3,"themes":["litteraire","abstrait","emotions"],"synonymes":["indicible","inexprimable","indéfinissable","sublime"],"antonymes":["exprimable","trivial","banal"],"exemplesCorrects":["Une ineffable tendresse passa dans son regard.","Le silence de la cathédrale dégageait une beauté ineffable.","Il évoquait son bonheur avec une joie ineffable."],"exemplesIncorrects":["Le règlement ineffable tient en quatre articles très clairs.","Cet ineffable horaire de train est affiché à la gare."],"distracteurs":["ineffaçable","innommable","inavouable"],"anecdote":"Dans la tradition mystique chrétienne, « ineffable » désigne la part de Dieu qui échappe à toute parole humaine."},{"id":"tonitruant","mot":"tonitruant","nature":"adjectif","definitions":["Qui résonne avec la force du tonnerre ; très bruyant, retentissant."],"phonetique":"/tɔ.ni.tʁy.ɑ̃/","etymologie":"Du latin tonitruare, « tonner ».","registre":"soutenu","niveau":3,"themes":["nature","litteraire"],"synonymes":["fracassant","retentissant","assourdissant","éclatant"],"antonymes":["étouffé","feutré","discret"],"exemplesCorrects":["Un éclat de rire tonitruant traversa la salle.","Il fit son entrée par une déclaration tonitruante.","La voix tonitruante du conférencier faisait vibrer les vitres."],"exemplesIncorrects":["Le chuchotement tonitruant des amoureux se perdit dans la nuit.","Une pluie tonitruante de pétales blancs tomba doucement."],"distracteurs":["détonnant","vibrant","torrentiel","tournoyant"],"anecdote":"L\'adjectif est très prisé du journalisme politique, qui aime décrire les sorties « tonitruantes » des ténors d\'assemblée."},{"id":"procrastiner","mot":"procrastiner","nature":"verbe","definitions":["Reporter sans cesse au lendemain ce qu\'on pourrait faire le jour même."],"phonetique":"/pʁɔ.kʁas.ti.ne/","etymologie":"Du latin procrastinare, de pro (en avant) et crastinus (du lendemain).","registre":"courant","niveau":3,"themes":["quotidien","abstrait"],"synonymes":["atermoyer","tergiverser","remettre","différer"],"antonymes":["expédier","achever","s\'atteler"],"exemplesCorrects":["J\'ai procrastiné cette tâche pendant deux semaines avant de m\'y mettre.","Lui qui procrastine en temps normal s\'est lancé sans hésiter.","Procrastiner devient un art quand on a vingt onglets ouverts."],"exemplesIncorrects":["Il a procrastiné son adversaire dès le premier set.","Le facteur procrastine le courrier avec une précision admirable."],"distracteurs":["temporiser","esquiver","déserter"],"anecdote":"Le verbe, attesté en français dès le XVIᵉ siècle, n\'a connu un usage massif qu\'avec l\'essor des sciences cognitives au début du XXIᵉ."},{"id":"atrabilaire","mot":"atrabilaire","nature":"adjectif","definitions":["D\'humeur sombre, hargneuse ; mélancolique au point d\'en être irritable."],"phonetique":"/a.tʁa.bi.lɛʁ/","etymologie":"Du latin atra bilis, « bile noire », fluide qui passait pour engendrer mélancolie et colère.","registre":"littéraire","niveau":4,"themes":["emotions","litteraire"],"synonymes":["acariâtre","bilieux","ombrageux","morose"],"antonymes":["enjoué","affable","serein"],"exemplesCorrects":["Ce personnage atrabilaire évoque irrésistiblement le Misanthrope de Molière.","Il accueillait les visiteurs d\'un ton atrabilaire qui les décourageait d\'insister.","Sa vieille tante atrabilaire trouvait à redire à tout."],"exemplesIncorrects":["Cet enfant atrabilaire riait aux éclats à la moindre plaisanterie.","Sa joie atrabilaire envahit toute la maisonnée."],"distracteurs":["lunatique","irascible","arbitraire","atrophié"],"anecdote":"Alceste, le héros du Misanthrope, est l\'archétype même de l\'atrabilaire amoureux."},{"id":"onirique","mot":"onirique","nature":"adjectif","definitions":["Qui appartient au rêve ou qui en a la qualité étrange et flottante."],"phonetique":"/ɔ.ni.ʁik/","etymologie":"Du grec oneiros, « rêve ».","registre":"soutenu","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["féerique","fantasmagorique","imaginaire","irréel"],"antonymes":["réel","concret","tangible"],"exemplesCorrects":["Le film offrait une succession d\'images oniriques d\'une grande beauté.","Elle décrivait ses paysages d\'enfance avec une intensité presque onirique.","Sa peinture, aux couleurs oniriques, semblait flotter hors du temps."],"exemplesIncorrects":["L\'inventaire onirique du magasin tient en deux pages de chiffres exacts.","Le rapport comptable onirique remporta le prix de la rigueur."],"distracteurs":["fantastique","spectral","vaporeux"],"anecdote":"L\'adjectif s\'est répandu dans le sillage de la psychanalyse, qui a fait du rêve un objet d\'étude central."},{"id":"sibyllin","mot":"sibyllin","nature":"adjectif","definitions":["Dont le sens est volontairement obscur, énigmatique."],"phonetique":"/si.bi.lɛ̃/","etymologie":"De « Sibylle », nom des prêtresses antiques qui prédisaient l\'avenir en termes ambigus.","registre":"soutenu","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["énigmatique","obscur","ambigu","hermétique"],"antonymes":["limpide","clair","explicite"],"exemplesCorrects":["Sa réponse sibylline ne fit qu\'épaissir le mystère.","Le ministre s\'est contenté de quelques formules sibyllines.","Elle se plaît à laisser des messages sibyllins sur son répondeur."],"exemplesIncorrects":["Ce mode d\'emploi sibyllin se lit en cinq minutes sans difficulté.","Son sourire sibyllin était d\'une franchise désarmante."],"distracteurs":["abscons","elliptique","serpentin","subliminal"],"anecdote":"La Sibylle de Cumes prophétisait sur des feuilles que le vent dispersait — les fidèles devaient les recomposer."},{"id":"iconoclaste","mot":"iconoclaste","nature":"adjectif","definitions":["Qui s\'attaque aux traditions, aux valeurs ou aux figures établies.","Sens historique : qui détruit les images religieuses."],"phonetique":"/i.kɔ.nɔ.klast/","etymologie":"Du grec eikôn (image) et klastes (briseur).","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["irrévérencieux","contestataire","subversif","novateur"],"antonymes":["conformiste","traditionaliste","orthodoxe"],"exemplesCorrects":["Son essai iconoclaste fit l\'effet d\'une bombe dans le milieu académique.","Il prit plaisir à formuler des opinions iconoclastes sur les classiques.","Cette mise en scène iconoclaste divisa profondément la critique."],"exemplesIncorrects":["Sa fidélité iconoclaste aux traditions familiales était irréprochable.","Elle gardait pieusement la mémoire iconoclaste de ses ancêtres."],"distracteurs":["frondeur","anticonformiste","iconographe","idéaliste"],"anecdote":"L\'iconoclasme byzantin, aux VIIIᵉ et IXᵉ siècles, fit détruire d\'innombrables icônes — un épisode dont le mot porte encore la trace."},{"id":"idiosyncrasie","mot":"idiosyncrasie","nature":"nom féminin","definitions":["Particularité de comportement, de tempérament ou de réaction propre à un individu."],"phonetique":"/i.djo.sɛ̃.kʁa.zi/","etymologie":"Du grec idios (propre, particulier) et sunkrasis (mélange).","registre":"littéraire","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["singularité","particularisme","tempérament","originalité"],"antonymes":["banalité","uniformité"],"exemplesCorrects":["Son idiosyncrasie le rendait reconnaissable entre tous, jusqu\'à sa façon de marcher.","Les idiosyncrasies de chaque écrivain font la richesse d\'une langue.","On apprenait à composer avec les idiosyncrasies de la patronne."],"exemplesIncorrects":["L\'idiosyncrasie commune à tous les humains rend ce trait universel.","Le règlement intérieur impose une idiosyncrasie stricte."],"distracteurs":["particularité","physionomie","identité"],"anecdote":"Le mot servait initialement en médecine pour décrire des réactions inhabituelles à certains aliments ou médicaments."},{"id":"apocryphe","mot":"apocryphe","nature":"adjectif","definitions":["Dont l\'authenticité est douteuse, qui n\'est pas reconnu par une autorité officielle.","Sens premier : textes religieux écartés du canon."],"phonetique":"/a.pɔ.kʁif/","etymologie":"Du grec apokruphos, « caché, secret ».","registre":"soutenu","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["douteux","controuvé","supposé","non authentifié"],"antonymes":["authentique","canonique","avéré"],"exemplesCorrects":["La citation circulait depuis des années, mais elle s\'est révélée apocryphe.","Plusieurs évangiles apocryphes sont aujourd\'hui étudiés par les historiens.","Cette anecdote, sans doute apocryphe, est trop belle pour être vraie."],"exemplesIncorrects":["L\'authenticité apocryphe de ce manuscrit ne fait aucun doute.","Le notaire a établi l\'origine apocryphe et certifiée du document."],"distracteurs":["fallacieux","fictif","spéculatif"],"anecdote":"Les premiers chrétiens distinguaient les écrits « canoniques » (officiels) des « apocryphes », souvent prisés pour leurs récits plus pittoresques."},{"id":"ersatz","mot":"ersatz","nature":"nom masculin","definitions":["Produit de substitution, généralement de moindre qualité que celui qu\'il remplace."],"phonetique":"/ɛʁ.zats/","etymologie":"Mot allemand signifiant « remplacement », popularisé pendant les guerres mondiales par les denrées de substitution.","registre":"courant","niveau":2,"themes":["emprunts","quotidien"],"synonymes":["succédané","substitut","imitation"],"antonymes":["original","véritable"],"exemplesCorrects":["Ce café d\'orge n\'est qu\'un pâle ersatz de l\'expresso italien.","On nous servait pendant la guerre un ersatz de beurre à base de margarine douteuse.","Son ami n\'était qu\'un ersatz de confident, attentif mais distrait."],"exemplesIncorrects":["Ce vin est un ersatz d\'exception, primé au concours général.","Elle a apprécié l\'ersatz authentique du grand chef étoilé."],"distracteurs":["subterfuge","pastiche","simulacre"],"anecdote":"L\'usage du mot s\'est répandu en français autour de 1914-1918, époque où les armées allemandes manquant de matières premières multipliaient les produits de remplacement."},{"id":"spleen","mot":"spleen","nature":"nom masculin","definitions":["Mélancolie profonde, ennui existentiel sans cause précise."],"phonetique":"/splin/","etymologie":"De l\'anglais spleen, « rate », l\'organe considéré jadis comme siège de l\'humeur noire.","registre":"littéraire","niveau":3,"themes":["emprunts","emotions","litteraire"],"synonymes":["mélancolie","nostalgie","neurasthénie","vague à l\'âme"],"antonymes":["allégresse","jubilation"],"exemplesCorrects":["Baudelaire a fait du spleen l\'une des grandes catégories de la sensibilité moderne.","Un spleen tenace l\'habitait dès les premières pluies d\'automne.","Il évoquait son spleen d\'adolescent avec un sourire ému."],"exemplesIncorrects":["Le spleen festif éclatait dans toutes les rues du village.","Elle a remporté la course portée par un spleen contagieux."],"distracteurs":["ennui","morosité","splendeur","spectre"],"anecdote":"Baudelaire intitule « Spleen et Idéal » la première partie des Fleurs du Mal — le spleen y est l\'envers nécessaire de l\'idéal."},{"id":"avatar","mot":"avatar","nature":"nom masculin","definitions":["Transformation, métamorphose d\'une chose ou d\'une personne.","Souvent au pluriel : mésaventure, incident fâcheux."],"phonetique":"/a.va.taʁ/","etymologie":"Du sanskrit avatāra, « descente », désignant à l\'origine l\'incarnation terrestre d\'une divinité hindoue.","registre":"courant","niveau":2,"themes":["emprunts","abstrait"],"synonymes":["incarnation","métamorphose","péripétie","mésaventure"],"antonymes":["stabilité","permanence"],"exemplesCorrects":["Le voyage a connu mille avatars avant d\'arriver à bon port.","Le mythe a traversé les siècles sous de multiples avatars.","Sa carrière n\'a pas été exempte d\'avatars."],"exemplesIncorrects":["Cet avatar inattendu fut d\'une banalité réjouissante.","Le projet s\'est déroulé sans le moindre avatar, à la grande joie de l\'avatar."],"distracteurs":["metempsycose","vicissitude","déboire"],"anecdote":"Le sens informatique de « représentation virtuelle » est arrivé bien plus tard, dans les années 1980, en gardant l\'idée d\'une incarnation."},{"id":"kitsch","mot":"kitsch","nature":"adjectif","definitions":["De mauvais goût, mais assumé ou cultivé pour son charme désuet ou son outrance."],"phonetique":"/kitʃ/","etymologie":"De l\'allemand kitsch, peut-être de kitschen « bâcler ».","registre":"courant","niveau":2,"themes":["emprunts","quotidien"],"synonymes":["clinquant","ringard","tape-à-l\'œil"],"antonymes":["sobre","raffiné","épuré"],"exemplesCorrects":["Son salon est délicieusement kitsch, plein de chinoiseries et de napperons brodés.","Le film assume son esthétique kitsch jusqu\'au générique de fin.","Elle collectionne les objets kitsch des années soixante-dix."],"exemplesIncorrects":["Ce manifeste kitsch d\'une sobriété rare a marqué l\'histoire de l\'art.","Le minimaliste kitsch épure tout dans son intérieur."],"distracteurs":["outré","rétro","kaki","kitchenette"],"anecdote":"Le mot a d\'abord servi à dénoncer l\'art bourgeois du XIXᵉ siècle avant d\'être revendiqué, dès les années soixante, comme un genre à part entière."},{"id":"patio","mot":"patio","nature":"nom masculin","definitions":["Cour intérieure, généralement pavée et ornée, propre à l\'architecture méditerranéenne."],"phonetique":"/pa.tjo/","etymologie":"Mot espagnol, lui-même issu du provençal patu, désignant un terrain non bâti.","registre":"courant","niveau":1,"themes":["emprunts","quotidien"],"synonymes":["cour","atrium","courette"],"antonymes":[],"exemplesCorrects":["Nous dînions chaque soir sur le patio, à l\'ombre du citronnier.","Le patio andalou bruissait d\'une fontaine discrète.","Le riad ouvrait sur un patio rafraîchissant."],"exemplesIncorrects":["Le patio s\'élevait sur trois étages au cœur de l\'immeuble.","Le patio enneigé du sommet alpin offrait une vue spectaculaire."],"distracteurs":["véranda","péristyle","palio","portique"],"anecdote":"Hérité des maisons romaines et arabes, le patio joue un rôle climatique : il aère et tempère l\'intérieur."},{"id":"gosse","mot":"gosse","nature":"nom","definitions":["Enfant, en français de France ; mais en français québécois, désigne un testicule (à n\'employer qu\'avec précaution)."],"phonetique":"/ɡɔs/","etymologie":"Origine incertaine ; attesté dès le XIXᵉ siècle dans l\'argot parisien.","registre":"familier","niveau":1,"themes":["regionalismes","quotidien"],"synonymes":["enfant","môme","gamin"],"antonymes":["adulte"],"exemplesCorrects":["À Paris, les gosses jouaient autrefois dans la rue, sans téléphone ni surveillance.","Il a élevé seul ses deux gosses après le départ de leur mère.","« Allez les gosses, à table ! » lança-t-elle joyeusement."],"exemplesIncorrects":["Cette gosse était la doyenne du village, à quatre-vingt-douze ans.","Le directeur a réuni les gosses de l\'entreprise pour le bilan annuel."],"distracteurs":["marmot","loupiot","goss","gosier"],"anecdote":"Le faux ami entre français de France et québécois est célèbre : un Québécois qui entend « j\'ai mal aux gosses » comprend tout autre chose qu\'un Français."},{"id":"crognon","mot":"crognon","nature":"nom masculin","definitions":["Croûton de pain, plus particulièrement l\'extrémité dorée et croquante d\'une baguette."],"phonetique":"/kʁɔ.ɲɔ̃/","etymologie":"Diminutif issu de l\'ancien français cron, « crochu, dur », désignant la partie ferme du pain.","registre":"familier","niveau":1,"themes":["regionalismes","quotidien"],"synonymes":["croûton","quignon","talon"],"antonymes":["mie"],"exemplesCorrects":["Elle mordit dans le crognon encore chaud sorti du four.","Mon grand-père réservait toujours le crognon pour son chien.","Donne-moi le crognon, c\'est ma part préférée."],"exemplesIncorrects":["Le crognon mousseux du dessert ravissait les enfants.","Ce crognon de pâte fraîche se boit en apéritif."],"distracteurs":["entame","crogneux","grognon","carcasse"],"anecdote":"Le mot est répandu dans l\'Ouest de la France, en concurrence avec « quignon » qui domine ailleurs — joli exemple de variation régionale française."},{"id":"chenu","mot":"chenu","nature":"adjectif","definitions":["Blanchi par l\'âge ; au sens figuré, vénérable.","Régionalement (Bourgogne, Suisse romande) : excellent, bien réussi."],"phonetique":"/ʃə.ny/","etymologie":"Du latin canutus, « blanc de cheveux ».","registre":"littéraire","niveau":3,"themes":["regionalismes","litteraire"],"synonymes":["chevronné","vénérable","blanchi"],"antonymes":["juvénile","novice"],"exemplesCorrects":["Le vieux chêne chenu se dressait au milieu de la cour de l\'école.","Il avait l\'air chenu et solennel des magistrats d\'autrefois.","En Bourgogne, on dit volontiers d\'un repas réussi qu\'il fut « bien chenu »."],"exemplesIncorrects":["Le poulain chenu galopait à travers le pré au lever du soleil.","Cette plante chenue vient tout juste de germer la semaine dernière."],"distracteurs":["argenté","barbon","chenil","chétif"],"anecdote":"Brillat-Savarin, gourmet bourguignon, employait « chenu » pour louer un fromage particulièrement réussi — un sens régional encore vivace."},{"id":"ataraxie","mot":"ataraxie","nature":"nom féminin","definitions":["Tranquillité profonde de l\'âme, exempte de trouble et de désir, idéal philosophique antique."],"phonetique":"/a.ta.ʁak.si/","etymologie":"Du grec ataraxia, « absence de trouble », central chez les stoïciens et les épicuriens.","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire","emotions"],"synonymes":["impassibilité","sérénité","imperturbabilité","quiétude"],"antonymes":["agitation","trouble","passion"],"exemplesCorrects":["Il cultivait une forme d\'ataraxie qui agaçait ses interlocuteurs les plus pressés.","L\'ataraxie épicurienne vise le plaisir stable, non l\'excitation.","Atteindre l\'ataraxie, c\'est moins ne rien sentir que ne plus être ballotté."],"exemplesIncorrects":["Dans une fureur d\'ataraxie, il claqua la porte de la salle de conseil.","Son ataraxie débordante envoya tous les invités sur la piste de danse."],"distracteurs":["apathie","agoraphobie","anorexie"],"anecdote":"Pour les stoïciens, l\'ataraxie s\'obtient en distinguant ce qui dépend de nous (nos jugements) de ce qui ne dépend pas (le monde)."},{"id":"bucolique","mot":"bucolique","nature":"adjectif","definitions":["Qui évoque la campagne paisible et idéalisée, propre aux poèmes pastoraux."],"phonetique":"/by.kɔ.lik/","etymologie":"Du grec boukolikos, « relatif au pâtre », par les Bucoliques de Virgile.","registre":"soutenu","niveau":3,"themes":["nature","litteraire"],"synonymes":["pastoral","champêtre","agreste","idyllique"],"antonymes":["urbain","industriel"],"exemplesCorrects":["Ils s\'étaient retirés dans une maison bucolique au cœur du Lubéron.","Le tableau, d\'une douceur bucolique, montrait un troupeau au crépuscule.","La scène avait quelque chose de bucolique, malgré la pluie fine."],"exemplesIncorrects":["Le périphérique parisien offrait un cadre bucolique au coureur.","L\'usine d\'aciérie, dans son ronronnement bucolique, charmait les passants."],"distracteurs":["rustique","botanique","boréal"],"anecdote":"Virgile écrit ses Bucoliques en imitant le grec Théocrite, lançant un genre poétique qui traversera deux mille ans."},{"id":"ineluctable","mot":"inéluctable","nature":"adjectif","definitions":["Qu\'on ne peut éviter, contre quoi on ne peut lutter."],"phonetique":"/i.ne.lyk.tabl/","etymologie":"Du latin ineluctabilis, de luctari « lutter », précédé de in- privatif.","registre":"soutenu","niveau":3,"themes":["abstrait"],"synonymes":["inévitable","fatal","implacable","irréversible"],"antonymes":["évitable","contournable"],"exemplesCorrects":["La fin de l\'été est inéluctable, comme chaque année.","Il accepta avec calme cette décision inéluctable.","Le déclin de l\'empire paraissait inéluctable aux contemporains."],"exemplesIncorrects":["Ce résultat inéluctable peut être facilement modifié au dernier moment.","Cette tartelette inéluctable a un goût de framboise délicieux."],"distracteurs":["irrévocable","imminent","inéducable","ineffable"],"anecdote":"Cicéron emploie déjà le mot pour décrire les destins que la philosophie stoïcienne enseigne à accepter."},{"id":"pernicieux","mot":"pernicieux","nature":"adjectif","definitions":["Dangereux, nuisible, particulièrement parce que son effet est sourd ou progressif."],"phonetique":"/pɛʁ.ni.sjø/","etymologie":"Du latin perniciosus, de pernicies « ruine, destruction ».","registre":"soutenu","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["nocif","néfaste","délétère","funeste"],"antonymes":["bienfaisant","salutaire","bénéfique"],"exemplesCorrects":["L\'influence pernicieuse des réseaux sociaux fait débat chez les pédiatres.","Il dénonça l\'habitude pernicieuse de répéter sans vérifier.","Une rumeur pernicieuse circulait dans tout le service."],"exemplesIncorrects":["Sa générosité pernicieuse aidait tout le monde.","Cette tisane pernicieuse soulage agréablement les nerfs."],"distracteurs":["perfide","vicieux","pernottant","permissif"],"anecdote":"« Pernicieux » est resté un classique du vocabulaire médical jusqu\'au XIXᵉ siècle, désignant des maladies à évolution insidieuse."},{"id":"halcyon","mot":"alcyonien","nature":"adjectif","definitions":["Qui évoque les jours paisibles, sereins et heureux, à la manière des légendaires jours d\'accalmie liés à l\'alcyon."],"phonetique":"/al.sjɔ.njɛ̃/","etymologie":"Du grec halkuốn, via le latin alcyo, « alcyon », oiseau mythique (martin-pêcheur) auquel les Grecs attribuaient le pouvoir d\'apaiser la mer pendant la couvaison.","registre":"littéraire","niveau":5,"themes":["emprunts","litteraire"],"synonymes":["serein","paisible","tranquille"],"antonymes":["tumultueux","agité"],"exemplesCorrects":["Il évoquait avec tendresse les jours alcyoniens de leur jeunesse.","Un calme alcyonien régnait sur la baie au lever du jour.","Les poètes du Grand Siècle aimaient cette image alcyonienne."],"exemplesIncorrects":["Le vent alcyonien arrachait les toits du village.","Une dispute alcyonienne explosa au milieu du dîner."],"distracteurs":["lénifiant","olympien","élégiaque","vespéral"],"anecdote":"Selon Ovide, Alcyon fut métamorphosée en oiseau ; Éole, son père, calmait la mer pendant qu\'elle couvait, d\'où l\'expression « jours alcyoniens »."},{"id":"saudade","mot":"saudade","nature":"nom féminin","definitions":["Mélancolie douce-amère, mêlée de nostalgie et de désir, propre à la culture portugaise.","Mot souvent considéré comme intraduisible : il évoque la présence d\'une absence."],"phonetique":"/saw.dad/","etymologie":"Du portugais saudade, peut-être issu du latin solitas « solitude ».","registre":"littéraire","niveau":4,"themes":["emprunts","emotions"],"synonymes":["mélancolie","nostalgie","spleen"],"antonymes":["allégresse","entrain"],"exemplesCorrects":["Une saudade tenace lui revenait chaque fois qu\'il entendait du fado.","Il y a dans Lisbonne une saudade urbaine, faite de pierres et de pluie.","Elle peignait sa saudade dans des paysages bleus et lents."],"exemplesIncorrects":["La saudade festive du carnaval éclatait dans toutes les rues.","Une saudade énergique le poussa à courir le marathon."],"distracteurs":["désenchantement","blues","sarcasme","savoir-vivre"],"anecdote":"Le poète Fernando Pessoa fait de la saudade un sentiment proprement portugais, mêlant le manque de ce qui n\'a peut-être jamais existé."},{"id":"lugubre","mot":"lugubre","nature":"adjectif","definitions":["Funeste, sinistre ; qui évoque la mort ou un profond chagrin."],"phonetique":"/ly.ɡybʁ/","etymologie":"Du latin lugubris, de lugere « être en deuil ».","registre":"soutenu","niveau":2,"themes":["emotions","litteraire"],"synonymes":["sinistre","funèbre","macabre","sombre"],"antonymes":["joyeux","gai","lumineux"],"exemplesCorrects":["La maison vide rendait un son lugubre quand la porte grinçait.","Il prit une voix lugubre pour raconter sa mésaventure.","Le couloir lugubre du vieil hôpital donnait des frissons."],"exemplesIncorrects":["Un sourire lugubre éclairait toute la pièce.","Sa robe lugubre couleur soleil attira tous les regards."],"distracteurs":["sépulcral","morne","luxueux","lugustre"],"anecdote":"Au XVIIᵉ, on jouait des « pièces lugubres » lors des veillées funéraires, sortes de poèmes en prose pour accompagner le deuil."},{"id":"etiquette","mot":"étiquette","nature":"nom féminin","definitions":["Ensemble des règles de comportement, surtout en société élégante ou diplomatique.","Petit papier collé sur un objet pour indiquer son nom, son prix, sa nature."],"phonetique":"/e.ti.kɛt/","etymologie":"De l\'ancien français estiquette « petit poteau, écriteau », dérivé du verbe estiquier « ficher ».","registre":"courant","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["protocole","convenances","cérémonial","label"],"antonymes":["désinvolture","familiarité"],"exemplesCorrects":["L\'étiquette de la cour de Versailles fixait des règles d\'une minutie déconcertante.","Elle observait les règles d\'étiquette avec un soin amusé.","Vérifie l\'étiquette avant d\'acheter : elle indique parfois la provenance."],"exemplesIncorrects":["Sans aucune étiquette ni règle, ce dîner d\'ambassadeurs fut parfait.","L\'étiquette du château vola dans le vent jusqu\'à la prochaine bourgade."],"distracteurs":["bienséance","étiologie","étincelle"],"anecdote":"On dit que la cour de Louis XIV adopta ces règles strictes parce que des panonceaux (étiquettes) indiquaient aux courtisans où ne pas marcher dans les jardins."},{"id":"obsequieux","mot":"obséquieux","nature":"adjectif","definitions":["Trop empressé à plaire, d\'une politesse exagérée et insincère."],"phonetique":"/ɔp.se.kjø/","etymologie":"Du latin obsequiosus, dérivé de obsequi « suivre, complaire à ».","registre":"soutenu","niveau":3,"themes":["emotions","litteraire"],"synonymes":["servile","flagorneur","complaisant","courtisan"],"antonymes":["fier","indépendant","franc"],"exemplesCorrects":["Il accueillait son patron d\'un sourire obséquieux qui agaçait tout le bureau.","Le ton obséquieux du majordome cachait mal son mépris.","Cette correspondance obséquieuse trahissait la peur du courtisan."],"exemplesIncorrects":["Sa franchise obséquieuse lui valait l\'admiration de tous.","Cet enfant obséquieux refusait toujours d\'obéir aux adultes."],"distracteurs":["doucereux","mielleux","objectif","obstiné"],"anecdote":"Molière met en scène l\'obséquiosité dans Le Tartuffe, qui devient le portrait-type du flatteur intéressé."},{"id":"exquis","mot":"exquis","nature":"adjectif","definitions":["D\'une délicatesse rare ; charmant, raffiné.","En art ou en cuisine : d\'une qualité supérieure, particulièrement choisie."],"phonetique":"/ɛks.ki/","etymologie":"Du latin exquisitus, « recherché », participe de exquirere « chercher avec soin ».","registre":"courant","niveau":1,"themes":["quotidien","emotions"],"synonymes":["délicieux","raffiné","délicat","charmant"],"antonymes":["grossier","vulgaire","fade"],"exemplesCorrects":["Le dîner fut exquis du début à la fin, et la conversation à l\'avenant.","Cette aquarelle exquise tient sur la paume d\'une main.","Elle a un goût exquis pour les vieux livres reliés."],"exemplesIncorrects":["Ce vacarme exquis sortait des hauts-parleurs à plein volume.","Une grossièreté exquise sortit de sa bouche."],"distracteurs":["succulent","exigeant","exquisite"],"anecdote":"Le « cadavre exquis » est un jeu surréaliste où chacun ajoute un mot à un poème sans voir ce qui précède — André Breton en raffolait."},{"id":"incurie","mot":"incurie","nature":"nom féminin","definitions":["Négligence grave dans la conduite d\'une affaire ; absence de soin."],"phonetique":"/ɛ̃.ky.ʁi/","etymologie":"Du latin incuria, « manque de soin ».","registre":"soutenu","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["négligence","laxisme","désinvolture","carence"],"antonymes":["soin","diligence","rigueur"],"exemplesCorrects":["Le rapport pointe une incurie chronique dans la gestion du dossier.","L\'incurie des services finit par lasser les usagers.","Tout ici trahissait l\'incurie : poussière, paperasses, ordinateurs en panne."],"exemplesIncorrects":["Son incurie maniaque l\'obligeait à tout vérifier trois fois.","Une incurie impeccable régnait dans ce bureau parfaitement tenu."],"distracteurs":["imprévoyance","incursion","incurable"],"anecdote":"Le terme est très utilisé en droit administratif pour caractériser les fautes lourdes mais sans intention de nuire."},{"id":"amphigourique","mot":"amphigourique","nature":"adjectif","definitions":["Obscur, embrouillé, qui n\'a ni queue ni tête, en parlant d\'un discours ou d\'un écrit."],"phonetique":"/ɑ̃.fi.ɡu.ʁik/","etymologie":"De « amphigouri », mot du XVIIIᵉ siècle d\'origine incertaine, peut-être de amphi- (autour) et goury (vraisemblablement formé par l\'usage).","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["abscons","obscur","embrouillé","alambiqué"],"antonymes":["clair","limpide","intelligible"],"exemplesCorrects":["Sa thèse amphigourique perdit ses lecteurs dès la troisième page.","Le discours amphigourique du ministre fit sourire la salle.","Cette lettre amphigourique sentait l\'ironie."],"exemplesIncorrects":["Une formulation amphigourique tient sur trois mots clairs.","Ce texte amphigourique se lit avec une facilité enfantine."],"distracteurs":["filandreux","sibyllin","amphibologique","amphigastrique"],"anecdote":"Voltaire raillait les sermons « amphigouriques » de certains prédicateurs, leur préférant un style sec et précis."},{"id":"lapidaire","mot":"lapidaire","nature":"adjectif","definitions":["Bref, frappant, qui dit beaucoup en peu de mots — comme une inscription sur une pierre.","Relatif aux pierres précieuses ou aux tailleurs de pierre."],"phonetique":"/la.pi.dɛʁ/","etymologie":"Du latin lapidarius, de lapis « pierre ».","registre":"soutenu","niveau":3,"themes":["litteraire","abstrait"],"synonymes":["concis","laconique","incisif","sentencieux"],"antonymes":["verbeux","diffus","prolixe"],"exemplesCorrects":["Sa réponse lapidaire mit fin à la conversation.","Il aimait les formules lapidaires, héritées des stoïciens.","Une critique lapidaire valait mieux qu\'un long argumentaire."],"exemplesIncorrects":["Il développa son raisonnement lapidaire pendant trois heures sans pause.","Cette tarte lapidaire est servie en dessert au restaurant."],"distracteurs":["lapilli","lapereau","lapinière"],"anecdote":"Le « style lapidaire » est celui des épitaphes : forcément bref, parce qu\'on n\'écrit que ce qu\'il faut sur une pierre tombale."},{"id":"soporifique","mot":"soporifique","nature":"adjectif","definitions":["Qui endort, qui provoque le sommeil.","Au figuré : très ennuyeux, qui plonge dans la somnolence."],"phonetique":"/sɔ.pɔ.ʁi.fik/","etymologie":"Du latin sopor « sommeil profond » et -ifique « qui produit ».","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["assoupissant","ennuyeux","anesthésiant","endormant"],"antonymes":["stimulant","captivant","tonique"],"exemplesCorrects":["Cette conférence soporifique a eu raison du quart de la salle.","Sa voix soporifique aurait endormi tout un théâtre.","Le médecin lui prescrivit une tisane légèrement soporifique."],"exemplesIncorrects":["Cet expresso soporifique m\'a tenu éveillé jusqu\'à l\'aube.","Son rire soporifique tonifiait toute l\'assemblée."],"distracteurs":["lassant","soliloque","somatique"],"anecdote":"Le suffixe -fique est très productif : pacifique (qui fait la paix), terrifique (qui terrifie), soporifique (qui endort)."},{"id":"chimerique","mot":"chimérique","nature":"adjectif","definitions":["Qui relève de la chimère ; imaginaire, irréalisable.","Qui se nourrit d\'illusions."],"phonetique":"/ʃi.me.ʁik/","etymologie":"De chimère, monstre fabuleux à tête de lion, corps de chèvre et queue de serpent, du grec khimaira.","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["illusoire","utopique","imaginaire","fantasque"],"antonymes":["réaliste","concret","tangible"],"exemplesCorrects":["Ce projet chimérique enchantait ses partisans et désespérait ses banquiers.","Elle nourrissait des espoirs chimériques pour son neveu.","Le rêve chimérique d\'une langue universelle a traversé les siècles."],"exemplesIncorrects":["Sa stratégie chimérique se réalisa en trois mois.","Cette pièce, parfaitement réaliste et chimérique, plut à la critique."],"distracteurs":["chimiotherapie","chichiteux","chinois"],"anecdote":"La Chimère figure parmi les créatures les plus étranges de la mythologie : tuée par Bellérophon, montée sur le cheval ailé Pégase."},{"id":"ataraxie2","mot":"stoïcisme","nature":"nom masculin","definitions":["Doctrine philosophique antique qui place la sagesse dans la maîtrise des passions et l\'acceptation des choses.","Plus largement, attitude faite de fermeté et d\'impassibilité face à l\'adversité."],"phonetique":"/stɔ.is.ism/","etymologie":"De stoïque, du grec stoa « portique », car Zénon de Cition enseignait sous le portique peint d\'Athènes.","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["impassibilité","endurance","force d\'âme","ataraxie"],"antonymes":["impatience","abattement"],"exemplesCorrects":["Il accepta la nouvelle avec un stoïcisme qui força le respect.","Le stoïcisme antique a profondément marqué la pensée occidentale.","Marc Aurèle a laissé un manuel de stoïcisme tenu à l\'usage personnel."],"exemplesIncorrects":["Son stoïcisme nerveux trahissait sa peur du moindre changement.","Le stoïcisme excité de la foule était impossible à canaliser."],"distracteurs":["résignation","asthénie","athéisme"],"anecdote":"Sénèque, Épictète et Marc Aurèle sont les trois figures romaines majeures du stoïcisme — un esclave, un philosophe et un empereur."},{"id":"guerilla","mot":"guérilla","nature":"nom féminin","definitions":["Forme de guerre menée par petits groupes contre une armée régulière, fondée sur la surprise et le harcèlement.","Lutte longue et inégale ; tout combat de ce type."],"phonetique":"/ɡe.ʁi.ja/","etymologie":"De l\'espagnol guerrilla « petite guerre », diminutif de guerra.","registre":"courant","niveau":2,"themes":["emprunts","abstrait"],"synonymes":["maquis","résistance","harcèlement"],"antonymes":["guerre rangée","armistice"],"exemplesCorrects":["La guérilla menée par les paysans tint l\'armée régulière en échec pendant des années.","Le procès s\'est transformé en guérilla juridique permanente.","Ils pratiquaient une guérilla communicationnelle redoutable."],"exemplesIncorrects":["Cette paix universelle de guérilla règne partout depuis dix ans.","Sa guérilla de gentillesse charmait tous ses voisins."],"distracteurs":["embuscade","rébellion","guerrière","guérite"],"anecdote":"Le mot apparaît en français pendant la guerre d\'indépendance espagnole (1808-1814), où les civils harassent les armées napoléoniennes."},{"id":"manie","mot":"manie","nature":"nom féminin","definitions":["Goût excessif ou habitude bizarre, propre à un individu.","En médecine : trouble caractérisé par une exaltation pathologique."],"phonetique":"/ma.ni/","etymologie":"Du grec mania « folie, frénésie ».","registre":"courant","niveau":1,"themes":["emotions","quotidien"],"synonymes":["tic","habitude","obsession","marotte"],"antonymes":["spontanéité","naturel"],"exemplesCorrects":["Il a la manie d\'aligner ses crayons par couleur avant d\'écrire.","Cette manie de tout vérifier le rendait fatigant à vivre.","Chacun a ses petites manies, après tout."],"exemplesIncorrects":["Sa rare manie de spontanéité bouleversait tous ses plans.","Cette manie collective d\'oublier ne dérange personne."],"distracteurs":["lubie","malice","manche"],"anecdote":"Le mot a longtemps désigné en français une véritable maladie mentale, avant d\'adoucir progressivement son sens jusqu\'à devenir un quasi-synonyme de « tic ». "},{"id":"incipit","mot":"incipit","nature":"nom masculin","definitions":["Premiers mots d\'un texte, d\'une œuvre littéraire ou d\'un morceau musical."],"phonetique":"/ɛ̃.si.pit/","etymologie":"Mot latin, « il commence », première personne du présent de incipere.","registre":"soutenu","niveau":4,"themes":["litteraire"],"synonymes":["ouverture","début","préambule"],"antonymes":["explicit","chute","épilogue"],"exemplesCorrects":["« Longtemps, je me suis couché de bonne heure » est sans doute l\'incipit le plus célèbre du XXᵉ siècle.","Un incipit réussi attire l\'œil et tient le lecteur.","Elle relisait sans cesse l\'incipit de Madame Bovary."],"exemplesIncorrects":["Cet incipit final du roman m\'a profondément ému.","L\'incipit musical, à la dernière mesure, fit pleurer la salle."],"distracteurs":["exorde","préface","incident","incise"],"anecdote":"Les manuscrits médiévaux indiquaient souvent en marge l\'incipit pour identifier l\'œuvre — d\'où le mot, repris tel quel du latin."},{"id":"revasser","mot":"rêvasser","nature":"verbe","definitions":["Se laisser aller à des rêveries vagues, sans suite ni objet précis."],"phonetique":"/ʁɛ.va.se/","etymologie":"Dérivé péjoratif de rêver, avec le suffixe -asser qui marque la répétition ou le caractère un peu vain.","registre":"courant","niveau":1,"themes":["quotidien","emotions"],"synonymes":["songer","rêvailler","musarder","lambiner"],"antonymes":["se concentrer","s\'atteler"],"exemplesCorrects":["Elle aime rêvasser à la fenêtre en regardant tomber la pluie.","Au lieu de travailler, il rêvassait à ses prochaines vacances.","Une heure passée à rêvasser n\'est pas une heure perdue."],"exemplesIncorrects":["Il rêvassa rigoureusement le rapport en deux heures.","Son aptitude à rêvasser intensément l\'a propulsé champion d\'échecs."],"distracteurs":["vaguer","ressasser","renifler","remâcher"],"anecdote":"« Rêvasser » a une connotation tendre, presque enfantine : on n\'imagine pas un dirigeant « rêvasser » en plein conseil."},{"id":"logorrhee","mot":"logorrhée","nature":"nom féminin","definitions":["Flot intarissable de paroles, qui dépasse les besoins de la communication."],"phonetique":"/lɔ.ɡɔ.ʁe/","etymologie":"Du grec logos « parole » et rhein « couler » : « flot de paroles ».","registre":"soutenu","niveau":4,"themes":["litteraire","emotions"],"synonymes":["verbiage","bavardage","flux","diarrhée verbale"],"antonymes":["concision","laconisme","silence"],"exemplesCorrects":["Sa logorrhée éclatait dès qu\'on prononçait le mot « politique ».","Cette logorrhée enthousiaste lassait tout l\'auditoire.","L\'écrivain souffrait d\'une logorrhée littéraire que ses éditeurs peinaient à freiner."],"exemplesIncorrects":["Sa logorrhée silencieuse résumait sa réticence à parler.","Sa concision avait quelque chose d\'une logorrhée bien mesurée."],"distracteurs":["verbosité","loquacité","logique","lobotomie"],"anecdote":"Le mot est venu du vocabulaire médical (incontinence verbale dans certains troubles psychiatriques) avant de glisser vers l\'usage courant."},{"id":"estran","mot":"estran","nature":"nom masculin","definitions":["Partie du littoral alternativement couverte et découverte par la marée."],"phonetique":"/ɛs.tʁɑ̃/","etymologie":"Du vieux norrois strönd, « rivage », transmis par le normand.","registre":"soutenu","niveau":4,"themes":["nature"],"synonymes":["grève","batture","laisse de mer"],"antonymes":["large","haute mer"],"exemplesCorrects":["À marée basse, les pêcheurs à pied arpentent l\'estran à la recherche de coques.","L\'estran rocheux abrite une faune que la mer recouvre deux fois par jour.","Nous avons marché sur l\'estran luisant jusqu\'aux premières vagues."],"exemplesIncorrects":["Il a garé sa voiture sur l\'estran du parking municipal.","L\'estran de la montagne offrait une vue imprenable sur la vallée."],"distracteurs":["écueil","estuaire","étiage","estompe"],"anecdote":"L\'estran est un milieu si particulier que les biologistes le découpent en étages selon la durée d\'immersion."},{"id":"frondaison","mot":"frondaison","nature":"nom féminin","definitions":["Feuillage des arbres.","Époque où les arbres se couvrent de feuilles."],"phonetique":"/fʁɔ̃.dɛ.zɔ̃/","etymologie":"Dérivé de l\'ancien français fronde, du latin frons, frondis, « feuillage ».","registre":"littéraire","niveau":3,"themes":["nature","litteraire"],"synonymes":["feuillage","ramure","verdure"],"antonymes":["défeuillaison","nudité"],"exemplesCorrects":["La lumière du soir filtrait à travers la frondaison du grand chêne.","Dès la frondaison, le parc retrouve sa fraîcheur et son ombre.","Les oiseaux se cachaient dans l\'épaisse frondaison des tilleuls."],"exemplesIncorrects":["Il a rangé la frondaison dans le tiroir de son bureau.","La frondaison de l\'orchestre a duré tout le concert."],"distracteurs":["floraison","fenaison","frondeur","fondation"],"anecdote":"Le mot vient du latin frons, frondis (feuillage) et n\'a aucun lien étymologique avec la fronde, instrument de jet. Hugo et Chateaubriand en ont popularisé l\'usage poétique, où il coexiste avec son cousin feuillaison."},{"id":"ramure","mot":"ramure","nature":"nom féminin","definitions":["Ensemble des branches d\'un arbre.","Bois ramifié du cerf et du daim."],"phonetique":"/ʁa.myʁ/","etymologie":"Dérivé de rame, ancienne forme de rameau, du latin ramus, « branche ».","registre":"soutenu","niveau":3,"themes":["nature"],"synonymes":["ramée","branchage","frondaison","bois"],"antonymes":["tronc","souche"],"exemplesCorrects":["Le vent agitait la ramure dénudée des peupliers.","Le cerf portait une ramure imposante à douze cors.","Sous la ramure entrelacée, le sentier disparaissait dans l\'ombre."],"exemplesIncorrects":["Elle a commandé une ramure de bœuf chez le boucher.","La ramure de la rivière coulait vers la mer."],"distracteurs":["rature","armure","rainure"],"anecdote":"Chez le cerf, la ramure tombe et repousse chaque année, plus fournie : un rare exemple de régénération osseuse chez les mammifères."},{"id":"embruns","mot":"embruns","nature":"nom masculin","definitions":["Fines gouttelettes d\'eau de mer arrachées aux vagues par le vent."],"phonetique":"/ɑ̃.bʁœ̃/","etymologie":"De l\'occitan embruma, « bruiner », de la famille du latin bruma.","registre":"soutenu","niveau":3,"themes":["nature"],"synonymes":["embrun","écume","poudrin"],"antonymes":["accalmie"],"exemplesCorrects":["Les embruns lui piquaient le visage à chaque rafale.","Sur la jetée, on respirait les embruns iodés du large.","Le phare disparaissait par moments derrière un voile d\'embruns."],"exemplesIncorrects":["Il a saupoudré sa tarte d\'embruns de sucre glace.","Les embruns du désert rendaient la marche pénible."],"distracteurs":["embuns","effluves","embellie"],"anecdote":"Les embruns transportent du sel et des micro-organismes parfois jusqu\'à plusieurs kilomètres à l\'intérieur des terres."},{"id":"bruine","mot":"bruine","nature":"nom féminin","definitions":["Pluie très fine et serrée, faite de gouttelettes presque en suspension."],"phonetique":"/bʁɥin/","etymologie":"Du latin pruina, « givre, gelée blanche ».","registre":"courant","niveau":2,"themes":["nature"],"synonymes":["crachin","bruinage","drache"],"antonymes":["averse","ondée"],"exemplesCorrects":["Une bruine glacée tombait sur la ville depuis le matin.","On distinguait à peine les toits dans la bruine de novembre.","La bruine collait les cheveux sans vraiment mouiller."],"exemplesIncorrects":["La bruine du volcan a recouvert le village de cendres.","Il a bu une bruine bien fraîche après sa course."],"distracteurs":["brume","bruire","buée","ruine"],"anecdote":"Météorologiquement, la bruine se distingue de la pluie par la taille de ses gouttes, inférieures à un demi-millimètre."},{"id":"givre","mot":"givre","nature":"nom masculin","definitions":["Fine couche de glace blanche qui se dépose sur les surfaces par temps froid et humide."],"phonetique":"/ʒivʁ/","etymologie":"Origine incertaine, peut-être d\'un radical prélatin évoquant le froid.","registre":"courant","niveau":2,"themes":["nature"],"synonymes":["gelée blanche","frimas","verglas"],"antonymes":["dégel"],"exemplesCorrects":["Le givre dessinait des fougères sur les carreaux de la fenêtre.","Au petit matin, le givre couvrait l\'herbe d\'un voile argenté.","Les branches alourdies de givre scintillaient au soleil levant."],"exemplesIncorrects":["Il a versé du givre dans son café pour le sucrer.","Le givre de l\'été rendait la plage brûlante."],"distracteurs":["guivre","cuivre","givret"],"anecdote":"Le givre se forme par sublimation inverse : la vapeur d\'eau se change directement en glace, sans passer par l\'état liquide."},{"id":"clairiere","mot":"clairière","nature":"nom féminin","definitions":["Endroit dégarni d\'arbres au milieu d\'une forêt."],"phonetique":"/klɛ.ʁjɛʁ/","etymologie":"Dérivé de clair, « lumineux, dégagé », du latin clarus.","registre":"courant","niveau":2,"themes":["nature"],"synonymes":["clarière","trouée","éclaircie"],"antonymes":["fourré","taillis"],"exemplesCorrects":["Au détour du sentier, une clairière baignée de soleil les attendait.","Les biches venaient brouter dans la clairière au crépuscule.","Ils dressèrent la tente au cœur d\'une clairière silencieuse."],"exemplesIncorrects":["Il a accroché la clairière au mur du salon.","La clairière de l\'océan était trop forte pour nager."],"distracteurs":["lisière","tanière","ornière"],"anecdote":"Les clairières naturelles naissent souvent de la chute d\'un grand arbre, qui ouvre une fenêtre de lumière exploitée aussitôt par les jeunes pousses."},{"id":"alize","mot":"alizé","nature":"nom masculin","definitions":["Vent régulier qui souffle toute l\'année des tropiques vers l\'équateur."],"phonetique":"/a.li.ze/","etymologie":"Origine incertaine, peut-être de l\'ancien français alis, « lisse, régulier ».","registre":"soutenu","niveau":3,"themes":["nature"],"synonymes":["vent régulier"],"antonymes":["bourrasque","rafale"],"exemplesCorrects":["Les voiliers d\'autrefois traversaient l\'Atlantique portés par les alizés.","L\'alizé rafraîchissait l\'île chaque après-midi avec une belle constance.","Sans l\'alizé, la chaleur des Antilles serait difficilement supportable."],"exemplesIncorrects":["Il a planté un alizé dans son jardin au printemps.","L\'alizé de minuit a réveillé toute la maisonnée par son vacarme."],"distracteurs":["zéphyr","alésage","alidade"],"anecdote":"Ce sont les alizés qui ont rendu possible la « route des épices » : Christophe Colomb les utilisa pour gagner les Amériques."},{"id":"limon","mot":"limon","nature":"nom masculin","definitions":["Terre fine et fertile déposée par les eaux d\'un cours d\'eau."],"phonetique":"/li.mɔ̃/","etymologie":"Du latin limus, « boue, vase ».","registre":"soutenu","niveau":3,"themes":["nature"],"synonymes":["alluvion","vase","boue","sédiment"],"antonymes":["roche","sable stérile"],"exemplesCorrects":["Les crues du Nil déposaient un limon noir qui faisait la richesse de l\'Égypte.","Après la décrue, les champs étaient couverts d\'un limon fertile.","Le potier puisait son argile dans le limon de la rivière."],"exemplesIncorrects":["Il a pressé un limon pour aromatiser son thé.","Le limon brillait de mille feux à la devanture du joaillier."],"distracteurs":["lichen","humus","filon"],"anecdote":"Plusieurs traditions font naître l\'homme du limon de la terre : l\'image dit la fécondité prêtée à cette terre des fleuves."},{"id":"zenith","mot":"zénith","nature":"nom masculin","definitions":["Point du ciel situé à la verticale de l\'observateur.","Point le plus haut, apogée."],"phonetique":"/ze.nit/","etymologie":"De l\'arabe samt (ar-ras), « le chemin au-dessus de la tête », via le latin médiéval.","registre":"courant","niveau":3,"themes":["nature","abstrait"],"synonymes":["apogée","sommet","faîte","summum"],"antonymes":["nadir","déclin","creux"],"exemplesCorrects":["À midi, le soleil atteignait presque le zénith.","Sa carrière connut son zénith au début des années quatre-vingt.","Au zénith de sa gloire, l\'écrivain choisit de se retirer."],"exemplesIncorrects":["Il a rangé le zénith dans la cave avec les vieux outils.","Le zénith de la soupe manquait cruellement de sel."],"distracteurs":["nadir","méridien","zéphyr"],"anecdote":"Le mot est jumeau de « nadir », son exact opposé : tous deux nous viennent des astronomes arabes du Moyen Âge."},{"id":"seve","mot":"sève","nature":"nom féminin","definitions":["Liquide nourricier qui circule dans les plantes.","Vigueur, énergie vitale."],"phonetique":"/sɛv/","etymologie":"Du latin sapa, « suc, vin cuit », croisé avec sucus.","registre":"courant","niveau":2,"themes":["nature","litteraire"],"synonymes":["suc","vigueur","vitalité","fluide"],"antonymes":["torpeur","langueur"],"exemplesCorrects":["Au printemps, la sève monte et les bourgeons éclatent.","On entaille l\'érable pour en recueillir la sève sucrée.","Il y avait dans ses vers une sève juvénile irrésistible."],"exemplesIncorrects":["Il a réparé la sève crevée de son vélo.","La sève du moteur était à plat ce matin."],"distracteurs":["fève","rêve","lève"],"anecdote":"La sève brute monte des racines vers les feuilles, et la sève élaborée redescend, chargée des sucres produits par la photosynthèse."},{"id":"futaie","mot":"futaie","nature":"nom féminin","definitions":["Forêt de grands arbres au tronc élevé et dégagé."],"phonetique":"/fy.tɛ/","etymologie":"Dérivé de fût, « tronc d\'arbre », du latin fustis.","registre":"soutenu","niveau":4,"themes":["nature"],"synonymes":["forêt","bois","sylve"],"antonymes":["taillis","broussaille"],"exemplesCorrects":["Le sentier s\'enfonçait dans une futaie de hêtres centenaires.","La haute futaie laissait à peine passer la lumière.","On exploitait cette futaie pour ses chênes de charpente."],"exemplesIncorrects":["Il a commandé une futaie de champagne pour la fête.","La futaie de poissons remontait le courant."],"distracteurs":["futile","frontaie","fustige"],"anecdote":"On oppose la futaie, faite d\'arbres issus de semences, au taillis, formé de rejets poussant sur des souches."},{"id":"drache","mot":"drache","nature":"nom féminin","definitions":["Forte pluie, averse soudaine et abondante."],"phonetique":"/dʁaʃ/","etymologie":"Du flamand, « forte averse ».","registre":"familier","niveau":3,"themes":["regionalismes","nature"],"synonymes":["averse","saucée","ondée"],"antonymes":["éclaircie","accalmie"],"exemplesCorrects":["On s\'est fait surprendre par une drache en sortant du café.","Quelle drache ! On ne voyait plus le bout de la rue.","À Lille, une drache de fin d\'après-midi n\'étonne personne."],"exemplesIncorrects":["Il a savouré une drache bien fraîche au dessert.","La drache du four a fait lever la pâte en quelques minutes."],"distracteurs":["bâche","tache","douche"],"anecdote":"Dans le Nord et en Belgique, on parle même de « drache nationale » pour la pluie qui tombe immanquablement les jours de fête."},{"id":"ducasse","mot":"ducasse","nature":"nom féminin","definitions":["Fête populaire annuelle, kermesse, dans le nord de la France et en Belgique."],"phonetique":"/dy.kas/","etymologie":"Altération de dédicace : la fête de la dédicace de l\'église, devenue fête de village.","registre":"courant","niveau":3,"themes":["regionalismes"],"synonymes":["kermesse","fête foraine","frairie"],"antonymes":[],"exemplesCorrects":["La ducasse du village attire les manèges chaque mois d\'août.","On mange des gaufres et on danse jusqu\'au bout de la nuit, c\'est la ducasse.","Les géants défilent dans les rues pour l\'ouverture de la ducasse."],"exemplesIncorrects":["Il a réglé la ducasse d\'électricité avant la fin du mois.","La ducasse de la montagne était couverte de neige."],"distracteurs":["bécasse","liesse","ripaille"],"anecdote":"La célèbre ducasse d\'Ath, avec ses géants, est inscrite au patrimoine culturel immatériel de l\'humanité par l\'UNESCO."},{"id":"gone","mot":"gone","nature":"nom masculin","definitions":["Enfant, gamin, dans le parler lyonnais."],"phonetique":"/ɡɔn/","etymologie":"Mot lyonnais d\'origine incertaine, « gamin des rues ».","registre":"familier","niveau":4,"themes":["regionalismes"],"synonymes":["gamin","gosse","môme","pitchoun"],"antonymes":["adulte","vieillard"],"exemplesCorrects":["Quand j\'étais gone, on jouait sur les pentes de la Croix-Rousse.","Les gones du quartier se retrouvaient au bord de la Saône.","C\'est un vrai gone de Lyon, fier de ses traboules."],"exemplesIncorrects":["Il a acheté un gone tout neuf pour aller travailler.","La gone de la rivière était en crue ce matin."],"distracteurs":["cône","zone","borne"],"anecdote":"Le personnage de Guignol, né à Lyon, est l\'archétype du gone : malicieux, gouailleur et bon cœur."},{"id":"pitchoun","mot":"pitchoun","nature":"nom masculin","definitions":["Petit enfant, dans le Midi de la France."],"phonetique":"/pi.tʃun/","etymologie":"De l\'occitan pichon, « petit ».","registre":"familier","niveau":4,"themes":["regionalismes"],"synonymes":["petit","gamin","gone","bambin"],"antonymes":["adulte","aîné"],"exemplesCorrects":["Allez, viens là, mon pitchoun, on va manger.","Les pitchouns couraient pieds nus dans les ruelles du village.","Elle gardait les pitchouns du quartier pendant l\'été."],"exemplesIncorrects":["Il a garé son pitchoun devant la mairie.","Le pitchoun de la soupe était trop épais."],"distracteurs":["potiron","pichet","pinson"],"anecdote":"Le mot a essaimé bien au-delà du Midi grâce aux chansons et au cinéma, au point de devenir un terme d\'affection presque national."},{"id":"cagnard","mot":"cagnard","nature":"nom masculin","definitions":["Soleil très chaud, forte chaleur ; endroit exposé au plein soleil."],"phonetique":"/ka.ɲaʁ/","etymologie":"Du provençal cagnard, « endroit abrité et ensoleillé ».","registre":"familier","niveau":4,"themes":["regionalismes","nature"],"synonymes":["plein soleil","canicule","fournaise"],"antonymes":["ombre","fraîcheur"],"exemplesCorrects":["On ne va pas rester en plein cagnard, cherchons un peu d\'ombre.","À deux heures, le cagnard rendait la place déserte.","Les cigales chantaient de plus belle sous le cagnard d\'août."],"exemplesIncorrects":["Il a mis un pull à cause du cagnard glacial.","Le cagnard tombait à gros flocons sur le village."],"distracteurs":["cafard","canard","cagneux"],"anecdote":"Le même mot a donné « cagnarder », c\'est-à-dire paresser au soleil : tout un art de vivre méridional en un verbe."},{"id":"fada","mot":"fada","nature":"adjectif","definitions":["Un peu fou, simple d\'esprit, dans le parler du Midi (souvent affectueux)."],"phonetique":"/fa.da/","etymologie":"De l\'occitan fadat, « touché par les fées », d\'où « un peu fou ».","registre":"familier","niveau":3,"themes":["regionalismes"],"synonymes":["toqué","timbré","marteau","zinzin"],"antonymes":["sensé","raisonnable"],"exemplesCorrects":["Il est complètement fada de pétanque, il y joue tous les jours.","Ne fais pas le fada, descends de ce mur !","Un peu fada, ce projet, mais après tout pourquoi pas."],"exemplesIncorrects":["La route était fada à cause des travaux.","Il a peint le mur d\'un beau fada lumineux."],"distracteurs":["fade","soda","fana"],"anecdote":"À Marseille, la Cité radieuse de Le Corbusier est surnommée « la Maison du fada », tant son architecture parut audacieuse à ses débuts."},{"id":"peuchere","mot":"peuchère","nature":"interjection","definitions":["Exclamation de compassion ou d\'attendrissement, dans le Midi : « le pauvre ! »."],"phonetique":"/pø.ʃɛʁ/","etymologie":"Du provençal pecaire, « pécheur », devenu exclamation de pitié.","registre":"familier","niveau":4,"themes":["regionalismes"],"synonymes":["le pauvre","hélas"],"antonymes":[],"exemplesCorrects":["Il a raté son train d\'une minute, peuchère !","Peuchère, le petit s\'est endormi avant la fin du repas.","Elle a tout perdu dans l\'inondation, peuchère."],"exemplesIncorrects":["Il a acheté une peuchère neuve au marché.","La peuchère du moteur faisait un bruit inquiétant."],"distracteurs":["pécore","vachère","panère"],"anecdote":"Pagnol a fait connaître « peuchère » à toute la France à travers ses films, où le mot ponctue la tendresse bourrue de ses personnages."},{"id":"barouf","mot":"barouf","nature":"nom masculin","definitions":["Grand bruit, tapage, vacarme."],"phonetique":"/ba.ʁuf/","etymologie":"De l\'arabe maghrébin, « grand bruit, tapage ».","registre":"familier","niveau":3,"themes":["quotidien"],"synonymes":["vacarme","raffut","ramdam","boucan"],"antonymes":["silence","calme"],"exemplesCorrects":["Les voisins ont fait un de ces baroufs jusqu\'à trois heures du matin.","Quel barouf dans la cour de récréation à la sonnerie !","Inutile de faire tout ce barouf pour si peu."],"exemplesIncorrects":["Il a dégusté un barouf bien mûr au dessert.","Le barouf du lac était parfaitement lisse ce matin."],"distracteurs":["baroud","bazar","tarif"],"anecdote":"Comme « ramdam » ou « toubib », « barouf » fait partie de ces mots venus de l\'arabe que le français a adoptés au fil des échanges méditerranéens."},{"id":"ramdam","mot":"ramdam","nature":"nom masculin","definitions":["Tapage, vacarme ; agitation bruyante."],"phonetique":"/ʁam.dam/","etymologie":"De ramadan, par allusion à l\'animation nocturne du mois de jeûne.","registre":"familier","niveau":3,"themes":["quotidien","emprunts"],"synonymes":["vacarme","raffut","barouf","tintamarre"],"antonymes":["silence","quiétude"],"exemplesCorrects":["Les enfants ont fait un ramdam de tous les diables tout l\'après-midi.","Cette annonce a déclenché un beau ramdam sur les réseaux.","Arrête ce ramdam, j\'essaie de me concentrer."],"exemplesIncorrects":["Il a planté un ramdam dans son jardin potager.","Le ramdam de la rivière reflétait le ciel bleu."],"distracteurs":["macadam","ramage","tandem"],"anecdote":"Le glissement de sens est curieux : du mois sacré du jeûne, le mot n\'a gardé en français que l\'idée de l\'agitation des veillées."},{"id":"esquinter","mot":"esquinter","nature":"verbe","definitions":["Abîmer, détériorer.","Fatiguer à l\'excès, épuiser."],"phonetique":"/ɛs.kɛ̃.te/","etymologie":"De l\'occitan esquinçar, « déchirer ».","registre":"familier","niveau":2,"themes":["quotidien"],"synonymes":["abîmer","amocher","éreinter","détériorer"],"antonymes":["réparer","ménager","soigner"],"exemplesCorrects":["Il a esquinté sa voiture contre un poteau en se garant.","Cette longue marche m\'a complètement esquinté.","Ne t\'esquinte pas la vue à lire dans la pénombre."],"exemplesIncorrects":["Elle a esquinté un délicieux gâteau pour le goûter.","Le soleil esquintait gaiement au-dessus des collines."],"distracteurs":["esquisser","esquiver","quintette"],"anecdote":"Dans la langue familière, on « s\'esquinte au travail » comme on « s\'esquinte les yeux » : le mot dit toujours l\'usure que l\'on s\'inflige."},{"id":"ronchon","mot":"ronchon","nature":"adjectif","definitions":["Qui ronchonne, qui exprime sa mauvaise humeur en grommelant."],"phonetique":"/ʁɔ̃.ʃɔ̃/","etymologie":"Dérivé de ronchonner, d\'origine onomatopéique (Sud-Est).","registre":"familier","niveau":2,"themes":["emotions","quotidien"],"synonymes":["grognon","bougon","râleur","grincheux"],"antonymes":["affable","enjoué","avenant"],"exemplesCorrects":["Il est toujours un peu ronchon avant son premier café.","Ne sois pas si ronchon, la journée commence à peine.","Sous ses airs ronchons, c\'est un homme très généreux."],"exemplesIncorrects":["Le ciel ronchon annonçait une belle journée ensoleillée.","Cette tarte ronchon était délicieusement sucrée."],"distracteurs":["cochon","torchon","bouchon"],"anecdote":"Blanche-Neige a popularisé le ronchon par excellence : Grincheux, le nain perpétuellement de mauvaise humeur."},{"id":"trifouiller","mot":"trifouiller","nature":"verbe","definitions":["Fouiller, remuer en désordre, manipuler maladroitement."],"phonetique":"/tʁi.fu.je/","etymologie":"Mot-valise de tripoter et fouiller.","registre":"familier","niveau":3,"themes":["quotidien"],"synonymes":["fouiller","fureter","tripoter","farfouiller"],"antonymes":["ranger","ordonner"],"exemplesCorrects":["Il a trifouillé dans le tiroir pendant dix minutes sans rien trouver.","Arrête de trifouiller les fils, tu vas tout débrancher.","Qui a encore trifouillé dans mes affaires ?"],"exemplesIncorrects":["Elle a trifouillé un magnifique discours pour la cérémonie.","Le soleil trifouillait à l\'horizon au lever du jour."],"distracteurs":["gribouiller","tortiller","trinquer","tricoter"],"anecdote":"Le français regorge de ces verbes expressifs en -ouiller — farfouiller, gribouiller, patouiller — où le suffixe ajoute une nuance de désordre brouillon."},{"id":"loustic","mot":"loustic","nature":"nom masculin","definitions":["Individu peu sérieux, plaisantin.","Personnage dont on se méfie un peu."],"phonetique":"/lus.tik/","etymologie":"De l\'allemand lustig, « joyeux, gai », introduit par les soldats.","registre":"familier","niveau":3,"themes":["quotidien"],"synonymes":["plaisantin","farceur","luron","zigoto"],"antonymes":["pince-sans-rire","rabat-joie"],"exemplesCorrects":["C\'est un sacré loustic, toujours prêt à faire le pitre.","Quel est le loustic qui a caché mes clés ?","Méfie-toi de ce loustic, il n\'en fait qu\'à sa tête."],"exemplesIncorrects":["Il a dégusté un loustic bien frais en terrasse.","La loustic de la voiture était à plat ce matin."],"distracteurs":["rustique","élastique","moustique"],"anecdote":"Dans les régiments d\'autrefois, le « loustic » était le farceur de la compagnie, chargé d\'égayer la troupe : le sens s\'est ensuite élargi."},{"id":"chambouler","mot":"chambouler","nature":"verbe","definitions":["Bouleverser, mettre sens dessus dessous."],"phonetique":"/ʃɑ̃.bu.le/","etymologie":"Probablement croisement de chambarder et de bouler.","registre":"familier","niveau":2,"themes":["quotidien"],"synonymes":["bouleverser","chambarder","renverser","perturber"],"antonymes":["ordonner","stabiliser","ranger"],"exemplesCorrects":["Cette nouvelle a chamboulé tous nos projets de vacances.","Le déménagement a chamboulé les habitudes de la famille.","Il est resté tout chamboulé après cette rencontre inattendue."],"exemplesIncorrects":["Elle a chamboulé une tarte aux pommes pour le dessert.","Le lac chamboulait paisiblement sous la lune."],"distracteurs":["chamailler","chambrer","bousculer"],"anecdote":"Le « chamboule-tout », jeu de fête foraine où l\'on renverse des boîtes, doit évidemment son nom à ce verbe."},{"id":"palimpseste","mot":"palimpseste","nature":"nom masculin","definitions":["Manuscrit dont on a effacé le premier texte pour en écrire un autre.","Œuvre dont on perçoit les états antérieurs sous la version finale."],"phonetique":"/pa.lɛ̃p.sɛst/","etymologie":"Du grec palimpsêstos, « gratté de nouveau », de palin (de nouveau) et psên (gratter).","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["manuscrit gratté"],"antonymes":[],"exemplesCorrects":["Sous la prière médiévale, les chercheurs ont retrouvé un palimpseste d\'Archimède.","La ville est un palimpseste où chaque époque a laissé sa trace.","Son roman se lit comme un palimpseste, hanté par ses lectures."],"exemplesIncorrects":["Il a commandé un palimpseste de jambon à la charcuterie.","Le palimpseste soufflait fort sur la côte cette nuit-là."],"distracteurs":["pamphlet","parchemin","palissade"],"anecdote":"Parce que le parchemin coûtait cher, les moines grattaient les textes antiques pour réécrire dessus : on a ainsi failli perdre, puis retrouvé, des œuvres entières."},{"id":"deliquescence","mot":"déliquescence","nature":"nom féminin","definitions":["État de décadence, de déchéance avancée.","Propriété d\'un corps qui fond en absorbant l\'humidité de l\'air."],"phonetique":"/de.li.kɛ.sɑ̃s/","etymologie":"Du latin deliquescere, « se liquéfier, fondre ».","registre":"littéraire","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["décadence","déchéance","délabrement","ruine"],"antonymes":["essor","apogée","vigueur"],"exemplesCorrects":["L\'empire glissait lentement vers la déliquescence.","La déliquescence des institutions inquiétait les observateurs.","On assistait, impuissant, à la déliquescence de ses facultés."],"exemplesIncorrects":["Il a célébré la déliquescence éclatante de son équipe victorieuse.","La déliquescence du sportif lui valut une médaille d\'or."],"distracteurs":["réminiscence","quintessence","luminescence"],"anecdote":"Le mot a d\'abord été chimique : certains sels, dits déliquescents, se dissolvent dans l\'eau qu\'ils captent à l\'air. La métaphore morale est venue ensuite."},{"id":"fuligineux","mot":"fuligineux","nature":"adjectif","definitions":["Qui produit ou rappelle la suie ; noirâtre.","Obscur, confus, en parlant de l\'esprit ou du style."],"phonetique":"/fy.li.ʒi.nø/","etymologie":"Du latin fuligo, « suie ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["enfumé","noirâtre","obscur","ténébreux"],"antonymes":["limpide","clair","lumineux"],"exemplesCorrects":["Une fumée fuligineuse s\'échappait des cheminées de l\'usine.","Le ciel fuligineux annonçait l\'orage.","Il se perdait dans des raisonnements fuligineux dont nul ne sortait."],"exemplesIncorrects":["Le diamant fuligineux jetait mille éclats au soleil.","Elle servit un dessert fuligineux et sucré à souhait."],"distracteurs":["vertigineux","ferrugineux","oléagineux"],"anecdote":"Les médecins anciens parlaient d\'haleine « fuligineuse » dans les fièvres : la langue s\'y couvrait comme d\'un dépôt de suie."},{"id":"abscons","mot":"abscons","nature":"adjectif","definitions":["Difficile à comprendre, obscur, peu intelligible."],"phonetique":"/aps.kɔ̃/","etymologie":"Du latin absconsus, « caché, dérobé ».","registre":"soutenu","niveau":5,"themes":["abstrait"],"synonymes":["obscur","abstrus","hermétique","sibyllin"],"antonymes":["limpide","clair","accessible"],"exemplesCorrects":["Le rapport était rédigé dans un jargon abscons.","Ses explications absconses ont laissé l\'auditoire perplexe.","Pourquoi rendre abscons ce qui pourrait être dit simplement ?"],"exemplesIncorrects":["Le ciel abscons promettait une journée radieuse.","Il a couru un marathon abscons en un temps record."],"distracteurs":["abscisse","fécond","abondant"],"anecdote":"« Abscons » et « caché » sont cousins : la racine latine se retrouve dans « absconse », la petite lanterne dont les moines masquaient la flamme."},{"id":"thaumaturge","mot":"thaumaturge","nature":"nom masculin","definitions":["Personne qui fait ou prétend faire des miracles."],"phonetique":"/to.ma.tyʁʒ/","etymologie":"Du grec thauma, « prodige », et ergon, « œuvre ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["faiseur de miracles","magicien","guérisseur"],"antonymes":["sceptique","rationaliste"],"exemplesCorrects":["La foule accourait vers le thaumaturge qui guérissait, disait-on, par l\'imposition des mains.","On le traitait de thaumaturge tant ses remèdes paraissaient miraculeux.","Le roman met en scène un thaumaturge ambigu, entre saint et imposteur."],"exemplesIncorrects":["Il a réparé le thaumaturge de la cuisine en deux minutes.","Le thaumaturge soufflait en tempête sur la baie."],"distracteurs":["dramaturge","démiurge","thérapeute"],"anecdote":"Les rois de France étaient réputés thaumaturges : on croyait qu\'ils guérissaient les écrouelles d\'un simple toucher, en disant « le roi te touche, Dieu te guérit »."},{"id":"anachorete","mot":"anachorète","nature":"nom masculin","definitions":["Religieux retiré dans la solitude ; par extension, personne qui vit à l\'écart du monde."],"phonetique":"/a.na.kɔ.ʁɛt/","etymologie":"Du grec anakhōrêtês, « celui qui se retire ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["ermite","solitaire","reclus","cénobite"],"antonymes":["mondain","sociable"],"exemplesCorrects":["Il vivait en anachorète, loin de toute agitation, parmi ses livres.","Les premiers anachorètes se retiraient au désert pour prier.","Depuis sa retraite, elle menait une existence d\'anachorète."],"exemplesIncorrects":["Il a commandé un anachorète bien cuit au restaurant.","L\'anachorète de l\'autoroute était saturé aux heures de pointe."],"distracteurs":["anachronisme","catéchèse","anchois"],"anecdote":"On oppose l\'anachorète, qui vit seul, au cénobite, qui vit en communauté : deux manières opposées d\'embrasser la vie monastique."},{"id":"matois","mot":"matois","nature":"adjectif","definitions":["Rusé et malin sous une apparence bonhomme."],"phonetique":"/ma.twa/","etymologie":"Origine incertaine, peut-être de l\'argot mate, « lieu de rencontre des filous ».","registre":"littéraire","niveau":4,"themes":["litteraire"],"synonymes":["rusé","finaud","madré","roublard"],"antonymes":["naïf","candide","ingénu"],"exemplesCorrects":["Le paysan matois feignait de ne rien comprendre pour mieux marchander.","Un sourire matois éclairait son visage ridé.","Sous des dehors placides, c\'était un négociateur matois."],"exemplesIncorrects":["Le ciel matois laissait présager un orage violent.","Elle a préparé un gratin matois et savoureux."],"distracteurs":["matelas","patois","matelot","matité"],"anecdote":"Le « compère matois » est un personnage récurrent des fables et des contes, cousin du renard goupil, toujours plus malin que ses dupes."},{"id":"fatras","mot":"fatras","nature":"nom masculin","definitions":["Amas confus et désordonné de choses ou d\'idées."],"phonetique":"/fa.tʁa/","etymologie":"De l\'ancien français, peut-être du latin farsura, « remplissage ».","registre":"soutenu","niveau":4,"themes":["abstrait","quotidien"],"synonymes":["amas","fouillis","bric-à-brac","capharnaüm"],"antonymes":["ordre","classement"],"exemplesCorrects":["Il fouillait dans un fatras de vieux papiers.","Son exposé n\'était qu\'un fatras d\'idées mal reliées.","Au grenier s\'entassait un fatras d\'objets oubliés."],"exemplesIncorrects":["Elle a savouré un fatras délicieux au dessert.","Le fatras coulait limpide entre les rochers."],"distracteurs":["fracas","matelas","fatigue"],"anecdote":"Au Moyen Âge, le « fatras » était un genre poétique fait d\'assemblages cocasses : le sens de désordre lui est resté."},{"id":"cenacle","mot":"cénacle","nature":"nom masculin","definitions":["Cercle restreint d\'écrivains, d\'artistes ou de penseurs réunis par une même affinité."],"phonetique":"/se.nakl/","etymologie":"Du latin cenaculum, « salle à manger à l\'étage », puis salle de la Cène.","registre":"littéraire","niveau":4,"themes":["litteraire"],"synonymes":["cercle","coterie","chapelle","aréopage"],"antonymes":["foule","grand public"],"exemplesCorrects":["Les jeunes romantiques se retrouvaient dans le cénacle de Victor Hugo.","Ce prix est décerné par un cénacle de happy few.","Loin des cénacles parisiens, il écrivait dans une solitude choisie."],"exemplesIncorrects":["Il a réparé le cénacle de la voiture au garage.","Le cénacle de l\'orage gronda toute la nuit."],"distracteurs":["tabernacle","obstacle","pinacle"],"anecdote":"Le mot vient de la salle où eut lieu la Cène ; il désigne aujourd\'hui tout petit cercle d\'initiés, souvent littéraire."},{"id":"sentencieux","mot":"sentencieux","nature":"adjectif","definitions":["Qui s\'exprime par maximes, avec une gravité affectée et un ton de leçon."],"phonetique":"/sɑ̃.tɑ̃.sjø/","etymologie":"Du latin sententiosus, « riche en pensées », de sententia.","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["doctoral","moralisateur","solennel","pontifiant"],"antonymes":["léger","badin","spontané"],"exemplesCorrects":["Il prit un ton sentencieux pour énoncer des évidences.","Ces maximes sentencieuses finissaient par lasser l\'auditoire.","Rien n\'agace comme un conseil donné d\'un air sentencieux."],"exemplesIncorrects":["Le gâteau sentencieux fondait délicieusement en bouche.","Une pluie sentencieuse arrosa les jardins tout l\'après-midi."],"distracteurs":["silencieux","consciencieux","sentimental"],"anecdote":"Le mot dérive de « sentence » au sens de maxime : le sentencieux multiplie les formules définitives comme s\'il rendait un verdict."},{"id":"rebarbatif","mot":"rébarbatif","nature":"adjectif","definitions":["D\'un abord rebutant, désagréable.","Ennuyeux, aride, en parlant d\'un sujet ou d\'un texte."],"phonetique":"/ʁe.baʁ.ba.tif/","etymologie":"De l\'ancien français se rebarber, « tenir tête, barbe contre barbe ».","registre":"soutenu","niveau":4,"themes":["abstrait","quotidien"],"synonymes":["rebutant","revêche","aride","ingrat"],"antonymes":["engageant","avenant","attrayant"],"exemplesCorrects":["Derrière des dehors rébarbatifs, le concierge était plein d\'attentions.","La grammaire lui semblait une matière rébarbative.","Le règlement, rébarbatif au possible, décourageait toute lecture."],"exemplesIncorrects":["Elle a passé des vacances rébarbatives et reposantes au soleil.","Ce dessert rébarbatif était d\'une douceur exquise."],"distracteurs":["réparateur","barbare","récapitulatif"],"anecdote":"L\'image est savoureuse : se « rebarber », c\'était autrefois s\'affronter de si près que les barbes se touchaient, d\'où l\'idée d\'un contact hérissé."},{"id":"serendipite","mot":"sérendipité","nature":"nom féminin","definitions":["Don de faire par hasard des découvertes heureuses et inattendues."],"phonetique":"/se.ʁɛ̃.di.pi.te/","etymologie":"De l\'anglais serendipity, forgé par Horace Walpole d\'après le conte Les Trois Princes de Serendip.","registre":"soutenu","niveau":4,"themes":["abstrait","emprunts"],"synonymes":["heureux hasard","fortuité"],"antonymes":["malchance","méthode"],"exemplesCorrects":["La pénicilline doit beaucoup à la sérendipité de Fleming.","C\'est par pure sérendipité qu\'elle a trouvé ce manuscrit oublié.","Flâner en librairie, c\'est s\'offrir une chance de sérendipité."],"exemplesIncorrects":["Il a rempli le réservoir de sérendipité avant de partir.","La sérendipité de la soupe manquait un peu de sel."],"distracteurs":["sérénité","serpentin","disparité"],"anecdote":"Walpole inventa le mot en 1754 dans une lettre, à partir d\'un conte persan où trois princes font sans cesse des trouvailles inattendues."},{"id":"amenite","mot":"aménité","nature":"nom féminin","definitions":["Amabilité, douceur dans les manières et le caractère.","Au pluriel et par ironie : paroles désobligeantes."],"phonetique":"/a.me.ni.te/","etymologie":"Du latin amoenitas, « agrément, charme ».","registre":"soutenu","niveau":4,"themes":["emotions","abstrait"],"synonymes":["amabilité","affabilité","courtoisie","douceur"],"antonymes":["rudesse","âpreté","acrimonie"],"exemplesCorrects":["Il recevait ses hôtes avec une aménité de tous les instants.","Elle répondit avec aménité aux questions les plus insistantes.","Les deux adversaires s\'échangèrent quelques aménités peu amènes."],"exemplesIncorrects":["L\'aménité du moteur l\'empêchait de démarrer.","Il a planté une aménité au fond du jardin."],"distracteurs":["amnistie","affinité","annuité"],"anecdote":"Par antiphrase, « échanger des aménités » signifie souvent tout le contraire : se lancer des amabilités acerbes."},{"id":"dereliction","mot":"déréliction","nature":"nom féminin","definitions":["État d\'abandon et de solitude morale extrême."],"phonetique":"/de.ʁe.lik.sjɔ̃/","etymologie":"Du latin derelictio, « abandon total ».","registre":"littéraire","niveau":5,"themes":["emotions","litteraire","abstrait"],"synonymes":["abandon","délaissement","isolement","déshérence"],"antonymes":["réconfort","secours","soutien"],"exemplesCorrects":["Il connut, dans l\'exil, une déréliction sans nom.","La déréliction du malade abandonné de tous serrait le cœur.","Le poème dit la déréliction de l\'âme privée de toute espérance."],"exemplesIncorrects":["La déréliction de la fête battait son plein jusqu\'à l\'aube.","Il a savouré sa déréliction éclatante après la victoire."],"distracteurs":["dérision","prédiction","déréglementation"],"anecdote":"Le mot a une forte charge spirituelle : on parle de la déréliction du Christ en croix, dans le cri « pourquoi m\'as-tu abandonné ? »."},{"id":"allegresse","mot":"allégresse","nature":"nom féminin","definitions":["Joie vive qui se manifeste au-dehors, gaieté débordante."],"phonetique":"/a.le.ɡʁɛs/","etymologie":"De l\'ancien français alegresse, de alègre, du latin alacer, « vif, gai ».","registre":"soutenu","niveau":2,"themes":["emotions"],"synonymes":["liesse","jubilation","exultation","gaieté"],"antonymes":["tristesse","abattement","morosité"],"exemplesCorrects":["Une allégresse générale saisit la foule à l\'annonce de la victoire.","Les enfants couraient dans le jardin avec une allégresse communicative.","Le retour du printemps le remplissait d\'une allégresse enfantine."],"exemplesIncorrects":["Il a annoncé la nouvelle avec une profonde allégresse et beaucoup de larmes.","L\'allégresse de l\'examen raté pesait sur tout le groupe."],"distracteurs":["allégeance","agilité","âpreté"],"anecdote":"L\'allégresse partage sa racine avec « allègre » et « alacrité » : toutes disent une légèreté vive, presque dansante."},{"id":"courroux","mot":"courroux","nature":"nom masculin","definitions":["Vive colère, indignation."],"phonetique":"/ku.ʁu/","etymologie":"De l\'ancien français corouz, du latin populaire corruptiare, « gâter, irriter ».","registre":"littéraire","niveau":4,"themes":["emotions","litteraire"],"synonymes":["colère","ire","fureur","indignation"],"antonymes":["sérénité","calme","mansuétude"],"exemplesCorrects":["Le courroux du roi s\'abattit sur les conspirateurs.","Elle contint son courroux et répondit d\'une voix glacée.","Rien n\'apaisait le courroux des dieux, disait le poète."],"exemplesIncorrects":["Il a accueilli ses amis avec un courroux chaleureux.","Le courroux du soleil rendait la promenade agréable."],"distracteurs":["courroie","concours","secours"],"anecdote":"Mot du registre épique, le courroux est celui d\'Achille dans l\'Iliade : la colère qui ouvre toute la littérature occidentale."},{"id":"depit","mot":"dépit","nature":"nom masculin","definitions":["Chagrin mêlé de contrariété, causé par une déception ou une vexation."],"phonetique":"/de.pi/","etymologie":"Du latin despectus, « mépris, action de regarder de haut ».","registre":"courant","niveau":3,"themes":["emotions"],"synonymes":["amertume","rancœur","vexation","déconvenue"],"antonymes":["satisfaction","contentement"],"exemplesCorrects":["Par dépit, elle déchira la lettre sans la lire.","Il accepta la défaite avec un dépit mal dissimulé.","Le dépit amoureux est un grand pourvoyeur de mauvaises décisions."],"exemplesIncorrects":["Quel dépit de gagner enfin le concours tant convoité !","Il sauta de dépit en apprenant son augmentation."],"distracteurs":["débit","répit","déni"],"anecdote":"La locution « en dépit de », qui signifie « malgré », garde la trace du sens premier de mépris : agir au mépris de quelque chose."},{"id":"langueur","mot":"langueur","nature":"nom féminin","definitions":["Abattement physique ou moral, mélancolie douce.","Manque d\'énergie, d\'entrain."],"phonetique":"/lɑ̃.ɡœʁ/","etymologie":"Du latin languor, « faiblesse, abattement ».","registre":"littéraire","niveau":4,"themes":["emotions","litteraire"],"synonymes":["alanguissement","torpeur","mélancolie","atonie"],"antonymes":["vigueur","ardeur","entrain"],"exemplesCorrects":["Une douce langueur l\'envahissait aux heures chaudes de l\'après-midi.","Il y avait dans son regard une langueur romantique.","La langueur de l\'été semblait suspendre le temps."],"exemplesIncorrects":["Il a remporté la course avec une langueur impressionnante.","La langueur du moteur faisait trembler toute la voiture."],"distracteurs":["longueur","candeur","ardeur"],"anecdote":"« Les sanglots longs des violons de l\'automne blessent mon cœur d\'une langueur monotone » : Verlaine a fixé pour toujours la couleur du mot."},{"id":"liesse","mot":"liesse","nature":"nom féminin","definitions":["Joie collective et débordante, allégresse partagée."],"phonetique":"/ljɛs/","etymologie":"De l\'ancien français leece, du latin laetitia, « joie ».","registre":"littéraire","niveau":4,"themes":["emotions","litteraire"],"synonymes":["allégresse","jubilation","exultation"],"antonymes":["affliction","désolation"],"exemplesCorrects":["La ville était en liesse après le sacre de son équipe.","Une foule en liesse accompagnait le cortège.","Ce fut un soir de liesse, de chants et de danses."],"exemplesIncorrects":["Il a appris la triste nouvelle dans une grande liesse.","Seul dans sa chambre, il ressentait une liesse silencieuse et solitaire."],"distracteurs":["laisse","paresse","lisse"],"anecdote":"On emploie presque toujours « liesse » dans la locution « en liesse » : le mot ne vit guère qu\'au cœur des foules en fête."},{"id":"felicite","mot":"félicité","nature":"nom féminin","definitions":["Bonheur complet et durable ; état de parfaite satisfaction."],"phonetique":"/fe.li.si.te/","etymologie":"Du latin felicitas, « bonheur, chance », de felix, « heureux, fertile ».","registre":"soutenu","niveau":4,"themes":["emotions","abstrait"],"synonymes":["béatitude","bonheur","plénitude","contentement"],"antonymes":["malheur","infortune","détresse"],"exemplesCorrects":["Ils goûtaient dans cette retraite une félicité parfaite.","La félicité conjugale qu\'on lui prêtait n\'était qu\'apparente.","Les Anciens plaçaient la félicité dans la sagesse, non dans les biens."],"exemplesIncorrects":["Il a vécu une félicité atroce après son accident.","La félicité de la défaite l\'a plongé dans le désespoir."],"distracteurs":["facilité","fébrilité","publicité"],"anecdote":"Les « félicitations » que l\'on adresse aujourd\'hui dérivent de ce mot : c\'était à l\'origine souhaiter à autrui la félicité."},{"id":"desarroi","mot":"désarroi","nature":"nom masculin","definitions":["Trouble profond, désorganisation morale qui ôte tout repère."],"phonetique":"/de.za.ʁwa/","etymologie":"De l\'ancien français desarroyer, « mettre en désordre », de arroi, « arrangement ».","registre":"courant","niveau":3,"themes":["emotions"],"synonymes":["détresse","trouble","confusion","égarement"],"antonymes":["assurance","sérénité","sang-froid"],"exemplesCorrects":["La nouvelle la laissa dans un désarroi total.","On lisait le désarroi sur le visage des rescapés.","Devant tant de choix, il éprouvait un certain désarroi."],"exemplesIncorrects":["Il a rangé son bureau avec un désarroi méthodique.","Le désarroi du paysage ensoleillé invitait à la promenade."],"distracteurs":["désaveu","désarmoi","convoi"],"anecdote":"Le mot vient de l\'ancien « arroi », l\'équipement et l\'ordre d\'une troupe : être en désarroi, c\'était d\'abord avoir rompu les rangs."},{"id":"emoi","mot":"émoi","nature":"nom masculin","definitions":["Trouble, agitation causés par une émotion vive."],"phonetique":"/e.mwa/","etymologie":"De l\'ancien français esmai, de esmayer, « troubler, effrayer ».","registre":"soutenu","niveau":3,"themes":["emotions","litteraire"],"synonymes":["agitation","trouble","effervescence","émotion"],"antonymes":["calme","quiétude","impassibilité"],"exemplesCorrects":["Sa déclaration mit toute l\'assemblée en émoi.","Le quartier était en émoi après l\'étrange disparition.","Un doux émoi la saisit lorsqu\'il entra."],"exemplesIncorrects":["Il a classé ses dossiers dans un émoi parfait.","L\'émoi du lac, parfaitement plat, reflétait les montagnes."],"distracteurs":["envoi","emploi","octroi"],"anecdote":"On retrouve « émoi » dans l\'expression « tout en émoi », et son cousin verbal « s\'émouvoir » : la même racine que l\'anglais dismay."},{"id":"leitmotiv","mot":"leitmotiv","nature":"nom masculin","definitions":["Formule, idée qui revient sans cesse dans un discours, une œuvre.","Thème musical récurrent associé à un personnage ou à une situation."],"phonetique":"/lajt.mo.tiv/","etymologie":"De l\'allemand Leitmotiv, « motif conducteur », de leiten, « conduire ».","registre":"courant","niveau":4,"themes":["emprunts","abstrait"],"synonymes":["refrain","rengaine","thème récurrent"],"antonymes":[],"exemplesCorrects":["« La sécurité d\'abord » était devenu le leitmotiv de la campagne.","Wagner a porté le leitmotiv musical à son apogée.","Le retour à la nature est le leitmotiv de tout le roman."],"exemplesIncorrects":["Il a réparé le leitmotiv crevé de son vélo.","Le leitmotiv soufflait fort sur la côte cette nuit-là."],"distracteurs":["lénifiant","diktat","laïus"],"anecdote":"Le terme est né dans l\'analyse des opéras de Wagner avant de gagner le langage courant pour désigner toute idée fixe."},{"id":"zeitgeist","mot":"zeitgeist","nature":"nom masculin","definitions":["Esprit d\'une époque, climat intellectuel et culturel d\'un temps donné."],"phonetique":"/zajt.ɡajst/","etymologie":"De l\'allemand Zeit, « temps », et Geist, « esprit ».","registre":"soutenu","niveau":5,"themes":["emprunts","abstrait"],"synonymes":["esprit du temps","air du temps"],"antonymes":[],"exemplesCorrects":["Ce film a parfaitement capté le zeitgeist des années folles.","Difficile d\'échapper au zeitgeist de son époque.","Le philosophe analysait le zeitgeist d\'un siècle inquiet."],"exemplesIncorrects":["Il a commandé un zeitgeist bien frais en terrasse.","Le zeitgeist de la rivière reflétait le ciel d\'été."],"distracteurs":["zénith","gestalt","ersatz"],"anecdote":"Popularisé par les philosophes allemands romantiques, le mot dit que chaque époque respire un même air, perceptible après coup."},{"id":"farniente","mot":"farniente","nature":"nom masculin","definitions":["Douce oisiveté, plaisir de ne rien faire."],"phonetique":"/faʁ.njɛnt/","etymologie":"De l\'italien far niente, « ne rien faire ».","registre":"familier","niveau":4,"themes":["emprunts","quotidien"],"synonymes":["oisiveté","paresse","désœuvrement","flânerie"],"antonymes":["labeur","activité","affairement"],"exemplesCorrects":["Après des mois de travail, il s\'offrit une semaine de pur farniente.","Le farniente sur la plage, à l\'ombre d\'un parasol, voilà son idéal.","Rien de tel qu\'un dimanche de farniente pour récupérer."],"exemplesIncorrects":["Il a couru le farniente en moins de quatre heures.","Le farniente du chantier a duré toute la semaine, sans répit."],"distracteurs":["fariboles","dolce vita","ferraille"],"anecdote":"L\'italien a légué au français cet art de l\'oisiveté heureuse, cousin du « dolce far niente », la douceur de ne rien faire."},{"id":"flegme","mot":"flegme","nature":"nom masculin","definitions":["Calme imperturbable, maîtrise de soi devant l\'agitation ou l\'adversité."],"phonetique":"/flɛɡm/","etymologie":"Du grec phlegma, « humeur froide », l\'une des quatre humeurs de la médecine antique.","registre":"courant","niveau":4,"themes":["emotions","emprunts"],"synonymes":["sang-froid","impassibilité","placidité","calme"],"antonymes":["fébrilité","emportement","nervosité"],"exemplesCorrects":["Il accueillit la mauvaise nouvelle avec un flegme tout britannique.","Son flegme en pleine tempête rassurait l\'équipage.","Rien n\'entame le flegme de ce vieux diplomate."],"exemplesIncorrects":["Il bondit de son siège avec un flegme incontrôlable.","Le flegme du volcan en éruption était terrifiant."],"distracteurs":["phlox","fragment","flemme"],"anecdote":"Pour les médecins anciens, l\'excès de « phlegme » donnait un tempérament froid et lent : le flegmatique d\'aujourd\'hui en a hérité le calme."},{"id":"aficionado","mot":"aficionado","nature":"nom masculin","definitions":["Amateur passionné et averti d\'un domaine, d\'une discipline."],"phonetique":"/a.fi.sjo.na.do/","etymologie":"Mot espagnol, de afición, « passion », du latin affectio.","registre":"courant","niveau":4,"themes":["emprunts"],"synonymes":["passionné","fervent","mordu","connaisseur"],"antonymes":["néophyte","indifférent"],"exemplesCorrects":["C\'est un aficionado de jazz qui connaît chaque enregistrement.","Les aficionados se pressaient aux arènes dès l\'aube.","En véritable aficionado, il distinguait les crus les yeux fermés."],"exemplesIncorrects":["Il a réparé l\'aficionado de la cuisine en deux minutes.","L\'aficionado tombait à gros flocons sur la ville."],"distracteurs":["aficio","incognito","desperado"],"anecdote":"Le mot vient de l\'univers de la corrida, où l\'aficionado est le spectateur connaisseur ; il s\'est étendu à toutes les passions."},{"id":"maelstrom","mot":"maelström","nature":"nom masculin","definitions":["Tourbillon marin puissant.","Tourbillon d\'événements, agitation qui emporte tout."],"phonetique":"/ma.ɛl.stʁɔm/","etymologie":"Du néerlandais, nom d\'un tourbillon célèbre des côtes norvégiennes.","registre":"littéraire","niveau":5,"themes":["emprunts","nature"],"synonymes":["tourbillon","maelstrom","remous","gouffre"],"antonymes":["calme plat","étale"],"exemplesCorrects":["Le navire fut aspiré par un maelström terrifiant.","Il se sentait happé par le maelström de la grande ville.","La crise plongea le pays dans un maelström d\'incertitudes."],"exemplesIncorrects":["Il a savouré un maelström bien sucré au dessert.","Le maelström de la prairie ondulait paisiblement au vent."],"distracteurs":["mausolée","marasme","mausoleum","mastodonte"],"anecdote":"Edgar Poe a immortalisé le mot dans « Une descente dans le Maelström », récit d\'un pêcheur happé par le gouffre."},{"id":"chocolatine","mot":"chocolatine","nature":"nom féminin","definitions":["Dans le Sud-Ouest, viennoiserie feuilletée fourrée au chocolat (ailleurs « pain au chocolat »)."],"phonetique":"/ʃɔ.kɔ.la.tin/","etymologie":"Dérivé de chocolat ; usage régional du Sud-Ouest et du Québec.","registre":"courant","niveau":2,"themes":["regionalismes","quotidien"],"synonymes":["pain au chocolat","petit pain"],"antonymes":[],"exemplesCorrects":["À Toulouse, on commande une chocolatine, pas un pain au chocolat.","Le boulanger sort une fournée de chocolatines encore tièdes.","La querelle chocolatine contre pain au chocolat divise la France."],"exemplesIncorrects":["Il a garé sa chocolatine devant la mairie.","La chocolatine de la rivière était en crue ce matin."],"distracteurs":["clémentine","tartine","praline"],"anecdote":"La rivalité entre « chocolatine » et « pain au chocolat » est si vive qu\'elle a fait l\'objet de propositions de loi, mi-sérieuses, à l\'Assemblée."},{"id":"tuque","mot":"tuque","nature":"nom féminin","definitions":["Au Québec, bonnet de laine ajusté, porté l\'hiver."],"phonetique":"/tyk/","etymologie":"Mot québécois, altération de toque, « coiffe sans bord ».","registre":"familier","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["bonnet","toque"],"antonymes":[],"exemplesCorrects":["Mets ta tuque, il fait moins vingt dehors !","Il a perdu sa tuque en faisant de la luge.","Une belle tuque rouge lui couvrait les oreilles."],"exemplesIncorrects":["Il a bu une tuque bien chaude en rentrant.","La tuque de la voiture était à plat ce matin."],"distracteurs":["tunique","truc","tuile"],"anecdote":"L\'expression québécoise « attache ta tuque ! » signifie « accroche-toi, ça va secouer » : la tuque y devient symbole de préparation."},{"id":"depanneur","mot":"dépanneur","nature":"nom masculin","definitions":["Au Québec, petite épicerie de proximité ouverte tard."],"phonetique":"/de.pa.nœʁ/","etymologie":"Dérivé de dépanner : le commerce qui « dépanne » à toute heure.","registre":"courant","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["épicerie","supérette"],"antonymes":[],"exemplesCorrects":["Je passe au dépanneur chercher du lait avant la fermeture.","Le dépanneur du coin est ouvert jusqu\'à minuit.","Au Québec, le dépanneur fait partie du paysage de quartier."],"exemplesIncorrects":["Le dépanneur soufflait en tempête sur le fleuve.","Il a planté un dépanneur au fond de son jardin."],"distracteurs":["dépanneuse","déménageur","démarcheur"],"anecdote":"En France, « dépanneur » désigne plutôt celui qui répare ; au Québec, c\'est le lieu où l\'on se dépanne d\'un achat de dernière minute."},{"id":"chicon","mot":"chicon","nature":"nom masculin","definitions":["En Belgique et dans le nord de la France, endive."],"phonetique":"/ʃi.kɔ̃/","etymologie":"De la famille de chicorée, dont l\'endive est issue.","registre":"courant","niveau":3,"themes":["regionalismes","quotidien"],"synonymes":["endive"],"antonymes":[],"exemplesCorrects":["Ce soir, on mange des chicons au gratin.","Au marché, les chicons bien blancs partent les premiers.","Le chicon se cultive à l\'abri de la lumière pour rester pâle."],"exemplesIncorrects":["Il a réglé son chicon d\'électricité à temps.","Le chicon de la voiture refusait de démarrer."],"distracteurs":["cochon","flacon","chignon"],"anecdote":"« Chicon au gratin », roulé dans du jambon, est un classique de la cuisine belge ; ailleurs on dira « endives au jambon »."},{"id":"wassingue","mot":"wassingue","nature":"nom féminin","definitions":["Dans le Nord, serpillière, toile dont on lave les sols."],"phonetique":"/wa.sɛ̃ɡ/","etymologie":"Du flamand, « toile à laver », de la famille de wassen, « laver ».","registre":"familier","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["serpillière","panosse","wassingue"],"antonymes":[],"exemplesCorrects":["Passe un coup de wassingue, le carrelage est tout sale.","Elle essorait la wassingue au-dessus du seau.","Dans le Nord, on dit wassingue là où d\'autres disent serpillière."],"exemplesIncorrects":["Il a dégusté une wassingue bien fraîche au dessert.","La wassingue du ciel annonçait une belle journée."],"distracteurs":["meringue","seringue","wagon"],"anecdote":"La France compte une mosaïque de mots pour la serpillière : wassingue dans le Nord, panosse en Suisse, cinse, loque ou pièce ailleurs."},{"id":"septante","mot":"septante","nature":"adjectif","definitions":["En Belgique et en Suisse, le nombre soixante-dix."],"phonetique":"/sɛp.tɑ̃t/","etymologie":"Du latin septuaginta, « soixante-dix ».","registre":"courant","niveau":3,"themes":["regionalismes"],"synonymes":["soixante-dix"],"antonymes":[],"exemplesCorrects":["En Belgique, on dit septante-cinq pour soixante-quinze.","Ma grand-mère suisse a fêté ses septante ans.","Septante est plus régulier que l\'étrange soixante-dix français."],"exemplesIncorrects":["Il a acheté une septante toute neuve au marché.","La septante du moteur faisait un bruit inquiétant."],"distracteurs":["soixante","septembre","nonante"],"anecdote":"Le français de France a gardé « soixante-dix » et « quatre-vingt-dix », vestiges d\'un comptage par vingt ; la Belgique et la Suisse ont préféré la logique latine."},{"id":"ressac","mot":"ressac","nature":"nom masculin","definitions":["Retour violent des vagues qui se brisent contre un obstacle et refluent."],"phonetique":"/ʁə.sak/","etymologie":"De l\'espagnol resaca, « ressac, reflux ».","registre":"courant","niveau":3,"themes":["nature"],"synonymes":["reflux","remous","ressaut"],"antonymes":["étale"],"exemplesCorrects":["Le ressac arrachait des galets à chaque vague.","On entendait, la nuit, le ressac régulier contre la digue.","Les nageurs se méfiaient du ressac près des rochers."],"exemplesIncorrects":["Il a servi un ressac bien frais à ses invités.","Le ressac de la forêt embaumait la résine."],"distracteurs":["ressort","bivouac","hamac"],"anecdote":"Par métaphore, on parle du « ressac » d\'une émotion ou d\'un souvenir qui revient en force après avoir semblé se retirer."},{"id":"frimas","mot":"frimas","nature":"nom masculin","definitions":["Brouillard froid qui se congèle en fine glace ; froid de l\'hiver."],"phonetique":"/fʁi.ma/","etymologie":"De l\'ancien français frime, d\'origine germanique, « brouillard givrant ».","registre":"littéraire","niveau":4,"themes":["nature","litteraire"],"synonymes":["givre","gelée blanche","froidure"],"antonymes":["canicule","tiédeur"],"exemplesCorrects":["Les arbres se couvraient de frimas aux premières gelées.","Emmitouflé, il affrontait les frimas de décembre.","Le frimas argentait les vitres au petit matin."],"exemplesIncorrects":["Il a bronzé sous le frimas éclatant du mois d\'août.","Le frimas tropical rendait la plage étouffante."],"distracteurs":["frimousse","climat","limon"],"anecdote":"Le mot appartient au vocabulaire poétique de l\'hiver, aux côtés de « froidure » et de « giboulée » ; on l\'emploie souvent au pluriel."},{"id":"meandre","mot":"méandre","nature":"nom masculin","definitions":["Sinuosité d\'un cours d\'eau.","Détour compliqué, cheminement tortueux."],"phonetique":"/me.ɑ̃dʁ/","etymologie":"Du nom du Méandre, fleuve très sinueux d\'Asie Mineure.","registre":"courant","niveau":3,"themes":["nature","abstrait"],"synonymes":["sinuosité","détour","lacet","circonvolution"],"antonymes":["ligne droite","raccourci"],"exemplesCorrects":["La rivière dessinait de larges méandres dans la plaine.","Il se perdait dans les méandres de l\'administration.","Suivre les méandres de sa pensée demandait de la patience."],"exemplesIncorrects":["Il a planté un méandre dans son potager au printemps.","Le méandre du soleil illuminait toute la pièce."],"distracteurs":["esclandre","calandre","cylindre"],"anecdote":"Le motif décoratif grec en grecques, fait d\'angles enchaînés, s\'appelle aussi « méandre », du nom du même fleuve capricieux."},{"id":"garrigue","mot":"garrigue","nature":"nom féminin","definitions":["Végétation broussailleuse et odorante des sols calcaires méditerranéens."],"phonetique":"/ɡa.ʁiɡ/","etymologie":"De l\'occitan garriga, terrain planté de chênes kermès.","registre":"courant","niveau":3,"themes":["nature"],"synonymes":["maquis","lande","brousse"],"antonymes":["futaie","prairie grasse"],"exemplesCorrects":["La garrigue embaumait le thym et le romarin sous le soleil.","Ils marchaient dans la garrigue parmi les cigales.","Rien ne pousse mieux dans la garrigue que les plantes aromatiques."],"exemplesIncorrects":["Il a accroché la garrigue au mur du salon.","La garrigue gelée craquait sous les patins."],"distracteurs":["guérite","barrique","garrot"],"anecdote":"On distingue souvent la garrigue, sur calcaire, du maquis, sur sol siliceux : deux paysages méditerranéens aux parfums voisins."},{"id":"zephyr","mot":"zéphyr","nature":"nom masculin","definitions":["Vent doux et agréable, brise légère."],"phonetique":"/ze.fiʁ/","etymologie":"Du grec Zephuros, dieu du vent d\'ouest.","registre":"littéraire","niveau":4,"themes":["nature","litteraire"],"synonymes":["brise","souffle","alizé"],"antonymes":["bourrasque","ouragan","tempête"],"exemplesCorrects":["Un zéphyr printanier agitait à peine les feuilles.","Le zéphyr du soir apportait le parfum des jardins.","Les voiles se gonflaient sous un zéphyr complaisant."],"exemplesIncorrects":["Le zéphyr déracina plusieurs arbres cette nuit-là.","Il a renversé sa tasse à cause du violent zéphyr."],"distracteurs":["saphir","zénith","satyre"],"anecdote":"Dans la mythologie, Zéphyr est le plus doux des vents ; son nom sert encore à vanter la légèreté d\'un tissu ou d\'une brise."},{"id":"houle","mot":"houle","nature":"nom féminin","definitions":["Mouvement ondulant de la mer formé de vagues larges, sans déferlement."],"phonetique":"/ul/","etymologie":"Origine incertaine, peut-être du germanique hol, « creux ».","registre":"courant","niveau":2,"themes":["nature"],"synonymes":["roulis","vague","ondulation"],"antonymes":["calme plat","mer d\'huile"],"exemplesCorrects":["Le bateau tanguait doucement au gré de la houle.","Une longue houle annonçait la tempête au large.","La houle berçait les barques amarrées au port."],"exemplesIncorrects":["Il a coupé la houle en deux pour la partager.","La houle des montagnes était couverte de neige."],"distracteurs":["boule","foule","houx"],"anecdote":"Par image, une « houle de têtes » ou une « houle humaine » décrit une foule qui ondule comme la mer."},{"id":"prolixe","mot":"prolixe","nature":"adjectif","definitions":["Qui s\'exprime trop longuement, avec un excès de mots."],"phonetique":"/pʁɔ.liks/","etymologie":"Du latin prolixus, « étendu, abondant ».","registre":"soutenu","niveau":4,"themes":["abstrait"],"synonymes":["bavard","verbeux","diffus","loquace"],"antonymes":["laconique","concis","succinct"],"exemplesCorrects":["L\'auteur, trop prolixe, dilue ses meilleures idées.","Il fut prolixe sur ses voyages, avare sur ses échecs.","Une préface prolixe décourage parfois la lecture."],"exemplesIncorrects":["Son style prolixe tenait en trois mots cinglants.","Réponse prolixe : il se contenta d\'un hochement de tête."],"distracteurs":["complexe","prolifique","prologue","proche"],"anecdote":"Attention au faux ami : « prolifique » se rapporte à l\'abondance des œuvres, « prolixe » à l\'abondance, souvent excessive, des paroles."},{"id":"laconique","mot":"laconique","nature":"adjectif","definitions":["Qui s\'exprime en peu de mots ; bref et concis."],"phonetique":"/la.kɔ.nik/","etymologie":"De Laconie, région de Sparte dont les habitants passaient pour avares de mots.","registre":"soutenu","niveau":4,"themes":["abstrait"],"synonymes":["concis","bref","lapidaire","succinct"],"antonymes":["prolixe","verbeux","bavard"],"exemplesCorrects":["Sa réponse fut laconique : « non ».","Le communiqué, volontairement laconique, n\'expliquait rien.","Il avait l\'art des formules laconiques et définitives."],"exemplesIncorrects":["Son discours laconique a duré plus de deux heures.","Il fut si laconique qu\'on ne put l\'arrêter de parler."],"distracteurs":["ironique","lacustre","canonique"],"anecdote":"Sommés par Philippe de Macédoine de se rendre « si » il entrait en Laconie, les Spartiates répondirent un seul mot : « Si. » Le laconisme en personne."},{"id":"thuriferaire","mot":"thuriféraire","nature":"nom masculin","definitions":["Flatteur empressé, admirateur servile.","Clerc qui porte l\'encensoir lors des cérémonies."],"phonetique":"/ty.ʁi.fe.ʁɛʁ/","etymologie":"Du latin thus, turis, « encens », et ferre, « porter ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["flagorneur","courtisan","laudateur","encenseur"],"antonymes":["détracteur","contempteur","critique"],"exemplesCorrects":["Le ministre était entouré de thuriféraires complaisants.","Loin des thuriféraires, elle préférait les critiques sincères.","L\'écrivain méprisait les thuriféraires qui louaient tout sans lire."],"exemplesIncorrects":["Il a réparé le thuriféraire de la chaudière.","Le thuriféraire de la rivière débordait après l\'orage."],"distracteurs":["vexillaire","secrétaire","tributaire"],"anecdote":"Du clerc qui balance l\'encensoir au flatteur qui « encense » son maître, le mot a glissé du rite religieux à la satire des cours."},{"id":"epigone","mot":"épigone","nature":"nom masculin","definitions":["Successeur ou imitateur sans originalité d\'un maître, d\'une école."],"phonetique":"/e.pi.ɡɔn/","etymologie":"Du grec epigonos, « né après », nom des fils des Sept chefs contre Thèbes.","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["imitateur","suiveur","disciple","continuateur"],"antonymes":["précurseur","initiateur","novateur"],"exemplesCorrects":["Ce peintre n\'est qu\'un épigone des grands maîtres flamands.","Les épigones du romantisme en ont épuisé les recettes.","Mieux vaut un précurseur maladroit qu\'un épigone habile."],"exemplesIncorrects":["Il a commandé un épigone bien cuit au restaurant.","L\'épigone soufflait en tempête sur la baie."],"distracteurs":["épigramme","antigone","épopée"],"anecdote":"Dans la mythologie grecque, les Épigones sont les fils qui reprirent la guerre de leurs pères contre Thèbes : des héritiers, jamais des fondateurs."},{"id":"nonobstant","mot":"nonobstant","nature":"préposition","definitions":["Sans être empêché par ; malgré, en dépit de."],"phonetique":"/nɔ.nɔp.stɑ̃/","etymologie":"De non et de l\'ancien participe obstant, du latin obstare, « faire obstacle ».","registre":"soutenu","niveau":5,"themes":["abstrait"],"synonymes":["malgré","en dépit de","nonobstant"],"antonymes":["à cause de","grâce à"],"exemplesCorrects":["Nonobstant ses réticences, il finit par accepter.","La séance se tint, nonobstant l\'absence du président.","Nonobstant toute clause contraire, l\'accord prévaut."],"exemplesIncorrects":["Il a réparé le nonobstant de la voiture au garage.","Le nonobstant tombait à gros flocons sur la ville."],"distracteurs":["néanmoins","obstiné","nonchalant"],"anecdote":"Mot du langage juridique, « nonobstant » garde un parfum d\'actes notariés ; l\'employer ailleurs relève d\'une élégance un brin désuète."},{"id":"perorer","mot":"pérorer","nature":"verbe","definitions":["Discourir longuement et avec emphase, en se croyant brillant."],"phonetique":"/pe.ʁɔ.ʁe/","etymologie":"Du latin perorare, « conclure un discours, plaider jusqu\'au bout ».","registre":"soutenu","niveau":4,"themes":["abstrait"],"synonymes":["discourir","pontifier","disserter","déclamer"],"antonymes":["se taire","écouter"],"exemplesCorrects":["Il pérorait au centre du salon, ravi de son auditoire.","Au lieu de pérorer, il ferait mieux d\'agir.","On le laissa pérorer une heure sans l\'interrompre."],"exemplesIncorrects":["Elle pérorait dans le plus grand silence, sans dire un mot.","Il a pérorè le mur du jardin avant l\'hiver."],"distracteurs":["perforer","déplorer","péricliter"],"anecdote":"À l\'origine simple terme de rhétorique pour « conclure », le mot a pris sa teinte ironique : pérorer, c\'est parler pour s\'écouter parler."},{"id":"baguenauder","mot":"baguenauder","nature":"verbe","definitions":["Flâner sans but, perdre son temps à des riens."],"phonetique":"/baɡ.no.de/","etymologie":"De baguenaude, fruit creux du baguenaudier, sans valeur.","registre":"soutenu","niveau":4,"themes":["quotidien","litteraire"],"synonymes":["flâner","musarder","déambuler","lambiner"],"antonymes":["s\'activer","se hâter","besogner"],"exemplesCorrects":["Il aimait baguenauder le long des quais le dimanche.","Au lieu de réviser, elle baguenaudait dans les librairies.","Nous avons baguenaudé tout l\'après-midi, sans plan ni montre."],"exemplesIncorrects":["Pressé, il baguenauda jusqu\'à la gare en deux minutes.","Il a baguenaudé un magnifique rapport en une nuit."],"distracteurs":["baliverner","bagarrer","badigeonner"],"anecdote":"Le baguenaudier porte des gousses gonflées qui éclatent sous les doigts : s\'amuser à les faire claquer, c\'était « baguenauder », perdre son temps."},{"id":"amadouer","mot":"amadouer","nature":"verbe","definitions":["Disposer favorablement quelqu\'un par des paroles douces ou flatteuses."],"phonetique":"/a.ma.dwe/","etymologie":"De amadou, matière qui s\'enflamme aisément, d\'où « rendre malléable ».","registre":"courant","niveau":3,"themes":["abstrait","emotions"],"synonymes":["enjôler","cajoler","apprivoiser","embobiner"],"antonymes":["braquer","rebuter","indisposer"],"exemplesCorrects":["Il tenta d\'amadouer le douanier d\'un sourire.","Quelques compliments suffirent à l\'amadouer.","On n\'amadoue pas si facilement un adversaire méfiant."],"exemplesIncorrects":["Furieux, il amadoua la porte d\'un grand coup de pied.","Il a amadoué le bois pour construire la cabane."],"distracteurs":["amocher","amarrer","amender","ambler"],"anecdote":"L\'amadou, ce champignon séché qui prend feu à la moindre étincelle, a donné l\'image : amadouer, c\'est rendre l\'autre aussi inflammable, aussi prêt à céder."},{"id":"aurore","mot":"aurore","nature":"nom féminin","definitions":["Lueur rosée qui précède le lever du soleil.","Commencement, naissance de quelque chose."],"phonetique":"/o.ʁɔʁ/","etymologie":"Du latin aurora, « lumière du matin ».","registre":"courant","niveau":1,"themes":["nature","litteraire"],"synonymes":["aube","point du jour","commencement"],"antonymes":["crépuscule","déclin","tombée de la nuit"],"exemplesCorrects":["Ils partirent dès l\'aurore, avant que la chaleur ne monte.","On voyait poindre l\'aurore derrière les collines.","Ce fut l\'aurore d\'une ère nouvelle pour la science."],"exemplesIncorrects":["Il alluma les lampes en pleine aurore de minuit.","L\'aurore tomba lentement et la nuit s\'installa."],"distracteurs":["aurône","augure","auréole"],"anecdote":"L\'aurore boréale doit son nom à cette déesse latine du matin : une lumière qui semble, elle aussi, annoncer un jour qui ne vient pas."},{"id":"bredouiller","mot":"bredouiller","nature":"verbe","definitions":["Parler de façon précipitée et confuse, en articulant mal."],"phonetique":"/bʁə.du.je/","etymologie":"Origine incertaine, d\'un radical expressif évoquant le bafouillage.","registre":"courant","niveau":1,"themes":["quotidien"],"synonymes":["balbutier","bafouiller","marmonner","bégayer"],"antonymes":["articuler","déclamer","scander"],"exemplesCorrects":["Intimidé, il bredouilla quelques excuses incompréhensibles.","Elle bredouilla son nom, rouge de confusion.","Ne bredouille pas : reprends calmement depuis le début."],"exemplesIncorrects":["Il bredouilla son discours avec une éloquence parfaite.","Elle a bredouillé le mur de la cuisine en bleu."],"distracteurs":["gazouiller","barbouiller","brandiller"],"anecdote":"Au jeu de trictrac, « bredouille » désignait une victoire écrasante ; revenir « bredouille » de la chasse, c\'est, lui, rentrer les mains vides."},{"id":"ribambelle","mot":"ribambelle","nature":"nom féminin","definitions":["Longue suite, grand nombre de personnes ou de choses."],"phonetique":"/ʁi.bɑ̃.bɛl/","etymologie":"Origine incertaine, peut-être de riban, « ruban », d\'où l\'idée d\'une longue file.","registre":"courant","niveau":2,"themes":["quotidien"],"synonymes":["kyrielle","flopée","multitude","cohorte"],"antonymes":["poignée","minorité"],"exemplesCorrects":["Une ribambelle d\'enfants suivait le marchand de glaces.","Il a posé une ribambelle de questions sans attendre les réponses.","Toute une ribambelle de cousins débarqua pour les fêtes."],"exemplesIncorrects":["Il ne restait qu\'une ribambelle de spectateurs : trois personnes.","Elle a bu une ribambelle bien fraîche au comptoir."],"distracteurs":["ritournelle","sarabande","farandole"],"anecdote":"Le mot évoque une guirlande de figurines en papier découpé qui se déplient en file : une image parfaite de la profusion."},{"id":"babiole","mot":"babiole","nature":"nom féminin","definitions":["Objet de peu de valeur ; chose sans importance."],"phonetique":"/ba.bjɔl/","etymologie":"De l\'italien babbola, « bagatelle, niaiserie ».","registre":"familier","niveau":2,"themes":["quotidien"],"synonymes":["bagatelle","bricole","babiole","colifichet"],"antonymes":["trésor","merveille"],"exemplesCorrects":["Il rapporte toujours des babioles de ses voyages.","Ne dépense pas tout ton argent en babioles.","Ce que tu prends pour une babiole a une grande valeur sentimentale."],"exemplesIncorrects":["Ce diamant rarissime n\'est qu\'une babiole inestimable.","Il a signé un contrat de plusieurs millions pour cette babiole."],"distracteurs":["bestiole","gondole","faribole"],"anecdote":"« Babiole », « bricole », « broutille », « bagatelle » : le français ne manque pas de mots tendres pour ce qui ne pèse rien."},{"id":"placide","mot":"placide","nature":"adjectif","definitions":["D\'un calme que rien ne trouble ; paisible."],"phonetique":"/pla.sid/","etymologie":"Du latin placidus, « paisible, doux ».","registre":"courant","niveau":2,"themes":["emotions"],"synonymes":["paisible","serein","tranquille","imperturbable"],"antonymes":["agité","nerveux","irascible"],"exemplesCorrects":["Il gardait un air placide au milieu du tumulte.","La placide rivière reflétait les nuages.","Sa placide assurance finissait par agacer ses adversaires."],"exemplesIncorrects":["Furieux, il entra d\'un pas placide en claquant la porte.","La mer placide se déchaînait contre les rochers."],"distracteurs":["lucide","candide","limpide"],"anecdote":"Le prénom Placide, porté par des saints réputés pour leur douceur, vient directement de cet adjectif latin."},{"id":"maussade","mot":"maussade","nature":"adjectif","definitions":["D\'humeur sombre, peu aimable.","Terne, déplaisant, en parlant du temps ou d\'un lieu."],"phonetique":"/mo.sad/","etymologie":"De l\'ancien français mal sade, « désagréable », de sade, « plaisant ».","registre":"courant","niveau":2,"themes":["emotions"],"synonymes":["morose","renfrogné","chagrin","terne"],"antonymes":["enjoué","avenant","radieux"],"exemplesCorrects":["Il restait maussade malgré la bonne nouvelle.","Un ciel maussade pesait sur la ville depuis trois jours.","Elle répondit d\'un ton maussade, sans lever les yeux."],"exemplesIncorrects":["Quelle journée maussade : grand soleil et ciel sans nuage !","Il accueillit ses amis d\'un sourire maussade et chaleureux."],"distracteurs":["moussu","massif","mauresque","musardise"],"anecdote":"Le mot cache son contraire : « sade » signifiait « agréable », du latin sapidus, « qui a du goût », d\'où vient aussi « savoureux »."},{"id":"ephemere","mot":"éphémère","nature":"adjectif","definitions":["Qui ne dure qu\'un temps très court ; passager."],"phonetique":"/e.fe.mɛʁ/","etymologie":"Du grec ephêmeros, « qui ne dure qu\'un jour », de epi et hêmera, « jour ».","registre":"courant","niveau":2,"themes":["abstrait","litteraire"],"synonymes":["passager","fugace","transitoire","précaire"],"antonymes":["durable","pérenne","éternel"],"exemplesCorrects":["La gloire est souvent éphémère.","Ils profitèrent d\'une éphémère accalmie pour sortir.","Les fleurs éphémères ne tiennent qu\'une matinée."],"exemplesIncorrects":["Ce monument éphémère traverse les siècles sans une ride.","Leur amitié éphémère dura toute une vie."],"distracteurs":["épidémie","éphéméride","éthéré"],"anecdote":"L\'éphémère est aussi un insecte qui, adulte, ne vit que quelques heures : un nom qui dit toute la brièveté de son existence."},{"id":"limpide","mot":"limpide","nature":"adjectif","definitions":["Parfaitement clair et transparent.","Facile à comprendre."],"phonetique":"/lɛ̃.pid/","etymologie":"Du latin limpidus, « clair, transparent ».","registre":"courant","niveau":2,"themes":["abstrait","nature"],"synonymes":["transparent","clair","cristallin","diaphane"],"antonymes":["trouble","opaque","obscur"],"exemplesCorrects":["L\'eau limpide laissait voir le fond du torrent.","Son explication était d\'une clarté limpide.","Un ciel limpide s\'étendait au-dessus des montagnes."],"exemplesIncorrects":["L\'eau limpide était si boueuse qu\'on n\'y voyait rien.","Ce raisonnement limpide laissa tout le monde perplexe."],"distracteurs":["lipide","intrépide","insipide"],"anecdote":"Sa parenté avec « lymphe » n\'est pas fortuite : tous deux descendent d\'une même idée d\'eau claire et pure."},{"id":"bise","mot":"bise","nature":"nom féminin","definitions":["Vent du nord, sec et froid."],"phonetique":"/biz/","etymologie":"D\'origine germanique, bisa, « vent du nord ».","registre":"courant","niveau":2,"themes":["nature"],"synonymes":["vent du nord","froidure"],"antonymes":["zéphyr","brise tiède"],"exemplesCorrects":["La bise glaciale balayait la place déserte.","On rentrait le col relevé contre la bise.","« Quand la bise fut venue », commence la fable de la cigale."],"exemplesIncorrects":["La bise étouffante du désert nous accablait.","Il transpirait sous la bise tropicale de midi."],"distracteurs":["brise","balise","braise"],"anecdote":"À ne pas confondre avec la bise que l\'on fait sur la joue : ce sont deux mots distincts, l\'un venté, l\'autre affectueux."},{"id":"tintamarre","mot":"tintamarre","nature":"nom masculin","definitions":["Grand bruit discordant, vacarme assourdissant."],"phonetique":"/tɛ̃.ta.maʁ/","etymologie":"Formation expressive, de tinter et d\'un élément obscur -marre.","registre":"courant","niveau":3,"themes":["quotidien"],"synonymes":["vacarme","tapage","raffut","charivari"],"antonymes":["silence","quiétude"],"exemplesCorrects":["Les casseroles tombèrent dans un tintamarre épouvantable.","Quel tintamarre, ces klaxons aux heures de pointe !","La fanfare passa dans un joyeux tintamarre."],"exemplesIncorrects":["Un tintamarre de silence régnait dans la bibliothèque.","Il a savouré un tintamarre bien glacé au dessert."],"distracteurs":["tintement","tartine","tintouin"],"anecdote":"En Acadie, le « Tintamarre » est devenu une fête : on défile en faisant le plus de bruit possible pour affirmer joyeusement sa présence."},{"id":"ferveur","mot":"ferveur","nature":"nom féminin","definitions":["Ardeur enthousiaste, élan passionné du cœur ou de l\'esprit."],"phonetique":"/fɛʁ.vœʁ/","etymologie":"Du latin fervor, « chaleur, bouillonnement », de fervere, « bouillir ».","registre":"soutenu","niveau":3,"themes":["emotions"],"synonymes":["ardeur","zèle","enthousiasme","élan"],"antonymes":["tiédeur","indifférence","apathie"],"exemplesCorrects":["Elle défendait ses idées avec ferveur.","Les fidèles priaient avec une ferveur recueillie.","Il étudiait la musique avec une ferveur de tous les instants."],"exemplesIncorrects":["Il accomplit la corvée avec une ferveur résignée et morne.","La ferveur du congélateur conservait les aliments."],"distracteurs":["fraîcheur","faveur","ferraille","fervent"],"anecdote":"La ferveur « bout » au sens propre : la même racine latine a donné « effervescence » et « fervent »."},{"id":"engouement","mot":"engouement","nature":"nom masculin","definitions":["Enthousiasme vif et souvent passager pour quelqu\'un ou quelque chose."],"phonetique":"/ɑ̃.ɡu.mɑ̃/","etymologie":"De s\'engouer, « s\'étrangler en avalant », d\'où « se passionner soudain ».","registre":"courant","niveau":3,"themes":["emotions","abstrait"],"synonymes":["emballement","toquade","passion","enthousiasme"],"antonymes":["désaffection","indifférence","lassitude"],"exemplesCorrects":["L\'engouement du public pour ce jeu fut foudroyant.","Son engouement pour la photographie ne dura qu\'un été.","On assista à un engouement général pour ces vélos électriques."],"exemplesIncorrects":["Son profond engouement le poussa à tout abandonner par ennui.","Il a rangé l\'engouement dans le tiroir du salon."],"distracteurs":["engourdissement","enjouement","agencement"],"anecdote":"Le sens vient de l\'image de l\'étouffement : s\'engouer, c\'était avaler de travers ; la passion soudaine vous « prend à la gorge » de la même façon."},{"id":"quietude","mot":"quiétude","nature":"nom féminin","definitions":["Calme paisible, tranquillité de l\'âme."],"phonetique":"/kje.tyd/","etymologie":"Du latin quietudo, « repos », de quies, « tranquillité ».","registre":"soutenu","niveau":3,"themes":["emotions"],"synonymes":["sérénité","tranquillité","paix","ataraxie"],"antonymes":["inquiétude","agitation","trouble"],"exemplesCorrects":["Il goûtait la quiétude du soir au bord de l\'étang.","Rien ne troublait la quiétude de ce village reculé.","Elle travaillait dans la quiétude de l\'aube."],"exemplesIncorrects":["La quiétude de la bataille assourdissait les soldats.","Il bondit de quiétude en apprenant la catastrophe."],"distracteurs":["inquiétude","quotité","habitude"],"anecdote":"Son contraire, « inquiétude », est bien plus courant : la langue dit peut-être par là que le repos de l\'âme se remarque surtout quand il manque."},{"id":"taciturne","mot":"taciturne","nature":"adjectif","definitions":["Qui parle peu, d\'un naturel silencieux et renfermé."],"phonetique":"/ta.si.tyʁn/","etymologie":"Du latin taciturnus, « silencieux », de tacere, « se taire ».","registre":"soutenu","niveau":3,"themes":["emotions"],"synonymes":["silencieux","renfermé","réservé","sombre"],"antonymes":["loquace","volubile","expansif"],"exemplesCorrects":["C\'était un homme taciturne, qui pesait chacun de ses mots.","Elle devint taciturne après cette épreuve.","Le voyage se fit dans un silence taciturne."],"exemplesIncorrects":["Taciturne, il n\'arrêtait pas de raconter des histoires.","La fontaine taciturne murmurait jour et nuit."],"distracteurs":["nocturne","saturne","taquin"],"anecdote":"Guillaume d\'Orange fut surnommé « le Taciturne », non par mutisme, mais pour son art de garder un secret d\'État sans broncher."},{"id":"mantra","mot":"mantra","nature":"nom masculin","definitions":["Formule sacrée que l\'on répète, dans l\'hindouisme et le bouddhisme.","Phrase répétée comme un principe directeur."],"phonetique":"/mɑ̃.tʁa/","etymologie":"Du sanskrit mantra, « formule, parole sacrée ».","registre":"courant","niveau":3,"themes":["emprunts","abstrait"],"synonymes":["formule","incantation","devise","leitmotiv"],"antonymes":[],"exemplesCorrects":["Il répétait son mantra, assis en tailleur, les yeux clos.","« Rester simple » était devenu son mantra professionnel.","La méditation s\'accompagnait d\'un mantra murmuré."],"exemplesIncorrects":["Il a réparé le mantra crevé de son vélo.","Le mantra de la rivière débordait après l\'orage."],"distracteurs":["mantille","mandala","matraque"],"anecdote":"Le mot a quitté les temples pour le langage courant : on parle désormais du « mantra » d\'une entreprise comme d\'une formule répétée à l\'envi."},{"id":"saga","mot":"saga","nature":"nom féminin","definitions":["Récit héroïque médiéval scandinave.","Longue histoire mouvementée, souvent familiale."],"phonetique":"/sa.ɡa/","etymologie":"Du vieux norrois saga, « récit, ce qui est raconté ».","registre":"courant","niveau":3,"themes":["emprunts","litteraire"],"synonymes":["épopée","chronique","geste"],"antonymes":[],"exemplesCorrects":["Les sagas islandaises content les exploits des premiers colons.","Ce roman retrace la saga d\'une dynastie d\'industriels.","Leur procès interminable est devenu une véritable saga."],"exemplesIncorrects":["Il a commandé une saga bien cuite au restaurant.","La saga soufflait fort sur la côte cette nuit-là."],"distracteurs":["soga","sage","sagaie","sagouin"],"anecdote":"Les sagas, d\'abord transmises oralement, furent fixées par écrit au XIIIᵉ siècle : on leur doit une part immense de la mythologie nordique."},{"id":"toundra","mot":"toundra","nature":"nom féminin","definitions":["Vaste plaine glacée des régions arctiques, à la végétation rase."],"phonetique":"/tun.dʁa/","etymologie":"Du russe tundra, lui-même emprunté au same (lapon).","registre":"courant","niveau":3,"themes":["emprunts","nature"],"synonymes":["steppe arctique"],"antonymes":["jungle","forêt tropicale"],"exemplesCorrects":["Les rennes traversaient la toundra à la recherche de lichen.","En été, la toundra se couvre brièvement de fleurs.","Rien n\'arrête le vent sur l\'immense toundra."],"exemplesIncorrects":["La toundra luxuriante regorgeait de palmiers.","Il a planté une toundra dans son jardin au printemps."],"distracteurs":["tarentule","tundra","toupie"],"anecdote":"Sous la toundra, le sol gelé en permanence, le permafrost, emprisonne d\'énormes quantités de carbone, ce qui en fait un enjeu climatique majeur."},{"id":"geyser","mot":"geyser","nature":"nom masculin","definitions":["Source d\'eau chaude qui jaillit par intermittence en hautes colonnes."],"phonetique":"/ʒe.zɛʁ/","etymologie":"De l\'islandais Geysir, nom d\'une source jaillissante, de geysa, « jaillir ».","registre":"courant","niveau":2,"themes":["emprunts","nature"],"synonymes":["source jaillissante","fontaine bouillonnante"],"antonymes":[],"exemplesCorrects":["Le geyser projetait son panache d\'eau brûlante toutes les heures.","Les touristes attendaient l\'éruption du geyser.","Un geyser de boue surgissait du sol volcanique."],"exemplesIncorrects":["Le geyser gelé n\'avait pas coulé depuis des années.","Il a accroché le geyser au mur du salon."],"distracteurs":["gésier","geôlier","glacier"],"anecdote":"Tous les geysers du monde portent, indirectement, le nom du grand Geysir d\'Islande, le premier décrit par les voyageurs européens."},{"id":"nonante","mot":"nonante","nature":"adjectif","definitions":["En Belgique et en Suisse, le nombre quatre-vingt-dix."],"phonetique":"/nɔ.nɑ̃t/","etymologie":"Du latin nonaginta, « quatre-vingt-dix ».","registre":"courant","niveau":3,"themes":["regionalismes"],"synonymes":["quatre-vingt-dix"],"antonymes":[],"exemplesCorrects":["En Suisse, on compte octante ou huitante, puis nonante.","Le grand-père belge approchait des nonante ans.","Nonante-neuf est plus simple à dire que quatre-vingt-dix-neuf."],"exemplesIncorrects":["Il a acheté une nonante toute neuve au marché.","La nonante du moteur faisait un bruit inquiétant."],"distracteurs":["soixante","nuance","septante"],"anecdote":"« Septante », « octante » et « nonante » forment un système régulier que la France a perdu : nos « quatre-vingts » étonnent souvent nos voisins francophones."},{"id":"poutine","mot":"poutine","nature":"nom féminin","definitions":["Plat québécois de frites nappées de sauce brune et de fromage en grains."],"phonetique":"/pu.tin/","etymologie":"Mot québécois d\'origine incertaine, peut-être de l\'anglais pudding, « mélange ».","registre":"familier","niveau":2,"themes":["regionalismes","quotidien"],"synonymes":[],"antonymes":[],"exemplesCorrects":["Après le match, on s\'est partagé une grosse poutine.","La vraie poutine se reconnaît au crissement du fromage.","Chaque cabane à frites a sa recette de poutine."],"exemplesIncorrects":["Il a garé sa poutine devant la mairie.","La poutine de la rivière était en crue ce matin."],"distracteurs":["praline","tartine","routine"],"anecdote":"Née dans le Québec rural des années 1950, la poutine est devenue un emblème national, déclinée aujourd\'hui en dizaines de variantes."},{"id":"magasiner","mot":"magasiner","nature":"verbe","definitions":["Au Québec, faire des courses, du lèche-vitrine."],"phonetique":"/ma.ɡa.zi.ne/","etymologie":"Dérivé de magasin ; calque de l\'anglais to shop.","registre":"familier","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["faire les boutiques","faire les magasins"],"antonymes":[],"exemplesCorrects":["On va magasiner au centre commercial cet après-midi.","Elle aime magasiner les soldes de fin de saison.","Avant d\'acheter, il faut magasiner pour comparer les prix."],"exemplesIncorrects":["Il a magasiné le mur de la cuisine en jaune.","Le ciel magasinait à gros nuages au-dessus du fleuve."],"distracteurs":["emmagasiner","marchander","ramasser"],"anecdote":"Là où le Français « fait les magasins », le Québécois « magasine » : un verbe que le français de France n\'a jamais formé, faute d\'en sentir le besoin."},{"id":"dreve","mot":"drève","nature":"nom féminin","definitions":["En Belgique et dans le Nord, allée bordée d\'arbres."],"phonetique":"/dʁɛv/","etymologie":"Du néerlandais dreef, « allée plantée d\'arbres ».","registre":"courant","niveau":4,"themes":["regionalismes","nature"],"synonymes":["allée","avenue arborée","charmille"],"antonymes":[],"exemplesCorrects":["Une longue drève de hêtres menait au château.","Ils se promenaient dans la drève ombragée.","La drève débouchait sur une clairière inattendue."],"exemplesIncorrects":["Il a bu une drève bien fraîche en terrasse.","La drève du moteur faisait un bruit inquiétant."],"distracteurs":["grève","trêve","drache"],"anecdote":"Beaucoup de lieux-dits belges s\'appellent « la Drève » : le mot a fixé dans la toponymie ces alignements d\'arbres hérités des grands domaines."},{"id":"lande","mot":"lande","nature":"nom féminin","definitions":["Étendue plate et inculte couverte de bruyère, d\'ajoncs et de genêts."],"phonetique":"/lɑ̃d/","etymologie":"Du gaulois landa, « terre, étendue dégagée ».","registre":"courant","niveau":3,"themes":["nature"],"synonymes":["brande","garrigue","friche"],"antonymes":["futaie","verger"],"exemplesCorrects":["La lande s\'étendait, mauve de bruyère, jusqu\'à l\'horizon.","Le vent sifflait sur la lande déserte.","Ils traversèrent une lande battue par la pluie."],"exemplesIncorrects":["La lande, plantée d\'immeubles, grouillait de monde.","Il a coupé une tranche de lande pour le dîner."],"distracteurs":["bande","amande","lente"],"anecdote":"Les landes de Gascogne, jadis marécageuses, furent plantées de pins au XIXᵉ siècle, formant la plus vaste forêt artificielle d\'Europe."},{"id":"calanque","mot":"calanque","nature":"nom féminin","definitions":["Crique étroite et profonde, aux parois rocheuses, du littoral méditerranéen."],"phonetique":"/ka.lɑ̃k/","etymologie":"Du provençal calanco, d\'un radical préroman cala, « crique, abri ».","registre":"courant","niveau":3,"themes":["nature"],"synonymes":["crique","anse","cale"],"antonymes":["large","haute mer"],"exemplesCorrects":["Ils plongèrent dans l\'eau turquoise de la calanque.","On n\'accède à cette calanque qu\'à pied ou en bateau.","Les calanques de Marseille attirent randonneurs et grimpeurs."],"exemplesIncorrects":["La calanque enneigée dominait toute la vallée.","Il a servi une calanque bien fraîche à ses invités."],"distracteurs":["palanque","calandre","carlingue"],"anecdote":"Les calanques entre Marseille et Cassis forment depuis 2012 un parc national, l\'un des rares à être à la fois terrestre, marin et périurbain."},{"id":"etiage","mot":"étiage","nature":"nom masculin","definitions":["Niveau le plus bas d\'un cours d\'eau ; débit minimal d\'une rivière."],"phonetique":"/e.tjaʒ/","etymologie":"Dérivé d\'un mot du Sud-Ouest signifiant « été » : le niveau atteint à la saison sèche.","registre":"soutenu","niveau":4,"themes":["nature"],"synonymes":["basses eaux"],"antonymes":["crue","hautes eaux"],"exemplesCorrects":["En période d\'étiage, on devine les galets du lit de la rivière.","L\'étiage sévère a contraint à limiter l\'irrigation.","Le pont laisse voir ses piles à l\'étiage."],"exemplesIncorrects":["L\'étiage déborda et inonda toute la plaine.","Il a savouré un étiage bien glacé au comptoir."],"distracteurs":["étirage","étuvage","héritage"],"anecdote":"Par métaphore économique, on parle de « l\'étiage » d\'une activité pour désigner son niveau le plus bas avant la reprise."},{"id":"ecueil","mot":"écueil","nature":"nom masculin","definitions":["Rocher à fleur d\'eau, dangereux pour la navigation.","Obstacle, difficulté contre laquelle on risque d\'échouer."],"phonetique":"/e.kœj/","etymologie":"Du latin scopulus, « rocher, écueil », par l\'intermédiaire du provençal.","registre":"soutenu","niveau":3,"themes":["nature","abstrait"],"synonymes":["récif","obstacle","embûche","piège"],"antonymes":["facilité","atout"],"exemplesCorrects":["Le navire évita de justesse les écueils de la passe.","La précipitation est le principal écueil de ce projet.","Il a su éviter l\'écueil de la caricature."],"exemplesIncorrects":["Cet écueil a rendu la traversée parfaitement sûre.","Il a planté un écueil dans son potager au printemps."],"distracteurs":["accueil","cercueil","orgueil"],"anecdote":"La métaphore est si naturelle qu\'on l\'oublie : « échouer », au figuré, garde la mémoire des bateaux brisés sur les écueils."},{"id":"mistral","mot":"mistral","nature":"nom masculin","definitions":["Vent violent, froid et sec, qui souffle du nord vers la Méditerranée dans la vallée du Rhône."],"phonetique":"/mis.tʁal/","etymologie":"Du provençal mistral, du latin magistralis, « du maître » : le vent maître.","registre":"courant","niveau":3,"themes":["nature"],"synonymes":["vent du nord"],"antonymes":["zéphyr","brise marine"],"exemplesCorrects":["Le mistral a soufflé trois jours, balayant le ciel jusqu\'au bleu.","Les cyprès pliaient sous les rafales du mistral.","Le mistral rend l\'air d\'une transparence éclatante."],"exemplesIncorrects":["Le mistral tropical et humide collait à la peau.","Il a versé du mistral dans son café pour le sucrer."],"distracteurs":["minéral","mistigri","littoral"],"anecdote":"On dit que le mistral, en chassant les nuages, « mange les nuages » : les Provençaux lui prêtent même une influence sur l\'humeur, parfois irritable, des habitants."},{"id":"susurrer","mot":"susurrer","nature":"verbe","definitions":["Dire à voix très basse, murmurer doucement."],"phonetique":"/sy.sy.ʁe/","etymologie":"Du latin susurrare, « murmurer », d\'origine onomatopéique.","registre":"soutenu","niveau":3,"themes":["quotidien","litteraire"],"synonymes":["murmurer","chuchoter","souffler","glisser"],"antonymes":["crier","hurler","clamer"],"exemplesCorrects":["Elle lui susurra quelques mots à l\'oreille.","Le vent susurrait dans les feuillages.","On susurrait dans les couloirs d\'étranges rumeurs."],"exemplesIncorrects":["Il susurra son ordre à pleins poumons d\'un bout à l\'autre du stade.","Elle a susurré le portail d\'un bleu éclatant."],"distracteurs":["suturer","sursauter","suspendre","subjuguer"],"anecdote":"Le mot imite ce qu\'il décrit : ses sifflantes répétées, « su-sur-rer », font entendre le murmure même qu\'il désigne."},{"id":"musarder","mot":"musarder","nature":"verbe","definitions":["Flâner, perdre son temps agréablement, s\'attarder à des riens."],"phonetique":"/my.zaʁ.de/","etymologie":"De muser, « perdre son temps, rêvasser ».","registre":"soutenu","niveau":3,"themes":["quotidien","litteraire"],"synonymes":["flâner","baguenauder","lambiner","traînasser"],"antonymes":["se hâter","s\'activer","filer"],"exemplesCorrects":["Il musardait le long des étals du marché.","Plutôt que de rentrer, elle musarda dans le parc.","On a musardé une heure devant les vitrines."],"exemplesIncorrects":["En retard, il musarda jusqu\'au bureau à toute allure.","Il a musardé un dossier complet en une nuit."],"distracteurs":["muser","museler","bavarder"],"anecdote":"« Muser » a aussi donné « amuser » : à l\'origine, amuser quelqu\'un, c\'était le faire « muser », le retenir agréablement à ne rien faire."},{"id":"ressasser","mot":"ressasser","nature":"verbe","definitions":["Revenir sans cesse sur les mêmes pensées, répéter inlassablement."],"phonetique":"/ʁə.sa.se/","etymologie":"De sas, « tamis » : repasser au crible, encore et encore.","registre":"courant","niveau":3,"themes":["abstrait","emotions"],"synonymes":["ruminer","rabâcher","remâcher","répéter"],"antonymes":["oublier","tourner la page"],"exemplesCorrects":["Il ressassait sans fin ses vieux griefs.","À quoi bon ressasser le passé ?","Elle ressassait la même question sans trouver de réponse."],"exemplesIncorrects":["Il a ressassé cette idée nouvelle pour la toute première fois.","Elle a ressassé le mur du salon d\'un beau vert."],"distracteurs":["ressaisir","tracasser","ressentir"],"anecdote":"L\'image est concrète : ressasser, c\'est repasser indéfiniment la même matière au tamis, le « sas », jusqu\'à n\'en plus rien tirer."},{"id":"vituperer","mot":"vitupérer","nature":"verbe","definitions":["Blâmer avec véhémence, élever des protestations indignées contre."],"phonetique":"/vi.ty.pe.ʁe/","etymologie":"Du latin vituperare, « blâmer, déprécier ».","registre":"soutenu","niveau":4,"themes":["abstrait"],"synonymes":["pester","fulminer","invectiver","fustiger"],"antonymes":["louer","approuver","féliciter"],"exemplesCorrects":["Il vitupérait contre la lenteur de l\'administration.","Au lieu de vitupérer, proposez des solutions.","Elle vitupéra ces décisions qu\'elle jugeait absurdes."],"exemplesIncorrects":["Ravi, il vitupéra son ami d\'un grand sourire reconnaissant.","Il a vitupéré la clôture du jardin avant l\'hiver."],"distracteurs":["récupérer","vociférer","vénérer"],"anecdote":"On « vitupère contre » plus souvent qu\'on ne « vitupère » quelqu\'un : la préposition s\'est imposée, malgré les puristes qui la jugent superflue."},{"id":"debonnaire","mot":"débonnaire","nature":"adjectif","definitions":["D\'une bonté un peu molle, d\'un naturel doux et accommodant."],"phonetique":"/de.bɔ.nɛʁ/","etymologie":"De l\'ancien français de bon aire, « de bonne race, de bon naturel ».","registre":"soutenu","niveau":4,"themes":["emotions"],"synonymes":["bonhomme","placide","accommodant","indulgent"],"antonymes":["sévère","autoritaire","acariâtre"],"exemplesCorrects":["Un patron débonnaire fermait les yeux sur les retards.","Il avait l\'air débonnaire d\'un grand-père comblé.","Sous ses dehors débonnaires, c\'était un fin stratège."],"exemplesIncorrects":["Le tyran débonnaire faisait régner la terreur.","Elle a peint la barrière d\'un débonnaire éclatant."],"distracteurs":["doctrinaire","milliardaire","débineur"],"anecdote":"Louis le Pieux, fils de Charlemagne, est aussi appelé « le Débonnaire » : à l\'époque, le mot vantait la noblesse de caractère plus que la mollesse."},{"id":"chafouin","mot":"chafouin","nature":"adjectif","definitions":["Qui a une mine sournoise et rusée."],"phonetique":"/ʃa.fwɛ̃/","etymologie":"De chat et fouine : à la mine d\'un petit animal rusé.","registre":"littéraire","niveau":4,"themes":["emotions","litteraire"],"synonymes":["sournois","matois","patelin","finaud"],"antonymes":["franc","ouvert","candide"],"exemplesCorrects":["Il arborait un petit air chafouin qui inspirait la méfiance.","Un sourire chafouin trahissait ses arrière-pensées.","Sa mine chafouine annonçait quelque mauvais tour."],"exemplesIncorrects":["Son visage chafouin respirait la franchise et la bonté.","Il a repeint sa chambre d\'un chafouin lumineux."],"distracteurs":["chagrin","babouin","chamois"],"anecdote":"Le mot soude deux bêtes à la réputation rusée, le chat et la fouine : la langue a fabriqué là un visage à partir d\'un bestiaire."},{"id":"brimborion","mot":"brimborion","nature":"nom masculin","definitions":["Petit objet sans valeur ; bagatelle."],"phonetique":"/bʁɛ̃.bɔ.ʁjɔ̃/","etymologie":"Altération de l\'ancien breborion, du latin breviarium, « bréviaire ».","registre":"littéraire","niveau":4,"themes":["quotidien","litteraire"],"synonymes":["babiole","colifichet","bagatelle","bricole"],"antonymes":["trésor","joyau"],"exemplesCorrects":["Son étagère croulait sous les brimborions rapportés de voyage.","Pourquoi t\'encombrer de tous ces brimborions ?","Un tiroir débordait de brimborions oubliés."],"exemplesIncorrects":["Ce collier de diamants est un brimborion d\'une valeur inestimable.","Il a dégusté un brimborion bien sucré au goûter."],"distracteurs":["histrion","morbidité","biberon"],"anecdote":"Curieux destin : du « bréviaire », livre de prières, le mot a glissé vers le menu objet sans importance, peut-être par moquerie des babioles dévotes."},{"id":"philippique","mot":"philippique","nature":"nom féminin","definitions":["Discours violent, réquisitoire véhément contre quelqu\'un."],"phonetique":"/fi.li.pik/","etymologie":"Des discours de Démosthène contre Philippe de Macédoine, puis de Cicéron contre Antoine.","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["réquisitoire","diatribe","satire","invective"],"antonymes":["éloge","panégyrique","apologie"],"exemplesCorrects":["Il se lança dans une philippique contre l\'hypocrisie des puissants.","Sa philippique enflammée laissa l\'assemblée stupéfaite.","L\'éditorial était une philippique contre la corruption."],"exemplesIncorrects":["Il prononça une tendre philippique pour féliciter la mariée.","Il a réparé la philippique de la voiture au garage."],"distracteurs":["polémique","périphérique","philharmonie"],"anecdote":"Le mot remonte à Démosthène, qui haranguait Athènes contre Philippe ; Cicéron reprit le genre contre Marc Antoine, qui le lui fit payer de sa vie."},{"id":"aporie","mot":"aporie","nature":"nom féminin","definitions":["Difficulté logique sans issue ; contradiction insoluble."],"phonetique":"/a.pɔ.ʁi/","etymologie":"Du grec aporia, « absence de passage, embarras ».","registre":"soutenu","niveau":5,"themes":["abstrait"],"synonymes":["impasse","contradiction","dilemme","antinomie"],"antonymes":["solution","issue","évidence"],"exemplesCorrects":["Le raisonnement aboutissait à une aporie embarrassante.","Les dialogues de Platon se closent souvent sur une aporie.","Devant cette aporie, la commission renonça à conclure."],"exemplesIncorrects":["La démonstration, d\'une aporie limpide, convainquit tout le monde.","Il a savouré une aporie bien fraîche au dessert."],"distracteurs":["agonie","allégorie","apostrophe"],"anecdote":"Socrate cultivait l\'aporie : pousser son interlocuteur jusqu\'à l\'aveu « je ne sais plus » était, pour lui, le vrai début de la philosophie."},{"id":"palinodie","mot":"palinodie","nature":"nom féminin","definitions":["Changement complet d\'opinion ; rétractation de ce qu\'on avait soutenu."],"phonetique":"/pa.li.nɔ.di/","etymologie":"Du grec palinôidia, « chant repris », de palin, « de nouveau », et ôidê, « chant ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["rétractation","revirement","volte-face","désaveu"],"antonymes":["constance","fidélité","persévérance"],"exemplesCorrects":["Sa palinodie surprit jusqu\'à ses plus proches alliés.","On l\'accusa de palinodie après ce brusque revirement.","Les palinodies répétées du ministre lassaient l\'opinion."],"exemplesIncorrects":["Sa palinodie inébranlable forçait l\'admiration de tous.","Il a planté une palinodie au fond du jardin."],"distracteurs":["mélodie","parodie","palissade"],"anecdote":"Le poète grec Stésichore aurait, dit-on, perdu la vue pour avoir médit d\'Hélène, et l\'aurait recouvrée en composant une palinodie qui la réhabilitait."},{"id":"sycophante","mot":"sycophante","nature":"nom masculin","definitions":["Délateur, dénonciateur de profession ; calomniateur."],"phonetique":"/si.kɔ.fɑ̃t/","etymologie":"Du grec sukophantês, « délateur », littéralement « qui dénonce les voleurs de figues ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["délateur","dénonciateur","calomniateur","mouchard"],"antonymes":["défenseur","avocat"],"exemplesCorrects":["Les sycophantes prospéraient sous ce régime de suspicion.","Il refusait de devenir le sycophante de ses collègues.","Athènes connut une engeance de sycophantes vénaux."],"exemplesIncorrects":["Ce sycophante intègre défendit l\'accusé avec courage.","Il a réparé le sycophante de la chaudière."],"distracteurs":["sarcophage","sycomore","éléphant"],"anecdote":"À Athènes, dénoncer l\'exportation illégale de figues aurait donné son nom à ces accusateurs publics, vite devenus l\'archétype du calomniateur intéressé."},{"id":"atavisme","mot":"atavisme","nature":"nom masculin","definitions":["Réapparition d\'un caractère hérité d\'un ancêtre lointain.","Comportement transmis par l\'hérédité, par tradition."],"phonetique":"/a.ta.vism/","etymologie":"Du latin atavus, « aïeul, ancêtre lointain ».","registre":"soutenu","niveau":5,"themes":["abstrait"],"synonymes":["hérédité","héritage","atavisme"],"antonymes":["innovation","rupture"],"exemplesCorrects":["Par atavisme, il avait le goût de la mer comme tous ses aïeux marins.","Cet atavisme paysan le ramenait toujours à la terre.","On expliquait sa prudence par un atavisme familial."],"exemplesIncorrects":["Son atavisme tout neuf n\'avait aucune racine dans le passé.","Il a bu un atavisme bien frais en terrasse."],"distracteurs":["altruisme","automatisme","ostracisme"],"anecdote":"Le mot fut forgé au XIXᵉ siècle par les naturalistes pour nommer ces ressemblances qui sautent une ou plusieurs générations avant de resurgir."},{"id":"casuistique","mot":"casuistique","nature":"nom féminin","definitions":["Partie de la morale qui résout les cas de conscience.","Subtilité excessive de raisonnement, ergotage."],"phonetique":"/ka.zɥis.tik/","etymologie":"Du latin casus, « cas » : l\'art de trancher les cas de conscience.","registre":"soutenu","niveau":5,"themes":["abstrait"],"synonymes":["argutie","ergotage","subtilité","sophistique"],"antonymes":["franchise","simplicité"],"exemplesCorrects":["Il se perdait dans une casuistique sans fin pour justifier l\'injustifiable.","La casuistique permettait d\'adapter la règle aux situations particulières.","Assez de casuistique : la question est simple."],"exemplesIncorrects":["Sa casuistique d\'une grande clarté tenait en une phrase.","Il a planté une casuistique dans son potager."],"distracteurs":["acoustique","caustique","balistique"],"anecdote":"Pascal, dans ses Provinciales, ridiculisa la casuistique des jésuites au point de donner au mot sa nuance péjorative d\'ergotage retors."},{"id":"prolegomenes","mot":"prolégomènes","nature":"nom masculin","definitions":["Longue introduction en tête d\'un ouvrage ; notions préliminaires."],"phonetique":"/pʁɔ.le.ɡɔ.mɛn/","etymologie":"Du grec prolegomena, « ce qui est dit en préliminaire ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["préliminaires","introduction","préambule","prémisses"],"antonymes":["conclusion","épilogue"],"exemplesCorrects":["Les prolégomènes de l\'ouvrage en exposent la méthode.","Kant a intitulé un livre « Prolégomènes à toute métaphysique future ».","Après d\'interminables prolégomènes, il en vint enfin au fait."],"exemplesIncorrects":["Les prolégomènes refermaient le livre par une belle conclusion.","Il a savouré des prolégomènes bien sucrés au goûter."],"distracteurs":["épiphénomènes","phénomènes","prolétaires"],"anecdote":"Le mot s\'emploie presque toujours au pluriel ; l\'utiliser au singulier, « un prolégomène », passe pour une coquetterie de pédant."},{"id":"oripeaux","mot":"oripeaux","nature":"nom masculin","definitions":["Vêtements voyants et défraîchis ; faux brillant, clinquant."],"phonetique":"/ɔ.ʁi.po/","etymologie":"De l\'ancien français orie pel, « peau dorée » : un clinquant qui imite l\'or.","registre":"littéraire","niveau":5,"themes":["quotidien","litteraire"],"synonymes":["clinquant","défroque","oripeaux","guenilles"],"antonymes":["sobriété","élégance"],"exemplesCorrects":["Sous les oripeaux du luxe se cachait une grande misère.","L\'acteur ôta ses oripeaux de scène.","Il dénonçait les oripeaux d\'une fausse modernité."],"exemplesIncorrects":["Elle portait de sobres oripeaux d\'une élégance discrète.","Il a dégusté des oripeaux bien chauds au dîner."],"distracteurs":["oripeau","barreaux","rideaux"],"anecdote":"Du sens propre de « faux or », le mot a glissé vers le figuré : les « oripeaux » d\'une doctrine, ce sont ses ornements trompeurs."},{"id":"pusillanime","mot":"pusillanime","nature":"adjectif","definitions":["Qui manque de courage et de fermeté ; craintif, timoré."],"phonetique":"/py.zi.la.nim/","etymologie":"Du latin pusillanimis, « qui a l\'âme petite ».","registre":"soutenu","niveau":5,"themes":["emotions"],"synonymes":["timoré","craintif","couard","veule"],"antonymes":["courageux","intrépide","magnanime"],"exemplesCorrects":["Trop pusillanime, il n\'osa jamais défendre ses idées.","Une réponse pusillanime déçut ses partisans.","Ce n\'est pas le moment de se montrer pusillanime."],"exemplesIncorrects":["Pusillanime, il chargea l\'ennemi sans la moindre hésitation.","Il a repeint la clôture d\'un pusillanime éclatant."],"distracteurs":["unanime","polysémie","magnanime"],"anecdote":"Mot à mot, le pusillanime a « l\'âme petite » ; son exact contraire latin, le magnanime, a « la grande âme »."},{"id":"concupiscence","mot":"concupiscence","nature":"nom féminin","definitions":["Penchant ardent vers les plaisirs des sens et les biens matériels."],"phonetique":"/kɔ̃.ky.pi.sɑ̃s/","etymologie":"Du latin concupiscentia, de concupiscere, « désirer ardemment ».","registre":"littéraire","niveau":5,"themes":["abstrait","emotions"],"synonymes":["convoitise","appétit","avidité","sensualité"],"antonymes":["tempérance","ascèse","continence"],"exemplesCorrects":["Les moralistes mettaient en garde contre la concupiscence.","Une lueur de concupiscence brillait dans son regard.","Il opposait l\'ascèse à toute forme de concupiscence."],"exemplesIncorrects":["Sa concupiscence ascétique l\'éloignait de tout plaisir.","Il a réparé la concupiscence de la voiture au garage."],"distracteurs":["réminiscence","concurrence","convalescence"],"anecdote":"Terme central de la théologie morale, la concupiscence désigne ce désir qui, selon la tradition chrétienne, subsiste en l\'homme et le porte vers les biens d\'ici-bas."},{"id":"diktat","mot":"diktat","nature":"nom masculin","definitions":["Exigence imposée par la force, sans négociation possible."],"phonetique":"/dik.tat/","etymologie":"De l\'allemand Diktat, « chose dictée, imposée ».","registre":"soutenu","niveau":4,"themes":["abstrait","emprunts"],"synonymes":["ultimatum","injonction","oukase","exigence"],"antonymes":["compromis","négociation","accord"],"exemplesCorrects":["Il refusa de se plier au diktat de l\'occupant.","Ce traité fut vécu comme un diktat humiliant.","Elle dénonçait le diktat de la mode."],"exemplesIncorrects":["Ce diktat fut le fruit d\'un long compromis amical.","Il a savouré un diktat bien sucré au dessert."],"distracteurs":["dictée","constat","digression","diatribe"],"anecdote":"Le mot est entré en français dans l\'entre-deux-guerres, l\'Allemagne ayant qualifié de « Diktat » le traité de Versailles qu\'elle jugeait imposé."},{"id":"nirvana","mot":"nirvana","nature":"nom masculin","definitions":["Dans le bouddhisme, extinction du désir et libération de la souffrance.","État de sérénité parfaite, béatitude."],"phonetique":"/niʁ.va.na/","etymologie":"Du sanskrit nirvana, « extinction (du désir) ».","registre":"courant","niveau":4,"themes":["emprunts","abstrait"],"synonymes":["béatitude","félicité","plénitude","sérénité"],"antonymes":["souffrance","tourment"],"exemplesCorrects":["Le bouddhisme vise l\'accès au nirvana.","Allongé au soleil, il atteignait une sorte de nirvana.","Ce silence absolu était pour elle un véritable nirvana."],"exemplesIncorrects":["Le nirvana de la bataille épuisait les soldats.","Il a garé son nirvana devant la mairie."],"distracteurs":["savane","caravane","nuance"],"anecdote":"Le mot signifie littéralement « extinction », comme celle d\'une flamme : non pas le néant, mais la fin de l\'agitation du désir."},{"id":"duende","mot":"duende","nature":"nom masculin","definitions":["Charme mystérieux et puissant qui émane d\'un artiste, d\'une œuvre."],"phonetique":"/dwɛn.de/","etymologie":"Mot espagnol, « lutin, esprit », puis grâce envoûtante d\'un interprète.","registre":"littéraire","niveau":5,"themes":["emprunts","emotions"],"synonymes":["magnétisme","grâce","charme","aura"],"antonymes":["fadeur","platitude"],"exemplesCorrects":["Cette danseuse de flamenco a un duende bouleversant.","Sans duende, la technique la plus parfaite reste froide.","Le poète Lorca a longuement médité sur le duende."],"exemplesIncorrects":["Il a réparé le duende crevé de son vélo.","Le duende tombait à gros flocons sur la ville."],"distracteurs":["duègne","duvet","détente"],"anecdote":"Federico García Lorca en fit le sujet d\'une célèbre conférence : le duende serait cette puissance obscure, presque douloureuse, qui distingue l\'art vivant du simple savoir-faire."},{"id":"gourou","mot":"gourou","nature":"nom masculin","definitions":["Maître spirituel, dans l\'hindouisme.","Personne très influente, guide d\'un groupe d\'adeptes."],"phonetique":"/ɡu.ʁu/","etymologie":"De l\'hindi guru, du sanskrit, « maître spirituel, vénérable ».","registre":"courant","niveau":3,"themes":["emprunts","abstrait"],"synonymes":["maître","mentor","guide","directeur"],"antonymes":["disciple","adepte","élève"],"exemplesCorrects":["Il s\'était fait gourou d\'une petite communauté.","On le présentait comme le gourou de la nouvelle cuisine.","Méfie-toi des gourous qui promettent le bonheur en dix leçons."],"exemplesIncorrects":["Il a planté un gourou au fond du jardin.","Le gourou de la rivière débordait après l\'orage."],"distracteurs":["verrou","garrot","ragoût"],"anecdote":"Du maître spirituel respecté, le mot a pris en Occident une teinte ambiguë : on parle aujourd\'hui de « gourou » du marketing comme d\'un meneur de secte."},{"id":"cicerone","mot":"cicérone","nature":"nom masculin","definitions":["Guide qui fait visiter une ville, un monument, et en commente les curiosités."],"phonetique":"/si.se.ʁon/","etymologie":"De l\'italien cicerone, de Cicéron, par allusion à l\'éloquence des guides.","registre":"soutenu","niveau":4,"themes":["emprunts"],"synonymes":["guide","accompagnateur"],"antonymes":["touriste","visiteur"],"exemplesCorrects":["Il nous servit de cicérone dans les ruelles de Venise.","Un cicérone érudit commentait chaque fresque.","Faute de cicérone, ils se perdirent dans la vieille ville."],"exemplesIncorrects":["Il a réparé le cicérone de la chaudière en deux minutes.","Le cicérone soufflait fort sur la côte cette nuit-là."],"distracteurs":["macédoine","cicatrice","chaperon"],"anecdote":"Les guides bavards d\'Italie furent surnommés « cicéroni » par dérision, tant leur faconde rappelait celle du grand orateur romain."},{"id":"dilettante","mot":"dilettante","nature":"nom masculin","definitions":["Personne qui s\'adonne à une activité par plaisir, en amateur, sans s\'y appliquer sérieusement."],"phonetique":"/di.le.tɑ̃t/","etymologie":"De l\'italien dilettante, « qui prend plaisir », du latin delectare, « charmer ».","registre":"courant","niveau":4,"themes":["emprunts","abstrait"],"synonymes":["amateur","fantaisiste","touche-à-tout"],"antonymes":["professionnel","spécialiste","expert"],"exemplesCorrects":["Il peint en dilettante, sans jamais exposer.","On lui reprochait de travailler en dilettante.","Ce dilettante éclairé connaissait mille choses sans rien approfondir."],"exemplesIncorrects":["Ce dilettante acharné s\'entraînait dix heures par jour.","Il a garé son dilettante devant la mairie."],"distracteurs":["débutante","militante","dilatation"],"anecdote":"Le mot vient du plaisir : le dilettante est d\'abord celui qui « se délecte ». La nuance de légèreté, voire de superficialité, est venue plus tard."},{"id":"huitante","mot":"huitante","nature":"adjectif","definitions":["En Suisse romande, le nombre quatre-vingts."],"phonetique":"/ɥi.tɑ̃t/","etymologie":"Du latin octoginta, « quatre-vingts ».","registre":"courant","niveau":3,"themes":["regionalismes"],"synonymes":["quatre-vingts","octante"],"antonymes":[],"exemplesCorrects":["Dans le canton de Vaud, on dit huitante, pas quatre-vingts.","La facture s\'élevait à huitante francs.","Il a fêté ses huitante ans entouré des siens."],"exemplesIncorrects":["Il a acheté une huitante toute neuve au marché.","La huitante du moteur faisait un bruit inquiétant."],"distracteurs":["soixante","habitante","nonante"],"anecdote":"« Huitante » survit surtout dans les cantons de Vaud, du Valais et de Fribourg ; ailleurs en Suisse, on entend parfois l\'ancien « octante »."},{"id":"estaminet","mot":"estaminet","nature":"nom masculin","definitions":["Dans le Nord, petit café populaire, débit de boissons convivial."],"phonetique":"/ɛs.ta.mi.nɛ/","etymologie":"Du wallon staminé, « petit café », d\'origine incertaine.","registre":"courant","niveau":3,"themes":["regionalismes","quotidien"],"synonymes":["bistrot","troquet","taverne","café"],"antonymes":[],"exemplesCorrects":["On refaisait le monde dans l\'estaminet du village.","L\'estaminet sentait la bière et le tabac froid.","Chaque dimanche, les joueurs de cartes envahissaient l\'estaminet."],"exemplesIncorrects":["Il a garé son estaminet devant la mairie.","L\'estaminet de la rivière était en crue ce matin."],"distracteurs":["estafette","robinet","estampe"],"anecdote":"Les estaminets flamands, avec leurs jeux traditionnels comme la grenouille ou le billard Nicolas, connaissent aujourd\'hui un fort renouveau touristique."},{"id":"biloute","mot":"biloute","nature":"nom masculin","definitions":["Dans le Nord, terme d\'affection familier adressé à un homme : « mon gars »."],"phonetique":"/bi.lut/","etymologie":"Mot ch\'ti (picard), terme affectueux populaire.","registre":"familier","niveau":3,"themes":["regionalismes"],"synonymes":["mon gars","mon vieux","copain"],"antonymes":[],"exemplesCorrects":["Ça va, biloute ? Viens t\'asseoir avec nous.","Allez, biloute, encore un petit effort !","Dans le Nord, on s\'appelle volontiers biloute entre amis."],"exemplesIncorrects":["Il a réglé sa biloute d\'électricité à temps.","La biloute du moteur refusait de démarrer."],"distracteurs":["bidule","mazoute","bicoque"],"anecdote":"Le film « Bienvenue chez les Ch\'tis » a fait connaître « biloute » à toute la France, au point d\'en faire un emblème affectueux du Nord."},{"id":"espante","mot":"espanté","nature":"adjectif","definitions":["Dans le Midi, stupéfait, ébahi, frappé d\'étonnement."],"phonetique":"/ɛs.pɑ̃.te/","etymologie":"De l\'occitan espantar, « stupéfier », du latin expaventare, « épouvanter ».","registre":"familier","niveau":4,"themes":["regionalismes","emotions"],"synonymes":["ébahi","stupéfait","estomaqué","sidéré"],"antonymes":["indifférent","blasé"],"exemplesCorrects":["J\'en suis resté espanté, je ne m\'y attendais pas !","Elle nous a regardés, toute espantée.","Il était espanté devant un tel spectacle."],"exemplesIncorrects":["Parfaitement espanté, il bâilla d\'ennui pendant le feu d\'artifice.","Il a repeint le mur d\'un espanté lumineux."],"distracteurs":["épaté","esquinté","écarté"],"anecdote":"« Espanté » partage sa racine avec « épouvante » : la même peur latine a donné, au Sud, un mot pour l\'ébahissement et, au Nord, un mot pour l\'effroi."},{"id":"poutou","mot":"poutou","nature":"nom masculin","definitions":["Dans le Midi et le Sud-Ouest, baiser affectueux, bise."],"phonetique":"/pu.tu/","etymologie":"De l\'occitan poutou, « baiser », de la famille de pot, « lèvre ».","registre":"familier","niveau":2,"themes":["regionalismes","emotions"],"synonymes":["bise","bisou","baiser"],"antonymes":[],"exemplesCorrects":["Allez, fais un poutou à ta mamie avant de partir.","Il lui claqua un gros poutou sur la joue.","Un dernier poutou et au lit, les enfants !"],"exemplesIncorrects":["Il a garé son poutou devant la mairie.","Le poutou de la rivière était en crue ce matin."],"distracteurs":["poutre","filou","doudou"],"anecdote":"Du Sud-Ouest, « poutou » a essaimé dans tout le français familier comme synonyme tendre de « bisou », surtout dans le langage adressé aux enfants."},{"id":"tourbiere","mot":"tourbière","nature":"nom féminin","definitions":["Marécage où s\'accumule la tourbe, formée de végétaux décomposés."],"phonetique":"/tuʁ.bjɛʁ/","etymologie":"Dérivé de tourbe, du francique turba, matière végétale des marais.","registre":"courant","niveau":4,"themes":["nature"],"synonymes":["marais","marécage","fagne"],"antonymes":["désert","steppe aride"],"exemplesCorrects":["La tourbière abrite des plantes carnivores et de rares libellules.","On extrayait jadis la tourbe de cette tourbière pour se chauffer.","Le sentier serpentait entre les flaques de la tourbière."],"exemplesIncorrects":["La tourbière, brûlante et sèche, n\'offrait pas une goutte d\'eau.","Il a servi une tourbière bien fraîche à ses invités."],"distracteurs":["tabatière","tourmente","théière"],"anecdote":"Les tourbières stockent d\'immenses quantités de carbone et conservent parfois, intacts pendant des millénaires, des corps qu\'on appelle « hommes des tourbières »."},{"id":"penombre","mot":"pénombre","nature":"nom féminin","definitions":["Lumière faible, demi-jour entre l\'ombre et la pleine clarté."],"phonetique":"/pe.nɔ̃bʁ/","etymologie":"Du latin paene, « presque », et umbra, « ombre ».","registre":"courant","niveau":2,"themes":["nature","litteraire"],"synonymes":["demi-jour","clair-obscur","obscurité"],"antonymes":["pleine lumière","clarté","éclat"],"exemplesCorrects":["Ses yeux s\'habituaient peu à peu à la pénombre de la cave.","Dans la pénombre du soir, les contours s\'estompaient.","Elle aimait lire dans la douce pénombre des après-midi d\'hiver."],"exemplesIncorrects":["En pleine pénombre de midi, le soleil aveuglait les passants.","Il a coupé une tranche de pénombre pour le dîner."],"distracteurs":["encombre","décombre","concombre"],"anecdote":"En astronomie, la pénombre est la zone d\'ombre partielle d\'une éclipse : là où l\'astre n\'est caché qu\'à moitié."},{"id":"onde","mot":"onde","nature":"nom féminin","definitions":["En poésie, eau d\'un lac, d\'une rivière, de la mer.","Mouvement vibratoire qui se propage."],"phonetique":"/ɔ̃d/","etymologie":"Du latin unda, « eau, vague ».","registre":"littéraire","niveau":2,"themes":["nature","litteraire"],"synonymes":["flot","eau","vague","onde"],"antonymes":["rive","terre ferme"],"exemplesCorrects":["Le cygne glissait sur l\'onde immobile.","Une onde de choc parcourut l\'assemblée.","La lune se reflétait dans l\'onde tremblante."],"exemplesIncorrects":["Il a empilé trois ondes dans le placard de la cuisine.","L\'onde poussiéreuse du désert montait jusqu\'aux dunes."],"distracteurs":["ronde","monde","sonde"],"anecdote":"« Sur l\'onde » est une cheville de la poésie classique pour dire « sur l\'eau » ; le mot a gardé ce parfum noble que « flotte » a perdu."},{"id":"embacle","mot":"embâcle","nature":"nom masculin","definitions":["Amas de glaces qui obstrue un cours d\'eau ; obstruction d\'une rivière."],"phonetique":"/ɑ̃.bɑkl/","etymologie":"De embâcler, « obstruer » ; contraire de débâcle.","registre":"soutenu","niveau":5,"themes":["nature"],"synonymes":["obstruction","barrage de glace"],"antonymes":["débâcle","dégel"],"exemplesCorrects":["L\'embâcle menaçait d\'inonder les rives au moment du dégel.","Un embâcle de troncs bloquait le cours de la rivière.","Les pompiers surveillaient l\'embâcle formé sous le pont."],"exemplesIncorrects":["L\'embâcle libéra soudain le courant, qui s\'écoula librement.","Il a savouré un embâcle bien glacé au comptoir."],"distracteurs":["débâcle","obstacle","réceptacle"],"anecdote":"L\'embâcle bloque, la débâcle libère : quand les glaces de l\'embâcle cèdent d\'un coup, la débâcle peut provoquer des crues dévastatrices."},{"id":"exaltation","mot":"exaltation","nature":"nom féminin","definitions":["Vive excitation de l\'esprit, enthousiasme intense."],"phonetique":"/ɛɡ.zal.ta.sjɔ̃/","etymologie":"Du latin exaltatio, « élévation », de exaltare, « élever ».","registre":"soutenu","niveau":4,"themes":["emotions"],"synonymes":["enthousiasme","ferveur","ardeur","transport"],"antonymes":["abattement","apathie","indifférence"],"exemplesCorrects":["Il parlait de son projet avec une exaltation communicative.","L\'exaltation de la foule était à son comble.","Dans son exaltation, elle promit l\'impossible."],"exemplesIncorrects":["Il accomplit sa corvée dans une morne exaltation de lassitude.","L\'exaltation du congélateur conservait les aliments."],"distracteurs":["exhalaison","exultation","exploitation"],"anecdote":"À ne pas confondre avec « exhalation », qui concerne le souffle : l\'exaltation élève l\'âme, l\'exhalation s\'échappe des poumons."},{"id":"accablement","mot":"accablement","nature":"nom masculin","definitions":["État d\'abattement profond, physique ou moral."],"phonetique":"/a.kɑ.blə.mɑ̃/","etymologie":"De accabler, de l\'ancien caable, « machine de guerre qui écrase ».","registre":"soutenu","niveau":4,"themes":["emotions"],"synonymes":["abattement","prostration","découragement","lassitude"],"antonymes":["entrain","vigueur","allégresse"],"exemplesCorrects":["La nouvelle le plongea dans un profond accablement.","On lisait l\'accablement sur le visage des sinistrés.","Un accablement de fin d\'été pesait sur la ville."],"exemplesIncorrects":["Quel accablement de gagner enfin ce qu\'il désirait tant !","Il a réparé l\'accablement de la voiture au garage."],"distracteurs":["ralentissement","redoublement","acharnement"],"anecdote":"Le mot garde la mémoire d\'une arme : le « caable » médiéval, ancêtre de la catapulte, qui écrasait sous ses projectiles ; accabler, c\'est encore écraser."},{"id":"magnanime","mot":"magnanime","nature":"adjectif","definitions":["Qui pardonne aisément, qui fait preuve de générosité et de grandeur d\'âme."],"phonetique":"/ma.ɲa.nim/","etymologie":"Du latin magnanimus, de magnus, « grand », et animus, « âme ».","registre":"soutenu","niveau":4,"themes":["emotions"],"synonymes":["généreux","clément","noble","indulgent"],"antonymes":["mesquin","rancunier","pusillanime"],"exemplesCorrects":["Magnanime, le vainqueur épargna les vaincus.","Elle eut le geste magnanime de pardonner l\'affront.","Un esprit magnanime ne s\'abaisse pas à la vengeance."],"exemplesIncorrects":["Magnanime, il réclama vengeance jusqu\'au dernier.","Il a repeint la barrière d\'un magnanime éclatant."],"distracteurs":["unanime","magnétique","pusillanime"],"anecdote":"La magnanimité était pour Aristote une vertu maîtresse : la « grande âme » se reconnaît à ce qu\'elle se juge digne de grandes choses, et l\'est."},{"id":"mirobolant","mot":"mirobolant","nature":"adjectif","definitions":["Si extraordinaire qu\'il en paraît à peine croyable ; mirifique."],"phonetique":"/mi.ʁɔ.bɔ.lɑ̃/","etymologie":"De myrobolan, fruit exotique aux vertus jadis réputées miraculeuses.","registre":"familier","niveau":4,"themes":["abstrait"],"synonymes":["mirifique","fabuleux","prodigieux","faramineux"],"antonymes":["médiocre","banal","dérisoire"],"exemplesCorrects":["On lui promit des gains mirobolants qui ne vinrent jamais.","Ce n\'est pas un salaire mirobolant, mais il suffit.","Il racontait des aventures mirobolantes à qui voulait l\'entendre."],"exemplesIncorrects":["Un résultat mirobolant si décevant qu\'il démissionna.","Il a peint la clôture d\'un mirobolant éclatant."],"distracteurs":["miroitant","exorbitant","rutilant"],"anecdote":"Le myrobolan, fruit venu d\'Orient, passait pour une panacée ; de ses vertus exagérées est né l\'adjectif pour tout ce qui promet monts et merveilles."},{"id":"volubile","mot":"volubile","nature":"adjectif","definitions":["Qui parle avec abondance et rapidité ; très bavard."],"phonetique":"/vɔ.ly.bil/","etymologie":"Du latin volubilis, « qui tourne aisément », de volvere, « rouler ».","registre":"soutenu","niveau":4,"themes":["emotions","abstrait"],"synonymes":["loquace","bavard","disert","prolixe"],"antonymes":["taciturne","laconique","réservé"],"exemplesCorrects":["Volubile, il enchaînait les anecdotes sans reprendre son souffle.","Elle devenait volubile dès qu\'on l\'interrogeait sur ses voyages.","Un guide volubile nous abreuva de détails."],"exemplesIncorrects":["Volubile, il restait muet des heures durant.","Il a repeint la porte d\'un volubile éclatant."],"distracteurs":["volatile","indélébile","automobile"],"anecdote":"Le liseron grimpant se nomme aussi « volubilis » : la même idée de ce qui s\'enroule et tourne, appliquée à la plante comme à la langue bien pendue."},{"id":"petulant","mot":"pétulant","nature":"adjectif","definitions":["Plein d\'une vivacité exubérante, d\'une ardeur impétueuse."],"phonetique":"/pe.ty.lɑ̃/","etymologie":"Du latin petulans, « impétueux », de petere, « se jeter sur ».","registre":"courant","niveau":3,"themes":["emotions"],"synonymes":["fougueux","exubérant","vif","turbulent"],"antonymes":["calme","placide","apathique"],"exemplesCorrects":["Une pétulante jeunesse animait toute la maisonnée.","Il répliqua avec une verve pétulante.","La pétulante fillette ne tenait pas en place."],"exemplesIncorrects":["Pétulant, il sombra dans une torpeur sans fin.","Il a repeint le portail d\'un pétulant lumineux."],"distracteurs":["pétillant","postulant","pétrifiant"],"anecdote":"Curieusement, « pétulant » et « péter » partagent la racine latine petere, « se précipiter » : la pétulance, c\'est l\'élan qui se jette en avant."},{"id":"vilipender","mot":"vilipender","nature":"verbe","definitions":["Traiter avec mépris, dénigrer publiquement."],"phonetique":"/vi.li.pɑ̃.de/","etymologie":"Du latin vilipendere, de vilis, « vil », et pendere, « estimer » : « tenir pour vil ».","registre":"littéraire","niveau":5,"themes":["abstrait"],"synonymes":["dénigrer","vitupérer","honnir","décrier"],"antonymes":["louer","vanter","encenser"],"exemplesCorrects":["On vilipenda son œuvre de son vivant, on la célébra ensuite.","Il vilipendait ses rivaux dans des pamphlets cinglants.","Inutile de vilipender l\'adversaire pour avoir raison."],"exemplesIncorrects":["Pour le remercier, elle le vilipenda chaleureusement.","Il a vilipendé la clôture du jardin avant l\'hiver."],"distracteurs":["dilapider","dépendre","violenter","vitupéré"],"anecdote":"Mot rare et précieux, « vilipender » dit littéralement qu\'on « pèse » quelqu\'un et qu\'on le trouve « vil » : un mépris mis en balance."},{"id":"escarcelle","mot":"escarcelle","nature":"nom féminin","definitions":["Autrefois, grande bourse suspendue à la ceinture ; par plaisanterie, les finances de quelqu\'un."],"phonetique":"/ɛs.kaʁ.sɛl/","etymologie":"De l\'ancien français escarcele, du latin médiéval scarsella, « petite bourse ».","registre":"littéraire","niveau":4,"themes":["quotidien","litteraire"],"synonymes":["bourse","porte-monnaie","cassette"],"antonymes":[],"exemplesCorrects":["Cette prime tomba opportunément dans son escarcelle.","Le voyageur portait son escarcelle bien serrée à la ceinture.","De nouveaux contrats vinrent gonfler l\'escarcelle de l\'entreprise."],"exemplesIncorrects":["Il a garé son escarcelle devant la mairie.","L\'escarcelle de la rivière était en crue ce matin."],"distracteurs":["escabelle","escarbille","ritournelle"],"anecdote":"Le mot, désuet au sens propre, ne survit guère que dans l\'expression « tomber dans l\'escarcelle de », c\'est-à-dire revenir, comme un gain, à quelqu\'un."},{"id":"sirocco","mot":"sirocco","nature":"nom masculin","definitions":["Vent du sud, chaud, sec et souvent chargé de sable, qui souffle du Sahara vers le bassin méditerranéen."],"phonetique":"/si.ʁɔ.ko/","etymologie":"De l\'italien scirocco, lui-même emprunté à l\'arabe šarqī, « oriental », de šarq, « est, levant » : le vent venu de cette direction.","registre":"soutenu","niveau":3,"themes":["emprunts","nature"],"synonymes":["simoun"],"antonymes":[],"exemplesCorrects":["Le sirocco soufflait depuis trois jours, déposant sur la ville une fine poussière ocre.","Sous le sirocco, l\'air devenait irrespirable et le ciel virait au jaune.","Les marins redoutaient le sirocco qui levait une houle courte et hargneuse."],"exemplesIncorrects":["Un sirocco neigeux descendait des sommets enveloppés de brume.","Elle a commandé un sirocco bien glacé à la terrasse du café."],"distracteurs":["étiage","ressac","embâcle","frimas"],"anecdote":"Le sirocco peut transporter le sable saharien jusqu\'au nord de l\'Europe, teintant parfois de roux la neige des Alpes."},{"id":"sylve","mot":"sylve","nature":"nom féminin","definitions":["Forêt, en particulier vaste et profonde, évoquée dans un registre poétique.","Au pluriel, recueil de pièces de vers d\'inspiration diverse, à la manière des Silves de Stace."],"phonetique":"/silv/","etymologie":"Du latin silva, « forêt, bois », qui a aussi donné « sylvestre » et « sylviculture ».","registre":"littéraire","niveau":3,"themes":["nature","emprunts","litteraire"],"synonymes":["forêt","futaie","bois","bosquet"],"antonymes":["clairière","lande","désert"],"exemplesCorrects":["Le poète s\'enfonçait dans la sylve obscure pour y chercher l\'inspiration.","Une sylve immémoriale couvrait jadis ces collines aujourd\'hui dénudées.","Sous la sylve épaisse, la lumière ne tombait qu\'en taches tremblantes."],"exemplesIncorrects":["Il a planté une sylve de tomates dans son potager ce printemps.","La sylve de l\'immeuble grouillait de passants pressés."],"distracteurs":["combe","garrigue","étiage","estran"],"anecdote":"Le latin silva a légué son nom au prénom Sylvie comme à Sylvain, le dieu romain protecteur des forêts."},{"id":"brame","mot":"brame","nature":"nom masculin","definitions":["Cri rauque et puissant que pousse le cerf à l\'époque du rut, à l\'automne.","Par extension littéraire, plainte sourde et prolongée."],"phonetique":"/bʁam/","etymologie":"Déverbal de « bramer », issu du bas latin bramare, « rugir, crier », d\'origine probablement germanique.","registre":"soutenu","niveau":3,"themes":["nature","litteraire"],"synonymes":["raire","bramement"],"antonymes":["silence","murmure"],"exemplesCorrects":["Au crépuscule d\'octobre, le brame du cerf montait du fond des bois.","On entendait au loin le brame rauque qui annonçait la saison des amours.","Le brame résonnait dans la combe comme une longue plainte."],"exemplesIncorrects":["Il a poussé un brame de joie en apprenant sa réussite à l\'examen.","Le brame léger du moineau égayait le jardin au petit matin."],"distracteurs":["ressac","frimas","embruns","limon"],"anecdote":"Chaque automne, les forêts comme celles de Chambord ou de Rambouillet attirent des promeneurs venus écouter, de nuit, le brame des cerfs."},{"id":"harmattan","mot":"harmattan","nature":"nom masculin","definitions":["Vent sec et poussiéreux qui souffle du Sahara vers le golfe de Guinée pendant la saison sèche, voilant l\'horizon d\'une brume de sable."],"phonetique":"/aʁ.ma.tɑ̃/","etymologie":"Emprunté, par l\'intermédiaire de l\'anglais, à une langue de la côte ouest-africaine, vraisemblablement le twi (ou fanti) haramata.","registre":"soutenu","niveau":3,"themes":["emprunts","nature"],"synonymes":[],"antonymes":[],"exemplesCorrects":["L\'harmattan desséchait les lèvres et brouillait le soleil d\'un halo laiteux.","Pendant l\'harmattan, la brume de poussière effaçait les contours des collines.","Les nuits d\'harmattan étaient étonnamment fraîches après la fournaise du jour."],"exemplesIncorrects":["L\'harmattan humide gonflait les rivières et inondait les rizières.","Il a rangé son harmattan dans le placard avec les autres manteaux d\'hiver."],"distracteurs":["sirocco","mousson","embruns","drache"],"anecdote":"Sur la côte ouest-africaine, on surnomme parfois l\'harmattan « le médecin », car son air sec apporte un répit à la moiteur tropicale."},{"id":"mousson","mot":"mousson","nature":"nom féminin","definitions":["Vent saisonnier de l\'océan Indien et de l\'Asie du Sud qui change de direction selon l\'époque de l\'année.","Par extension, la saison des pluies qu\'amène ce vent."],"phonetique":"/mu.sɔ̃/","etymologie":"Du portugais monção, emprunté à l\'arabe mawsim, « saison, époque fixée », répandu par les navigateurs de l\'océan Indien.","registre":"courant","niveau":3,"themes":["emprunts","nature"],"synonymes":["saison des pluies","pluies de mousson"],"antonymes":["sécheresse"],"exemplesCorrects":["La mousson d\'été déversait sur la côte des trombes d\'eau tièdes.","Les paysans attendaient la mousson pour repiquer le riz.","Dès les premières pluies de la mousson, la poussière laissait place à la boue."],"exemplesIncorrects":["Une mousson de neige a recouvert les sommets alpins cette nuit.","Il a épousseté la mousson accumulée sur les étagères du grenier."],"distracteurs":["alizé","embruns","étiage","frimas"],"anecdote":"Le mot arabe d\'origine signifie « saison » : les marins arabes nommaient ainsi le rythme des vents qui réglait leurs traversées vers l\'Inde."},{"id":"foehn","mot":"foehn","nature":"nom masculin","definitions":["Vent chaud et sec qui souffle sur le versant sous le vent d\'une chaîne de montagnes, après avoir abandonné son humidité sur le versant opposé."],"phonetique":"/føn/","etymologie":"De l\'allemand de Suisse Föhn, lui-même issu du latin favonius, « vent de l\'ouest, vent doux ».","registre":"soutenu","niveau":3,"themes":["nature","emprunts"],"synonymes":["vent"],"antonymes":[],"exemplesCorrects":["Le foehn avait fait fondre la neige en une seule nuit sur les pentes valaisannes.","Quand souffle le foehn, l\'air devient sec et les cimes paraissent étrangement proches.","On attribuait au foehn les migraines et l\'irritabilité des habitants de la vallée."],"exemplesIncorrects":["Le foehn glacial du large nous transperçait sur la jetée du port.","Un foehn humide et brumeux montait de la mer et détrempait nos vêtements."],"distracteurs":["alizé","embruns","houle","givre"],"anecdote":"En allemand, Föhn désigne aussi le sèche-cheveux, par analogie avec ce vent d\'air chaud descendant des montagnes."},{"id":"simoun","mot":"simoun","nature":"nom masculin","definitions":["Vent violent, brûlant et chargé de sable qui balaie les déserts d\'Afrique du Nord et d\'Arabie."],"phonetique":"/si.mun/","etymologie":"Emprunté à l\'anglais simoom, lui-même issu de l\'arabe samūm, « vent pestilentiel, empoisonné », de la racine samma, « empoisonner ».","registre":"littéraire","niveau":3,"themes":["emprunts","nature"],"synonymes":["sirocco","khamsin"],"antonymes":[],"exemplesCorrects":["Le simoun se leva soudain, ensevelissant la caravane sous des tourbillons de sable.","Nul ne s\'aventurait dans le désert quand menaçait le simoun.","Le simoun soufflait avec une fureur qui semblait vouloir effacer toute trace de vie."],"exemplesIncorrects":["Un simoun rafraîchissant montait de la mer en fin d\'après-midi.","Elle s\'est abritée du simoun sous un parapluie pendant l\'averse."],"distracteurs":["alizé","houle","embâcle","givre"],"anecdote":"Théophile Gautier et bien des écrivains romantiques firent du simoun l\'image même de la fureur dévorante du désert."},{"id":"combe","mot":"combe","nature":"nom féminin","definitions":["Petite vallée encaissée, dépression au creux d\'un relief de collines ou de montagnes, fréquente dans le Jura et les Alpes."],"phonetique":"/kɔ̃b/","etymologie":"Du gaulois cumba, « vallée, dépression », mot prélatin conservé surtout dans la toponymie et le vocabulaire géographique ; à rapprocher du gallois cwm et du breton komm.","registre":"soutenu","niveau":3,"themes":["nature","litteraire"],"synonymes":["vallon","ravin","gorge","val"],"antonymes":["crête","sommet","plateau"],"exemplesCorrects":["Le sentier descendait au fond de la combe où subsistait un peu de neige.","Une brume tenace stagnait dans la combe à l\'abri du vent.","Les villages se nichaient au creux des combes, à l\'écart des cols battus par les bourrasques."],"exemplesIncorrects":["Elle s\'est coiffée d\'une combe avant de sortir sous la pluie.","Il a gravi la combe pour atteindre le point le plus haut du massif."],"distracteurs":["calanque","garrigue","étiage","estran"],"anecdote":"Le mot survit dans des centaines de noms de lieux français, de Combloux à La Combe-de-Lancey, témoins discrets d\'un substrat gaulois."},{"id":"tohubohu","mot":"tohu-bohu","nature":"nom masculin","definitions":["Désordre confus et bruyant ; agitation chaotique mêlée de vacarme."],"phonetique":"/tɔ.y.bɔ.y/","etymologie":"De l\'hébreu biblique tohu wa-bohu, « informe et vide », expression de la Genèse décrivant la Terre avant la création.","registre":"soutenu","niveau":3,"themes":["emprunts"],"synonymes":["chaos","tintamarre","ramdam","tumulte"],"antonymes":["ordre","calme","quiétude","silence"],"exemplesCorrects":["Dans le tohu-bohu de la gare, il peinait à retrouver ses compagnons.","Le marché du matin n\'était qu\'un tohu-bohu de cris et de couleurs.","Un tohu-bohu indescriptible régnait dans la salle au moment du vote."],"exemplesIncorrects":["Le tohu-bohu paisible du monastère invitait à la méditation.","Il a rangé son bureau dans un parfait tohu-bohu, tout y était impeccable."],"distracteurs":["palimpseste","atavisme","logorrhée","marasme"],"anecdote":"Avant de désigner le vacarme, l\'expression hébraïque décrivait, dans la Genèse, l\'état chaotique du monde avant que la lumière n\'en sépare les éléments."},{"id":"deletere","mot":"délétère","nature":"adjectif","definitions":["Qui nuit à la santé, qui peut tuer en s\'attaquant à l\'organisme.","Au figuré : qui exerce une influence pernicieuse, qui corrompt moralement ou socialement."],"phonetique":"/de.le.tɛʁ/","etymologie":"Emprunté au bas latin deleterius, lui-même issu du grec dêlêtêrios, « nuisible, funeste », dérivé du verbe dêleîsthai, « nuire, détruire ».","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["nocif","pernicieux","nuisible","toxique","morbide"],"antonymes":["salutaire","bénéfique","salubre","bienfaisant"],"exemplesCorrects":["Des vapeurs délétères montaient du marais et incommodaient les voyageurs.","Il dénonçait l\'influence délétère que ce climat de soupçon faisait peser sur l\'amitié.","Une rumeur délétère se répandit dans la cour et ruina peu à peu sa réputation."],"exemplesIncorrects":["Cette tisane délétère m\'a fait le plus grand bien après le dîner.","Son discours délétère a réconforté toute l\'assemblée et redonné espoir."],"distracteurs":["léthargique","délibéré","doctoral","diaphane"],"anecdote":"Le mot appartenait d\'abord au vocabulaire des chimistes et des hygiénistes du XIXᵉ siècle, qui parlaient de « gaz délétères » bien avant que l\'usage figuré ne s\'impose en morale."},{"id":"subreptice","mot":"subreptice","nature":"adjectif","definitions":["Qui se fait de manière furtive, cachée, en se dérobant à l\'attention.","En droit ancien : obtenu par des moyens frauduleux, en surprenant la bonne foi d\'autrui."],"phonetique":"/syb.ʁɛp.tis/","etymologie":"Du latin subrepticius, « clandestin, dérobé », dérivé de subripere « soustraire furtivement, en se glissant dessous » (sub- « sous » et rapere « saisir, ravir »).","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["furtif","clandestin","insidieux","sournois","occulte"],"antonymes":["manifeste","ostensible","patent","déclaré"],"exemplesCorrects":["Il lui adressa un regard subreptice, espérant n\'être surpris de personne.","Une joie subreptice passa sur son visage avant qu\'il ne reprît son air grave.","Par une manœuvre subreptice, il fit disparaître le document compromettant."],"exemplesIncorrects":["Le maire a inauguré la place de façon subreptice, devant une foule immense et sous les applaudissements.","Elle annonça la nouvelle de manière subreptice, à voix haute, du haut de la tribune."],"distracteurs":["superfétatoire","succinct","sciemment","saccadé"],"anecdote":"L\'adverbe « subrepticement » a largement supplanté l\'adjectif dans l\'usage courant, au point que beaucoup de locuteurs ignorent l\'existence de « subreptice »."},{"id":"smala","mot":"smala","nature":"nom féminin","definitions":["Camp itinérant d\'un chef arabe, avec sa suite, ses tentes et ses troupeaux.","Familièrement, famille ou entourage nombreux qui se déplace en groupe."],"phonetique":"/sma.la/","etymologie":"De l\'arabe dialectal d\'Algérie zmāla, « famille, maison du chef et sa suite » (lui-même d\'origine berbère), popularisé en français après la prise de la smala d\'Abd el-Kader en 1843.","registre":"courant","niveau":3,"themes":["emprunts"],"synonymes":["tribu","maisonnée","marmaille","smalah"],"antonymes":[],"exemplesCorrects":["Il est arrivé au baptême avec toute sa smala, cousins et petits-cousins compris.","La smala du caïd se déplaçait au gré des pâturages et des points d\'eau.","Impossible de loger pareille smala dans un studio."],"exemplesIncorrects":["Elle a accroché une smala précieuse au-dessus de la cheminée du salon.","Le médecin a prescrit une smala à prendre chaque matin à jeun."],"distracteurs":["caravane","douar","cohorte","saugrenu"],"anecdote":"La prise de la smala d\'Abd el-Kader en 1843 inspira à Horace Vernet une toile immense, l\'une des plus grandes du château de Versailles."},{"id":"immarcescible","mot":"immarcescible","nature":"adjectif","definitions":["Qui ne peut se flétrir, se faner.","Au figuré : qui ne saurait s\'altérer ni disparaître ; impérissable, inaltérable."],"phonetique":"/i.maʁ.se.sibl/","etymologie":"Du latin chrétien immarcescibilis, de marcescere, « se flétrir, se dessécher », précédé du préfixe privatif in-.","registre":"littéraire","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["impérissable","inaltérable","indéfectible","éternel"],"antonymes":["périssable","éphémère","altérable","fugace"],"exemplesCorrects":["Il croyait en une gloire immarcescible que les siècles ne sauraient ternir.","Sa foi immarcescible le soutint jusque dans les pires épreuves.","Le marbre semblait promettre à ce visage une beauté immarcescible."],"exemplesIncorrects":["Ces roses coupées, immarcescibles, ont fané en deux jours sur la table.","Son humeur immarcescible changeait du tout au tout selon le temps qu\'il faisait."],"distracteurs":["irascible","inextinguible","incoercible","impavide"],"anecdote":"Le mot, d\'abord cantonné au vocabulaire religieux où il qualifiait la couronne de gloire promise aux justes, fascine par sa longueur et son allure savante les amateurs de mots rares."},{"id":"prometheen","mot":"prométhéen","nature":"adjectif","definitions":["Qui évoque Prométhée par son audace, sa révolte contre l\'ordre établi ou son désir de dépasser la condition humaine.","Qui témoigne d\'une ambition créatrice démesurée, défiant les limites imposées."],"phonetique":"/pʁɔ.me.te.ɛ̃/","etymologie":"Dérivé de Prométhée, le Titan de la mythologie grecque qui déroba le feu aux dieux pour le donner aux hommes et fut châtié par Zeus.","registre":"littéraire","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["titanesque","audacieux","rebelle","démiurgique"],"antonymes":["résigné","soumis","pusillanime","timoré"],"exemplesCorrects":["Il y avait dans ce projet un élan prométhéen, une volonté de tout réinventer.","Le romantisme a fait du génie une figure prométhéenne, en lutte contre les dieux et les hommes.","Son ambition prométhéenne le poussait à défier les limites mêmes de la science."],"exemplesIncorrects":["Il accepta son sort avec une humilité prométhéenne et baissa la tête.","Ce petit arrangement prométhéen consistait à ranger ses crayons par couleur."],"distracteurs":["protéiforme","promiscuité","providentiel","prosaïque"],"anecdote":"Mary Shelley sous-titra son Frankenstein « Le Prométhée moderne », faisant du savant qui crée la vie un nouvel avatar du Titan voleur de feu."},{"id":"vesperal","mot":"vespéral","nature":"adjectif","definitions":["Qui appartient au soir, qui a lieu ou paraît au moment du crépuscule.","Au figuré : qui évoque le déclin, la fin paisible d\'une journée ou d\'une vie."],"phonetique":"/vɛs.pe.ʁal/","etymologie":"Du latin tardif vesperalis, dérivé de vesper, « le soir, l\'étoile du soir ».","registre":"littéraire","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["crépusculaire","vespertin","nocturne"],"antonymes":["matinal","matutinal","auroral"],"exemplesCorrects":["Une lumière vespérale dorait la façade des vieilles maisons.","Il aimait ces promenades vespérales où la ville se taisait peu à peu.","Le poète célébrait la douceur vespérale de son âge, sereine et résignée."],"exemplesIncorrects":["Dès l\'aube vespérale, le coq se mit à chanter dans la cour.","Nous avons pris un copieux petit-déjeuner vespéral avant de partir randonner."],"distracteurs":["viscéral","vénéneux","véhément","versatile"],"anecdote":"Dans la liturgie catholique, le « vespéral » désigne aussi un recueil contenant l\'office des vêpres, la prière chantée du soir."},{"id":"seraphique","mot":"séraphique","nature":"adjectif","definitions":["Qui appartient aux séraphins, les anges du plus haut rang.","Au figuré : d\'une pureté, d\'une douceur ou d\'une sérénité quasi angéliques, détaché des choses terrestres."],"phonetique":"/se.ʁa.fik/","etymologie":"Dérivé de séraphin, lui-même issu de l\'hébreu seraphim, pluriel de saraph, « brûlant », par l\'intermédiaire du latin ecclésiastique.","registre":"littéraire","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["angélique","céleste","éthéré","extatique"],"antonymes":["démoniaque","terrestre","charnel","prosaïque"],"exemplesCorrects":["Un sourire séraphique éclairait le visage de l\'enfant endormi.","Elle écoutait la musique dans une extase presque séraphique.","Le vieux moine inspirait une paix séraphique à tous ceux qui l\'approchaient."],"exemplesIncorrects":["Il est entré dans une colère séraphique et a renversé la table.","Le boxeur a porté un coup séraphique qui a mis son adversaire au tapis."],"distracteurs":["sibyllin","sardonique","sentencieux","sépulcral"],"anecdote":"Saint François d\'Assise est traditionnellement surnommé « le Docteur séraphique » et son ordre, les franciscains, « l\'ordre séraphique »."},{"id":"apophtegme","mot":"apophtegme","nature":"nom masculin","definitions":["Parole mémorable, sentence concise exprimant une vérité d\'une autorité reconnue, souvent attribuée à un personnage illustre."],"phonetique":"/a.pɔf.tɛɡm/","etymologie":"Emprunté au XVIe siècle au latin apophthegma, lui-même issu du grec apophthegma, « sentence, mot bien frappé », dérivé de apophthengesthai, « énoncer nettement ».","registre":"littéraire","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["maxime","aphorisme","sentence","adage","dicton"],"antonymes":[],"exemplesCorrects":["Il aimait à ponctuer ses lettres d\'un apophtegme emprunté aux Anciens.","« Connais-toi toi-même » est sans doute l\'apophtegme le plus célèbre de la sagesse grecque.","Le vieux maître parlait par apophtegmes, comme s\'il craignait de gaspiller ses mots."],"exemplesIncorrects":["Le médecin a diagnostiqué un apophtegme au genou après sa chute.","Elle a rangé ses apophtegmes dans le tiroir, à côté des couverts."],"distracteurs":["paradigme","anathème","épithète","syllogisme"],"anecdote":"Plutarque rassembla les mots célèbres des grands hommes dans un recueil intitulé « Apophtegmes des rois et des généraux », véritable ancêtre antique du livre de citations."},{"id":"adamantin","mot":"adamantin","nature":"adjectif","definitions":["Qui a la dureté ou l\'éclat du diamant.","Au figuré : d\'une fermeté, d\'une pureté ou d\'une transparence inaltérables."],"phonetique":"/a.da.mɑ̃.tɛ̃/","etymologie":"Du latin adamantinus, du grec adamas, adamantos, littéralement « l\'indomptable » (de a- privatif et damaô, « dompter ») — terme appliqué d\'abord aux substances les plus dures, le fer et l\'acier, puis au diamant.","registre":"littéraire","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["cristallin","diamantin","inflexible","inaltérable"],"antonymes":["friable","trouble","malléable","fragile"],"exemplesCorrects":["Une lumière adamantine jaillissait de la rosée au lever du jour.","Il opposa à ses juges une fermeté adamantine que rien ne put entamer.","Sa prose avait une clarté adamantine, sans une ombre ni une scorie."],"exemplesIncorrects":["Le coussin adamantin était si moelleux qu\'on s\'y enfonçait avec délice.","Il a une volonté adamantine : il change d\'avis à la moindre contrariété."],"distracteurs":["argentin","opalin","ambrosien","azuréen"],"anecdote":"Le mot grec adamas, « l\'indomptable », a donné à la fois « diamant » et « aimant » en français, deux objets que les Anciens croyaient doués de pouvoirs invincibles."},{"id":"lenifiant","mot":"lénifiant","nature":"adjectif","definitions":["Qui apaise, adoucit la douleur ou l\'inquiétude.","Souvent péjoratif : qui calme à bon compte, par des paroles rassurantes mais vaines."],"phonetique":"/le.ni.fjɑ̃/","etymologie":"Participe présent du verbe lénifier, du bas latin lenificare, « adoucir », de lenis, « doux », et facere, « faire ».","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["apaisant","adoucissant","calmant","émollient"],"antonymes":["irritant","exacerbant","alarmant","exaspérant"],"exemplesCorrects":["Il tenait des propos lénifiants pour endormir la méfiance de ses adversaires.","La voix lénifiante du conférencier finit par bercer l\'auditoire tout entier.","On lui servit des discours lénifiants là où elle attendait des actes."],"exemplesIncorrects":["Sa remarque lénifiante a déclenché une violente dispute entre les convives.","Le café, particulièrement lénifiant, l\'a tenu éveillé toute la nuit."],"distracteurs":["lancinant","languissant","léthargique","lascif"],"anecdote":"Le mot vient du même radical latin lenis que « lénitif », terme de pharmacie désignant un remède destiné à calmer la douleur."},{"id":"vesanie","mot":"vésanie","nature":"nom féminin","definitions":["Folie, dérangement durable de l\'esprit, envisagé dans sa gravité.","Par extension littéraire : déraison furieuse, égarement collectif."],"phonetique":"/ve.za.ni/","etymologie":"Du latin vesania, « folie », de vesanus, « insensé », composé de ve- (privatif, marquant l\'écart) et sanus, « sain ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["démence","aliénation","égarement","folie"],"antonymes":["raison","lucidité","santé mentale"],"exemplesCorrects":["Les médecins d\'alors rangeaient sous le nom de vésanie tout ce que la raison ne pouvait plus contenir.","Une vésanie collective semblait s\'être emparée de la foule, ivre de slogans.","Le poète sombra peu à peu dans une vésanie que ses amis affectaient de ne pas voir."],"exemplesIncorrects":["Il a rangé ses dossiers avec une vésanie méthodique avant de partir.","Sa vésanie pour la cuisine italienne le pousse à voyager chaque été en Toscane."],"distracteurs":["véhémence","vétusté","vénalité","vacuité"],"anecdote":"Le terme figurait jadis dans les nosographies médicales pour désigner la classe des maladies mentales, avant que la psychiatrie moderne n\'en abandonne l\'usage clinique."},{"id":"desherence","mot":"déshérence","nature":"nom féminin","definitions":["État d\'un bien ou d\'une succession sans héritier, qui revient alors à l\'État.","Au figuré : état d\'abandon, de délaissement d\'une chose dont nul ne se réclame plus."],"phonetique":"/de.ze.ʁɑ̃s/","etymologie":"Dérivé de « déshériter » (dés- privatif + hériter), avec le suffixe -ence ; de la base latine heres, heredis, « héritier ». Littéralement « état où il n\'y a pas d\'héritier ».","registre":"soutenu","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["abandon","délaissement","vacance"],"antonymes":["transmission","héritage","succession"],"exemplesCorrects":["Faute d\'héritier connu, la maison tomba en déshérence et l\'État en hérita.","Tout un pan de notre mémoire collective est aujourd\'hui laissé en déshérence.","Ces savoirs artisanaux, tombés en déshérence, ne survivent plus que chez quelques anciens."],"exemplesIncorrects":["Il a reçu une déshérence considérable à la mort de son oncle.","Le notaire a réparti la déshérence entre les trois enfants du défunt."],"distracteurs":["déliquescence","désuétude","déréliction","dévolution"],"anecdote":"En droit français, les biens dits « en déshérence » échoient à l\'État, qui les recueille faute de tout autre ayant droit."},{"id":"inanite","mot":"inanité","nature":"nom féminin","definitions":["Caractère de ce qui est vide de sens, de portée ou d\'utilité ; vanité profonde d\'une chose.","Par extension : futilité d\'un propos ou d\'une entreprise."],"phonetique":"/i.na.ni.te/","etymologie":"Du latin inanitas, « vide, vacuité », dérivé de inanis, « vide, creux ».","registre":"soutenu","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["vacuité","futilité","vanité","inutilité"],"antonymes":["substance","consistance","utilité","valeur"],"exemplesCorrects":["Il finit par mesurer l\'inanité de ses efforts contre un mur d\'indifférence.","L\'inanité de ces débats sans fin décourageait jusqu\'aux plus patients.","Devant l\'immensité du ciel, elle ressentit l\'inanité de ses petites tracasseries."],"exemplesIncorrects":["Son discours était d\'une telle inanité qu\'il a convaincu toute l\'assemblée.","Grâce à l\'inanité de ses arguments, il a remporté le débat haut la main."],"distracteurs":["immensité","inanition","innéité","iniquité"],"anecdote":"À ne pas confondre avec « inanition », l\'état d\'épuisement faute de nourriture : les deux mots remontent au même latin inanis, « vide », mais l\'un dit le vide du sens, l\'autre celui de l\'estomac."},{"id":"prodrome","mot":"prodrome","nature":"nom masculin","definitions":["Signe avant-coureur, symptôme qui annonce l\'imminence d\'un mal ou d\'un événement.","Au figuré littéraire : ce qui précède et présage une crise."],"phonetique":"/pʁɔ.dʁom/","etymologie":"Du grec prodromos, « qui court devant, avant-coureur », de pro- (devant) et dromos (course).","registre":"soutenu","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["prémices","présage","signe avant-coureur","préliminaire"],"antonymes":["séquelle","aboutissement","épilogue"],"exemplesCorrects":["Ces tensions diplomatiques n\'étaient que les prodromes d\'un conflit plus vaste.","La migraine débutait toujours par les mêmes prodromes : une lumière trop vive, un picotement.","Les historiens lisent dans ces émeutes les prodromes de la révolution à venir."],"exemplesIncorrects":["Après des mois de soins, le prodrome de sa maladie marqua enfin sa guérison.","Ce prodrome glorieux couronna une carrière déjà bien remplie."],"distracteurs":["paradigme","prolixité","promontoire","prosélyte"],"anecdote":"En médecine, on appelle encore « phase prodromique » la période où des symptômes diffus annoncent une maladie avant que celle-ci ne se déclare franchement."},{"id":"dehiscence","mot":"déhiscence","nature":"nom féminin","definitions":["Ouverture spontanée d\'un organe végétal arrivé à maturité, qui libère graines ou pollen.","Par extension : tout écartement, toute fente par laquelle un contenu se libère."],"phonetique":"/de.i.sɑ̃s/","etymologie":"Du latin dehiscere, « s\'ouvrir, s\'entrebâiller », de hiscere, « s\'entrouvrir, se fendre » ; le substantif est emprunté au bas latin dehiscentia.","registre":"soutenu","niveau":5,"themes":["nature","abstrait"],"synonymes":["ouverture","fente","écartement"],"antonymes":["fermeture","occlusion","indéhiscence"],"exemplesCorrects":["À la déhiscence des capsules, le pavot répand ses graines au moindre souffle.","Le botaniste notait la date exacte de déhiscence de chaque espèce.","On pourrait parler, par métaphore, de la déhiscence d\'un secret trop longtemps contenu."],"exemplesIncorrects":["La déhiscence de la porte cochère résonna lorsqu\'on la verrouilla pour la nuit.","Le maçon a comblé la déhiscence en cimentant solidement les deux pierres."],"distracteurs":["efflorescence","dénivellation","désinence","exsudation"],"anecdote":"On distingue en botanique les fruits « déhiscents », qui s\'ouvrent à maturité comme la gousse du pois, des fruits « indéhiscents », qui gardent leurs graines enfermées, telle la noisette."},{"id":"palingenesie","mot":"palingénésie","nature":"nom féminin","definitions":["Renaissance, retour à la vie ou régénération complète d\'un être, d\'une société ou du monde.","En philosophie et en théologie : doctrine d\'un perpétuel recommencement, d\'une nouvelle naissance des âmes ou de l\'univers."],"phonetique":"/pa.lɛ̃.ʒe.ne.zi/","etymologie":"Emprunté, par l\'intermédiaire du latin palingenesia, au grec palingenesia, composé de palin, « de nouveau, à nouveau », et de genesis, « naissance, génération » : littéralement « nouvelle naissance ».","registre":"littéraire","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["renaissance","régénération","résurrection","renouveau"],"antonymes":["déclin","extinction","anéantissement","déchéance"],"exemplesCorrects":["Les stoïciens enseignaient une palingénésie du cosmos, sans cesse consumé et reformé.","Le romancier rêvait d\'une palingénésie de la société par la seule force de l\'art.","Il voyait dans le printemps l\'image d\'une palingénésie universelle."],"exemplesIncorrects":["Le médecin a prescrit une palingénésie deux fois par jour après les repas.","Elle a garé sa palingénésie devant l\'immeuble avant de monter."],"distracteurs":["parthénogenèse","métempsycose","anamnèse","eschatologie"],"anecdote":"Le mot, longtemps cantonné à la philosophie mystique, fut popularisé par la Palingénésie philosophique de Charles Bonnet (1769) puis par les Essais de palingénésie sociale de Ballanche ; Balzac en hérita pour exprimer sa croyance en une perpétuelle transformation des êtres et des sociétés."},{"id":"clenche","mot":"clenche","nature":"nom féminin","definitions":["Pièce mobile d\'un loquet qui, en s\'abaissant dans la gâche, maintient une porte fermée.","Régionalement (Nord, Belgique) : poignée ou bec-de-cane d\'une porte."],"phonetique":"/klɑ̃ʃ/","etymologie":"De l\'ancien bas francique *klinka, « loquet », apparenté au néerlandais klink ; mot d\'aire septentrionale, de même racine germanique que l\'anglais to clinch.","registre":"courant","niveau":5,"themes":["regionalismes","quotidien"],"synonymes":["loquet","bec-de-cane","poignée"],"antonymes":[],"exemplesCorrects":["Il abaissa la clenche sans bruit pour ne réveiller personne.","Dans le Nord, on vous dira d\'« abaisser la clenche » là où d\'autres disent la poignée.","La clenche rouillée résistait, et il fallut peser de tout son poids sur la porte."],"exemplesIncorrects":["Il a accroché son manteau à la clenche du portemanteau de l\'entrée.","La clenche du robinet gouttait toute la nuit dans l\'évier de la cuisine."],"distracteurs":["targette","espagnolette","crémone","gâche"],"anecdote":"Restée vivante dans le Nord de la France et en Belgique, « clenche » a longtemps désigné aussi bien le loquet que la poignée, au point de dérouter les visiteurs venus du Sud."},{"id":"nitescence","mot":"nitescence","nature":"nom féminin","definitions":["Éclat lumineux, état de ce qui brille d\'une lueur douce ou naissante."],"phonetique":"/ni.te.sɑ̃s/","etymologie":"Du latin nitescere, « commencer à briller », forme inchoative de nitere, « luire, resplendir ».","registre":"littéraire","niveau":5,"themes":["litteraire","nature"],"synonymes":["luminescence","éclat","brillance","lueur"],"antonymes":["obscurité","ternissure","opacité"],"exemplesCorrects":["La nitescence du couchant teintait les vitres d\'un or liquide.","On devinait sous la cendre la nitescence des dernières braises.","Une étrange nitescence émanait de la mer phosphorescente cette nuit-là."],"exemplesIncorrects":["Une épaisse nitescence enveloppait la cave et l\'on n\'y voyait goutte.","La nitescence du brouillard nous empêchait d\'avancer sur la route."],"distracteurs":["incandescence","réminiscence","turgescence","phosphène"],"anecdote":"Attesté dès 1834 sous la plume de Sainte-Beuve, dans Volupté, « nitescence » a séduit les poètes friands de termes savants pour dire la lumière sous toutes ses nuances."},{"id":"retif","mot":"rétif","nature":"adjectif","definitions":["Qui refuse d\'avancer ou d\'obéir, en parlant d\'une monture ; par extension, d\'une personne récalcitrante, qui résiste à ce qu\'on lui demande."],"phonetique":"/ʁe.tif/","etymologie":"Du latin populaire restivus, « qui s\'arrête, qui reste en arrière », dérivé du verbe restare, « rester, s\'arrêter », lui-même formé de re- et de stare, « se tenir debout ».","registre":"soutenu","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["récalcitrant","rebelle","indocile","réfractaire"],"antonymes":["docile","obéissant","soumis"],"exemplesCorrects":["Le cheval, rétif, refusa de franchir le ruisseau malgré les encouragements.","Cet élève rétif à toute discipline finissait toujours par se faire remarquer.","Elle restait rétive aux conseils, persuadée de mieux savoir."],"exemplesIncorrects":["Après une bonne nuit, je me sens parfaitement rétif et plein d\'énergie.","Ce fauteuil est très rétif, on s\'y assoit avec un grand confort."],"distracteurs":["pusillanime","loquace","affable","fébrile"],"anecdote":"Le mot s\'applique d\'abord aux chevaux qui « restent » plantés et refusent d\'avancer ; cette image équestre, héritée du latin restare (« s\'arrêter »), a donné son sens figuré à l\'esprit rétif."},{"id":"imperitie","mot":"impéritie","nature":"nom féminin","definitions":["Manque d\'aptitude, incapacité notoire à exercer une fonction ou un métier.","Maladresse coupable de celui qui agit sans le savoir-faire requis."],"phonetique":"/ɛ̃.pe.ʁi.si/","etymologie":"Du latin imperitia, « inexpérience, ignorance, maladresse », dérivé de imperitus, « inexpérimenté, ignorant », composé du préfixe privatif in- et de peritus, « expérimenté, habile, qui sait par expérience ».","registre":"littéraire","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["incompétence","incapacité","maladresse","inhabileté"],"antonymes":["compétence","habileté","maestria","expertise"],"exemplesCorrects":["On lui reprocha une impéritie qui avait coûté cher à l\'entreprise.","L\'impéritie des dirigeants précipita la déroute de la campagne.","Sa plume dénonçait sans relâche l\'impéritie des administrations engourdies."],"exemplesIncorrects":["Il a mené le projet avec une impéritie remarquable qui força l\'admiration de tous.","Grâce à son impéritie de chirurgien, l\'opération fut un éclatant succès."],"distracteurs":["impavidité","improbité","impécuniosité","impétuosité"],"anecdote":"Le terme garde une coloration juridique : on parle encore d\'« impéritie » pour qualifier la faute du professionnel dont l\'incompétence engage la responsabilité."},{"id":"contrit","mot":"contrit","nature":"adjectif","definitions":["Qui éprouve un regret sincère, une tristesse marquée d\'avoir commis une faute ; pénétré de repentir."],"phonetique":"/kɔ̃.tʁi/","etymologie":"Du latin contritus, « broyé, écrasé », participe passé de conterere ; au sens religieux, « dont le cœur est brisé par le remords ».","registre":"soutenu","niveau":2,"themes":["emotions"],"synonymes":["repentant","penaud","confus","marri"],"antonymes":["impénitent","fier","satisfait"],"exemplesCorrects":["Il présenta ses excuses d\'un air contrit, n\'osant lever les yeux.","Contrite de sa maladresse, elle resta silencieuse le reste du dîner.","L\'enfant, contrit, avoua tout bas qu\'il avait cassé le vase."],"exemplesIncorrects":["Ravi de sa bonne plaisanterie, il riait d\'un air contrit.","Après sa victoire, il affichait un sourire contrit et triomphant."],"distracteurs":["serein","véhément","désinvolte","perspicace"],"anecdote":"Dans la tradition catholique, on distingue la « contrition parfaite », inspirée par l\'amour de Dieu, de la simple « attrition », motivée par la peur du châtiment."},{"id":"sagace","mot":"sagace","nature":"adjectif","definitions":["Qui fait preuve d\'une pénétration d\'esprit vive, capable de deviner et de comprendre ce qui échappe aux autres."],"phonetique":"/sa.ɡas/","etymologie":"Du latin sagax, sagacis, « qui a l\'odorat ou le flair subtil », d\'abord dit des chiens de chasse, dérivé de sagire, « percevoir finement, flairer ».","registre":"soutenu","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["perspicace","clairvoyant","fin","avisé"],"antonymes":["obtus","borné","naïf"],"exemplesCorrects":["Un observateur sagace aurait remarqué l\'hésitation dans sa voix.","Elle posa une question sagace qui désarçonna tout le jury.","Le vieux médecin, sagace, devina le mal avant même l\'examen."],"exemplesIncorrects":["Cette tarte est délicieusement sagace, relevée comme il faut.","Il a couru de manière très sagace et a remporté la course."],"distracteurs":["affable","taciturne","véhément","candide"],"anecdote":"Le mot vient du flair des chiens de chasse : être sagace, c\'est avoir du « nez » au sens figuré, savoir flairer ce que les autres ne perçoivent pas."},{"id":"cassine","mot":"cassine","nature":"nom féminin","definitions":["Petite maison de campagne, souvent modeste ou isolée.","Par dépréciation : masure, bicoque délabrée ; au sens militaire vieilli, petite construction isolée dans les champs servant de poste d\'embuscade."],"phonetique":"/ka.sin/","etymologie":"Emprunté à l\'italien septentrional « cassina », variante du toscan « cascina » (« ferme, étable à vaches »), issu du bas-latin « cassina » et remontant au latin vulgaire « *capsea », apparenté à « capsa » (« caisse »).","registre":"littéraire","niveau":5,"themes":["regionalismes","litteraire"],"synonymes":["masure","maisonnette","bicoque","chaumière"],"antonymes":["palais","manoir","demeure"],"exemplesCorrects":["Ils passaient l\'été dans une cassine perdue au milieu des oliviers.","La vieille cassine, fendue de lézardes, tenait encore debout par miracle.","Il rêvait de finir ses jours dans quelque cassine du Luberon, loin du tumulte."],"exemplesIncorrects":["Le promoteur a fait bâtir une somptueuse cassine de mille mètres carrés sur la colline.","Ils ont organisé le grand bal de mariage dans la cassine royale du château."],"distracteurs":["mazet","borie","bastide","métairie"],"anecdote":"Déjà présent chez Rabelais en 1532, le mot a longtemps désigné, dans la langue militaire, une bâtisse isolée au milieu des champs d\'où l\'on guettait l\'ennemi : la modeste maison de campagne pouvait ainsi devenir un poste d\'embuscade."},{"id":"obombrer","mot":"obombrer","nature":"verbe","definitions":["Couvrir d\'ombre, voiler d\'une ombre légère.","Au figuré, littéraire : assombrir, ternir l\'éclat de quelque chose."],"phonetique":"/ɔ.bɔ̃.bʁe/","etymologie":"Du latin obumbrare, « couvrir d\'ombre, ombrager », de ob- (devant, contre) et umbra, « ombre ». Attesté dès le XIIe siècle.","registre":"littéraire","niveau":5,"themes":["litteraire","nature"],"synonymes":["ombrager","voiler","assombrir","obscurcir"],"antonymes":["éclairer","illuminer","aviver"],"exemplesCorrects":["Un grand cèdre obombrait la terrasse aux heures les plus chaudes.","Une mélancolie soudaine vint obombrer sa joie naissante.","Les nuages obombraient la vallée d\'une grisaille pesante."],"exemplesIncorrects":["Le soleil de midi obombrait la plage d\'une lumière aveuglante.","Sa réussite éclatante obombra de bonheur toute la famille réunie."],"distracteurs":["obstruer","ombiliquer","obvier","obnubiler"],"anecdote":"Verbe que l\'on croise surtout chez les poètes et dans les anciennes traductions bibliques, où la nuée « obombre » les fidèles et où les anges « obombrent » de leurs ailes : il appartient à ce français rare et mystique que la prose courante a presque oublié."},{"id":"barguigner","mot":"barguigner","nature":"verbe","definitions":["Hésiter longuement, avoir de la peine à se décider, manquer de résolution."],"phonetique":"/baʁ.gi.ɲe/","etymologie":"De l\'ancien français bargaignier ; rattaché soit au latin médiéval barcaniare (« faire du commerce »), soit au francique borganjan (« emprunter »), d\'où l\'idée de marchander qui a glissé vers « hésiter ».","registre":"littéraire","niveau":4,"themes":["quotidien","abstrait","litteraire"],"synonymes":["tergiverser","atermoyer","hésiter"],"antonymes":["trancher","décider","agir"],"exemplesCorrects":["Il accepta sans barguigner la mission qu\'on lui proposait.","Cessez de barguigner : la décision doit être prise ce soir.","Elle paya le prix demandé sans barguigner davantage."],"exemplesIncorrects":["Le maçon a barguigné le mur en une journée.","Nous avons barguigné la rivière à gué."],"distracteurs":["bredouiller","rechigner","marchander"],"anecdote":"La locution « sans barguigner » a survécu bien plus que le verbe seul ; on l\'emploie pour louer une décision prompte et sans réticence.","categorie":"mot-rare"},{"id":"berdouille","mot":"berdouille","nature":"nom féminin","definitions":["Boue, gadoue, terre détrempée et collante (régionalisme du Nord de la France et de Belgique)."],"phonetique":"/bɛʁ.duj/","etymologie":"Mot des dialectes wallons et des parlers du Nord, de la même famille populaire que bredouille, sur un radical expressif évoquant le désordre et la salissure.","registre":"familier","niveau":4,"themes":["nature","regionalismes","quotidien"],"synonymes":["boue","gadoue","fange"],"antonymes":["propreté","sécheresse"],"exemplesCorrects":["Après l\'averse, le chemin de terre n\'était plus que berdouille.","Les enfants sont rentrés couverts de berdouille jusqu\'aux genoux.","On s\'enfonçait dans la berdouille à chaque pas."],"exemplesIncorrects":["Il a bu une berdouille bien chaude au café.","Elle a chanté une berdouille de son village."],"distracteurs":["bourbier","limon","ornière"],"anecdote":"Dans le Nord et en Belgique, on dit « être à l\'berdouille » pour quelqu\'un mal en point ou dans le pétrin, image directe de qui patauge dans la boue.","categorie":"mot-rare"},{"id":"guincher","mot":"guincher","nature":"verbe","definitions":["Danser, surtout dans un bal populaire ou une fête."],"phonetique":"/ɡɛ̃.ʃe/","etymologie":"De l\'ancien français guenchir (« obliquer, esquiver »), du francique wenkjan (« vaciller ») ; le sens « danser » s\'est développé dans l\'argot des bals populaires (la guinche).","registre":"familier","niveau":3,"themes":["quotidien","emprunts"],"synonymes":["danser","gambiller","valser"],"antonymes":[],"exemplesCorrects":["On a guinché toute la nuit sur l\'accordéon.","Viens guincher, l\'orchestre vient de commencer !","Le 14 juillet, tout le village guinchait sur la place."],"exemplesIncorrects":["Il a guinché la porte d\'un coup d\'épaule.","Elle a guinché un café avant de partir."],"distracteurs":["sautiller","trémousser","swinguer"],"anecdote":"Le mot est lié aux « guinches », ces bals de barrière du Paris du XIXe siècle ; guincher garde un parfum d\'accordéon et de bal musette.","categorie":"mot-rare"},{"id":"ronchonner","mot":"ronchonner","nature":"verbe","definitions":["Manifester sa mauvaise humeur en grognant, en marmonnant des protestations."],"phonetique":"/ʁɔ̃.ʃɔ.ne/","etymologie":"Dérivé de ronchon, lui-même issu de l\'ancien français ronchier, du latin rhoncare (« ronfler »), d\'où l\'idée d\'un grognement sourd.","registre":"courant","niveau":2,"themes":["emotions","quotidien"],"synonymes":["grogner","bougonner","rouspéter"],"antonymes":["se réjouir","approuver","acquiescer"],"exemplesCorrects":["Il ronchonne dès qu\'on lui demande un service.","Arrête de ronchonner et viens nous aider.","Le vieux chien ronchonnait dans son coin."],"exemplesIncorrects":["Elle a ronchonné la sauce pendant une heure.","Nous avons ronchonné la colline avant midi."],"distracteurs":["maugréer","ricaner","soupirer"],"anecdote":"Ronchonner désigne un mécontentement plus marmonné que véhément : le ronchon proteste pour lui-même autant que pour être entendu.","categorie":"mot-rare"},{"id":"s-encoubler","mot":"s\'encoubler","nature":"verbe","definitions":["Trébucher, s\'empêtrer les pieds dans un obstacle (suisse romand et Savoie)."],"phonetique":"/sɑ̃.ku.ble/","etymologie":"De couble (« entrave, lien »), du latin copula (« lien, attache ») ; littéralement « s\'entraver les jambes ».","registre":"familier","niveau":4,"themes":["quotidien","regionalismes"],"synonymes":["trébucher","s\'empêtrer","chopper"],"antonymes":["se rattraper","se stabiliser"],"exemplesCorrects":["Il s\'est encoublé dans le tapis et a failli tomber.","Fais attention à ne pas t\'encoubler dans les câbles.","Elle s\'est encoublée sur une racine en pleine course."],"exemplesIncorrects":["Il a encoublé la lettre dans l\'enveloppe.","Nous nous sommes encoublés un bon repas."],"distracteurs":["s\'affaler","buter","vaciller"],"anecdote":"Typiquement suisse romand, « s\'encoubler » déroute souvent les Français, qui n\'ont pas de verbe unique aussi imagé pour « se prendre les pieds dans quelque chose ».","categorie":"mot-rare"},{"id":"poutser","mot":"poutser","nature":"verbe","definitions":["Nettoyer à fond, faire le ménage (suisse romand)."],"phonetique":"/put.se/","etymologie":"De l\'allemand putzen (« nettoyer »), germanisme intégré à la conjugaison française ; aussi orthographié poutzer.","registre":"familier","niveau":4,"themes":["quotidien","emprunts","regionalismes"],"synonymes":["nettoyer","astiquer","récurer"],"antonymes":["salir","souiller"],"exemplesCorrects":["Le samedi matin, on poutse toute la maison.","Il a poutsé la cuisine de fond en comble.","Elle poutse les vitres avant l\'arrivée des invités."],"exemplesIncorrects":["Il a poutsé un grand verre d\'eau d\'un trait.","Nous avons poutsé jusqu\'au sommet de la colline."],"distracteurs":["balayer","fourbir","lessiver"],"anecdote":"Directement repris de l\'allemand putzen, « poutser » illustre l\'empreinte germanique du français de Suisse, que les puristes raillent au profit de « nettoyer ».","categorie":"mot-rare"},{"id":"bisbille","mot":"bisbille","nature":"nom féminin","definitions":["Petite querelle, brouille de peu de gravité, désaccord passager."],"phonetique":"/biz.bij/","etymologie":"De l\'italien bisbiglio (« murmure, chuchotement »), d\'origine onomatopéique évoquant les chuchotements d\'une dispute.","registre":"courant","niveau":3,"themes":["emotions","quotidien"],"synonymes":["querelle","brouille","chamaillerie"],"antonymes":["entente","harmonie","réconciliation"],"exemplesCorrects":["Une bisbille de voisinage à propos d\'une haie a vite été oubliée.","Ils ont eu une petite bisbille, mais se sont réconciliés le soir même.","Tout ce remue-ménage pour une simple bisbille de famille !"],"exemplesIncorrects":["La bisbille a ravagé toute la région pendant dix ans.","Il a déclaré la bisbille à son rival juré."],"distracteurs":["zizanie","altercation","discorde"],"anecdote":"La bisbille suppose la futilité : on parle de bisbille pour une fâcherie sans conséquence, là où « conflit » ou « querelle » sonneraient trop solennels.","categorie":"mot-rare"},{"id":"carabistouille","mot":"carabistouille","nature":"nom féminin","definitions":["Sornette, histoire mensongère, propos peu crédible (surtout au pluriel ; Belgique et Nord de la France)."],"phonetique":"/ka.ʁa.bis.tuj/","etymologie":"Du wallon carabistouye (« mensonge plaisant, histoire à dormir debout »), apparenté à la famille de bistouille.","registre":"familier","niveau":4,"themes":["quotidien","regionalismes","abstrait"],"synonymes":["sornette","baliverne","calembredaine"],"antonymes":["vérité","certitude"],"exemplesCorrects":["Arrête de raconter des carabistouilles, je ne te crois pas une seconde.","Tout ça, ce sont des carabistouilles pour endormir les naïfs.","Il nous a servi une carabistouille de plus pour justifier son retard."],"exemplesIncorrects":["Elle a peint la carabistouille en bleu vif.","Nous avons gravi la carabistouille au lever du jour."],"distracteurs":["fariboles","billevesées","balourdise"],"anecdote":"En Belgique, « raconter des carabistouilles » est l\'équivalent savoureux de « raconter des bobards » : le mot amuse autant qu\'il dénonce le mensonge.","categorie":"mot-rare"},{"id":"dejeuner","mot":"déjeuner","nature":"nom masculin","definitions":["En France, repas de la mi-journée.","Au Québec, en Belgique et en Suisse, repas du matin (le petit-déjeuner des Français)."],"phonetique":"/de.ʒœ.ne/","etymologie":"De l\'ancien français desjuner, « rompre le jeûne », de des- (cessation) et jeun, du latin jejunus (« à jeun »).","registre":"courant","niveau":1,"themes":["quotidien","regionalismes"],"synonymes":["repas","collation"],"antonymes":[],"exemplesCorrects":["À Montréal, le déjeuner se prend dès le réveil, avec café et œufs.","En Belgique, on prend son déjeuner avant de partir travailler le matin.","« On se retrouve pour le déjeuner ? » — à Bruxelles, cela peut signifier le matin."],"exemplesIncorrects":["Au Québec, le déjeuner désigne forcément le repas de midi.","En Belgique, le déjeuner se prend toujours le soir vers vingt heures."],"distracteurs":["dînette","festin","brunch"],"anecdote":"Beaucoup de Français croient que « déjeuner » signifie partout le repas de midi. En réalité, au Québec, en Belgique et en Suisse, le déjeuner est le repas du matin : déjeuner / dîner / souper s\'y décalent d\'un cran par rapport à la France.","categorie":"piege-sens","piege":{"formeFautive":"déjeuner = repas de midi partout dans la francophonie","explication":"Au Québec, en Belgique et en Suisse, le déjeuner est le repas du matin, et non celui de midi (qui s\'y appelle dîner). Le sens « repas de midi » n\'est valable qu\'en France."}},{"id":"diner","mot":"dîner","nature":"nom masculin","definitions":["En France, repas du soir.","Au Québec, en Belgique et en Suisse, repas de la mi-journée."],"phonetique":"/di.ne/","etymologie":"De l\'ancien français disner, du bas latin disjejunare, « rompre le jeûne », même origine que déjeuner.","registre":"courant","niveau":1,"themes":["quotidien","regionalismes"],"synonymes":["repas","souper"],"antonymes":[],"exemplesCorrects":["À Genève, le dîner se prend vers midi, entre deux réunions.","Au Québec, les enfants rentrent dîner à la maison à l\'heure du midi.","En Belgique, le dîner désigne le repas pris à midi."],"exemplesIncorrects":["Au Québec, le dîner se prend forcément à vingt heures.","En Suisse, le dîner désigne toujours le premier repas du matin."],"distracteurs":["banquet","goûter","réveillon"],"anecdote":"Un Français invité à « dîner » à midi par un Québécois ou un Belge ne se trompe pas d\'heure : là-bas, le dîner est le repas de la mi-journée, et le repas du soir s\'appelle le souper.","categorie":"piege-sens","piege":{"formeFautive":"dîner = repas du soir partout dans la francophonie","explication":"Au Québec, en Belgique et en Suisse, le dîner est le repas de midi, et non celui du soir (qui s\'y appelle souper). Le sens « repas du soir » n\'est valable qu\'en France."}},{"id":"souper","mot":"souper","nature":"nom masculin","definitions":["Repas du soir (Belgique, Suisse, Québec et est de la France).","En France standard, repas pris tard dans la nuit, après une sortie ou un spectacle."],"phonetique":"/su.pe/","etymologie":"De l\'ancien français super, dérivé de soupe (« tranche de pain arrosée de bouillon »), le souper étant à l\'origine le repas où l\'on mangeait la soupe.","registre":"courant","niveau":2,"themes":["quotidien","regionalismes"],"synonymes":["dîner","repas"],"antonymes":[],"exemplesCorrects":["En Belgique, on appelle le repas du soir le souper.","Au Québec, la famille se réunit pour le souper vers dix-huit heures.","Après le théâtre, ils sont allés faire un souper en ville."],"exemplesIncorrects":["En France standard, le souper désigne le repas de midi.","Au Québec, le souper est le tout premier repas du matin."],"distracteurs":["festin","collation","ripaille"],"anecdote":"En France, beaucoup pensent que « souper » est un mot vieilli ou paysan ; en Belgique, en Suisse et au Québec, c\'est simplement le mot courant pour le repas du soir, là où la France dit « dîner ».","categorie":"piege-sens","piege":{"formeFautive":"souper = repas de midi ou mot purement archaïque","explication":"Le souper est le repas du soir dans une grande partie de la francophonie (Belgique, Suisse, Québec, est de la France). En France standard, il ne désigne qu\'un repas tardif pris après une sortie ; ce n\'est ni le repas de midi ni un simple archaïsme."}},{"id":"babelutte","mot":"babelutte","nature":"nom féminin","definitions":["Caramel mou et long, à base de sucre candi (ou de cassonade) et de sirop, spécialité du Nord de la France et de la Belgique.","Par extension, sucette de ce caramel, notamment à Furnes (Veurne)."],"phonetique":"/ba.blyt/","etymologie":"Du néerlandais babbelaar, confiserie traditionnelle de la côte belge, probablement apparenté à babbelen (« bavarder ») ; le terme a été francisé au début du XXe siècle.","registre":"courant","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["caramel","berlingot"],"antonymes":[],"exemplesCorrects":["À la kermesse, les enfants se collaient les doigts avec des babeluttes.","La babelutte de Furnes se vend encore dans des cornets en papier.","Elle suçait une babelutte en attendant le tram à Ostende."],"exemplesIncorrects":["Le maçon a posé une babelutte de briques le long du mur.","Il a signé la babelutte du contrat avant de partir."],"distracteurs":["nougatine","pralin","dragée"],"anecdote":"À Furnes, en Flandre-Occidentale, la babelutte est si emblématique qu\'elle a donné son nom à des confiseries artisanales perpétuant une recette de cassonade et de beurre.","categorie":"mot-rare"},{"id":"crolle","mot":"crolle","nature":"nom féminin","definitions":["Boucle de cheveux, frisure (Belgique, Nord de la France).","Par extension, toute forme enroulée, spirale."],"phonetique":"/kʁɔl/","etymologie":"Déverbal de croller (« friser, boucler »), apparenté au moyen néerlandais crulle, krulle (« boucle »), à l\'anglais curl et à l\'allemand kraus.","registre":"familier","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["boucle","frisure","anglaise"],"antonymes":[],"exemplesCorrects":["Avec l\'humidité, ses cheveux reprennent toutes leurs crolles.","Le bébé a une jolie crolle sur le front.","Elle s\'est fait des crolles au fer à friser pour la fête."],"exemplesIncorrects":["Il a pris une crolle de soupe avant le repas.","La crolle du marteau s\'est cassée en deux."],"distracteurs":["mèche","tresse","frange"],"anecdote":"En Belgique, on dit d\'une personne aux cheveux bouclés qu\'elle est « crollée », un adjectif que les francophones de France comprennent rarement.","categorie":"mot-rare"},{"id":"spitant","mot":"spitant","nature":"adjectif","definitions":["Vif, pétillant, plein d\'énergie et d\'entrain (Belgique).","En parlant d\'une boisson, qui pétille, qui mousse."],"phonetique":"/spi.tɑ̃/","etymologie":"Du verbe wallon spiter (« gicler, jaillir, pétiller »), apparenté au flamand spitten et au néerlandais spuiten ; participe présent adjectivé.","registre":"familier","niveau":4,"themes":["regionalismes","emotions"],"synonymes":["vif","pétillant","fringant"],"antonymes":["amorphe","apathique","éteint"],"exemplesCorrects":["Ce matin, les enfants sont particulièrement spitants.","Malgré son âge, elle reste spitante et pleine d\'idées.","Une eau bien spitante désaltère mieux qu\'une eau plate."],"exemplesIncorrects":["Le contrat a été spitant entre les deux parties.","Il a spitant la porte avant de sortir."],"distracteurs":["alerte","guilleret","primesautier"],"anecdote":"Le mot « spitant » fait partie de ces belgicismes que les Français trouvent charmants : il dit en deux syllabes ce que « plein d\'allant » dit en trois.","categorie":"mot-rare"},{"id":"dringuelle","mot":"dringuelle","nature":"nom féminin","definitions":["Pourboire, gratification (Belgique, Lorraine, Nord).","Argent de poche, étrennes que l\'on reçoit pour une fête ou un anniversaire."],"phonetique":"/dʁɛ̃.ɡɛl/","etymologie":"Du néerlandais drinkgeld ou de l\'allemand Trinkgeld, littéralement « argent pour boire », c\'est-à-dire pourboire.","registre":"familier","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["pourboire","étrennes","gratification"],"antonymes":[],"exemplesCorrects":["Le livreur a empoché une belle dringuelle.","Pour la Saint-Nicolas, les petits reçoivent une dringuelle de leur grand-mère.","Il laisse toujours une dringuelle au café du coin."],"exemplesIncorrects":["La dringuelle de la voiture est tombée en panne.","Elle a peint le mur d\'une dringuelle bien vive."],"distracteurs":["aumône","obole","ristourne"],"anecdote":"Comme « pourboire » en français standard, « dringuelle » garde dans son étymologie néerlandaise l\'idée que la somme était destinée à offrir un verre.","categorie":"mot-rare"},{"id":"clinche","mot":"clinche","nature":"nom féminin","definitions":["Poignée de porte, plus précisément le loquet ou la béquille que l\'on abaisse pour ouvrir (Belgique, Est de la France, Suisse)."],"phonetique":"/klɛ̃ʃ/","etymologie":"Du moyen néerlandais klinke (« loquet »), emprunté à l\'allemand Klinke (« loquet, poignée ») ; le mot évoque le mécanisme du loquet qui s\'enclenche.","registre":"familier","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["poignée","béquille","loquet"],"antonymes":[],"exemplesCorrects":["Abaisse la clinche, la porte n\'est pas verrouillée.","La clinche est tellement froide en hiver qu\'on hésite à la toucher.","Il a graissé la clinche qui grinçait."],"exemplesIncorrects":["Elle a mangé une clinche de pain au petit-déjeuner.","Le bateau a jeté la clinche au fond du port."],"distracteurs":["targette","gâche","espagnolette"],"anecdote":"Un Belge qui demande « ferme la clinche » laisse souvent perplexe un Parisien, pour qui le mot n\'évoque rien : la poignée de porte change de nom dès qu\'on franchit la frontière linguistique.","categorie":"mot-rare"},{"id":"tantot","mot":"tantôt","nature":"adverbe","definitions":["Dans un moment, sous peu ; ou il y a peu de temps, tout à l\'heure (l\'adverbe désigne un moment proche, passé ou futur, selon le contexte).","Régionalement (Belgique, Ouest, Canada), cet après-midi.","Répété (« tantôt… tantôt… »), marque l\'alternance : à un moment… à un autre moment."],"phonetique":"/tɑ̃.to/","etymologie":"De tant et tôt, littéralement « aussitôt, dans un temps aussi bref ».","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["bientôt","naguère"],"antonymes":[],"exemplesCorrects":["Je repasserai tantôt, attends-moi.","Je l\'ai croisé tantôt, il avait l\'air pressé.","Il est tantôt gai, tantôt morose."],"exemplesIncorrects":["Nous nous verrons tantôt dans dix ans.","Tantôt est mon plat préféré du dimanche."],"distracteurs":["jadis","désormais","dorénavant"],"anecdote":"Beaucoup croient que « tantôt » désigne toujours le futur proche ; en réalité l\'adverbe est ambivalent et peut renvoyer au passé récent (« je l\'ai vu tantôt ») aussi bien qu\'à l\'imminent (« à tantôt ! »).","categorie":"piege-sens"},{"id":"ringard","mot":"ringard","nature":"nom masculin","definitions":["À l\'origine, barre de fer servant à attiser le feu, à remuer les braises ou à racler le foyer d\'un fourneau ; tisonnier.","Au sens figuré et familier devenu courant, personne ou chose démodée, sans talent, dépassée (emploi adjectival ou nominal)."],"phonetique":"/ʁɛ̃.ɡaʁ/","etymologie":"Du wallon ringuèle, ringuéle (« levier »), emprunté à l\'allemand dialectal Rengel (« bûche, barre »), avec substitution du suffixe -ard à la finale -èle ; le sens d\'outil de forge et de fonderie est le sens premier.","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["tisonnier","fourgon"],"antonymes":["moderne","branché"],"exemplesCorrects":["Le fondeur racla le creuset avec un ringard.","À la forge, un ringard rougi traînait près de l\'enclume.","On se sert d\'un ringard pour décrasser la grille du foyer."],"exemplesIncorrects":["Il a relu le ringard du contrat avant de signer.","Elle a planté un ringard de fleurs dans le jardin."],"distracteurs":["chenet","soufflet","attisoir"],"anecdote":"On ne connaît plus guère que le sens figuré (« quel film ringard ! »), mais le ringard était d\'abord, et reste dans le vocabulaire des fonderies, la barre de fer pour attiser et racler le feu.","categorie":"piege-sens"},{"id":"berlauder","mot":"berlauder","nature":"verbe","definitions":["Flâner, traîner, perdre son temps à des riens (Lorraine, Belgique).","Régionalement, faire un travail à moitié, le bâcler, l\'exécuter sans soin."],"phonetique":"/bɛʁ.lo.de/","etymologie":"Verbe régional de l\'Est et du Nord, d\'origine dialectale lorraine ; rattaché à une racine évoquant le flottement, l\'errance désœuvrée.","registre":"familier","niveau":5,"themes":["regionalismes","quotidien"],"synonymes":["flâner","traînasser","lambiner"],"antonymes":["s\'activer","peaufiner","soigner"],"exemplesCorrects":["Au lieu de berlauder dans les rues, va donc finir tes devoirs.","Il passe ses après-midi à berlauder sans rien faire de précis.","Ne berlaude pas ton ouvrage, applique-toi un peu."],"exemplesIncorrects":["Il a berlaudé sa sœur d\'une gifle.","Nous avons berlaudé toute la maison de fond en comble."],"distracteurs":["musarder","vadrouiller","bricoler"],"anecdote":"En Lorraine, « arrête de berlauder ! » est l\'admonestation classique adressée à l\'enfant qui lambine au lieu de se mettre au travail.","categorie":"mot-rare"},{"id":"escagasser","mot":"escagasser","nature":"verbe","definitions":["Abîmer, esquinter, casser, mettre en mauvais état (Provence, Sud-Est).","Au figuré et familièrement, importuner, fatiguer, casser les pieds à quelqu\'un."],"phonetique":"/ɛs.ka.ɡa.se/","etymologie":"De l\'occitan provençal escagassar, « accroupir, écraser, aplatir », dérivé de cagar avec le préfixe es-.","registre":"familier","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["esquinter","abîmer","amocher"],"antonymes":["réparer","arranger","rafistoler"],"exemplesCorrects":["Il a escagassé l\'aile de la voiture contre un platane.","Arrête de tripoter ce jouet, tu vas l\'escagasser.","Tu m\'escagasses avec tes histoires sans fin !"],"exemplesIncorrects":["Le pâtissier a escagassé une belle tarte aux pommes.","Elle a escagassé un poème magnifique sur l\'amour."],"distracteurs":["bousiller","rapetasser","ravauder"],"anecdote":"En Provence, « tu m\'escagasses » se dit aussi bien d\'un objet qu\'on a abîmé que d\'un fâcheux qui vous épuise de sa présence.","categorie":"mot-rare"},{"id":"pegueux","mot":"pégueux","nature":"adjectif","definitions":["Collant, poisseux, gluant (Sud-Ouest, Provence, Occitanie)."],"phonetique":"/pe.ɡø/","etymologie":"De l\'occitan pegós, dérivé de pega (« poix »), du latin pix, picis (« poix, résine collante »).","registre":"familier","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["poisseux","collant","gluant"],"antonymes":["sec","lisse"],"exemplesCorrects":["Après avoir mangé la barbe à papa, les enfants ont les mains toutes pégueuses.","La table est encore pégueuse de sirop renversé.","Ce miel a rendu le pot de confiture tout pégueux."],"exemplesIncorrects":["Le ciel était pégueux et limpide ce matin.","Sa voix pégueuse résonnait dans le hall vide."],"distracteurs":["visqueux","spongieux","graisseux"],"anecdote":"Au Québec, on retrouve l\'expression imagée « pégueux comme une poignée de porte », preuve que ce mot occitan a essaimé jusqu\'outre-Atlantique.","categorie":"mot-rare"},{"id":"empeguer","mot":"empéguer","nature":"verbe","definitions":["Coller, engluer, rendre poisseux (Sud, Provence).","Au figuré et familièrement, embarquer, entraîner dans une mauvaise affaire, mettre dans l\'embarras ; à la forme pronominale (s\'empéguer), s\'enivrer."],"phonetique":"/ɑ̃.pe.ɡe/","etymologie":"De l\'occitan empegar, « enduire de poix, coller », dérivé de pega (« poix »), du latin pix, picis.","registre":"familier","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["engluer","embarquer","empêtrer"],"antonymes":["dégager","libérer","décoller"],"exemplesCorrects":["Il s\'est laissé empéguer dans une histoire d\'héritage qui n\'en finit pas.","Méfie-toi, ce vendeur va t\'empéguer un contrat que tu ne pourras plus résilier.","À la fête du village, certains s\'étaient bien empégués au pastis."],"exemplesIncorrects":["Le menuisier a empégué une armoire en chêne massif.","Elle a empégué un magnifique discours devant l\'assemblée."],"distracteurs":["enliser","embobiner","emberlificoter"],"anecdote":"Du sens propre « coller à la poix », « empéguer » a glissé vers l\'idée d\'être pris au piège : se faire empéguer, en Provence, c\'est se retrouver englué dans une situation dont on se serait bien passé.","categorie":"mot-rare"},{"id":"remuneration","mot":"rémunération","nature":"nom féminin","definitions":["Somme d\'argent versée en contrepartie d\'un travail, d\'un service rendu ; salaire, paiement."],"phonetique":"/ʁe.my.ne.ʁa.sjɔ̃/","etymologie":"Du latin remuneratio, « récompense », de remunerari, « récompenser », formé sur munus, muneris, « don, présent ».","registre":"courant","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["salaire","rétribution","traitement"],"antonymes":["bénévolat","gratuité"],"exemplesCorrects":["La rémunération de ce poste reste à négocier lors de l\'entretien.","Il réclame une juste rémunération pour les heures supplémentaires effectuées.","La rémunération des consultants dépasse celle des salariés permanents."],"exemplesIncorrects":["Il a renuméré ses dossiers avant de les classer par ordre.","Le comptable a rénuméré chaque ligne de la facture."],"distracteurs":["énumération","numérotation","récupération"],"anecdote":"Beaucoup écrivent à tort « renumération » par contamination de « numéro ». Le mot n\'a rien à voir avec les chiffres : il vient du latin munus, « le don ». La forme correcte est bien « rémunération », sans inversion des lettres.","categorie":"piege-orthographe","piege":{"formeFautive":"renumération","explication":"On intervertit souvent les syllabes en pensant, à tort, à « numéro » ou « numéroter ». Le mot dérive du latin munus (don) et s\'écrit ré-mu-né-ra-tion."}},{"id":"carrousel","mot":"carrousel","nature":"nom masculin","definitions":["Parade équestre, exercice où des cavaliers exécutent des figures réglées.","Manège forain tournant pour enfants.","Mouvement circulaire et répété d\'objets ou de personnes."],"phonetique":"/ka.ʁu.zɛl/","etymologie":"Emprunté à l\'italien (napolitain) carosello, jeu équestre où l\'on se lançait des balles ; le second r a été ajouté en français par analogie avec carrosse.","registre":"courant","niveau":2,"themes":["quotidien","emprunts"],"synonymes":["manège","parade","ronde"],"antonymes":[],"exemplesCorrects":["Le carrousel de Saumur réunit les meilleurs cavaliers du Cadre noir.","Les enfants tournaient sur le carrousel de la fête foraine.","Un carrousel de voitures officielles encombrait la place."],"exemplesIncorrects":["Il a caroussel le dossier en plusieurs exemplaires.","Nous avons carousel toute la nuit dans les rues."],"distracteurs":["caravelle","carrosse","carillon"],"anecdote":"On hésite souvent sur le nombre de r et de s. En italien d\'origine, carosello ne prend qu\'un seul r ; c\'est le français qui a doublé le r par analogie avec carrosse. La graphie correcte est carrousel : deux r, un seul s.","categorie":"piege-orthographe","piege":{"formeFautive":"caroussel","explication":"On double souvent le s par erreur, ou l\'on oublie le second r. La forme correcte est carrousel : deux r (par analogie avec carrosse) et un seul s."}},{"id":"interessant","mot":"intéressant","nature":"adjectif","definitions":["Qui retient l\'attention, éveille l\'intérêt ou la curiosité.","Qui présente un avantage, notamment financier ; avantageux."],"phonetique":"/ɛ̃.te.ʁe.sɑ̃/","etymologie":"Participe présent adjectivé du verbe intéresser, lui-même issu du latin interesse, « importer, être de l\'intérêt de », de inter (entre) et esse (être).","registre":"courant","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["captivant","passionnant","avantageux"],"antonymes":["ennuyeux","insipide","fastidieux"],"exemplesCorrects":["Cette conférence sur les abysses était particulièrement intéressante.","Le vendeur a proposé un prix vraiment intéressant.","Tu soulèves là un point intéressant que nous avions négligé."],"exemplesIncorrects":["Ce livre est très intérressant du début à la fin.","Elle a fait une remarque interressante en réunion."],"distracteurs":["impressionnant","ressortissant","intermittent"],"anecdote":"Faute fréquente : doubler le r en pensant à « intérêt » avec son accent circonflexe. Or l\'adjectif s\'écrit avec un seul r et deux s : in-té-res-sant, comme le verbe intéresser dont il dérive.","categorie":"piege-orthographe","piege":{"formeFautive":"intérressant","explication":"On ajoute souvent un r de trop par analogie avec « intérêt ». La forme correcte ne prend qu\'un seul r et deux s : intéressant."}},{"id":"occurrence","mot":"occurrence","nature":"nom féminin","definitions":["Circonstance, occasion ; cas où une chose se produit.","Apparition, manifestation d\'un fait, d\'un élément (notamment d\'un mot dans un texte)."],"phonetique":"/ɔ.ky.ʁɑ̃s/","etymologie":"Du latin médiéval occurrentia, de occurrens, participe présent de occurrere, « se présenter, venir au-devant », de ob (vers) et currere (courir).","registre":"soutenu","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["circonstance","occasion","cas"],"antonymes":[],"exemplesCorrects":["En l\'occurrence, mieux vaut attendre demain pour décider.","Le logiciel compte chaque occurrence du mot dans le manuscrit.","C\'est une occurrence rare, qui mérite d\'être notée."],"exemplesIncorrects":["Il a occurrence son voyage à cause de la grève.","Nous avons occurrence la réunion de plusieurs heures."],"distracteurs":["récurrence","concurrence","occlusion"],"anecdote":"Mot souvent malmené : on oublie un c ou un r. Il s\'écrit avec deux c et deux r, comme le latin occurrere dont il vient. À ne pas confondre avec « récurrence » (un seul c).","categorie":"piege-orthographe","piege":{"formeFautive":"occurence","explication":"On omet fréquemment le second r. La forme correcte prend deux c et deux r : occurrence, du latin occurrere."}},{"id":"recurrent","mot":"récurrent","nature":"adjectif","definitions":["Qui revient, se reproduit, réapparaît de façon répétée.","En anatomie, qui revient vers son point de départ (nerf récurrent)."],"phonetique":"/ʁe.ky.ʁɑ̃/","etymologie":"Du latin recurrens, participe présent de recurrere, « courir en arrière, revenir », de re- (retour) et currere (courir).","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["répétitif","périodique","fréquent"],"antonymes":["unique","isolé","exceptionnel"],"exemplesCorrects":["Ce mal de dos récurrent l\'oblige à consulter régulièrement.","Le thème de l\'exil est récurrent dans toute son œuvre.","Nous faisons face à un problème récurrent de surchauffe."],"exemplesIncorrects":["Il a récurrent la même histoire toute la soirée.","Elle a récurrent ses excuses sans grande conviction."],"distracteurs":["concurrent","courant","déférent"],"anecdote":"On oublie souvent le second r en pensant à « récurer » ou par simple distraction. L\'adjectif s\'écrit récurrent, avec deux r, de la même famille que « occurrence » et « concurrence ».","categorie":"piege-orthographe","piege":{"formeFautive":"récurent","explication":"Un seul r est une faute courante. Le mot vient du latin recurrere et prend deux r : récurrent."}},{"id":"concurrence","mot":"concurrence","nature":"nom féminin","definitions":["Rivalité entre plusieurs personnes ou entreprises poursuivant un même but, notamment économique.","Ensemble des concurrents sur un marché.","Locution : jusqu\'à concurrence de, jusqu\'à une certaine limite."],"phonetique":"/kɔ̃.ky.ʁɑ̃s/","etymologie":"Du latin concurrentia, de concurrere, « courir ensemble, se rencontrer, rivaliser », de cum (avec) et currere (courir).","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["rivalité","compétition","émulation"],"antonymes":["monopole","coopération","entente"],"exemplesCorrects":["La concurrence sur ce marché fait baisser les prix.","Cette boutique craint la concurrence du grand magasin voisin.","Les remboursements sont plafonnés jusqu\'à concurrence de mille euros."],"exemplesIncorrects":["Ils ont concurrence pour obtenir le meilleur poste.","Nous avons concurrence nos efforts pour réussir."],"distracteurs":["conférence","concordance","convergence"],"anecdote":"Comme « occurrence » et « récurrent », ce mot de la famille latine de currere (courir) prend deux r. On écrit souvent à tort « concurence » : il faut bien deux c et deux r.","categorie":"piege-orthographe","piege":{"formeFautive":"concurence","explication":"Oublier le second r est une faute répandue. Le mot vient du latin concurrere et s\'écrit avec deux r : concurrence."}},{"id":"denivele","mot":"dénivelé","nature":"nom masculin","definitions":["Différence d\'altitude entre deux points ; variation de hauteur sur un parcours."],"phonetique":"/de.niv.le/","etymologie":"Substantivation du participe passé de déniveler, formé de dé- (préfixe marquant la séparation) et de niveler, de nivel, ancienne forme de niveau (du latin libella).","registre":"courant","niveau":2,"themes":["nature","quotidien"],"synonymes":["pente","inclinaison"],"antonymes":["palier","plat","horizontale"],"exemplesCorrects":["Cette randonnée présente un dénivelé de huit cents mètres.","Le coureur a avalé le dénivelé sans ralentir.","Le dénivelé positif de l\'étape décourage les débutants."],"exemplesIncorrects":["Il a dénivelé toute la soirée à raconter ses exploits.","Nous avons dénivelé la table pour qu\'elle tienne droit."],"distracteurs":["déclivité","niveau","dévers"],"anecdote":"On rencontre les deux formes : « le dénivelé » (nom masculin) et « la dénivelée » (nom féminin), toutes deux admises. La forme masculine s\'est imposée dans le langage sportif et la randonnée. Attention à l\'accent aigu sur le premier e seulement.","categorie":"piege-orthographe","piege":{"formeFautive":"dénivellé","explication":"On double parfois le l à tort. Le mot dérive de déniveler (un seul l) et s\'écrit dénivelé, avec un seul l."}},{"id":"ennuyeux","mot":"ennuyeux","nature":"adjectif","definitions":["Qui cause de l\'ennui ; lassant, monotone.","Qui contrarie, qui crée des difficultés ; fâcheux, gênant."],"phonetique":"/ɑ̃.nɥi.jø/","etymologie":"Dérivé de ennui, lui-même issu du verbe ennuyer, du bas latin inodiare, « inspirer du dégoût », de l\'expression latine in odio esse, « être un objet de haine ».","registre":"courant","niveau":1,"themes":["emotions","quotidien"],"synonymes":["lassant","monotone","fastidieux"],"antonymes":["captivant","intéressant","divertissant"],"exemplesCorrects":["Le film était si ennuyeux que plusieurs spectateurs sont partis.","Voilà un contretemps bien ennuyeux pour notre départ.","Elle trouve les longues réunions terriblement ennuyeuses."],"exemplesIncorrects":["Il a ennuyeux son frère toute la journée.","Cette nouvelle nous a beaucoup ennuyeux."],"distracteurs":["envieux","soyeux","anxieux"],"anecdote":"Faute classique : écrire « ennuyeux » avec un i (ennuieux). Le mot conserve le y du verbe ennuyer ; on écrit donc ennuyeux, ennuyeuse, comme joyeux vient de joie.","categorie":"piege-orthographe","piege":{"formeFautive":"ennuieux","explication":"On remplace souvent le y par un i. La forme correcte garde le y du verbe ennuyer : ennuyeux."}},{"id":"soi-disant","mot":"soi-disant","nature":"locution","definitions":["Qui se dit, se prétend tel ; prétendu (en parlant d\'une personne).","Adverbialement, à ce que l\'on prétend ; prétendument."],"phonetique":"/swa.di.zɑ̃/","etymologie":"Composé de soi (pronom réfléchi, du latin se) et de disant (participe présent de dire) : « se disant tel ». Locution figée et invariable.","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["prétendu","supposé","prétendument"],"antonymes":["avéré","authentique","véritable"],"exemplesCorrects":["Ce soi-disant expert n\'a jamais publié la moindre étude.","Elle est arrivée en retard, soi-disant à cause des embouteillages.","Les soi-disant économies se sont révélées des dépenses cachées."],"exemplesIncorrects":["Cette soi-disante amélioration n\'a rien changé.","Les marchandises soi-disantes neuves étaient en fait usagées."],"distracteurs":["prétendant","bien-disant","médisant"],"anecdote":"Deux pièges. D\'abord soi-disant est invariable : ni accord en genre, ni en nombre. Ensuite, les puristes le réservent aux personnes capables de parler ; pour une chose prétendue, on devrait dire « prétendu ». L\'usage courant a toutefois étendu son emploi aux objets.","categorie":"piege-orthographe","piege":{"formeFautive":"soi-disante","explication":"On l\'accorde à tort (soi-disante, soi-disants). La locution est invariable : disant est ici un participe présent figé. On écrit toujours soi-disant."}},{"id":"tache","mot":"tâche","nature":"nom féminin","definitions":["Travail déterminé à accomplir, ouvrage imposé ou que l\'on s\'impose.","Mission, fonction qui incombe à quelqu\'un."],"phonetique":"/tɑʃ/","etymologie":"Du latin médiéval tasca, « redevance, corvée imposée », variante de taxa lié au verbe taxare, « évaluer, taxer » ; le sens a glissé vers le travail imposé.","registre":"courant","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["travail","besogne","mission"],"antonymes":["loisir","repos","oisiveté"],"exemplesCorrects":["Ranger les archives est une tâche fastidieuse mais nécessaire.","Chacun s\'acquitte de sa tâche avec sérieux.","Il s\'est attelé à la lourde tâche de réécrire le rapport."],"exemplesIncorrects":["Il a fait une tâche sur sa chemise en mangeant.","Le soleil affiche des tâches sombres à sa surface."],"distracteurs":["corvée","labeur","fonction"],"anecdote":"Deux mots homophones distingués par l\'accent. La tâche avec accent circonflexe désigne un travail ; la tache sans accent désigne une salissure. Moyen mnémotechnique : l\'accent circonflexe pèse comme le poids du travail à accomplir.","categorie":"piege-sens","piege":{"formeFautive":"tache","explication":"Écrire « tache » (sans accent) pour parler d\'un travail est une faute de sens : « tache » désigne une salissure. Le travail à accomplir prend l\'accent circonflexe : tâche."}},{"id":"balade","mot":"balade","nature":"nom féminin","definitions":["Promenade sans but précis, flânerie ; petite excursion d\'agrément."],"phonetique":"/ba.lad/","etymologie":"Déverbal de balader, du provençal balar, « danser » (bas latin ballare) ; le sens a évolué de « courir les rues en chantant » vers « se promener ».","registre":"courant","niveau":1,"themes":["quotidien","nature"],"synonymes":["promenade","flânerie","excursion"],"antonymes":[],"exemplesCorrects":["Nous sommes partis en balade le long de la rivière.","Une petite balade en forêt lui éclaircit toujours les idées.","Profitons du beau temps pour faire une balade en vélo."],"exemplesIncorrects":["Le pianiste a joué une balade mélancolique au clair de lune.","Ce poème médiéval est une balade à refrain."],"distracteurs":["barricade","brigade","embuscade"],"anecdote":"Homophone redoutable. La balade (un l) est une promenade ; la ballade (deux l) est un poème ou un morceau de musique. Curieusement, les deux remontent au même verbe ballare, « danser » : les troubadours composaient leurs ballades en se baladant.","categorie":"piege-sens","piege":{"formeFautive":"ballade","explication":"Écrire « ballade » (deux l) pour une promenade est une confusion de sens : avec deux l, c\'est un poème ou une chanson. La promenade prend un seul l : balade."}},{"id":"ballade","mot":"ballade","nature":"nom féminin","definitions":["Poème de forme fixe médiévale, composé de strophes terminées par un refrain et d\'un envoi.","Pièce musicale au caractère narratif ou romantique, souvent lente."],"phonetique":"/ba.lad/","etymologie":"De l\'ancien provençal ballada, « danse, chanson à danser », dérivé de ballar, « danser » (bas latin ballare).","registre":"soutenu","niveau":2,"themes":["litteraire","abstrait"],"synonymes":["poème","complainte","chant"],"antonymes":[],"exemplesCorrects":["Villon est célèbre pour sa Ballade des pendus.","Le pianiste a interprété une ballade de Chopin.","Cette ballade médiévale se termine par un envoi adressé au prince."],"exemplesIncorrects":["Nous avons fait une belle ballade en montagne dimanche.","Après le déjeuner, ils sont partis en ballade au bord du lac."],"distracteurs":["romance","sonnet","rondeau"],"anecdote":"Le mot et son homophone « balade » partagent l\'étymologie de la danse (ballare). Au Moyen Âge, la ballade était d\'abord une chanson à danser. Aujourd\'hui, deux l renvoient au poème ou à la musique, un seul l à la promenade.","categorie":"piege-sens","piege":{"formeFautive":"balade","explication":"Écrire « balade » (un l) pour un poème ou un morceau de musique est une confusion de sens : un seul l désigne une promenade. Le poème et la pièce musicale prennent deux l : ballade."}},{"id":"resolution","mot":"résolution","nature":"nom féminin","definitions":["Décision ferme prise après réflexion ; ce que l\'on a résolu de faire.","Action de résoudre, de trouver la solution d\'un problème ou de dissoudre une chose en ses éléments."],"phonetique":"/ʁe.zɔ.ly.sjɔ̃/","etymologie":"Du latin resolutio, « action de dénouer, de relâcher », de resolvere (dénouer, dissoudre).","registre":"courant","niveau":1,"themes":["abstrait","quotidien"],"synonymes":["décision","détermination","fermeté"],"antonymes":["hésitation","indécision","irrésolution"],"exemplesCorrects":["Il a pris la ferme résolution d\'arrêter de fumer.","La résolution de l\'équation lui a demandé une heure.","Ses bonnes résolutions de janvier n\'ont pas tenu jusqu\'en mars."],"exemplesIncorrects":["Il a montré beaucoup de résolution en arrosant les plantes.","Elle a résolution chaque matin à six heures.","La résolution du gâteau était parfaite après cuisson."],"distracteurs":["dissolution","révolution","absolution"],"anecdote":"On écrit « résolution » avec un seul s, contrairement à « dissolution ». Beaucoup ajoutent à tort un double s par analogie avec d\'autres mots de la même famille.","categorie":"piege-orthographe","piege":{"formeFautive":"ressolution","explication":"Le mot prend un seul s, prononcé /z/ entre deux voyelles ; le doublement « ressolution » est fautif."}},{"id":"apotheose","mot":"apothéose","nature":"nom féminin","definitions":["Point culminant, moment le plus brillant et le plus glorieux de quelque chose.","Dans l\'Antiquité, déification d\'un mortel, élevé au rang des dieux."],"phonetique":"/a.pɔ.te.oz/","etymologie":"Du grec apothéôsis, « déification », de apotheoûn (élever au rang de dieu), de theós (dieu).","registre":"soutenu","niveau":2,"themes":["abstrait","litteraire"],"synonymes":["consécration","triomphe","couronnement"],"antonymes":["déchéance","chute","fiasco"],"exemplesCorrects":["Le feu d\'artifice final fut l\'apothéose de la soirée.","Cette victoire marqua l\'apothéose de sa carrière.","Les empereurs romains recevaient parfois les honneurs de l\'apothéose après leur mort."],"exemplesIncorrects":["Il a apothéosé la table en quelques minutes.","Elle souffrait d\'une apothéose au genou depuis sa chute.","Le médecin a diagnostiqué une apothéose chronique."],"distracteurs":["apogée","apostrophe","hypothèse"],"anecdote":"On écrit « apothéose » avec un th, hérité du grec theós, « dieu », et un accent aigu sur le deuxième e. Oublier le h et écrire « apotéose » est une faute fréquente.","categorie":"piege-orthographe","piege":{"formeFautive":"apotéose","explication":"Le groupe th (du grec theós) est obligatoire : « apotéose » sans h est fautif."}},{"id":"premices","mot":"prémices","nature":"nom féminin","definitions":["Premiers signes, commencements, débuts d\'un phénomène ou d\'un événement.","Dans l\'Antiquité, premiers fruits de la terre ou premiers-nés du troupeau offerts à la divinité."],"phonetique":"/pʁe.mis/","etymologie":"Du latin primitiae, « prémices, premiers produits », de primus (premier).","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["commencement","début","prélude"],"antonymes":["aboutissement","fin","épilogue"],"exemplesCorrects":["On sentait déjà les prémices du printemps dans l\'air tiède.","Les prémices de la crise étaient visibles dès l\'automne.","Ces premiers succès n\'étaient que les prémices d\'une longue série."],"exemplesIncorrects":["Sa démonstration reposait sur de fausses prémices logiques.","Le syllogisme part de deux prémices pour aboutir à une conclusion.","Il faut accepter les prémices du raisonnement avant de le critiquer."],"distracteurs":["auspices","préludes","balbutiements"],"anecdote":"« Prémices » (les premiers signes) se confond souvent avec « prémisse » (une proposition d\'un raisonnement). On parle des prémices du printemps, mais des prémisses d\'un syllogisme.","categorie":"piege-sens","piege":{"formeFautive":"les prémices d\'un raisonnement","explication":"« Prémices » désigne les premiers signes ou débuts ; la proposition initiale d\'un raisonnement est une « prémisse ». Les deux mots ne sont pas interchangeables."}},{"id":"premisse","mot":"prémisse","nature":"nom féminin","definitions":["Chacune des deux propositions initiales d\'un syllogisme, dont on tire une conclusion.","Fait ou proposition d\'où découle une conséquence ; point de départ d\'un raisonnement."],"phonetique":"/pʁe.mis/","etymologie":"Du latin médiéval praemissa (sententia), « (proposition) mise en avant », de praemittere (envoyer devant).","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["postulat","proposition","axiome"],"antonymes":["conclusion","conséquence","déduction"],"exemplesCorrects":["Si les prémisses sont fausses, la conclusion l\'est aussi.","Le syllogisme repose sur deux prémisses et une conclusion.","Sa démonstration partait de prémisses contestables."],"exemplesIncorrects":["On devinait les prémisses du printemps dans les bourgeons.","Les prémisses de la révolte couvaient depuis des mois.","Ce vin était l\'une des premières prémisses offertes aux dieux."],"distracteurs":["corollaire","hypothèse","lemme"],"anecdote":"« Prémisse » (proposition de départ d\'un raisonnement) est souvent confondu avec « prémices » (les premiers signes). On dit les prémisses d\'un syllogisme, mais les prémices d\'une saison.","categorie":"piege-sens","piege":{"formeFautive":"les prémisses du printemps","explication":"« Prémisse » désigne une proposition d\'un raisonnement ; les premiers signes d\'un phénomène sont les « prémices ». Ne pas confondre les deux."}},{"id":"recrudescence","mot":"recrudescence","nature":"nom féminin","definitions":["Reprise, aggravation d\'un phénomène après une accalmie ou une rémission.","Augmentation soudaine de l\'intensité d\'une maladie, d\'un mal."],"phonetique":"/ʁə.kʁy.de.sɑ̃s/","etymologie":"Du latin recrudescere, « redevenir cru, se rouvrir (en parlant d\'une plaie) », de re- et crudescere (devenir cru), de crudus (cru, saignant).","registre":"soutenu","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["regain","reprise","intensification"],"antonymes":["accalmie","rémission","apaisement"],"exemplesCorrects":["On observe une recrudescence des cambriolages cet été.","La recrudescence de la grippe a saturé les urgences.","Une recrudescence de violence a éclaté après le verdict."],"exemplesIncorrects":["La recrudescence du calme a apaisé tout le quartier.","Après une recrudescence, la maladie a enfin reculé.","Il a ressenti une recrudescence de fatigue qui l\'a reposé."],"distracteurs":["résurgence","prolifération","exacerbation"],"anecdote":"Le mot vient du latin crudus, « cru, saignant », et désignait d\'abord la réouverture d\'une plaie ; il implique toujours une reprise après une accalmie, jamais un simple commencement.","categorie":"mot-rare"},{"id":"subvenir","mot":"subvenir","nature":"verbe","definitions":["Fournir à quelqu\'un ce qui lui est nécessaire ; pourvoir aux besoins de quelqu\'un ou de quelque chose."],"phonetique":"/syb.və.niʁ/","etymologie":"Du latin subvenire, « venir au secours », de sub- (sous) et venire (venir).","registre":"soutenu","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["pourvoir","secourir","entretenir"],"antonymes":["priver","démunir","négliger"],"exemplesCorrects":["Il travaille dur pour subvenir aux besoins de sa famille.","Cette pension lui permet de subvenir à son entretien.","L\'État doit subvenir aux dépenses les plus urgentes."],"exemplesIncorrects":["Un imprévu a subvenu pendant la réunion.","Plusieurs incidents ont subvenu cette nuit.","Il a subvenu un accident sur l\'autoroute."],"distracteurs":["survenir","prévenir","convenir"],"anecdote":"« Subvenir » signifie pourvoir aux besoins, et se construit toujours avec « à » ; il est souvent confondu avec « survenir » (arriver de façon imprévue), qui a un sens et une construction tout différents.","categorie":"piege-sens","piege":{"formeFautive":"un problème a subvenu","explication":"« Subvenir » signifie pourvoir aux besoins (subvenir à) ; pour exprimer qu\'un événement arrive à l\'improviste, on emploie « survenir »."}},{"id":"amphitheatre","mot":"amphithéâtre","nature":"nom masculin","definitions":["Grande salle de cours ou de conférences disposée en gradins.","Vaste édifice antique de forme ovale, à gradins étagés autour d\'une arène."],"phonetique":"/ɑ̃.fi.te.atʁ/","etymologie":"Du latin amphitheatrum, du grec amphitheatron, de amphi- (autour) et theatron (théâtre, lieu où l\'on regarde).","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["amphi","arène","hémicycle"],"antonymes":[],"exemplesCorrects":["Le cours magistral se tient dans le grand amphithéâtre.","Les gladiateurs combattaient dans l\'amphithéâtre romain.","L\'amphithéâtre était bondé pour la conférence inaugurale."],"exemplesIncorrects":["Il a planté un amphithéâtre de roses dans son jardin.","Le chef a servi l\'amphithéâtre en entrée du repas.","Elle portait un amphithéâtre autour du cou."],"distracteurs":["auditorium","colisée","planétarium"],"anecdote":"Le mot s\'écrit avec th (du grec theatron) et un accent circonflexe sur le â : « amphithéâtre ». Oublier l\'accent du â ou écrire « amphitéâtre » sont des fautes courantes.","categorie":"piege-orthographe","piege":{"formeFautive":"amphitéatre","explication":"Le mot exige le th grec et l\'accent circonflexe sur le â : « amphithéâtre », et non « amphitéatre »."}},{"id":"antediluvien","mot":"antédiluvien","nature":"adjectif","definitions":["Qui est antérieur au Déluge biblique.","Par extension, extrêmement ancien, démodé, qui date d\'une autre époque."],"phonetique":"/ɑ̃.te.di.ly.vjɛ̃/","etymologie":"Composé savant du latin ante (avant) et diluvium (déluge) ; formé au XVIIIe siècle.","registre":"littéraire","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["archaïque","préhistorique","désuet"],"antonymes":["moderne","récent","contemporain"],"exemplesCorrects":["Il conduit encore une voiture antédiluvienne.","Ces méthodes antédiluviennes n\'ont plus cours aujourd\'hui.","On a retrouvé des fossiles d\'animaux antédiluviens."],"exemplesIncorrects":["Ce smartphone flambant neuf est résolument antédiluvien.","La mode antédiluvienne de cet été plaît aux jeunes.","Il a acheté un modèle antédiluvien sorti la semaine dernière."],"distracteurs":["séculaire","vétuste","obsolète"],"anecdote":"Littéralement « d\'avant le Déluge », le mot s\'emploie surtout au figuré pour railler ce qui est désespérément vieux ou dépassé ; il fut popularisé au siècle des Lumières dans les débats sur l\'âge de la Terre.","categorie":"mot-rare"},{"id":"peripetie","mot":"péripétie","nature":"nom féminin","definitions":["Changement subit de situation dans une action, un récit ; rebondissement imprévu.","Au théâtre classique, événement qui renverse le cours de l\'intrigue."],"phonetique":"/pe.ʁi.pe.si/","etymologie":"Du grec peripéteia, « changement soudain », de peripiptein (tomber autour, changer brusquement), de peri- (autour) et piptein (tomber).","registre":"courant","niveau":2,"themes":["litteraire","quotidien"],"synonymes":["rebondissement","incident","aventure"],"antonymes":["stagnation","monotonie","immobilité"],"exemplesCorrects":["Le voyage fut riche en péripéties.","Après mille péripéties, ils atteignirent enfin le sommet.","La pièce enchaîne les péripéties jusqu\'au dénouement."],"exemplesIncorrects":["Il a péripétie son discours d\'une anecdote drôle.","Elle souffrait d\'une péripétie à la cheville.","Le menuisier a posé une nouvelle péripétie à la porte."],"distracteurs":["odyssée","intrigue","tribulation"],"anecdote":"On écrit « péripétie » avec deux accents aigus et un t prononcé /s/ devant le i final, sans c : la graphie « péripécie » est fautive, bien que la prononciation puisse le laisser croire.","categorie":"piege-orthographe","piege":{"formeFautive":"péripécie","explication":"Le mot s\'écrit avec un t (du grec piptein), prononcé /s/ devant le i : « péripétie », et jamais « péripécie »."}},{"id":"psychiatre","mot":"psychiatre","nature":"nom","definitions":["Médecin spécialiste du diagnostic et du traitement des troubles mentaux."],"phonetique":"/psi.kjatʁ/","etymologie":"Du grec psukhê (âme, esprit) et iatros (médecin) ; formé au XIXe siècle.","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["aliéniste","psychothérapeute"],"antonymes":[],"exemplesCorrects":["Son psychiatre lui a prescrit un nouveau traitement.","Elle consulte un psychiatre depuis plusieurs mois.","Le psychiatre a posé un diagnostic après plusieurs entretiens."],"exemplesIncorrects":["Le psychiatre a réparé la fuite sous l\'évier.","Il a appelé un psychiatre pour repeindre le salon.","Le psychiatre a opéré la fracture du tibia."],"distracteurs":["psychologue","pédiatre","psychanalyste"],"anecdote":"« Psychiatre » s\'écrit sans accent circonflexe sur le a, contrairement à ce que beaucoup croient : la forme « psychiâtre » est fautive. Le mot conjugue le psy- de psukhê et le -iatre de iatros, « médecin ».","categorie":"piege-orthographe","piege":{"formeFautive":"psychiâtre","explication":"Aucun accent circonflexe sur le a : on écrit « psychiatre », comme « pédiatre », et non « psychiâtre »."}},{"id":"rythme","mot":"rythme","nature":"nom masculin","definitions":["Retour régulier et mesuré d\'éléments dans le temps ; cadence.","Mouvement général, allure à laquelle se déroule une activité."],"phonetique":"/ʁitm/","etymologie":"Du latin rhythmus, du grec rhuthmos, « mouvement réglé et mesuré », de rhein (couler).","registre":"courant","niveau":1,"themes":["abstrait","quotidien"],"synonymes":["cadence","tempo","allure"],"antonymes":["irrégularité","arythmie"],"exemplesCorrects":["Il marche à un rythme soutenu.","La musique imposait un rythme entraînant.","Le rythme des saisons règle la vie des campagnes."],"exemplesIncorrects":["Il a rythme le mur d\'une couche de peinture.","Elle a mangé un rythme entier au dessert.","Le plombier a rythme la canalisation hier."],"distracteurs":["mélodie","tempérament","harmonie"],"anecdote":"« Rythme » contient deux fois la lettre h (rh- au début, -th- au milieu) et un y, héritage du grec rhuthmos. Beaucoup oublient le premier h ou remplacent le y par un i : « rithme » et « rytme » sont fautifs.","categorie":"piege-orthographe","piege":{"formeFautive":"rytme","explication":"Le mot vient du grec rhuthmos : il prend rh- au début, un y et -th- au milieu (« rythme »). Les formes « rytme » et « rithme » sont fautives."}},{"id":"ressusciter","mot":"ressusciter","nature":"verbe","definitions":["Revenir de la mort à la vie ; ramener un mort à la vie.","Au figuré, faire renaître, redonner vie ou vigueur à ce qui était disparu."],"phonetique":"/ʁe.sy.si.te/","etymologie":"Du latin resuscitare, « réveiller, ranimer », de re- et suscitare (soulever, exciter).","registre":"courant","niveau":2,"themes":["abstrait","litteraire"],"synonymes":["renaître","revivre","raviver"],"antonymes":["mourir","périr","s\'éteindre"],"exemplesCorrects":["Selon les Évangiles, Lazare ressuscita après quatre jours.","Ce metteur en scène a ressuscité une pièce oubliée.","Le printemps ressuscite la nature endormie."],"exemplesIncorrects":["Il a ressuscité la vaisselle après le dîner.","Elle a ressuscité la porte d\'un coup de pinceau.","Le mécanicien a ressuscité le pneu crevé en une minute."],"distracteurs":["réanimer","revigorer","ranimer"],"anecdote":"« Ressusciter » s\'écrit avec deux s au début (prononcés /s/) puis un seul s suivi d\'un c (le groupe -sci-). On oublie souvent ce c muet ou on inverse les doubles lettres : « réssusiter » et « resusciter » sont fautifs.","categorie":"piege-orthographe","piege":{"formeFautive":"resusciter","explication":"Le mot prend deux s après le préfixe re- (ressusciter) puis le groupe -sci- avec un c : « resusciter » ou « ressuciter » sont fautifs."}},{"id":"areopage","mot":"aréopage","nature":"nom masculin","definitions":["Assemblée, réunion de personnes particulièrement compétentes ou savantes dans un domaine.","Dans l\'Antiquité, tribunal d\'Athènes qui siégeait sur la colline d\'Arès."],"phonetique":"/a.ʁe.ɔ.paʒ/","etymologie":"Emprunté au latin areopagus, du grec ancien Areios pagos, « la colline d\'Arès », de Arês (le dieu Arès, Mars) et pagos (colline).","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["assemblée","tribunal","cénacle"],"antonymes":["individu","quidam"],"exemplesCorrects":["Un aréopage de spécialistes fut réuni pour trancher la question.","Elle dut défendre sa thèse devant un aréopage de professeurs intimidants.","Le jury formait un aréopage de critiques redoutés."],"exemplesIncorrects":["Il a posé son aréopage sur la table avant de partir.","Nous avons repeint l\'aréopage de la cuisine en bleu."],"distracteurs":["conclave","consistoire","panthéon"],"anecdote":"L\'aréopage athénien tirait son nom de la colline d\'Arès où, selon la légende, le dieu de la guerre lui-même aurait été jugé pour meurtre.","categorie":"mot-rare"},{"id":"degingande","mot":"dégingandé","nature":"adjectif","definitions":["Dont l\'allure est décousue, gauche, comme désarticulée ; qui a des mouvements disgracieux et mal coordonnés."],"phonetique":"/de.ʒɛ̃.ɡɑ̃.de/","etymologie":"Altération de l\'ancien français deshingander, « disloquer », apparenté à hingre (« maigre, chétif »), d\'origine incertaine, peut-être germanique.","registre":"courant","niveau":3,"themes":["quotidien","litteraire"],"synonymes":["disloqué","gauche","désarticulé"],"antonymes":["gracieux","harmonieux","élégant"],"exemplesCorrects":["Ce grand adolescent dégingandé ne savait que faire de ses longs bras.","Sa démarche dégingandée le faisait remarquer de loin.","Une silhouette dégingandée se profila dans l\'embrasure de la porte."],"exemplesIncorrects":["Le tissu de la robe est très dégingandé et brillant.","Ce vin dégingandé a un goût de fruits rouges."],"distracteurs":["décharné","déguenillé","désaxé"],"anecdote":"Le mot évoque l\'image d\'un pantin dont les membres pendent de travers, sans la coordination d\'une démarche assurée.","categorie":"mot-rare"},{"id":"exorbitant","mot":"exorbitant","nature":"adjectif","definitions":["Qui sort de la mesure, qui dépasse toute limite raisonnable ; excessif, démesuré."],"phonetique":"/ɛɡ.zɔʁ.bi.tɑ̃/","etymologie":"Du bas latin exorbitans, participe présent de exorbitare, « sortir de l\'orbite, de la voie », de ex- (hors de) et orbita (ornière, trajectoire).","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["excessif","démesuré","astronomique"],"antonymes":["modéré","raisonnable","modique"],"exemplesCorrects":["Le loyer qu\'il réclamait était tout à fait exorbitant.","Ces honoraires exorbitants découragèrent les clients.","Elle jugea exorbitantes les prétentions du vendeur."],"exemplesIncorrects":["Il a exhorbitant les yeux de surprise en la voyant.","Le prix exhorbitant figurait sur l\'étiquette."],"distracteurs":["extravagant","exubérant","prohibitif"],"anecdote":"On écrit souvent à tort « exhorbitant » par confusion avec « exhorter », mais le mot s\'écrit sans h : il vient de orbita, l\'orbite, ce qui « sort de sa trajectoire ».","categorie":"piege-orthographe","piege":{"formeFautive":"exhorbitant","explication":"Le mot s\'écrit sans h après le x : exorbitant. Il dérive du latin exorbitare (sortir de l\'orbite), et non d\'« exhorter »."}},{"id":"dorenavant","mot":"dorénavant","nature":"adverbe","definitions":["À partir de ce moment, désormais, à l\'avenir."],"phonetique":"/dɔ.ʁe.na.vɑ̃/","etymologie":"De l\'ancien français d\'or en avant, « de maintenant en avant », où or signifie « maintenant » (du latin hac hora).","registre":"soutenu","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["désormais","dès lors","à l\'avenir"],"antonymes":["jadis","autrefois","auparavant"],"exemplesCorrects":["Dorénavant, je fermerai la porte à clé.","Tu devras dorénavant rendre tes devoirs à l\'heure.","Dorénavant, plus rien ne serait comme avant."],"exemplesIncorrects":["Il a dorénavanté toute la nuit sur ce problème.","Le dorénavant de la réunion fut très long."],"distracteurs":["antérieurement","incessamment","naguère"],"anecdote":"On écrit fréquemment « dorénivant » ou « dorrénavant », mais la forme correcte est dorénavant : un seul r, accent aigu sur le e, vestige de « d\'or en avant ».","categorie":"piege-orthographe","piege":{"formeFautive":"dorénivant","explication":"La forme correcte est dorénavant (un seul r, terminaison -avant). Elle vient de « d\'or en avant », jamais « -ivant »."}},{"id":"rebondissement","mot":"rebondissement","nature":"nom masculin","definitions":["Événement imprévu qui relance une affaire, une intrigue ou une situation.","Fait de rebondir, de reprendre de l\'élan."],"phonetique":"/ʁə.bɔ̃.dis.mɑ̃/","etymologie":"Dérivé du verbe rebondir, de re- (de nouveau) et bondir (du latin populaire bombitire, « bourdonner »).","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["coup de théâtre","péripétie","retournement"],"antonymes":["dénouement","stagnation","enlisement"],"exemplesCorrects":["L\'affaire connut un rebondissement spectaculaire la semaine suivante.","Les rebondissements du procès tenaient le pays en haleine.","Ce roman multiplie les rebondissements jusqu\'à la dernière page."],"exemplesIncorrects":["Il a rebondissement le ballon contre le mur.","Le rebondissement de la balle était très haut sur le terrain."],"distracteurs":["soubresaut","revirement","ricochet"],"anecdote":"On écrit souvent « rebondissment » en oubliant le e, mais le mot conserve le e du verbe rebondir : rebondissement, avec deux s.","categorie":"piege-orthographe","piege":{"formeFautive":"rebondissment","explication":"Il faut conserver le e du radical : rebondissement, avec deux s. La graphie « rebondissment » est fautive."}},{"id":"obnubiler","mot":"obnubiler","nature":"verbe","definitions":["Occuper l\'esprit de quelqu\'un au point de l\'obséder ; obscurcir le jugement, hanter la pensée."],"phonetique":"/ɔb.ny.bi.le/","etymologie":"Du latin obnubilare, « couvrir de nuages, obscurcir », de ob- (devant) et nubilare (se couvrir de nuages), de nubes (nuage).","registre":"soutenu","niveau":3,"themes":["abstrait","emotions"],"synonymes":["obséder","hanter","préoccuper"],"antonymes":["libérer","détacher","apaiser"],"exemplesCorrects":["Cette idée fixe l\'obnubilait au point qu\'il en perdait le sommeil.","Obnubilé par le succès, il négligeait tout le reste.","La peur de l\'échec obnubile parfois les esprits les plus brillants."],"exemplesIncorrects":["Il a obnubilé la fenêtre avec un rideau épais.","Nous avons obnubilé la sauce avant de la servir."],"distracteurs":["subjuguer","obstruer","offusquer"],"anecdote":"On prononce et on écrit souvent à tort « obnibuler » par interversion des syllabes ; la forme correcte est obnubiler, du latin nubes, le nuage qui obscurcit.","categorie":"piege-orthographe","piege":{"formeFautive":"obnibuler","explication":"La forme correcte est obnubiler (nu-bi), du latin nubes, « nuage ». La graphie « obnibuler », par interversion des syllabes, est fautive."}},{"id":"inclination","mot":"inclination","nature":"nom féminin","definitions":["Penchant, disposition naturelle, goût marqué pour quelque chose ou quelqu\'un.","Mouvement du corps, en particulier de la tête, que l\'on incline en signe de respect ou d\'acquiescement."],"phonetique":"/ɛ̃.kli.na.sjɔ̃/","etymologie":"Du latin inclinatio, « action de pencher », de inclinare (pencher), de in- et clinare (incliner).","registre":"soutenu","niveau":3,"themes":["emotions","abstrait"],"synonymes":["penchant","propension","attirance"],"antonymes":["aversion","répugnance","dégoût"],"exemplesCorrects":["Il avait une inclination naturelle pour la musique.","Son inclination pour la peinture se manifesta très tôt.","Elle salua d\'une légère inclination de la tête."],"exemplesIncorrects":["L\'inclination du toit était de trente degrés.","On mesure l\'inclination de la pente à l\'aide d\'un instrument."],"distracteurs":["aspiration","vocation","affinité"],"anecdote":"On confond souvent inclination et inclinaison : inclination désigne un penchant du cœur ou de l\'esprit, tandis qu\'inclinaison renvoie à un angle, à l\'état de ce qui est physiquement penché.","categorie":"piege-sens","piege":{"formeFautive":"inclinaison (au sens de penchant)","explication":"Pour un goût, un penchant affectif, on dit inclination. Inclinaison ne s\'emploie que pour un angle ou l\'état de ce qui est physiquement penché."}},{"id":"inclinaison","mot":"inclinaison","nature":"nom féminin","definitions":["État de ce qui est penché ; angle formé par une ligne ou une surface avec un plan de référence."],"phonetique":"/ɛ̃.kli.nɛ.zɔ̃/","etymologie":"Dérivé de incliner, du latin inclinare, « pencher », de in- et clinare.","registre":"courant","niveau":2,"themes":["nature","abstrait"],"synonymes":["pente","déclivité","obliquité"],"antonymes":["horizontalité","verticalité","aplomb"],"exemplesCorrects":["L\'inclinaison du terrain rendait la marche difficile.","On régla l\'inclinaison du dossier pour plus de confort.","L\'inclinaison de l\'axe terrestre est à l\'origine des saisons."],"exemplesIncorrects":["Il éprouvait une vive inclinaison pour la poésie.","Son inclinaison à la générosité était bien connue."],"distracteurs":["courbure","déclinaison","élévation"],"anecdote":"À ne pas confondre avec inclination : inclinaison concerne un angle ou une pente physique, tandis qu\'inclination désigne un penchant du cœur ou de l\'esprit.","categorie":"piege-sens","piege":{"formeFautive":"inclination (au sens d\'angle)","explication":"Pour un angle ou une pente, on dit inclinaison. Inclination est réservé au penchant affectif ou intellectuel."}},{"id":"perpetrer","mot":"perpétrer","nature":"verbe","definitions":["Commettre, accomplir un acte criminel ou répréhensible."],"phonetique":"/pɛʁ.pe.tʁe/","etymologie":"Du latin perpetrare, « accomplir, exécuter », de per- (jusqu\'au bout) et patrare (accomplir).","registre":"soutenu","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["commettre","accomplir","exécuter"],"antonymes":["empêcher","prévenir","réparer"],"exemplesCorrects":["Les malfaiteurs avaient perpétré leur forfait à la nuit tombée.","Qui a pu perpétrer un crime aussi odieux ?","L\'attentat fut perpétré en plein jour."],"exemplesIncorrects":["Cette tradition se perpétre de génération en génération.","Il veut perpétrer le souvenir de son maître."],"distracteurs":["fomenter","perpétuer","instaurer"],"anecdote":"On confond souvent perpétrer (commettre un méfait) et perpétuer (faire durer) : on perpètre un crime, mais on perpétue une coutume.","categorie":"piege-sens","piege":{"formeFautive":"perpétuer (au sens de commettre)","explication":"Perpétrer signifie commettre un acte (souvent criminel). Perpétuer signifie faire durer, transmettre : ce sont deux verbes distincts à ne pas confondre."}},{"id":"perpetuer","mot":"perpétuer","nature":"verbe","definitions":["Faire durer toujours ou longtemps ; transmettre, faire subsister sans interruption."],"phonetique":"/pɛʁ.pe.tɥe/","etymologie":"Du latin perpetuare, « rendre continu, perpétuel », de perpetuus (continu), de per- et petere (aller vers).","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["pérenniser","transmettre","maintenir"],"antonymes":["abolir","interrompre","supprimer"],"exemplesCorrects":["Ils tiennent à perpétuer les traditions familiales.","Cette fondation perpétue la mémoire de l\'écrivain.","L\'espèce se perpétue grâce à la reproduction."],"exemplesIncorrects":["Les voleurs ont perpétué un cambriolage audacieux.","On l\'accuse d\'avoir perpétué un meurtre."],"distracteurs":["perpétrer","pérorer","pérégriner"],"anecdote":"Ne pas confondre avec perpétrer : on perpétue une mémoire ou une coutume, mais on perpètre un crime.","categorie":"piege-sens","piege":{"formeFautive":"perpétrer (au sens de faire durer)","explication":"Perpétuer signifie faire durer, transmettre. Perpétrer signifie commettre un acte répréhensible : les deux verbes ne sont pas interchangeables."}},{"id":"infection","mot":"infection","nature":"nom féminin","definitions":["Grande puanteur, odeur infecte et corrompue.","Chose extrêmement répugnante ou dégoûtante.","Pénétration et développement dans l\'organisme d\'un agent pathogène."],"phonetique":"/ɛ̃.fɛk.sjɔ̃/","etymologie":"Du latin infectio, « action de teindre, d\'altérer », de inficere (« imprégner, gâter »), de in- et facere (faire).","registre":"courant","niveau":2,"themes":["quotidien","nature"],"synonymes":["puanteur","pestilence","fétidité"],"antonymes":["parfum","fragrance","salubrité"],"exemplesCorrects":["Quelle infection ! On ne peut pas respirer dans cette pièce.","Le marais dégageait une infection insupportable.","Ce restaurant, une vraie infection, fut fermé sur-le-champ."],"exemplesIncorrects":["Il éprouvait une grande infection pour la lecture.","L\'infection du toit le protégeait de la pluie."],"distracteurs":["miasme","relent","remugle"],"anecdote":"Avant son sens médical moderne, infection désignait surtout une puanteur ; on dit encore « quelle infection ! » devant une odeur nauséabonde.","categorie":"mot-rare"},{"id":"gabegie","mot":"gabegie","nature":"nom féminin","definitions":["Gaspillage désordonné dû à une mauvaise gestion ; gestion chaotique et dispendieuse."],"phonetique":"/ɡa.bə.ʒi/","etymologie":"D\'origine incertaine, peut-être de l\'ancien français gaber (« railler, tromper »), apparenté à une racine évoquant la fraude ou le désordre.","registre":"soutenu","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["gaspillage","gâchis","dilapidation"],"antonymes":["économie","gestion","rigueur"],"exemplesCorrects":["La commission dénonça la gabegie des fonds publics.","Une telle gabegie ne pouvait que mener à la faillite.","On reprochait au directeur la gabegie qui régnait dans ses services."],"exemplesIncorrects":["Il a rangé la gabegie sur l\'étagère du salon.","La gabegie soufflait fort ce matin sur la côte."],"distracteurs":["bureaucratie","incurie","prévarication"],"anecdote":"Le mot, longtemps cantonné au langage administratif, est devenu un terme de prédilection des rapports parlementaires pour fustiger le mauvais usage de l\'argent public.","categorie":"mot-rare"},{"id":"vraisemblable","mot":"vraisemblable","nature":"adjectif","definitions":["Qui paraît vrai, qui a toutes les apparences de la vérité ; plausible, probable."],"phonetique":"/vʁɛ.sɑ̃.blabl/","etymologie":"Composé de vrai et de semblable, calque du latin verisimilis, de verum (le vrai) et similis (semblable).","registre":"courant","niveau":1,"themes":["abstrait","quotidien"],"synonymes":["plausible","probable","crédible"],"antonymes":["invraisemblable","improbable","absurde"],"exemplesCorrects":["Son explication paraît tout à fait vraisemblable.","Il a inventé un alibi vraisemblable mais faux.","Rien dans ce récit n\'est vraisemblable."],"exemplesIncorrects":["Il a vraisemblable la porte d\'un coup d\'épaule.","Nous avons vraisemblé toute la soirée."],"distracteurs":["véridique","crédule","ressemblant"],"anecdote":"On écrit souvent à tort « vraissemblable » avec deux s, par fausse analogie avec « ressembler ». Le mot ne prend qu\'un seul s, car il est formé de « vrai » + « semblable ».","categorie":"piege-orthographe","piege":{"formeFautive":"vraissemblable","explication":"Le mot s\'écrit avec un seul s : « vrai » + « semblable ». Le doublement du s (« vraissemblable ») est une faute répandue."}},{"id":"susceptible","mot":"susceptible","nature":"adjectif","definitions":["Qui se vexe ou s\'offense facilement ; ombrageux.","Qui peut recevoir une qualité, subir une modification ou accomplir une action (susceptible de)."],"phonetique":"/sy.sɛp.tibl/","etymologie":"Emprunté au bas latin susceptibilis, « capable de recevoir », du latin suscipere (prendre sur soi, recevoir).","registre":"courant","niveau":2,"themes":["abstrait","emotions"],"synonymes":["ombrageux","chatouilleux","capable"],"antonymes":["impassible","indifférent","flegmatique"],"exemplesCorrects":["Ne lui en parle pas, il est très susceptible.","Ce projet est susceptible d\'évoluer encore.","Toute personne susceptible de témoigner sera convoquée."],"exemplesIncorrects":["Il a susceptible la remarque comme un affront.","Nous avons susceptibilisé la salle de réunion."],"distracteurs":["perceptible","réceptif","irascible"],"anecdote":"On voit parfois « suceptible » sans le premier s. Le mot s\'écrit avec deux s rapprochés (su-s-ceptible), du préfixe latin sus- ; il ne faut pas en oublier un.","categorie":"piege-orthographe","piege":{"formeFautive":"suceptible","explication":"Le mot prend bien deux s : « su-s-ceptible ». La forme « suceptible » sans le premier s est fautive."}},{"id":"millenaire","mot":"millénaire","nature":"nom masculin","definitions":["Période de mille ans.","(adjectif) Qui a mille ans ou plusieurs milliers d\'années."],"phonetique":"/mi.le.nɛʁ/","etymologie":"Emprunté au latin millenarius, « qui contient mille », de mille.","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["multiséculaire"],"antonymes":["récent","éphémère","nouveau"],"exemplesCorrects":["Le passage au troisième millénaire a été célébré en grande pompe.","Cette tradition millénaire se transmet encore.","On a fêté le millénaire de la fondation de la ville."],"exemplesIncorrects":["Il a millénaire la corde pour l\'attacher.","Nous avons millénairé toute la nuit."],"distracteurs":["centenaire","séculaire","millésime"],"anecdote":"On oublie fréquemment l\'un des deux l. « Millénaire » prend deux l comme « mille », mais un seul n, à la différence de « millionnaire » qui en prend deux.","categorie":"piege-orthographe","piege":{"formeFautive":"milénaire","explication":"Le mot prend deux l (comme « mille ») mais un seul n. La forme « milénaire » avec un seul l est fautive."}},{"id":"fluorescent","mot":"fluorescent","nature":"adjectif","definitions":["Qui émet de la lumière sous l\'effet d\'un rayonnement reçu (fluorescence), et cesse de briller dès que ce rayonnement s\'arrête."],"phonetique":"/fly.ɔ.ʁe.sɑ̃/","etymologie":"Emprunté à l\'anglais fluorescent, forgé en 1853 par le physicien George Gabriel Stokes sur fluor (la fluorine, qui présente ce phénomène), sur le modèle de phosphorescent.","registre":"courant","niveau":2,"themes":["nature","abstrait"],"synonymes":["luminescent"],"antonymes":["terne","mat","opaque"],"exemplesCorrects":["Le gilet de sécurité est d\'un jaune fluorescent.","Sous la lampe à ultraviolets, le minéral devient fluorescent.","Elle a surligné le passage avec un marqueur fluorescent."],"exemplesIncorrects":["Il a fluorescent la lampe d\'un coup de doigt.","Nous avons fluorescent les murs de la pièce."],"distracteurs":["phosphorescent","incandescent","translucide"],"anecdote":"On écrit très souvent « fluo » dans le langage courant, mais le mot complet contient bien deux o : « flu-o-rescent », du nom de la fluorine. Oublier le second o (« flurescent ») est une faute fréquente.","categorie":"piege-orthographe","piege":{"formeFautive":"flurescent","explication":"Le mot contient le groupe « -uo- » (de fluorine) : on écrit fluorescent. La forme « flurescent » sans le o est fautive."}},{"id":"quincaillerie","mot":"quincaillerie","nature":"nom féminin","definitions":["Ensemble d\'objets et d\'ustensiles en métal (clous, vis, serrures, outils).","Commerce ou magasin où l\'on vend ces articles."],"phonetique":"/kɛ̃.kaj.ʁi/","etymologie":"Dérivé de l\'ancien français quincaille, mot d\'origine onomatopéique évoquant le bruit du métal entrechoqué, avec le suffixe -erie.","registre":"courant","niveau":2,"themes":["quotidien"],"synonymes":["ferronnerie","droguerie"],"antonymes":[],"exemplesCorrects":["Il faut passer à la quincaillerie acheter des vis.","La quincaillerie du coin a fermé l\'an dernier.","Toute cette quincaillerie traînait au fond du garage."],"exemplesIncorrects":["Il a quincaillerie la porte avec soin.","Nous avons quincaillé les outils du jardin."],"distracteurs":["serrurerie","chaudronnerie","bimbeloterie"],"anecdote":"Le mot accumule les pièges : il commence par « quin- » et non « can- », et se termine par « -aillerie » avec le son « ye ». On écrit parfois à tort « quincaierie » en oubliant le groupe « -aill- ».","categorie":"piege-orthographe","piege":{"formeFautive":"quincaierie","explication":"Le mot s\'écrit « quin-cail-le-rie » : il faut le groupe « -aill- » avec deux l, et un début en « quin- ». Les formes simplifiées comme « quincaierie » sont fautives."}},{"id":"atterrir","mot":"atterrir","nature":"verbe","definitions":["Se poser sur le sol, en parlant d\'un aéronef.","(familier) Arriver, échouer quelque part."],"phonetique":"/a.te.ʁiʁ/","etymologie":"Dérivé de terre, avec le préfixe a- (ad-, mouvement vers) et le suffixe -ir ; littéralement « venir à terre ».","registre":"courant","niveau":1,"themes":["quotidien","nature"],"synonymes":["se poser"],"antonymes":["décoller","s\'envoler","redécoller"],"exemplesCorrects":["L\'avion va atterrir dans quelques minutes.","Après bien des détours, il a fini par atterrir chez nous.","Le pilote a réussi à atterrir malgré le brouillard."],"exemplesIncorrects":["Il a atterri la valise sur le tapis roulant.","Nous avons atterri le ballon dans le jardin."],"distracteurs":["amerrir","amarrer","alunir"],"anecdote":"On oublie souvent un t ou un r. « Atterrir » prend deux t et deux r, comme « terre ». Penser au mot « terre » aide à retenir le double r.","categorie":"piege-orthographe","piege":{"formeFautive":"aterrir","explication":"Le verbe prend deux t et deux r (de « terre ») : atterrir. Les formes « aterrir » (un t) ou « atterir » (un r) sont fautives."}},{"id":"interpeller","mot":"interpeller","nature":"verbe","definitions":["Adresser la parole à quelqu\'un de façon brusque ou pressante pour lui demander quelque chose.","(droit) Sommer quelqu\'un de répondre ; arrêter une personne.","Susciter l\'intérêt, la réflexion de quelqu\'un."],"phonetique":"/ɛ̃.tɛʁ.pe.le/","etymologie":"Emprunté au latin interpellare, « interrompre en parlant », de inter- (entre) et pellere (pousser).","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["apostropher","héler","questionner"],"antonymes":["ignorer","esquiver"],"exemplesCorrects":["Un passant l\'a interpellé pour lui demander son chemin.","Le député a interpellé le ministre en pleine séance.","Cette question d\'éthique nous interpelle tous."],"exemplesIncorrects":["Il a interpellé la porte avant d\'entrer.","Nous avons interpellé le silence de la nuit."],"distracteurs":["interroger","interjeter","rappeler"],"anecdote":"Traditionnellement, « interpeller » prend deux l à toutes les formes, contrairement à « appeler » qui n\'en double qu\'un. La forme « interpeler » à un seul l, alignée sur « appeler », a été admise par les rectifications de 1990, mais la graphie classique reste la plus courante.","categorie":"piege-orthographe","piege":{"formeFautive":"interpeler","explication":"La graphie traditionnelle est « interpeller » avec deux l à toutes les formes (j\'interpelle, nous interpellons). La forme « interpeler » à un seul l n\'est tolérée que depuis les rectifications de 1990."}},{"id":"echalote","mot":"échalote","nature":"nom féminin","definitions":["Plante potagère voisine de l\'oignon, dont le bulbe allongé sert de condiment."],"phonetique":"/e.ʃa.lɔt/","etymologie":"De l\'ancien français eschaloigne, du latin (cepa) Ascalonia, « (oignon) d\'Ascalon », ville de Palestine.","registre":"courant","niveau":2,"themes":["nature","quotidien"],"synonymes":[],"antonymes":[],"exemplesCorrects":["Il a fait revenir une échalote dans le beurre.","La sauce au vin rouge se prépare avec des échalotes.","Hache finement l\'échalote avant de l\'ajouter."],"exemplesIncorrects":["Il a échalote la viande pendant deux heures.","Nous avons échaloté la sauce trop longtemps."],"distracteurs":["ciboulette","civette","oignonade"],"anecdote":"Contrairement à « carotte » ou « biscotte », le mot « échalote » ne prend qu\'un seul t. L\'écrire « échalotte » avec deux t est une faute très répandue.","categorie":"piege-orthographe","piege":{"formeFautive":"échalotte","explication":"Le mot s\'écrit avec un seul t : échalote. La forme « échalotte » avec deux t, par analogie avec « carotte », est fautive."}},{"id":"esquimau","mot":"esquimau","nature":"nom masculin","definitions":["Glace enrobée de chocolat fixée à un bâtonnet.","Combinaison chaude d\'une seule pièce pour bébé."],"phonetique":"/ɛs.ki.mo/","etymologie":"Du nom des peuples Esquimaux du Grand Nord, attesté dès le XVIIe siècle ; appellation déposée comme marque par Gervais en 1922 pour la glace.","registre":"courant","niveau":2,"themes":["quotidien","emprunts"],"synonymes":["glace"],"antonymes":[],"exemplesCorrects":["Les enfants réclamaient un esquimau à la sortie de l\'école.","Il a mordu dans son esquimau au chocolat.","On vendait des esquimaux sur la plage."],"exemplesIncorrects":["Il a esquimau la porte du congélateur.","Nous avons esquimaué le dessert de la fête."],"distracteurs":["calisson","berlingot","esquif"],"anecdote":"Au pluriel, le mot suit la règle des noms en -au et prend un x : des esquimaux, et non « des esquimaus ». À noter qu\'« Esquimau » désignant un peuple est aujourd\'hui jugé péjoratif, ces populations se nommant Inuits.","categorie":"piege-orthographe","piege":{"formeFautive":"esquimaus","explication":"Comme les noms en -au, le pluriel prend un x : des esquimaux. La forme « esquimaus » est fautive."}},{"id":"intrinseque","mot":"intrinsèque","nature":"adjectif","definitions":["Qui appartient en propre à une chose, qui lui est essentiel et indépendant des circonstances extérieures."],"phonetique":"/ɛ̃.tʁɛ̃.sɛk/","etymologie":"Du latin intrinsecus, « au-dedans », formé de intra (à l\'intérieur) et secus (le long de).","registre":"soutenu","niveau":2,"themes":["abstrait"],"synonymes":["inhérent","essentiel","constitutif"],"antonymes":["extrinsèque","accessoire","superficiel"],"exemplesCorrects":["La valeur intrinsèque d\'une œuvre ne dépend pas de sa cote.","Ce défaut est intrinsèque au système, non au hasard.","La beauté intrinsèque du langage l\'a toujours fasciné."],"exemplesIncorrects":["Il a intrinsèque la porte avant de partir.","Nous avons mangé un plat très intrinsèque ce midi."],"distracteurs":["intrépide","insidieux","intangible"],"anecdote":"On écrit souvent à tort « intrasèque » : le mot prend bien un « in » suivi de « trinsèque », du latin intrinsecus.","categorie":"piege-orthographe","piege":{"formeFautive":"intrasèque","explication":"La graphie correcte est « intrinsèque » avec un « in » initial et le groupe « trinsèque » ; « intrasèque » n\'existe pas."}},{"id":"reminiscence","mot":"réminiscence","nature":"nom féminin","definitions":["Souvenir vague, imprécis, dont on ne reconnaît pas nettement l\'origine.","Retour à la mémoire d\'une image, d\'un mot ou d\'une sensation oubliés."],"phonetique":"/ʁe.mi.ni.sɑ̃s/","etymologie":"Du bas latin reminiscentia, de reminisci, « se ressouvenir », de re- et du radical de memini (se souvenir).","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["souvenir","évocation","ressouvenance"],"antonymes":["oubli","amnésie"],"exemplesCorrects":["Cette mélodie réveilla en lui de lointaines réminiscences.","Le roman fourmille de réminiscences classiques.","Une vague réminiscence d\'enfance lui revint en humant le pain chaud."],"exemplesIncorrects":["Il a réminiscence la leçon avant l\'examen.","Nous réminiscençons toujours nos rendez-vous dans cet agenda."],"distracteurs":["résurgence","prescience","convalescence"],"anecdote":"Chez Platon, la réminiscence (anamnèse) désigne la doctrine selon laquelle apprendre n\'est que se ressouvenir des vérités contemplées par l\'âme avant la naissance.","categorie":"mot-rare"},{"id":"stupefait","mot":"stupéfait","nature":"adjectif","definitions":["Frappé d\'un étonnement profond au point d\'en rester interdit."],"phonetique":"/sty.pe.fɛ/","etymologie":"Du latin stupefactus, participe passé de stupefacere, « engourdir, frapper de stupeur », de stupere (être engourdi) et facere (faire).","registre":"courant","niveau":2,"themes":["emotions"],"synonymes":["abasourdi","interdit","ébahi"],"antonymes":["indifférent","impassible","blasé"],"exemplesCorrects":["Elle resta stupéfaite devant l\'ampleur du désastre.","Stupéfait, il relut la lettre trois fois.","Nous étions stupéfaits par la rapidité de sa réponse."],"exemplesIncorrects":["Cette nouvelle m\'a stupéfait pendant des heures sans m\'arrêter.","Il a stupéfait la table de la cuisine avant le dîner."],"distracteurs":["satisfait","stupéfiant","contrefait"],"anecdote":"On confond souvent l\'adjectif « stupéfait » (frappé d\'étonnement) et le participe « stupéfié » : on est stupéfait, mais une nouvelle nous a stupéfiés.","categorie":"piege-sens","piege":{"formeFautive":"stupéfié employé pour stupéfait","explication":"« Stupéfait » est un adjectif décrivant un état (« je suis stupéfait ») ; « stupéfié » est le participe du verbe stupéfier et exprime une action subie. On ne dit pas « je suis stupéfié » au sens d\'« étonné », mais « je suis stupéfait »."}},{"id":"alternative","mot":"alternative","nature":"nom féminin","definitions":["Situation où l\'on doit choisir entre deux possibilités s\'excluant mutuellement.","Par extension admise, chacune des deux possibilités offertes par ce choix ; solution de remplacement."],"phonetique":"/al.tɛʁ.na.tiv/","etymologie":"Du latin médiéval alternativus, de alternare, « faire tour à tour », de alternus, « l\'un après l\'autre », dérivé de alter (l\'autre).","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["dilemme","choix","option"],"antonymes":["certitude","évidence","obligation"],"exemplesCorrects":["L\'alternative est claire : partir maintenant ou renoncer au train.","Devant cette alternative, il hésita longtemps.","Nous nous trouvions face à une cruelle alternative."],"exemplesIncorrects":["Il existe trois alternatives possibles à ce projet.","Plusieurs alternatives s\'offraient à nous parmi une dizaine d\'options."],"distracteurs":["palliatif","conjoncture","prérogative"],"anecdote":"Au sens strict, une alternative n\'oppose que deux termes : parler de « plusieurs alternatives » ou de « trois alternatives » est, pour les puristes, un contresens, car l\'alternative est le choix lui-même, non l\'une de ses branches.","categorie":"piege-sens","piege":{"formeFautive":"plusieurs alternatives","explication":"Une « alternative » désigne le choix entre deux possibilités, pas l\'une des options. L\'expression « trois alternatives » est critiquée : il faut dire « trois possibilités » ou « trois solutions »."}},{"id":"occasion","mot":"occasion","nature":"nom féminin","definitions":["Circonstance favorable, moment propice pour faire quelque chose.","Affaire avantageuse ; objet acheté de seconde main."],"phonetique":"/ɔ.ka.zjɔ̃/","etymologie":"Du latin occasio, « occasion, moment favorable », de occidere, « tomber, survenir », de ob- et cadere (tomber).","registre":"courant","niveau":1,"themes":["quotidien"],"synonymes":["opportunité","aubaine","circonstance"],"antonymes":["contretemps","empêchement"],"exemplesCorrects":["Il a saisi l\'occasion de voyager à l\'étranger.","C\'est une occasion à ne pas manquer.","À l\'occasion, passez nous voir."],"exemplesIncorrects":["Cette ocasion ne se représentera pas de sitôt.","J\'ai trouvé une bonne occassion au marché."],"distracteurs":["invitation","vocation","incursion"],"anecdote":"L\'orthographe piège : « occasion » prend deux « c » mais un seul « s ». On écrit fautivement « ocasion » ou « occassion » par analogie trompeuse.","categorie":"piege-orthographe","piege":{"formeFautive":"occassion","explication":"« Occasion » s\'écrit avec deux « c » et un seul « s » ; les graphies « ocasion » (un seul c) et « occassion » (deux s) sont fautives."}},{"id":"ammoniac","mot":"ammoniac","nature":"nom masculin","definitions":["Gaz incolore à l\'odeur piquante et suffocante, composé d\'azote et d\'hydrogène (NH₃)."],"phonetique":"/a.mɔ.njak/","etymologie":"Du latin sal ammoniacus, « sel d\'Ammon », du nom du temple de Jupiter Ammon, en Égypte, près duquel on récoltait ce sel.","registre":"courant","niveau":3,"themes":["nature"],"synonymes":["gaz ammoniac","azane"],"antonymes":[],"exemplesCorrects":["L\'ammoniac dégage une odeur âcre qui pique les yeux.","On synthétise l\'ammoniac à partir d\'azote et d\'hydrogène.","Le procédé Haber-Bosch produit de l\'ammoniac à l\'échelle industrielle."],"exemplesIncorrects":["J\'ai versé un peu d\'ammoniac dans mon café.","L\'ammoniac pousse au printemps dans les sous-bois."],"distracteurs":["aluminium","arsenic","camphre"],"anecdote":"Attention au piège : le gaz s\'écrit « ammoniac » (deux m, finale en -ac), tandis que l\'« ammoniaque » avec un -que final désigne sa solution aqueuse, le produit ménager liquide.","categorie":"piege-orthographe","piege":{"formeFautive":"amoniac","explication":"« Ammoniac » prend deux « m ». De plus, « ammoniac » (terminé par -ac) désigne le gaz, à ne pas confondre avec « ammoniaque » (terminé par -que), la solution liquide."}},{"id":"deconvenue","mot":"déconvenue","nature":"nom féminin","definitions":["Déception causée par un espoir trompé, un échec inattendu ; mécompte."],"phonetique":"/de.kɔ̃v.ny/","etymologie":"Dérivé de l\'ancien français desconvenue, de desconvenir, « ne pas convenir, mal tourner », formé de dé- et convenir.","registre":"soutenu","niveau":3,"themes":["emotions","abstrait"],"synonymes":["déception","désappointement","mécompte"],"antonymes":["satisfaction","réussite","contentement"],"exemplesCorrects":["Il essuya une cuisante déconvenue à l\'examen oral.","La soirée s\'acheva sur une amère déconvenue.","Après tant de déconvenues, elle gardait pourtant espoir."],"exemplesIncorrects":["Nous avons signé une déconvenue avec le partenaire étranger.","La déconvenue de la rivière débordait après l\'orage."],"distracteurs":["mésaventure","convoitise","inconvénient"],"anecdote":"La « déconvenue » avait jadis un sens plus fort qu\'aujourd\'hui : en ancien français, elle désignait carrément une défaite ou un malheur, avant de s\'adoucir en simple déception.","categorie":"mot-rare"},{"id":"peremptoire","mot":"péremptoire","nature":"adjectif","definitions":["Qui n\'admet ni réplique ni objection ; décisif et tranchant.","En droit, qui met fin de manière définitive à une procédure ou à une action."],"phonetique":"/pe.ʁɑ̃p.twaʁ/","etymologie":"Du latin juridique peremptorius, « qui anéantit », de peremptus, participe passé de perimere, « détruire, anéantir », de per- et emere (prendre).","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["catégorique","tranchant","décisif"],"antonymes":["hésitant","nuancé","dubitatif"],"exemplesCorrects":["Il répondit d\'un ton péremptoire qui coupa court au débat.","Son argument péremptoire ne souffrait aucune objection.","Elle balaya nos doutes d\'un geste péremptoire."],"exemplesIncorrects":["Le ciel péremptoire annonçait la pluie pour le lendemain.","Nous avons péremptoire la salle avant la réunion."],"distracteurs":["pérenne","prétentieux","préemptif"],"anecdote":"Le mot vient du vocabulaire judiciaire romain : une « exception péremptoire » était celle qui « tuait » définitivement l\'action en justice, d\'où l\'idée de réponse sans appel.","categorie":"mot-rare"},{"id":"resilience","mot":"résilience","nature":"nom féminin","definitions":["Capacité à surmonter un choc, à se reconstruire après une épreuve ou un traumatisme.","En physique, aptitude d\'un matériau à résister aux chocs et à reprendre sa forme."],"phonetique":"/ʁe.zi.ljɑ̃s/","etymologie":"Emprunté à l\'anglais resilience, lui-même du latin resilire, « rebondir, sauter en arrière », de re- et salire (sauter).","registre":"courant","niveau":2,"themes":["abstrait","emotions"],"synonymes":["endurance","résistance","ressort"],"antonymes":["fragilité","vulnérabilité","effondrement"],"exemplesCorrects":["La résilience de cette communauté après la catastrophe forçait l\'admiration.","On mesure la résilience d\'un acier par sa capacité à absorber les chocs.","Sa résilience lui a permis de rebondir après cet échec."],"exemplesIncorrects":["Il a fait preuve d\'une grande résiliance face à l\'adversité.","La résillience de l\'enfant a surpris les médecins."],"distracteurs":["résonance","réticence","résignation"],"anecdote":"Le mot s\'écrit « résilience » avec un seul « l » ; la graphie « résiliance » ou « résillience » est fautive. Le psychiatre Boris Cyrulnik a popularisé son usage psychologique en France.","categorie":"piege-orthographe","piege":{"formeFautive":"résiliance","explication":"On écrit « résilience » avec un seul « l » et la terminaison « -ience » (comme patience), non « -iance ». Les formes « résiliance » et « résillience » sont fautives."}},{"id":"circonscrire","mot":"circonscrire","nature":"verbe","definitions":["Tracer ou marquer les limites d\'un espace, d\'un domaine.","Limiter, contenir l\'extension de quelque chose."],"phonetique":"/siʁ.kɔ̃s.kʁiʁ/","etymologie":"Du latin circumscribere, « tracer un cercle autour », de circum (autour) et scribere (écrire, tracer).","registre":"soutenu","niveau":3,"themes":["abstrait"],"synonymes":["délimiter","cerner","circonvenir"],"antonymes":["étendre","propager","élargir"],"exemplesCorrects":["Les pompiers sont parvenus à circonscrire l\'incendie.","Il faut circonscrire le sujet pour ne pas s\'égarer.","Une haie circonscrit le jardin sur trois côtés."],"exemplesIncorrects":["Nous avons circonscrit une lettre à notre ami d\'enfance.","Le chanteur circonscrit une mélodie entraînante."],"distracteurs":["proscrire","souscrire","retranscrire"],"anecdote":"Piège fréquent : on écrit « circonscrire » avec un « s » après « circon- » (du latin scribere), et non « circonscrir » ou « circoncrire ». Au passé simple, on dit « il circonscrivit ».","categorie":"piege-orthographe","piege":{"formeFautive":"circoncrire","explication":"« Circonscrire » contient bien le groupe « -scrire » (du latin scribere) : il s\'écrit avec un « s ». La forme « circoncrire » est fautive, par confusion avec « circoncire »."}},{"id":"exutoire","mot":"exutoire","nature":"nom masculin","definitions":["Moyen de se libérer d\'une tension, d\'un trop-plein d\'énergie ou d\'émotion.","Ouverture par où s\'écoule un liquide ; en médecine, plaie entretenue pour évacuer des humeurs."],"phonetique":"/ɛɡ.zy.twaʁ/","etymologie":"Du latin exutus, participe passé de exuere, « dépouiller, se débarrasser de », avec le suffixe -oire.","registre":"soutenu","niveau":3,"themes":["abstrait","emotions"],"synonymes":["dérivatif","échappatoire","défoulement"],"antonymes":["refoulement","blocage","inhibition"],"exemplesCorrects":["Le sport lui sert d\'exutoire après une journée éprouvante.","L\'écriture fut son seul exutoire pendant cette période sombre.","Faute d\'exutoire, sa colère ne cessait de monter."],"exemplesIncorrects":["Il a signé un exutoire avec son nouvel employeur.","L\'exutoire poussait au bord du chemin parmi les ronces."],"distracteurs":["exorde","auditoire","réquisitoire"],"anecdote":"Avant son sens psychologique, « exutoire » désignait en médecine une petite plaie volontairement maintenue ouverte pour « évacuer les humeurs » du corps, selon la théorie humorale ancienne.","categorie":"mot-rare"},{"id":"succinct","mot":"succinct","nature":"adjectif","definitions":["Exprimé en peu de mots ; bref et concis."],"phonetique":"/syk.sɛ̃/","etymologie":"Du latin succinctus, « retroussé, court vêtu », participe passé de succingere, « ceindre par-dessous », de sub- et cingere (ceindre).","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["bref","concis","laconique"],"antonymes":["prolixe","verbeux","détaillé"],"exemplesCorrects":["Il fit un compte rendu succinct de la réunion.","Sois succinct : nous manquons de temps.","Un résumé succinct figure en tête du rapport."],"exemplesIncorrects":["Le discours était si succinct qu\'il dura trois heures.","Elle a rédigé un succinct très détaillé de cinquante pages."],"distracteurs":["distinct","subtil","instinct"],"anecdote":"Mot redouté en dictée : « succinct » comporte deux « c », un « t » final muet, et son adverbe « succinctement » fait sonner ce « ct » que l\'adjectif tait.","categorie":"piege-orthographe","piege":{"formeFautive":"succint","explication":"« Succinct » prend deux « c » et un « t » final muet (du latin succinctus). On oublie souvent ce « c » devant le « t » ou le « t » final, d\'où les graphies fautives « succint » ou « succin »."}},{"id":"vehement","mot":"véhément","nature":"adjectif","definitions":["Qui est emporté, impétueux, plein d\'une passion ardente.","Qui agit avec force et intensité ; violent, intense."],"phonetique":"/ve.e.mɑ̃/","etymologie":"Du latin vehemens, « emporté, passionné, violent », apparenté à vehere, « porter, transporter ».","registre":"soutenu","niveau":2,"themes":["emotions","abstrait","litteraire"],"synonymes":["impétueux","fougueux","ardent","emporté"],"antonymes":["posé","modéré","placide","tiède"],"exemplesCorrects":["Il opposa un refus véhément à toute compromission.","Le tribun prononça un discours véhément contre l\'injustice.","Une protestation véhémente s\'éleva dans l\'assemblée."],"exemplesIncorrects":["Le lac véhément reflétait paisiblement le ciel d\'été.","Elle rangea ses affaires d\'un geste véhément et silencieux, sans émotion aucune."],"distracteurs":["véniel","véreux","véloce"],"anecdote":"On écrit souvent à tort « véhement » : la forme correcte porte bien un accent aigu sur les deux premiers e, « véhément », hérité du latin vehemens.","categorie":"piege-orthographe","piege":{"formeFautive":"véhement","explication":"L\'erreur consiste à oublier l\'accent aigu sur le deuxième e. La graphie correcte est « véhément », avec deux accents aigus successifs."}},{"id":"fingerspitzengefuhl","mot":"Fingerspitzengefühl","nature":"nom masculin","definitions":["Tact instinctif, doigté ; sens aigu de la nuance et de la situation qui permet de réagir avec finesse sans réfléchir."],"phonetique":"/fiŋ.ɡɛʁ.ʃpit.sən.ɡe.ˈfyl/","etymologie":"De l\'allemand Fingerspitzengefühl, littéralement « sensation du bout des doigts », de Fingerspitze (bout du doigt) et Gefühl (sensation).","registre":"soutenu","niveau":5,"themes":["emprunts","abstrait"],"synonymes":["doigté","tact","flair"],"antonymes":["maladresse","lourdeur","balourdise"],"exemplesCorrects":["Ce médiateur possède un Fingerspitzengefühl rare pour désamorcer les tensions.","Mener une négociation aussi délicate exige un certain Fingerspitzengefühl.","Son Fingerspitzengefühl lui fit sentir qu\'il valait mieux se taire."],"exemplesIncorrects":["Il a rangé son Fingerspitzengefühl dans le tiroir de la cuisine.","Nous avons repeint le Fingerspitzengefühl du salon en bleu."],"distracteurs":["entregent","perspicacité","circonspection"],"anecdote":"Le terme, issu du jargon militaire allemand, désignait à l\'origine l\'instinct d\'un artilleur capable d\'ajuster son tir « au bout des doigts ».","categorie":"mot-rare"},{"id":"zugzwang","mot":"zugzwang","nature":"nom masculin","definitions":["Aux échecs, situation où le joueur ayant le trait est contraint de jouer un coup qui dégrade sa position, alors qu\'il préférerait pouvoir passer son tour.","Par extension, situation où toute action que l\'on entreprend aggrave sa position."],"phonetique":"/tsuɡ.tsvaŋ/","etymologie":"De l\'allemand Zugzwang, de Zug (coup, mouvement) et Zwang (contrainte) : « contrainte de jouer un coup ».","registre":"soutenu","niveau":4,"themes":["emprunts","abstrait"],"synonymes":["impasse","contrainte"],"antonymes":["liberté","latitude","initiative"],"exemplesCorrects":["En finale de pions, le roi noir se retrouva en zugzwang.","Politiquement, le gouvernement est en plein zugzwang : chaque décision lui coûte des voix.","Le maître exploita le zugzwang pour gagner sans même attaquer."],"exemplesIncorrects":["Il a zugzwang la porte avant de partir.","Nous avons mangé un zugzwang délicieux au dessert."],"distracteurs":["gambit","fourchette","roque"],"anecdote":"Le mot apparaît dans la presse échiquéenne allemande dès 1858, mais le champion du monde Emanuel Lasker contribua à le populariser au XXe siècle.","categorie":"mot-rare"},{"id":"feierabend","mot":"Feierabend","nature":"nom masculin","definitions":["En allemand, moment où le travail s\'achève et où commence le temps libre du soir ; la fin de journée vécue comme une parenthèse méritée."],"phonetique":"/ˈfaɪ.ɐ.ˌʔaː.bənt/","etymologie":"De l\'allemand Feierabend, de feiern (célébrer, faire la fête, chômer) et Abend (soir) : à l\'origine, la veille de fête où l\'on cessait le travail.","registre":"courant","niveau":5,"themes":["emprunts","quotidien"],"synonymes":["débauche","repos"],"antonymes":["labeur","service","besogne"],"exemplesCorrects":["À dix-huit heures pile, il lance un « Feierabend ! » et quitte le bureau.","Les Allemands tiennent à leur Feierabend comme à un droit sacré.","Rien de tel qu\'une bière au jardin pour célébrer le Feierabend."],"exemplesIncorrects":["Elle a acheté un Feierabend neuf pour remplacer l\'ancien.","Le Feierabend pesait trois kilos dans le panier."],"distracteurs":["crépuscule","trêve","loisir"],"anecdote":"Le mot remonte au Moyen Âge où l\'« Abend » de veille de fête marquait l\'arrêt anticipé du travail dans les ateliers.","categorie":"mot-rare"},{"id":"kabelsalat","mot":"Kabelsalat","nature":"nom masculin","definitions":["En allemand, enchevêtrement inextricable de câbles ; littéralement « salade de câbles »."],"phonetique":"/ˈkaː.bəl.za.laːt/","etymologie":"De l\'allemand Kabelsalat, de Kabel (câble) et Salat (salade), par image du fouillis emmêlé.","registre":"familier","niveau":5,"themes":["emprunts","quotidien"],"synonymes":["enchevêtrement","fouillis","embrouillamini"],"antonymes":["rangement","ordre","agencement"],"exemplesCorrects":["Derrière le bureau s\'étalait un Kabelsalat impossible à démêler.","Avec le sans-fil, on en finit enfin avec le Kabelsalat.","Il a passé l\'après-midi à dompter le Kabelsalat du meuble télé."],"exemplesIncorrects":["Au déjeuner, j\'ai commandé un Kabelsalat bien assaisonné.","Le chef a servi le Kabelsalat avec une vinaigrette au citron."],"distracteurs":["écheveau","imbroglio","dédale"],"anecdote":"L\'allemand multiplie ce genre de composés imagés : la « salade de câbles » côtoie le « Tohuwabohu » pour dire le désordre.","categorie":"mot-rare"},{"id":"ikigai","mot":"ikigai","nature":"nom masculin","definitions":["Concept japonais désignant la raison d\'être, ce qui donne du sens à l\'existence et incite à se lever chaque matin."],"phonetique":"/i.ki.ɡaj/","etymologie":"Du japonais 生き甲斐 (ikigai), de iki (la vie, vivre) et gai (valeur, mérite) : « ce qui rend la vie digne d\'être vécue ».","registre":"courant","niveau":3,"themes":["emprunts","abstrait"],"synonymes":["vocation","raison d\'être"],"antonymes":["vacuité","désœuvrement","ennui"],"exemplesCorrects":["Pour elle, transmettre est devenu un véritable ikigai.","Le livre invite chacun à chercher son ikigai au croisement de ses talents et de ses passions.","Depuis qu\'il jardine, il dit avoir retrouvé son ikigai."],"exemplesIncorrects":["Il a garé son ikigai devant la maison.","Nous avons repeint l\'ikigai du couloir."],"distracteurs":["sérénité","épanouissement","aspiration"],"anecdote":"Vulgarisé en Occident par des essais de développement personnel, l\'ikigai y est souvent réduit à un diagramme à quatre cercles, simplification que le concept japonais d\'origine ne comporte pas.","categorie":"mot-rare"},{"id":"wabi-sabi","mot":"wabi-sabi","nature":"nom masculin","definitions":["Esthétique japonaise qui célèbre la beauté de l\'imparfait, de l\'éphémère et de l\'humble, et la patine que le temps dépose sur les choses."],"phonetique":"/wa.bi.sa.bi/","etymologie":"Du japonais 侘寂, de wabi (simplicité dépouillée, sobriété mélancolique) et sabi (la patine, la beauté née du passage du temps).","registre":"soutenu","niveau":4,"themes":["emprunts","abstrait","litteraire"],"synonymes":["sobriété","dépouillement"],"antonymes":["faste","clinquant","ostentation"],"exemplesCorrects":["Cette poterie fêlée incarne à merveille l\'esprit wabi-sabi.","Le wabi-sabi nous apprend à goûter la beauté des choses usées.","Sa maison, sobre et patinée, respire le wabi-sabi."],"exemplesIncorrects":["Il a wabi-sabi la table de la cuisine ce matin.","Nous avons couru un wabi-sabi de dix kilomètres."],"distracteurs":["minimalisme","épure","frugalité"],"anecdote":"La notion plonge ses racines dans la cérémonie du thé, où l\'on préfère un bol fruste et asymétrique à une porcelaine parfaite.","categorie":"mot-rare"},{"id":"tsundoku","mot":"tsundoku","nature":"nom masculin","definitions":["Habitude d\'acquérir des livres et de les entasser sans jamais les lire."],"phonetique":"/tsun.dɔ.ku/","etymologie":"Du japonais 積ん読 (tsundoku), mot-valise de tsunde-oku (empiler et laisser) et de dokusho (lecture), né comme argot à l\'ère Meiji.","registre":"courant","niveau":4,"themes":["emprunts","litteraire","quotidien"],"synonymes":["accumulation","thésaurisation"],"antonymes":["lecture","dévoration"],"exemplesCorrects":["Ma table de chevet est un monument au tsundoku.","Le tsundoku n\'est pas un défaut, plaide-t-il, mais une promesse de lectures futures.","Entre deux soldes en librairie, elle cède volontiers au tsundoku."],"exemplesIncorrects":["Il a tsundoku la lettre avant de la poster.","Nous avons mangé un tsundoku au restaurant japonais."],"distracteurs":["bibliophilie","compilation","florilège"],"anecdote":"La première mention imprimée, en 1879, raillait déjà un « tsundoku sensei », professeur entouré de livres qu\'il ne lit pas.","categorie":"mot-rare"},{"id":"shinrin-yoku","mot":"shinrin-yoku","nature":"nom masculin","definitions":["Pratique japonaise du « bain de forêt » : immersion sensorielle et apaisante dans les bois, à des fins de bien-être.","Par extension, la sylvothérapie qui en découle."],"phonetique":"/ʃin.ʁin.jo.ku/","etymologie":"Du japonais 森林浴, de shinrin (forêt) et yoku (bain) ; expression forgée en 1982 par le ministère japonais de l\'Agriculture et des Forêts.","registre":"courant","niveau":4,"themes":["emprunts","nature"],"synonymes":["sylvothérapie"],"antonymes":["claustration","enfermement"],"exemplesCorrects":["Chaque dimanche, elle s\'offre une heure de shinrin-yoku en forêt de Fontainebleau.","Le shinrin-yoku ferait baisser la tension artérielle, selon plusieurs études.","Loin du bruit, il pratiquait le shinrin-yoku pour décompresser."],"exemplesIncorrects":["J\'ai bu un shinrin-yoku bien chaud ce matin.","Le mécanicien a remplacé le shinrin-yoku de la voiture."],"distracteurs":["thalassothérapie","balnéothérapie","héliothérapie"],"anecdote":"Né d\'une politique de santé publique japonaise des années 1980, le shinrin-yoku a essaimé en Occident sous le nom de « bain de forêt ».","categorie":"mot-rare"},{"id":"kintsugi","mot":"kintsugi","nature":"nom masculin","definitions":["Art japonais de réparer une céramique brisée en soulignant ses fêlures à la laque saupoudrée d\'or, faisant de la cassure un ornement."],"phonetique":"/kin.tsu.ɡi/","etymologie":"Du japonais 金継ぎ (kintsugi), de kin (or) et tsugi (jointure, raccord) : « jointure d\'or ».","registre":"soutenu","niveau":4,"themes":["emprunts","abstrait","litteraire"],"synonymes":["raccommodage","restauration"],"antonymes":["dissimulation","rebut"],"exemplesCorrects":["Le bol, réparé au kintsugi, vaut désormais plus que neuf à ses yeux.","Le kintsugi est souvent érigé en métaphore de la résilience.","Elle s\'est initiée au kintsugi pour sauver un vase de famille."],"exemplesIncorrects":["Il a kintsugi jusqu\'au sommet de la colline.","Nous avons commandé un kintsugi avec des nouilles."],"distracteurs":["marqueterie","dorure","émaillage"],"anecdote":"La tradition veut que le kintsugi soit né au XVe siècle, après qu\'un bol réparé de vulgaires agrafes métalliques eut déplu au shogun Ashikaga Yoshimasa.","categorie":"mot-rare"},{"id":"yugen","mot":"yūgen","nature":"nom masculin","definitions":["Notion esthétique japonaise désignant le sentiment profond et mystérieux suscité par la beauté du monde, trop subtil pour être dit."],"phonetique":"/ju.ɡɛn/","etymologie":"Du japonais 幽玄 (yūgen), de yū (obscur, profond) et gen (mystérieux, secret) ; terme d\'abord emprunté au vocabulaire bouddhique sino-japonais.","registre":"littéraire","niveau":5,"themes":["emprunts","abstrait","litteraire"],"synonymes":["mystère","profondeur"],"antonymes":["trivialité","platitude","banalité"],"exemplesCorrects":["La brume sur la montagne lui inspira un sentiment de yūgen indicible.","Le théâtre nô cherche à faire affleurer le yūgen sous le geste épuré.","Devant l\'océan nocturne, elle éprouva ce que les Japonais nomment yūgen."],"exemplesIncorrects":["Il a rempli son yūgen d\'essence à la station.","Le boulanger a vendu son dernier yūgen à midi."],"distracteurs":["sublime","ineffable","transcendance"],"anecdote":"Le poète et dramaturge Zeami fit du yūgen, au tournant des XIVe et XVe siècles, l\'idéal suprême du théâtre nô.","categorie":"mot-rare"},{"id":"litost","mot":"litost","nature":"nom","definitions":["État de tourment né de la vue soudaine de sa propre misère ; sentiment mêlant détresse, remords et désir confus de réparation, popularisé par Milan Kundera comme intraduisible."],"phonetique":"/li.tɔst/","etymologie":"Mot tchèque lítost, « regret, compassion, chagrin », rendu célèbre par Milan Kundera dans Le Livre du rire et de l\'oubli.","registre":"littéraire","niveau":5,"themes":["emprunts","emotions"],"synonymes":["tourment","affliction","mortification"],"antonymes":["contentement","sérénité","allégresse"],"exemplesCorrects":["Kundera décrit la litost comme un sursaut de l\'âme blessée par sa propre faiblesse.","Une vague de litost le saisit quand il mesura tout ce qu\'il avait gâché.","Elle évoquait cette litost tchèque que nul mot français ne traduit vraiment."],"exemplesIncorrects":["Il rangea ses litosts dans le tiroir du bas.","Nous avons litosté toute la soirée au coin du feu."],"distracteurs":["mansuétude","componction","abnégation"],"anecdote":"Kundera affirmait qu\'il lui était impossible d\'imaginer comment on pouvait comprendre l\'âme humaine sans ce mot ; sa première syllabe, longue et accentuée, évoquerait selon lui la plainte d\'un chien abandonné.","categorie":"mot-rare"},{"id":"fuubutsushi","mot":"fuubutsushi","nature":"nom","definitions":["Chose, sensation ou phénomène typique d\'une saison, qui en évoque aussitôt l\'atmosphère (chant des cigales, carillon à vent, premières neiges) ; au sens premier, poème célébrant les paysages saisonniers."],"phonetique":"/fu.but.su.ʃi/","etymologie":"Mot japonais 風物詩 (fūbutsushi), littéralement « poème (詩) des choses (物) du vent/du paysage (風) ».","registre":"littéraire","niveau":5,"themes":["emprunts","nature"],"synonymes":["emblème saisonnier","marqueur saisonnier"],"antonymes":[],"exemplesCorrects":["Au Japon, le tintement du carillon à vent est un fuubutsushi de l\'été.","Les feux d\'artifice comptent parmi les fuubutsushi les plus aimés de la saison chaude.","Chaque fuubutsushi rappelle, par un détail sensible, la saison qu\'il annonce."],"exemplesIncorrects":["Il a fuubutsushi son jardin pour l\'hiver.","Nous fuubutsushissons chaque dimanche après le repas."],"distracteurs":["haïku","estampe","almanach"],"anecdote":"Le mot désignait à l\'origine des poèmes sur les paysages des saisons, avant de s\'appliquer à toute chose emblématique d\'une période de l\'année, du chant des cigales à la glace pilée sur les nouilles soba.","categorie":"mot-rare"},{"id":"poshlost","mot":"poshlost","nature":"nom","definitions":["Vulgarité prétentieuse qui se croit raffinée ; faux bon goût, imitation creuse de l\'élégance ou de la profondeur, marquée par le clinquant et la mièvrerie satisfaite de soi."],"phonetique":"/pɔʃ.lɔst/","etymologie":"Mot russe по́шлость (póšlost\'), « banalité triviale, mauvais goût », popularisé en Occident par Vladimir Nabokov (qu\'il romanisait « poshlust »).","registre":"littéraire","niveau":5,"themes":["emprunts","abstrait"],"synonymes":["clinquant","afféterie","mièvrerie"],"antonymes":["authenticité","sobriété","raffinement"],"exemplesCorrects":["Nabokov voyait de la poshlost dans tout ce qui est faussement beau ou faussement profond.","Cette publicité dégouline d\'une poshlost qui se prend pour de l\'art.","Le salon, surchargé de dorures, respirait la poshlost."],"exemplesIncorrects":["Il a poshlosté la table avec une nappe brodée.","Nous avons mangé une poshlost délicieuse au dessert."],"distracteurs":["pruderie","outrecuidance","grandiloquence"],"anecdote":"Nabokov distinguait la poshlost de la simple vulgarité : la vulgarité est une mauvaise grâce sincère, tandis que la poshlost est un mauvais goût qui se déguise en goût élevé.","categorie":"mot-rare"},{"id":"yakamoz","mot":"yakamoz","nature":"nom","definitions":["Reflet scintillant de la lune sur la surface de l\'eau, la nuit.","Au sens premier, lueur phosphorescente de la mer due à des micro-organismes."],"phonetique":"/ja.ka.mɔz/","etymologie":"Mot turc yakamoz, emprunté au grec διακαμός (diakamós) ; il désigne d\'abord la phosphorescence marine, puis le reflet de la lune sur l\'eau.","registre":"littéraire","niveau":5,"themes":["emprunts","nature"],"synonymes":["miroitement","scintillement","reflet"],"antonymes":["obscurité","ténèbres"],"exemplesCorrects":["Du quai, ils contemplaient le yakamoz qui frémissait sur le Bosphore.","Aucun mot français ne rend aussi bien que yakamoz cette traînée de lune sur les flots.","Le yakamoz traçait un sentier d\'argent jusqu\'à l\'horizon."],"exemplesIncorrects":["Il a yakamoz la barque jusqu\'au port.","Nous avons bu un yakamoz à la terrasse du café."],"distracteurs":["embrun","ressac","halo"],"anecdote":"Élu un jour « plus beau mot du monde » lors d\'un concours, yakamoz désignait à l\'origine la lueur des planctons bioluminescents, sens aujourd\'hui presque oublié au profit du reflet de la lune.","categorie":"mot-rare"},{"id":"gigil","mot":"gigil","nature":"nom","definitions":["Envie irrépressible de serrer, pincer ou presser ce que l\'on trouve trop mignon, au point de crisper les mains et de serrer les dents."],"phonetique":"/ɡi.ɡil/","etymologie":"Mot tagalog gigil, « tremblement contenu d\'émotion intense » ; entré en 2025 dans l\'Oxford English Dictionary.","registre":"courant","niveau":5,"themes":["emprunts","emotions"],"synonymes":["attendrissement","émoi"],"antonymes":["indifférence","répulsion"],"exemplesCorrects":["Devant le chiot, elle fut saisie d\'un gigil et dut serrer les poings.","Ce mélange de tendresse et d\'envie de pincer les joues du bébé, c\'est le gigil.","Le tagalog possède un mot, gigil, pour cette frénésie que provoque trop de mignardise."],"exemplesIncorrects":["Il a gigil la porte d\'un coup d\'épaule.","Nous avons acheté trois gigils au marché."],"distracteurs":["frisson","vertige","engouement"],"anecdote":"En 2025, l\'Oxford English Dictionary a intégré gigil parmi des dizaines de mots jugés intraduisibles, faute d\'équivalent simple en anglais pour cette « attaque de mignonnerie ».","categorie":"mot-rare"},{"id":"kilig","mot":"kilig","nature":"nom","definitions":["Frisson papillonnant de joie ou d\'émoi amoureux ; sensation euphorique provoquée par un moment romantique, réel ou imaginé."],"phonetique":"/ki.liɡ/","etymologie":"Mot tagalog kilig, « frisson, tremblement de plaisir » ; entré en 2016 dans l\'Oxford English Dictionary.","registre":"courant","niveau":5,"themes":["emprunts","emotions"],"synonymes":["émoi","frisson","papillonnement"],"antonymes":["froideur","ennui","indifférence"],"exemplesCorrects":["Leur premier regard lui causa un kilig qu\'elle ne put cacher.","Les comédies romantiques sont faites pour provoquer le kilig.","Un simple message tendre suffit à déclencher ce kilig délicieux."],"exemplesIncorrects":["Il a kilig la lettre avant de l\'envoyer.","Nous avons commandé deux kiligs au restaurant."],"distracteurs":["langueur","transport","exaltation"],"anecdote":"Le kilig est si central dans la culture populaire philippine que l\'Oxford English Dictionary l\'a admis en 2016, le décrivant comme le frisson d\'excitation provoqué par une expérience romantique.","categorie":"mot-rare"},{"id":"pana-poo","mot":"pana po\'o","nature":"locution","definitions":["Action de se gratter ou se tapoter la tête pour tenter de se rappeler quelque chose que l\'on a oublié."],"phonetique":"/pa.na.po.ʔo/","etymologie":"Locution hawaïenne, de pana (« frapper, tapoter ») et po\'o (« tête »).","registre":"littéraire","niveau":5,"themes":["emprunts","quotidien"],"synonymes":[],"antonymes":[],"exemplesCorrects":["Il faisait un pana po\'o en cherchant le nom de cet acteur.","Le hawaïen a une expression, pana po\'o, pour ce geste machinal qu\'on fait en essayant de se souvenir.","Un léger pana po\'o trahissait son effort de mémoire."],"exemplesIncorrects":["Elle a pana po\'o la liste des courses sur le frigo.","Nous avons mangé un pana po\'o très épicé."],"distracteurs":["circonlocution","réminiscence","tergiversation"],"anecdote":"Souvent citée dans les listes de mots « intraduisibles », l\'expression repose sur deux mots hawaïens bien réels : pana, frapper, et po\'o, la tête.","categorie":"expression"},{"id":"iktsuarpok","mot":"iktsuarpok","nature":"nom","definitions":["Impatience mêlée d\'anticipation qui pousse à sortir sans cesse pour guetter l\'arrivée de quelqu\'un que l\'on attend."],"phonetique":"/ik.tsu.aʁ.pɔk/","etymologie":"Mot inuit (inuktitut) iktsuarpok, formé sur une racine évoquant le fait de sortir vérifier si quelqu\'un vient.","registre":"littéraire","niveau":5,"themes":["emprunts","emotions"],"synonymes":["impatience","fébrilité"],"antonymes":["patience","indifférence","flegme"],"exemplesCorrects":["Saisi d\'iktsuarpok, il sortait toutes les cinq minutes guetter la route.","Cette fébrilité qui vous fait regarder par la fenêtre en attendant un invité, les Inuits l\'appellent iktsuarpok.","L\'iktsuarpok le tint en haleine jusqu\'à ce que la voiture apparaisse."],"exemplesIncorrects":["Il a iktsuarpok la porte d\'entrée toute la matinée.","Nous avons servi de l\'iktsuarpok aux convives."],"distracteurs":["nostalgie","appréhension","fébricule"],"anecdote":"Iktsuarpok figure dans toutes les anthologies de mots intraduisibles : il nomme précisément ces allers-retours vers la porte que provoque l\'attente d\'un visiteur.","categorie":"mot-rare"},{"id":"ubuntu","mot":"ubuntu","nature":"nom","definitions":["Philosophie africaine de l\'humanité partagée, selon laquelle une personne n\'existe pleinement qu\'à travers les autres : « je suis parce que nous sommes »."],"phonetique":"/u.bun.tu/","etymologie":"Mot des langues bantoues (zoulou, xhosa) ubuntu, « humanité, qualité d\'être humain », de la racine -ntu (personne).","registre":"soutenu","niveau":4,"themes":["emprunts","abstrait"],"synonymes":["solidarité","humanité","fraternité"],"antonymes":["individualisme","égoïsme","isolement"],"exemplesCorrects":["Desmond Tutu fit de l\'ubuntu une clé de la réconciliation sud-africaine.","Selon l\'ubuntu, mon humanité est liée à la tienne, indissociablement.","Cette entraide spontanée du village illustrait l\'ubuntu."],"exemplesIncorrects":["Il a ubuntu son ordinateur portable hier soir.","Nous avons ubuntu la salle de réunion avant la conférence."],"distracteurs":["altruisme","communauté","réciprocité"],"anecdote":"L\'archevêque Desmond Tutu résumait l\'ubuntu ainsi : « une personne est une personne à travers les autres personnes » ; le mot a aussi donné son nom à un célèbre système d\'exploitation.","categorie":"mot-rare"},{"id":"fargin","mot":"fargin","nature":"verbe","definitions":["Se réjouir sincèrement et sans envie de la réussite ou du bonheur d\'autrui ; accorder de bon cœur à quelqu\'un ce qui lui arrive d\'heureux."],"phonetique":"/faʁ.ɡin/","etymologie":"Mot yiddish farginen, emprunté à l\'allemand vergönnen, « accorder, ne pas envier ».","registre":"littéraire","niveau":5,"themes":["emprunts","emotions"],"synonymes":["se réjouir","féliciter"],"antonymes":["envier","jalouser","convoiter"],"exemplesCorrects":["Loin de l\'envier, elle savait fargin le succès de sa rivale.","Fargin, c\'est l\'exact contraire de la Schadenfreude.","Il fargine à ses amis chaque bonne nouvelle, sans la moindre aigreur."],"exemplesIncorrects":["Il a fargin son adversaire d\'un revers de main.","Nous avons fargin la salle de réception toute la nuit."],"distracteurs":["congratuler","magnifier","complimenter"],"anecdote":"Le yiddish fargin nomme un sentiment que l\'anglais et le français peinent à exprimer en un mot : la joie pure et sans jalousie devant le bonheur des autres, à l\'opposé de la Schadenfreude.","categorie":"mot-rare"},{"id":"luftmensch","mot":"luftmensch","nature":"nom","definitions":["Rêveur peu pratique, vivant pour ainsi dire « dans les nuages », sans métier ni moyens d\'existence assurés ; idéaliste tête en l\'air."],"phonetique":"/lyft.mɛnʃ/","etymologie":"Mot yiddish luftmentsh, littéralement « homme (mentsh) d\'air (luft) », sur le modèle de l\'allemand Luft (air) et Mensch (homme).","registre":"littéraire","niveau":5,"themes":["emprunts","abstrait"],"synonymes":["rêveur","utopiste","songe-creux"],"antonymes":["pragmatique","réaliste","terre-à-terre"],"exemplesCorrects":["Ce luftmensch enchaînait les projets grandioses sans jamais en mener un à bien.","On le tenait pour un aimable luftmensch, perdu dans ses chimères.","Le personnage, véritable luftmensch, semblait flotter au-dessus des contingences."],"exemplesIncorrects":["Il a luftmensch la fenêtre pour aérer la pièce.","Nous avons réservé deux luftmensch pour le concert."],"distracteurs":["dilettante","noctambule","misanthrope"],"anecdote":"Le luftmensch peuple la littérature yiddish d\'Europe de l\'Est : c\'est l\'homme qui « vit d\'air », sans assise matérielle, tout entier tourné vers ses idées et ses rêves.","categorie":"mot-rare"},{"id":"peguer","mot":"péguer","nature":"verbe","definitions":["Être collant, poisseux ; coller aux doigts (régionalisme du Sud de la France)."],"phonetique":"/pe.ɡe/","etymologie":"De l\'occitan pegar, « coller, enduire de poix », du latin picare, dérivé de pix, picis (poix, résine).","registre":"familier","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["coller","poisser"],"antonymes":["glisser","sécher"],"exemplesCorrects":["Avec cette chaleur, le sirop renversé fait péguer toute la table.","Mes mains péguent encore après avoir épluché les figues.","Le sol de la cuisine pègue, il faut passer la serpillière."],"exemplesIncorrects":["Il a pégué la voiture jusqu\'au garage en panne.","Nous avons pégué une longue lettre à nos amis."],"distracteurs":["engluer","tartiner","barbouiller"],"anecdote":"Très courant à Marseille et en Provence, « ça pègue » est l\'une de ces expressions méridionales que les non-initiés peinent à traduire d\'un seul mot en français standard.","categorie":"mot-rare"},{"id":"bouleguer","mot":"bouléguer","nature":"verbe","definitions":["Remuer, agiter, bouger (régionalisme du Sud de la France)."],"phonetique":"/bu.le.ɡe/","etymologie":"De l\'occitan bolegar, « remuer, s\'agiter », issu du bas latin bullicare, « bouillonner », dérivé de bullire (bouillir).","registre":"familier","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["remuer","agiter","bouger"],"antonymes":["immobiliser","figer"],"exemplesCorrects":["Arrête de bouléguer sur ta chaise, tu m\'étourdis.","Il faut bien bouléguer la soupe pour qu\'elle n\'attache pas.","Boulègue-toi un peu, on va finir par être en retard !"],"exemplesIncorrects":["Il a bouléguer son adversaire d\'une réplique cinglante.","Nous avons bouléguer la nouvelle dans tout le quartier."],"distracteurs":["secouer","brasser","tournebouler"],"anecdote":"À Marseille, « boulègue ! » s\'emploie comme une exhortation amicale signifiant « bouge-toi, dépêche-toi », équivalent méridional du « grouille » parisien.","categorie":"mot-rare"},{"id":"ensuque","mot":"ensuqué","nature":"adjectif","definitions":["Assommé, abruti, hébété par la chaleur, le sommeil ou la fatigue (régionalisme du Sud de la France)."],"phonetique":"/ɑ̃.sy.ke/","etymologie":"De l\'occitan ensucar, « assommer, frapper sur la tête », dérivé de suc, « sommet du crâne, occiput », mot d\'origine pré-indo-européenne apparenté à l\'italien zucca (courge, tête).","registre":"familier","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["assommé","abruti","hébété"],"antonymes":["alerte","vif","dispos"],"exemplesCorrects":["Après la sieste en plein soleil, il était complètement ensuqué.","Cette canicule me laisse ensuquée toute la journée.","Les enfants, ensuqués par le voyage, dormaient déjà à table."],"exemplesIncorrects":["Il a ensuqué la porte d\'un grand coup d\'épaule.","Le boxeur a ensuqué son adversaire au troisième round."],"distracteurs":["engourdi","amorphe","groggy"],"anecdote":"Le mot vient de la même racine que « suc », ancien nom du sommet du crâne : être ensuqué, c\'est littéralement avoir reçu un coup sur la tête, au figuré la torpeur de l\'été provençal.","categorie":"mot-rare"},{"id":"estourbir","mot":"estourbir","nature":"verbe","definitions":["Assommer, mettre hors de combat ; tuer (argot)."],"phonetique":"/ɛs.tuʁ.biʁ/","etymologie":"De l\'argot stourbe ou chtourbe, « mort », probablement issu de l\'alsacien storb, apparenté à l\'allemand sterben (mourir).","registre":"familier","niveau":3,"themes":["quotidien","abstrait"],"synonymes":["assommer","estropier","neutraliser"],"antonymes":["ranimer","épargner","soigner"],"exemplesCorrects":["Un coup de barre l\'a estourbi avant qu\'il ait pu crier.","Le malfrat menaçait d\'estourbir quiconque approcherait du coffre.","La chaleur l\'avait à moitié estourbi sur le banc."],"exemplesIncorrects":["Il a estourbi un long discours devant l\'assemblée.","Nous avons estourbi la maison de fond en comble."],"distracteurs":["étourdir","esquinter","rosser"],"anecdote":"Mot d\'argot très présent dans le roman policier français, estourbir doit sa sonorité rugueuse à une racine germanique évoquant la mort, transmise par l\'alsacien.","categorie":"mot-rare"},{"id":"degun","mot":"dégun","nature":"nom","definitions":["Personne, aucun être humain (employé dans une négation ; régionalisme de Marseille et du Sud)."],"phonetique":"/de.ɡœ̃/","etymologie":"De l\'occitan degun, altération de l\'ancien occitan negun, « aucun », du latin nec unus, « pas un seul ».","registre":"familier","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["personne","aucun","nul"],"antonymes":["quelqu\'un","tout le monde","chacun"],"exemplesCorrects":["Il n\'y avait dégun sur la plage à cette heure-là.","Je n\'ai croisé dégun en rentrant.","À Marseille, on dit qu\'on ne craint dégun."],"exemplesIncorrects":["Dégun de mes amis sont venus à la fête.","Il a salué dégun avec un grand sourire chaleureux."],"distracteurs":["quidam","autrui","quiconque"],"anecdote":"« Craindre dégun » est devenu un slogan identitaire marseillais, repris notamment par les supporters de l\'OM pour clamer qu\'ils ne redoutent personne.","categorie":"mot-rare"},{"id":"cafi","mot":"cafi","nature":"adjectif","definitions":["Rempli, bourré, plein à craquer (régionalisme de Provence)."],"phonetique":"/ka.fi/","etymologie":"De l\'occitan provençal cafi, participe passé de cafir, « emplir, combler, bourrer ».","registre":"familier","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["rempli","bondé","bourré"],"antonymes":["vide","désert","dégarni"],"exemplesCorrects":["Le marché était cafi de monde ce matin.","Après la rougeole, il était cafi de boutons.","Le grenier est cafi de vieux meubles et de cartons."],"exemplesIncorrects":["Il a cafi son verre jusqu\'au bord d\'un geste vif.","Nous avons cafi la salle de spectateurs enthousiastes."],"distracteurs":["comble","saturé","regorgeant"],"anecdote":"Adjectif typiquement provençal, cafi s\'emploie toujours suivi de « de » : une rue cafi de touristes, un panier cafi de figues.","categorie":"mot-rare"},{"id":"mitan","mot":"mitan","nature":"nom masculin","definitions":["Le milieu, le centre (d\'un lieu, d\'une période) ; régional et vieilli."],"phonetique":"/mi.tɑ̃/","etymologie":"De l\'ancien français mitan, composé de mi, « à demi » (du latin medius), et de tant (du latin tantum) ; littéralement « la moitié juste ».","registre":"littéraire","niveau":3,"themes":["litteraire","quotidien"],"synonymes":["milieu","centre","cœur"],"antonymes":["bord","extrémité","lisière"],"exemplesCorrects":["Au mitan du chemin de la vie, le poète s\'égara dans une forêt obscure.","La table était dressée au mitan de la grande salle.","C\'était au mitan de l\'été, sous une chaleur écrasante."],"exemplesIncorrects":["Il a mitan la corde en deux morceaux égaux.","Nous avons mitan le pré jusqu\'au crépuscule."],"distracteurs":["pourtour","tréfonds","intervalle"],"anecdote":"Conservé surtout dans la langue littéraire et les chansons populaires, « au mitan de » a été immortalisé par Georges Brassens et de nombreux contes traditionnels.","categorie":"mot-rare"},{"id":"gnognotte","mot":"gnognotte","nature":"nom féminin","definitions":["Chose insignifiante, sans valeur ou sans difficulté (familier)."],"phonetique":"/ɲɔ.ɲɔt/","etymologie":"Mot expressif d\'origine onomatopéique, de la même famille que gnan-gnan, évoquant la mollesse et la niaiserie.","registre":"familier","niveau":3,"themes":["quotidien","abstrait"],"synonymes":["bagatelle","broutille","vétille"],"antonymes":["merveille","trésor","prouesse"],"exemplesCorrects":["Ce devoir, c\'est de la gnognotte pour un élève de son niveau.","À côté de leur dette, mes économies, c\'est de la gnognotte.","Ne te vante pas : ce que tu as fait là, c\'est de la gnognotte."],"exemplesIncorrects":["Il a reçu une gnognotte officielle pour ses services rendus.","La gnognotte du sommet a impressionné toute l\'assemblée."],"distracteurs":["babiole","fadaise","fariboles"],"anecdote":"Presque toujours employée dans la tournure « c\'est de la gnognotte », l\'expression sert à minimiser une difficulté ou à dénigrer la valeur de quelque chose.","categorie":"mot-rare"},{"id":"tatillon","mot":"tatillon","nature":"adjectif","definitions":["Qui s\'attache avec un soin excessif à des détails minutieux ; exagérément méticuleux."],"phonetique":"/ta.ti.jɔ̃/","etymologie":"Dérivé de tâter, « toucher, examiner avec soin » (du latin populaire tastare), avec le suffixe péjoratif -illon.","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["pointilleux","méticuleux","vétilleux"],"antonymes":["négligent","insouciant","désinvolte"],"exemplesCorrects":["Ce correcteur tatillon relève la moindre virgule mal placée.","Une administration tatillonne réclame dix justificatifs pour la moindre démarche.","Elle est tatillonne sur la propreté de sa cuisine."],"exemplesIncorrects":["Il a tatillon son rapport avant de le rendre.","Nous avons tatillon la liste des invités toute la soirée."],"distracteurs":["scrupuleux","tracassier","rigoriste"],"anecdote":"Souvent teinté de reproche, « tatillon » qualifie celui dont la minutie devient agaçante, à la frontière de la maniaquerie bureaucratique.","categorie":"mot-rare"},{"id":"rabibocher","mot":"rabibocher","nature":"verbe","definitions":["Réconcilier des personnes fâchées.","Réparer sommairement, raccommoder de façon provisoire (familier)."],"phonetique":"/ʁa.bi.bɔ.ʃe/","etymologie":"Probablement variante de rabobicher, lui-même issu de rabobiner, « raccommoder de vieilles choses », dérivé de bobine.","registre":"familier","niveau":3,"themes":["quotidien","emotions"],"synonymes":["réconcilier","raccommoder","rapetasser"],"antonymes":["brouiller","fâcher","désunir"],"exemplesCorrects":["Leur mère a fini par rabibocher les deux frères après des mois de bouderie.","Ils se sont rabibochés autour d\'un café, comme si de rien n\'était.","Avec du fil de fer, il a rabiboché la clôture en attendant mieux."],"exemplesIncorrects":["Il a rabiboché un long voyage à travers le pays.","Nous avons rabiboché la vérité au cours du procès."],"distracteurs":["amadouer","rafistoler","ressouder"],"anecdote":"Le mot oscille entre deux registres concrets : on rabiboche aussi bien un couple en froid qu\'un vieil objet cassé, toujours avec une nuance de bricolage approximatif.","categorie":"mot-rare"},{"id":"ramollo","mot":"ramollo","nature":"adjectif","definitions":["Amolli, sans énergie, avachi ; physiquement ou intellectuellement diminué (familier)."],"phonetique":"/ʁa.mɔ.lo/","etymologie":"Dérivé familier de ramolli, participe passé de ramollir, avec la finale plaisante -o (sur le modèle de rigolo) ; de mou, du latin mollis.","registre":"familier","niveau":3,"themes":["quotidien","emotions"],"synonymes":["avachi","ramolli","flagada"],"antonymes":["fringant","vigoureux","alerte"],"exemplesCorrects":["Après ce gros repas, je me sens tout ramollo.","Le vieux chien, complètement ramollo, somnolait au soleil.","Reste pas ramollo sur le canapé, viens marcher un peu !"],"exemplesIncorrects":["Il a ramollo la pâte avant de l\'étaler.","La chaleur a ramollo le beurre dans son emballage."],"distracteurs":["amorphe","languide","indolent"],"anecdote":"La finale en -o, comme dans « rigolo » ou « dingo », donne à « ramollo » une coloration plaisante et affectueuse propre à l\'argot familier.","categorie":"mot-rare"},{"id":"berlue","mot":"berlue","nature":"nom féminin","definitions":["Illusion d\'optique, vision trompeuse ; dans la locution « avoir la berlue », croire voir ce qui n\'existe pas ou mal voir."],"phonetique":"/bɛʁ.ly/","etymologie":"Dérivé de l\'ancien verbe belluer, « éblouir, tromper la vue » (XIVe siècle), d\'origine incertaine, peut-être du préfixe bes- (latin bis) et d\'un radical issu de lux, lucis (lumière).","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["hallucination","illusion","éblouissement"],"antonymes":["lucidité","clairvoyance","réalité"],"exemplesCorrects":["Je crois que j\'ai la berlue : son nom apparaît vraiment sur la liste ?","Avec cette lumière vacillante, on a vite la berlue.","Non, tu n\'as pas la berlue, c\'est bien lui que tu as vu."],"exemplesIncorrects":["Il a berlue son rendez-vous de la matinée.","Nous avons offert une berlue à notre voisin pour son anniversaire."],"distracteurs":["mirage","chimère","trouble"],"anecdote":"Presque toujours figée dans l\'expression « avoir la berlue », cette vieille image médiévale de l\'éblouissement traduit aujourd\'hui la stupeur de celui qui doute de ses propres yeux.","categorie":"mot-rare"},{"id":"mensch","mot":"mensch","nature":"nom masculin","definitions":["Personne d\'une intégrité et d\'une bonté exemplaires, digne d\'admiration et de respect ; être humain accompli sur le plan moral."],"phonetique":"/mɛnʃ/","etymologie":"De l\'yiddish מענטש (mentsh), « être humain », apparenté à l\'allemand Mensch (homme, personne), du moyen-haut-allemand mensch et du vieux-haut-allemand mennisco.","registre":"soutenu","niveau":4,"themes":["emprunts","abstrait","emotions"],"synonymes":["homme de bien","honnête homme","personne de cœur"],"antonymes":["goujat","malhonnête","scélérat"],"exemplesCorrects":["Son père était un véritable mensch, toujours prêt à aider sans rien attendre en retour.","Devenir un mensch, voilà le plus bel idéal qu\'une éducation puisse transmettre.","On le tenait pour un mensch, et sa parole valait tous les contrats."],"exemplesIncorrects":["Il y avait trois mensch dans la salle d\'attente.","Ce mensch passa devant moi sans même me saluer, le malotru."],"distracteurs":["bourgeois","philistin","notable"],"anecdote":"On croit souvent que mensch signifie simplement « homme » ou « individu », comme l\'allemand Mensch. En français, le mot emprunté à l\'yiddish ne désigne pas n\'importe quelle personne mais quelqu\'un de noble caractère : un modèle d\'humanité, pas un simple membre de l\'espèce humaine.","categorie":"piege-sens","piege":{"formeFautive":"un mensch = un homme quelconque","explication":"Mensch ne désigne pas n\'importe quelle personne mais quelqu\'un d\'une intégrité et d\'une bonté exemplaires. L\'employer comme simple synonyme de « homme » ou « individu » est un contresens."}},{"id":"chutzpah","mot":"chutzpah","nature":"nom féminin","definitions":["Audace effrontée, culot poussé jusqu\'à l\'insolence ; aplomb déconcertant de qui ose ce que la bienséance interdit."],"phonetique":"/xut.spa/","etymologie":"De l\'yiddish חוצפּה (khutspe), lui-même issu de l\'hébreu mishnique חֻצְפָּה (ḥuṣpā), « insolence, effronterie », de la racine ḥāṣap, « être insolent ».","registre":"soutenu","niveau":4,"themes":["emprunts","abstrait","emotions"],"synonymes":["effronterie","toupet","aplomb"],"antonymes":["timidité","réserve","humilité"],"exemplesCorrects":["Il a eu la chutzpah de réclamer une augmentation le lendemain de sa bourde.","Quelle chutzpah de critiquer l\'hôte dans sa propre maison !","Sa chutzpah désarma les jurés, qui finirent par sourire."],"exemplesIncorrects":["La chutzpah du paysage au crépuscule nous laissa muets.","Il fit preuve d\'une grande chutzpah en s\'effaçant pour laisser passer les autres."],"distracteurs":["obséquiosité","forfanterie","componction"],"anecdote":"On voit souvent ce mot écorché en « chutzpa », « hutzpah » ou « choutzpa ». La graphie consacrée en français est chutzpah, fidèle à la translittération de l\'yiddish ; le « ch » initial note le son guttural de l\'hébreu, étranger au français, ce qui explique les nombreuses variantes fautives.","categorie":"piege-orthographe","piege":{"formeFautive":"chutzpa","explication":"La forme consacrée comporte un « h » final : chutzpah. Les graphies « chutzpa », « hutzpah » ou « choutzpa » sont fautives."}},{"id":"depaysement","mot":"dépaysement","nature":"nom masculin","definitions":["Sensation de désorientation agréable ou troublante éprouvée hors de son cadre familier ; changement complet d\'habitudes et de décor.","Fait d\'être transporté loin de ses repères ordinaires."],"phonetique":"/de.pɛ.iz.mɑ̃/","etymologie":"Dérivé du verbe dépayser, de dé- (préfixe de séparation) et pays, du latin pagensis, « habitant d\'un canton », de pagus, « bourg, district ».","registre":"courant","niveau":2,"themes":["emotions","abstrait","quotidien"],"synonymes":["désorientation","exotisme","changement de décor"],"antonymes":["accoutumance","routine","familiarité"],"exemplesCorrects":["Trois jours à Lisbonne lui offrirent un dépaysement total, loin de la grisaille du bureau.","Elle recherchait le dépaysement plus que le repos, l\'imprévu plus que le confort.","Le simple parfum des épices, au marché, suffisait à provoquer un délicieux dépaysement."],"exemplesIncorrects":["Le dépaysement de l\'usine entraîna le licenciement de cent ouvriers.","On l\'accusa de dépaysement pour avoir trahi son pays natal."],"distracteurs":["désœuvrement","déracinement","désagrément"],"anecdote":"On réduit souvent le dépaysement à un malaise, à la simple perte de repères. Le mot, réputé difficile à traduire, dit en réalité bien davantage : ce mélange de désorientation et d\'émerveillement que procure l\'arrachement, même bref, à son quotidien — un trouble le plus souvent recherché et savouré.","categorie":"piege-sens","piege":{"formeFautive":"dépaysement = simple désagrément ou mal du pays","explication":"Le dépaysement n\'est pas le mal du pays ni une gêne pénible : c\'est le changement de cadre, souvent plaisant, qui mêle désorientation et émerveillement. Le confondre avec la nostalgie du foyer est un contresens."}},{"id":"abbiocco","mot":"abbiocco","nature":"nom masculin","definitions":["Somnolence lourde et irrésistible qui survient après un repas copieux ; coup de barre digestif."],"phonetique":"/a.bjɔ.ko/","etymologie":"De l\'italien abbiocco, déverbal de abbioccarsi, « s\'assoupir, se pelotonner », du dialectal abbioccàsse, « devenir poule couveuse, couver », dénominal de biocca, « poule couveuse », évoquant l\'engourdissement de l\'oiseau accroupi sur ses œufs.","registre":"familier","niveau":4,"themes":["emprunts","quotidien"],"synonymes":["somnolence","torpeur","assoupissement"],"antonymes":["vivacité","fébrilité","éveil"],"exemplesCorrects":["Après les lasagnes de sa grand-mère, un abbiocco invincible le cloua sur le canapé.","Le déjeuner de Noël se termina, comme toujours, par un abbiocco général.","Méfie-toi de l\'abbiocco si tu dois conduire juste après ce festin."],"exemplesIncorrects":["Un abbiocco d\'énergie le poussa à courir dix kilomètres.","Elle commanda un abbiocco bien serré pour rester éveillée."],"distracteurs":["fringale","courbature","migraine"],"anecdote":"Les Italiens ont un mot pour ce que tout le monde éprouve mais que peu de langues nomment : cette envie de sieste qui s\'abat après un plat de pâtes. L\'abbiocco serait apparenté à la « poule couveuse », image de l\'engourdissement repu — preuve que la langue italienne prend la digestion très au sérieux.","categorie":"mot-rare"},{"id":"culaccino","mot":"culaccino","nature":"nom masculin","definitions":["Trace ronde laissée sur une table par le fond d\'un verre humide ou froid ; auréole d\'un récipient mouillé.","En italien, désigne aussi le quignon ou l\'extrémité d\'un pain ou d\'un saucisson."],"phonetique":"/ky.la.tʃi.no/","etymologie":"De l\'italien culaccino, diminutif de culo, « cul, fond », au sens de « petit fond » d\'un objet, d\'où la marque laissée par le fond d\'un verre.","registre":"familier","niveau":5,"themes":["emprunts","quotidien"],"synonymes":["auréole","trace","cerne"],"antonymes":["propreté","netteté","immaculé"],"exemplesCorrects":["Le verre de limonade avait laissé un culaccino bien net sur le bois ciré.","Elle s\'agaçait du culaccino que chaque invité abandonnait sur sa belle table.","Un sous-verre évite tout culaccino, même avec une boisson glacée."],"exemplesIncorrects":["Il commanda un culaccino de vin rouge au comptoir.","Le culaccino du ciel annonçait l\'orage du soir."],"distracteurs":["éclaboussure","estompe","tavelure"],"anecdote":"L\'italien désigne d\'un seul mot la petite auréole humide qu\'un verre laisse sur la table. Le terme vient de culo, le « fond » de l\'objet ; il sert d\'ailleurs aussi, en cuisine, à nommer le quignon du pain ou le bout du saucisson — autant de « petits fonds ».","categorie":"mot-rare"},{"id":"gattara","mot":"gattara","nature":"nom féminin","definitions":["Femme, souvent âgée, qui se consacre à nourrir et soigner les chats errants ; protectrice des chats des rues."],"phonetique":"/ɡa.ta.ra/","etymologie":"De l\'italien gattara, dérivé de gatto, « chat », lui-même du bas latin cattus, avec le suffixe romain -aro (latin -arium).","registre":"familier","niveau":5,"themes":["emprunts","quotidien"],"synonymes":["protectrice des chats","nourrisseuse"],"antonymes":[],"exemplesCorrects":["Chaque soir, la gattara du quartier déposait des gamelles au pied des immeubles.","À Rome, les gattare veillent sur les colonies félines des ruines antiques.","On la traitait de gattara, mais sans elle ces chats n\'auraient pas survécu à l\'hiver."],"exemplesIncorrects":["Le gattara ronronnait sur le rebord de la fenêtre.","Elle adopta une gattara tigrée trouvée dans la rue."],"distracteurs":["dompteuse","éleveuse","vétérinaire"],"anecdote":"À Rome, les gattare sont si reconnues qu\'une loi de 1991 protège les colonies de chats des rues qu\'elles nourrissent. Le mot, d\'abord teinté de moquerie, désigne ces femmes dévouées que l\'on croise au crépuscule, gamelle à la main, parmi les vestiges antiques peuplés de félins.","categorie":"mot-rare"},{"id":"meriggiare","mot":"meriggiare","nature":"verbe","definitions":["Se reposer à l\'ombre, à l\'abri de la chaleur, pendant les heures les plus chaudes de la journée ; faire halte au plus fort du midi."],"phonetique":"/me.ri.dʒa.re/","etymologie":"De l\'italien meriggiare, dérivé de meriggio, « milieu du jour, midi », du latin meridies, « midi », altération de medidies (medius + dies, « milieu du jour »).","registre":"littéraire","niveau":5,"themes":["emprunts","nature","litteraire"],"synonymes":["se reposer","s\'abriter","somnoler"],"antonymes":["s\'activer","peiner","s\'agiter"],"exemplesCorrects":["Sous le grand pin, les bergers aimaient meriggiare jusqu\'à ce que tombe la fournaise.","Meriggiare au plus chaud de l\'été, voilà tout le programme d\'un après-midi en Toscane.","Les voyageurs s\'étaient arrêtés pour meriggiare avant de reprendre la route poussiéreuse."],"exemplesIncorrects":["Il aimait meriggiare au petit matin, avant le lever du soleil.","Ils décidèrent de meriggiare toute la nuit sous les étoiles glacées."],"distracteurs":["flâner","lézarder","musarder"],"anecdote":"Le verbe doit sa célébrité à Eugenio Montale, dont le poème s\'ouvre sur « Meriggiare pallido e assorto ». Rare dans l\'italien courant, il dit en un seul mot cette halte ombragée qu\'impose la canicule de midi, héritée du latin meridies dont le français a tiré « méridienne », la sieste de l\'après-midi.","categorie":"mot-rare"},{"id":"magari","mot":"magari","nature":"interjection","definitions":["Si seulement ! exprimant un souhait ardent teinté de doute ou de résignation.","Peut-être, éventuellement (selon le contexte)."],"phonetique":"/ma.ɡa.ri/","etymologie":"De l\'italien magari, du grec byzantin μακάρι (makári), « plût au ciel », lui-même issu du grec ancien μακάριος (makários), « bienheureux ».","registre":"courant","niveau":4,"themes":["emprunts","emotions","abstrait"],"synonymes":["pourvu que","plût au ciel","si seulement"],"antonymes":["hélas","sûrement pas","jamais"],"exemplesCorrects":["Gagner au loto ? Magari ! Mais je n\'y crois pas une seconde.","« Tu viendras cet été ? — Magari, si le travail me le permet. »","Magari pouvoir tout recommencer, soupira-t-elle en refermant l\'album."],"exemplesIncorrects":["Il rangea ses magari dans le tiroir du bureau.","Le magari de la montagne se reflétait dans le lac."],"distracteurs":["volontiers","désormais","carrément"],"anecdote":"Mot fétiche des Italiens, magari condense en deux syllabes tout l\'espoir mêlé de doute d\'un « si seulement ». Venu du grec « makári » (plût au ciel !), il peut signifier tantôt un désir ardent, tantôt un « peut-être » prudent, au gré de l\'intonation.","categorie":"expression"},{"id":"qualunquismo","mot":"qualunquismo","nature":"nom masculin","definitions":["Attitude d\'indifférence cynique et de défiance systématique envers la politique, les institutions et le bien commun ; rejet désabusé de tout engagement civique."],"phonetique":"/kwa.lun.kwi.zmo/","etymologie":"De l\'italien qualunquismo, dérivé de qualunque, « quelconque, n\'importe lequel », forgé d\'après le Fronte dell\'Uomo Qualunque, mouvement politique fondé en 1944 par Guglielmo Giannini.","registre":"soutenu","niveau":5,"themes":["emprunts","abstrait"],"synonymes":["antipolitisme","désengagement","cynisme"],"antonymes":["militantisme","engagement","civisme"],"exemplesCorrects":["Le qualunquismo ambiant vidait les bureaux de vote année après année.","Dénoncer le qualunquismo, c\'est rappeler que se désintéresser de tout est aussi un choix politique.","Derrière son ironie perçait un qualunquismo qui refusait toute cause."],"exemplesIncorrects":["Il décora son salon dans un style qualunquismo très épuré.","Le qualunquismo des Alpes attire les randonneurs chaque été."],"distracteurs":["conformisme","populisme","scepticisme"],"anecdote":"Le mot naît en Italie de l\'« Uomo Qualunque » (l\'homme quelconque), journal puis parti fondé en 1944, qui se faisait le porte-voix de la défiance envers tous les partis. Le qualunquismo désigne depuis cette posture de rejet désabusé de la politique, où l\'on renvoie dos à dos gouvernants et opposants au nom du « citoyen ordinaire ».","categorie":"mot-rare"},{"id":"estrenar","mot":"estrenar","nature":"verbe","definitions":["Porter, utiliser ou inaugurer une chose pour la toute première fois ; étrenner.","En espagnol, se dit aussi de la première représentation d\'un spectacle ou de la sortie d\'un film."],"phonetique":"/es.tʁe.naʁ/","etymologie":"De l\'espagnol estrenar, du latin strena, « présage, cadeau de bon augure offert en début d\'année », mot qui a aussi donné le français étrenner.","registre":"courant","niveau":5,"themes":["emprunts","quotidien"],"synonymes":["étrenner","inaugurer","essayer"],"antonymes":["user","ranger","délaisser"],"exemplesCorrects":["Elle attendait la fête pour estrenar la robe qu\'elle s\'était offerte.","Le théâtre allait estrenar la pièce du jeune auteur le soir même.","Rien n\'égale le plaisir d\'estrenar des chaussures neuves un matin de printemps."],"exemplesIncorrects":["Il faut estrenar ces vieux outils avant de les jeter.","Elle décida d\'estrenar le manteau qu\'elle portait depuis dix ans."],"distracteurs":["entamer","rénover","dénicher"],"anecdote":"L\'espagnol estrenar partage son ancêtre latin avec le français « étrenner » : tous deux viennent de strena, le cadeau de bon augure du Nouvel An, qui a aussi donné nos « étrennes ». Là où le français a un peu vieilli, l\'espagnol l\'emploie au quotidien, jusqu\'à désigner la première d\'un film.","categorie":"mot-rare"},{"id":"verguenza-ajena","mot":"vergüenza ajena","nature":"locution","definitions":["Honte ou gêne ressentie pour le compte d\'autrui, par procuration, devant le comportement embarrassant d\'une autre personne ; malaise empathique."],"phonetique":"/beʁ.ɡwen.sa.a.xe.na/","etymologie":"Locution espagnole, de vergüenza, « honte » (du latin verecundia, « pudeur, retenue »), et ajena, féminin de ajeno, « d\'autrui » (du latin alienus, « étranger, d\'autrui »).","registre":"courant","niveau":4,"themes":["emprunts","emotions","abstrait"],"synonymes":["gêne par procuration","honte empathique","embarras"],"antonymes":["fierté","indifférence","détachement"],"exemplesCorrects":["Le discours maladroit du marié me donna une vergüenza ajena insoutenable.","Devant ce candidat qui s\'enfonçait, le public éprouvait une nette vergüenza ajena.","Elle changea de chaîne, gagnée par la vergüenza ajena que lui inspirait l\'animateur."],"exemplesIncorrects":["Il ressentit une grande vergüenza ajena de ses propres erreurs.","La vergüenza ajena du sommet offrait une vue imprenable sur la vallée."],"distracteurs":["compassion","indignation","componction"],"anecdote":"L\'espagnol nomme d\'une locution ce malaise que tout le monde connaît : avoir honte à la place de quelqu\'un d\'autre. Les Allemands disent Fremdschämen et l\'anglais a fini par emprunter ce sentiment. La vergüenza ajena, c\'est rougir non de ses propres fautes, mais des bévues d\'autrui.","categorie":"expression"},{"id":"desenrascanco","mot":"desenrascanço","nature":"nom masculin","definitions":["Art de se tirer d\'un mauvais pas par l\'improvisation, la débrouille et l\'ingéniosité du dernier moment ; talent pour trouver une solution avec les moyens du bord."],"phonetique":"/dɛ.zɛ̃.ʁas.kɑ̃.so/","etymologie":"Du portugais desenrascanço, dérivé du verbe desenrascar, « se dépêtrer, se sortir d\'embarras », de des- (préfixe inverseur) et enrascar, « emmêler, embourber », de rasca, « filet de pêche ».","registre":"courant","niveau":5,"themes":["emprunts","abstrait","quotidien"],"synonymes":["débrouillardise","système D","improvisation"],"antonymes":["méthode","planification","maladresse"],"exemplesCorrects":["Sans outils ni notice, il répara le moteur par pur desenrascanço.","Le desenrascanço est, dit-on, une vertu nationale au Portugal.","Grâce à un peu de desenrascanço, elle improvisa un dîner pour dix avec trois fois rien."],"exemplesIncorrects":["Il prépara son exposé avec un desenrascanço minutieux, planifié des mois à l\'avance.","Le desenrascanço de la falaise dominait l\'océan Atlantique."],"distracteurs":["persévérance","désinvolture","circonspection"],"anecdote":"Les Portugais revendiquent le desenrascanço comme un trait national : l\'art de s\'en sortir sans rien, à la dernière minute. Le mot vient du vocabulaire de la pêche — le filet « enrascado », coincé sur les rochers, qu\'il fallait dégager avec adresse sans le déchirer.","categorie":"mot-rare"},{"id":"cafune","mot":"cafuné","nature":"nom masculin","definitions":["Au Brésil, geste tendre consistant à passer délicatement les doigts dans les cheveux d\'un proche, à lui caresser doucement la tête ou la nuque en signe d\'affection."],"phonetique":"/ka.fu.ne/","etymologie":"Mot du portugais brésilien cafuné, d\'origine incertaine, peut-être issu du kimbundu (langue bantoue d\'Angola) kifumate, désignant l\'action de craquer les ongles sur la tête de quelqu\'un.","registre":"littéraire","niveau":5,"themes":["emprunts","emotions"],"synonymes":["caresse","câlin"],"antonymes":["brusquerie","rudoiement"],"exemplesCorrects":["Au Brésil, le cafuné est un geste d\'affection que l\'on offre à un enfant ou à un amoureux.","Elle s\'endormait toujours plus vite quand il lui faisait un cafuné.","Le cafuné n\'a pas vraiment d\'équivalent en un seul mot dans notre langue."],"exemplesIncorrects":["Il a cafuné la porte d\'un grand coup de pied.","Le cafuné de la voiture était couvert de boue après l\'orage."],"distracteurs":["bercement","effleurement","chuchotement"],"anecdote":"Le cafuné est souvent cité parmi les mots intraduisibles : il dit en une seule syllabe ce que le français doit décrire par toute une phrase.","categorie":"mot-rare"},{"id":"dolce-far-niente","mot":"dolce far niente","nature":"locution","definitions":["La douceur de ne rien faire ; l\'art d\'une oisiveté tranquille et savourée, sans culpabilité."],"phonetique":"/dɔl.tʃe.faʁ.njɛn.te/","etymologie":"Locution empruntée à l\'italien dolce far niente, littéralement « doux faire rien », c\'est-à-dire « la douce chose qu\'est de ne rien faire ».","registre":"littéraire","niveau":3,"themes":["emprunts","abstrait"],"synonymes":["farniente","oisiveté","paresse"],"antonymes":["labeur","activité","affairement"],"exemplesCorrects":["Après des mois de travail acharné, il s\'abandonna au dolce far niente sur la terrasse.","Les vacances italiennes invitent au dolce far niente, entre sieste et café.","Elle défendait le dolce far niente comme une forme supérieure de sagesse."],"exemplesIncorrects":["Il a dolce far niente toute la maison en une journée.","Le dolce far niente du moteur indiquait une panne sérieuse."],"distracteurs":["villégiature","quiétude","désœuvrement"],"anecdote":"Le français a tiré de cette locution le mot « farniente », soudé en un seul terme, qui a perdu en chemin le « dolce » mais gardé toute la douceur.","categorie":"expression"},{"id":"rester-en-carafe","mot":"rester en carafe","nature":"locution","definitions":["Se retrouver bloqué, abandonné ou laissé de côté ; être en panne, ou rester sans rien dire après avoir perdu le fil de ce que l\'on voulait exprimer."],"phonetique":"/ʁɛs.te.ɑ̃.ka.ʁaf/","etymologie":"Locution familière du XIXe siècle ; carafe y désigne par image la gorge ou la bouche, « rester en carafe » signifiant d\'abord rester bouche bée, à court de mots.","registre":"familier","niveau":2,"themes":["quotidien","regionalismes"],"synonymes":["rester en plan","rester en rade","être planté"],"antonymes":["être tiré d\'affaire","avancer","poursuivre"],"exemplesCorrects":["Le train est parti sans nous : on est restés en carafe sur le quai.","Sa voiture l\'a lâché et il est resté en carafe à l\'entrée de l\'autoroute.","En plein discours, il a perdu ses notes et est resté en carafe devant l\'assemblée."],"exemplesIncorrects":["Elle a resté en carafe un magnifique bouquet sur la table.","Le sommelier a rempli la carafe pour rester en carafe les invités."],"distracteurs":["rester coi","rester sur sa faim","prendre le large"],"anecdote":"« Rester en carafe » et « tomber en rade » se ressemblent, mais la « rade » de la seconde n\'est pas un port : c\'est une déformation de « en plan ».","categorie":"expression"},{"id":"decouvrir-le-pot-aux-roses","mot":"découvrir le pot aux roses","nature":"locution","definitions":["Percer un secret bien gardé, déjouer une supercherie, mettre au jour la vérité d\'une affaire cachée."],"phonetique":"/de.ku.vʁiʁ.lə.po.to.ʁoz/","etymologie":"Locution attestée dès le XIIIe siècle, d\'origine discutée ; la rose y symbolise traditionnellement le secret, et « découvrir le pot » jouait sur les deux sens de découvrir : ôter le couvercle et mettre au jour.","registre":"courant","niveau":2,"themes":["quotidien","litteraire"],"synonymes":["éventer le secret","déjouer la ruse","percer le mystère"],"antonymes":["dissimuler","étouffer l\'affaire","garder le secret"],"exemplesCorrects":["Le comptable a fini par découvrir le pot aux roses : les factures étaient truquées.","Quand elle a découvert le pot aux roses, toute la mascarade s\'est effondrée.","Les journalistes ont découvert le pot aux roses après des mois d\'enquête."],"exemplesIncorrects":["Au marché, elle a découvert le pot aux roses parmi les fleurs du jardinier.","Il a découvert le pot aux roses fané sur le rebord de la fenêtre."],"distracteurs":["enterrer l\'affaire","noyer le poisson","couvrir la fraude"],"anecdote":"On écrit « le pot aux roses » et non « le poteau rose » : l\'homophonie a engendré une coquille devenue presque légendaire.","categorie":"expression"},{"id":"jeter-sa-gourme","mot":"jeter sa gourme","nature":"locution","definitions":["Faire ses premières folies de jeunesse, se livrer aux écarts et aux excès propres à l\'entrée dans l\'âge adulte."],"phonetique":"/ʒə.te.sa.ɡuʁm/","etymologie":"Locution attestée dès le XVIe siècle ; la gourme est une maladie infectieuse des jeunes chevaux (du bas francique worm, « pus »), passage obligé dont la jeunesse devait « se débarrasser ».","registre":"familier","niveau":3,"themes":["litteraire","quotidien"],"synonymes":["faire les quatre cents coups","faire ses folies","s\'émanciper"],"antonymes":["s\'assagir","se ranger","se discipliner"],"exemplesCorrects":["Il a jeté sa gourme à vingt ans avant de devenir un père de famille rangé.","Laissons-le jeter sa gourme : ces escapades lui passeront avec l\'âge.","Après avoir jeté sa gourme dans les capitales d\'Europe, elle s\'établit enfin."],"exemplesIncorrects":["Furieux, il a jeté sa gourme contre le mur de la cuisine.","Le palefrenier a jeté sa gourme du cheval malade dans la rivière."],"distracteurs":["faire amende honorable","rentrer dans le rang","filer doux"],"anecdote":"On comprend souvent « gourme » comme une grossièreté, alors qu\'il s\'agit d\'une vraie maladie équine ; le jeune homme qui « jette sa gourme » imite le poulain qui guérit en grandissant.","categorie":"expression"},{"id":"monter-sur-ses-grands-chevaux","mot":"monter sur ses grands chevaux","nature":"locution","definitions":["S\'emporter, se mettre en colère, prendre de haut son interlocuteur en adoptant un ton arrogant ou indigné."],"phonetique":"/mɔ̃.te.syʁ.se.ɡʁɑ̃.ʃə.vo/","etymologie":"Locution issue du vocabulaire médiéval de la guerre ; les « grands chevaux » étaient les puissants destriers de bataille, montés au combat, par opposition aux montures ordinaires des déplacements paisibles.","registre":"courant","niveau":2,"themes":["emotions","quotidien"],"synonymes":["s\'emporter","prendre la mouche","se cabrer"],"antonymes":["garder son calme","rester posé","tempérer"],"exemplesCorrects":["Dès qu\'on critique son travail, il monte sur ses grands chevaux.","Inutile de monter sur tes grands chevaux : je voulais seulement t\'aider.","Elle est montée sur ses grands chevaux à la moindre remarque du jury."],"exemplesIncorrects":["Au manège, les enfants sont montés sur ses grands chevaux pour la balade.","Il a monté sur ses grands chevaux jusqu\'au sommet de la colline."],"distracteurs":["serrer les dents","baisser pavillon","ronger son frein"],"anecdote":"L\'image vient du Moyen Âge : enfourcher son destrier de combat, c\'était se préparer à en découdre, d\'où l\'idée d\'une colère prête à charger.","categorie":"expression"},{"id":"tirer-le-diable-par-la-queue","mot":"tirer le diable par la queue","nature":"locution","definitions":["Vivre dans la gêne, avoir constamment du mal à joindre les deux bouts, manquer d\'argent."],"phonetique":"/ti.ʁe.lə.djabl.paʁ.la.kø/","etymologie":"Locution attestée au XVIIe siècle ; l\'image serait celle du miséreux si désespéré qu\'il en appelle au diable, tirant sa queue pour le faire venir, sans même y parvenir.","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["être dans la gêne","joindre difficilement les deux bouts","vivoter"],"antonymes":["prospérer","rouler sur l\'or","être à l\'aise"],"exemplesCorrects":["Depuis qu\'il a perdu son emploi, il tire le diable par la queue.","Cette famille tire le diable par la queue pour payer le loyer chaque mois.","Étudiante, elle a longtemps tiré le diable par la queue avant de percer."],"exemplesIncorrects":["Le dompteur a tiré le diable par la queue pour amuser le public.","Il a tiré le diable par la queue jusqu\'à la sortie du village."],"distracteurs":["mener grand train","se la couler douce","battre monnaie"],"anecdote":"On a longtemps cru l\'expression née d\'une enseigne de cabaret figurant un diable ; en réalité elle peint surtout le dénuement de qui n\'a plus que le diable à qui s\'adresser.","categorie":"expression"},{"id":"se-mettre-la-rate-au-court-bouillon","mot":"se mettre la rate au court-bouillon","nature":"locution","definitions":["S\'inquiéter à l\'excès, se faire un sang d\'encre, se tourmenter outre mesure pour une affaire."],"phonetique":"/sə.mɛtʁ.la.ʁat.o.kuʁ.bu.jɔ̃/","etymologie":"Locution familière popularisée au XXe siècle par Frédéric Dard (San-Antonio) ; elle s\'appuie sur la rate, organe que la médecine ancienne associait aux humeurs et à la mélancolie, et sur le court-bouillon, métaphore culinaire d\'une ébullition intérieure.","registre":"familier","niveau":3,"themes":["emotions","quotidien"],"synonymes":["se faire un sang d\'encre","se ronger les sangs","se faire du mauvais sang"],"antonymes":["rester serein","prendre les choses du bon côté","se rassurer"],"exemplesCorrects":["Ne te mets pas la rate au court-bouillon, l\'examen se passera bien.","Elle s\'est mis la rate au court-bouillon tant que les résultats n\'arrivaient pas.","Inutile de se mettre la rate au court-bouillon pour un retard de cinq minutes."],"exemplesIncorrects":["Le cuisinier a mis la rate au court-bouillon avec un filet de citron.","Pour le dîner, on s\'est mis la rate au court-bouillon avec des légumes."],"distracteurs":["prendre son mal en patience","garder la tête froide","couper la poire en deux"],"anecdote":"Cousine de « se faire de la bile », l\'expression remonte à la théorie des humeurs, qui logeait dans la rate la mélancolie et les soucis.","categorie":"expression"},{"id":"avoir-un-fil-a-la-patte","mot":"avoir un fil à la patte","nature":"locution","definitions":["Être entravé dans sa liberté par une attache, une obligation ou un engagement, souvent sentimental."],"phonetique":"/a.vwaʁ.œ̃.fil.a.la.pat/","etymologie":"Locution née de l\'image d\'un oiseau ou d\'un animal retenu par un fil noué à la patte, qui l\'empêche de s\'envoler ou de s\'éloigner librement.","registre":"familier","niveau":2,"themes":["quotidien","emotions"],"synonymes":["être attaché","être lié","avoir une entrave"],"antonymes":["être libre","être sans attaches","voler de ses propres ailes"],"exemplesCorrects":["Il ne peut plus sortir le soir : depuis son mariage, il a un fil à la patte.","Avec ce prêt sur vingt ans, ils ont un fil à la patte pour longtemps.","Elle refusait tout engagement, de peur d\'avoir un fil à la patte."],"exemplesIncorrects":["Le chirurgien a un fil à la patte du patient après l\'opération.","Le cordonnier a un fil à la patte pour réparer la chaussure."],"distracteurs":["avoir le bras long","avoir le pied marin","avoir les coudées franches"],"anecdote":"Georges Feydeau en fit le titre d\'un vaudeville célèbre, « Un fil à la patte », où un homme tente en vain de se défaire d\'une maîtresse encombrante.","categorie":"expression"},{"id":"porter-le-chapeau","mot":"porter le chapeau","nature":"locution","definitions":["Endosser la responsabilité d\'une faute, être tenu pour coupable, souvent à la place du véritable fautif."],"phonetique":"/pɔʁ.te.lə.ʃa.po/","etymologie":"Locution familière du XXe siècle issue de l\'argot ; « le chapeau » y symbolise la responsabilité ou l\'accusation que l\'on fait peser, comme un couvre-chef, sur la tête de quelqu\'un.","registre":"familier","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["endosser la faute","payer les pots cassés","trinquer"],"antonymes":["se disculper","être blanchi","s\'en tirer"],"exemplesCorrects":["C\'est toujours le subalterne qui porte le chapeau quand le projet échoue.","Il a porté le chapeau pour une erreur qu\'il n\'avait pas commise.","Pas question que je porte le chapeau à la place des vrais responsables."],"exemplesIncorrects":["En hiver, il faut porter le chapeau pour se protéger du froid.","Le mannequin a porté le chapeau de paille tout au long du défilé."],"distracteurs":["tirer son épingle du jeu","laver son honneur","porter le deuil"],"anecdote":"Dans le même registre argotique, « faire porter le chapeau » à quelqu\'un, c\'est lui faire endosser une faute : le couvre-chef y devient le symbole d\'une culpabilité que l\'on coiffe de force.","categorie":"expression"},{"id":"se-faire-tirer-l-oreille","mot":"se faire tirer l\'oreille","nature":"locution","definitions":["Se faire prier longuement avant de consentir à quelque chose ; n\'accepter qu\'avec réticence."],"phonetique":"/sə fɛʁ ti.ʁe lɔ.ʁɛj/","etymologie":"Image ancienne : tirer l\'oreille de quelqu\'un pour le rappeler à l\'ordre ou le contraindre ; l\'expression évoque le fait qu\'il faille presque le forcer pour qu\'il cède.","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["se faire prier","rechigner","renâcler"],"antonymes":["s\'empresser","accepter d\'emblée","consentir aussitôt"],"exemplesCorrects":["Il s\'est fait tirer l\'oreille avant d\'accepter de nous accompagner.","Pour régler sa part, elle se fait toujours tirer l\'oreille.","Les enfants se font tirer l\'oreille quand vient l\'heure des devoirs."],"exemplesIncorrects":["Il s\'est fait tirer l\'oreille au coin de la rue par un passant.","Le médecin lui a tiré l\'oreille pour soigner son otite."],"distracteurs":["se faire mousser","se faire l\'écho","se faire la malle"],"anecdote":"L\'expression reflète une époque où tirer l\'oreille d\'un récalcitrant, élève ou enfant, était un geste de réprimande courant.","categorie":"expression"},{"id":"rendre-gorge","mot":"rendre gorge","nature":"locution","definitions":["Restituer de force ce que l\'on a injustement ou indûment acquis ; être contraint de rendre un profit illégitime."],"phonetique":"/ʁɑ̃dʁ ɡɔʁʒ/","etymologie":"De la fauconnerie : la « gorge » désignait le jabot de l\'oiseau de proie ; lui « faire rendre gorge », c\'était lui faire vomir la nourriture avalée. L\'image de la restitution forcée en découle.","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["restituer","rembourser","dégorger"],"antonymes":["s\'approprier","détourner","conserver"],"exemplesCorrects":["Les fraudeurs ont dû rendre gorge sous la pression de la justice.","Condamné, il fut sommé de rendre gorge jusqu\'au dernier centime.","On finit toujours par faire rendre gorge à ceux qui s\'enrichissent malhonnêtement."],"exemplesIncorrects":["Il a rendu gorge un magnifique compliment à son hôtesse.","La cantatrice rendait gorge avec une justesse remarquable."],"distracteurs":["prendre langue","faire chorus","rendre raison"],"anecdote":"L\'image vient des fauconniers qui pressaient le jabot de l\'oiseau pour lui faire « rendre gorge » : la métaphore de la restitution forcée en découle directement.","categorie":"expression"},{"id":"filer-un-mauvais-coton","mot":"filer un mauvais coton","nature":"locution","definitions":["Être en mauvaise voie, voir sa santé ou sa situation se dégrader peu à peu ; péricliter, dépérir."],"phonetique":"/fi.le œ̃ mo.vɛ kɔ.tɔ̃/","etymologie":"À la fin du XVIIe siècle on disait « jeter un vilain coton », par allusion aux étoffes usées qui perdaient leurs bouloches de coton ; au XIXe siècle, avec l\'essor des filatures, « jeter » devint « filer » et « vilain » devint « mauvais ».","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["péricliter","dépérir","décliner"],"antonymes":["prospérer","se rétablir","s\'améliorer"],"exemplesCorrects":["Depuis son licenciement, il file un mauvais coton.","Le médecin s\'inquiète : le patient file un mauvais coton.","Cette entreprise file un mauvais coton depuis le départ de son fondateur."],"exemplesIncorrects":["Elle a filé un mauvais coton à sa couturière pour la robe.","Au marché, j\'ai filé un mauvais coton de très belle qualité."],"distracteurs":["tirer le diable par la queue","prendre la tangente","filer doux"],"anecdote":"L\'expression a d\'abord désigné une conduite qui tourne mal avant de s\'appliquer surtout, dès le XIXe siècle, à la santé déclinante.","categorie":"expression"},{"id":"passer-l-arme-a-gauche","mot":"passer l\'arme à gauche","nature":"locution","definitions":["Mourir, trépasser (registre familier et imagé)."],"phonetique":"/pa.se laʁm a ɡoʃ/","etymologie":"Origine incertaine et débattue, attestée depuis le début du XIXe siècle. Plusieurs hypothèses la rattachent au geste militaire de rechargement du fusil, à la connotation néfaste de la gauche (senestre, sinistre) ou à l\'escrime.","registre":"familier","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["mourir","trépasser","décéder"],"antonymes":["naître","vivre","survivre"],"exemplesCorrects":["Le vieux soldat a passé l\'arme à gauche pendant son sommeil.","On craignait qu\'il ne passe l\'arme à gauche après cette mauvaise chute.","Son chat a fini par passer l\'arme à gauche à l\'âge respectable de vingt ans."],"exemplesIncorrects":["Le sergent a passé l\'arme à gauche de son camarade pour la nettoyer.","À la parade, les fantassins passèrent l\'arme à gauche avec discipline."],"distracteurs":["casser sa croûte","tourner casaque","baisser pavillon"],"anecdote":"L\'euphémisme s\'est imposé dans la langue familière au XIXe siècle pour évoquer la mort sans la nommer crûment ; son origine exacte reste discutée par les linguistes.","categorie":"expression"},{"id":"faire-long-feu","mot":"faire long feu","nature":"locution","definitions":["Échouer, ne pas atteindre son but, manquer son effet."],"phonetique":"/fɛʁ lɔ̃ fø/","etymologie":"Vocabulaire des armes à feu anciennes : une amorce qui brûlait trop lentement « faisait long feu », et le coup ne partait pas ou manquait sa cible — d\'où l\'idée d\'échec.","registre":"soutenu","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["échouer","avorter","tourner court"],"antonymes":["réussir","aboutir","triompher"],"exemplesCorrects":["Le projet de réforme a fait long feu faute de soutien.","Ses ambitions ont fait long feu dès les premières difficultés.","La conspiration fit long feu avant même d\'être mise à exécution."],"exemplesIncorrects":["Leur amitié a fait long feu pendant trente belles années.","Ce moteur fiable n\'a jamais fait long feu et tourne encore.","La mode du vinyle n\'a pas fait long feu : elle dure depuis des décennies."],"distracteurs":["tomber à l\'eau","faire chou blanc","prendre l\'eau"],"anecdote":"Beaucoup confondent « faire long feu » (échouer) avec « ne pas faire long feu » (durer peu) : ce sont deux sens distincts. L\'expression pour « échouer » est bien « faire long feu », sans négation.","categorie":"piege-sens","piege":{"formeFautive":"faire long feu = durer longtemps","explication":"« Faire long feu » signifie échouer, manquer son but, et non pas durer longtemps. Le sens « durer peu » appartient à la forme négative « ne pas faire long feu »."}},{"id":"ne-pas-faire-long-feu","mot":"ne pas faire long feu","nature":"locution","definitions":["Durer peu de temps, ne pas se maintenir longtemps, disparaître rapidement."],"phonetique":"/nə pa fɛʁ lɔ̃ fø/","etymologie":"Forme négative de « faire long feu », issue du vocabulaire des armes anciennes. Le sens s\'est ici spécialisé pour exprimer la brièveté, ce qui ne tient pas dans la durée.","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["ne pas durer","s\'éteindre vite","tourner court"],"antonymes":["perdurer","s\'éterniser","se maintenir"],"exemplesCorrects":["Cette nouvelle mode n\'a pas fait long feu.","Son enthousiasme ne fit pas long feu devant l\'ampleur de la tâche.","Le gâteau n\'a pas fait long feu entre les mains des enfants."],"exemplesIncorrects":["Leur entreprise, florissante, n\'a pas fait long feu et prospère depuis vingt ans.","Le projet n\'a pas fait long feu : il a échoué dès le départ.","Ce vieux chêne n\'a pas fait long feu et trône encore dans le parc."],"distracteurs":["faire des étincelles","battre son plein","tenir le coup"],"anecdote":"La nuance piège bien des locuteurs : « ne pas faire long feu » veut dire durer peu, alors que « faire long feu » (sans négation) veut dire échouer — deux idées qu\'il ne faut pas intervertir.","categorie":"piege-sens","piege":{"formeFautive":"ne pas faire long feu = échouer","explication":"« Ne pas faire long feu » signifie durer peu de temps, et non échouer. C\'est la forme affirmative « faire long feu » qui exprime l\'échec."}},{"id":"battre-froid-a-quelqu-un","mot":"battre froid à quelqu\'un","nature":"locution","definitions":["Manifester de la froideur à l\'égard de quelqu\'un, le traiter avec distance et réserve, lui marquer son indifférence."],"phonetique":"/batʁ fʁwa a kɛl.kœ̃/","etymologie":"De la langue de la métallurgie, où l\'on bat le métal « à chaud » ou « à froid » ; « battre froid » s\'est employé dès le XVIe siècle au sens d\'être d\'un naturel froid, puis de réserver un accueil distant.","registre":"soutenu","niveau":3,"themes":["emotions","quotidien"],"synonymes":["bouder","tenir à distance","snober"],"antonymes":["choyer","faire fête","accueillir chaleureusement"],"exemplesCorrects":["Depuis leur dispute, elle lui bat froid.","Vexé, il se mit à battre froid à toute la famille.","On lui battait froid au bureau depuis sa promotion contestée."],"exemplesIncorrects":["Il a battu froid les œufs pour préparer une omelette.","Le boxeur a battu froid son adversaire au troisième round."],"distracteurs":["tenir tête","faire grise mine","prendre ombrage"],"anecdote":"L\'expression survit surtout dans la langue écrite et soutenue ; à l\'oral, on dira plus volontiers « faire la tête » ou « bouder ».","categorie":"expression"},{"id":"couper-la-poire-en-deux","mot":"couper la poire en deux","nature":"locution","definitions":["Trouver un compromis, partager équitablement la différence entre deux positions ou deux parties."],"phonetique":"/ku.pe la pwaʁ ɑ̃ dø/","etymologie":"Attestée dès 1863 sous la forme « partager la poire en deux », l\'expression est popularisée par un sketch de 1882, La poire en deux, où deux personnages s\'accordent à lire chacun à tour de rôle. L\'image du fruit partagé en deux parts égales symbolise le compromis.","registre":"courant","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["transiger","s\'arranger","trouver un terrain d\'entente"],"antonymes":["intransiger","s\'entêter","camper sur ses positions"],"exemplesCorrects":["Pour clore la négociation, ils ont coupé la poire en deux.","Plutôt que de se disputer le prix, coupons la poire en deux.","Le médiateur a proposé de couper la poire en deux."],"exemplesIncorrects":["Au dessert, elle a coupé la poire en deux pour la manger.","Le jardinier a coupé la poire en deux d\'un coup de sécateur."],"distracteurs":["mettre les bouchées doubles","tirer son épingle du jeu","mettre la charrue avant les bœufs"],"anecdote":"Le sens figuré du compromis a totalement supplanté le geste littéral : on l\'emploie presque toujours pour une négociation, rarement pour un vrai fruit.","categorie":"expression"},{"id":"se-piquer-au-jeu","mot":"se piquer au jeu","nature":"locution","definitions":["Se prendre de passion ou d\'intérêt pour une activité d\'abord entreprise sans conviction ou par hasard ; s\'y investir progressivement."],"phonetique":"/sə pi.ke o ʒø/","etymologie":"De « se piquer », au sens de se prendre d\'émulation ou d\'amour-propre, appliqué au jeu : on s\'échauffe et l\'on s\'attache à ce qui n\'était d\'abord qu\'un divertissement.","registre":"courant","niveau":2,"themes":["emotions","quotidien"],"synonymes":["s\'enthousiasmer","se passionner","s\'emballer"],"antonymes":["se désintéresser","se lasser","se détacher"],"exemplesCorrects":["Il a commencé le dessin par curiosité, puis s\'est piqué au jeu.","Sceptique au départ, elle s\'est vite piquée au jeu de la recherche.","On se pique au jeu et l\'on finit par y consacrer toutes ses soirées."],"exemplesIncorrects":["L\'abeille s\'est piquée au jeu en butinant les fleurs.","Il s\'est piqué au jeu avec une épine en taillant le rosier."],"distracteurs":["se prendre les pieds dans le tapis","tirer les marrons du feu","mettre de l\'eau dans son vin"],"anecdote":"L\'expression vient des jeux d\'argent, où l\'on « se pique » d\'amour-propre en voulant se refaire, avant d\'élargir son sens à toute activité.","categorie":"expression"},{"id":"prendre-la-mouche","mot":"prendre la mouche","nature":"locution","definitions":["Se vexer ou s\'emporter brusquement, sans grand motif ; se froisser pour peu de chose."],"phonetique":"/pʁɑ̃dʁ la muʃ/","etymologie":"L\'image vient de la réaction vive du bétail piqué par une mouche, en particulier le taon : la bête s\'agite soudain comme prise d\'un accès de colère. « Prendre » a ici le sens de subir l\'effet de quelque chose, comme dans « prendre froid ».","registre":"courant","niveau":2,"themes":["emotions","quotidien"],"synonymes":["se vexer","se froisser","s\'emporter"],"antonymes":["garder son calme","prendre du recul","rester impassible"],"exemplesCorrects":["À la moindre remarque, il prend la mouche.","Elle a pris la mouche pour une plaisanterie anodine.","Inutile de prendre la mouche, ce n\'était qu\'une taquinerie."],"exemplesIncorrects":["Le pêcheur a pris la mouche au bout de sa ligne.","La grenouille a pris la mouche d\'un coup de langue."],"distracteurs":["prendre la tangente","prendre langue","tenir rigueur"],"anecdote":"Dès le XVIIe siècle, l\'expression s\'inspire de la réaction du bétail face aux taons, qui le fait s\'agiter brusquement comme sous l\'effet de la colère.","categorie":"expression"},{"id":"menager-la-chevre-et-le-chou","mot":"ménager la chèvre et le chou","nature":"locution","definitions":["Satisfaire ou ménager deux partis opposés sans prendre franchement position ; concilier des intérêts contraires."],"phonetique":"/me.na.ʒe la ʃɛvʁ e lə ʃu/","etymologie":"De la vieille énigme du passeur qui doit faire traverser une rivière à un loup, une chèvre et un chou sans que l\'un dévore l\'autre : il faut tout ménager pour éviter les dégâts.","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["temporiser","concilier","louvoyer"],"antonymes":["trancher","prendre parti","choisir son camp"],"exemplesCorrects":["En politique, il faut souvent ménager la chèvre et le chou.","Pour ne fâcher personne, elle ménage la chèvre et le chou.","Le diplomate excelle à ménager la chèvre et le chou entre les deux camps."],"exemplesIncorrects":["Le berger a ménagé la chèvre et le chou dans son potager.","Au marché, j\'ai acheté une chèvre et un chou bien frais."],"distracteurs":["mettre les pieds dans le plat","prêcher le faux pour savoir le vrai","jeter de l\'huile sur le feu"],"anecdote":"L\'expression remonte à une devinette médiévale de passage de rivière, où il fallait protéger à la fois la chèvre (qui mange le chou) et le chou.","categorie":"expression"},{"id":"avoir-voix-au-chapitre","mot":"avoir voix au chapitre","nature":"locution","definitions":["Avoir le droit de donner son avis et de participer à une décision ; avoir de l\'autorité ou de l\'influence dans une affaire."],"phonetique":"/a.vwaʁ vwa o ʃa.pitʁ/","etymologie":"Le « chapitre » désignait l\'assemblée des chanoines ou des moines réunis pour traiter des affaires de leur communauté ; y « avoir voix » signifiait avoir le droit d\'y voter et d\'y délibérer.","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["avoir son mot à dire","peser dans la décision","compter"],"antonymes":["être tenu à l\'écart","n\'avoir aucune influence","subir"],"exemplesCorrects":["Sur ce dossier, les riverains ont enfin voix au chapitre.","En tant qu\'actionnaire minoritaire, il a tout de même voix au chapitre.","Les jeunes réclament d\'avoir voix au chapitre dans les décisions du quartier."],"exemplesIncorrects":["Le chanteur a une belle voix au chapitre des refrains.","J\'ai lu à voix au chapitre trois de ce roman passionnant."],"distracteurs":["avoir le dernier mot","tenir le haut du pavé","avoir maille à partir"],"anecdote":"Les chanoines revendiquaient « stallum in choro et vocem in capitulo » : un siège au chœur et une voix au chapitre, c\'est-à-dire le droit de délibérer.","categorie":"expression"},{"id":"rompre-une-lance","mot":"rompre une lance","nature":"locution","definitions":["Engager une discussion contradictoire, intervenir avec énergie en faveur d\'une personne ou d\'une cause ; s\'employer surtout à la forme « rompre une lance (ou des lances) pour quelqu\'un »."],"phonetique":"/ʁɔ̃.pʁ‿yn lɑ̃s/","etymologie":"Métaphore issue des tournois médiévaux, où les chevaliers brisaient leur lance en chargeant un adversaire ; combattre pour une cause comme on jouterait pour elle.","registre":"soutenu","niveau":3,"themes":["litteraire","abstrait"],"synonymes":["plaider","ferrailler","batailler"],"antonymes":["se désintéresser","abandonner","se taire"],"exemplesCorrects":["Il a rompu une lance en faveur des étudiants menacés d\'exclusion.","Devant le tribunal, l\'avocate rompit des lances pour son client.","Je ne romprai pas une lance pour défendre une thèse à laquelle je ne crois pas."],"exemplesIncorrects":["Il a rompu une lance le manche de son outil contre le mur.","La tempête a rompu une lance toutes les branches du chêne."],"distracteurs":["ployer","fourbir","harnacher"],"anecdote":"L\'image vient des joutes où une lance brisée sur l\'adversaire valait des points : on se « rompait » donc pour défendre son camp.","categorie":"expression"},{"id":"envoyer-paitre","mot":"envoyer paître","nature":"locution","definitions":["Éconduire quelqu\'un sèchement, le rabrouer, se débarrasser de lui avec brusquerie."],"phonetique":"/ɑ̃.vwa.je pɛtʁ/","etymologie":"De paître, « brouter de l\'herbe », du latin pascere ; envoyer quelqu\'un « paître » revient à le renvoyer aux champs comme un animal, loin de soi.","registre":"familier","niveau":2,"themes":["quotidien","emotions"],"synonymes":["rabrouer","éconduire","rembarrer"],"antonymes":["accueillir","écouter","amadouer"],"exemplesCorrects":["Lassé de ses sollicitations, il l\'a envoyé paître sans ménagement.","Quand le démarcheur a insisté, elle l\'a envoyé paître.","Plutôt que de discuter, le patron nous a envoyés paître."],"exemplesIncorrects":["Le berger envoie paître ses moutons dans le pré chaque matin.","Nous avons envoyé paître les vaches avant l\'orage."],"distracteurs":["amadouer","héberger","convoquer"],"anecdote":"On trouve de nombreuses variantes pastorales du même renvoi cavalier : envoyer « promener », « sur les roses » ou « au diable ».","categorie":"expression"},{"id":"faire-des-gorges-chaudes","mot":"faire des gorges chaudes","nature":"locution","definitions":["Se moquer ouvertement et avec malignité de quelqu\'un ou de quelque chose, en faire le sujet de plaisanteries malveillantes."],"phonetique":"/fɛʁ de ɡɔʁʒ ʃod/","etymologie":"Terme de fauconnerie : la « gorge chaude » était la viande encore tiède donnée en pâture aux oiseaux de proie ; « faire gorge chaude de » a d\'abord signifié « dévorer », puis « se gausser de ».","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["railler","se gausser","persifler"],"antonymes":["respecter","louer","ménager"],"exemplesCorrects":["La presse a fait des gorges chaudes de cette gaffe ministérielle.","On a longtemps fait des gorges chaudes de ses prédictions ratées.","Ne crains pas qu\'on fasse des gorges chaudes de ta maladresse."],"exemplesIncorrects":["Après la course, il avait des gorges chaudes et toussait beaucoup.","Le bouillon brûlant lui a fait des gorges chaudes."],"distracteurs":["encenser","déplorer","fustiger"],"anecdote":"La « gorge chaude » désignait chez les fauconniers la proie fraîche servie tiède au rapace ; de là le sens de festin moqueur fait aux dépens d\'autrui.","categorie":"expression"},{"id":"tailler-une-bavette","mot":"tailler une bavette","nature":"locution","definitions":["Bavarder familièrement, faire un brin de causette."],"phonetique":"/ta.je yn ba.vɛt/","etymologie":"Jeu sur bavette, dérivé de baver (« parler à tort et à travers ») ; on « taille » la bavette comme un tailleur découpe le tissu, l\'image associant le bavardage à un ouvrage de couture.","registre":"familier","niveau":2,"themes":["quotidien"],"synonymes":["bavarder","papoter","deviser"],"antonymes":["se taire","écourter","se quitter"],"exemplesCorrects":["Les voisines taillent une bavette sur le pas de la porte.","Nous avons taillé une bavette pendant toute la pause.","Il s\'est arrêté pour tailler une bavette avec le boulanger."],"exemplesIncorrects":["Le boucher a taillé une bavette dans le morceau de bœuf.","Elle a taillé une bavette de tissu pour le bébé."],"distracteurs":["déambuler","ronchonner","patienter"],"anecdote":"La bavette, ce bavoir d\'enfant, a donné par jeu de mots l\'idée d\'une conversation « bavée » sans fin, sans rapport avec la pièce de viande du même nom.","categorie":"expression"},{"id":"manger-son-ble-en-herbe","mot":"manger son blé en herbe","nature":"locution","definitions":["Dépenser par avance et imprudemment son revenu ou son capital, dilapider ses ressources avant de les avoir effectivement perçues."],"phonetique":"/mɑ̃.ʒe sɔ̃ ble ɑ̃n‿ɛʁb/","etymologie":"Image agricole attestée chez Rabelais (Tiers Livre, 1546) : consommer le blé encore en herbe, c\'est-à-dire avant sa maturité, donc le détruire avant qu\'il ne rapporte.","registre":"soutenu","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["dilapider","gaspiller","dissiper"],"antonymes":["épargner","thésauriser","économiser"],"exemplesCorrects":["À force de tout dépenser d\'avance, il a mangé son blé en herbe.","L\'héritier mangeait son blé en herbe bien avant la succession.","Vivre à crédit, c\'est manger son blé en herbe."],"exemplesIncorrects":["Le cheval a mangé son blé en herbe dans le champ voisin.","Au printemps, les vaches mangent leur blé en herbe sans prendre de poids."],"distracteurs":["amasser","capitaliser","rentabiliser"],"anecdote":"Le blé n\'a de valeur qu\'à maturité ; le couper en herbe revient à anéantir une récolte future, d\'où l\'idée d\'une dépense ruineuse et prématurée.","categorie":"expression"},{"id":"tenir-la-dragee-haute","mot":"tenir la dragée haute","nature":"locution","definitions":["Faire attendre ou payer cher à quelqu\'un ce qu\'il désire ; lui tenir tête en lui faisant sentir sa dépendance ou son pouvoir."],"phonetique":"/tə.niʁ la dʁa.ʒe ot/","etymologie":"Apparue au XVIIIe siècle, l\'image renvoie à un jeu où l\'on suspendait une dragée à un fil et où celui qui tenait le fil l\'élevait pour empêcher les enfants de l\'attraper trop aisément.","registre":"soutenu","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["dominer","résister","tenir tête"],"antonymes":["céder","capituler","fléchir"],"exemplesCorrects":["Le vendeur lui tenait la dragée haute sur le prix.","L\'équipe modeste a tenu la dragée haute au champion en titre.","Elle sait tenir la dragée haute à ses concurrents."],"exemplesIncorrects":["Il a tenu la dragée haute sur l\'étagère pour la décorer.","Le pâtissier tient la dragée haute dans sa vitrine de Pâques."],"distracteurs":["concéder","tergiverser","amadouer"],"anecdote":"La « dragée » du jeu n\'a rien d\'un projectile : c\'est la friandise suspendue, tenue haut exprès pour faire languir celui qui la convoite.","categorie":"expression"},{"id":"avoir-des-oursins-dans-la-poche","mot":"avoir des oursins dans la poche","nature":"locution","definitions":["Être avare, rechigner à dépenser ou à sortir son argent."],"phonetique":"/a.vwaʁ de.z‿uʁ.sɛ̃ dɑ̃ la pɔʃ/","etymologie":"Image plaisante du XXe siècle : porter des oursins, hérissés de piquants, au fond de sa poche dissuaderait d\'y plonger la main pour en tirer de la monnaie.","registre":"familier","niveau":3,"themes":["quotidien","emotions"],"synonymes":["lésiner","économiser sordidement","être pingre"],"antonymes":["dépenser","être prodigue","être généreux"],"exemplesCorrects":["Il n\'a jamais payé sa tournée : il a des oursins dans la poche.","Avec des oursins dans la poche, il chipote sur le moindre pourboire.","On dit d\'un radin qu\'il a des oursins dans la poche."],"exemplesIncorrects":["En revenant de la plage, il avait des oursins dans la poche de son maillot.","Le pêcheur avait des oursins dans la poche pour les vendre au marché."],"distracteurs":["bredouiller","tâtonner","gribouiller"],"anecdote":"On dit aussi, dans le même esprit, avoir « des oursins dans le porte-monnaie » : l\'idée est qu\'on se piquerait à vouloir en sortir un sou.","categorie":"expression"},{"id":"se-mettre-martel-en-tete","mot":"se mettre martel en tête","nature":"locution","definitions":["Se tourmenter, se faire du souci, se laisser ronger par une préoccupation."],"phonetique":"/sə mɛtʁ maʁ.tɛl ɑ̃ tɛt/","etymologie":"Martel est l\'ancienne forme de marteau, rapprochée de l\'italien martello (« marteau », puis « jalousie, souci ») ; dès le XVIe siècle, « avoir martel » signifiait « avoir du tourment », les soucis frappant la tête comme des coups de marteau.","registre":"soutenu","niveau":3,"themes":["emotions","abstrait"],"synonymes":["s\'inquiéter","se tourmenter","se ronger"],"antonymes":["se rassurer","se tranquilliser","se détendre"],"exemplesCorrects":["Ne te mets pas martel en tête pour un simple retard.","Elle s\'est mis martel en tête à cause d\'une remarque anodine.","Inutile de se mettre martel en tête avant les résultats."],"exemplesIncorrects":["Il s\'est mis martel en tête pour planter le clou dans le mur.","Le forgeron se met martel en tête à l\'enclume chaque matin."],"distracteurs":["s\'enorgueillir","s\'esclaffer","s\'attendrir"],"anecdote":"L\'expression ne doit rien à Charles Martel : le « martel » est ici un petit marteau dont les coups figurent les soucis qui martèlent l\'esprit.","categorie":"expression"},{"id":"broyer-du-noir","mot":"broyer du noir","nature":"locution","definitions":["Être en proie à des idées sombres, à la mélancolie ; se laisser aller au pessimisme et à la tristesse."],"phonetique":"/bʁwa.je dy nwaʁ/","etymologie":"Image empruntée au métier de peintre, où l\'on broyait jadis les pigments : ressasser des pensées noires reviendrait à moudre sans cesse cette couleur sombre. La « noire humeur » était associée à la mélancolie depuis la théorie des humeurs.","registre":"courant","niveau":2,"themes":["emotions","abstrait"],"synonymes":["déprimer","se morfondre","ruminer"],"antonymes":["se réjouir","s\'égayer","rayonner"],"exemplesCorrects":["Depuis son départ, il broie du noir à longueur de journée.","Ne reste pas seul à broyer du noir, sors prendre l\'air.","L\'automne pluvieux la pousse à broyer du noir."],"exemplesIncorrects":["L\'artiste broie du noir pour préparer sa peinture à l\'huile.","Le moulin broie du noir avant de moudre le grain."],"distracteurs":["jubiler","fulminer","s\'extasier"],"anecdote":"La mélancolie tenait son nom du grec melas (« noir ») et kholê (« bile ») : « broyer du noir », c\'est encore moudre cette vieille bile noire des Anciens.","categorie":"expression"},{"id":"prendre-des-vessies-pour-des-lanternes","mot":"prendre des vessies pour des lanternes","nature":"locution","definitions":["Se tromper grossièrement, se laisser abuser, confondre une chose avec une autre toute différente."],"phonetique":"/pʁɑ̃dʁ de ve.si puʁ de lɑ̃.tɛʁn/","etymologie":"Une vessie d\'animal séchée, gonflée et translucide pouvait jadis servir de lampion ; confondre cette vessie avec une véritable lanterne, c\'est se méprendre du tout au tout. La locution est attestée dès le XIIIe siècle.","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["se méprendre","s\'illusionner","se fourvoyer"],"antonymes":["discerner","comprendre","voir clair"],"exemplesCorrects":["Avec ses promesses creuses, il nous fait prendre des vessies pour des lanternes.","Ne te laisse pas berner, tu prends des vessies pour des lanternes.","Le bonimenteur excelle à faire prendre des vessies pour des lanternes."],"exemplesIncorrects":["Au marché, il a pris des vessies pour des lanternes afin d\'éclairer l\'étal.","Le boucher prend des vessies pour des lanternes et les accroche à sa devanture."],"distracteurs":["entrevoir","soupçonner","deviner"],"anecdote":"On gonflait autrefois des vessies pour en faire des lampions de fortune ; les confondre avec de vraies lanternes est le type même de la bévue énorme.","categorie":"expression"},{"id":"donner-sa-langue-au-chat","mot":"donner sa langue au chat","nature":"locution","definitions":["Renoncer à deviner ou à trouver la solution d\'une énigme, avouer qu\'on ne sait pas la réponse."],"phonetique":"/dɔ.ne sa lɑ̃ɡ o ʃa/","etymologie":"Évolution de l\'ancienne tournure « jeter sa langue aux chiens » (y renoncer comme on jette un reste sans valeur), adoucie au XIXe siècle en « donner sa langue au chat », confident discret à qui l\'on confie son ignorance.","registre":"courant","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["renoncer","abandonner","capituler"],"antonymes":["deviner","trouver","persévérer"],"exemplesCorrects":["Après cinq essais, j\'ai donné ma langue au chat.","Tu donnes déjà ta langue au chat ? La devinette était facile.","Devant cette énigme, tous ont fini par donner leur langue au chat."],"exemplesIncorrects":["Le vétérinaire a donné sa langue au chat malade pour l\'examiner.","Elle a donné sa langue au chat de la voisine pour qu\'il joue avec."],"distracteurs":["persévérer","élucider","trancher"],"anecdote":"On ne « donne » sa langue au chat que parce qu\'on l\'a d\'abord « jetée aux chiens » : la version féline, plus tendre, l\'a emporté au XIXe siècle.","categorie":"expression"},{"id":"etre-a-cheval-sur-les-principes","mot":"être à cheval sur les principes","nature":"locution","definitions":["Tenir rigoureusement aux règles, à la discipline ou aux convenances, sans tolérer le moindre écart."],"phonetique":"/ɛtʁ‿a ʃə.val syʁ le pʁɛ̃.sip/","etymologie":"De « être à cheval sur », qui signifie au propre « se tenir fermement en selle », d\'où, au figuré, « se maintenir avec rigueur sur » un point qu\'on n\'abandonne pas plus qu\'un cavalier ne quitte sa monture.","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["intransigeant","rigoriste","pointilleux"],"antonymes":["laxiste","accommodant","indulgent"],"exemplesCorrects":["Le directeur est à cheval sur les principes de ponctualité.","Très à cheval sur les principes, elle ne tolère aucune entorse au règlement.","Mon grand-père était à cheval sur les principes de politesse."],"exemplesIncorrects":["Le cavalier est à cheval sur les principes au milieu de la carrière.","Il est à cheval sur les principes pour franchir l\'obstacle au galop."],"distracteurs":["conciliant","désinvolte","permissif"],"anecdote":"L\'image n\'a rien d\'équestre au figuré : on est « à cheval sur » un principe comme on enfourche une selle, c\'est-à-dire en s\'y cramponnant fermement.","categorie":"expression"},{"id":"avoir-le-compas-dans-l-oeil","mot":"avoir le compas dans l\'œil","nature":"locution","definitions":["Savoir apprécier une mesure, une distance ou une proportion avec exactitude, à la simple vue, sans instrument."],"phonetique":"/a.vwaʁ lə kɔ̃.pa dɑ̃ l‿œj/","etymologie":"Image empruntée au compas de l\'artisan et de l\'architecte : l\'œil exercé remplace l\'instrument de mesure pour juger les proportions.","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["avoir l\'œil juste","avoir le coup d\'œil"],"antonymes":[],"exemplesCorrects":["Le menuisier a le compas dans l\'œil : il coupe ses planches à la bonne longueur sans même les mesurer.","Inutile de sortir le mètre, ma grand-mère avait le compas dans l\'œil pour ses ourlets.","Ce chef de chantier a le compas dans l\'œil et repère au premier regard un mur qui n\'est pas d\'aplomb."],"exemplesIncorrects":["Il a le compas dans l\'œil depuis qu\'il porte des lunettes correctrices.","Le médecin lui a retiré le compas dans l\'œil après l\'opération."],"distracteurs":["avoir le bras long","avoir la main verte","avoir le pied marin"],"anecdote":"On attribue l\'origine de cette expression à Michel-Ange, dont on disait qu\'il jugeait les proportions de ses sculptures « avec un compas dans l\'œil », tant son regard suffisait à mesurer juste.","categorie":"expression"},{"id":"se-fendre-la-pipe","mot":"se fendre la pipe","nature":"locution","definitions":["Rire franchement, de bon cœur ; beaucoup s\'amuser."],"phonetique":"/sə fɑ̃dʁ la pip/","etymologie":"Du français familier où « pipe » désigne, par plaisanterie, la figure ou le visage ; rire à pleine bouche reviendrait à « se fendre » la figure.","registre":"familier","niveau":2,"themes":["emotions","quotidien"],"synonymes":["se marrer","se bidonner","se gondoler"],"antonymes":["s\'attrister","pleurer","s\'ennuyer"],"exemplesCorrects":["On s\'est fendu la pipe toute la soirée devant ce vieux film comique.","Ses imitations sont si réussies qu\'on se fend la pipe à chaque fois.","Les enfants se fendaient la pipe en regardant les pitreries du clown."],"exemplesIncorrects":["Il s\'est fendu la pipe en tombant dans l\'escalier et a dû voir un médecin.","Le fumeur s\'est fendu la pipe en la faisant tomber sur le carrelage."],"distracteurs":["se serrer la ceinture","se mettre la rate au court-bouillon","se monter le bourrichon"],"anecdote":"L\'expression cohabite avec « se fendre la poire » et « se fendre la gueule », toutes nées de la même idée : rire si fort qu\'on s\'en ouvre le visage.","categorie":"expression"},{"id":"rouler-quelqu-un-dans-la-farine","mot":"rouler quelqu\'un dans la farine","nature":"locution","definitions":["Tromper, duper habilement quelqu\'un, l\'abuser par la ruse."],"phonetique":"/ʁu.le kɛl.k‿œ̃ dɑ̃ la fa.ʁin/","etymologie":"Combinaison de « rouler quelqu\'un » (le tromper, attesté au XIXᵉ siècle) et de la farine : dès le XVIᵉ siècle, « enfariner » désignait le bouffon qui se poudrait le visage pour tromper son monde.","registre":"familier","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["duper","berner","embobiner"],"antonymes":["détromper","éclairer","être franc"],"exemplesCorrects":["Le vendeur l\'a roulé dans la farine en lui cédant une voiture trafiquée.","Ne te laisse pas rouler dans la farine par ses belles promesses.","Ils se sont fait rouler dans la farine et ont signé un contrat désavantageux."],"exemplesIncorrects":["La cuisinière a roulé le poisson dans la farine avant de le frire.","Il a roulé le boudin dans la farine pour la recette de sa grand-mère."],"distracteurs":["mettre les pieds dans le plat","mener en bateau","faire chou blanc"],"anecdote":"Au XVIᵉ siècle, « enfariner » son visage, c\'était le poudrer comme un comédien grimé en pierrot : on déguisait ses traits comme on déguise la vérité au gogo qu\'on dupe.","categorie":"expression"},{"id":"mettre-la-charrue-avant-les-boeufs","mot":"mettre la charrue avant les bœufs","nature":"locution","definitions":["Faire les choses dans le mauvais ordre ; commencer par où l\'on devrait finir."],"phonetique":"/mɛtʁ la ʃa.ʁy a.vɑ̃ le bø/","etymologie":"Image agricole : atteler la charrue devant les bœufs au lieu de la faire tirer par eux est une absurdité qui empêche tout labour.","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["intervertir l\'ordre","anticiper à tort"],"antonymes":["procéder méthodiquement","respecter l\'ordre"],"exemplesCorrects":["Acheter les meubles avant d\'avoir signé pour l\'appartement, c\'est mettre la charrue avant les bœufs.","Tu mets la charrue avant les bœufs : il faut d\'abord apprendre les bases avant de te lancer.","Annoncer le mariage sans avoir fait sa demande, c\'était mettre la charrue avant les bœufs."],"exemplesIncorrects":["Le paysan a mis la charrue avant les bœufs pour gagner du temps au labour.","Il a mis la charrue avant les bœufs dans la grange pour l\'hiver."],"distracteurs":["mettre de l\'eau dans son vin","mettre les bouchées doubles","tirer le diable par la queue"],"anecdote":"Rabelais s\'amuse déjà de cette absurdité au XVIᵉ siècle : dans l\'enfance de Gargantua, son héros « mettoyt la charrette devant les bœufz » parmi mille autres incohérences.","categorie":"expression"},{"id":"noyer-le-poisson","mot":"noyer le poisson","nature":"locution","definitions":["Embrouiller volontairement une affaire pour esquiver une question ou détourner l\'attention ; créer la confusion afin de ne pas répondre."],"phonetique":"/nwa.je lə pwa.sɔ̃/","etymologie":"Issu du vocabulaire de la pêche à la ligne : on « noie » le poisson en le fatiguant par allers-retours dans l\'eau pour qu\'il cesse de résister avant d\'être sorti.","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["embrouiller","esquiver","détourner l\'attention"],"antonymes":["clarifier","répondre franchement","trancher"],"exemplesCorrects":["Interrogé sur le budget, le ministre a noyé le poisson en multipliant les digressions.","Arrête de noyer le poisson et dis-moi simplement ce qui s\'est passé.","Chaque fois qu\'on aborde le sujet, il noie le poisson pour éviter de s\'engager."],"exemplesIncorrects":["Le pêcheur a noyé le poisson dans le seau avant de rentrer.","Elle a noyé le poisson dans la sauce pour parfumer son plat."],"distracteurs":["ménager la chèvre et le chou","couper la poire en deux","jeter l\'éponge"],"anecdote":"À la pêche, « noyer le poisson » est une technique réelle : en le promenant dans l\'eau, on l\'épuise et on le prive d\'oxygène, d\'où l\'idée d\'épuiser l\'interlocuteur jusqu\'à lui faire perdre le fil.","categorie":"expression"},{"id":"lever-un-lievre","mot":"lever un lièvre","nature":"locution","definitions":["Mettre au jour, le premier, une difficulté inattendue ou une question embarrassante qu\'on n\'avait pas vue venir."],"phonetique":"/lə.ve œ̃ ljɛvʁ/","etymologie":"Du langage de la chasse : « lever » un lièvre, c\'est le faire débusquer de son gîte pour qu\'il déboule à découvert.","registre":"soutenu","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["soulever un problème","débusquer","révéler"],"antonymes":["dissimuler","étouffer","passer sous silence"],"exemplesCorrects":["En vérifiant les comptes, l\'auditeur a levé un lièvre que personne n\'avait remarqué.","Sa question, anodine en apparence, a levé un lièvre embarrassant pour la direction.","Le journaliste a levé un lièvre en exhumant ce vieux contrat oublié."],"exemplesIncorrects":["Le chasseur a levé un lièvre et l\'a rapporté pour le dîner.","Il a levé un lièvre du fossé en marchant dans les champs."],"distracteurs":["enterrer la hache de guerre","prendre le taureau par les cornes","tirer son épingle du jeu"],"anecdote":"La locution latine « hic jacet lepus » (« ici gît le lièvre ») exprimait déjà la même idée : c\'est là que se cache le problème, là qu\'il faut chercher.","categorie":"expression"},{"id":"battre-sa-coulpe","mot":"battre sa coulpe","nature":"locution","definitions":["Reconnaître publiquement ses torts, s\'avouer fautif et s\'en repentir avec contrition."],"phonetique":"/batʁ sa kulp/","etymologie":"Du latin liturgique culpa (faute) : pendant le Confiteor, le fidèle se frappait la poitrine en disant « mea culpa », geste dit « battre sa coulpe ».","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["se repentir","faire son mea-culpa","s\'amender"],"antonymes":["se justifier","persister","se disculper"],"exemplesCorrects":["Après l\'échec du projet, le directeur a battu sa coulpe devant ses équipes.","Plutôt que de battre sa coulpe, il a préféré rejeter la faute sur les autres.","Elle bat sa coulpe d\'avoir douté de lui sans raison."],"exemplesIncorrects":["Il a battu sa coulpe contre le mur jusqu\'à la fissurer.","Le boxeur a battu sa coulpe au troisième round du combat."],"distracteurs":["prêcher dans le désert","donner sa langue au chat","retourner sa veste"],"anecdote":"« Coulpe » vient directement du latin culpa, qu\'on retrouve dans la formule « mea culpa, mea maxima culpa » : battre sa coulpe, c\'est en faire le geste, paume frappant la poitrine.","categorie":"expression"},{"id":"avoir-maille-a-partir","mot":"avoir maille à partir","nature":"locution","definitions":["Avoir un différend, une querelle ou des démêlés avec quelqu\'un."],"phonetique":"/a.vwaʁ maj a paʁ.tiʁ/","etymologie":"La « maille » était au Moyen Âge la plus petite monnaie, valant un demi-denier ; « partir » signifiait alors « partager ». Se disputer le partage d\'une pièce indivisible, c\'était avoir matière à querelle.","registre":"soutenu","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["avoir des démêlés","se quereller","être en conflit"],"antonymes":["s\'entendre","s\'accorder","fraterniser"],"exemplesCorrects":["Il a eu maille à partir avec son voisin au sujet de la mitoyenneté du mur.","Cette entreprise a eu maille à partir avec le fisc.","Mieux vaut ne pas avoir maille à partir avec un homme aussi rancunier."],"exemplesIncorrects":["Elle a réparé la maille à partir du bas de son pull en laine.","La couturière a repris une maille à partir du col."],"distracteurs":["avoir voix au chapitre","avoir le cœur sur la main","avoir un fil à la patte"],"anecdote":"Beaucoup croient que la « maille » désigne ici une maille de tricot et que « partir » signifie « s\'en aller ». En réalité, c\'est une vieille pièce de monnaie, et « partir » garde son sens médiéval de « partager » : la querelle naît du partage impossible d\'une piécette.","piege":{"formeFautive":"comprendre « maille » comme une maille de tricot et « partir » au sens de « s\'en aller »","explication":"La « maille » est une ancienne monnaie (un demi-denier) et « partir » signifie ici « partager », non « s\'en aller ». L\'expression évoque le partage litigieux d\'une piécette, donc un différend."},"categorie":"piege-sens"},{"id":"tenir-le-crachoir","mot":"tenir le crachoir","nature":"locution","definitions":["Monopoliser la parole, parler longuement et seul, sans laisser les autres s\'exprimer ; pérorer."],"phonetique":"/tə.niʁ lə kʁa.ʃwaʁ/","etymologie":"Du crachoir, récipient où l\'on crachait : « cracher » a pris dès le XVᵉ siècle le sens de « parler », et tenir le crachoir, c\'est garder pour soi la parole en parlant sans cesse.","registre":"familier","niveau":3,"themes":["quotidien","abstrait"],"synonymes":["pérorer","monopoliser la parole","discourir"],"antonymes":["écouter","se taire","laisser parler"],"exemplesCorrects":["À chaque dîner, l\'oncle tient le crachoir et personne ne peut placer un mot.","Elle a tenu le crachoir pendant deux heures sans reprendre son souffle.","Difficile de tenir le crachoir face à un auditoire aussi distrait."],"exemplesIncorrects":["Le dentiste lui a demandé de tenir le crachoir pendant le soin.","Il a tenu le crachoir près du lavabo pour ne pas tacher le sol."],"distracteurs":["tenir la jambe","tenir le haut du pavé","tenir la chandelle"],"anecdote":"L\'expression « tenir le crachoir à quelqu\'un » a d\'abord signifié l\'inverse : lui donner la réplique, l\'écouter complaisamment ; le sens s\'est ensuite renversé vers celui qui accapare la parole.","categorie":"expression"},{"id":"ne-pas-y-aller-de-main-morte","mot":"ne pas y aller de main morte","nature":"locution","definitions":["Agir avec vigueur et sans ménagement ; frapper fort, au propre comme au figuré, sans retenue."],"phonetique":"/nə pa z‿i a.le də mɛ̃ mɔʁt/","etymologie":"Par opposition à la « main morte », molle et sans force : ne pas y aller de main morte, c\'est frapper d\'une main bien vivante, donc avec énergie.","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["frapper fort","ne pas se ménager","y aller franchement"],"antonymes":["y aller mollement","ménager","se retenir"],"exemplesCorrects":["La critique n\'y est pas allée de main morte avec ce premier roman.","Pour assaisonner son plat, il n\'y va pas de main morte sur le poivre.","L\'arbitre n\'y est pas allé de main morte : trois cartons rouges en une mi-temps."],"exemplesIncorrects":["Il n\'y est pas allé de main morte et a posé délicatement le vase.","Elle n\'y est pas allée de main morte en murmurant tout doucement à son oreille."],"distracteurs":["faire la sourde oreille","prendre des gants","filer doux"],"anecdote":"La « mainmorte » désignait au Moyen Âge le droit du seigneur sur les biens d\'un serf défunt ; l\'expression imagée, elle, joue plutôt sur l\'idée d\'une main inerte, sans vigueur, par opposition au geste énergique.","categorie":"expression"},{"id":"se-regarder-le-nombril","mot":"se regarder le nombril","nature":"locution","definitions":["Se complaire dans l\'égocentrisme ; n\'avoir d\'intérêt que pour soi-même, se croire le centre du monde."],"phonetique":"/sə ʁə.ɡaʁ.de lə nɔ̃.bʁil/","etymologie":"Image renvoyant à l\'omphalos, le « nombril du monde » de Delphes, point que les Anciens croyaient être le centre de la terre ; se regarder le nombril, c\'est se prendre pour ce centre.","registre":"courant","niveau":2,"themes":["abstrait","emotions"],"synonymes":["se contempler","s\'admirer","faire son nombril du monde"],"antonymes":["s\'ouvrir aux autres","se décentrer","s\'effacer"],"exemplesCorrects":["Au lieu de se regarder le nombril, ce parti ferait mieux d\'écouter les électeurs.","Cet écrivain ne cesse de se regarder le nombril dans ses romans autobiographiques.","Arrête de te regarder le nombril et intéresse-toi un peu aux autres."],"exemplesIncorrects":["Le médecin lui a demandé de se regarder le nombril pour vérifier la cicatrice.","Elle s\'est regardé le nombril pour retirer l\'écharde qui s\'y était plantée."],"distracteurs":["se serrer les coudes","se mordre les doigts","se faire des cheveux"],"anecdote":"Les moines hésychastes du mont Athos, qui méditaient le regard fixé sur leur nombril, furent raillés sous le nom d\'« omphalopsyques » : l\'expression moderne en garde l\'ironie, mais vise le nombrilisme plutôt que la prière.","categorie":"expression"},{"id":"passer-du-coq-a-l-ane","mot":"passer du coq à l\'âne","nature":"locution","definitions":["Changer brusquement de sujet de conversation, sans transition ni lien logique."],"phonetique":"/pɑ.se dy kɔk a l‿ɑn/","etymologie":"Expression attestée dès le Moyen Âge sous la forme « saillir du coq en l\'âne ». « Âne » serait une altération de « ane », ancien nom de la cane (femelle du canard) : le coq passant indûment d\'une espèce à une autre illustrait le coq-à-l\'âne, le propos décousu.","registre":"courant","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["digresser","divaguer"],"antonymes":["enchaîner","suivre un fil"],"exemplesCorrects":["En pleine réunion, il passa du coq à l\'âne et personne ne suivait plus son raisonnement.","Tu passes du coq à l\'âne : on parlait du budget, et te voilà sur tes vacances.","Sa lettre, écrite à la hâte, passait du coq à l\'âne d\'un paragraphe à l\'autre."],"exemplesIncorrects":["Il a passé du coq à l\'âne son discours pour mieux conclure.","Nous avons passé du coq à l\'âne la rivière à pied sec."],"distracteurs":["bifurquer","ânonner","caqueter"],"anecdote":"L\'expression a donné le substantif « un coq-à-l\'âne », qui désigne un propos sans suite ; Clément Marot a même composé au XVIe siècle des poèmes satiriques appelés « coq-à-l\'âne ».","categorie":"expression"},{"id":"mettre-de-l-eau-dans-son-vin","mot":"mettre de l\'eau dans son vin","nature":"locution","definitions":["Modérer ses prétentions, ses exigences ou ses ardeurs ; devenir plus conciliant, faire des concessions."],"phonetique":"/mɛtʁ də l‿o dɑ̃ sɔ̃ vɛ̃/","etymologie":"Expression formée par image : couper son vin d\'eau l\'adoucit et en atténue la force. Au sens figuré, attestée dès le XVIe siècle, elle signifie tempérer ses emportements ou rabattre de ses prétentions.","registre":"courant","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["transiger","modérer","s\'assagir"],"antonymes":["s\'entêter","camper sur ses positions","intransiger"],"exemplesCorrects":["Après des mois de conflit, les deux camps ont enfin mis de l\'eau dans leur vin.","Il a dû mettre de l\'eau dans son vin pour conserver son emploi.","Avec l\'âge, elle a mis de l\'eau dans son vin et discute désormais sans s\'emporter."],"exemplesIncorrects":["Le sommelier a mis de l\'eau dans son vin pour le servir frais.","J\'ai mis de l\'eau dans mon vin avant de le faire vieillir en cave."],"distracteurs":["capituler","atermoyer","ratiociner"],"anecdote":"L\'image renvoie à une pratique réelle ancienne : dans l\'Antiquité gréco-romaine, on jugeait barbare de boire le vin pur, et on le coupait systématiquement d\'eau.","categorie":"expression"},{"id":"se-mettre-a-dos-quelqu-un","mot":"se mettre à dos quelqu\'un","nature":"locution","definitions":["S\'attirer l\'hostilité, l\'inimitié ou la rancune de quelqu\'un ; transformer une personne en adversaire."],"phonetique":"/sə mɛtʁ a do kɛl.k‿œ̃/","etymologie":"De « dos », le tournant le dos évoquant la rupture et l\'inimitié. Avoir quelqu\'un « à dos », c\'est l\'avoir contre soi, dans son dos, prêt à nuire ; la locution est attestée dès l\'époque classique.","registre":"courant","niveau":2,"themes":["quotidien","abstrait","emotions"],"synonymes":["s\'aliéner","indisposer","se brouiller avec"],"antonymes":["se concilier","s\'attacher","amadouer"],"exemplesCorrects":["En critiquant ouvertement la direction, il s\'est mis à dos toute la hiérarchie.","Ne te mets pas à dos tes voisins pour une histoire de clôture.","Elle s\'est mis à dos la moitié du conseil par ses remarques cinglantes."],"exemplesIncorrects":["Il a porté son sac à dos quelqu\'un de plus fort que lui.","Nous nous sommes mis à dos contre le mur pour nous reposer."],"distracteurs":["froisser","exaspérer","amadouer"],"anecdote":"La locution voisine « avoir le dos au mur » joue aussi sur le dos comme métaphore de la vulnérabilité, mais avec un sens tout différent, celui d\'être acculé.","categorie":"expression"},{"id":"precher-pour-sa-paroisse","mot":"prêcher pour sa paroisse","nature":"locution","definitions":["Défendre son propre intérêt, sa cause ou son camp sous couvert d\'objectivité ou de bien commun."],"phonetique":"/pʁe.ʃe puʁ sa pa.ʁwas/","etymologie":"De « prêcher » (du latin praedicare, proclamer) et « paroisse ». L\'image vient du curé qui, dans son sermon, vante sa propre paroisse, c\'est-à-dire ses intérêts particuliers, plutôt que ceux de tous.","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["défendre sa chapelle","plaider sa cause"],"antonymes":["être impartial","être désintéressé","arbitrer"],"exemplesCorrects":["Quand il vante les mérites de son service, il prêche évidemment pour sa paroisse.","Méfie-toi de ce consultant : il prêche pour sa paroisse en recommandant ses propres outils.","Chaque ministre prêchait pour sa paroisse lors de l\'arbitrage budgétaire."],"exemplesIncorrects":["Le curé a prêché pour sa paroisse trois messes dimanche dernier.","Elle a prêché pour sa paroisse en visitant la cathédrale voisine."],"distracteurs":["sermonner","catéchiser","haranguer"],"anecdote":"L\'expression a un quasi-synonyme, « défendre sa chapelle », qui file la même métaphore religieuse pour désigner la défense d\'un petit groupe ou clan.","categorie":"expression"},{"id":"ronger-son-frein","mot":"ronger son frein","nature":"locution","definitions":["Contenir avec peine son impatience, sa colère ou son dépit ; trépigner intérieurement sans pouvoir agir."],"phonetique":"/ʁɔ̃.ʒe sɔ̃ fʁɛ̃/","etymologie":"Le « frein » désigne ici le mors du cheval. Le cheval impatient ou retenu mâchonne nerveusement son mors ; par métaphore, l\'homme qui ronge son frein réprime mal son impatience d\'agir.","registre":"soutenu","niveau":2,"themes":["abstrait","emotions","quotidien"],"synonymes":["s\'impatienter","bouillir","trépigner"],"antonymes":["patienter sereinement","prendre son mal en patience"],"exemplesCorrects":["Écarté du projet, il rongeait son frein en attendant une nouvelle occasion.","Pendant des mois, elle a rongé son frein avant de pouvoir enfin répliquer.","Les remplaçants rongeaient leur frein sur le banc de touche."],"exemplesIncorrects":["Le mécanicien a rongé son frein avant de changer les plaquettes.","J\'ai rongé mon frein jusqu\'à l\'os tellement il était dur."],"distracteurs":["s\'aigrir","ruminer","fulminer"],"anecdote":"« Frein » au sens de mors se retrouve dans l\'expression « sans frein » (sans retenue) et dans le verbe « refréner », étymologiquement « remettre le mors », c\'est-à-dire réprimer.","categorie":"expression"},{"id":"avoir-un-poil-dans-la-main","mot":"avoir un poil dans la main","nature":"locution","definitions":["Être extrêmement paresseux, fuir le travail et l\'effort."],"phonetique":"/a.vwaʁ œ̃ pwal dɑ̃ la mɛ̃/","etymologie":"Expression du XIXe siècle. L\'image est hyperbolique : la main qui ne travaille jamais laisserait pousser un poil dans la paume, faute d\'être usée par l\'effort. La paresse est si grande que le poil aurait le temps de croître.","registre":"familier","niveau":1,"themes":["quotidien","emotions"],"synonymes":["fainéant","tire-au-flanc","cossard"],"antonymes":["bosseur","travailleur","besogneux"],"exemplesCorrects":["Ce stagiaire a un poil dans la main : il faut le pousser pour qu\'il finisse la moindre tâche.","On ne peut rien lui confier, il a un poil dans la main.","Avec un tel poil dans la main, pas étonnant qu\'il n\'ait jamais terminé ses études."],"exemplesIncorrects":["Il a un poil dans la main depuis qu\'il s\'est blessé au jardin.","Le coiffeur a trouvé un poil dans la main du client."],"distracteurs":["velléitaire","désinvolte","brouillon"],"anecdote":"Certains exagèrent l\'image en précisant que le poil est si long « qu\'on pourrait y faire des nœuds », histoire d\'accentuer la paresse prêtée à la personne.","categorie":"expression"},{"id":"promettre-monts-et-merveilles","mot":"promettre monts et merveilles","nature":"locution","definitions":["Faire des promesses extravagantes, mirobolantes et le plus souvent intenables."],"phonetique":"/pʁɔ.mɛtʁ mɔ̃ z‿e mɛʁ.vɛj/","etymologie":"Expression attestée dès le XVe siècle. Les « monts » (montagnes d\'or) et les « merveilles » symbolisent des richesses et prodiges démesurés ; promettre de telles choses, c\'est promettre l\'impossible.","registre":"courant","niveau":2,"themes":["abstrait","litteraire","quotidien"],"synonymes":["promettre la lune","faire miroiter"],"antonymes":["tenir parole","promettre avec mesure"],"exemplesCorrects":["Le candidat promettait monts et merveilles pour séduire les électeurs.","On m\'avait promis monts et merveilles, et l\'emploi s\'est révélé décevant.","Ce vendeur promet monts et merveilles, mais lisez les petites lignes du contrat."],"exemplesIncorrects":["Nous avons promis monts et merveilles lors de notre randonnée en altitude.","Le guide a promis monts et merveilles au sommet du col."],"distracteurs":["leurrer","amadouer","cajoler"],"anecdote":"La tournure existait déjà en latin : Salluste écrivait « maria montesque polliceri », « promettre des mers et des montagnes », pour railler les promesses démesurées.","categorie":"expression"},{"id":"se-mordre-les-doigts","mot":"se mordre les doigts","nature":"locution","definitions":["Regretter amèrement une décision, un acte ou une parole."],"phonetique":"/sə mɔʁdʁ le dwa/","etymologie":"Expression imagée attestée dès le Moyen Âge. Le geste de se mordre les doigts traduit le dépit et le regret violent ; on se ronge littéralement de remords devant ce qu\'on n\'aurait pas dû faire.","registre":"courant","niveau":1,"themes":["emotions","quotidien","abstrait"],"synonymes":["regretter","se repentir","s\'en vouloir"],"antonymes":["se féliciter","se réjouir","se satisfaire"],"exemplesCorrects":["Il se mord les doigts d\'avoir refusé cette offre d\'emploi.","Tu te mordras les doigts d\'avoir vendu cette maison si vite.","Elle s\'est mordu les doigts de lui avoir fait confiance."],"exemplesIncorrects":["Le bébé se mord les doigts parce qu\'il fait ses dents.","Je me suis mordu les doigts en attrapant le couteau."],"distracteurs":["déplorer","compatir","s\'apitoyer"],"anecdote":"L\'expression voisine « s\'en mordre les pouces » a existé avec le même sens ; on disait aussi autrefois « s\'en mordre les lèvres » pour exprimer le regret rentré.","categorie":"expression"},{"id":"faire-des-chateaux-en-espagne","mot":"faire des châteaux en Espagne","nature":"locution","definitions":["Échafauder des projets chimériques, irréalisables ; se bercer d\'illusions."],"phonetique":"/fɛʁ de ʃɑ.to ɑ̃ n‿ɛs.paɲ/","etymologie":"Expression attestée dès le XIIIe siècle (Roman de la Rose). On bâtit des châteaux en un lieu où l\'on n\'en possède pas : l\'Espagne, terre lointaine et longtemps disputée aux Maures, symbolisait l\'inaccessible où l\'on ne pouvait rien construire de réel.","registre":"soutenu","niveau":2,"themes":["abstrait","litteraire"],"synonymes":["rêvasser","se bercer d\'illusions","fantasmer"],"antonymes":["être réaliste","avoir les pieds sur terre"],"exemplesCorrects":["Au lieu de faire des châteaux en Espagne, dresse un plan d\'action concret.","Adolescent, il faisait des châteaux en Espagne sur sa future gloire littéraire.","Cessons de faire des châteaux en Espagne : ce budget ne suffira jamais."],"exemplesIncorrects":["Nous avons fait des châteaux en Espagne lors de notre voyage à Séville.","L\'architecte a fait des châteaux en Espagne pour un riche client de Madrid."],"distracteurs":["spéculer","extrapoler","supputer"],"anecdote":"La Fontaine illustre l\'idée dans « La Laitière et le Pot au lait » : Perrette bâtit toute sa fortune en imagination avant de renverser son lait et de retomber dans la réalité.","categorie":"expression"},{"id":"donner-du-fil-a-retordre","mot":"donner du fil à retordre","nature":"locution","definitions":["Causer bien des difficultés, des embarras ; opposer une résistance qui complique la tâche."],"phonetique":"/dɔ.ne dy fil a ʁə.tɔʁdʁ/","etymologie":"Expression issue du travail textile. Retordre le fil, c\'est tordre ensemble plusieurs brins pour les renforcer : une opération délicate et fastidieuse. Donner du fil à retordre, c\'est donner de l\'ouvrage pénible, donc des difficultés.","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["compliquer la tâche","mettre en difficulté"],"antonymes":["faciliter","aplanir","simplifier"],"exemplesCorrects":["Cette équipe adverse nous a donné du fil à retordre jusqu\'au bout du match.","Le dossier juridique a donné du fil à retordre aux avocats.","Ses enfants lui donnent du fil à retordre depuis l\'adolescence."],"exemplesIncorrects":["La couturière a donné du fil à retordre à son apprentie pour la bobine.","J\'ai donné du fil à retordre au tailleur pour recoudre mon bouton."],"distracteurs":["entraver","embrouiller","contrecarrer"],"anecdote":"L\'image du fil tordu survit aussi dans « retors », adjectif qui qualifiait d\'abord un fil tordu plusieurs fois, puis, au figuré, une personne rusée et compliquée.","categorie":"expression"},{"id":"mettre-les-bouchees-doubles","mot":"mettre les bouchées doubles","nature":"locution","definitions":["Redoubler d\'efforts pour aller plus vite, accélérer fortement un travail."],"phonetique":"/mɛtʁ le bu.ʃe dubl/","etymologie":"Expression du XVIIIe siècle issue du vocabulaire de la table. Manger en doublant les bouchées, c\'est avaler son repas plus vite ; par extension, on double la cadence du travail pour le terminer plus rapidement.","registre":"courant","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["accélérer","se hâter","forcer l\'allure"],"antonymes":["lambiner","traîner","ralentir"],"exemplesCorrects":["Pour livrer à temps, l\'équipe a mis les bouchées doubles tout le week-end.","Il faudra mettre les bouchées doubles si nous voulons rattraper le retard.","Elle a mis les bouchées doubles et terminé sa thèse en avance."],"exemplesIncorrects":["Au restaurant, il a mis les bouchées doubles dans son assiette de pâtes.","Le cuisinier a mis les bouchées doubles sur le grill pour la sauce."],"distracteurs":["tergiverser","atermoyer","peaufiner"],"anecdote":"On entend parfois la variante fautive « mettre les bouchées triples » : l\'usage consacré reste « doubles », l\'image renvoyant simplement au fait de manger deux fois plus vite.","categorie":"expression"},{"id":"tomber-dans-les-pommes","mot":"tomber dans les pommes","nature":"locution","definitions":["S\'évanouir, perdre connaissance."],"phonetique":"/tɔ̃.be dɑ̃ le pɔm/","etymologie":"Expression du XIXe siècle d\'origine discutée. L\'hypothèse la plus citée y voit une déformation de « tomber en pâmoison » (s\'évanouir), « pâmes » ayant pu glisser vers « pommes » ; George Sand emploie une forme proche, « tomber dans les pommes cuites ».","registre":"familier","niveau":1,"themes":["quotidien","emotions"],"synonymes":["s\'évanouir","défaillir","se trouver mal"],"antonymes":["revenir à soi","reprendre connaissance"],"exemplesCorrects":["À la vue du sang, il est tombé dans les pommes.","Elle a failli tomber dans les pommes tant la chaleur était accablante.","Le malade, épuisé, est tombé dans les pommes en se levant."],"exemplesIncorrects":["Le panier s\'est renversé et les fruits sont tombés dans les pommes.","Nous sommes tombés dans les pommes en cueillant le verger d\'automne."],"distracteurs":["chanceler","trébucher","sombrer"],"anecdote":"On rattache souvent l\'expression à la lettre de George Sand à Madame Dupin où elle écrit « être dans les pommes cuites » pour dire qu\'elle est épuisée, ce qui aurait pu favoriser le glissement avec « pâmoison ».","categorie":"expression"},{"id":"avoir-la-berlue","mot":"avoir la berlue","nature":"locution","definitions":["Avoir des visions, croire voir une chose qui n\'existe pas ; se tromper grossièrement dans son appréciation de ce que l\'on voit."],"phonetique":"/a.vwaʁ la bɛʁ.ly/","etymologie":"De « berlue », trouble passager de la vue attesté dès l\'ancien français, vraisemblablement rattaché au verbe « belluer » (éblouir, mais aussi tromper, duper) ; la berlue désigne une impression visuelle trompeuse, d\'où l\'idée d\'erreur de jugement.","registre":"familier","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["se méprendre","rêver","halluciner"],"antonymes":["voir juste","percevoir clairement"],"exemplesCorrects":["J\'ai cru voir ton frère au marché : j\'avais sans doute la berlue.","Tu as la berlue, ce tableau n\'a jamais été accroché ici.","Non, je n\'ai pas la berlue, c\'est bien lui qui sort de la banque."],"exemplesIncorrects":["Il a soigné sa berlue chez l\'ophtalmologue en deux séances.","Le médecin a diagnostiqué une berlue chronique à l\'œil gauche."],"distracteurs":["mirage","cataracte","éblouir"],"anecdote":"« Berlue » ne désigne aucune maladie réelle de l\'œil : c\'est uniquement une illusion passagère, ce qui explique la nuance d\'erreur de jugement de l\'expression.","categorie":"expression"},{"id":"tenir-la-jambe-a-quelquun","mot":"tenir la jambe à quelqu\'un","nature":"locution","definitions":["Retenir quelqu\'un par un bavardage long et importun dont il ne parvient pas à se défaire."],"phonetique":"/tə.niʁ la ʒɑ̃b a kɛl.kœ̃/","etymologie":"Image populaire née au XIXe siècle : retenir quelqu\'un par la jambe l\'empêche littéralement de s\'en aller, d\'où le sens de l\'immobiliser par un discours.","registre":"familier","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["importuner","retenir","assommer"],"antonymes":["congédier","abréger","laisser partir"],"exemplesCorrects":["Désolé du retard, un voisin m\'a tenu la jambe une demi-heure.","Elle m\'a tenu la jambe avec ses histoires de copropriété.","Je file, je ne voudrais pas te tenir la jambe plus longtemps."],"exemplesIncorrects":["Le kinésithérapeute lui a tenu la jambe pendant la rééducation.","Il a tenu la jambe du blessé pour l\'empêcher de bouger."],"distracteurs":["accaparer","sermonner","alpaguer"],"anecdote":"L\'expression est si ancrée qu\'on dit parfois ironiquement « tenir le crachoir » pour le même bavard intarissable.","categorie":"expression"},{"id":"couper-lherbe-sous-le-pied","mot":"couper l\'herbe sous le pied","nature":"locution","definitions":["Devancer quelqu\'un pour le priver d\'un avantage qu\'il escomptait ; lui ôter un moyen de réussir en agissant avant lui."],"phonetique":"/ku.pe lɛʁb su lə pje/","etymologie":"Métaphore agricole attestée dès le XVIe siècle : couper l\'herbe que le bétail s\'apprêtait à brouter le prive de sa pâture, d\'où l\'idée de déposséder d\'un avantage.","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["devancer","supplanter","damer le pion"],"antonymes":["favoriser","laisser le champ libre","seconder"],"exemplesCorrects":["Un concurrent nous a coupé l\'herbe sous le pied en signant le contrat la veille.","Elle lui a coupé l\'herbe sous le pied en annonçant la nouvelle avant lui.","En baissant ses prix, l\'enseigne a coupé l\'herbe sous le pied de ses rivaux."],"exemplesIncorrects":["Le jardinier a coupé l\'herbe sous le pied du pommier pour l\'aérer.","Il a coupé l\'herbe sous le pied en tondant soigneusement la pelouse."],"distracteurs":["temporiser","ratifier","sermonner"],"anecdote":"On dit aussi « damer le pion » ou « griller la politesse », autant d\'images qui traduisent la même idée de devancer un rival.","categorie":"expression"},{"id":"avoir-le-bras-long","mot":"avoir le bras long","nature":"locution","definitions":["Disposer d\'une influence étendue, de relations puissantes permettant d\'obtenir ce que l\'on souhaite."],"phonetique":"/a.vwaʁ lə bʁa lɔ̃/","etymologie":"Image ancienne du bras qui s\'étend loin pour atteindre ce qui est hors de portée, symbolisant un pouvoir d\'action dépassant les limites ordinaires.","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["être influent","avoir des appuis","être puissant"],"antonymes":["être sans appui","être impuissant","être démuni"],"exemplesCorrects":["Adresse-toi à lui pour ce dossier, il a le bras long à la mairie.","Grâce à un oncle qui a le bras long, elle a obtenu le rendez-vous.","Méfie-toi de ce notable : il a le bras long dans toute la région."],"exemplesIncorrects":["Ce basketteur a le bras long, il marque facilement de loin.","Avec ses bras longs, le gardien arrête tous les ballons."],"distracteurs":["entregent","notoriété","prestigieux"],"anecdote":"L\'expression est souvent teintée d\'une légère méfiance : avoir le bras long, c\'est aussi pouvoir contourner les règles ordinaires.","categorie":"expression"},{"id":"faire-la-pluie-et-le-beau-temps","mot":"faire la pluie et le beau temps","nature":"locution","definitions":["Exercer une autorité absolue sur un domaine, décider de tout, être tout-puissant dans un milieu donné."],"phonetique":"/fɛʁ la plɥi e lə bo tɑ̃/","etymologie":"Métaphore empruntée à la toute-puissance attribuée jadis aux divinités sur les éléments : maîtriser le climat, c\'est régner sur tout.","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["régner","dominer","commander"],"antonymes":["obéir","subir","se soumettre"],"exemplesCorrects":["Au conseil d\'administration, c\'est elle qui fait la pluie et le beau temps.","Pendant des années, ce baron local a fait la pluie et le beau temps.","Dans cette rédaction, le rédacteur en chef fait la pluie et le beau temps."],"exemplesIncorrects":["La météo a fait la pluie et le beau temps sur toute la côte ce week-end.","Le ministre de l\'Agriculture a fait la pluie et le beau temps tomber sur les champs."],"distracteurs":["arbitrer","tergiverser","superviser"],"anecdote":"L\'expression remonte à l\'Antiquité, où l\'on prêtait aux dieux et aux devins le pouvoir d\'influer sur le temps qu\'il fait.","categorie":"expression"},{"id":"se-ranger-des-voitures","mot":"se ranger des voitures","nature":"locution","definitions":["Renoncer à une vie aventureuse ou marginale pour mener une existence rangée ; s\'assagir, s\'établir."],"phonetique":"/sə ʁɑ̃.ʒe de vwa.tyʁ/","etymologie":"Argot parisien du XIXe siècle, croisé avec « se ranger » (adopter une vie réglée) : l\'image évoque celui qui se met à l\'écart du danger de la circulation des voitures hippomobiles, d\'où l\'idée de quitter une vie risquée pour s\'assagir.","registre":"familier","niveau":3,"themes":["quotidien","abstrait"],"synonymes":["s\'assagir","se ranger","s\'établir"],"antonymes":["s\'encanailler","mener la vie de bohème","faire les quatre cents coups"],"exemplesCorrects":["Après une jeunesse agitée, il s\'est rangé des voitures et a ouvert une librairie.","Elle a fini par se ranger des voitures et fonder une famille.","On le croyait incorrigible, mais il s\'est rangé des voitures à quarante ans."],"exemplesIncorrects":["Le voiturier a rangé des voitures toute la soirée devant l\'hôtel.","Il s\'est rangé des voitures sur le parking du supermarché."],"distracteurs":["décrocher","capituler","renoncer"],"anecdote":"L\'expression vient de l\'époque où traverser une rue encombrée de voitures à cheval était périlleux : « se ranger » signifiait littéralement se mettre en sécurité.","categorie":"expression"},{"id":"en-avoir-gros-sur-la-patate","mot":"en avoir gros sur la patate","nature":"locution","definitions":["Éprouver un vif chagrin, beaucoup de peine ou un fort ressentiment que l\'on a du mal à contenir."],"phonetique":"/ɑ̃.n‿a.vwaʁ ɡʁo syʁ la pa.tat/","etymologie":"Variante familière de « en avoir gros sur le cœur », attestée au début du XXe siècle, où « patate » désigne argotiquement le cœur, par analogie de forme avec le tubercule.","registre":"familier","niveau":2,"themes":["emotions","quotidien"],"synonymes":["être affligé","avoir du chagrin","être peiné"],"antonymes":["être soulagé","être réjoui","avoir le cœur léger"],"exemplesCorrects":["Depuis qu\'il est parti sans dire au revoir, j\'en ai gros sur la patate.","Elle en avait gros sur la patate après cette injustice.","Il a serré les dents, mais on voyait qu\'il en avait gros sur la patate."],"exemplesIncorrects":["Le maraîcher en avait gros sur la patate qu\'il a vendue au marché.","J\'ai épluché des patates et j\'en ai gros sur la table."],"distracteurs":["bouder","ronchonner","s\'apitoyer"],"anecdote":"« Patate » remplace ici le cœur, comme dans « avoir la patate » qui, à l\'inverse, signifie être plein d\'énergie.","categorie":"expression"},{"id":"fumer-comme-un-pompier","mot":"fumer comme un pompier","nature":"locution","definitions":["Fumer énormément, de façon presque continuelle."],"phonetique":"/fy.me kɔm œ̃ pɔ̃.pje/","etymologie":"Comparaison apparue au XIXe siècle : les pompiers d\'autrefois, copieusement arrosés d\'eau avant d\'affronter les flammes, ressortaient enveloppés d\'un nuage de vapeur et de fumée, d\'où l\'image de celui qui dégage sans cesse de la fumée.","registre":"familier","niveau":2,"themes":["quotidien"],"synonymes":["fumer beaucoup","être un gros fumeur"],"antonymes":["ne pas fumer","s\'abstenir de fumer"],"exemplesCorrects":["Mon grand-père fumait comme un pompier jusqu\'à ses soixante ans.","Elle fume comme un pompier dès qu\'elle est stressée.","Pendant ses examens, il fumait comme un pompier sur le balcon."],"exemplesIncorrects":["Le pompier a fumé l\'incendie pour le maîtriser rapidement.","Les viandes fumées comme un pompier se conservent plus longtemps."],"distracteurs":["tousser","s\'enrhumer","crachoter"],"anecdote":"L\'expression n\'a rien à voir avec un goût particulier des pompiers pour le tabac : on dit d\'ailleurs aussi « fumer comme une cheminée » ou « comme un sapeur », sur la même idée de fumée incessante.","categorie":"expression"},{"id":"graisser-la-patte","mot":"graisser la patte","nature":"locution","definitions":["Soudoyer quelqu\'un, le corrompre en lui glissant de l\'argent pour obtenir un service ou une faveur."],"phonetique":"/ɡʁɛ.se la pat/","etymologie":"Image attestée dès le XVIIe siècle : glisser une pièce dans la main (la « patte ») de quelqu\'un, la graisse symbolisant depuis longtemps le profit et le gain mal acquis.","registre":"familier","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["soudoyer","corrompre","acheter"],"antonymes":["refuser","rester intègre","être incorruptible"],"exemplesCorrects":["Pour accélérer le dossier, il a fallu graisser la patte d\'un fonctionnaire.","On raconte qu\'il a graissé la patte du douanier pour passer la frontière.","Inutile de graisser la patte du juge : il est réputé incorruptible."],"exemplesIncorrects":["Le mécanicien a graissé la patte du moteur avant de redémarrer.","Elle a graissé la patte du poêle pour qu\'il ne rouille pas."],"distracteurs":["amadouer","cajoler","sermonner"],"anecdote":"La « patte » désignait ici la main de façon familière et méprisante, ce qui renforce la connotation peu reluisante de la corruption.","categorie":"expression"},{"id":"rester-baba","mot":"rester baba","nature":"locution","definitions":["Demeurer stupéfait, interdit, sans voix devant quelque chose d\'étonnant."],"phonetique":"/ʁɛs.te ba.ba/","etymologie":"« Baba », apparu à la fin du XVIIIe siècle, est une onomatopée formée par redoublement du radical « ba » de « ébahir » (du bas latin batare, ouvrir la bouche) : l\'image est celle de la bouche restée ouverte sous l\'effet de la surprise.","registre":"familier","niveau":2,"themes":["emotions","quotidien"],"synonymes":["rester stupéfait","être ébahi","rester coi"],"antonymes":["rester de marbre","être indifférent","rester impassible"],"exemplesCorrects":["Quand il a vu le résultat, il en est resté baba.","Elle est restée baba devant l\'ampleur du décor.","La nouvelle nous a laissés babas pendant un instant."],"exemplesIncorrects":["Il a mangé un baba au rhum à la fin du repas.","Le pâtissier a fait rester le baba au frais toute la nuit."],"distracteurs":["pantois","éberlué","médusé"],"anecdote":"L\'adjectif « baba », ici figé, n\'a rien à voir avec le baba au rhum : il évoque la bouche restée ouverte de la personne stupéfaite.","categorie":"expression"},{"id":"se-faire-mousser","mot":"se faire mousser","nature":"locution","definitions":["Se faire valoir avec exagération, vanter ses propres mérites de façon ostentatoire."],"phonetique":"/sə fɛʁ mu.se/","etymologie":"Image tirée de la mousse qui gonfle et déborde en occupant beaucoup de volume pour peu de matière : se faire mousser, c\'est se gonfler d\'importance.","registre":"familier","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["se vanter","se faire valoir","se mettre en avant"],"antonymes":["se déprécier","rester modeste","s\'effacer"],"exemplesCorrects":["Il ne rate jamais une occasion de se faire mousser devant le patron.","Au lieu de se faire mousser, elle a salué le travail de l\'équipe.","Arrête de te faire mousser, on connaît la vérité."],"exemplesIncorrects":["Le savon se fait mousser sous l\'eau chaude du robinet.","Elle a fait mousser le shampoing dans ses cheveux."],"distracteurs":["pavoiser","fanfaronner","plastronner"],"anecdote":"L\'image de la mousse, abondante mais vite retombée, suggère malicieusement que celui qui se fait mousser a plus d\'apparence que de substance.","categorie":"expression"},{"id":"porter-le-pet","mot":"porter le pet","nature":"locution","definitions":["Se plaindre, dénoncer une affaire ou porter une accusation auprès d\'une autorité (emploi vieilli ou argotique)."],"phonetique":"/pɔʁ.te lə pɛ/","etymologie":"De « pet » pris au sens figuré et argotique de « bruit, querelle, scandale, plainte » (cf. « il y a du pet », « faire du pet ») ; porter le pet, c\'est porter la querelle ou la plainte devant qui de droit.","registre":"familier","niveau":4,"themes":["quotidien","regionalismes"],"synonymes":["se plaindre","dénoncer","porter plainte"],"antonymes":["se taire","couvrir","dissimuler"],"exemplesCorrects":["Le voisin est allé porter le pet à la gendarmerie pour le tapage.","Plutôt que de régler l\'affaire à l\'amiable, il a préféré porter le pet.","Dès qu\'on le contrarie, il va porter le pet auprès du maire."],"exemplesIncorrects":["Le facteur est venu porter le pet jusqu\'à la boîte aux lettres.","Elle a porté le pet de fleurs sur le rebord de la fenêtre."],"distracteurs":["récriminer","incriminer","déblatérer"],"anecdote":"Le mot « pet » a longtemps signifié « bruit, esclandre » : « faire du pet » voulait dire faire du scandale, sens conservé dans l\'argot « faire le pet » (faire le guet pour signaler un danger).","categorie":"expression"},{"id":"couper-le-sifflet","mot":"couper le sifflet","nature":"locution","definitions":["Réduire brusquement quelqu\'un au silence ; l\'interloquer au point qu\'il ne sait plus quoi répondre."],"phonetique":"/ku.pe lə si.flɛ/","etymologie":"Locution attestée dès le XVIe siècle ; « sifflet » désigne familièrement la gorge ou le gosier, l\'organe par lequel passent la voix et le souffle. Le sens premier était « égorger », avant de s\'atténuer en « réduire au silence ».","registre":"familier","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["clouer le bec","river son clou","faire taire"],"antonymes":["encourager","faire parler","relancer"],"exemplesCorrects":["Sa réplique m\'a coupé le sifflet, je n\'ai rien trouvé à répondre.","L\'avocat a coupé le sifflet au témoin avec une seule question.","Cette nouvelle inattendue lui a coupé le sifflet en pleine tirade."],"exemplesIncorrects":["Il a coupé le sifflet du train avant le départ.","Le plombier a coupé le sifflet de la chaudière pour la réparer."],"distracteurs":["déconcerter","interrompre","contredire"],"anecdote":"L\'expression joue sur l\'image du gosier comme un petit instrument à vent : couper le sifflet, c\'est en quelque sorte priver l\'autre de son souffle et donc de sa parole.","categorie":"expression"},{"id":"manger-les-pissenlits-par-la-racine","mot":"manger les pissenlits par la racine","nature":"locution","definitions":["Être mort et enterré."],"phonetique":"/mɑ̃.ʒe le pi.sɑ̃.li paʁ la ʁa.sin/","etymologie":"Locution imagée du XIXe siècle : le mort, étendu sous terre, se trouve sous les pissenlits dont il atteindrait les racines, à l\'inverse du vivant qui en mange les feuilles en salade.","registre":"familier","niveau":2,"themes":["quotidien","litteraire"],"synonymes":["passer l\'arme à gauche","casser sa pipe","trépasser"],"antonymes":["vivre","subsister","exister"],"exemplesCorrects":["À quoi bon thésauriser ? On finit tous par manger les pissenlits par la racine.","Depuis dix ans déjà, le vieux mange les pissenlits par la racine.","Il plaisantait en disant qu\'il mangerait bientôt les pissenlits par la racine."],"exemplesIncorrects":["Au déjeuner, nous avons mangé les pissenlits par la racine, c\'était amer.","Le jardinier conseille de manger les pissenlits par la racine pour profiter de leurs vertus."],"distracteurs":["défunt","inhumer","périr"],"anecdote":"L\'image renverse la perspective du vivant : tandis que nous mangeons les feuilles du pissenlit en salade, le défunt, lui, se trouve du côté des racines.","categorie":"expression"},{"id":"passer-une-nuit-blanche","mot":"passer une nuit blanche","nature":"locution","definitions":["Passer une nuit entière sans dormir."],"phonetique":"/pa.se yn nɥi blɑ̃ʃ/","etymologie":"Locution où « blanche » évoque une nuit vide, sans le « noir » du sommeil ; l\'adjectif blanc a pris en français le sens figuré de « vide, sans résultat » (comme dans bulletin blanc, examen blanc).","registre":"courant","niveau":1,"themes":["quotidien","emotions"],"synonymes":["veiller","ne pas fermer l\'œil","veillée"],"antonymes":["dormir","se reposer","sommeiller"],"exemplesCorrects":["L\'angoisse de l\'examen lui a fait passer une nuit blanche.","Après plusieurs nuits blanches, l\'interne tenait à peine debout.","Le bébé fiévreux nous a valu une nuit blanche."],"exemplesIncorrects":["Il a peint le mur pendant une nuit blanche dans la chambre.","La neige a recouvert le village d\'une nuit blanche éclatante."],"distracteurs":["somnoler","insomniaque","assoupir"],"anecdote":"La « Nuit Blanche » est devenue, depuis 2002 à Paris, le nom d\'une manifestation artistique nocturne où musées et lieux publics restent ouverts jusqu\'à l\'aube.","categorie":"expression"},{"id":"avoir-un-chat-dans-la-gorge","mot":"avoir un chat dans la gorge","nature":"locution","definitions":["Être enroué, avoir la gorge prise et la voix embarrassée par un picotement ou un mucus passager."],"phonetique":"/a.vwaʁ œ̃ ʃa dɑ̃ la ɡɔʁʒ/","etymologie":"Déformation probable de l\'ancien « avoir un maton dans la gorge », « maton » désignant les grumeaux de lait caillé qui gênent la gorge ; par paronymie avec « matou », l\'image du chat s\'est imposée à partir du XIXe siècle.","registre":"courant","niveau":1,"themes":["quotidien","emotions"],"synonymes":["être enroué","avoir la voix prise","s\'érailler la voix"],"antonymes":["s\'éclaircir la voix","être clair","articuler"],"exemplesCorrects":["Excusez-moi, j\'ai un chat dans la gorge, je vais boire un peu d\'eau.","Le conférencier toussota : il avait visiblement un chat dans la gorge.","Sa voix se brisa, comme s\'il avait soudain un chat dans la gorge."],"exemplesIncorrects":["Elle a recueilli un chat dans la gorge de la ruelle.","Le vétérinaire a trouvé un chat dans la gorge du tuyau."],"distracteurs":["aphone","s\'étrangler","éternuer"],"anecdote":"On a longtemps cru que l\'expression dérivait du « maton », grumeau de lait caillé ; le chat s\'y serait glissé par paronymie avec « matou », donnant à la formule sa savoureuse étrangeté.","categorie":"expression"},{"id":"mettre-du-beurre-dans-les-epinards","mot":"mettre du beurre dans les épinards","nature":"locution","definitions":["Améliorer son ordinaire, accroître ses ressources, vivre plus confortablement grâce à un revenu supplémentaire."],"phonetique":"/mɛtʁ dy bœʁ dɑ̃ le.z‿e.pi.naʁ/","etymologie":"Locution du XIXe siècle : les épinards étant un plat modeste et peu coûteux, y ajouter du beurre, denrée plus chère, symbolise une aisance financière retrouvée.","registre":"familier","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["arrondir ses fins de mois","améliorer son ordinaire","s\'enrichir"],"antonymes":["se serrer la ceinture","s\'appauvrir","économiser"],"exemplesCorrects":["Ce petit boulot du week-end lui met du beurre dans les épinards.","Avec la prime, on pourra enfin mettre du beurre dans les épinards.","Les cours particuliers qu\'elle donne mettent du beurre dans les épinards."],"exemplesIncorrects":["Le chef a mis du beurre dans les épinards pour relever sa recette.","Mets du beurre dans les épinards, sinon ils seront trop secs."],"distracteurs":["thésauriser","prospérer","subvenir"],"anecdote":"L\'expression oppose deux symboles culinaires : l\'épinard, légume du pauvre, et le beurre, marqueur d\'une table mieux garnie ; ajouter l\'un à l\'autre, c\'est franchir un cran de confort.","categorie":"expression"},{"id":"tourner-casaque","mot":"tourner casaque","nature":"locution","definitions":["Changer brusquement d\'opinion, de camp ou de parti ; renier ses convictions par opportunisme."],"phonetique":"/tuʁ.ne ka.zak/","etymologie":"Locution née au XVIe siècle, lors des guerres de Religion : la casaque était un vêtement militaire porté par-dessus l\'armure ; retourner sa casaque pour en montrer l\'envers permettait de dissimuler les couleurs de son camp et de rejoindre l\'adversaire.","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["retourner sa veste","virer de bord","se dédire"],"antonymes":["persévérer","rester fidèle","tenir bon"],"exemplesCorrects":["Dès que le vent a tourné, le député a tourné casaque.","On l\'accuse d\'avoir tourné casaque pour conserver son poste.","Fidèle à ses idées, il refusa de tourner casaque malgré les pressions."],"exemplesIncorrects":["Le cavalier a tourné casaque autour de la piste avant la course.","Elle a tourné casaque sur le cintre avant de la repasser."],"distracteurs":["transiger","abjurer","capituler"],"anecdote":"L\'expression « retourner sa veste » est la cousine plus récente et plus familière de « tourner casaque », toutes deux nées de l\'idée de dissimuler les couleurs de son camp.","categorie":"expression"},{"id":"prendre-ses-cliques-et-ses-claques","mot":"prendre ses cliques et ses claques","nature":"locution","definitions":["Rassembler toutes ses affaires et s\'en aller précipitamment."],"phonetique":"/pʁɑ̃dʁ se klik e se klak/","etymologie":"Locution attestée dès le début du XIXe siècle (1811) : « cliques » désigne en ancien dialecte les jambes, et « claques » désignait des galoches ou couvre-chaussures ; l\'ensemble évoque tout ce qu\'on emporte pour déguerpir.","registre":"familier","niveau":2,"themes":["quotidien"],"synonymes":["plier bagage","déguerpir","filer"],"antonymes":["s\'installer","demeurer","rester"],"exemplesCorrects":["Vexé, il a pris ses cliques et ses claques et a claqué la porte.","Dès le préavis reçu, elle a pris ses cliques et ses claques.","Prends tes cliques et tes claques, on ne veut plus de toi ici."],"exemplesIncorrects":["Il a pris ses cliques et ses claques sur l\'étagère du salon.","Le percussionniste a pris ses cliques et ses claques pour le concert."],"distracteurs":["décamper","s\'esquiver","détaler"],"anecdote":"Le mot « cliques » de l\'expression n\'a rien à voir avec la « clique » au sens de bande d\'amis : il désigne ici, en ancien français régional, les jambes elles-mêmes.","categorie":"expression"},{"id":"faire-le-pied-de-grue","mot":"faire le pied de grue","nature":"locution","definitions":["Attendre longuement, debout et immobile, au même endroit."],"phonetique":"/fɛʁ lə pje də ɡʁy/","etymologie":"Locution apparue au XVIIe siècle, qui a remplacé les formes plus anciennes « faire la grue » (XVIe) puis « faire la jambe de grue » : par analogie avec la grue, l\'oiseau échassier qui se tient longtemps immobile sur une seule patte.","registre":"courant","niveau":2,"themes":["quotidien"],"synonymes":["poireauter","attendre","croquer le marmot"],"antonymes":["partir","s\'activer","circuler"],"exemplesCorrects":["J\'ai fait le pied de grue une heure devant le guichet fermé.","Sous la pluie, ils faisaient le pied de grue en attendant le bus.","Inutile de faire le pied de grue, le magasin n\'ouvre qu\'à dix heures."],"exemplesIncorrects":["L\'ouvrier a fait le pied de grue pour soulever la poutre.","Sur le chantier, la grue a fait le pied de grue toute la journée."],"distracteurs":["patienter","flâner","stationner"],"anecdote":"C\'est bien l\'oiseau, et non l\'engin de chantier, qui a donné l\'expression : la grue échassier dort souvent perchée sur une seule patte, image même de l\'attente immobile.","categorie":"expression"},{"id":"se-mettre-sur-son-trente-et-un","mot":"se mettre sur son trente et un","nature":"locution","definitions":["Revêtir ses plus beaux habits ; s\'habiller avec une élégance soignée pour une occasion particulière."],"phonetique":"/sə mɛtʁ syʁ sɔ̃ tʁɑ̃.t‿e œ̃/","etymologie":"Locution probablement issue d\'une déformation de « trentain », nom d\'un drap de luxe tissé avec trente fois cent fils de chaîne ; se mettre sur son trentain, c\'était porter cette étoffe précieuse.","registre":"courant","niveau":2,"themes":["quotidien"],"synonymes":["se pomponner","s\'endimancher","se parer"],"antonymes":["se négliger","se débrailler","traîner"],"exemplesCorrects":["Pour le mariage, toute la famille s\'est mise sur son trente et un.","Elle s\'est mise sur son trente et un avant l\'entretien.","Mets-toi sur ton trente et un, nous dînons en ville ce soir."],"exemplesIncorrects":["Il s\'est mis sur son trente et un en haut de l\'escalier.","Le réveil indiquait trente et un quand il s\'est mis debout."],"distracteurs":["se dévêtir","se costumer","se draper"],"anecdote":"L\'origine la plus probable n\'a rien à voir avec le nombre 31 : elle remonterait au « trentain », un drap de très haute qualité réservé aux toilettes de prestige.","categorie":"expression"},{"id":"donner-un-coup-de-trafalgar","mot":"donner un coup de Trafalgar","nature":"locution","definitions":["Porter un coup décisif et inattendu ; provoquer un revers brutal et désastreux.","Par extension, mauvais coup ou catastrophe soudaine."],"phonetique":"/dɔ.ne œ̃ ku də tʁa.fal.ɡaʁ/","etymologie":"De la bataille navale de Trafalgar (1805), où la flotte franco-espagnole fut écrasée par la Royal Navy de Nelson ; le nom du cap espagnol est devenu synonyme de défaite cinglante et soudaine.","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["coup fatal","coup de massue","désastre"],"antonymes":["triomphe","réussite","aubaine"],"exemplesCorrects":["La faillite de leur principal client leur a donné un coup de Trafalgar.","Cette révélation a donné un coup de Trafalgar à toute sa carrière.","Il redoutait quelque coup de Trafalgar de la part de ses rivaux."],"exemplesIncorrects":["Nous avons donné un coup de Trafalgar pour fêter la victoire.","Le marin a donné un coup de Trafalgar dans la voile pour la hisser."],"distracteurs":["estocade","camouflet","déconvenue"],"anecdote":"L\'expression conserve, deux siècles après, le souvenir cuisant de la défaite navale de 1805 : « Trafalgar » est devenu en français le synonyme même du désastre soudain.","categorie":"expression"},{"id":"faire-ripaille","mot":"faire ripaille","nature":"locution","definitions":["Festoyer copieusement ; faire un repas abondant et joyeux, manger et boire avec excès."],"phonetique":"/fɛʁ ʁi.paj/","etymologie":"De « ripaille », mot dérivé du verbe régional riper (« gratter, racler »), évoquant l\'action de racler le plat ; l\'association avec le château de Ripaille en Savoie, où l\'on prêtait au duc Amédée VIII une vie de bonne chère, a renforcé le sens festif.","registre":"littéraire","niveau":3,"themes":["litteraire","quotidien"],"synonymes":["festoyer","banqueter","bombancer"],"antonymes":["jeûner","se priver","s\'abstenir"],"exemplesCorrects":["Après la moisson, les villageois faisaient ripaille jusqu\'au matin.","On a fait ripaille pour célébrer son retour.","Loin de toute mesure, ils firent ripaille trois jours durant."],"exemplesIncorrects":["Il a fait ripaille de son adversaire au tribunal.","Le maçon a fait ripaille sur le mur avant de le peindre."],"distracteurs":["festin","agapes","victuailles"],"anecdote":"Le château de Ripaille, sur les rives du Léman en Savoie, a longtemps nourri la légende d\'une vie de plaisirs et de bonne chère, renforçant le sens festif du mot.","categorie":"expression"},{"id":"avoir-d-autres-chats-a-fouetter","mot":"avoir d\'autres chats à fouetter","nature":"locution","definitions":["Avoir des préoccupations plus pressantes ou plus importantes ; avoir mieux à faire."],"phonetique":"/a.vwaʁ dotʁ ʃa a fwɛ.te/","etymologie":"Locution du XVIIe siècle, variante de l\'ancien « avoir d\'autres chiens à fouetter » ; l\'image d\'une besogne désagréable et secondaire (fouetter un animal) sert à dire qu\'on en a de plus urgentes ailleurs.","registre":"familier","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["avoir mieux à faire","avoir du pain sur la planche","être occupé"],"antonymes":["s\'ennuyer","être désœuvré","avoir du temps"],"exemplesCorrects":["Je n\'ai pas écouté ses ragots : j\'ai d\'autres chats à fouetter.","Le directeur a d\'autres chats à fouetter que de régler ce détail.","Laisse tomber cette querelle, nous avons d\'autres chats à fouetter."],"exemplesIncorrects":["Au refuge, elle a d\'autres chats à fouetter et à nourrir.","Le dompteur a d\'autres chats à fouetter pendant le numéro."],"distracteurs":["s\'affairer","vaquer","prioriser"],"anecdote":"La formule a connu une variante avec « chiens » avant que le chat ne l\'emporte ; dans les deux cas, l\'animal n\'est qu\'un prétexte imagé pour désigner une corvée jugée secondaire.","categorie":"expression"},{"id":"mener-une-vie-de-baton-de-chaise","mot":"mener une vie de bâton de chaise","nature":"locution","definitions":["Mener une existence agitée, désordonnée et dissolue, faite de plaisirs et d\'excès."],"phonetique":"/mə.ne yn vi də ba.tɔ̃ də ʃɛz/","etymologie":"L\'expression remonte à l\'apparition de la chaise à porteurs vers 1640. Les « bâtons de chaise » sont les longs brancards latéraux servant à la porter, sans cesse en mouvement ; on l\'explique aussi par la vie agitée des porteurs, toujours en déplacement et fréquentant les lieux de plaisir en attendant leur maître. Le sens d\'« activité excessive » a glissé vers celui de « vie désordonnée » au XIXe siècle.","registre":"courant","niveau":2,"themes":["quotidien","litteraire"],"synonymes":["faire la noce","mener grand train","faire la bringue"],"antonymes":["mener une vie rangée","vivre sobrement","se ranger"],"exemplesCorrects":["Depuis son héritage, il mène une vie de bâton de chaise, dépensant sans compter.","À la fac, elle a mené une vie de bâton de chaise avant de se ranger.","On ne peut pas mener une vie de bâton de chaise et espérer rester en forme."],"exemplesIncorrects":["J\'ai mené une vie de bâton de chaise pour réparer le tabouret cassé.","Le menuisier a taillé un beau bâton de chaise en chêne."],"distracteurs":["mener en bateau","tirer le diable par la queue","mettre les bouts"],"anecdote":"On a longtemps cherché le sens caché de cette expression ; le « bâton de chaise » serait l\'un des brancards de la chaise à porteurs, objet sans cesse ballotté, image de l\'existence agitée.","categorie":"expression"},{"id":"se-la-couler-douce","mot":"se la couler douce","nature":"locution","definitions":["Mener une vie facile, paisible, sans souci ni effort ; prendre du bon temps."],"phonetique":"/sə la ku.le dus/","etymologie":"Locution familière du XIXe siècle, métaphore de l\'eau qui « coule douce », c\'est-à-dire calmement, sans heurt, par opposition à un courant agité.","registre":"familier","niveau":1,"themes":["quotidien"],"synonymes":["se prélasser","couler des jours heureux","lézarder"],"antonymes":["trimer","se démener","peiner"],"exemplesCorrects":["Pendant que nous travaillions, lui se la coulait douce au bord de la piscine.","À la retraite, il compte bien se la couler douce.","Ils se la coulent douce sur une île au lieu de chercher du travail."],"exemplesIncorrects":["Le ruisseau se la coule douce entre les rochers du torrent.","Elle se la coule douce pour finir son rapport avant minuit."],"distracteurs":["filer doux","se la jouer","couler à pic"],"anecdote":"L\'image vient de l\'eau qui « coule douce », sans turbulence ; l\'oisiveté tranquille est ainsi comparée à un cours d\'eau paisible.","categorie":"expression"},{"id":"faire-les-yeux-de-chimene","mot":"faire les yeux de Chimène","nature":"locution","definitions":["Regarder quelqu\'un ou quelque chose avec un désir amoureux ou une convoitise manifeste."],"phonetique":"/fɛʁ le.z‿jø də ʃi.mɛn/","etymologie":"Allusion à Chimène, héroïne du Cid de Corneille (1637), éprise de Rodrigue malgré tout ce qui les sépare ; ses regards passionnés sont devenus proverbiaux, expression popularisée par un vers de Boileau.","registre":"soutenu","niveau":3,"themes":["litteraire","emotions"],"synonymes":["faire les yeux doux","lorgner","convoiter"],"antonymes":["dédaigner","ignorer","détourner le regard"],"exemplesCorrects":["Elle faisait les yeux de Chimène à ce jeune homme depuis le début de la soirée.","Devant la vitrine du bijoutier, il faisait les yeux de Chimène.","Inutile de faire les yeux de Chimène, je ne te prêterai pas la voiture."],"exemplesIncorrects":["Il a fait les yeux de Chimène pour soigner sa conjonctivite.","Le médecin a fait les yeux de Chimène durant l\'examen ophtalmologique."],"distracteurs":["faire grise mine","faire les gros yeux","faire la moue"],"anecdote":"Chimène, héroïne du Cid de Corneille, aime Rodrigue tout en étant tenue de réclamer sa mort : ses regards déchirés et amoureux ont donné naissance à l\'expression.","categorie":"expression"},{"id":"jeter-le-manche-apres-la-cognee","mot":"jeter le manche après la cognée","nature":"locution","definitions":["Renoncer à une entreprise, tout abandonner par découragement ou par dépit."],"phonetique":"/ʒə.te lə mɑ̃ʃ a.pʁɛ la kɔ.ɲe/","etymologie":"Locution attestée dès 1548. La cognée est la hache du bûcheron ; lorsqu\'il en perd le fer, jeter aussi le manche, devenu inutile, revient à renoncer à tout.","registre":"soutenu","niveau":3,"themes":["litteraire","abstrait"],"synonymes":["baisser les bras","se décourager","renoncer"],"antonymes":["persévérer","s\'accrocher","persister"],"exemplesCorrects":["Au premier échec, il a jeté le manche après la cognée et fermé sa boutique.","Ne jette pas le manche après la cognée : une seule mauvaise note ne décide pas de tout.","Découragée par les obstacles, elle finit par jeter le manche après la cognée."],"exemplesIncorrects":["Le bûcheron a jeté le manche après la cognée pour aiguiser sa lame.","Il a jeté le manche après la cognée afin de réparer l\'outil cassé."],"distracteurs":["mettre la main à la pâte","prendre le taureau par les cornes","tenir bon"],"anecdote":"On entend souvent la version négative « il ne faut pas jeter le manche après la cognée » ; la cognée désigne bien la hache, non le tas de bois.","categorie":"expression"},{"id":"ne-pas-etre-sorti-de-l-auberge","mot":"ne pas être sorti de l\'auberge","nature":"locution","definitions":["Être encore loin du terme de ses difficultés ; avoir encore beaucoup d\'obstacles à surmonter."],"phonetique":"/nə pa.z‿ɛtʁ sɔʁ.ti də l‿o.bɛʁʒ/","etymologie":"Expression issue de l\'argot des voleurs du XIXe siècle où « auberge » désigne ironiquement la prison, où l\'on était nourri et logé gratuitement mais dont on ne sortait pas aisément ; ne pas en être sorti, c\'est rester pris dans les ennuis.","registre":"familier","niveau":1,"themes":["quotidien"],"synonymes":["ne pas être au bout de ses peines","avoir du pain sur la planche","être dans de beaux draps"],"antonymes":["être tiré d\'affaire","voir le bout du tunnel","en avoir fini"],"exemplesCorrects":["Avec toutes ces réparations à faire, on n\'est pas sorti de l\'auberge.","S\'il faut tout recommencer, nous ne sommes pas sortis de l\'auberge.","Vu l\'ampleur du dossier, elle n\'est pas sortie de l\'auberge."],"exemplesIncorrects":["Après un bon dîner, nous ne sommes pas sortis de l\'auberge avant minuit.","L\'aubergiste n\'est pas sorti de l\'auberge de toute la journée pour servir."],"distracteurs":["être au bout du rouleau","filer à l\'anglaise","prendre le large"],"anecdote":"L\'« auberge » de l\'expression n\'a rien d\'accueillant : en argot du XIXe siècle, le mot désignait la prison, d\'où l\'idée d\'ennuis dont on ne sort pas.","categorie":"expression"},{"id":"courir-le-guilledou","mot":"courir le guilledou","nature":"locution","definitions":["Rechercher des aventures galantes ; fréquenter les lieux de plaisir, surtout la nuit."],"phonetique":"/ku.ʁiʁ lə ɡij.du/","etymologie":"Locution attestée en 1694, issue d\'une forme plus ancienne du XVIe siècle. Selon le Dictionnaire historique de la langue française, « guilledou » dériverait du vieux verbe guiller, « tromper, séduire », combiné à l\'adjectif doux ; le mot ne survit que dans cette expression.","registre":"soutenu","niveau":4,"themes":["litteraire","quotidien"],"synonymes":["batifoler","conter fleurette","folâtrer"],"antonymes":["rester fidèle","se ranger","s\'assagir"],"exemplesCorrects":["Au lieu de rentrer, il préférait courir le guilledou dans les tavernes.","On murmurait que le jeune marquis courait le guilledou chaque nuit.","À vingt ans, elle courait le guilledou sans se soucier des convenances."],"exemplesIncorrects":["Il a couru le guilledou jusqu\'à la ligne d\'arrivée du marathon.","Le chien a couru le guilledou dans tout le jardin."],"distracteurs":["courir les rues","battre la campagne","courir le cachet"],"anecdote":"Le mot « guilledou » n\'existe que dans cette locution ; il dériverait du vieux verbe guiller, « séduire, tromper », accolé à l\'adjectif doux.","categorie":"expression"},{"id":"battre-la-chamade","mot":"battre la chamade","nature":"locution","definitions":["En parlant du cœur, battre très fort sous l\'effet d\'une émotion vive (peur, amour, émotion)."],"phonetique":"/batʁ la ʃa.mad/","etymologie":"De l\'italien chiamata, « appel » (du latin clamare), via le piémontais ciamada : la chamade était jadis un signal de tambour ou de trompette par lequel une place assiégée annonçait sa reddition. Le mot est passé au vocabulaire amoureux au XVIIe siècle.","registre":"soutenu","niveau":2,"themes":["emotions","litteraire"],"synonymes":["palpiter","s\'emballer","cogner"],"antonymes":["s\'apaiser","se calmer","ralentir"],"exemplesCorrects":["En la voyant arriver, son cœur se mit à battre la chamade.","Devant le précipice, j\'avais le cœur qui battait la chamade.","Son cœur battait la chamade à l\'idée de monter sur scène."],"exemplesIncorrects":["Le tambour battait la chamade pour annoncer le défilé du quartier.","Il a battu la chamade contre la table tellement il était nerveux."],"distracteurs":["battre la breloque","battre son plein","battre froid"],"anecdote":"À l\'origine, battre la chamade n\'avait rien d\'amoureux : c\'était un signal militaire de tambour annonçant qu\'une place assiégée demandait à se rendre.","categorie":"expression"},{"id":"tomber-des-nues","mot":"tomber des nues","nature":"locution","definitions":["Être extrêmement surpris par un événement inattendu ; être stupéfait."],"phonetique":"/tɔ̃.be de ny/","etymologie":"Locution du XVIIe siècle. « Nue » désigne en français classique le nuage ; tomber des nues, c\'est chuter brusquement du ciel, image de la surprise totale.","registre":"courant","niveau":2,"themes":["emotions","litteraire"],"synonymes":["être abasourdi","être stupéfait","être ahuri"],"antonymes":["s\'y attendre","prévoir","anticiper"],"exemplesCorrects":["Quand on lui a annoncé son licenciement, il est tombé des nues.","Je suis tombée des nues en apprenant leur séparation.","Elle tomba des nues devant une accusation aussi inattendue."],"exemplesIncorrects":["Les randonneurs sont tombés des nues en glissant sur le sentier.","La pluie tombait des nues sur toute la vallée."],"distracteurs":["tomber dans les pommes","tomber à pic","tomber de haut"],"anecdote":"« Nue » n\'est pas ici une faute : en français classique, le mot désigne le nuage, si bien que tomber des nues, c\'est tomber du ciel de surprise.","categorie":"expression"},{"id":"faire-amende-honorable","mot":"faire amende honorable","nature":"locution","definitions":["Reconnaître publiquement ses torts et présenter des excuses ; se repentir ouvertement d\'une faute."],"phonetique":"/fɛʁ a.mɑ̃d ɔ.nɔ.ʁabl/","etymologie":"Sous l\'Ancien Régime, l\'amende honorable était une peine infamante infligeant au condamné de demander pardon en public, souvent à genoux, pieds nus et en chemise, devant l\'église ou le tribunal. L\'expression a perdu son caractère punitif dès le XVIIIe siècle.","registre":"soutenu","niveau":2,"themes":["abstrait","litteraire"],"synonymes":["reconnaître ses torts","se repentir","s\'excuser"],"antonymes":["persister","nier","s\'entêter"],"exemplesCorrects":["Conscient de son erreur, le directeur a fait amende honorable devant ses employés.","Plutôt que de se justifier, elle a préféré faire amende honorable.","Le journal a fait amende honorable après avoir publié une information erronée."],"exemplesIncorrects":["Il a fait amende honorable de 150 euros pour excès de vitesse.","Le tribunal lui a fait amende honorable pour stationnement gênant."],"distracteurs":["faire bonne figure","faire profil bas","rendre les armes"],"anecdote":"L\'expression ne parle pas d\'argent : sous l\'Ancien Régime, l\'amende honorable était une peine publique où le condamné demandait pardon, souvent à genoux et en chemise.","categorie":"expression"},{"id":"avoir-l-estomac-dans-les-talons","mot":"avoir l\'estomac dans les talons","nature":"locution","definitions":["Avoir très faim ; ressentir une faim intense."],"phonetique":"/a.vwaʁ l‿ɛs.tɔ.ma dɑ̃ le ta.lɔ̃/","etymologie":"Locution imagée du XIXe siècle : l\'estomac vide semble s\'être affaissé jusqu\'aux talons, exprimant par l\'exagération l\'intensité de la faim.","registre":"familier","niveau":1,"themes":["quotidien"],"synonymes":["être affamé","avoir une faim de loup","crier famine"],"antonymes":["être rassasié","être repu","n\'avoir aucune faim"],"exemplesCorrects":["Après cette longue marche, j\'ai l\'estomac dans les talons.","On n\'a pas déjeuné, j\'ai l\'estomac dans les talons.","Les enfants rentraient de l\'école l\'estomac dans les talons."],"exemplesIncorrects":["Il s\'est foulé l\'estomac dans les talons en courant.","Le médecin lui a trouvé l\'estomac dans les talons après l\'examen."],"distracteurs":["avoir les jambes en coton","avoir le cœur sur la main","avoir la dent dure"],"anecdote":"L\'image joue sur l\'exagération : l\'estomac vide paraît descendre jusqu\'aux talons, comme s\'il s\'était affaissé faute de nourriture.","categorie":"expression"},{"id":"prendre-la-cle-des-champs","mot":"prendre la clé des champs","nature":"locution","definitions":["S\'enfuir, s\'évader ; partir librement, sans entrave."],"phonetique":"/pʁɑ̃dʁ la kle de ʃɑ̃/","etymologie":"Locution attestée dès le XVIe siècle : les champs, espaces ouverts hors des murs de la ville ou de la prison, symbolisent la liberté dont on s\'ouvre la « clé » en partant.","registre":"courant","niveau":1,"themes":["quotidien","litteraire"],"synonymes":["s\'évader","prendre le large","filer"],"antonymes":["rester enfermé","demeurer","s\'attarder"],"exemplesCorrects":["Las de la ville, il a pris la clé des champs pour respirer.","Le prisonnier a profité d\'un instant d\'inattention pour prendre la clé des champs.","Dès les vacances venues, les enfants prennent la clé des champs."],"exemplesIncorrects":["Il a perdu la clé des champs et n\'a pas pu ouvrir la grange.","Le fermier range la clé des champs sur le trousseau de la maison."],"distracteurs":["prendre la mouche","prendre racine","prendre ses cliques et ses claques"],"anecdote":"La « clé des champs » n\'a jamais existé comme objet : les champs, ouverts et sans serrure, symbolisent la liberté qu\'on s\'offre en s\'échappant.","categorie":"expression"},{"id":"se-faire-l-echo-de","mot":"se faire l\'écho de","nature":"locution","definitions":["Rapporter, répandre un propos, une rumeur ou une opinion en les transmettant comme le ferait un écho."],"phonetique":"/sə fɛʁ l‿e.ko də/","etymologie":"Du grec êkhô, « son renvoyé », par l\'intermédiaire de la nymphe Écho de la mythologie, condamnée à ne répéter que les dernières paroles entendues.","registre":"soutenu","niveau":2,"themes":["abstrait","litteraire"],"synonymes":["relayer","rapporter","propager"],"antonymes":["taire","passer sous silence","étouffer"],"exemplesCorrects":["La presse s\'est faite l\'écho des inquiétudes des riverains.","Je me fais simplement l\'écho de ce que tout le monde pense tout bas.","Ce roman se fait l\'écho des angoisses de son époque."],"exemplesIncorrects":["Dans la grotte, il s\'est fait l\'écho de sa propre voix.","Le chanteur s\'est fait l\'écho au micro pendant le concert."],"distracteurs":["se faire fort de","se faire l\'avocat du diable","se faire prier"],"anecdote":"L\'expression renvoie à la nymphe Écho de la mythologie grecque, condamnée à ne pouvoir que répéter les derniers mots qu\'on prononçait devant elle.","categorie":"expression"},{"id":"vendre-la-meche","mot":"vendre la mèche","nature":"locution","definitions":["Révéler un secret, dévoiler un complot ou une affaire que l\'on devait taire."],"phonetique":"/vɑ̃dʁ la mɛʃ/","etymologie":"Altération de « éventer la mèche », expression du XVIe siècle : éventer (découvrir, déjouer) la mèche servant à allumer une mine, donc déjouer le complot. Dans la seconde moitié du XIXe siècle, l\'argot a substitué « vendre » (au sens de trahir, dénoncer) à « éventer ».","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["trahir","dévoiler","révéler"],"antonymes":["taire","dissimuler","garder le secret"],"exemplesCorrects":["Surtout ne va pas vendre la mèche avant la fête surprise.","Un complice arrêté a fini par vendre la mèche.","C\'est lui qui a vendu la mèche aux concurrents."],"exemplesIncorrects":["Au marché, elle vend la mèche pour réparer les bougies.","Le quincaillier a vendu la mèche à un bon prix."],"distracteurs":["cacher","colporter","chuchoter"],"anecdote":"L\'expression vient du langage des mineurs et des sapeurs : « éventer la mèche » signifiait découvrir la traînée de poudre d\'un explosif avant qu\'elle ne fasse feu, donc déjouer un mauvais coup.","categorie":"expression"},{"id":"garder-une-poire-pour-la-soif","mot":"garder une poire pour la soif","nature":"locution","definitions":["Se ménager une réserve, économiser quelque chose en prévision de besoins futurs."],"phonetique":"/ɡaʁde yn pwaʁ puʁ la swaf/","etymologie":"Expression attestée dès la fin du XVIe siècle et citée par Antoine Oudin en 1640, où l\'on conservait une poire juteuse pour étancher la soif plus tard ; la poire, fruit gorgé d\'eau, sert d\'image de la provision prudente.","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["économiser","épargner","se ménager"],"antonymes":["dilapider","gaspiller","dépenser"],"exemplesCorrects":["Il a placé une partie de ses gains : il garde une poire pour la soif.","Mieux vaut garder une poire pour la soif que de tout dépenser d\'un coup.","Prudente, elle gardait toujours une poire pour la soif."],"exemplesIncorrects":["Au dessert, il a gardé une poire pour la soif et l\'a mangée.","Le verger gardait une poire pour la soif des cueilleurs."],"distracteurs":["prévoir","temporiser","anticiper"],"anecdote":"On confond parfois cette expression avec « couper la poire en deux » ; la première parle de prévoyance, la seconde de compromis.","categorie":"expression"},{"id":"faire-la-sourde-oreille","mot":"faire la sourde oreille","nature":"locution","definitions":["Feindre de ne pas entendre une demande, refuser d\'y prêter attention."],"phonetique":"/fɛʁ la suʁd‿ɔ.ʁɛj/","etymologie":"Locution attestée depuis le XVe siècle ; « faire la sourde oreille » signifie littéralement présenter une oreille sourde, c\'est-à-dire simuler la surdité pour ne pas répondre.","registre":"courant","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["ignorer","feindre l\'indifférence","se dérober"],"antonymes":["écouter","répondre","prêter attention"],"exemplesCorrects":["Malgré nos relances, l\'administration fait la sourde oreille.","Il a fait la sourde oreille à toutes mes objections.","Inutile d\'insister, elle fait la sourde oreille."],"exemplesIncorrects":["Le médecin a fait la sourde oreille du patient âgé.","On lui a fait la sourde oreille avec un appareil auditif."],"distracteurs":["esquiver","tergiverser","éconduire"],"anecdote":"L\'expression existe au moins depuis le Moyen Âge ; on trouve déjà chez les auteurs du XVe siècle l\'idée de « se faire sourd » pour éviter une requête gênante.","categorie":"expression"},{"id":"mettre-la-puce-a-l-oreille","mot":"mettre la puce à l\'oreille","nature":"locution","definitions":["Éveiller le soupçon ou la curiosité de quelqu\'un, l\'intriguer en attirant son attention sur un détail."],"phonetique":"/mɛtʁ la pys a l‿ɔ.ʁɛj/","etymologie":"Expression médiévale attestée dès le XIIIe siècle qui désignait d\'abord l\'éveil du désir amoureux : la démangeaison d\'une puce dans l\'oreille symbolisait le trouble. Au XVIIe siècle, le sens s\'est déplacé vers l\'inquiétude, puis vers l\'éveil du soupçon.","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["alerter","intriguer","éveiller les soupçons"],"antonymes":["rassurer","endormir la méfiance","tranquilliser"],"exemplesCorrects":["Cette incohérence dans son récit m\'a mis la puce à l\'oreille.","Un appel anonyme lui a mis la puce à l\'oreille.","Les comptes truqués ont mis la puce à l\'oreille de l\'expert."],"exemplesIncorrects":["Le vétérinaire a mis la puce à l\'oreille du chien.","On lui a mis la puce à l\'oreille pour entendre la musique."],"distracteurs":["dévoiler","apaiser","insinuer"],"anecdote":"Au Moyen Âge, « avoir la puce à l\'oreille » évoquait l\'émoi amoureux ; ce n\'est qu\'à partir du XVIIe siècle que l\'expression a pris son sens actuel d\'éveil du soupçon.","categorie":"expression"},{"id":"rabattre-le-caquet","mot":"rabattre le caquet","nature":"locution","definitions":["Faire taire quelqu\'un de présomptueux ou de bavard, le remettre à sa place."],"phonetique":"/ʁa.batʁ lə ka.kɛ/","etymologie":"De « caquet », bavardage bruyant (du verbe « caqueter », imité du cri de la poule), et « rabattre », faire baisser. Attestée dès le XVe siècle, l\'expression image le fait de réduire au silence un beau parleur.","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["clouer le bec","moucher","remettre à sa place"],"antonymes":["encourager","flatter","laisser pérorer"],"exemplesCorrects":["Sa repartie a rabattu le caquet à ce fanfaron.","Il fallait quelqu\'un pour lui rabattre le caquet.","Le verdict a rabattu le caquet aux plus arrogants."],"exemplesIncorrects":["La couturière a rabattu le caquet sur l\'ourlet de la robe.","Le fermier a rabattu le caquet du poulailler vers l\'enclos."],"distracteurs":["rembarrer","tempérer","rabrouer"],"anecdote":"« Rabattre le caquet » se dit aussi « rabaisser le caquet » ; le mot caquet, né du cri des poules, désigne depuis le XVe siècle le bavardage vaniteux.","categorie":"expression"},{"id":"decouvrir-le-fin-mot-de-l-affaire","mot":"découvrir le fin mot de l\'affaire","nature":"locution","definitions":["Comprendre la véritable explication d\'une situation, en percer le sens caché."],"phonetique":"/de.ku.vʁiʁ lə fɛ̃ mo də l‿a.fɛʁ/","etymologie":"Le « fin mot » désigne le mot ultime, le sens dernier ; « fin » a ici le sens ancien de « final, profond ». L\'expression date du français classique et joue sur l\'idée de l\'explication cachée au fond d\'une affaire.","registre":"courant","niveau":2,"themes":["quotidien","abstrait","litteraire"],"synonymes":["élucider","percer le mystère","comprendre"],"antonymes":["s\'égarer","ignorer","rester perplexe"],"exemplesCorrects":["L\'enquêteur finit par découvrir le fin mot de l\'affaire.","Personne n\'a jamais découvert le fin mot de cette affaire.","En lisant le testament, elle découvrit le fin mot de l\'affaire."],"exemplesIncorrects":["Il a découvert le fin mot de l\'affaire dans son dictionnaire.","Le commerçant a découvert le fin mot de l\'affaire pour deux euros."],"distracteurs":["entériner","déchiffrer","dénouer"],"anecdote":"Dans « le fin mot », l\'adjectif « fin » ne renvoie pas à la finesse mais au sens ancien de « final » : c\'est le mot de la fin, celui qui livre la clé.","categorie":"expression"},{"id":"etre-fait-comme-un-rat","mot":"être fait comme un rat","nature":"locution","definitions":["Être pris au piège, se trouver dans une situation sans issue."],"phonetique":"/ɛtʁ fɛ kɔm œ̃ ʁa/","etymologie":"Image de la ratière : le rat « fait » (attrapé) dans le piège ne peut plus s\'échapper. « Fait » a ici le sens argotique de « pris, capturé » ; l\'expression actuelle, proche de l\'ancien « pris et cuit comme un rat » (1725), s\'est répandue au début du XXe siècle.","registre":"familier","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["être coincé","être pris au piège","être cuit"],"antonymes":["s\'échapper","s\'en tirer","être libre"],"exemplesCorrects":["Les issues bloquées, les cambrioleurs étaient faits comme des rats.","Avec ces preuves, il est fait comme un rat.","Encerclés, ils se sont vite vus faits comme des rats."],"exemplesIncorrects":["Ce fromage est fait comme un rat l\'aurait grignoté.","Le sculpteur a fait comme un rat dans la glaise."],"distracteurs":["acculé","traqué","cerné"],"anecdote":"On entend parfois « fait comme un rat » employé au sens de « trompé » ; le sens premier, lié à la ratière, est bien celui d\'être pris au piège sans échappatoire.","categorie":"expression"},{"id":"se-fourrer-le-doigt-dans-l-oeil","mot":"se fourrer le doigt dans l\'œil","nature":"locution","definitions":["Se tromper lourdement, se faire de grandes illusions."],"phonetique":"/sə fu.ʁe lə dwa dɑ̃ l‿œj/","etymologie":"Expression familière du milieu du XIXe siècle (attestée vers 1856) ; l\'image absurde de se mettre le doigt dans l\'œil, geste maladroit et douloureux, illustre l\'erreur grossière que l\'on commet à ses dépens.","registre":"familier","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["se tromper","se méprendre","se leurrer"],"antonymes":["voir juste","avoir raison","deviner"],"exemplesCorrects":["S\'il croit que je vais accepter, il se fourre le doigt dans l\'œil.","Tu te fourres le doigt dans l\'œil en l\'imaginant honnête.","Nous nous sommes fourré le doigt dans l\'œil sur ses intentions."],"exemplesIncorrects":["Le médecin lui a demandé de se fourrer le doigt dans l\'œil irrité.","Elle s\'est fourré le doigt dans l\'œil pour retirer un cil."],"distracteurs":["divaguer","s\'illusionner","s\'abuser"],"anecdote":"On dit aussi « se mettre le doigt dans l\'œil jusqu\'au coude » pour insister, par hyperbole comique, sur l\'ampleur de l\'erreur commise.","categorie":"expression"},{"id":"tenir-le-bon-bout","mot":"tenir le bon bout","nature":"locution","definitions":["Être en bonne voie de réussir, approcher du but, avoir l\'essentiel d\'une affaire en main."],"phonetique":"/tə.niʁ lə bɔ̃ bu/","etymologie":"Image de celui qui, saisissant une corde ou un objet par la bonne extrémité, en maîtrise le maniement ; le « bon bout » est le côté par lequel on tient la situation. Dérivée de « prendre une affaire par le bon bout » (XVe siècle), l\'expression appartient au français familier classique.","registre":"familier","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["être en bonne voie","approcher du but","être bien parti"],"antonymes":["échouer","piétiner","être mal engagé"],"exemplesCorrects":["Encore un effort, on tient le bon bout.","Après des mois de travaux, ils tiennent enfin le bon bout.","Avec ce dernier chapitre, je tiens le bon bout."],"exemplesIncorrects":["Le menuisier tient le bon bout de la planche à raboter.","Elle tient le bon bout de la ficelle pour faire un nœud."],"distracteurs":["progresser","aboutir","persévérer"],"anecdote":"L\'expression dérive de « tenir le bon bout » d\'une corde ou d\'un bâton : prendre l\'objet par la bonne extrémité, c\'est en avoir le contrôle, d\'où l\'idée d\'être bien parti pour réussir.","categorie":"expression"},{"id":"passer-entre-les-gouttes","mot":"passer entre les gouttes","nature":"locution","definitions":["Échapper habilement à un danger, à une sanction ou à un reproche, s\'en tirer sans dommage."],"phonetique":"/pa.se ɑ̃tʁ le ɡut/","etymologie":"Image de celui qui traverserait une averse sans être mouillé, en se faufilant entre les gouttes de pluie ; expression imagée du français familier moderne.","registre":"familier","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["s\'en tirer","esquiver","échapper"],"antonymes":["être pris","essuyer les conséquences","écoper"],"exemplesCorrects":["Lors des licenciements, il est passé entre les gouttes.","Tous ont été sanctionnés, mais elle est passée entre les gouttes.","Le scandale n\'a éclaboussé que les autres : il est passé entre les gouttes."],"exemplesIncorrects":["Sous l\'averse, le toit laisse passer entre les gouttes la pluie.","Le filtre du café laisse passer entre les gouttes le marc."],"distracteurs":["se faufiler","contourner","esquinter"],"anecdote":"L\'expression « passer entre les gouttes » illustre par une image de pluie l\'idée d\'une chance presque insolente : traverser le danger sans en recevoir une seule éclaboussure.","categorie":"expression"},{"id":"avoir-la-moutarde-qui-monte-au-nez","mot":"avoir la moutarde qui monte au nez","nature":"locution","definitions":["Sentir la colère gagner, commencer à s\'emporter, perdre patience."],"phonetique":"/a.vwaʁ la mu.taʁd ki mɔ̃t o ne/","etymologie":"De la moutarde forte qui, lorsqu\'on en mange, pique et fait monter une sensation brûlante jusqu\'au nez et aux yeux ; cette montée piquante sert d\'image à l\'irritation qui gagne. L\'expression date du XVIIe siècle (la forme « la moutarde lui monte au nez » est attestée vers 1640).","registre":"courant","niveau":2,"themes":["emotions","quotidien"],"synonymes":["s\'irriter","s\'emporter","sentir la colère monter"],"antonymes":["se calmer","garder son sang-froid","s\'apaiser"],"exemplesCorrects":["À force d\'être interrompu, il a la moutarde qui lui monte au nez.","Quand elle entendit ces mensonges, la moutarde lui monta au nez.","Sentant la moutarde lui monter au nez, il préféra sortir."],"exemplesIncorrects":["Au déjeuner, j\'ai la moutarde qui monte au nez du sandwich.","Le cuisinier a fait monter la moutarde au nez du plat."],"distracteurs":["s\'attendrir","fulminer","bouillir"],"anecdote":"L\'image vient de la moutarde forte, dont les vapeurs piquantes montent réellement au nez ; la sensation cuisante a donné, par analogie, l\'idée de la colère qui gagne.","categorie":"expression"},{"id":"se-croire-sorti-de-la-cuisse-de-jupiter","mot":"se croire sorti de la cuisse de Jupiter","nature":"locution","definitions":["Se croire d\'une origine ou d\'une importance supérieure, se surestimer, être imbu de soi-même."],"phonetique":"/sə kʁwaʁ sɔʁ.ti də la kɥis də ʒy.pi.tɛʁ/","etymologie":"Allusion au mythe de Dionysos (Bacchus) : Zeus (Jupiter), après la mort de Sémélé, cousit l\'enfant à naître dans sa cuisse jusqu\'au terme. Naître de la cuisse de Jupiter signifie donc avoir une origine divine et exceptionnelle ; l\'expression est attestée dès le XVIIIe siècle.","registre":"courant","niveau":2,"themes":["abstrait","litteraire","emotions"],"synonymes":["se surestimer","se prendre pour un autre","être vaniteux"],"antonymes":["rester modeste","s\'effacer","être humble"],"exemplesCorrects":["Depuis sa promotion, il se croit sorti de la cuisse de Jupiter.","Cette arrogance ! Elle se croit sortie de la cuisse de Jupiter.","Ne te crois pas sorti de la cuisse de Jupiter pour si peu."],"exemplesIncorrects":["Le boucher a sorti de la cuisse de Jupiter un beau morceau.","Le mythe raconte qu\'il est réellement sorti de la cuisse de Jupiter sans métaphore."],"distracteurs":["se rengorger","plastronner","fanfaronner"],"anecdote":"L\'expression renvoie au mythe de Dionysos : Zeus, après la mort de sa mère Sémélé, aurait porté l\'enfant dans sa cuisse jusqu\'à la naissance, d\'où l\'idée d\'une origine prestigieuse que raillent ceux qui se croient supérieurs.","categorie":"expression"},{"id":"ratiboiser","mot":"ratiboiser","nature":"verbe","definitions":["Rafler, prendre tout à quelqu\'un, le dépouiller (notamment au jeu).","Couper les cheveux très court, tondre à ras."],"phonetique":"/ʁa.ti.bwa.ze/","etymologie":"Mot de l\'argot des joueurs (1875), issu du croisement de ratisser et de l\'ancien verbe emboiser, « enjôler, séduire par des artifices ».","registre":"familier","niveau":3,"themes":["quotidien"],"synonymes":["rafler","dépouiller","tondre"],"antonymes":["restituer","rendre","dédommager"],"exemplesCorrects":["Il s\'est fait ratiboiser au poker en une soirée.","Le coiffeur l\'a ratiboisé : il ne lui reste presque plus de cheveux.","Les soldes ont ratiboisé tout son budget du mois."],"exemplesIncorrects":["Le ciel s\'est ratiboisé avant l\'orage.","Elle a ratiboisé une lettre très émouvante à sa mère."],"distracteurs":["rabioter","ratifier","raboter"],"anecdote":"Avant de désigner une coupe de cheveux radicale, ratiboiser voulait dire « rafler les enjeux au baccara » dans l\'argot des salles de jeu du XIXe siècle.","categorie":"mot-rare"},{"id":"amignoter","mot":"amignoter","nature":"verbe","definitions":["Câliner, dorloter, traiter avec une affection délicate."],"phonetique":"/a.mi.ɲɔ.te/","etymologie":"Mot ancien (vers 1223), dérivé avec le préfixe a- du verbe mignoter, lui-même issu de l\'ancien français mignot, « joli, agréable ».","registre":"littéraire","niveau":4,"themes":["emotions","regionalismes"],"synonymes":["dorloter","câliner","choyer"],"antonymes":["maltraiter","rudoyer","négliger"],"exemplesCorrects":["La grand-mère amignotait l\'enfant fiévreux au coin du feu.","On l\'a amignoté toute la semaine pour qu\'il se rétablisse.","Elle aimait amignoter le vieux chat qui ronronnait sur ses genoux."],"exemplesIncorrects":["Il a amignoté la porte d\'un grand coup d\'épaule.","Le vent amignotait violemment les volets toute la nuit."],"distracteurs":["amadouer","amidonner","emmitoufler"],"anecdote":"Encore vivant en Lorraine, amignoter est un cousin désuet de dorloter qui sentait jadis l\'affection un peu enveloppante des nourrices.","categorie":"mot-rare"},{"id":"frichti","mot":"frichti","nature":"nom masculin","definitions":["Repas simple, souvent improvisé, préparé à la maison ; petit plat sans façon."],"phonetique":"/fʁiʃ.ti/","etymologie":"Emprunté vers 1855, par l\'intermédiaire de l\'alsacien fristick, à l\'allemand Frühstück, « petit déjeuner » ; rapproché aussi du radical de fricasser, fricot.","registre":"familier","niveau":3,"themes":["quotidien","emprunts"],"synonymes":["fricot","popote","tambouille"],"antonymes":["festin","banquet","gala"],"exemplesCorrects":["Elle nous a mijoté un petit frichti avec ce qu\'il restait dans le frigo.","Après la randonnée, on s\'est partagé un frichti improvisé.","Rien de tel qu\'un frichti maison pour réchauffer une soirée d\'hiver."],"exemplesIncorrects":["Le frichti gronda longuement dans le ciel avant la pluie.","Il a signé le frichti devant le notaire ce matin."],"distracteurs":["bricheton","fricassée","ragoût"],"anecdote":"Né dans l\'argot militaire, le frichti vient en droite ligne du Frühstück allemand passé par l\'alsacien : un mot d\'outre-Rhin pour désigner la cuisine la plus modeste.","categorie":"mot-rare"},{"id":"lichette","mot":"lichette","nature":"nom féminin","definitions":["Très petite quantité de nourriture ou de boisson ; petit morceau, fine tranche."],"phonetique":"/li.ʃɛt/","etymologie":"Attesté en 1821, variante de léchette, diminutif de lèche, sous l\'influence de licher, forme populaire de lécher.","registre":"familier","niveau":3,"themes":["quotidien"],"synonymes":["miette","soupçon","goutte"],"antonymes":["portion","ration","platée"],"exemplesCorrects":["Je reprendrais bien une lichette de ce fromage.","Elle n\'a bu qu\'une lichette de vin pour trinquer.","Ajoute juste une lichette de crème dans la sauce."],"exemplesIncorrects":["Il a englouti une lichette entière de gigot à lui seul.","La foule formait une immense lichette devant le stade."],"distracteurs":["languette","paupiette","rondelle"],"anecdote":"La lichette se déguste plus qu\'elle ne se mange : le mot garde l\'idée de licher, c\'est-à-dire de lécher du bout des lèvres ce qu\'on savoure à peine.","categorie":"mot-rare"},{"id":"guibole","mot":"guibole","nature":"nom féminin","definitions":["Jambe (familier)."],"phonetique":"/ɡi.bɔl/","etymologie":"Mot familier du XIXe siècle, dérivé de la forme normande guibon, « cuisse », rattachée à l\'ancien verbe giber, « gigoter, remuer bras et jambes ».","registre":"familier","niveau":3,"themes":["quotidien"],"synonymes":["jambe","patte","gambette"],"antonymes":[],"exemplesCorrects":["À son âge, il a encore de bonnes guiboles.","Après le marathon, je ne sentais plus mes guiboles.","Tiens-toi droit sur tes guiboles, voyons !"],"exemplesIncorrects":["Il a réfléchi avec ses guiboles avant de répondre.","Elle a rangé la guibole dans le tiroir de la cuisine."],"distracteurs":["quenotte","guimbarde","guignol"],"anecdote":"On écrit guibole (parfois guibolle), jamais avec un verbe « guiboler » qui n\'existe pas : c\'est un nom, cousin argotique de gigoter et de gambette.","categorie":"mot-rare"},{"id":"bringuebaler","mot":"bringuebaler","nature":"verbe","definitions":["Se balancer, osciller de façon désordonnée ; avancer en cahotant, ballotter."],"phonetique":"/bʁɛ̃ɡ.ba.le/","etymologie":"Origine incertaine ; altération de brimbaler (« osciller, aller et venir ») sous l\'influence de trinqueballer, d\'où les variantes brinquebaler et bringuebaler.","registre":"courant","niveau":2,"themes":["quotidien"],"synonymes":["cahoter","ballotter","brimbaler"],"antonymes":["stabiliser","immobiliser","caler"],"exemplesCorrects":["La vieille charrette bringuebalait sur les pavés.","Le chargement mal arrimé bringuebalait à chaque virage.","On a roulé toute la nuit dans un car qui bringuebalait."],"exemplesIncorrects":["Il a bringuebalé son rapport au directeur avant midi.","Le silence bringuebalait paisiblement dans la bibliothèque."],"distracteurs":["trimbaler","dégringoler","gambader"],"anecdote":"On voit souvent la graphie fautive « bringueballer » avec deux l ; l\'Académie retient bringuebaler (variante brinquebaler), tous deux dérivés du vieux brimbaler.","categorie":"piege-orthographe","piege":{"formeFautive":"bringueballer","explication":"Le verbe s\'écrit avec un seul l : bringuebaler (ou brinquebaler), même si la prononciation et l\'analogie avec « baller » poussent à doubler la consonne."}},{"id":"trapanelle","mot":"trapanelle","nature":"nom féminin","definitions":["Vieux véhicule délabré et peu fiable ; guimbarde."],"phonetique":"/tʁa.pa.nɛl/","etymologie":"Mot d\'argot du XXe siècle, d\'origine obscure ; le terme a aussi désigné un petit engin de chantier à benne avant.","registre":"familier","niveau":4,"themes":["quotidien"],"synonymes":["guimbarde","tacot","clou"],"antonymes":["bolide","berline","limousine"],"exemplesCorrects":["Il sillonne la campagne dans une trapanelle qui fume et qui pétarade.","Comment as-tu fait monter cette trapanelle jusqu\'au col ?","On a fini le voyage à pousser la trapanelle tombée en panne."],"exemplesIncorrects":["Elle a garé sa trapanelle de luxe devant l\'opéra.","La trapanelle exposait une émotion bouleversante au public."],"distracteurs":["torpédo","patache","berline"],"anecdote":"La trapanelle est l\'une de ces guimbardes d\'argot dont l\'étymologie reste incertaine ; Citroën a même baptisé ainsi un prototype tout-terrain dérivé de la 2 CV.","categorie":"mot-rare"},{"id":"aiguail","mot":"aiguail","nature":"nom masculin","definitions":["Rosée du matin qui reste sur l\'herbe, les feuilles et les arbres."],"phonetique":"/ɛ.ɡwaj/","etymologie":"Mot dialectal du Sud-Ouest, dérivé de aigue, « eau », du latin aqua ; attesté sous les formes esgail (1561), égail, aiguail (1690).","registre":"littéraire","niveau":5,"themes":["nature","litteraire"],"synonymes":["rosée","égail","serein"],"antonymes":["sécheresse","aridité","hâle"],"exemplesCorrects":["À l\'aube, l\'aiguail faisait briller chaque brin d\'herbe.","Les chasseurs aiment lever le gibier dans l\'aiguail du petit matin.","Ses chaussures étaient trempées par l\'aiguail des prairies."],"exemplesIncorrects":["L\'aiguail tomba en grosses gouttes pendant tout l\'orage.","Il a planté un aiguail au milieu du jardin pour les oiseaux."],"distracteurs":["frimas","embrun","givre"],"anecdote":"Cher aux poètes et aux veneurs, l\'aiguail désignait surtout la rosée matinale dans laquelle on relevait la voie du gibier au lever du jour.","categorie":"mot-rare"},{"id":"gresil","mot":"grésil","nature":"nom masculin","definitions":["Précipitation de petits grains de glace, plus fins et plus durs que la grêle, qui crépitent en tombant."],"phonetique":"/ɡʁe.zil/","etymologie":"Mot attesté dès le XIe siècle, déverbal de grésiller, qui évoque le crépitement de ce qui frit.","registre":"courant","niveau":2,"themes":["nature"],"synonymes":["grêle","grêlon","glace"],"antonymes":["canicule","sécheresse","chaleur"],"exemplesCorrects":["Le grésil crépitait contre les vitres comme une poignée de sable.","Une averse de grésil a blanchi le trottoir en quelques minutes.","Sous le grésil, les pas faisaient craquer la fine couche de glace."],"exemplesIncorrects":["Le grésil soufflait en rafales chaudes venues du désert.","Il a versé un peu de grésil sucré sur sa crêpe."],"distracteurs":["frimas","verglas","embrun"],"anecdote":"On prononce le l final : /ɡʁe.zil/. Le mot vient de grésiller, car le grésil grésille en tombant, ce crépitement le distingue de la neige silencieuse.","categorie":"piege-orthographe","piege":{"formeFautive":"grézil","explication":"On écrit grésil avec un s (qui se prononce [z] entre deux voyelles), non « grézil » ; et le l final se prononce."}},{"id":"verglas","mot":"verglas","nature":"nom masculin","definitions":["Couche de glace mince et lisse formée par la congélation au sol de la pluie ou d\'une eau de fonte."],"phonetique":"/vɛʁ.ɡla/","etymologie":"Composé de l\'ancien français verre (par allusion à l\'aspect lisse et transparent) et de glas, ancienne forme de glace ; attesté au XIIIe siècle.","registre":"courant","niveau":1,"themes":["nature"],"synonymes":["glace","givre","gel"],"antonymes":["dégel","fonte","redoux"],"exemplesCorrects":["Une plaque de verglas a provoqué plusieurs sorties de route.","Le verglas rendait le trottoir aussi glissant qu\'une patinoire.","Méfie-toi du verglas matinal sur le pont."],"exemplesIncorrects":["Le verglas soufflait en bourrasques tièdes sur la plage.","Elle a saupoudré un peu de verglas sur le gâteau."],"distracteurs":["frimas","grésil","congère"],"anecdote":"Le s final de verglas est muet et ne s\'entend jamais ; le mot cache l\'ancien glas (« glace ») accolé à verre, image de la glace lisse comme du verre.","categorie":"mot-rare"},{"id":"filer-a-l-anglaise","mot":"filer à l\'anglaise","nature":"locution","definitions":["S\'en aller discrètement, sans se faire remarquer et sans prendre congé."],"phonetique":"/fi.le a la.ɡlɛz/","etymologie":"Locution attestée au XIXe siècle. Elle est le pendant de l\'anglais to take French leave (« filer à la française ») : chaque nation attribuait à l\'autre cette habitude jugée impolie de partir sans saluer.","registre":"courant","niveau":1,"themes":["quotidien","litteraire"],"synonymes":["s\'éclipser","s\'esquiver","se défiler"],"antonymes":["prendre congé","saluer","s\'annoncer"],"exemplesCorrects":["Lassé de la réception, il a filé à l\'anglaise avant le dessert.","Profitant de la cohue, les deux amis filèrent à l\'anglaise.","Elle déteste les adieux interminables et préfère filer à l\'anglaise."],"exemplesIncorrects":["Il a filé à l\'anglaise sa démission au directeur.","Nous avons filé à l\'anglaise la nappe sur la table."],"distracteurs":["déguerpir","tergiverser","atermoyer"],"anecdote":"Les Anglais ont l\'expression symétrique to take French leave : chaque peuple impute à l\'autre la désinvolture de l\'esquive.","categorie":"expression"},{"id":"couper-les-cheveux-en-quatre","mot":"couper les cheveux en quatre","nature":"locution","definitions":["Se perdre dans des subtilités excessives, ergoter sur des détails insignifiants."],"phonetique":"/ku.pe le ʃə.vø ɑ̃ katʁ/","etymologie":"Locution imagée attestée dès le XVIIe siècle : l\'idée d\'un cheveu, déjà très fin, qu\'on s\'acharnerait à fendre en quatre dans le sens de la longueur figure une minutie absurde.","registre":"courant","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["ergoter","pinailler","chicaner"],"antonymes":["simplifier","trancher","généraliser"],"exemplesCorrects":["Au lieu de couper les cheveux en quatre, allons à l\'essentiel.","Ce juriste coupe les cheveux en quatre sur la moindre virgule.","Inutile de couper les cheveux en quatre : la réponse est évidente."],"exemplesIncorrects":["Le coiffeur a coupé les cheveux en quatre de la cliente.","Elle a coupé les cheveux en quatre pour gagner du temps."],"distracteurs":["temporiser","fignoler","disserter"],"anecdote":"L\'image se retrouve dans d\'autres langues : les Anglais disent to split hairs, « fendre les cheveux », pour la même manie du détail.","categorie":"expression"},{"id":"faire-contre-mauvaise-fortune-bon-coeur","mot":"faire contre mauvaise fortune bon cœur","nature":"locution","definitions":["Accepter l\'adversité avec sérénité, prendre courageusement son parti d\'une situation fâcheuse."],"phonetique":"/fɛʁ kɔ̃tʁ mo.vɛz fɔʁ.tyn bɔ̃ kœʁ/","etymologie":"Proverbe attesté dès le XVIe siècle. « Fortune » y conserve son sens ancien de sort, de destin ; il s\'agit d\'opposer un cœur vaillant (« bon cœur ») au mauvais sort.","registre":"soutenu","niveau":2,"themes":["abstrait","emotions"],"synonymes":["s\'accommoder","se résigner","endurer"],"antonymes":["se lamenter","se révolter","désespérer"],"exemplesCorrects":["Privé de vacances, il fit contre mauvaise fortune bon cœur et travailla.","Plutôt que de récriminer, elle a fait contre mauvaise fortune bon cœur.","Faisons contre mauvaise fortune bon cœur : la pluie n\'empêchera pas la fête."],"exemplesIncorrects":["Il a fait contre mauvaise fortune bon cœur en héritant d\'un château.","Nous avons fait contre mauvaise fortune bon cœur la liste des invités."],"distracteurs":["prospérer","triompher","exulter"],"anecdote":"Le mot « fortune » garde ici son acception médiévale de hasard, de destinée, et non son sens moderne de richesse.","categorie":"expression"},{"id":"mettre-la-derniere-main","mot":"mettre la dernière main","nature":"locution","definitions":["Achever un ouvrage, le parfaire en lui apportant les ultimes retouches."],"phonetique":"/mɛtʁ la dɛʁ.njɛʁ mɛ̃/","etymologie":"Calque du latin manum ultimam imponere, « mettre la main une dernière fois » sur un travail pour le mener à sa perfection ; l\'image de la touche finale apportée par l\'artiste à son œuvre.","registre":"soutenu","niveau":2,"themes":["quotidien","litteraire"],"synonymes":["parachever","finaliser","parfaire"],"antonymes":["ébaucher","commencer","esquisser"],"exemplesCorrects":["L\'écrivain met la dernière main à son roman avant l\'impression.","Les ouvriers ont mis la dernière main à la façade.","Elle mettait la dernière main à sa robe quand on sonna."],"exemplesIncorrects":["Il a mis la dernière main sur la rampe pour ne pas tomber.","Nous avons mis la dernière main au paquet pour l\'ouvrir."],"distracteurs":["entamer","amorcer","remanier"],"anecdote":"L\'expression latine dont elle dérive, manus ultima, désignait chez les Romains la touche finale apportée par l\'artiste à son œuvre.","categorie":"expression"},{"id":"prendre-la-tangente","mot":"prendre la tangente","nature":"locution","definitions":["S\'esquiver adroitement ; éluder une question ou une difficulté pour s\'en tirer."],"phonetique":"/pʁɑ̃dʁ la tɑ̃.ʒɑ̃t/","etymologie":"Du vocabulaire de la géométrie : la tangente s\'échappe du cercle en n\'en touchant qu\'un point. L\'expression, popularisée au XIXe siècle par l\'argot de l\'École polytechnique, image cette fuite par la ligne droite.","registre":"courant","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["s\'esquiver","se dérober","filer"],"antonymes":["affronter","rester","s\'engager"],"exemplesCorrects":["Dès qu\'on aborde le sujet, il prend la tangente.","Sentant le piège, elle prit aussitôt la tangente.","Plutôt que de répondre, le ministre a pris la tangente."],"exemplesIncorrects":["Le géomètre a pris la tangente au tableau noir.","Il a pris la tangente du chemin le plus court vers la gare."],"distracteurs":["bifurquer","tergiverser","obliquer"],"anecdote":"À Polytechnique, la « tangente » désignait aussi familièrement l\'épée du grand uniforme ; le terme a nourri plusieurs sens argotiques de l\'esquive.","categorie":"expression"},{"id":"battre-en-breche","mot":"battre en brèche","nature":"locution","definitions":["Attaquer vigoureusement pour démolir un argument, une thèse ou une position ; chercher à les ruiner."],"phonetique":"/batʁ ɑ̃ bʁɛʃ/","etymologie":"Locution issue du vocabulaire militaire des sièges : « battre en brèche » une muraille, c\'était la canonner pour y ouvrir une brèche par laquelle donner l\'assaut.","registre":"soutenu","niveau":2,"themes":["abstrait","litteraire"],"synonymes":["réfuter","combattre","saper"],"antonymes":["défendre","soutenir","étayer"],"exemplesCorrects":["Ses recherches battent en brèche une idée reçue tenace.","L\'avocat a battu en brèche tous les arguments de la partie adverse.","Cette découverte bat en brèche la théorie admise jusqu\'ici."],"exemplesIncorrects":["Il a battu en brèche son ami d\'une tape sur l\'épaule.","Nous avons battu en brèche le tambour toute la nuit."],"distracteurs":["corroborer","entériner","consolider"],"anecdote":"Avant l\'artillerie, « ouvrir une brèche » au pied des remparts était l\'objectif premier de tout siège : l\'image guerrière s\'est muée en métaphore du débat d\'idées.","categorie":"expression"},{"id":"tenir-le-haut-du-pave","mot":"tenir le haut du pavé","nature":"locution","definitions":["Occuper une position sociale dominante, jouir d\'un rang élevé et considéré."],"phonetique":"/tə.niʁ lə o dy pa.ve/","etymologie":"Locution née de l\'urbanisme médiéval : les rues, sans trottoir et creusées en leur milieu, voyaient les eaux usées s\'écouler au centre. Le « haut du pavé », le long des maisons, restait propre ; on le cédait par convenance au passant le plus considérable.","registre":"soutenu","niveau":2,"themes":["abstrait","litteraire"],"synonymes":["dominer","prévaloir","régner"],"antonymes":["s\'effacer","végéter","déchoir"],"exemplesCorrects":["Cette famille a longtemps tenu le haut du pavé dans la région.","En littérature, ce courant tient le haut du pavé depuis dix ans.","Jadis riche et titré, il tenait le haut du pavé à la cour."],"exemplesIncorrects":["Le maçon a tenu le haut du pavé pendant la réfection de la rue.","Elle a tenu le haut du pavé contre la pluie pour ne pas glisser."],"distracteurs":["surplomber","prospérer","trôner"],"anecdote":"La courtoisie voulait que le plus modeste des deux passants se range vers le caniveau central pour laisser le « haut du pavé », propre, au plus puissant.","categorie":"expression"},{"id":"ergoter-sur-des-vetilles","mot":"ergoter sur des vétilles","nature":"locution","definitions":["Discuter sans fin sur des riens, contester de menus détails sans importance."],"phonetique":"/ɛʁ.ɡɔ.te syʁ de ve.tij/","etymologie":"Le verbe ergoter est rattaché par les lexicographes au latin ergo (« donc »), mot clé du raisonnement scolastique, d\'où le sens de chicaner ; « vétille » vient de l\'ancien français vette, « ruban », chose menue et sans valeur.","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["chipoter","pinailler","chicaner"],"antonymes":["trancher","concéder","approuver"],"exemplesCorrects":["Cessez d\'ergoter sur des vétilles, l\'essentiel est ailleurs.","Ils ont passé la réunion à ergoter sur des vétilles.","Plutôt que d\'ergoter sur des vétilles, il aurait dû signer."],"exemplesIncorrects":["Il a ergoté sur des vétilles le contrat en deux exemplaires.","Nous avons ergoté sur des vétilles le jardin avant l\'hiver."],"distracteurs":["disserter","palabrer","tergiverser"],"anecdote":"Le verbe ergoter est traditionnellement rattaché au latin ergo, « donc » : il évoque le pédant qui multiplie les « donc » pour gagner une querelle stérile.","categorie":"expression"},{"id":"se-mettre-en-quatre","mot":"se mettre en quatre","nature":"locution","definitions":["Se donner beaucoup de peine, déployer tous ses efforts pour rendre service à quelqu\'un."],"phonetique":"/sə mɛtʁ ɑ̃ katʁ/","etymologie":"Locution attestée dès le XVIIe siècle : l\'image, hyperbolique, est celle d\'une personne qui se diviserait, se mettrait « en quatre » morceaux, pour se multiplier au service d\'autrui.","registre":"courant","niveau":1,"themes":["quotidien","emotions"],"synonymes":["se dévouer","se démener","se décarcasser"],"antonymes":["se ménager","négliger","se désintéresser"],"exemplesCorrects":["Ses parents se sont mis en quatre pour l\'accueillir.","Elle se met en quatre pour satisfaire chaque client.","Nous nous sommes mis en quatre afin que la soirée soit réussie."],"exemplesIncorrects":["Il s\'est mis en quatre parts égales sur le canapé.","Le boulanger s\'est mis en quatre la pâte avant de la cuire."],"distracteurs":["s\'esquinter","prodiguer","s\'évertuer"],"anecdote":"On rencontre aussi la variante imagée « se couper en quatre », qui pousse encore plus loin l\'idée d\'un dévouement physique total.","categorie":"expression"},{"id":"a-l-envi","mot":"à l\'envi","nature":"locution","definitions":["À qui mieux mieux, en rivalisant les uns avec les autres ; avec émulation."],"phonetique":"/a lɑ̃.vi/","etymologie":"De l\'ancien verbe envier au sens de « provoquer, défier », issu du latin invitare (« inviter, défier »). « À l\'envi » signifie donc « à qui rivalisera le mieux », sans aucun rapport avec le mot envie.","registre":"littéraire","niveau":3,"themes":["litteraire","abstrait"],"synonymes":["à qui mieux mieux","en rivalisant","en émulation"],"antonymes":["mollement","isolément","indifféremment"],"exemplesCorrects":["Les poètes la célébraient à l\'envi.","Les enfants criaient à l\'envi pour couvrir la voix des autres.","On vantait à l\'envi les mérites du nouveau venu."],"exemplesIncorrects":["Il regardait le gâteau à l\'envi de le manger.","Elle partit à l\'envi de découvrir la ville."],"distracteurs":["allègrement","frénétiquement","promptement"],"anecdote":"On écrit souvent à tort « à l\'envie » : la locution s\'écrit sans e final et n\'a rien à voir avec le désir ; elle vient du verbe envier au sens ancien de « défier ».","categorie":"piege-sens","piege":{"formeFautive":"à l\'envie","explication":"« À l\'envi » (sans e) signifie « en rivalisant, à qui mieux mieux » et dérive de l\'ancien verbe envier, « défier ». La graphie « à l\'envie », avec un e, est fautive : elle confond la locution avec le nom envie, le désir."}},{"id":"achalande","mot":"achalandé","nature":"adjectif","definitions":["Qui a une nombreuse clientèle, qui attire beaucoup de chalands (clients)."],"phonetique":"/a.ʃa.lɑ̃.de/","etymologie":"Dérivé de chaland au sens ancien de « client, acheteur » (de l\'ancien français chaloir, « avoir de l\'intérêt pour »). Une boutique achalandée est donc fréquentée par de nombreux clients, et non garnie de marchandises.","registre":"soutenu","niveau":3,"themes":["quotidien","abstrait"],"synonymes":["fréquenté","couru","prospère"],"antonymes":["désert","délaissé","déserté"],"exemplesCorrects":["Cette boulangerie, très achalandée, ne désemplit pas.","Le marché du samedi est le plus achalandé de la ville.","Bien situé, le commerce était fort achalandé dès l\'ouverture."],"exemplesIncorrects":["Le rayon était mal achalandé : il ne restait plus rien sur les étagères.","Une cave bien achalandée en grands crus et en fromages."],"distracteurs":["approvisionné","garni","assorti"],"anecdote":"On dit souvent à tort qu\'un magasin « bien achalandé » est bien fourni en marchandises : le mot vient de chaland, le client, et qualifie en réalité l\'affluence, non le stock.","categorie":"piege-sens","piege":{"formeFautive":"magasin bien achalandé (au sens de bien approvisionné)","explication":"« Achalandé » signifie « qui a beaucoup de clients » (le chaland est le client), et non « bien approvisionné en marchandises ». Employer le mot pour parler d\'un stock fourni est un glissement de sens fautif, même s\'il est devenu courant."}},{"id":"recouvrer","mot":"recouvrer","nature":"verbe","definitions":["Rentrer en possession de ce que l\'on avait perdu ; récupérer.","Encaisser, percevoir une somme due (impôt, créance)."],"phonetique":"/ʁə.ku.vʁe/","etymologie":"Du latin recuperare, « recouvrer, regagner » (qui a aussi donné récupérer). À ne pas confondre avec recouvrir, du latin recooperire, « couvrir de nouveau ».","registre":"soutenu","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["récupérer","regagner","percevoir"],"antonymes":["perdre","égarer","céder"],"exemplesCorrects":["Après des mois de convalescence, il a recouvré la vue.","Le Trésor public recouvre l\'impôt sur le revenu.","Elle finit par recouvrer la liberté et tous ses droits."],"exemplesIncorrects":["Il a recouvré le fauteuil d\'un tissu neuf.","La neige a recouvré les toits du village pendant la nuit."],"distracteurs":["reconquérir","rapatrier","restituer"],"anecdote":"On confond fréquemment recouvrer et recouvrir : on ne « recouvre » pas un livre de papier, on le recouvre ; mais on recouvre la santé ou une créance. « Recouvrir » a pour participe recouvert, « recouvrer » a recouvré.","categorie":"piege-sens","piege":{"formeFautive":"recouvrir (employé pour récupérer, ex. « recouvrir la santé »)","explication":"« Recouvrer » (du latin recuperare) signifie récupérer ou encaisser ; « recouvrir » (du latin recooperire) signifie couvrir de nouveau. On recouvre la santé, ses droits ou une créance ; on recouvre un meuble d\'un tissu. Les confondre est une faute fréquente."}},{"id":"conjecture","mot":"conjecture","nature":"nom féminin","definitions":["Opinion fondée sur des probabilités ou des apparences, sans certitude ; supposition, hypothèse."],"phonetique":"/kɔ̃.ʒɛk.tyʁ/","etymologie":"Du latin conjectura, « action de jeter ensemble, déduction », de conicere (jeter ensemble, conclure).","registre":"soutenu","niveau":2,"themes":["abstrait"],"synonymes":["supposition","hypothèse","présomption"],"antonymes":["certitude","preuve","fait"],"exemplesCorrects":["En l\'absence de témoins, l\'enquêteur en était réduit aux conjectures.","Ce n\'est qu\'une conjecture, mais elle me paraît vraisemblable.","Les historiens se perdent en conjectures sur les causes de sa mort."],"exemplesIncorrects":["Dans la conjecture économique actuelle, les taux remontent.","La conjecture du marché est favorable aux investisseurs."],"distracteurs":["intuition","déduction","spéculation"],"anecdote":"On confond souvent « conjecture » (supposition) avec « conjoncture » (situation, contexte du moment) : « la conjoncture économique » désigne l\'état présent de l\'économie, tandis qu\'une « conjecture » n\'est qu\'une hypothèse.","categorie":"piege-sens","piege":{"formeFautive":"conjoncture (au sens de supposition)","explication":"« Conjecture » signifie supposition ; « conjoncture » désigne la situation, le contexte d\'un moment. On dit « se perdre en conjectures », mais « la conjoncture économique »."}},{"id":"prodigue","mot":"prodigue","nature":"adjectif","definitions":["Qui fait des dépenses excessives, qui dissipe son bien sans compter.","Qui donne, qui distribue généreusement et avec abondance (prodigue de conseils, de compliments)."],"phonetique":"/pʁɔ.diɡ/","etymologie":"Du latin prodigus, « qui dépense sans mesure », de prodigere (pousser devant soi, dissiper).","registre":"soutenu","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["dépensier","dilapidateur","gaspilleur"],"antonymes":["économe","avare","parcimonieux"],"exemplesCorrects":["Héritier prodigue, il dilapida sa fortune en quelques années.","Elle se montre prodigue de compliments envers ses élèves.","La parabole de l\'enfant prodigue raconte le retour du fils dissipateur."],"exemplesIncorrects":["Ce jeune prodigue du piano a remporté tous les concours.","Mozart fut un prodigue dès l\'âge de cinq ans."],"distracteurs":["frivole","dispendieux","munificent"],"anecdote":"On écrit parfois « enfant prodige » au lieu d\'« enfant prodigue » pour la célèbre parabole : le « prodigue » est celui qui gaspille son héritage, alors qu\'un « prodige » est un être exceptionnellement doué.","categorie":"piege-sens","piege":{"formeFautive":"prodige (au sens de dépensier)","explication":"« Prodigue » qualifie celui qui dépense sans compter ; un « prodige » est une personne aux dons extraordinaires. C\'est l\'enfant prodigue (dissipateur) de la parabole, non l\'enfant prodige."}},{"id":"eluder","mot":"éluder","nature":"verbe","definitions":["Éviter avec adresse, esquiver une question, une difficulté, en se dérobant."],"phonetique":"/e.ly.de/","etymologie":"Du latin eludere, « se jouer de, esquiver », de ludere (jouer).","registre":"soutenu","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["esquiver","contourner","escamoter"],"antonymes":["affronter","aborder","traiter"],"exemplesCorrects":["Le ministre a éludé la question des journalistes avec une pirouette.","Elle élude habilement tout sujet qui la met en difficulté.","On ne peut pas éluder indéfiniment ce problème."],"exemplesIncorrects":["L\'enquête a permis d\'éluder enfin le mystère.","Le professeur a éludé le passage le plus obscur du texte pour ses élèves."],"distracteurs":["éloigner","exclure","évincer"],"anecdote":"« Éluder » se confond parfois avec « élucider » : éluder, c\'est éviter une question ; élucider, c\'est au contraire la tirer au clair. Les deux mots sont des faux frères trompeurs.","categorie":"piege-sens","piege":{"formeFautive":"élucider (au sens d\'éviter)","explication":"« Éluder » signifie esquiver, se dérober ; « élucider » signifie éclaircir, résoudre. On élude une question gênante, on élucide un mystère."}},{"id":"infester","mot":"infester","nature":"verbe","definitions":["Envahir en grand nombre et causer des ravages, en parlant d\'animaux nuisibles, de parasites ou de personnes malfaisantes."],"phonetique":"/ɛ̃.fɛs.te/","etymologie":"Du latin infestare, « attaquer, ravager », de infestus (hostile, ennemi).","registre":"courant","niveau":2,"themes":["nature","quotidien"],"synonymes":["envahir","pulluler","ravager"],"antonymes":["assainir","débarrasser","éradiquer"],"exemplesCorrects":["Les cafards infestaient la cuisine du vieil immeuble.","Des pirates infestaient autrefois ces côtes.","La cave était infestée de rats."],"exemplesIncorrects":["La plaie s\'est infestée faute de soins.","Le virus a infesté la moitié des ordinateurs du réseau."],"distracteurs":["coloniser","proliférer","parasiter"],"anecdote":"On confond souvent « infester » et « infecter » : on est envahi (infesté) par des nuisibles, mais contaminé (infecté) par un microbe. Une maison est infestée de rats, une plaie est infectée par une bactérie.","categorie":"piege-sens","piege":{"formeFautive":"infecter (au sens d\'envahir)","explication":"« Infester » signifie envahir en masse (nuisibles) ; « infecter » signifie contaminer par un germe. Une cave est infestée de souris, une blessure est infectée."}},{"id":"decade","mot":"décade","nature":"nom féminin","definitions":["Période de dix jours.","Groupe ou suite de dix éléments (notamment les divisions d\'un ouvrage)."],"phonetique":"/de.kad/","etymologie":"Du latin decas, decadis, lui-même du grec dekas, « groupe de dix », de deka (dix).","registre":"soutenu","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["dizaine","décadi"],"antonymes":[],"exemplesCorrects":["Le calendrier révolutionnaire divisait le mois en trois décades de dix jours.","Il a relu la première décade de Tite-Live.","Une décade s\'écoula avant que la lettre ne lui parvienne."],"exemplesIncorrects":["Pendant la décade 2000, internet a transformé nos vies.","Cette technologie existe depuis plus de trois décades.","Il a vécu là durant la décade qui suivit la guerre, soit pendant dix ans."],"distracteurs":["lustre","quinzaine","trimestre"],"anecdote":"Sous l\'influence de l\'anglais « decade », beaucoup emploient « décade » pour « dix ans ». En français rigoureux, une décade vaut dix jours ; une période de dix ans est une décennie.","categorie":"piege-sens","piege":{"formeFautive":"décade (au sens de dix ans)","explication":"« Décade » désigne dix jours (ou un ensemble de dix) ; pour dix ans, le mot juste est « décennie ». L\'anglicisme « décade = décennie » est à éviter."}},{"id":"par-acquit-de-conscience","mot":"par acquit de conscience","nature":"locution","definitions":["Pour se libérer d\'un scrupule, pour n\'avoir rien à se reprocher, afin d\'être en règle avec soi-même."],"phonetique":"/paʁ a.ki də kɔ̃.sjɑ̃s/","etymologie":"De « acquit », substantif du verbe acquitter (quittance, décharge), du latin quietus (en repos, libéré) ; littéralement « pour décharger sa conscience ».","registre":"courant","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["par scrupule","par précaution"],"antonymes":["par négligence","à la légère"],"exemplesCorrects":["J\'ai vérifié une dernière fois, par acquit de conscience.","Par acquit de conscience, le médecin prescrivit un examen complémentaire.","Elle relut le contrat par acquit de conscience, bien qu\'elle lui fît confiance."],"exemplesIncorrects":["Il a agi par acquis de conscience pour se rassurer.","Par acquis de conscience, je l\'ai rappelé deux fois."],"distracteurs":["par prudence","par routine","par courtoisie"],"anecdote":"On écrit fréquemment « par acquis de conscience » : c\'est une faute. Le terme exact est « acquit » (de acquitter, comme dans « pour acquit » sur une facture), et non « acquis » (ce que l\'on a appris).","categorie":"expression","piege":{"formeFautive":"par acquis de conscience","explication":"La graphie correcte est « par acquit de conscience », avec « acquit » (décharge, du verbe acquitter), et non « acquis » (savoir accumulé)."}},{"id":"affleurer","mot":"affleurer","nature":"verbe","definitions":["Apparaître, arriver au niveau de la surface ; émerger juste au ras de quelque chose.","Mettre deux surfaces exactement au même niveau."],"phonetique":"/a.flœ.ʁe/","etymologie":"Dérivé de « fleur » dans la locution « à fleur de » (à la surface de), avec le préfixe a-.","registre":"soutenu","niveau":3,"themes":["nature","abstrait"],"synonymes":["émerger","pointer","poindre"],"antonymes":["s\'enfoncer","submerger","disparaître"],"exemplesCorrects":["Des rochers affleurent à marée basse.","Une émotion contenue affleurait sous ses paroles polies.","Le filon de quartz affleure à flanc de colline."],"exemplesIncorrects":["Il a affleuré le sujet sans s\'y attarder.","Du bout des doigts, elle affleura la joue de l\'enfant."],"distracteurs":["surgir","jaillir","sourdre"],"anecdote":"« Affleurer » (venir à la surface) se confond avec « effleurer » (toucher légèrement, frôler). Une nappe d\'eau affleure le sol ; une main effleure une épaule.","categorie":"piege-sens","piege":{"formeFautive":"effleurer (au sens d\'arriver à la surface)","explication":"« Affleurer », c\'est venir au niveau de la surface, émerger ; « effleurer », c\'est frôler, toucher à peine. Les racines minérales affleurent, une caresse effleure."}},{"id":"amener","mot":"amener","nature":"verbe","definitions":["Conduire, mener quelqu\'un (ou un animal) vers un lieu ou une personne.","Faire venir, occasionner, entraîner (amener des conséquences)."],"phonetique":"/am.ne/","etymologie":"Composé du préfixe a- et de « mener », du latin minare, « pousser devant soi (des animaux) ».","registre":"courant","niveau":1,"themes":["quotidien"],"synonymes":["conduire","accompagner","emmener"],"antonymes":["emmener","ramener","éloigner"],"exemplesCorrects":["Tu peux amener ta sœur à la fête.","Le hasard l\'a amené jusqu\'ici.","Ces décisions ont amené de graves conséquences."],"exemplesIncorrects":["N\'oublie pas d\'amener une bouteille de vin au dîner.","Elle a amené son parapluie au cas où il pleuvrait."],"distracteurs":["apporter","ramener","entraîner"],"anecdote":"L\'usage soigné distingue « amener » (pour un être animé que l\'on conduit) et « apporter » (pour une chose que l\'on porte). On amène un ami, on apporte un gâteau.","categorie":"piege-sens","piege":{"formeFautive":"amener (un objet)","explication":"On « amène » une personne ou un animal (qu\'on mène), mais on « apporte » une chose (qu\'on porte). « Amener une bouteille » est fautif : il faut « apporter une bouteille »."}},{"id":"collusion","mot":"collusion","nature":"nom féminin","definitions":["Entente secrète et frauduleuse entre deux ou plusieurs parties, au détriment d\'un tiers."],"phonetique":"/kɔ.ly.zjɔ̃/","etymologie":"Du latin collusio, « entente frauduleuse », de colludere (jouer ensemble, s\'entendre secrètement), de cum (avec) et ludere (jouer).","registre":"soutenu","niveau":3,"themes":["abstrait"],"synonymes":["connivence","complicité","entente"],"antonymes":["loyauté","probité","transparence"],"exemplesCorrects":["On soupçonne une collusion entre le maire et l\'entrepreneur.","La presse dénonça la collusion des deux partis.","Cette collusion d\'intérêts vicie tout le marché public."],"exemplesIncorrects":["La collusion des deux voitures a bloqué le carrefour.","Une violente collusion frontale a eu lieu sur l\'autoroute."],"distracteurs":["coalition","conspiration","corruption"],"anecdote":"« Collusion » (entente secrète) se confond avec « collision » (choc, heurt) à cause de leur ressemblance sonore. Deux escrocs sont en collusion ; deux véhicules entrent en collision.","categorie":"piege-sens","piege":{"formeFautive":"collision (au sens d\'entente)","explication":"« Collusion » désigne une entente secrète et frauduleuse ; « collision » désigne un choc matériel. Des fraudeurs sont en collusion, des voitures en collision."}},{"id":"denoter","mot":"dénoter","nature":"verbe","definitions":["Indiquer, marquer, révéler par un signe ; être l\'indice de quelque chose."],"phonetique":"/de.nɔ.te/","etymologie":"Du latin denotare, « désigner, marquer », de notare (marquer, noter), de nota (marque, signe).","registre":"soutenu","niveau":2,"themes":["abstrait"],"synonymes":["révéler","indiquer","traduire"],"antonymes":["dissimuler","cacher","masquer"],"exemplesCorrects":["Sa réponse posée dénote une grande maîtrise de soi.","Ces erreurs dénotent un manque de préparation.","Le choix des mots dénote une certaine culture."],"exemplesIncorrects":["La bombe a dénoté avec un fracas assourdissant.","Cette cravate criarde dénote dans un costume si sobre."],"distracteurs":["dénombrer","dénier","dénigrer"],"anecdote":"« Dénoter » (révéler) forme un trio piégeux avec « détoner » (exploser) et « détonner » (sonner faux). Un calme dénote du sang-froid ; une charge détone ; une note détonne dans l\'accord.","categorie":"piege-sens","piege":{"formeFautive":"détoner / détonner (au sens de révéler)","explication":"« Dénoter » signifie révéler, indiquer. À distinguer de « détoner » (exploser) et de « détonner » (chanter faux, jurer)."}},{"id":"detoner","mot":"détoner","nature":"verbe","definitions":["Exploser violemment avec un bruit fort et soudain."],"phonetique":"/de.tɔ.ne/","etymologie":"Du latin detonare, « tonner avec force », de tonare (tonner), apparenté à tonitrus (tonnerre).","registre":"soutenu","niveau":3,"themes":["nature","abstrait"],"synonymes":["exploser","éclater","sauter"],"antonymes":["s\'éteindre","s\'amortir"],"exemplesCorrects":["La charge de dynamite détona dans un fracas terrible.","Le mélange peut détoner au moindre choc.","On entendit l\'obus détoner au loin."],"exemplesIncorrects":["Cette couleur vive détone avec le reste du décor.","Sa voix détonait dans le chœur des choristes."],"distracteurs":["fulminer","crépiter","gronder"],"anecdote":"Avec un seul « n », « détoner » veut dire exploser ; avec deux « n », « détonner » signifie chanter faux ou jurer (couleurs, propos). Un explosif détone, une fausse note détonne.","categorie":"piege-sens","piege":{"formeFautive":"détonner (au sens d\'exploser)","explication":"« Détoner » (un seul n) = exploser bruyamment. « Détonner » (deux n) = sortir du ton, jurer. La poudre détone ; une couleur criarde détonne."}},{"id":"detonner","mot":"détonner","nature":"verbe","definitions":["Sortir du ton, chanter ou jouer faux.","Contraster désagréablement, jurer, ne pas s\'accorder avec un ensemble."],"phonetique":"/de.tɔ.ne/","etymologie":"Composé du préfixe dé- (marquant l\'écart) et de « ton », du latin tonus (tension, ton musical).","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["jurer","trancher","contraster"],"antonymes":["s\'harmoniser","s\'accorder","cadrer"],"exemplesCorrects":["Cette chaise moderne détonne dans le salon ancien.","Sa tenue tapageuse détonnait au milieu des costumes sombres.","Au dernier couplet, le ténor se mit à détonner."],"exemplesIncorrects":["La grenade détonna dès qu\'elle toucha le sol.","On entendit le canon détonner à l\'horizon."],"distracteurs":["dissoner","disconvenir","clocher"],"anecdote":"« Détonner » (deux n, du mot « ton ») se confond avec « détoner » (un n, exploser). Un meuble criard détonne dans une pièce sobre ; une bombe détone.","categorie":"piege-sens","piege":{"formeFautive":"détoner (au sens de jurer)","explication":"« Détonner » (deux n) = sortir du ton, contraster, jurer. « Détoner » (un seul n) = exploser. Un tableau voyant détonne ; une charge explosive détone."}},{"id":"emigrer","mot":"émigrer","nature":"verbe","definitions":["Quitter son pays pour s\'établir durablement dans un autre."],"phonetique":"/e.mi.ɡʁe/","etymologie":"Du latin emigrare, « changer de demeure », de migrare (se déplacer, changer de lieu).","registre":"courant","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["s\'expatrier","s\'exiler"],"antonymes":["immigrer","rester"],"exemplesCorrects":["Pour fuir la misère, des familles entières ont émigré vers le Nouveau Monde.","Ses grands-parents ont émigré d\'Italie dans les années trente.","Beaucoup choisissent d\'émigrer quand l\'avenir leur semble bouché chez eux."],"exemplesIncorrects":["Ces oiseaux émigrent dans notre région chaque printemps pour y nicher.","Il a émigré en France l\'an dernier et s\'y plaît beaucoup."],"distracteurs":["déambuler","déménager","naviguer"],"anecdote":"On confond souvent émigrer et immigrer : on émigre d\'un pays (on en sort), on immigre dans un pays (on y entre). La même personne est émigrée vue de son pays d\'origine, et immigrée vue du pays d\'accueil.","categorie":"piege-sens","piege":{"formeFautive":"émigrer en France","explication":"On émigre DE son pays de départ ; pour désigner l\'entrée dans un pays d\'accueil, on dit immigrer (immigrer en France)."}},{"id":"eminent","mot":"éminent","nature":"adjectif","definitions":["Qui s\'élève au-dessus du niveau commun par son rang, son mérite ou ses qualités ; remarquable, supérieur."],"phonetique":"/e.mi.nɑ̃/","etymologie":"Du latin eminens, participe présent de eminere, « s\'élever au-dessus, se distinguer ».","registre":"soutenu","niveau":2,"themes":["abstrait","litteraire"],"synonymes":["remarquable","distingué","insigne"],"antonymes":["médiocre","obscur","insignifiant"],"exemplesCorrects":["C\'est un éminent spécialiste de la Renaissance italienne.","Le prix récompense les éminents services rendus à la recherche.","Elle occupe une place éminente parmi les juristes de sa génération."],"exemplesIncorrects":["Un orage éminent menaçait, le ciel s\'était assombri.","L\'arrivée du train était éminente, nous avons couru sur le quai."],"distracteurs":["proéminent","prééminent","permanent"],"anecdote":"On écrit parfois à tort « un danger éminent » : un danger qui va survenir est imminent. Éminent qualifie ce qui est supérieur, élevé en dignité, pas ce qui est proche dans le temps.","categorie":"piege-sens","piege":{"formeFautive":"un danger éminent","explication":"Éminent (remarquable, supérieur) se confond avec imminent (sur le point de se produire) : un danger proche est imminent, pas éminent."}},{"id":"preeminence","mot":"prééminence","nature":"nom féminin","definitions":["Supériorité de rang, de dignité ou d\'importance qui place au-dessus des autres."],"phonetique":"/pʁe.e.mi.nɑ̃s/","etymologie":"Du latin praeeminentia, de praeeminere, « s\'élever en avant, l\'emporter », de prae (devant) et eminere (s\'élever).","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["primauté","suprématie","prépondérance"],"antonymes":["infériorité","subordination","soumission"],"exemplesCorrects":["La prééminence du pouvoir spirituel sur le temporel fut longtemps contestée.","Nul ne discutait alors la prééminence de Paris sur les autres capitales du goût.","Il revendiquait la prééminence de la raison sur la passion."],"exemplesIncorrects":["La prééminence de son menton donnait à son profil une allure énergique.","On remarquait la prééminence de ses pommettes saillantes."],"distracteurs":["proéminence","imminence","convenance"],"anecdote":"Prééminence (deux é, supériorité de rang) ne doit pas être confondue avec proéminence (saillie physique, comme celle d\'un nez). L\'une relève de la hiérarchie, l\'autre du relief.","categorie":"piege-sens","piege":{"formeFautive":"la prééminence de son nez","explication":"Prééminence désigne une supériorité de rang ; pour une saillie physique (nez, menton), le mot est proéminence."}},{"id":"proeminent","mot":"proéminent","nature":"adjectif","definitions":["Qui dépasse, fait saillie, s\'avance en relief par rapport à ce qui l\'entoure."],"phonetique":"/pʁɔ.e.mi.nɑ̃/","etymologie":"Du latin prominens, participe présent de prominere, « s\'avancer en saillie », de pro (en avant) et eminere (s\'élever).","registre":"courant","niveau":2,"themes":["quotidien","nature"],"synonymes":["saillant","protubérant","saillissant"],"antonymes":["rentrant","creux","effacé"],"exemplesCorrects":["Son menton proéminent lui donnait un air volontaire.","Le portrait soulignait des pommettes proéminentes et un front haut.","Une veine proéminente courait sur le dos de sa main."],"exemplesIncorrects":["Ce proéminent professeur dirige le laboratoire depuis vingt ans.","Il occupe une fonction proéminente au sein du ministère."],"distracteurs":["prééminent","imminent","culminant"],"anecdote":"Proéminent décrit ce qui dépasse physiquement (un nez, un ventre) ; pour une supériorité de rang ou de dignité, c\'est prééminent qu\'il faut écrire. La distinction tient à un seul é.","categorie":"piege-sens","piege":{"formeFautive":"un proéminent professeur","explication":"Proéminent qualifie ce qui fait saillie physiquement ; pour une personne supérieure en dignité ou en rang, on dit prééminent."}},{"id":"luxation","mot":"luxation","nature":"nom féminin","definitions":["Déplacement anormal et durable des surfaces d\'une articulation, qui sortent de leur position normale ; déboîtement."],"phonetique":"/lyk.sa.sjɔ̃/","etymologie":"Du latin luxatio, de luxare, « démettre, déboîter », de luxus, « déboîté, de travers ».","registre":"courant","niveau":2,"themes":["quotidien"],"synonymes":["déboîtement","déplacement","entorse"],"antonymes":["réduction","remboîtement"],"exemplesCorrects":["Sa chute a provoqué une luxation de l\'épaule.","Le médecin a réduit la luxation du genou sous anesthésie.","Une luxation du doigt l\'a écarté des terrains plusieurs semaines."],"exemplesIncorrects":["Le moraliste dénonçait la luxation et la débauche de la cour.","Cette vie de plaisirs et de luxation finit par le ruiner."],"distracteurs":["fracture","foulure","lassitude"],"anecdote":"À l\'oreille, luxation (déboîtement articulaire) frôle luxure (débauche, péché de chair) : deux mots de racines latines distinctes, luxare (déboîter) et luxuria (excès, dérèglement).","categorie":"piege-sens","piege":{"formeFautive":"une vie de luxation","explication":"Luxation est un terme médical (déboîtement d\'une articulation) ; le penchant pour la débauche se nomme luxure."}},{"id":"veneneux","mot":"vénéneux","nature":"adjectif","definitions":["Qui renferme un poison dangereux lorsqu\'on l\'absorbe, en parlant surtout des végétaux et des champignons."],"phonetique":"/ve.ne.nø/","etymologie":"Du latin venenosus, « empoisonné », de venenum, « poison, philtre ».","registre":"courant","niveau":2,"themes":["nature"],"synonymes":["toxique","empoisonné"],"antonymes":["comestible","inoffensif","salutaire"],"exemplesCorrects":["L\'amanite phalloïde est un champignon vénéneux et souvent mortel.","Ne cueille pas ces baies, elles sont vénéneuses.","Le jardin botanique présente une collection de plantes vénéneuses."],"exemplesIncorrects":["La vipère est un serpent vénéneux dont la morsure peut tuer.","La piqûre de ce scorpion vénéneux est très douloureuse."],"distracteurs":["véreux","vénérable","vénal"],"anecdote":"On dit d\'une plante qu\'elle est vénéneuse (poison ingéré) et d\'un animal qu\'il est venimeux (venin inoculé par morsure ou piqûre). Un champignon est vénéneux, une vipère venimeuse.","categorie":"piege-sens","piege":{"formeFautive":"un serpent vénéneux","explication":"Vénéneux se dit d\'un végétal dont l\'ingestion empoisonne ; un animal qui injecte du venin est venimeux."}},{"id":"venimeux","mot":"venimeux","nature":"adjectif","definitions":["Se dit d\'un animal qui sécrète du venin et l\'inocule par une morsure, une piqûre ou un dard.","Au figuré, plein de fiel, de méchanceté haineuse."],"phonetique":"/və.ni.mø/","etymologie":"Dérivé de l\'ancien français venim, « venin », lui-même du latin venenum, « poison ».","registre":"courant","niveau":2,"themes":["nature","abstrait"],"synonymes":["fielleux","perfide","haineux"],"antonymes":["inoffensif","bienveillant","anodin"],"exemplesCorrects":["La vipère est un serpent venimeux.","Le scorpion possède un dard venimeux à l\'extrémité de sa queue.","Il glissa une remarque venimeuse à voix basse."],"exemplesIncorrects":["Ce champignon venimeux a provoqué une grave intoxication.","Ne mange pas cette plante, elle est venimeuse."],"distracteurs":["vénéneux","vénal","vindicatif"],"anecdote":"Un animal venimeux inocule son venin (morsure, piqûre) ; une plante vénéneuse empoisonne quand on l\'ingère. Au figuré, seul venimeux s\'emploie : une langue venimeuse.","categorie":"piege-sens","piege":{"formeFautive":"un champignon venimeux","explication":"Venimeux qualifie un animal qui injecte du venin ; un végétal toxique à l\'ingestion est vénéneux."}},{"id":"oiseux","mot":"oiseux","nature":"adjectif","definitions":["Qui ne sert à rien, sans utilité ni portée ; inutile, vain.","En parlant de propos ou de questions, qui ne mène à aucune conclusion."],"phonetique":"/wa.zø/","etymologie":"Du latin otiosus, « de loisir, inoccupé », de otium, « loisir, repos ».","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["vain","inutile","futile"],"antonymes":["utile","fructueux","pertinent"],"exemplesCorrects":["Nous nous sommes perdus en discussions oiseuses.","C\'est une question oiseuse qui ne fait pas avancer le débat.","Il jugeait oiseuse toute spéculation sans preuve."],"exemplesIncorrects":["Resté oiseux toute la journée, il n\'avait rien fait de ses mains.","Une vie oiseuse, sans travail ni occupation, finit par lui peser."],"distracteurs":["fastidieux","spécieux","scrupuleux"],"anecdote":"Oiseux (inutile, vain) se confond avec oisif (désœuvré, qui ne travaille pas). Les deux viennent du latin otium, mais oiseux qualifie une chose sans portée, oisif une personne sans occupation.","categorie":"piege-sens","piege":{"formeFautive":"rester oiseux toute la journée","explication":"Oiseux signifie « inutile, sans portée » et se dit de choses ; une personne qui ne fait rien est oisive."}},{"id":"oisif","mot":"oisif","nature":"adjectif","definitions":["Qui ne travaille pas, qui reste sans occupation ; désœuvré.","Qui se passe dans l\'inaction, en parlant du temps."],"phonetique":"/wa.zif/","etymologie":"Réfection, d\'après le latin otium (loisir), de l\'ancien français oiseus, du latin otiosus, « inoccupé ».","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["désœuvré","inactif","inoccupé"],"antonymes":["actif","occupé","affairé"],"exemplesCorrects":["Une foule oisive flânait le long des quais.","Il menait une existence oisive, partagée entre le café et les promenades.","Pendant ces journées oisives, le temps semblait s\'étirer."],"exemplesIncorrects":["Ces débats oisifs ne mènent nulle part et nous font perdre du temps.","Il posa une question oisive, sans intérêt pour la discussion."],"distracteurs":["oiseux","paisible","placide"],"anecdote":"Oisif décrit une personne désœuvrée, sans occupation ; oiseux qualifie une chose inutile, vaine. On a un homme oisif mais une remarque oiseuse.","categorie":"piege-sens","piege":{"formeFautive":"un débat oisif","explication":"Oisif se dit d\'une personne désœuvrée ; un propos inutile ou sans portée est oiseux."}},{"id":"tendresse","mot":"tendresse","nature":"nom féminin","definitions":["Sentiment d\'affection douce, de chaleur bienveillante envers quelqu\'un.","Au pluriel, marques, témoignages d\'affection."],"phonetique":"/tɑ̃.dʁɛs/","etymologie":"Dérivé de tendre (adjectif), du latin tener, « délicat, jeune, sensible ».","registre":"courant","niveau":1,"themes":["emotions"],"synonymes":["affection","douceur","attachement"],"antonymes":["dureté","froideur","rudesse"],"exemplesCorrects":["Elle regardait son enfant endormi avec une infinie tendresse.","Il y avait dans sa voix une tendresse qui le désarmait.","Ils échangèrent quelques tendresses avant de se quitter."],"exemplesIncorrects":["La tendresse de ce gigot, fondant à souhait, ravit les convives.","On apprécie cette viande pour sa tendresse exceptionnelle."],"distracteurs":["tendreté","mansuétude","allégresse"],"anecdote":"Tendresse, c\'est l\'affection du cœur ; la qualité d\'une viande tendre se nomme tendreté. On loue la tendresse d\'une mère, mais la tendreté d\'un steak.","categorie":"piege-sens","piege":{"formeFautive":"la tendresse de la viande","explication":"Tendresse désigne un sentiment d\'affection ; la qualité d\'un aliment tendre se dit tendreté."}},{"id":"tendrete","mot":"tendreté","nature":"nom féminin","definitions":["Qualité d\'un aliment, et particulièrement d\'une viande, qui est tendre et se mâche aisément."],"phonetique":"/tɑ̃.dʁə.te/","etymologie":"Dérivé de tendre (adjectif), du latin tener, « délicat, mou », avec le suffixe -té marquant la qualité.","registre":"courant","niveau":3,"themes":["quotidien"],"synonymes":["moelleux","fondant"],"antonymes":["dureté","fermeté","coriacité"],"exemplesCorrects":["La tendreté de cette entrecôte tient à la maturation de la viande.","Le chef vante la tendreté de son agneau de lait.","On juge un bon rôti à sa tendreté et à son jus."],"exemplesIncorrects":["Il la regardait avec une tendreté pleine d\'amour.","Leur amitié était faite de confiance et de tendreté."],"distracteurs":["tendresse","fermeté","sécheresse"],"anecdote":"La tendreté est un terme de gastronomie et de boucherie réservé aux aliments tendres ; le sentiment affectueux, lui, se nomme tendresse. On parle de la tendreté d\'un steak, jamais de sa tendresse.","categorie":"piege-sens","piege":{"formeFautive":"la tendreté d\'une mère","explication":"Tendreté qualifie une viande ou un aliment tendre ; le sentiment d\'affection se dit tendresse."}},{"id":"notable","mot":"notable","nature":"adjectif","definitions":["Qui mérite d\'être noté, remarqué ; digne d\'attention par son importance.","Comme nom, personne qui occupe un rang important dans une ville ou une communauté."],"phonetique":"/nɔ.tabl/","etymologie":"Du latin notabilis, « digne d\'être remarqué », de notare, « marquer, noter ».","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["remarquable","appréciable","sensible"],"antonymes":["négligeable","insignifiant","infime"],"exemplesCorrects":["On observe une amélioration notable depuis le début du traitement.","À une exception notable près, tous les invités étaient présents.","Les notables de la ville s\'étaient réunis à l\'hôtel de ville."],"exemplesIncorrects":["Son escroquerie le rendit notable dans toute la région.","C\'est un menteur notable, sa réputation n\'est plus à faire."],"distracteurs":["notoire","honorable","notarial"],"anecdote":"Notable (digne d\'être noté, appréciable) se confond avec notoire (connu de tous, manifeste). On dit une amélioration notable, mais un fait notoire ou un escroc notoire ; notoire s\'emploie souvent pour ce qui est connu en mal.","categorie":"piege-sens","piege":{"formeFautive":"un menteur notable","explication":"Notable signifie « digne d\'être remarqué, appréciable » ; pour ce qui est connu de tous (souvent en mauvaise part), on dit notoire."}},{"id":"notoire","mot":"notoire","nature":"adjectif","definitions":["Qui est connu de tous, manifeste, incontestablement établi.","Qui est largement reconnu (souvent en mauvaise part)."],"phonetique":"/nɔ.twaʁ/","etymologie":"Du bas latin notorius, « qui fait connaître », du latin notus, « connu », participe passé de noscere, « connaître ».","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["manifeste","patent","avéré"],"antonymes":["caché","ignoré","secret"],"exemplesCorrects":["Sa mauvaise foi est notoire dans tout le service.","C\'est un fait notoire que la ville fut détruite au siècle dernier.","L\'incompétence notoire du gérant a précipité la faillite."],"exemplesIncorrects":["Ce chercheur notoire a reçu le prix Nobel pour ses travaux.","Le château est un monument notoire de la région.","Elle a fait un effort notoire pour améliorer son score."],"distracteurs":["notable","remarquable","éminent"],"anecdote":"On confond souvent « notoire » avec « notable » : « notoire » signifie « connu de tous » (et a souvent une nuance péjorative : un escroc notoire), tandis que « notable » signifie « digne d\'être remarqué, important ». On ne dit pas « un savant notoire » pour le louer, mais « un savant notable ».","categorie":"piege-sens","piege":{"formeFautive":"un savant notoire (au sens de remarquable)","explication":"« Notoire » veut dire « connu de tous », souvent avec une connotation négative ; pour exprimer « digne d\'être remarqué », il faut « notable »."}},{"id":"gradation","mot":"gradation","nature":"nom féminin","definitions":["Progression par degrés successifs, augmentation ou diminution graduelle.","Figure de style consistant à disposer des termes selon une intensité croissante ou décroissante."],"phonetique":"/ɡʁa.da.sjɔ̃/","etymologie":"Du latin gradatio, « disposition par degrés », de gradus, « pas, degré ».","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["progression","graduation","échelonnement"],"antonymes":["rupture","saut","uniformité"],"exemplesCorrects":["L\'orateur ménageait une savante gradation dans son indignation.","La douleur s\'apaisa par une lente gradation.","« Va, cours, vole et nous venge » illustre une gradation."],"exemplesIncorrects":["Il a lu la température sur la gradation du thermomètre.","Les gradations du verre doseur sont effacées.","La gradation gravée sur la règle facilite la mesure."],"distracteurs":["échelle","calibrage","dégradé"],"anecdote":"« Gradation » désigne une progression (de la douleur, d\'un sentiment, d\'un effet rhétorique), à ne pas confondre avec « graduation », qui est la division en degrés marqués sur un instrument. Le thermomètre porte une graduation ; un discours obéit à une gradation.","categorie":"piege-sens","piege":{"formeFautive":"la gradation d\'un thermomètre","explication":"Les traits marqués sur un instrument constituent la « graduation » ; « gradation » désigne une progression par degrés."}},{"id":"graduation","mot":"graduation","nature":"nom féminin","definitions":["Division d\'une grandeur, d\'un instrument en degrés marqués servant de repères.","Action de graduer ; ensemble des traits ou repères ainsi tracés."],"phonetique":"/ɡʁa.dɥa.sjɔ̃/","etymologie":"Dérivé savant du latin médiéval graduare, « graduer », de gradus, « degré ».","registre":"courant","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["échelle","calibrage","repérage"],"antonymes":[],"exemplesCorrects":["La graduation de la règle s\'arrête à trente centimètres.","Lisez le volume au niveau de la graduation supérieure.","Le pharmacien vérifia la graduation de l\'éprouvette."],"exemplesIncorrects":["Le poète a ménagé une habile graduation dans sa colère.","Sa fièvre monta par lente graduation.","« Je le vis, je rougis » : quelle belle graduation !"],"distracteurs":["progression","dégradé","échelonnement"],"anecdote":"« Graduation » nomme les traits chiffrés d\'un thermomètre ou d\'une règle ; on la confond avec « gradation », qui désigne une progression par degrés. La fièvre monte par gradation, mais on la lit sur la graduation.","categorie":"piege-sens","piege":{"formeFautive":"une graduation dans le ton du discours","explication":"Une montée progressive est une « gradation » ; « graduation » ne désigne que les repères chiffrés d\'un instrument."}},{"id":"litteral","mot":"littéral","nature":"adjectif","definitions":["Qui suit le sens propre, exact des mots, par opposition au sens figuré.","Qui est pris à la lettre, mot pour mot.","Qui est représenté par des lettres (calcul littéral)."],"phonetique":"/li.te.ʁal/","etymologie":"Du bas latin litteralis, « relatif aux lettres », de littera, « lettre ».","registre":"courant","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["textuel","exact","propre"],"antonymes":["figuré","métaphorique","libre"],"exemplesCorrects":["La traduction littérale du proverbe en fausse le sens.","Au sens littéral, « perdre la tête » serait une décapitation.","Le calcul littéral remplace les nombres par des lettres."],"exemplesIncorrects":["Un salon littéral réunissait les écrivains du siècle.","Cet auteur a reçu un grand prix littéral.","Le patrimoine littéral de la France est immense."],"distracteurs":["allégorique","approximatif","métaphorique"],"anecdote":"« Littéral » (au sens propre, mot pour mot) se confond souvent avec « littéraire » (relatif aux lettres, à la littérature). Une traduction littérale suit la lettre ; un prix littéraire récompense un écrivain.","categorie":"piege-sens","piege":{"formeFautive":"un prix littéral","explication":"Ce qui touche à la littérature est « littéraire » ; « littéral » signifie « pris au pied de la lettre »."}},{"id":"effraction","mot":"effraction","nature":"nom féminin","definitions":["Bris d\'une clôture, d\'une porte ou d\'une serrure pour pénétrer quelque part.","Fait de forcer un dispositif de fermeture."],"phonetique":"/e.fʁak.sjɔ̃/","etymologie":"Du bas latin juridique effractura, de effringere, « rompre, enlever en brisant », du latin frangere, « briser ».","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["cambriolage","forcement","fracture"],"antonymes":[],"exemplesCorrects":["Les voleurs sont entrés par effraction dans l\'entrepôt.","La porte forcée révélait une effraction nocturne.","L\'assurance ne couvre le vol qu\'en cas d\'effraction caractérisée."],"exemplesIncorrects":["Rouler sans permis constitue une effraction au code de la route.","Il a commis une effraction en stationnant sur la zone interdite.","Cette effraction au règlement lui vaudra une amende."],"distracteurs":["infraction","intrusion","déprédation"],"anecdote":"« Effraction » et « infraction » partagent le latin frangere, « briser », mais l\'effraction brise un obstacle matériel (porte, serrure) tandis que l\'infraction « brise » une règle. Toute effraction est une infraction, mais l\'inverse est faux.","categorie":"piege-sens","piege":{"formeFautive":"une effraction au code de la route","explication":"Violer une règle est une « infraction » ; « effraction » désigne uniquement le bris d\'une fermeture pour s\'introduire quelque part."}},{"id":"infraction","mot":"infraction","nature":"nom féminin","definitions":["Violation d\'une loi, d\'un règlement ou d\'une convention.","Acte transgressant une norme établie."],"phonetique":"/ɛ̃.fʁak.sjɔ̃/","etymologie":"Du bas latin infractio, « action de briser », de infringere, « briser », du latin frangere.","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["violation","transgression","manquement"],"antonymes":["respect","observance","conformité"],"exemplesCorrects":["Stationner ici constitue une infraction passible d\'amende.","Le contrôleur a relevé plusieurs infractions au règlement.","Toute infraction aux statuts entraîne l\'exclusion."],"exemplesIncorrects":["Les cambrioleurs sont entrés par infraction dans la villa.","La serrure forcée prouve l\'infraction du logement.","L\'assurance exige une trace d\'infraction sur la porte."],"distracteurs":["effraction","délit","contravention"],"anecdote":"On dit fautivement « entrer par infraction » : pour le bris d\'une porte, c\'est « par effraction ». L\'infraction concerne la transgression d\'une règle, l\'effraction le forcement d\'un obstacle matériel.","categorie":"piege-sens","piege":{"formeFautive":"entrer par infraction","explication":"Pénétrer en forçant une fermeture se dit « par effraction » ; « infraction » désigne la violation d\'une règle."}},{"id":"subsidiaire","mot":"subsidiaire","nature":"adjectif","definitions":["Qui vient en complément ou à l\'appui d\'une chose principale, accessoire.","En droit, qui ne s\'applique qu\'à défaut de la disposition principale."],"phonetique":"/syb.zi.djɛʁ/","etymologie":"Du latin subsidiarius, « qui forme la réserve, de renfort », de subsidium, « troupe de réserve, secours ».","registre":"soutenu","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["accessoire","complémentaire","annexe"],"antonymes":["principal","essentiel","primordial"],"exemplesCorrects":["Le concours fut départagé par une question subsidiaire.","Il invoqua, à titre subsidiaire, la prescription des faits.","Ce revenu subsidiaire complète sa pension."],"exemplesIncorrects":["L\'État a versé une subsidiaire aux agriculteurs sinistrés.","Cette entreprise est une subsidiaire du grand groupe américain.","Il touche une subsidiaire mensuelle de la commune."],"distracteurs":["subordonné","marginal","supplétif"],"anecdote":"« Subsidiaire » signifie « accessoire, de complément » : la fameuse question subsidiaire départage les ex æquo. À ne pas confondre avec le faux ami anglais « subsidiary » (filiale d\'une société), ni avec « subside » (aide financière).","categorie":"piege-sens","piege":{"formeFautive":"une subsidiaire du groupe (au sens de filiale)","explication":"« Subsidiaire » est un adjectif signifiant « accessoire » ; la filiale d\'une société se dit « filiale », non « subsidiaire » (calque de l\'anglais subsidiary)."}},{"id":"consommer","mot":"consommer","nature":"verbe","definitions":["User d\'une chose pour ses besoins ; absorber un aliment, une boisson, une énergie.","Mener à son terme, accomplir, parachever (consommer un mariage, une rupture)."],"phonetique":"/kɔ̃.sɔ.me/","etymologie":"Du latin consummare, « faire la somme, achever », de summa, « somme » ; influencé par consumere, « employer entièrement ».","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["absorber","user","parachever"],"antonymes":["produire","économiser","épargner"],"exemplesCorrects":["Cette voiture consomme huit litres aux cent kilomètres.","Leur rupture était désormais consommée.","On consomme moins de viande qu\'autrefois."],"exemplesIncorrects":["L\'incendie a consommé toute la grange en une heure.","Le feu consomma lentement les vieilles poutres.","La rouille consomme peu à peu la carrosserie."],"distracteurs":["consumer","dilapider","ingérer"],"anecdote":"« Consommer » (user, manger ; ou parachever) se confond avec « consumer » (détruire par le feu). On consomme un repas ou un carburant ; le feu, lui, consume une maison. La proximité vient de leurs racines latines voisines, summa et sumere.","categorie":"piege-sens","piege":{"formeFautive":"le feu a consommé la grange","explication":"Détruire par le feu se dit « consumer » ; « consommer » signifie user, absorber ou parachever."}},{"id":"consumer","mot":"consumer","nature":"verbe","definitions":["Détruire, anéantir par le feu.","Au figuré, épuiser, ronger peu à peu (être consumé de chagrin)."],"phonetique":"/kɔ̃.sy.me/","etymologie":"Du latin consumere, « employer entièrement, détruire », de sumere, « prendre ».","registre":"soutenu","niveau":3,"themes":["litteraire","emotions"],"synonymes":["brûler","calciner","dévorer"],"antonymes":["préserver","épargner","conserver"],"exemplesCorrects":["Les flammes consumèrent la bibliothèque entière.","La bougie se consume jusqu\'à la dernière mèche.","Il se consumait d\'un amour sans espoir."],"exemplesIncorrects":["Ce ménage consume trop d\'électricité chaque mois.","Au bistrot, ils ont consumé deux cafés.","Cette berline consume dix litres au cent."],"distracteurs":["consommer","embraser","étioler"],"anecdote":"« Consumer » signifie « détruire par le feu » ou « ronger » (consumé de chagrin) ; on le confond avec « consommer » (user, manger). Un foyer consume du bois ; un consommateur consomme un produit.","categorie":"piege-sens","piege":{"formeFautive":"ce moteur consume trop d\'essence","explication":"User d\'un bien ou d\'un carburant se dit « consommer » ; « consumer » s\'applique à ce que le feu détruit ou à ce qui ronge intérieurement."}},{"id":"comprehensible","mot":"compréhensible","nature":"adjectif","definitions":["Qui peut être compris, intelligible, clair.","Qui se conçoit, qui s\'explique aisément (une réaction compréhensible)."],"phonetique":"/kɔ̃.pʁe.ɑ̃.sibl/","etymologie":"Du latin comprehensibilis, « qui peut être saisi », de comprehendere, « saisir, embrasser ».","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["intelligible","clair","accessible"],"antonymes":["incompréhensible","obscur","hermétique"],"exemplesCorrects":["Son exposé était parfaitement compréhensible.","Sa colère est compréhensible après un tel affront.","Rédige une notice compréhensible par un débutant."],"exemplesIncorrects":["Mon chef s\'est montré compréhensible quand j\'ai expliqué mon retard.","Soyez compréhensible envers les nouveaux venus.","Elle est si compréhensible qu\'elle pardonne tout."],"distracteurs":["compréhensif","perceptible","lisible"],"anecdote":"« Compréhensible » qualifie ce qui peut être compris (un texte clair) ; on le confond avec « compréhensif », qui qualifie une personne indulgente. Un patron compréhensif tolère ; un mode d\'emploi compréhensible se laisse comprendre.","categorie":"piege-sens","piege":{"formeFautive":"un chef compréhensible (au sens d\'indulgent)","explication":"Une personne indulgente est « compréhensive » ; « compréhensible » se dit de ce qui peut être compris."}},{"id":"comprehensif","mot":"compréhensif","nature":"adjectif","definitions":["Qui comprend autrui, indulgent, bienveillant.","En logique, qui se rapporte à la compréhension d\'un concept (par opposition à extensif)."],"phonetique":"/kɔ̃.pʁe.ɑ̃.sif/","etymologie":"Du bas latin comprehensivus, « qui a la faculté de comprendre », de comprehendere, « saisir, embrasser ».","registre":"courant","niveau":2,"themes":["emotions","quotidien"],"synonymes":["indulgent","bienveillant","tolérant"],"antonymes":["intransigeant","sévère","intolérant"],"exemplesCorrects":["Ses parents se sont montrés très compréhensifs.","Un médecin compréhensif met le patient en confiance.","Soyez compréhensif : il traverse une période difficile."],"exemplesIncorrects":["Ce manuel est clair et tout à fait compréhensif.","Sa démonstration reste compréhensive même pour un novice.","Rédige un message bref et compréhensif."],"distracteurs":["compréhensible","conciliant","magnanime"],"anecdote":"« Compréhensif » se dit d\'une personne indulgente ; on le confond avec « compréhensible », qui qualifie ce qui peut être compris. Un professeur peut être compréhensif (tolérant) tout en donnant un cours compréhensible (clair).","categorie":"piege-sens","piege":{"formeFautive":"un texte compréhensif (au sens de clair)","explication":"Ce qui se laisse comprendre est « compréhensible » ; « compréhensif » qualifie la personne indulgente, non le texte clair."}},{"id":"nielle","mot":"nielle","nature":"nom féminin","definitions":["Maladie des céréales causée par un champignon ou un ver parasite, qui noircit les grains.","Plante herbacée des moissons (Agrostemma githago), à fleurs roses, mauvaise herbe des champs de blé."],"phonetique":"/njɛl/","etymologie":"De l\'ancien français neiele, du latin nigella, diminutif de niger « noir », à cause de la couleur sombre des graines ou des grains atteints.","registre":"soutenu","niveau":4,"themes":["nature"],"synonymes":["nielle des blés","githage","lychnis githago"],"antonymes":[],"exemplesCorrects":["La nielle avait gâté une partie de la récolte de blé.","Dans le champ s\'épanouissaient les fleurs mauves de la nielle.","Le meunier redoutait la nielle, qui rendait la farine impropre."],"exemplesIncorrects":["Il portait une bague ornée de fine nielle d\'argent.","L\'orfèvre travaillait la nielle pour décorer le calice."],"distracteurs":["rouille","charançon","ortie"],"anecdote":"On croit souvent que « nielle » désigne l\'incrustation noire d\'argent sur un métal précieux : c\'est exact, mais ce sens est masculin (le nielle, de nieller). Au féminin, la nielle est une plante ou une maladie des céréales.","categorie":"piege-sens","piege":{"formeFautive":"le nielle (pour la plante ou la maladie)","explication":"Au masculin, le nielle désigne une incrustation d\'émail noir sur un métal. La plante des moissons et la maladie des céréales s\'emploient au féminin : la nielle."}},{"id":"friche","mot":"friche","nature":"nom féminin","definitions":["Terrain non cultivé, laissé à l\'abandon, où pousse une végétation spontanée.","Au figuré, ce qui reste inexploité ou inutilisé."],"phonetique":"/fʁiʃ/","etymologie":"Du moyen néerlandais versch « frais, récent », par l\'ancien français friche « terre non cultivée ».","registre":"courant","niveau":2,"themes":["nature","quotidien"],"synonymes":["jachère","lande","terrain vague"],"antonymes":["culture","champ cultivé"],"exemplesCorrects":["Derrière l\'usine désaffectée s\'étendait une vaste friche industrielle.","Le terrain est tombé en friche depuis le départ des fermiers.","Son talent est resté en friche faute d\'occasions."],"exemplesIncorrects":["Il a récolté une belle friche de blé cet été.","Les jardiniers ont planté des rosiers dans cette friche bien entretenue."],"distracteurs":["guéret","garrigue","prairie"],"anecdote":"Les « friches industrielles » des anciennes usines sont aujourd\'hui reconverties en lieux culturels, comme la Friche la Belle de Mai à Marseille.","categorie":"mot-rare"},{"id":"maquis","mot":"maquis","nature":"nom masculin","definitions":["Végétation dense et touffue, faite d\'arbustes et de broussailles, propre aux sols siliceux du pourtour méditerranéen.","Par extension, lieu retiré ; au figuré, enchevêtrement inextricable (le maquis d\'une procédure)."],"phonetique":"/ma.ki/","etymologie":"De l\'italien de Corse macchia « tache, broussaille », du latin macula « tache ».","registre":"courant","niveau":2,"themes":["nature","regionalismes"],"synonymes":["garrigue","broussaille","fourré"],"antonymes":["clairière","plaine"],"exemplesCorrects":["Le sanglier disparut dans l\'épaisseur du maquis corse.","Prendre le maquis signifiait, sous l\'Occupation, rejoindre la résistance.","On se perd dans le maquis des formalités administratives."],"exemplesIncorrects":["Il a repeint le maquis de sa cuisine en bleu.","Nous avons traversé le maquis à la nage avant l\'orage."],"distracteurs":["taillis","garenne","halage"],"anecdote":"« Prendre le maquis » est passé dans la langue commune pendant la Seconde Guerre mondiale : les résistants se cachaient dans cette végétation impénétrable.","categorie":"mot-rare"},{"id":"venelle","mot":"venelle","nature":"nom féminin","definitions":["Petite rue étroite ; ruelle, surtout entre des maisons ou des jardins."],"phonetique":"/və.nɛl/","etymologie":"Diminutif, par le bas latin venella, du latin vena « veine », par analogie avec un passage étroit.","registre":"littéraire","niveau":4,"themes":["quotidien","litteraire"],"synonymes":["ruelle","passage","venel"],"antonymes":["avenue","boulevard"],"exemplesCorrects":["Ils s\'engouffrèrent dans une venelle obscure pour échapper à la foule.","Les venelles du vieux quartier sentaient le pain chaud.","Une venelle pavée serpentait entre les jardins clos."],"exemplesIncorrects":["Ils ont remonté la large venelle à six voies en voiture.","La venelle débouchait sur l\'autoroute saturée."],"distracteurs":["impasse","esplanade","courette"],"anecdote":"En Bretagne et en Normandie, les venelles désignaient autrefois les passages servant à mener le bétail entre les habitations.","categorie":"mot-rare"},{"id":"sente","mot":"sente","nature":"nom féminin","definitions":["Petit sentier étroit, souvent en pleine nature ou à travers champs."],"phonetique":"/sɑ̃t/","etymologie":"Du latin semita « sentier, petit chemin ».","registre":"littéraire","niveau":4,"themes":["nature","litteraire"],"synonymes":["sentier","layon","chemin"],"antonymes":["route","avenue"],"exemplesCorrects":["Une sente herbeuse menait jusqu\'au lavoir abandonné.","Ils gravirent la sente escarpée qui longeait la falaise.","La sente se perdait dans les fougères du sous-bois."],"exemplesIncorrects":["L\'autoroute traverse la région par une immense sente bétonnée.","Il a garé son camion au bout de la sente à quatre voies."],"distracteurs":["orée","haie","lisière"],"anecdote":"Le mot, hérité du latin semita, a aussi donné « sentier » par l\'ancien français : la sente en est la forme la plus courte et la plus ancienne.","categorie":"mot-rare"},{"id":"noue","mot":"noue","nature":"nom féminin","definitions":["Terre grasse et humide, prairie marécageuse ; ancien lit d\'un cours d\'eau.","Fossé large et peu profond aménagé pour recueillir et drainer les eaux de pluie."],"phonetique":"/nu/","etymologie":"Du gaulois nauda « terrain marécageux », à l\'origine de nombreux noms de lieux humides.","registre":"soutenu","niveau":4,"themes":["nature"],"synonymes":["prairie humide","marécage","fossé"],"antonymes":["coteau","hauteur"],"exemplesCorrects":["Le bétail paissait dans la noue gorgée d\'eau après la crue.","On a creusé une noue paysagère pour absorber les eaux de ruissellement.","Les iris des marais fleurissaient au bord de la noue."],"exemplesIncorrects":["Ils ont planté des oliviers en plein sur la noue aride et caillouteuse.","La noue dominait toute la vallée du haut de la colline."],"distracteurs":["combe","lande","guéret"],"anecdote":"En toiture, le mot « noue » désigne aussi l\'angle rentrant où se rencontrent deux versants d\'un toit, par où l\'eau s\'écoule : même idée d\'un creux qui draine l\'eau.","categorie":"mot-rare"},{"id":"coteau","mot":"coteau","nature":"nom masculin","definitions":["Versant d\'une colline ; petite éminence, souvent plantée de vignes."],"phonetique":"/kɔ.to/","etymologie":"Diminutif de l\'ancien français coste « côte, pente », du latin costa « côté, flanc ».","registre":"courant","niveau":2,"themes":["nature"],"synonymes":["versant","colline","côte"],"antonymes":["plaine","vallée"],"exemplesCorrects":["La vigne s\'étageait sur le coteau exposé au sud.","Du haut du coteau, on apercevait les toits du village.","Les maisons s\'accrochaient au flanc du coteau."],"exemplesIncorrects":["Ils ont pêché de belles truites dans le coteau ce matin.","Le bateau a remonté le coteau jusqu\'à l\'écluse."],"distracteurs":["talweg","ravin","guéret"],"anecdote":"Les « coteaux du Layon » ou les « coteaux de Provence » doivent leur nom à ces versants ensoleillés idéaux pour la culture de la vigne.","categorie":"mot-rare"},{"id":"talweg","mot":"talweg","nature":"nom masculin","definitions":["Ligne joignant les points les plus bas du fond d\'une vallée, suivant la plus grande pente ; en météorologie, axe d\'une zone de basses pressions."],"phonetique":"/tal.vɛɡ/","etymologie":"De l\'allemand Talweg, de Tal « vallée » et Weg « chemin », littéralement « chemin de la vallée ».","registre":"soutenu","niveau":5,"themes":["nature","emprunts"],"synonymes":["thalweg","ligne de fond","coulière"],"antonymes":["ligne de crête","interfluve"],"exemplesCorrects":["Les eaux de pluie convergent naturellement vers le talweg.","Le géographe a tracé le talweg sur la carte topographique.","Un talweg dépressionnaire descendait des Açores vers la péninsule."],"exemplesIncorrects":["Le randonneur a planté sa tente au sommet du talweg, sur la crête venteuse.","Le talweg culminait à trois mille mètres d\'altitude."],"distracteurs":["versant","coteau","moraine"],"anecdote":"On écrit souvent « thalweg » avec un h, graphie ancienne calquée sur l\'allemand d\'avant 1901 ; la forme rectifiée « talweg », sans h, est aujourd\'hui recommandée. Le g final se prononce, et le w comme un v : /tal.vɛɡ/.","categorie":"piege-orthographe","piege":{"formeFautive":"thalweg / prononcé /tal.wɛɡ/","explication":"La graphie « thalweg », avec h, reproduit l\'orthographe allemande d\'avant la réforme de 1901 ; le français a retenu « talweg ». De plus, le w se prononce v, comme en allemand : on dit /tal.vɛɡ/, non /tal.wɛɡ/."}},{"id":"moutonner","mot":"moutonner","nature":"verbe","definitions":["Se couvrir de petites vagues blanches d\'écume, en parlant de la mer ; se garnir de petits nuages blancs arrondis, en parlant du ciel."],"phonetique":"/mu.tɔ.ne/","etymologie":"Dérivé de mouton, par analogie entre l\'écume ou les nuages blancs et la toison de l\'animal.","registre":"littéraire","niveau":3,"themes":["nature","litteraire"],"synonymes":["écumer","friser","onduler"],"antonymes":["se calmer","s\'apaiser"],"exemplesCorrects":["Sous le vent du large, la mer commençait à moutonner.","Le ciel moutonnait de petits nuages annonçant le beau temps.","Les vagues moutonnaient jusqu\'à la ligne d\'horizon."],"exemplesIncorrects":["Le berger a moutonné son troupeau dans l\'enclos.","Elle a moutonné la laine avant de la filer."],"distracteurs":["clapoter","ondoyer","frissonner"],"anecdote":"Un ciel « moutonné » a donné le dicton « ciel moutonné, dans trois jours mouillé » : ces cumulus annoncent souvent un changement de temps.","categorie":"mot-rare"},{"id":"pleuvioter","mot":"pleuvioter","nature":"verbe","definitions":["Pleuvoir très légèrement, par petites gouttes fines et intermittentes."],"phonetique":"/plø.vjɔ.te/","etymologie":"Dérivé de pleuvoir avec le suffixe fréquentatif et péjoratif -oter, marquant une action faible et répétée.","registre":"familier","niveau":3,"themes":["nature","quotidien"],"synonymes":["bruiner","pleuvasser","crachiner"],"antonymes":["pleuvoir à verse"],"exemplesCorrects":["Il pleuviote depuis ce matin, juste de quoi mouiller le trottoir.","On est sortis malgré le ciel gris qui pleuviotait.","Ça pleuviote à peine, inutile de prendre le grand parapluie."],"exemplesIncorrects":["L\'orage a pleuvioté toute la nuit, inondant les caves.","Il pleuviotait des trombes d\'eau sur l\'autoroute."],"distracteurs":["grésiller","ruisseler","venter"],"anecdote":"Le français regorge de verbes pour la pluie faible : bruiner, crachiner, pleuvasser, pleuvoter, pluviner — autant de nuances pour décrire un ciel maussade sans averse franche.","categorie":"mot-rare"},{"id":"cramine","mot":"cramine","nature":"nom féminin","definitions":["Froid très vif, gel intense (français régional du Sud-Est et de Suisse romande)."],"phonetique":"/kʁa.min/","etymologie":"Du latin cremare « brûler », le froid mordant étant ressenti comme une brûlure.","registre":"familier","niveau":5,"themes":["nature","regionalismes"],"synonymes":["froidure","gel","bise"],"antonymes":["canicule","douceur"],"exemplesCorrects":["Couvre-toi bien, il fait une de ces cramines ce matin !","La cramine de janvier avait gelé toutes les conduites.","On grelottait dans la cramine en attendant le bus."],"exemplesIncorrects":["Quelle cramine cet été, on a frôlé les quarante degrés !","Il transpirait sous la cramine du mois d\'août."],"distracteurs":["frimas","verglas","embrun"],"anecdote":"« Cramine » illustre un paradoxe étymologique savoureux : un mot du froid issu d\'un verbe latin signifiant « brûler », car le gel intense pince la peau comme une brûlure.","categorie":"mot-rare"},{"id":"roupie","mot":"roupie","nature":"nom féminin","definitions":["Goutte de morve qui pend au nez.","Chose de très peu de valeur, sans importance (surtout dans la locution « roupie de sansonnet »)."],"phonetique":"/ʁu.pi/","etymologie":"Attesté depuis le XIIIe siècle, peut-être issu du grec ancien ῥύπος (« crasse, saleté »). Cet homonyme n\'a aucun rapport avec la roupie, monnaie de l\'Inde, venue du portugais rupia, lui-même du sanskrit rūpya (« argent »).","registre":"familier","niveau":4,"themes":["quotidien","regionalismes"],"synonymes":["morve","goutte","broutille"],"antonymes":["trésor","merveille"],"exemplesCorrects":["L\'enfant enrhumé avait une roupie au bout du nez.","Ton cadeau, à côté du sien, c\'est de la roupie de sansonnet.","Il a vendu sa collection pour une roupie de sansonnet."],"exemplesIncorrects":["Il a changé ses roupies à la banque avant de partir en Inde.","Le touriste a payé l\'entrée du temple en roupies."],"distracteurs":["guenille","rognure","fadaise"],"anecdote":"Beaucoup pensent que « roupie de sansonnet » fait allusion à la monnaie indienne. En réalité, la roupie désigne ici une goutte au nez : l\'expression dit donc qu\'une chose ne vaut pas même la morve d\'un petit étourneau.","categorie":"piege-sens","piege":{"formeFautive":"la roupie = la monnaie de l\'Inde","explication":"Dans « roupie de sansonnet », roupie ne désigne pas la monnaie indienne mais une goutte de morve ; l\'expression signifie « chose insignifiante »."}},{"id":"tomber-des-cordes","mot":"tomber des cordes","nature":"locution","definitions":["Pleuvoir très fort, à verse."],"phonetique":"/tɔ̃.be de kɔʁd/","etymologie":"Image populaire où les filets de pluie serrés et continus évoquent des cordes tendues entre le ciel et la terre.","registre":"familier","niveau":2,"themes":["nature","quotidien"],"synonymes":["pleuvoir à verse","pleuvoir à seaux","pleuvoir à torrents"],"antonymes":["bruiner","crachiner"],"exemplesCorrects":["Ne sors pas maintenant, il tombe des cordes.","On a annulé le pique-nique : ça tombait des cordes depuis l\'aube.","Regarde par la fenêtre, il tombe des cordes."],"exemplesIncorrects":["Le grimpeur a tombé des cordes du haut de la falaise.","Elle range les cordes qui tombent du grenier."],"distracteurs":["grêler","venter","ruisseler"],"anecdote":"L\'anglais emploie une image plus pittoresque encore pour la même idée : « it\'s raining cats and dogs », alors que le français préfère la sobriété tendue des cordes.","categorie":"expression"},{"id":"il-fait-un-froid-de-canard","mot":"il fait un froid de canard","nature":"locution","definitions":["Il fait extrêmement froid, un froid très vif."],"phonetique":"/il fɛ œ̃ fʁwa də ka.naʁ/","etymologie":"Expression liée à la chasse au canard, qui se pratique en automne et en hiver, par temps glacial, quand les oiseaux gagnent les plans d\'eau. Première attestation relevée en 1888.","registre":"courant","niveau":2,"themes":["nature","quotidien"],"synonymes":["froid de loup","froid glacial","froid sibérien"],"antonymes":["chaleur étouffante","canicule"],"exemplesCorrects":["Couvre-toi bien, il fait un froid de canard ce matin.","Sur le quai désert, il faisait un froid de canard.","En janvier, là-bas, il fait un froid de canard."],"exemplesIncorrects":["Il a mangé un froid de canard au restaurant.","Le froid de canard nageait sur l\'étang gelé."],"distracteurs":["froidure","engelure","verglas"],"anecdote":"Le froid de l\'expression vient moins du canard que du chasseur : c\'est par grand gel, posté immobile à l\'affût près des marais, qu\'on attend le passage des palmipèdes.","categorie":"expression"},{"id":"un-temps-de-chien","mot":"un temps de chien","nature":"locution","definitions":["Un très mauvais temps, pluvieux, venteux ou orageux."],"phonetique":"/œ̃ tɑ̃ də ʃjɛ̃/","etymologie":"Le mot chien sert depuis longtemps de péjoratif intensif en français (« un mal de chien », « une vie de chien ») pour désigner ce qui est pénible ou détestable.","registre":"courant","niveau":2,"themes":["nature","quotidien"],"synonymes":["sale temps","temps de cochon","intempéries"],"antonymes":["temps radieux","beau fixe"],"exemplesCorrects":["Quel temps de chien pour une randonnée !","Ils ont navigué par un temps de chien.","Avec ce temps de chien, mieux vaut rester au coin du feu."],"exemplesIncorrects":["Le vétérinaire a soigné un temps de chien malade.","Elle promène son temps de chien sous la pluie."],"distracteurs":["bourrasque","ondée","grisaille"],"anecdote":"Le chien donne son nom à toute une famille d\'expressions négatives : « un mal de chien », « un caractère de chien », « être malade comme un chien » ; le pauvre animal y incarne invariablement la pénibilité.","categorie":"expression"},{"id":"se-cailler","mot":"se cailler","nature":"verbe","definitions":["Avoir très froid, geler (familier)."],"phonetique":"/sə ka.je/","etymologie":"Emploi figuré de cailler, « se figer, prendre en caillots » (du latin coagulare), comme si le froid figeait le sang dans les veines.","registre":"familier","niveau":3,"themes":["quotidien","emotions"],"synonymes":["geler","grelotter","se geler"],"antonymes":["transpirer","suer","étouffer"],"exemplesCorrects":["On se caille dehors, rentre vite.","Sans manteau, je me suis caillé toute la soirée.","Ferme la fenêtre, on se caille ici."],"exemplesIncorrects":["Le lait s\'est caillé pour avoir trop chaud au soleil.","Elle se caille de bonheur devant le feu de cheminée."],"distracteurs":["frissonner","trembloter","claquer"],"anecdote":"Le verbe vient du lait qui caille, c\'est-à-dire qui se fige ; par image, quand on « se caille », c\'est comme si le froid faisait prendre le sang en masse.","categorie":"expression"},{"id":"peler-de-froid","mot":"peler de froid","nature":"locution","definitions":["Souffrir d\'un froid intense, être transi de froid."],"phonetique":"/pə.le də fʁwa/","etymologie":"Du verbe peler (du latin pilare, « ôter le poil », puis « écorcher »), l\'image étant celle d\'un froid si vif qu\'il semble arracher la peau.","registre":"familier","niveau":2,"themes":["quotidien","emotions"],"synonymes":["grelotter","geler","être transi"],"antonymes":["avoir chaud","suffoquer"],"exemplesCorrects":["On pelait de froid sur le quai de la gare.","Mets un bonnet, tu vas peler de froid.","À l\'arrêt de bus, je pelais de froid."],"exemplesIncorrects":["Il pèle une orange de froid avant le dessert.","La peinture pèle de froid sur les vieux volets."],"distracteurs":["frissonner","trembloter","engourdir"],"anecdote":"L\'expression joue sur le double sens de « peler » : on pèle un fruit en lui ôtant sa peau, et l\'on « pèle de froid » comme si le gel nous écorchait.","categorie":"expression"},{"id":"a-la-fraiche","mot":"à la fraîche","nature":"locution","definitions":["Au moment frais de la journée, tôt le matin ou en soirée, quand la chaleur est tombée."],"phonetique":"/a la fʁɛʃ/","etymologie":"Locution formée sur l\'adjectif fraîche substantivé au féminin, désignant la fraîcheur de l\'air ; ancien cri des marchands ambulants de la fin du XVIIe siècle (« à la fraîche, qui veut boire ! »).","registre":"courant","niveau":2,"themes":["quotidien","nature"],"synonymes":["au frais","à la fraîcheur"],"antonymes":["en pleine chaleur","sous le soleil de midi"],"exemplesCorrects":["En été, on part marcher à la fraîche, vers six heures.","Les vendanges commencent à la fraîche.","Profitons du jardin à la fraîche, avant qu\'il fasse trop chaud."],"exemplesIncorrects":["Il a mangé une salade à la fraîche bien assaisonnée.","Elle a repeint le mur à la fraîche pour qu\'il sèche vite."],"distracteurs":["à l\'aube","au crépuscule","à la nuitée"],"anecdote":"« À la fraîche » était autrefois le cri des marchands d\'eau et de boissons fraîches dans les rues ; l\'expression a glissé du produit vendu au moment de la journée où l\'air est frais.","categorie":"expression"},{"id":"ramequin","mot":"ramequin","nature":"nom masculin","definitions":["Petit récipient individuel, en porcelaine, verre ou terre, servant à cuire ou présenter une préparation au four ou au bain-marie.","En Suisse romande, tarte ou préparation chaude au fromage."],"phonetique":"/ʁam.kɛ̃/","etymologie":"Du néerlandais rammeken, diminutif lié à rahm (« crème »), désignant à l\'origine une petite préparation chaude au fromage.","registre":"courant","niveau":3,"themes":["quotidien","emprunts","regionalismes"],"synonymes":["coupelle","godet","cassolette"],"antonymes":[],"exemplesCorrects":["Répartissez la crème dans quatre ramequins avant d\'enfourner.","Elle sert les œufs cocotte dans de jolis ramequins.","À Lausanne, on s\'est régalés d\'un ramequin au fromage."],"exemplesIncorrects":["Il a planté un ramequin dans le jardin pour faire pousser des fleurs.","Le maçon a gâché son mortier dans un grand ramequin de chantier."],"distracteurs":["bol","timbale","soucoupe"],"anecdote":"Le mot a voyagé : d\'abord une petite pâtisserie au fromage venue des Pays-Bas, il a fini par désigner, par métonymie, le récipient dans lequel on la cuisait.","categorie":"piege-sens","piege":{"explication":"On croit souvent que ramequin ne désigne que le petit récipient ; en Suisse romande, le mot nomme d\'abord une tarte chaude au fromage, sens d\'origine du terme."}},{"id":"cornet","mot":"cornet","nature":"nom masculin","definitions":["En Suisse et en Belgique, sac en papier ou en plastique, notamment un sac de courses.","Petit récipient ou emballage de forme conique."],"phonetique":"/kɔʁ.nɛ/","etymologie":"Diminutif de corne, par allusion à la forme effilée et recourbée des premiers cornets de papier roulés en pointe.","registre":"courant","niveau":3,"themes":["regionalismes","quotidien"],"synonymes":["sac","poche","sachet"],"antonymes":[],"exemplesCorrects":["À la caisse genevoise, on m\'a demandé si je voulais un cornet.","Range les légumes dans le cornet en papier.","En Belgique, on transporte ses achats dans un cornet."],"exemplesIncorrects":["Le trompettiste a fait sonner son cornet pendant le défilé.","Le médecin a examiné les cornets dans son nez."],"distracteurs":["cabas","panier","besace"],"anecdote":"Pour un Français, un cornet évoque la glace ou l\'instrument à pistons ; pour un Suisse ou un Belge, c\'est tout simplement le sac qu\'on remplit à la caisse du magasin.","categorie":"piege-sens","piege":{"explication":"En France, « cornet » désigne surtout l\'emballage conique d\'une glace ; en Suisse et en Belgique, le mot signifie couramment « sac de courses »."}},{"id":"panosse","mot":"panosse","nature":"nom féminin","definitions":["En Suisse romande et dans le centre-est de la France, serpillière servant à laver les sols."],"phonetique":"/pa.nɔs/","etymologie":"Du bas latin pannucia, « haillon, guenille », dérivé de pannus, « morceau d\'étoffe » ; le terme est attesté à Fribourg dès 1411.","registre":"courant","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["serpillière","wassingue","loque"],"antonymes":[],"exemplesCorrects":["Passe un coup de panosse, le carrelage est plein de boue.","À Lausanne, on demande la panosse, pas la serpillière.","Elle a essoré la panosse dans le seau."],"exemplesIncorrects":["Il a accroché une panosse au mur comme tableau précieux.","Le sommelier a versé une panosse dans le verre du client."],"distracteurs":["lavette","torchon","éponge"],"anecdote":"La France a une mosaïque de mots pour la serpillière : « panosse » en Suisse romande et en Rhône-Alpes, « wassingue » dans le Nord, « cinse » ou « toile à laver » ailleurs ; un même objet, autant de régionalismes.","categorie":"mot-rare"},{"id":"linge","mot":"linge","nature":"nom masculin","definitions":["En Suisse romande, serviette de toilette ou de bain.","Ensemble des pièces de tissu d\'usage domestique (draps, nappes, sous-vêtements)."],"phonetique":"/lɛ̃ʒ/","etymologie":"Du latin lineus, « de lin », l\'étoffe ayant d\'abord été tissée à partir de cette fibre.","registre":"courant","niveau":3,"themes":["regionalismes","quotidien"],"synonymes":["serviette","essuie-mains"],"antonymes":[],"exemplesCorrects":["Prends un linge propre avant d\'aller à la piscine.","À l\'hôtel valaisan, le linge de bain était moelleux.","N\'oublie pas ton linge pour aller au lac."],"exemplesIncorrects":["Il a versé du linge dans la machine à café.","Le boucher a découpé un beau morceau de linge."],"distracteurs":["drap","nappe","torchon"],"anecdote":"Demandez « un linge » à Genève et l\'on vous tendra une serviette de bain ; le même mot, en France, désigne plutôt, de façon non comptable, le linge de maison ou de corps en général.","categorie":"piege-sens","piege":{"explication":"En France, « linge » désigne l\'ensemble du linge domestique ; en Suisse romande, le mot signifie spécifiquement « serviette de toilette »."}},{"id":"natel","mot":"natel","nature":"nom masculin","definitions":["En Suisse, téléphone portable, téléphone mobile."],"phonetique":"/na.tɛl/","etymologie":"Mot-valise tiré de l\'allemand « Nationales Autotelefon » (« téléphone automobile national »), service lancé par les PTT suisses en 1978, puis marque déposée par Swisscom, passée dans l\'usage courant.","registre":"courant","niveau":4,"themes":["regionalismes","emprunts"],"synonymes":["portable","mobile","téléphone"],"antonymes":[],"exemplesCorrects":["Je t\'appelle sur ton natel ce soir.","Mon natel n\'a plus de batterie.","Donne-moi ton numéro de natel."],"exemplesIncorrects":["Il a branché le natel pour faire griller le pain.","Elle range ses vêtements dans le natel de la chambre."],"distracteurs":["combiné","récepteur","interphone"],"anecdote":"Comme « Frigidaire » pour le réfrigérateur, « Natel » est une marque devenue nom commun : Swisscom a abandonné le terme commercialement en 2017, mais les Suisses continuent de dire « natel » pour leur portable.","categorie":"mot-rare"},{"id":"fourbi","mot":"fourbi","nature":"nom masculin","definitions":["Désordre, ensemble d\'objets en pagaille.","Ensemble d\'affaires, d\'effets personnels d\'un individu (familier)."],"phonetique":"/fuʁ.bi/","etymologie":"Participe passé substantivé du verbe fourbir (« nettoyer, astiquer une arme »), issu du francique fürbjan ; le mot a d\'abord désigné, dans l\'argot militaire, l\'équipement du soldat avant de prendre le sens familier de « désordre ».","registre":"familier","niveau":2,"themes":["quotidien"],"synonymes":["bazar","capharnaüm","fatras"],"antonymes":["ordre","rangement"],"exemplesCorrects":["Range-moi tout ce fourbi qui traîne dans l\'entrée.","Il a entassé tout son fourbi dans un vieux sac de marin.","Quel fourbi dans ce grenier, on ne sait plus où donner de la tête."],"exemplesIncorrects":["Le professeur a expliqué la théorie avec un grand fourbi.","Elle a chanté ce fourbi d\'une voix cristalline."],"distracteurs":["fourbe","fourreau","fourgon"],"anecdote":"Le mot vient du jargon des casernes : le « fourbi » désignait l\'attirail que le soldat devait fourbir, c\'est-à-dire astiquer, avant l\'inspection.","categorie":"mot-rare"},{"id":"tracasser","mot":"tracasser","nature":"verbe","definitions":["Préoccuper, inquiéter, causer du souci à quelqu\'un.","Se tracasser : se faire du souci, se tourmenter."],"phonetique":"/tʁa.ka.se/","etymologie":"Formé au XVe siècle sur trac ou traque, avec le suffixe fréquentatif -asser ; le mot a d\'abord signifié « traquer les bêtes », avant de prendre vers 1588 le sens d\'« inquiéter, tourmenter ».","registre":"courant","niveau":1,"themes":["emotions"],"synonymes":["inquiéter","préoccuper","tourmenter"],"antonymes":["rassurer","apaiser","tranquilliser"],"exemplesCorrects":["Cette question le tracasse depuis des jours.","Ne te tracasse pas, tout finira par s\'arranger.","Ce qui me tracasse, c\'est son silence prolongé."],"exemplesIncorrects":["Il a tracassé une magnifique aquarelle pour l\'exposition.","Le boulanger a tracassé le pain avant la cuisson."],"distracteurs":["traquer","tracter","harasser"],"anecdote":"Avant de signifier « inquiéter », tracasser voulait dire « traquer, poursuivre le gibier en tous sens » : l\'idée d\'agitation incessante a glissé vers celle du souci qui ne nous lâche pas.","categorie":"mot-rare"},{"id":"mitaine","mot":"mitaine","nature":"nom féminin","definitions":["Moufle, gant qui couvre la main et le poignet sans séparer les doigts (sauf parfois le pouce).","Gant laissant à nu l\'extrémité des doigts.","Au Québec, gant en général, et tout particulièrement la moufle."],"phonetique":"/mi.tɛn/","etymologie":"De l\'ancien français mite, nom familier de la chatte, par allusion à la patte velue de l\'animal, avec le suffixe diminutif -aine.","registre":"courant","niveau":2,"themes":["quotidien","regionalismes"],"synonymes":["moufle","gant"],"antonymes":[],"exemplesCorrects":["L\'enfant avait perdu une mitaine dans la neige.","Elle tricotait des mitaines de laine pour l\'hiver.","Au Québec, on dit « mes mitaines » là où la France dirait « mes moufles »."],"exemplesIncorrects":["Il a chaussé ses mitaines avant la randonnée en montagne.","La mitaine de la fenêtre grinçait dans le vent."],"distracteurs":["manique","mitre","mantille"],"anecdote":"Le mot dérive de « mite », ancien nom affectueux de la chatte : la mitaine évoquait à l\'origine la douce patte de l\'animal.","categorie":"piege-sens","piege":{"explication":"En France, la mitaine laisse souvent les doigts à découvert et se distingue de la moufle ; au Québec, le terme désigne la moufle elle-même et, plus largement, n\'importe quel gant."}},{"id":"poudrerie","mot":"poudrerie","nature":"nom féminin","definitions":["Au Québec, neige fine déjà tombée puis soulevée et chassée par le vent.","Ailleurs, fabrique de poudre à canon ou d\'explosifs."],"phonetique":"/pu.dʁə.ʁi/","etymologie":"Dérivé de poudre, du latin pulvis, pulveris (« poussière »), avec le suffixe -erie ; au Québec, la neige soulevée évoque une fine poussière blanche.","registre":"courant","niveau":3,"themes":["nature","regionalismes"],"synonymes":["poudrin","rafale"],"antonymes":[],"exemplesCorrects":["La poudrerie réduisait la visibilité à quelques mètres sur l\'autoroute.","Le bulletin météo annonce de la poudrerie pour la soirée.","Sous la poudrerie, la route disparaissait sous des volutes de neige."],"exemplesIncorrects":["La poudrerie tombait doucement du ciel ce matin-là.","Ils ont allumé la poudrerie pour réchauffer la cabane."],"distracteurs":["bruine","verglas","givre"],"anecdote":"Au Québec, la poudrerie n\'est pas une neige qui tombe mais une neige déjà au sol que le vent reprend et chasse en nappes mouvantes.","categorie":"mot-rare"},{"id":"bordee","mot":"bordée","nature":"nom féminin","definitions":["Au Québec, grosse chute de neige.","Décharge simultanée de tous les canons d\'un même côté d\'un navire.","Distance qu\'un voilier parcourt sans changer d\'amures ; tirer une bordée."],"phonetique":"/bɔʁ.de/","etymologie":"Dérivé de bord, mot d\'origine germanique désignant le flanc du navire ; la « bordée » fut d\'abord la salve tirée par un bord du vaisseau.","registre":"courant","niveau":3,"themes":["nature","regionalismes"],"synonymes":["salve","rafale"],"antonymes":[],"exemplesCorrects":["Une bordée de neige est tombée pendant la nuit, paralysant la ville.","Le navire riposta par une bordée qui ébranla la frégate ennemie.","Le marin lâcha une bordée de jurons retentissants."],"exemplesIncorrects":["Il a peint la bordée du tableau d\'un trait rouge vif.","Elle a cousu une jolie bordée de dentelle à sa robe."],"distracteurs":["bordure","bourrasque","embardée"],"anecdote":"« Tirer une bordée » signifiait à l\'origine, en marine, naviguer un certain temps sans virer ; l\'expression a pris le sens familier de « faire la fête » à terre.","categorie":"piege-sens","piege":{"explication":"On confond la bordée (sens québécois : grosse chute de neige ; sens marin : salve de canon) avec la bordure ; ce sont deux mots distincts, la bordée venant de « bord » de navire."}},{"id":"frette","mot":"frette","nature":"adjectif","definitions":["Au Québec, familièrement, très froid (en parlant du temps, de l\'eau, d\'un objet).","Par extension, désagréable ou pénible (une situation « frette »)."],"phonetique":"/fʁɛt/","etymologie":"Du latin frigidus (« froid »), comme l\'ancien français freid ; frette est une forme dialectale conservée au Québec, parallèle à l\'évolution de rigidus en raide.","registre":"familier","niveau":3,"themes":["nature","regionalismes"],"synonymes":["froid","glacial","glacé"],"antonymes":["chaud","tiède"],"exemplesCorrects":["Il fait frette à matin, mets ta tuque.","L\'eau du lac était frette même en plein été.","On n\'est pas sortis : il faisait bien trop frette dehors."],"exemplesIncorrects":["Cette soupe est délicieusement frette et parfumée au safran.","Il a posé une frette autour du moyeu pour le réchauffer."],"distracteurs":["fraîche","frêle","frileuse"],"anecdote":"« Frette » n\'est pas une déformation paresseuse de « froid » : c\'est une forme dialectale ancienne issue du latin frigidus, conservée au Québec là où le français standard a gardé « froid ».","categorie":"mot-rare"},{"id":"achaler","mot":"achaler","nature":"verbe","definitions":["Au Québec, familièrement, importuner, embêter, déranger quelqu\'un de façon répétée.","Dans l\'ouest de la France, accabler de chaleur, incommoder."],"phonetique":"/a.ʃa.le/","etymologie":"Dérivé dialectal de chaler, variante de l\'ancien verbe chaloir (« chauffer »), issu du latin calere (« être chaud ») ; l\'idée d\'accablement par la chaleur a glissé vers celle d\'agacement.","registre":"familier","niveau":4,"themes":["emotions","regionalismes"],"synonymes":["importuner","embêter","agacer"],"antonymes":["laisser tranquille","apaiser"],"exemplesCorrects":["Arrête de m\'achaler avec tes questions, je travaille.","Les moustiques nous ont achalés toute la soirée.","Il s\'est fait achaler par les vendeurs dès l\'entrée du magasin."],"exemplesIncorrects":["Elle a achalé un superbe gâteau pour l\'anniversaire.","Le maçon a achalé le mur de briques rouges."],"distracteurs":["accabler","achalander","harceler"],"anecdote":"« Achaler » et « achalandé » n\'ont aucun lien : le premier vient de chaloir (être chaud), le second de chaland (le client). On dérange l\'un, on remplit l\'autre de clients.","categorie":"mot-rare"},{"id":"niaiseux","mot":"niaiseux","nature":"adjectif","definitions":["Au Québec, familièrement, niais, sot, dépourvu d\'intelligence ou de jugement.","Sans intérêt, insignifiant (un film niaiseux)."],"phonetique":"/njɛ.zø/","etymologie":"Dérivé québécois de niais (de l\'ancien français niais, « pris au nid », en parlant d\'un oiseau de fauconnerie), avec le suffixe -eux.","registre":"familier","niveau":3,"themes":["emotions","regionalismes"],"synonymes":["niais","sot","stupide"],"antonymes":["malin","futé","intelligent"],"exemplesCorrects":["Arrête de faire le niaiseux et réponds sérieusement.","C\'est un film niaiseux, on n\'a pas ri une seule fois.","Il a posé une question vraiment niaiseuse devant tout le monde."],"exemplesIncorrects":["Ce raisonnement est d\'une finesse niaiseuse remarquable.","Le savant a livré une démonstration niaiseuse et brillante."],"distracteurs":["nigaud","nébuleux","niaisé"],"anecdote":"« Niais » désignait à l\'origine, en fauconnerie, l\'oiseau encore au nid, donc inexpérimenté ; le québécois en a tiré « niaiseux » avec son suffixe -eux caractéristique.","categorie":"mot-rare"},{"id":"barrer","mot":"barrer","nature":"verbe","definitions":["Tracer un trait, rayer ce qui est écrit ; obstruer un passage.","Au Québec et dans l\'ouest de la France, verrouiller, fermer à clé une porte.","En marine, tenir la barre, gouverner un bateau."],"phonetique":"/ba.ʁe/","etymologie":"Dérivé de barre, du bas latin barra (« barre, traverse »), désignant la pièce qui ferme ou obstrue.","registre":"courant","niveau":2,"themes":["quotidien","regionalismes"],"synonymes":["verrouiller","rayer","obstruer"],"antonymes":["déverrouiller","ouvrir","débarrer"],"exemplesCorrects":["N\'oublie pas de barrer la porte avant de partir.","Il a barré son nom de la liste d\'un trait rageur.","Un arbre tombé barrait complètement la route."],"exemplesIncorrects":["Il a barré la soupe avec une pincée de sel.","Elle a barré ses cheveux d\'un joli ruban de soie."],"distracteurs":["bâcler","boucler","barricader"],"anecdote":"Au Québec, on « barre » et on « débarre » sa porte, là où la France dit « verrouiller » et « déverrouiller » ; ce sens, jugé régional, est en réalité un usage ancien et bien attesté.","categorie":"piege-sens","piege":{"explication":"Le sens « verrouiller, fermer à clé » est québécois et de l\'ouest de la France ; en français de référence, barrer signifie d\'abord « rayer » ou « obstruer », pas « fermer à clé »."}},{"id":"garrocher","mot":"garrocher","nature":"verbe","definitions":["Au Québec et en Acadie, familièrement, lancer, jeter quelque chose, souvent sans soin.","Se garrocher : se précipiter, se jeter quelque part."],"phonetique":"/ɡa.ʁɔ.ʃe/","etymologie":"Issu des parlers de l\'ouest de la France (Poitou, Saintonge, Aunis), où garrocher signifiait « jeter des pierres », sans doute apparenté à garrot, « projectile d\'arbalète ».","registre":"familier","niveau":4,"themes":["quotidien","regionalismes"],"synonymes":["lancer","jeter","projeter"],"antonymes":["attraper","retenir","ramasser"],"exemplesCorrects":["Il a garroché son sac sur le lit en rentrant.","Arrête de garrocher tes affaires partout dans la chambre.","Les enfants se garrochaient dans la piscine en criant."],"exemplesIncorrects":["Elle a garroché une magnifique symphonie au piano.","Le chef a garroché les légumes avec une grande délicatesse."],"distracteurs":["garrotter","ricocher","harponner"],"anecdote":"« Garrocher » n\'est pas né au Québec : il vient des patois de l\'ouest de la France où il signifiait « jeter des cailloux », et a traversé l\'Atlantique avec les colons.","categorie":"mot-rare"},{"id":"ostiner","mot":"ostiner","nature":"verbe","definitions":["Au Québec, familièrement, contredire quelqu\'un avec entêtement.","S\'ostiner : s\'obstiner, se disputer en s\'entêtant sur un point."],"phonetique":"/ɔs.ti.ne/","etymologie":"Variante de obstiner, du latin obstinare (« persister »), avec chute du b ; cette prononciation était courante à la cour de France aux XVIIe et XVIIIe siècles.","registre":"familier","niveau":4,"themes":["emotions","regionalismes"],"synonymes":["contredire","s\'obstiner","s\'entêter"],"antonymes":["approuver","céder","acquiescer"],"exemplesCorrects":["Arrête de m\'ostiner, je sais ce que j\'ai vu.","Ils se sont ostinés toute la soirée sur le score du match.","Inutile de l\'ostiner, il ne changera pas d\'avis."],"exemplesIncorrects":["Le maçon a ostiné le mur avec soin avant de peindre.","Elle a ostiné un bouquet de fleurs pour la table."],"distracteurs":["obstruer","ostraciser","rationner"],"anecdote":"« Ostiner », loin d\'être une faute, est une variante de « obstiner » que l\'on prononçait ainsi à la cour de France ; le Québec a conservé cette forme ancienne aujourd\'hui disparue de l\'Hexagone.","categorie":"mot-rare"},{"id":"bardasser","mot":"bardasser","nature":"verbe","definitions":["Au Québec, secouer, brasser, malmener quelque chose ou quelqu\'un.","Faire du bruit ou des gestes brusques, s\'agiter, notamment sous le coup de la colère."],"phonetique":"/baʁ.da.se/","etymologie":"Probablement issu du poitevin bordanser (« balancer, secouer »), ou dérivé de barda (« équipement »), par allusion au bruit du matériel qu\'on remue.","registre":"familier","niveau":5,"themes":["quotidien","regionalismes"],"synonymes":["secouer","brasser","malmener"],"antonymes":["ménager","immobiliser"],"exemplesCorrects":["Le camion nous a bardassés sur le chemin de terre.","Arrête de bardasser dans la cuisine, tu vas réveiller tout le monde.","La tempête a bardassé le petit bateau toute la nuit."],"exemplesIncorrects":["Le poète a bardassé ses vers avec une grande tendresse.","Elle a bardassé une berceuse pour endormir l\'enfant."],"distracteurs":["barder","tarabuster","cahoter"],"anecdote":"« Bardasser » se rattache sans doute au barda du soldat : le mot évoquait le vacarme de l\'équipement qu\'on transporte et qu\'on remue sans ménagement.","categorie":"mot-rare"},{"id":"tiquer","mot":"tiquer","nature":"verbe","definitions":["Marquer par un léger mouvement involontaire du visage son mécontentement, son étonnement ou sa réticence.","Être arrêté, heurté par une difficulté ou une proposition à laquelle on répugne."],"phonetique":"/ti.ke/","etymologie":"Dérivé de « tic », mot d\'abord employé au XVIe siècle pour le défaut du cheval qui mord sa mangeoire, puis étendu au geste nerveux involontaire.","registre":"familier","niveau":2,"themes":["quotidien","emotions"],"synonymes":["sourciller","broncher","réagir"],"antonymes":["accepter","approuver","acquiescer"],"exemplesCorrects":["Il a tiqué en découvrant le montant de la facture.","Le directeur n\'a pas tiqué quand on a évoqué une rallonge de budget.","Elle tiqua légèrement, mais ne dit rien."],"exemplesIncorrects":["Il a tiqué la porte pour la fermer doucement.","Nous avons tiqué la liste des invités avant la réception."],"distracteurs":["frémir","ciller","grimacer"],"anecdote":"Avant de désigner notre froncement de sourcils, « tiquer » se disait du cheval qui contracte l\'encolure en mordillant sa mangeoire : un même tic nerveux, passé de l\'écurie au salon.","categorie":"mot-rare"},{"id":"berdeller","mot":"berdeller","nature":"verbe","definitions":["Ronchonner, marmonner, grommeler sans cesse à voix basse.","Parler beaucoup et sans grand intérêt (Lorraine, Belgique)."],"phonetique":"/bɛʁ.dɛ.le/","etymologie":"Emprunté au wallon et au lorrain « bèrdèler », « bavarder, grommeler », formation expressive évoquant le marmonnement.","registre":"familier","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["ronchonner","marmonner","grommeler"],"antonymes":["se taire","approuver","applaudir"],"exemplesCorrects":["Mémé n\'arrête pas de berdeller dès qu\'on déplace ses affaires.","Il berdelle dans son coin depuis le matin, va savoir pourquoi.","Au lieu de berdeller, viens nous donner un coup de main."],"exemplesIncorrects":["Il a berdellé le mur d\'une couche de peinture fraîche.","Nous avons berdellé la table avant le dîner."],"distracteurs":["bredouiller","chuchoter","ânonner"],"anecdote":"Le verbe est si vivant en Lorraine que beaucoup de locuteurs ignorent qu\'il s\'agit d\'un régionalisme absent du français standard, hérité du wallon voisin.","categorie":"mot-rare"},{"id":"ribouldingue","mot":"ribouldingue","nature":"nom féminin","definitions":["Fête joyeuse et bruyante, partie de plaisir où l\'on fait bombance.","Noce, bringue (vieilli et familier)."],"phonetique":"/ʁi.bul.dɛ̃ɡ/","etymologie":"Dérivé de « ribouldinguer », « faire la fête », croisement d\'une forme dialectale « riboule » (festin de fin de moisson) et de « dinguer ».","registre":"familier","niveau":3,"themes":["quotidien","litteraire"],"synonymes":["bombance","bringue","noce"],"antonymes":["abstinence","recueillement","austérité"],"exemplesCorrects":["Après les vendanges, le village s\'offrit une belle ribouldingue.","Ils ont fait la ribouldingue jusqu\'au petit matin.","Une ribouldingue mémorable clôtura le mariage."],"exemplesIncorrects":["Il a ribouldingue le compte rendu de la réunion.","Nous avons rangé la ribouldingue dans le placard de l\'entrée."],"distracteurs":["bisbille","ribambelle","chamaille"],"anecdote":"« Ribouldingue » sentait si bon la fête qu\'il devint au XXe siècle le nom d\'un des Pieds Nickelés, l\'éternel bon vivant de la bande dessinée.","categorie":"mot-rare"},{"id":"fagne","mot":"fagne","nature":"nom féminin","definitions":["Lande marécageuse et tourbeuse de haute altitude.","Marais tourbeux des Ardennes et de Belgique."],"phonetique":"/faɲ/","etymologie":"Emprunté au wallon « fanie, fagne », « terrain marécageux », issu de l\'ancien bas-francique *fanja, « boue », apparenté à « fange ».","registre":"courant","niveau":4,"themes":["nature","regionalismes"],"synonymes":["tourbière","marécage","lande"],"antonymes":["coteau","plateau aride","désert"],"exemplesCorrects":["Les Hautes Fagnes abritent une flore unique en Belgique.","Le brouillard stagnait au-dessus de la fagne au lever du jour.","On s\'enfonçait jusqu\'aux chevilles dans la fagne détrempée."],"exemplesIncorrects":["Il a fagné le bois avant l\'hiver.","Nous avons grimpé la fagne escarpée du sommet."],"distracteurs":["garrigue","steppe","mangrove"],"anecdote":"Les Hautes Fagnes, plateau venteux à cheval sur la Belgique et l\'Allemagne, doivent leur nom à ce mot wallon désignant le sol spongieux des tourbières d\'altitude.","categorie":"mot-rare"},{"id":"rincette","mot":"rincette","nature":"nom féminin","definitions":["Petite quantité d\'eau-de-vie versée dans la tasse après que l\'on a bu son café.","Dernière goutte d\'alcool versée dans le verre pour le « rincer »."],"phonetique":"/ʁɛ̃.sɛt/","etymologie":"Déverbal de « rincer », avec le suffixe diminutif « -ette » : on rince le fond de la tasse à l\'eau-de-vie.","registre":"familier","niveau":3,"themes":["quotidien","regionalismes"],"synonymes":["pousse-café","goutte","rasade"],"antonymes":[],"exemplesCorrects":["Après le café, le grand-père s\'octroyait toujours sa rincette de calvados.","Une petite rincette pour la route, et nous partîmes.","En Normandie, la rincette se prend en fin de repas, pas au milieu comme le trou normand."],"exemplesIncorrects":["Elle a passé une rincette sur le carrelage de la cuisine.","J\'ai fait une rincette du linge avant de l\'étendre."],"distracteurs":["lampée","gorgée","chopine"],"anecdote":"La tradition normande pousse le jeu loin : après la rincette viennent la surrincette, le gloria et même « la déchirante », chacune marquant une étape de plus dans les adieux arrosés.","categorie":"mot-rare"},{"id":"nareux","mot":"nareux","nature":"adjectif","definitions":["Qui éprouve un dégoût excessif pour la saleté, le manque d\'hygiène, en particulier autour de la nourriture.","Difficile, délicat, qui répugne à boire ou manger après autrui (Est, Lorraine, Champagne)."],"phonetique":"/na.ʁø/","etymologie":"Dérivé du latin « naris », « narine, nez », avec le suffixe « -eux » : qui fronce le nez de dégoût.","registre":"familier","niveau":4,"themes":["regionalismes","quotidien"],"synonymes":["dégoûté","délicat","difficile"],"antonymes":["insensible","indifférent","tolérant"],"exemplesCorrects":["Trop nareux pour boire à la bouteille, il réclama toujours un verre propre.","Ne sois pas si nareux, ce torchon est parfaitement propre.","Les nareux détestent partager leurs couverts."],"exemplesIncorrects":["Le ciel nareux annonçait l\'orage.","Il avançait d\'un pas nareux sur le chemin de halage."],"distracteurs":["pointilleux","frileux","douillet"],"anecdote":"Longtemps cantonné au parler de l\'Est, « nareux » a fait son entrée officielle dans le Petit Robert pour l\'édition 2021, consacrant un régionalisme que la Lorraine employait depuis des générations.","categorie":"mot-rare"},{"id":"briquet","mot":"briquet","nature":"nom masculin","definitions":["Casse-croûte, repas froid qu\'emportaient les mineurs au fond (Nord, Wallonie).","Petit appareil produisant une flamme pour allumer le feu (sens courant)."],"phonetique":"/bʁi.kɛ/","etymologie":"Au sens du casse-croûte, se rattache au sens ancien de « morceau », d\'un mot dialectal du Nord désignant un morceau de pain ; à distinguer du briquet « pièce d\'acier servant à battre le feu ».","registre":"familier","niveau":3,"themes":["regionalismes","quotidien"],"synonymes":["casse-croûte","en-cas","goûter"],"antonymes":["festin","banquet","jeûne"],"exemplesCorrects":["À midi, le mineur sortait son briquet et s\'asseyait contre la berline.","Dans le Nord, « faire briquet », c\'est s\'arrêter pour casser la croûte.","Sa grand-mère lui préparait un briquet de pain et de fromage pour la mine."],"exemplesIncorrects":["Il alluma sa cigarette avec son briquet de pain et de fromage.","Elle rangea le briquet du mineur dans sa poche pour allumer la gazinière."],"distracteurs":["bivouac","fricot","ripaille"],"anecdote":"On croit souvent que ce « briquet »-là vient du député Raoul Briquet, qui aurait imposé la pause des mineurs ; or Zola évoquait déjà le casse-croûte dans Germinal en 1885, bien avant lui : le mot vient en réalité de l\'ancien sens de « morceau » de pain.","categorie":"piege-sens","piege":{"formeFautive":"briquet (= l\'appareil à flamme)","explication":"Dans le Nord et en Wallonie, le « briquet » désigne le casse-croûte du mineur, et non l\'objet servant à faire du feu : « faire briquet », c\'est manger, pas allumer une flamme."}},{"id":"octante","mot":"octante","nature":"adjectif","definitions":["Quatre-vingts ; nombre cardinal valant 80 (régional ou vieilli)."],"phonetique":"/ɔk.tɑ̃t/","etymologie":"Emprunt savant au latin « octoginta », « quatre-vingts », de « octo », « huit ».","registre":"courant","niveau":4,"themes":["regionalismes","abstrait"],"synonymes":["quatre-vingts","huitante"],"antonymes":[],"exemplesCorrects":["En Suisse romande, on entend encore dire octante pour quatre-vingts.","Le vieux registre comptait octante feuillets numérotés.","Octante francs, annonça-t-il sans hésiter, fidèle à son parler régional."],"exemplesIncorrects":["L\'octante de la rivière était couvert de roseaux.","Il joua une octante magnifique au piano."],"distracteurs":["nonante","septante","centaine"],"anecdote":"Là où le français de France a figé l\'archaïque « quatre-vingts », plusieurs régions francophones ont gardé des formes héritées du latin : « huitante » en Suisse, « octante » plus rare, plus logiques mais aujourd\'hui marginales.","categorie":"mot-rare"},{"id":"bouffarde","mot":"bouffarde","nature":"nom féminin","definitions":["Grosse pipe à tuyau court (familier).","Pipe à fumer, en général."],"phonetique":"/bu.faʁd/","etymologie":"Dérivé du radical de « bouffée » (de fumée), avec le suffixe « -arde » ; attesté à la fin du XVIIIe siècle.","registre":"familier","niveau":3,"themes":["quotidien","litteraire"],"synonymes":["pipe","brûle-gueule"],"antonymes":[],"exemplesCorrects":["Le vieux loup de mer bourrait tranquillement sa bouffarde.","Il tirait sur sa bouffarde en regardant la pluie tomber.","Une épaisse fumée montait de sa bouffarde noircie."],"exemplesIncorrects":["Elle agita une bouffarde pour rafraîchir la pièce surchauffée.","Le boulanger sortit la bouffarde brûlante du four."],"distracteurs":["bouffée","blague","fumerolle"],"anecdote":"Une jolie légende fait remonter le mot au sergent Bouffard, dont la pipe annonçait toujours qu\'il allait pester ; les lexicographes y voient plus sobrement un dérivé de « bouffée » de fumée.","categorie":"mot-rare"},{"id":"nasarde","mot":"nasarde","nature":"nom féminin","definitions":["Chiquenaude donnée sur le nez.","Au figuré : affront, moquerie, marque de mépris."],"phonetique":"/na.zaʁd/","etymologie":"Dérivé de « nez » (forme savante « nas- », du latin « nasus »), avec le suffixe « -arde » ; attesté au XVIe siècle sous la forme « nazarde ».","registre":"littéraire","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["chiquenaude","affront","camouflet"],"antonymes":["hommage","déférence","égard"],"exemplesCorrects":["Il accueillit la critique comme une nasarde imméritée.","D\'une nasarde, le maître rappela l\'écolier distrait à l\'ordre.","Ses reparties cinglantes distribuaient les nasardes sans ménagement."],"exemplesIncorrects":["Elle versa une nasarde de vinaigre dans la salade.","Le menuisier serra la nasarde pour fixer la planche."],"distracteurs":["œillade","estafilade","nasale"],"anecdote":"De la chiquenaude bien réelle sur le nez, « nasarde » a glissé vers le sens figuré d\'humiliation : recevoir une nasarde, c\'est subir un petit affront aussi vexant qu\'une pichenette en public.","categorie":"mot-rare"},{"id":"dilemme","mot":"dilemme","nature":"nom masculin","definitions":["Situation offrant un choix entre deux possibilités également insatisfaisantes ou contraignantes.","Argument présentant deux propositions contraires dont l\'une mène nécessairement à la conclusion."],"phonetique":"/di.lɛm/","etymologie":"Du bas latin dilemma, emprunté au grec dilêmma, de di- (deux) et lêmma (proposition, prémisse).","registre":"courant","niveau":1,"themes":["abstrait","quotidien"],"synonymes":["alternative","embarras","impasse"],"antonymes":["évidence","certitude"],"exemplesCorrects":["Partir ou rester : elle était face à un cruel dilemme.","Le dilemme moral du médecin était insoluble.","Aider l\'un revenait à trahir l\'autre, véritable dilemme."],"exemplesIncorrects":["Il a résolu son dilemne en une minute.","Quel dilème entre les deux postes !"],"distracteurs":["dilatation","diaphragme","dilettante"],"anecdote":"On écrit souvent « dilemne » par confusion avec « indemne », mais la forme correcte est « dilemme », avec deux m, du grec lêmma (proposition).","categorie":"piege-orthographe","piege":{"formeFautive":"dilemne","explication":"Le mot se termine par -emme (deux m) et non par -emne ; la graphie « dilemne » est une faute fréquente induite par analogie avec « indemne »."}},{"id":"tranquillite","mot":"tranquillité","nature":"nom féminin","definitions":["État de calme, d\'absence d\'agitation ou de trouble.","Quiétude de l\'esprit, sérénité morale."],"phonetique":"/tʁɑ̃.ki.li.te/","etymologie":"Du latin tranquillitas, de tranquillus (calme, paisible).","registre":"courant","niveau":1,"themes":["emotions","quotidien"],"synonymes":["calme","quiétude","sérénité"],"antonymes":["agitation","inquiétude","trouble"],"exemplesCorrects":["Il recherchait la tranquillité de la campagne.","La tranquillité de son sommeil n\'était jamais troublée.","Elle attendait, dans une tranquillité parfaite, le verdict."],"exemplesIncorrects":["J\'apprécie la tranquilité de ce village.","Une tranquilitée enfin retrouvée."],"distracteurs":["plénitude","indolence","torpeur"],"anecdote":"On voit souvent « tranquilité » avec un seul l, mais le mot s\'écrit avec deux l, comme l\'adjectif « tranquille » dont il dérive.","categorie":"piege-orthographe","piege":{"formeFautive":"tranquilité","explication":"Le mot conserve les deux l de « tranquille » : on écrit « tranquillité », jamais « tranquilité »."}},{"id":"appel","mot":"appel","nature":"nom masculin","definitions":["Action d\'appeler, de héler quelqu\'un pour attirer son attention.","Communication téléphonique.","Action de nommer successivement les personnes d\'un groupe pour vérifier leur présence."],"phonetique":"/a.pɛl/","etymologie":"Déverbal de l\'ancien français apeler, du latin appellare (adresser la parole, nommer).","registre":"courant","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["sollicitation","convocation","interpellation"],"antonymes":["renvoi","réponse"],"exemplesCorrects":["Le professeur fit l\'appel avant le cours.","J\'ai manqué ton appel ce matin.","Son appel à la solidarité fut entendu de tous."],"exemplesIncorrects":["Je passe un appell téléphonique.","Il a répondu à l\'appelle du devoir."],"distracteurs":["rappel","écho","signal"],"anecdote":"Le verbe « appeler » prend deux p et deux l à certaines formes (j\'appelle), mais le nom « appel » ne prend qu\'un seul l, contrairement à ce qu\'on écrit parfois.","categorie":"piege-orthographe","piege":{"formeFautive":"appell","explication":"Le nom « appel » s\'écrit avec deux p mais un seul l ; le doublement du l appartient à la conjugaison (j\'appelle), pas au substantif."}},{"id":"apercevoir","mot":"apercevoir","nature":"verbe","definitions":["Voir, distinguer plus ou moins nettement, souvent de loin ou un bref instant.","Commencer à comprendre, prendre conscience de quelque chose (s\'apercevoir de)."],"phonetique":"/a.pɛʁ.sə.vwaʁ/","etymologie":"Dérivé de « percevoir » (du latin percipere, saisir, recueillir) avec le préfixe a-.","registre":"courant","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["distinguer","entrevoir","remarquer"],"antonymes":["ignorer","manquer"],"exemplesCorrects":["On apercevait au loin les premières maisons du village.","Elle s\'aperçut trop tard de son erreur.","À travers la brume, j\'apercevais une silhouette."],"exemplesIncorrects":["Il a appercu une lumière au fond du couloir.","Nous nous sommes apperçus de rien."],"distracteurs":["aborder","appréhender","approcher"],"anecdote":"On double souvent le p à tort en écrivant « appercevoir » : le verbe ne prend qu\'un seul p, comme « apercevoir » et son dérivé « aperçu ».","categorie":"piege-orthographe","piege":{"formeFautive":"appercevoir","explication":"Le verbe et tous ses dérivés (aperçu, apercevant) s\'écrivent avec un seul p, jamais deux."}},{"id":"embarras","mot":"embarras","nature":"nom masculin","definitions":["Situation gênante, difficile à résoudre.","Trouble, gêne éprouvée devant quelqu\'un ou quelque chose.","Encombrement, obstacle (vieilli)."],"phonetique":"/ɑ̃.ba.ʁa/","etymologie":"Déverbal d\'« embarrasser », emprunté à l\'espagnol embarazar, d\'origine incertaine, que la tradition rattache à barra (barre, obstacle).","registre":"courant","niveau":1,"themes":["emotions","quotidien"],"synonymes":["gêne","trouble","difficulté"],"antonymes":["aisance","assurance","désinvolture"],"exemplesCorrects":["Sa question me plongea dans un profond embarras.","Il avait l\'embarras du choix devant tant d\'options.","Elle rougit d\'embarras en entrant dans la salle."],"exemplesIncorrects":["Quel embara, je ne sais que dire !","Il bredouilla, plein d\'embaras."],"distracteurs":["scrupule","tracas","atermoiement"],"anecdote":"Le mot se termine par un s muet et prend deux r : « embarras », comme « embarrasser ». On oublie souvent l\'un ou l\'autre.","categorie":"piege-orthographe","piege":{"formeFautive":"embara","explication":"Le mot prend deux r et se termine par un s muet : « embarras », à ne pas réduire à « embara » ou « embaras »."}},{"id":"courir","mot":"courir","nature":"verbe","definitions":["Se déplacer rapidement en mouvant alternativement et vivement les jambes.","Se hâter, aller vite quelque part.","Se répandre, circuler (un bruit qui court)."],"phonetique":"/ku.ʁiʁ/","etymologie":"Du latin currere (courir), qui a aussi donné « courant » et « course ».","registre":"courant","niveau":1,"themes":["quotidien","nature"],"synonymes":["filer","galoper","se précipiter"],"antonymes":["marcher","s\'arrêter","flâner"],"exemplesCorrects":["Il aime courir au bord de la mer chaque matin.","Le bruit court qu\'elle va démissionner.","Elle a couru pour ne pas manquer son train."],"exemplesIncorrects":["Je vais courrir jusqu\'au parc.","Nous allons courrir un grand danger."],"distracteurs":["secourir","parcourir","concourir"],"anecdote":"À l\'infinitif et au futur, « courir » ne prend qu\'un seul r ; le futur « je courrai » en prend deux, ce qui le distingue du conditionnel « je courrais ».","categorie":"piege-orthographe","piege":{"formeFautive":"courrir","explication":"L\'infinitif s\'écrit « courir » avec un seul r ; le double r n\'apparaît qu\'au futur et au conditionnel (je courrai, je courrais)."}},{"id":"mourir","mot":"mourir","nature":"verbe","definitions":["Cesser de vivre, perdre la vie.","S\'éteindre, disparaître progressivement (un feu qui meurt).","Éprouver une sensation extrême (mourir de faim, d\'ennui)."],"phonetique":"/mu.ʁiʁ/","etymologie":"Du latin populaire morire, réfection du latin classique mori (mourir).","registre":"courant","niveau":1,"themes":["quotidien","abstrait"],"synonymes":["décéder","périr","s\'éteindre"],"antonymes":["naître","vivre","renaître"],"exemplesCorrects":["On peut mourir de chagrin, dit-on parfois.","Le vieil arbre finit par mourir l\'hiver dernier.","Je meurs d\'envie de te revoir."],"exemplesIncorrects":["Il craint de mourrir seul.","Les flammes vont mourrir d\'elles-mêmes."],"distracteurs":["nourrir","secourir","discourir"],"anecdote":"« Mourir » ne prend qu\'un seul r à l\'infinitif ; le double r du futur « je mourrai » le distingue à l\'oral comme à l\'écrit du conditionnel « je mourrais ».","categorie":"piege-orthographe","piege":{"formeFautive":"mourrir","explication":"L\'infinitif « mourir » s\'écrit avec un seul r ; le redoublement n\'a lieu qu\'au futur et au conditionnel (je mourrai, je mourrais)."}},{"id":"nourrir","mot":"nourrir","nature":"verbe","definitions":["Donner à manger à, fournir les aliments nécessaires à la subsistance.","Entretenir, alimenter (nourrir un feu, une conversation).","Entretenir en soi un sentiment, une pensée (nourrir un espoir)."],"phonetique":"/nu.ʁiʁ/","etymologie":"Du latin nutrire (allaiter, nourrir), qui a aussi donné « nourrice » et « nutrition ».","registre":"courant","niveau":1,"themes":["quotidien","nature"],"synonymes":["alimenter","sustenter","entretenir"],"antonymes":["affamer","priver","épuiser"],"exemplesCorrects":["Elle nourrit ses poules dès l\'aube.","Cette lecture a nourri sa réflexion.","Il nourrissait un secret espoir de la revoir."],"exemplesIncorrects":["Il faut nourir le chat ce soir.","Ces expériences ont nouri sa curiosité."],"distracteurs":["mourir","courir","fleurir"],"anecdote":"Contrairement à « mourir » et « courir » qui ne prennent qu\'un r à l\'infinitif, « nourrir » en prend deux à toutes ses formes, comme « nourrice ».","categorie":"piege-orthographe","piege":{"formeFautive":"nourir","explication":"« Nourrir » prend deux r à toutes les formes ; ne pas le calquer sur « mourir » ou « courir » qui n\'en prennent qu\'un à l\'infinitif."}},{"id":"exaucer","mot":"exaucer","nature":"verbe","definitions":["Satisfaire quelqu\'un en lui accordant ce qu\'il demande.","Accueillir favorablement un vœu, une prière, une demande."],"phonetique":"/ɛɡ.zo.se/","etymologie":"Variante d\'« exhausser », de l\'ancien français essaucier, du latin exaltare (élever) ; le sens « accueillir une prière » vient de l\'idée de l\'élever vers le ciel.","registre":"soutenu","niveau":2,"themes":["abstrait","emotions"],"synonymes":["satisfaire","contenter","accomplir"],"antonymes":["refuser","décevoir","éconduire"],"exemplesCorrects":["Le ciel a enfin exaucé ses prières.","Elle fut exaucée au-delà de ses espérances.","Que mon vœu soit exaucé !"],"exemplesIncorrects":["On a exhaussé sa demande de mutation.","Ses prières furent exhaussées par la providence."],"distracteurs":["consentir","entériner","plébisciter"],"anecdote":"On confond souvent « exaucer » (satisfaire un vœu) avec « exhausser » (surélever) : le premier s\'écrit sans h, le second avec h et deux s.","categorie":"piege-sens","piege":{"formeFautive":"exhausser un vœu","explication":"« Exaucer » (sans h) signifie satisfaire une prière ou un vœu ; « exhausser » (avec h) signifie surélever. On exauce un souhait, on exhausse un mur."}},{"id":"exhausser","mot":"exhausser","nature":"verbe","definitions":["Augmenter la hauteur de quelque chose, surélever.","Rendre plus haut un ouvrage, un terrain, une construction."],"phonetique":"/ɛɡ.zo.se/","etymologie":"Composé de ex- et de « hausser » (rendre plus haut), avec un h issu de l\'influence de « haut » (du latin altus).","registre":"soutenu","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["surélever","rehausser","hausser"],"antonymes":["abaisser","rabaisser","niveler"],"exemplesCorrects":["On a exhaussé le mur d\'un mètre pour gagner en intimité.","Le terrain fut exhaussé avant la construction.","Il fallut exhausser la digue contre les crues."],"exemplesIncorrects":["Le ciel a exhaussé ma prière la plus chère.","Mon vœu le plus cher fut enfin exhaussé."],"distracteurs":["étayer","consolider","remblayer"],"anecdote":"« Exhausser » (avec h, surélever) ne doit pas être confondu avec « exaucer » (sans h, satisfaire un vœu) : on exhausse un mur, on exauce une prière.","categorie":"piege-sens","piege":{"formeFautive":"exhausser une prière","explication":"« Exhausser » signifie surélever ; pour satisfaire un vœu ou une prière, on emploie « exaucer » (sans h)."}},{"id":"imbecillite","mot":"imbécillité","nature":"nom féminin","definitions":["Manque grave d\'intelligence ; stupidité, bêtise.","Acte ou parole révélant une grande sottise.","Faiblesse mentale profonde (sens médical vieilli)."],"phonetique":"/ɛ̃.be.si.li.te/","etymologie":"Du latin imbecillitas (faiblesse), de imbecillus (faible, sans bâton, de baculus).","registre":"courant","niveau":2,"themes":["abstrait","emotions"],"synonymes":["stupidité","bêtise","sottise"],"antonymes":["intelligence","finesse","sagacité"],"exemplesCorrects":["Son imbécillité crasse exaspérait ses collègues.","C\'est une imbécillité de partir sans carte.","Il fit preuve d\'une rare imbécillité ce jour-là."],"exemplesIncorrects":["Quelle imbécilité, ce raisonnement !","Il a dit une imbécilitée sans nom."],"distracteurs":["crédulité","naïveté","étourderie"],"anecdote":"Curieusement, « imbécile » prend un seul l mais « imbécillité » en prend deux, conformément au latin imbecillitas dont le mot est issu.","categorie":"piege-orthographe","piege":{"formeFautive":"imbécilité","explication":"Bien que « imbécile » s\'écrive avec un seul l, le nom « imbécillité » en prend deux, fidèle au latin imbecillitas."}},{"id":"boursoufler","mot":"boursoufler","nature":"verbe","definitions":["Gonfler par endroits en formant des cloques ou des renflements ; faire enfler.","Rendre emphatique, ampoulé (un style boursouflé)."],"phonetique":"/buʁ.su.fle/","etymologie":"Altération de « boursouflé », lui-même issu de « bousouflé » (enflé) ; le verbe n\'a gardé qu\'un seul f, contrairement à « souffler ».","registre":"courant","niveau":3,"themes":["nature","quotidien"],"synonymes":["gonfler","enfler","cloquer"],"antonymes":["dégonfler","aplatir","désenfler"],"exemplesCorrects":["La peinture a fini par se boursoufler sous la chaleur.","Son visage était boursouflé par les larmes.","Un style boursouflé nuit à la clarté du propos."],"exemplesIncorrects":["Le mur commence à boursouffler d\'humidité.","Ses paupières étaient boursoufflées au réveil."],"distracteurs":["tuméfier","crevasser","craqueler"],"anecdote":"Alors que « souffler » prend deux f, « boursoufler » n\'en prend qu\'un seul, ce qui en fait une anomalie orthographique notoire (l\'orthographe rectifiée de 1990 propose toutefois « boursouffler »).","categorie":"piege-orthographe","piege":{"formeFautive":"boursouffler","explication":"L\'orthographe traditionnelle s\'écrit avec un seul f, « boursoufler », malgré l\'analogie tentante avec « souffler » qui en prend deux."}},{"id":"persifler","mot":"persifler","nature":"verbe","definitions":["Tourner quelqu\'un en ridicule par des propos d\'apparence flatteuse mais en réalité moqueurs ; railler finement."],"phonetique":"/pɛʁ.si.fle/","etymologie":"Composé de per- (préfixe intensif) et de siffler, au sens figuré de « se moquer en sifflant », attesté au XVIIIe siècle.","registre":"soutenu","niveau":3,"themes":["quotidien","abstrait"],"synonymes":["railler","ironiser","brocarder"],"antonymes":["louer","complimenter","flatter"],"exemplesCorrects":["Il aimait persifler ses collègues sous des dehors aimables.","Cesse de persifler, ta moquerie finit par blesser.","Le journaliste persifla le ministre avec une élégance cruelle."],"exemplesIncorrects":["Le vent persifla entre les branches du vieux chêne.","Elle a persiflé la bouilloire jusqu\'à ce qu\'elle chauffe."],"distracteurs":["pérorer","persister","persuader"],"anecdote":"On écrit souvent à tort « persiffler » avec deux f, par analogie avec « siffler » ; pourtant l\'orthographe traditionnelle ne prend qu\'un seul f, tout comme le substantif « persiflage ».","categorie":"piege-orthographe","piege":{"formeFautive":"persiffler","explication":"Bien que le verbe dérive de « siffler » (deux f), « persifler » et « persiflage » s\'écrivent avec un seul f."}},{"id":"chariot","mot":"chariot","nature":"nom masculin","definitions":["Voiture à roulettes servant à transporter des charges, des marchandises ou des bagages.","Pièce mobile d\'une machine se déplaçant sur des rails ou des glissières."],"phonetique":"/ʃa.ʁjo/","etymologie":"Diminutif de char, du latin carrus, « chariot à quatre roues », mot d\'origine gauloise.","registre":"courant","niveau":1,"themes":["quotidien"],"synonymes":["caddie","diable","charrette"],"antonymes":[],"exemplesCorrects":["Il poussa son chariot le long des rayons du supermarché.","Le bagagiste empila les valises sur un chariot.","Le chariot élévateur déposa la palette devant l\'entrepôt."],"exemplesIncorrects":["Elle a chariot tous les meubles jusqu\'au camion.","Nous avons chariot la pièce avant de la repeindre."],"distracteurs":["fardier","brouette","tombereau"],"anecdote":"On écrit fréquemment « charriot » avec deux r, par contamination avec « charrette » et « charrue » ; la graphie traditionnelle n\'en garde qu\'un seul, « chariot », même si la réforme de 1990 tolère « charriot ».","categorie":"piege-orthographe","piege":{"formeFautive":"charriot","explication":"Contrairement à « charrette » et « charrue » qui doublent le r, « chariot » s\'écrit avec un seul r dans la graphie traditionnelle."}},{"id":"combatif","mot":"combatif","nature":"adjectif","definitions":["Qui est porté à combattre, à la lutte ; qui aime se battre ou défendre énergiquement sa position."],"phonetique":"/kɔ̃.ba.tif/","etymologie":"Dérivé du radical de combattre, lui-même du latin combattere, de cum (avec) et battuere (frapper).","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["batailleur","agressif","pugnace"],"antonymes":["pacifique","conciliant","résigné"],"exemplesCorrects":["Malgré la défaite, l\'équipe est restée combative jusqu\'au bout.","Son tempérament combatif lui a permis de surmonter la maladie.","C\'est une avocate combative qui ne lâche jamais un dossier."],"exemplesIncorrects":["Le climat était combatif et très doux ce matin-là.","Ce fauteuil combatif est d\'un grand confort."],"distracteurs":["tenace","intrépide","belliqueux"],"anecdote":"On écrit souvent « combattif » avec deux t, par analogie avec « combattre » et « combattant » ; pourtant « combatif » et « combativité » ne prennent qu\'un seul t.","categorie":"piege-orthographe","piege":{"formeFautive":"combattif","explication":"Bien que « combattre » et « combattant » prennent deux t, l\'adjectif « combatif » et le nom « combativité » s\'écrivent avec un seul t."}},{"id":"fourmiliere","mot":"fourmilière","nature":"nom féminin","definitions":["Habitation, nid d\'une colonie de fourmis, souvent en forme de dôme.","Au figuré, lieu où s\'agite une multitude de personnes affairées."],"phonetique":"/fuʁ.mi.ljɛʁ/","etymologie":"Dérivé de fourmi, du latin formica, avec le suffixe -ière désignant un lieu.","registre":"courant","niveau":1,"themes":["nature","quotidien"],"synonymes":["nid","termitière","essaim"],"antonymes":[],"exemplesCorrects":["Les enfants observaient le va-et-vient incessant de la fourmilière.","À midi, la gare ressemblait à une véritable fourmilière.","Un coup de bâton suffit à transformer la fourmilière en chaos."],"exemplesIncorrects":["Il a fourmilière les invités dans le grand salon.","Cette soupe est trop fourmilière pour mon goût."],"distracteurs":["ruche","garenne","tanière"],"anecdote":"On écrit souvent « fourmillière » avec deux l, par contamination avec le verbe « fourmiller » ; pourtant le nom ne prend qu\'un seul l, « fourmilière ».","categorie":"piege-orthographe","piege":{"formeFautive":"fourmillière","explication":"Le verbe « fourmiller » prend deux l, mais le nom « fourmilière » s\'écrit avec un seul l."}},{"id":"deambuler","mot":"déambuler","nature":"verbe","definitions":["Marcher sans but précis, aller çà et là ; flâner, se promener nonchalamment."],"phonetique":"/de.ɑ̃.by.le/","etymologie":"Du latin deambulare, « se promener », de de- et ambulare (marcher).","registre":"soutenu","niveau":2,"themes":["quotidien"],"synonymes":["flâner","errer","musarder"],"antonymes":["se hâter","courir","stationner"],"exemplesCorrects":["Ils déambulaient dans les ruelles du vieux quartier.","Elle aime déambuler le long des quais au crépuscule.","Des badauds déambulaient sans hâte sous les arcades."],"exemplesIncorrects":["Le professeur a déambulé un long discours devant la classe.","Nous avons déambulé tous les meubles dans le couloir."],"distracteurs":["divaguer","vagabonder","arpenter"],"anecdote":"L\'accent aigu du préfixe trompe : on lit « dé-ambuler » mais on prononce souvent le hiatus, ce qui pousse certains à oublier l\'accent ou à mal couper le mot.","categorie":"piege-orthographe","piege":{"formeFautive":"deambuler","explication":"Le verbe prend un accent aigu sur le e initial : « déambuler », et non « deambuler »."}},{"id":"egerie","mot":"égérie","nature":"nom féminin","definitions":["Femme qui inspire un artiste, un écrivain ou un homme politique ; conseillère inspiratrice.","Femme qui incarne et représente une marque."],"phonetique":"/e.ʒe.ʁi/","etymologie":"De Égérie, nymphe de la mythologie romaine, conseillère du roi Numa Pompilius.","registre":"soutenu","niveau":3,"themes":["litteraire","abstrait"],"synonymes":["muse","inspiratrice","conseillère"],"antonymes":[],"exemplesCorrects":["Elle fut l\'égérie des peintres impressionnistes de Montmartre.","Cette actrice est devenue l\'égérie d\'une grande maison de parfum.","Derrière chaque ministre se cachait, dit-on, une égérie discrète."],"exemplesIncorrects":["Il a poussé l\'égérie de la voiture jusqu\'au garage.","Le mécanicien a remplacé l\'égérie usée du moteur."],"distracteurs":["dryade","mécène","courtisane"],"anecdote":"Le mot vient du nom propre de la nymphe Égérie : on écrit donc « égérie » avec un accent aigu sur chaque e, et non « egerie » ou « égerie ».","categorie":"piege-orthographe","piege":{"formeFautive":"égerie","explication":"Le mot prend un accent aigu sur les deux premiers e : « égérie », du nom de la nymphe Égérie."}},{"id":"alleluia","mot":"alléluia","nature":"interjection","definitions":["Cri de joie et de louange employé dans la liturgie chrétienne et juive.","Exclamation marquant l\'allégresse ou le soulagement."],"phonetique":"/a.le.lɥja/","etymologie":"Du latin ecclésiastique alleluia, emprunté à l\'hébreu halləlûyāh, « louez Yah (Dieu) ».","registre":"courant","niveau":2,"themes":["litteraire","abstrait"],"synonymes":["hosanna","gloire","louange"],"antonymes":[],"exemplesCorrects":["Le chœur entonna un alléluia éclatant sous les voûtes.","Alléluia, le train est enfin arrivé !","À Pâques, l\'église résonne d\'alléluias triomphants."],"exemplesIncorrects":["Il a alléluia toute la matinée dans son bureau.","Ce gâteau est délicieusement alléluia."],"distracteurs":["oraison","litanie","cantique"],"anecdote":"On voit souvent « alleluia » sans accent, sous l\'influence du latin ; mais en français moderne, la graphie reconnue par l\'Académie est « alléluia », avec un accent aigu sur le premier e.","categorie":"piege-orthographe","piege":{"formeFautive":"alleluia","explication":"En français, le mot s\'écrit avec un accent aigu : « alléluia », même si le latin liturgique écrit « alleluia » sans accent."}},{"id":"millefeuille","mot":"millefeuille","nature":"nom masculin","definitions":["Gâteau composé de fines couches de pâte feuilletée séparées de crème pâtissière.","Au féminin, plante herbacée aux feuilles très découpées (achillée millefeuille)."],"phonetique":"/mil.fœj/","etymologie":"Composé de mille et de feuille, par allusion aux nombreuses couches de pâte feuilletée.","registre":"courant","niveau":1,"themes":["quotidien"],"synonymes":["napoléon","feuilleté","gâteau"],"antonymes":[],"exemplesCorrects":["Le pâtissier saupoudra le millefeuille de sucre glace.","Rien ne vaut un millefeuille à la crème vanille pour le goûter.","Ce dossier administratif est un véritable millefeuille de formulaires."],"exemplesIncorrects":["Il a millefeuille la pâte avant de la cuire.","Cette route est trop millefeuille pour les vélos."],"distracteurs":["chausson","palmier","vol-au-vent"],"anecdote":"On hésite entre « mille-feuille », « mille feuille » et « millefeuille » ; les rectifications orthographiques de 1990 recommandent la soudure, « millefeuille », au pluriel « millefeuilles ».","categorie":"piege-orthographe","piege":{"formeFautive":"mille-feuilles","explication":"La graphie recommandée est soudée et sans s à « feuille » au singulier : « millefeuille » (pluriel « millefeuilles »)."}},{"id":"rationnel","mot":"rationnel","nature":"adjectif","definitions":["Conforme à la raison, fondé sur le raisonnement logique.","En mathématiques, qui peut s\'exprimer comme le rapport de deux entiers."],"phonetique":"/ʁa.sjɔ.nɛl/","etymologie":"Du latin rationalis, « doué de raison », dérivé de ratio, « calcul, raison ».","registre":"courant","niveau":2,"themes":["abstrait"],"synonymes":["logique","raisonnable","cohérent"],"antonymes":["irrationnel","absurde","instinctif"],"exemplesCorrects":["Sa décision repose sur une analyse parfaitement rationnelle.","Un esprit rationnel se méfie des explications surnaturelles.","Le nombre 0,5 est rationnel, car il vaut un demi."],"exemplesIncorrects":["Ce parfum rationnel embaume toute la pièce.","Il a rationnel la porte d\'un grand coup d\'épaule."],"distracteurs":["empirique","pragmatique","méthodique"],"anecdote":"On écrit parfois « rationel » avec un seul n, par oubli ; mais « rationnel », comme « rationnellement » et « rationaliser », prend bien deux n.","categorie":"piege-orthographe","piege":{"formeFautive":"rationel","explication":"L\'adjectif s\'écrit avec deux n : « rationnel », tout comme « rationnellement »."}},{"id":"traditionnel","mot":"traditionnel","nature":"adjectif","definitions":["Qui relève de la tradition, qui se transmet d\'âge en âge.","Qui est habituel, conforme à l\'usage établi."],"phonetique":"/tʁa.di.sjɔ.nɛl/","etymologie":"Dérivé de tradition, du latin traditio, « action de transmettre », avec le suffixe -el.","registre":"courant","niveau":1,"themes":["abstrait","quotidien"],"synonymes":["coutumier","habituel","ancestral"],"antonymes":["moderne","novateur","inhabituel"],"exemplesCorrects":["La famille perpétue le repas traditionnel du dimanche.","Ce village conserve son architecture traditionnelle.","Le discours traditionnel du maire clôtura la cérémonie."],"exemplesIncorrects":["Le ciel était traditionnel et chargé de nuages.","Il a traditionnel la corde autour du paquet."],"distracteurs":["folklorique","conventionnel","rituel"],"anecdote":"On voit souvent « traditionel » avec un seul n ; pourtant, comme tous les adjectifs en -ionnel, « traditionnel » s\'écrit avec deux n.","categorie":"piege-orthographe","piege":{"formeFautive":"traditionel","explication":"Les adjectifs en -ionnel prennent deux n : « traditionnel », « professionnel », « émotionnel »."}},{"id":"abreviation","mot":"abréviation","nature":"nom féminin","definitions":["Réduction d\'un mot ou d\'un groupe de mots à quelques lettres ou syllabes ; forme ainsi raccourcie."],"phonetique":"/a.bʁe.vja.sjɔ̃/","etymologie":"Du bas latin abbreviatio, de abbreviare, « raccourcir », de brevis (bref).","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["sigle","raccourci","contraction"],"antonymes":["développement","allongement"],"exemplesCorrects":["« Etc. » est l\'abréviation de « et cetera ».","Le devoir interdit toute abréviation dans la rédaction.","Il a dressé une liste des abréviations utilisées dans le rapport."],"exemplesIncorrects":["L\'abréviation du moteur a provoqué une panne.","Elle a abréviation la nappe sur la table."],"distracteurs":["acronyme","troncature","élision"],"anecdote":"Bien que le latin abbreviatio prenne deux b, le français a simplifié : on écrit « abréviation » avec un seul b, comme « abréger ».","categorie":"piege-orthographe","piege":{"formeFautive":"abbréviation","explication":"Malgré le latin « abbreviatio » à deux b, le mot français s\'écrit avec un seul b : « abréviation »."}},{"id":"infarctus","mot":"infarctus","nature":"nom masculin","definitions":["Lésion d\'un tissu ou d\'un organe due à l\'arrêt brutal de la circulation sanguine, le plus souvent par obstruction d\'une artère."],"phonetique":"/ɛ̃.faʁk.tys/","etymologie":"Du latin médical infarctus, participe passé de infarcire, « farcir, bourrer », par allusion à l\'obstruction du vaisseau.","registre":"courant","niveau":3,"themes":["quotidien","abstrait"],"synonymes":["nécrose","crise cardiaque","thrombose"],"antonymes":[],"exemplesCorrects":["Il a été hospitalisé d\'urgence à la suite d\'un infarctus du myocarde.","Le tabac augmente nettement le risque d\'infarctus.","Les secours sont intervenus rapidement après son infarctus."],"exemplesIncorrects":["Le mécanicien a réparé l\'infarctus de la voiture.","Elle a posé un infarctus sur le mur de la cuisine."],"distracteurs":["embolie","anévrisme","ischémie"],"anecdote":"On entend et on écrit très souvent « infractus », par fausse analogie avec « fracture » ; la forme correcte est « infarctus », du latin infarcire, « bourrer », car le vaisseau est obstrué.","categorie":"piege-orthographe","piege":{"formeFautive":"infractus","explication":"L\'erreur courante « infractus » (par analogie avec « fracture ») est fautive : on dit et on écrit « infarctus », avec -farc-."}},{"id":"invoquer","mot":"invoquer","nature":"verbe","definitions":["Appeler à l\'aide, solliciter par une prière (une divinité, une puissance, un secours).","Citer, alléguer en sa faveur (un argument, un texte, un témoignage)."],"phonetique":"/ɛ̃.vɔ.ke/","etymologie":"Du latin invocare, « appeler à soi, appeler au secours », de in- (« vers ») et vocare (« appeler »).","registre":"soutenu","niveau":2,"themes":["abstrait","litteraire"],"synonymes":["alléguer","implorer","prétexter","exciper"],"antonymes":["répudier","récuser"],"exemplesCorrects":["Pour justifier son retard, il invoqua un embouteillage monstre.","Les fidèles invoquaient la protection des saints avant la bataille.","L\'avocat invoqua un vice de procédure pour faire annuler le jugement."],"exemplesIncorrects":["Ce parfum invoque en moi des souvenirs d\'enfance.","Le vieux tableau invoque la douceur des soirs d\'été."],"distracteurs":["convoquer","révoquer","provoquer","interpeller"],"anecdote":"On confond souvent « invoquer » et « évoquer ». Invoquer, c\'est appeler en renfort ou alléguer (invoquer un argument, une excuse) ; évoquer, c\'est faire surgir à l\'esprit, rappeler (ce parfum évoque mon enfance).","categorie":"piege-sens","piege":{"formeFautive":"évoquer un argument / invoquer un souvenir","explication":"« Invoquer » signifie appeler en renfort ou alléguer (invoquer une excuse) ; « évoquer » signifie faire surgir à l\'esprit (évoquer un souvenir). Les deux verbes ne sont pas interchangeables."}},{"id":"prolifique","mot":"prolifique","nature":"adjectif","definitions":["Qui se reproduit ou se multiplie rapidement et en abondance.","Qui produit beaucoup d\'œuvres ; fécond, productif (en parlant d\'un artiste, d\'un auteur)."],"phonetique":"/pʁɔ.li.fik/","etymologie":"Dérivé savant du latin proles (« lignée, descendance ») et du suffixe -fique (du latin -ficus, « qui fait »).","registre":"courant","niveau":2,"themes":["abstrait","litteraire"],"synonymes":["fécond","productif","fertile","généreux"],"antonymes":["stérile","improductif","infécond"],"exemplesCorrects":["Balzac fut un romancier prolifique, auteur de près de cent ouvrages.","Les lapins sont des animaux particulièrement prolifiques.","Cette année prolifique a vu naître trois de ses meilleures symphonies."],"exemplesIncorrects":["L\'orateur prolifique multipliait les digressions interminables.","Un discours prolifique nous a tous endormis tant il était bavard."],"distracteurs":["prolixe","prodigue","pléthorique","luxuriant"],"anecdote":"« Prolifique » et « prolixe » se ressemblent mais n\'ont rien à voir. Prolifique signifie « qui produit beaucoup » (un auteur prolifique) ; prolixe qualifie une personne trop bavarde ou un discours trop long (un orateur prolixe).","categorie":"piege-sens","piege":{"formeFautive":"un orateur prolifique (au sens de bavard)","explication":"« Prolifique » signifie « qui produit beaucoup » et ne s\'applique pas à un excès de paroles. Pour quelqu\'un de trop bavard, on dit « prolixe »."}},{"id":"acception","mot":"acception","nature":"nom féminin","definitions":["Sens particulier dans lequel un mot est employé ; signification admise d\'un terme.","Vieilli, dans la locution « sans acception de » : sans tenir compte de, sans considération pour (sans acception de personnes)."],"phonetique":"/ak.sɛp.sjɔ̃/","etymologie":"Du latin acceptio, « action de recevoir, de prendre dans tel ou tel sens », de accipere (« recevoir »).","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["sens","signification","valeur"],"antonymes":[],"exemplesCorrects":["Dans son acception courante, ce mot désigne une émotion légère.","Le terme « liberté » prend ici une acception strictement juridique.","La justice doit s\'exercer sans acception de personnes."],"exemplesIncorrects":["Il a donné son acception au contrat sans le relire.","Après mûre réflexion, elle a signifié son acception du poste."],"distracteurs":["acceptation","acuité","assertion","exception"],"anecdote":"« Acception » et « acceptation » sont des paronymes redoutables. Acception désigne le sens d\'un mot (l\'acception courante d\'un terme) ; acceptation désigne le fait d\'accepter (l\'acceptation d\'une offre).","categorie":"piege-sens","piege":{"formeFautive":"donner son acception (au sens d\'accord)","explication":"« Acception » désigne le sens d\'un mot, jamais le fait d\'accepter. Pour le consentement, c\'est « acceptation »."}},{"id":"acceptation","mot":"acceptation","nature":"nom féminin","definitions":["Action d\'accepter ce qui est proposé ou offert ; consentement.","Fait de supporter, d\'agréer une situation, une épreuve (l\'acceptation de la mort)."],"phonetique":"/ak.sɛp.ta.sjɔ̃/","etymologie":"Du latin acceptatio, dérivé de acceptare, fréquentatif de accipere (« recevoir »).","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["consentement","approbation","agrément","adhésion"],"antonymes":["refus","rejet","déni"],"exemplesCorrects":["L\'acceptation de l\'offre engage les deux parties.","Le deuil passe par une phase d\'acceptation de la perte.","Sa lettre d\'acceptation est parvenue à l\'employeur ce matin."],"exemplesIncorrects":["Ce mot possède plusieurs acceptations selon le contexte.","Dans son acceptation littéraire, le terme évoque la mélancolie."],"distracteurs":["acception","acclamation","accointance","adhérence"],"anecdote":"Ne pas confondre avec « acception ». Acceptation, c\'est le fait d\'accepter (l\'acceptation d\'un héritage) ; acception, c\'est le sens d\'un mot (les différentes acceptions d\'un terme).","categorie":"piege-sens","piege":{"formeFautive":"les acceptations d\'un mot","explication":"Un mot a des « acceptions » (des sens), pas des « acceptations ». « Acceptation » désigne uniquement le fait d\'accepter."}},{"id":"allocation","mot":"allocation","nature":"nom féminin","definitions":["Somme d\'argent attribuée régulièrement à quelqu\'un pour subvenir à un besoin (allocation familiale, de chômage).","Action d\'allouer, d\'attribuer une chose (allocation de ressources, de mémoire)."],"phonetique":"/a.lɔ.ka.sjɔ̃/","etymologie":"Du latin médiéval allocatio, de allocare (« placer, attribuer »), de ad- et locare (« placer »).","registre":"courant","niveau":2,"themes":["quotidien","abstrait"],"synonymes":["attribution","subvention","indemnité","prestation"],"antonymes":["retenue","prélèvement"],"exemplesCorrects":["La famille touche une allocation logement chaque mois.","L\'allocation des ressources entre les services a suscité des tensions.","Il a perdu son droit à l\'allocation chômage après six mois."],"exemplesIncorrects":["Le maire a prononcé une brève allocation devant les habitants.","Son allocation de bienvenue a été chaleureusement applaudie."],"distracteurs":["allocution","dotation","affectation"],"anecdote":"« Allocation » et « allocution » ne diffèrent que d\'une lettre, mais tout les sépare. L\'allocation est une somme versée ; l\'allocution est un bref discours officiel.","categorie":"piege-sens","piege":{"formeFautive":"prononcer une allocation","explication":"On prononce une « allocution » (un discours), pas une « allocation » (une somme d\'argent). Le « u » fait toute la différence."}},{"id":"allocution","mot":"allocution","nature":"nom féminin","definitions":["Discours bref, généralement de circonstance, prononcé par une personnalité officielle.","Courte adresse orale à un auditoire."],"phonetique":"/a.lɔ.ky.sjɔ̃/","etymologie":"Du latin allocutio, « action d\'adresser la parole », de alloqui (« haranguer, s\'adresser à »), de ad- et loqui (« parler »).","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["discours","harangue","speech","intervention"],"antonymes":[],"exemplesCorrects":["Le président a prononcé une brève allocution télévisée.","Le maire ouvrit la cérémonie par une allocution de bienvenue.","Son allocution de cinq minutes fut saluée par une longue ovation."],"exemplesIncorrects":["Les chômeurs perçoivent une allocution mensuelle.","Le service a revu l\'allocution de son budget annuel."],"distracteurs":["allocation","élocution","interpellation","péroraison"],"anecdote":"Ne pas confondre avec « allocation ». L\'allocution est un bref discours (l\'allocution du président) ; l\'allocation est une somme versée (l\'allocation familiale).","categorie":"piege-sens","piege":{"formeFautive":"toucher une allocution","explication":"On touche une « allocation » (une somme d\'argent), pas une « allocution » (un discours). À ne pas confondre non plus avec « élocution », la manière de s\'exprimer."}},{"id":"affecter","mot":"affecter","nature":"verbe","definitions":["Feindre, simuler un sentiment ou une attitude (affecter l\'indifférence).","Destiner à un usage déterminé, attribuer (affecter des crédits, un agent à un poste).","Toucher, atteindre, émouvoir (la nouvelle l\'a profondément affecté)."],"phonetique":"/a.fɛk.te/","etymologie":"Du latin affectare, « rechercher, viser à », fréquentatif de afficere (« mettre dans un certain état »), de ad- et facere (« faire »).","registre":"courant","niveau":2,"themes":["abstrait","emotions"],"synonymes":["feindre","simuler","destiner","émouvoir"],"antonymes":["réjouir","consoler"],"exemplesCorrects":["Il affectait une assurance qu\'il était loin d\'éprouver.","On l\'a affecté à la succursale de Lyon dès la rentrée.","Cette nouvelle l\'a profondément affecté."],"exemplesIncorrects":["La grippe a affecté la moitié du service en une semaine.","Une blessure mal soignée risque d\'affecter la plaie."],"distracteurs":["infecter","effectuer","altérer","affermir"],"anecdote":"« Affecter » et « infecter » sont des paronymes piégeux. Affecter, c\'est feindre, destiner ou émouvoir ; infecter, c\'est contaminer par des germes (une plaie infectée). Un virus infecte un organisme ; une émotion affecte une personne.","categorie":"piege-sens","piege":{"formeFautive":"une plaie affectée (au sens de contaminée)","explication":"« Affecter » ne signifie pas contaminer. Pour une plaie ou un organisme envahi par des germes, on emploie « infecter » : une plaie infectée."}},{"id":"prescription","mot":"prescription","nature":"nom féminin","definitions":["Ordre formel, recommandation détaillée ; ce qui est prescrit (prescription médicale).","En droit, mode d\'acquisition ou d\'extinction d\'un droit par l\'écoulement d\'un certain temps (prescription d\'une dette, d\'un crime)."],"phonetique":"/pʁɛs.kʁip.sjɔ̃/","etymologie":"Du latin praescriptio, « ce qui est écrit en tête, prescription », de praescribere (« écrire en tête, prescrire »), de prae- (« devant ») et scribere (« écrire »).","registre":"courant","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["ordonnance","directive","recommandation","péremption"],"antonymes":["interdiction","imprescriptibilité"],"exemplesCorrects":["Le pharmacien refuse de délivrer ce médicament sans prescription.","Le délai de prescription de ce délit est de six ans.","Les prescriptions du cahier des charges doivent être respectées à la lettre."],"exemplesIncorrects":["La prescription de ce livre par la censure a fait scandale.","Le tyran ordonna la prescription de ses opposants politiques."],"distracteurs":["proscription","souscription","inscription"],"anecdote":"« Prescription » et « proscription » sont des contraires déguisés en paronymes. La prescription est un ordre ou l\'extinction d\'un droit par le temps ; la proscription est une interdiction, un bannissement.","categorie":"piege-sens","piege":{"formeFautive":"la prescription d\'un opposant (au sens de bannissement)","explication":"Bannir ou interdire quelqu\'un, c\'est le « proscrire » : on parle de « proscription ». La « prescription » est un ordre ou l\'extinction d\'un droit par le temps."}},{"id":"proscription","mot":"proscription","nature":"nom féminin","definitions":["Action de proscrire, d\'interdire formellement quelque chose ; interdiction.","Bannissement, mesure d\'exclusion frappant une personne ou un groupe (les proscriptions de Sylla)."],"phonetique":"/pʁɔs.kʁip.sjɔ̃/","etymologie":"Du latin proscriptio, « affichage d\'une vente, mise hors la loi », de proscribere (« afficher, mettre hors la loi »), de pro- et scribere (« écrire »).","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["interdiction","bannissement","exil","ostracisme"],"antonymes":["autorisation","réhabilitation","amnistie"],"exemplesCorrects":["La proscription de ce terme du langage officiel a fait débat.","Sous Sylla, les proscriptions envoyèrent à la mort des centaines de citoyens.","Le régime décréta la proscription de tous les opposants notoires."],"exemplesIncorrects":["Le médecin a rédigé une proscription pour calmer la douleur.","Sans proscription du médecin, la pharmacie ne délivre pas ce produit."],"distracteurs":["prescription","souscription","conscription","circonscription"],"anecdote":"Ne pas confondre avec « prescription ». La proscription est une interdiction ou un bannissement (les proscriptions romaines) ; la prescription est un ordre, une recommandation (une prescription médicale).","categorie":"piege-sens","piege":{"formeFautive":"rédiger une proscription (au sens d\'ordonnance)","explication":"Une ordonnance médicale est une « prescription ». La « proscription » désigne au contraire une interdiction ou un bannissement."}},{"id":"perpetuel","mot":"perpétuel","nature":"adjectif","definitions":["Qui dure toujours ou est censé durer sans fin ; éternel.","Qui ne cesse pas, qui se répète sans arrêt (des plaintes perpétuelles).","Qui dure toute la vie ou exercé à vie (secrétaire perpétuel)."],"phonetique":"/pɛʁ.pe.tɥɛl/","etymologie":"Du latin perpetualis, de perpetuus (« continu, ininterrompu »), de perpes (« qui se poursuit sans interruption »).","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["éternel","incessant","permanent","continuel"],"antonymes":["temporaire","éphémère","provisoire","passager"],"exemplesCorrects":["Les neiges perpétuelles couronnent les hauts sommets.","Ses jérémiades perpétuelles finissaient par lasser tout le monde.","Le secrétaire perpétuel de l\'Académie veille sur le dictionnaire."],"exemplesIncorrects":["Le juge l\'a condamné à la perpétuel.","Il purge une peine de perpétuel pour ce crime."],"distracteurs":["perpétuité","perpétuer","perpétrer","intarissable"],"anecdote":"« Perpétuel » est un adjectif ; le nom correspondant est « perpétuité ». On dit « une peine de perpétuité » (ou « réclusion à perpétuité »), et non « une peine de perpétuel ». L\'adjectif qualifie ce qui dure sans fin.","categorie":"piege-sens","piege":{"formeFautive":"une peine de perpétuel","explication":"« Perpétuel » est un adjectif. Pour la durée illimitée employée comme nom (notamment la peine), c\'est « perpétuité » : réclusion à perpétuité."}},{"id":"rabattre","mot":"rabattre","nature":"verbe","definitions":["Ramener vivement vers le bas ou vers soi ; rabaisser, replier (rabattre un col, un capot).","Diminuer, retrancher d\'un prix, d\'une prétention (rabattre du prix).","Rabattre du gibier : le rabattre vers les chasseurs en le poussant."],"phonetique":"/ʁa.batʁ/","etymologie":"Dérivé de battre, avec le préfixe re- (ra-), au sens de « ramener en frappant, repousser ».","registre":"courant","niveau":2,"themes":["quotidien","nature"],"synonymes":["replier","rabaisser","déduire","diminuer"],"antonymes":["relever","majorer","augmenter"],"exemplesCorrects":["Le vent rabattait la fumée sur le village.","Le commerçant a accepté de rabattre dix euros sur le prix affiché.","Les chiens rabattaient le gibier vers la ligne des chasseurs."],"exemplesIncorrects":["Il nous rabat les oreilles avec ses exploits de jeunesse.","Cesse de me rabattre cette histoire, je la connais par cœur."],"distracteurs":["rebattre","rabrouer","ravaler"],"anecdote":"« Rabattre » (ramener vers le bas, diminuer) et « rebattre » (battre de nouveau) se confondent surtout dans l\'expression « rebattre les oreilles » — répéter sans cesse —, où la bonne forme est bien « rebattre », et non « rabattre ».","categorie":"piege-sens","piege":{"formeFautive":"rabattre les oreilles à quelqu\'un","explication":"L\'expression correcte est « rebattre les oreilles » (répéter sans cesse). « Rabattre » signifie ramener vers le bas ou diminuer un prix."}},{"id":"rebattre-les-oreilles","mot":"rebattre les oreilles","nature":"locution","definitions":["Répéter sans cesse la même chose à quelqu\'un, au point de l\'importuner ; lui en parler avec insistance."],"phonetique":"/ʁə.batʁ.le.z‿ɔ.ʁɛj/","etymologie":"De rebattre (« battre de nouveau, répéter »), composé de re- (itératif) et battre, du latin battuere (« frapper »).","registre":"courant","niveau":2,"themes":["quotidien","litteraire"],"synonymes":["seriner","ressasser","rabâcher","répéter"],"antonymes":[],"exemplesCorrects":["Il nous rebat les oreilles de ses succès en Bourse.","Ma grand-mère me rebattait les oreilles avec ses proverbes.","On nous a tellement rebattu les oreilles de ce slogan qu\'il en perd tout sens."],"exemplesIncorrects":["Il nous rabat les oreilles avec ses histoires de pêche.","Cesse de me rabattre les oreilles avec cette vieille rengaine."],"distracteurs":["rabattre les oreilles","casser les pieds","débattre","dresser l\'oreille"],"anecdote":"On écrit et dit fautivement « rabattre les oreilles ». La forme correcte est « rebattre les oreilles » : rebattre, c\'est battre de nouveau, donc répéter. « Rabattre » (ramener vers le bas) n\'a rien à voir.","categorie":"expression","piege":{"formeFautive":"rabattre les oreilles","explication":"La locution correcte est « rebattre les oreilles », de « rebattre » (répéter). La forme « rabattre les oreilles » est une faute courante."}},{"id":"cense","mot":"censé","nature":"adjectif","definitions":["Qui est supposé, présumé faire quelque chose ; réputé être ou faire.","Considéré comme tel par convention ou présomption (souvent suivi d\'un infinitif)."],"phonetique":"/sɑ̃.se/","etymologie":"Du latin census, participe passé de censere (« évaluer, estimer, recenser »). Le mot s\'est spécialisé en français au sens de « supposé, présumé » à partir du XVIe siècle.","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["supposé","présumé","réputé","tenu de"],"antonymes":[],"exemplesCorrects":["Nul n\'est censé ignorer la loi.","Tu étais censé arriver à huit heures, pas à dix.","Ce document est censé prouver son innocence."],"exemplesIncorrects":["Il a pris une décision censée après mûre réflexion.","Voilà un raisonnement parfaitement censé et logique.","Elle a tenu des propos très censés pendant la réunion."],"distracteurs":["obligé","destiné","autorisé","habilité"],"anecdote":"On confond très souvent « censé » avec « sensé ». « Censé » signifie « supposé » (il est censé venir), tandis que « sensé » signifie « plein de bon sens » (un avis sensé). Astuce : « censé » se rapproche de « recensé, recensement », l\'idée d\'être compté comme.","categorie":"piege-sens","piege":{"formeFautive":"sensé (au sens de supposé)","explication":"« Censé » (avec un c) veut dire « supposé, présumé » : il est censé arriver. À ne pas écrire « sensé », qui signifie « doté de bon sens »."}},{"id":"sense","mot":"sensé","nature":"adjectif","definitions":["Qui a du bon sens, qui est doué de raison et de jugement.","Conforme à la raison ; raisonnable, judicieux (en parlant d\'une chose)."],"phonetique":"/sɑ̃.se/","etymologie":"Dérivé de sens (du latin sensus, « faculté de sentir, de juger »), avec le suffixe adjectival -é. Le mot exprime l\'idée de « pourvu de sens, de jugement ».","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["raisonnable","judicieux","avisé","réfléchi"],"antonymes":["insensé","absurde","déraisonnable"],"exemplesCorrects":["C\'est une personne sensée, à qui l\'on peut se fier.","Sa proposition me paraît tout à fait sensée.","Il a tenu des propos sensés au milieu de la panique générale."],"exemplesIncorrects":["Personne n\'est sensé connaître les détails de l\'affaire.","Tu étais sensé fermer la porte en partant.","Le facteur est sensé passer avant midi."],"distracteurs":["érudit","cultivé","instruit","perspicace"],"anecdote":"« Sensé » (plein de bon sens) est régulièrement écrit à tort « censé » et inversement. Pour ne pas se tromper : si l\'on peut remplacer par « raisonnable », c\'est « sensé » ; si l\'on peut remplacer par « supposé », c\'est « censé ».","categorie":"piege-sens","piege":{"formeFautive":"censé (au sens de raisonnable)","explication":"« Sensé » (avec un s) qualifie ce qui a du bon sens : un projet sensé. À ne pas confondre avec « censé », qui veut dire « supposé »."}},{"id":"abjurer","mot":"abjurer","nature":"verbe","definitions":["Renoncer solennellement et publiquement à une religion, une croyance ou une opinion.","Par extension, abandonner formellement quelque chose que l\'on tenait pour vrai ou auquel on était attaché."],"phonetique":"/ab.ʒy.ʁe/","etymologie":"Emprunté au latin abjurare (« nier par serment »), de ab- (« loin de ») et jurare (« jurer »). L\'idée première est de « renier par serment ».","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["renier","abandonner","apostasier","renoncer à"],"antonymes":["embrasser","professer","adopter"],"exemplesCorrects":["Sous la menace, il dut abjurer sa foi devant l\'assemblée.","Henri IV abjura le protestantisme pour accéder au trône.","Elle refusa d\'abjurer ses convictions, quoi qu\'il lui en coûtât."],"exemplesIncorrects":["Je vous abjure de m\'écouter une dernière fois.","Il l\'abjura à genoux de lui pardonner.","Les naufragés abjuraient le ciel de les épargner."],"distracteurs":["proclamer","confesser","invoquer","sermonner"],"anecdote":"« Abjurer » est souvent confondu avec « adjurer ». Abjurer, c\'est renier solennellement une croyance ; adjurer, c\'est supplier instamment. Le piège tient à la seule lettre b/d et à la proximité sonore.","categorie":"piege-sens","piege":{"formeFautive":"adjurer (au sens de renier)","explication":"« Abjurer » signifie renoncer solennellement à une foi ou une opinion. À ne pas confondre avec « adjurer », qui veut dire supplier instamment."}},{"id":"adjurer","mot":"adjurer","nature":"verbe","definitions":["Supplier quelqu\'un avec insistance, au nom de ce qu\'il a de plus sacré.","Sommer solennellement, conjurer instamment de faire quelque chose."],"phonetique":"/ad.ʒy.ʁe/","etymologie":"Emprunté au latin adjurare (« conjurer, supplier au nom des dieux »), de ad- (« vers ») et jurare (« jurer »). L\'idée est d\'« obtenir par serment ».","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["supplier","conjurer","implorer","sommer"],"antonymes":[],"exemplesCorrects":["Je vous adjure de me dire la vérité.","Elle l\'adjura, au nom de leur amitié, de renoncer à ce duel.","Le prêtre adjura le possédé de quitter ce corps."],"exemplesIncorrects":["Contraint par l\'Inquisition, il finit par adjurer sa foi.","Le roi adjura le catholicisme pour des raisons politiques.","Après des années de doute, le philosophe adjura toute croyance."],"distracteurs":["réprimander","interpeller","apostropher","haranguer"],"anecdote":"« Adjurer » (supplier instamment) se confond souvent avec « abjurer » (renier sa foi). Le moyen mnémotechnique : adjurer est de la même famille que conjurer, l\'idée d\'une prière pressante adressée à quelqu\'un.","categorie":"piege-sens","piege":{"formeFautive":"abjurer (au sens de supplier)","explication":"« Adjurer » signifie supplier avec insistance. À ne pas confondre avec « abjurer », qui veut dire renier solennellement une croyance."}},{"id":"denuder","mot":"dénuder","nature":"verbe","definitions":["Mettre à nu, dépouiller de ce qui couvre ; découvrir.","Débarrasser un fil, un câble de sa gaine ou de son isolant.","En parlant du sol, d\'un arbre, etc. : dépouiller de ce qui le recouvre (végétation, écorce)."],"phonetique":"/de.ny.de/","etymologie":"Du latin denudare (« mettre à nu »), de de- (intensif) et nudare (« dénuder »), lui-même de nudus (« nu »).","registre":"courant","niveau":2,"themes":["quotidien","nature"],"synonymes":["découvrir","dévêtir","dépouiller","dégarnir"],"antonymes":["couvrir","vêtir","habiller","recouvrir"],"exemplesCorrects":["L\'électricien dénude le fil avant de le raccorder.","Le vent d\'automne a dénudé les branches du vieux chêne.","Elle dénuda son épaule pour montrer la cicatrice."],"exemplesIncorrects":["Ce village est dénudé de tout commerce depuis des années.","Son discours était dénudé d\'intérêt.","Il se retrouva dénudé de ressources après le procès."],"distracteurs":["entailler","gratter","raboter","éroder"],"anecdote":"On confond parfois le verbe « dénuder » (mettre à nu) avec l\'adjectif « dénué » (privé de). On dénude un fil électrique, mais une argumentation est dénuée de fondement, jamais « dénudée de fondement ».","categorie":"piege-sens","piege":{"formeFautive":"dénué (au sens de mettre à nu)","explication":"« Dénuder » signifie mettre à nu (dénuder un fil). À ne pas confondre avec « dénué », adjectif signifiant « privé de » : un propos dénué de sens."}},{"id":"habilete","mot":"habileté","nature":"nom féminin","definitions":["Qualité de celui qui est habile ; adresse, dextérité dans l\'exécution.","Caractère de ce qui est fait avec adresse et intelligence ; finesse, ingéniosité."],"phonetique":"/a.bil.te/","etymologie":"Dérivé de habile (du latin habilis, « maniable, apte »), avec le suffixe -eté. La forme moderne s\'est fixée par influence de l\'adjectif habile.","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["adresse","dextérité","savoir-faire","ingéniosité"],"antonymes":["maladresse","gaucherie","inhabileté"],"exemplesCorrects":["Il manie le pinceau avec une habileté remarquable.","Son habileté à désamorcer les conflits force l\'admiration.","L\'artisan tailla la pierre avec une habileté consommée."],"exemplesIncorrects":["Le tribunal lui a retiré son habileté à gérer ses biens.","Cette procuration confère l\'habileté de signer les contrats.","Sans cette habileté juridique, il ne peut pas voter en assemblée."],"distracteurs":["patience","rapidité","élégance","prudence"],"anecdote":"« Habileté » (adresse) est parfois confondue avec « habilité » (capacité juridique reconnue par la loi). On admire l\'habileté d\'un joueur d\'échecs, mais on parle de l\'habilité d\'un mandataire à agir au nom d\'autrui.","categorie":"piege-sens","piege":{"formeFautive":"habilité (au sens d\'adresse)","explication":"« Habileté » désigne l\'adresse, le savoir-faire. À ne pas confondre avec « habilité », qui désigne une aptitude légale conférée par le droit."}},{"id":"habilite","mot":"habilité","nature":"nom féminin","definitions":["Aptitude légale, capacité juridique reconnue à une personne pour accomplir un acte.","Droit, qualité conféré par la loi ou une autorité pour agir."],"phonetique":"/a.bi.li.te/","etymologie":"Emprunté au latin juridique habilitas (« aptitude »), de habilis (« apte »). Terme de droit, distinct de la forme populaire « habileté ».","registre":"soutenu","niveau":4,"themes":["abstrait"],"synonymes":["aptitude","capacité","qualité","pouvoir"],"antonymes":["incapacité","inhabilité"],"exemplesCorrects":["La loi reconnaît à l\'héritier l\'habilité à recueillir la succession.","Le mineur émancipé acquiert une certaine habilité juridique.","On contesta l\'habilité du témoin à déposer devant la cour."],"exemplesIncorrects":["Le pianiste exécuta le morceau avec une grande habilité.","Son habilité manuelle lui permet de tout réparer.","Le prestidigitateur déploya une habilité stupéfiante."],"distracteurs":["immunité","responsabilité","notoriété","ancienneté"],"anecdote":"« Habilité » est un terme juridique signifiant « aptitude légale », à ne pas confondre avec « habileté » (adresse, dextérité). On dit l\'habileté d\'un artiste, mais l\'habilité à hériter au sens du droit.","categorie":"piege-sens","piege":{"formeFautive":"habileté (au sens d\'aptitude légale)","explication":"« Habilité » désigne une capacité juridique reconnue par la loi. À ne pas confondre avec « habileté », qui signifie adresse ou dextérité."}},{"id":"amoral","mot":"amoral","nature":"adjectif","definitions":["Qui est étranger à la morale, qui se situe en dehors de toute considération morale.","Qui ne connaît ni n\'applique de règles morales, sans pour autant les transgresser sciemment."],"phonetique":"/a.mɔ.ʁal/","etymologie":"Formé du préfixe privatif a- (« absence de », du grec) et de moral (du latin moralis). Le a- marque ici la neutralité, non l\'opposition.","registre":"soutenu","niveau":3,"themes":["abstrait"],"synonymes":["non-moral","indifférent à la morale","areligieux"],"antonymes":["moral","moraliste"],"exemplesCorrects":["La nature est amorale : elle ignore le bien et le mal.","Un nourrisson est un être amoral, qui n\'a pas encore conscience des règles.","La science, en tant que telle, est amorale.","Le marché financier obéit à une logique amorale, étrangère aux notions de bien et de mal."],"exemplesIncorrects":["Voler les pauvres est un acte profondément amoral et révoltant.","Ce dictateur amoral a fait fusiller des innocents.","Sa conduite amorale a scandalisé tout le village."],"distracteurs":["asexué","apolitique","neutre","incolore"],"anecdote":"« Amoral » (en dehors de la morale, neutre) est sans cesse confondu avec « immoral » (contraire à la morale). Un paysage est amoral ; un crime est immoral. Le préfixe a- marque l\'absence, le préfixe in- marque l\'opposition.","categorie":"piege-sens","piege":{"formeFautive":"immoral (au sens d\'étranger à la morale)","explication":"« Amoral » signifie « étranger à toute morale », neutre. À ne pas confondre avec « immoral », qui qualifie ce qui est contraire à la morale."}},{"id":"immoral","mot":"immoral","nature":"adjectif","definitions":["Qui est contraire à la morale, qui viole les règles morales établies.","Qui choque les bonnes mœurs, qui pousse à la dépravation."],"phonetique":"/i.mɔ.ʁal/","etymologie":"Formé du préfixe négatif in- (devenu im- devant m), marquant l\'opposition, et de moral (du latin moralis). Le préfixe in- exprime ici la contrariété.","registre":"courant","niveau":3,"themes":["abstrait"],"synonymes":["dépravé","corrompu","scandaleux"],"antonymes":["moral","vertueux","honnête"],"exemplesCorrects":["Trahir la confiance d\'un ami est un acte immoral.","On lui reprochait de tenir des propos immoraux devant des enfants.","Cette spéculation sur la misère humaine est profondément immorale."],"exemplesIncorrects":["Une pierre qui roule est un objet parfaitement immoral.","Les lois de la physique sont immorales par définition.","Le nouveau-né, encore immoral, ne distingue pas le bien du mal."],"distracteurs":["illégal","cruel","mensonger","déloyal"],"anecdote":"« Immoral » (contraire à la morale) est souvent employé à la place d\'« amoral » (en dehors de la morale). Un escroc est immoral ; un caillou ou une machine est amoral. Le préfixe in-/im- marque l\'opposition, là où a- marque l\'absence.","categorie":"piege-sens","piege":{"formeFautive":"amoral (au sens de contraire à la morale)","explication":"« Immoral » qualifie ce qui transgresse la morale. À ne pas confondre avec « amoral », qui désigne ce qui est neutre, hors du champ de la morale."}},{"id":"original","mot":"original","nature":"adjectif","definitions":["Qui émane directement de la source, qui est le premier exemplaire (un document original).","Qui ne ressemble à rien d\'autre ; neuf, singulier, inédit.","Qui se distingue par son caractère bizarre, excentrique (en parlant d\'une personne)."],"phonetique":"/ɔ.ʁi.ʒi.nal/","etymologie":"Emprunté au bas latin originalis (« qui existe dès l\'origine »), de origo, originis (« origine »). Le sens de « singulier, neuf » s\'est développé en français à partir du XVIIe siècle.","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["inédit","neuf","singulier","authentique"],"antonymes":["banal","commun","copie","ordinaire"],"exemplesCorrects":["Le notaire conserve l\'acte original dans son coffre.","Cette mise en scène est d\'une grande originalité, vraiment originale.","C\'est un homme original, qui s\'habille de manière surprenante."],"exemplesIncorrects":["Le péché original a entaché toute l\'humanité selon la doctrine.","On a retrouvé la version originale du texte, celle des tout premiers temps de l\'humanité.","Adam et Ève vivaient dans la pureté originale du jardin."],"distracteurs":["officiel","manuscrit","certifié","intégral"],"anecdote":"« Original » (de la source, ou singulier) est parfois confondu avec « originel » (qui remonte à l\'origine, primitif). On parle du document original, mais du péché originel et du sens originel d\'un mot.","categorie":"piege-sens","piege":{"formeFautive":"originel (au sens de premier exemplaire ou singulier)","explication":"« Original » désigne ce qui émane de la source ou ce qui est singulier, neuf. À ne pas confondre avec « originel », qui signifie « qui remonte à l\'origine, primitif »."}},{"id":"originel","mot":"originel","nature":"adjectif","definitions":["Qui date de l\'origine, qui remonte à la source première ; primitif, initial.","Qui appartient à l\'état des commencements (notamment en théologie : le péché originel)."],"phonetique":"/ɔ.ʁi.ʒi.nɛl/","etymologie":"Dérivé de origine (du latin origo, originis, « origine »), avec le suffixe -el. « Originel » a conservé le sens étymologique de « relatif au commencement », là où « original » a évolué vers « singulier ».","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["primitif","initial","premier","natif"],"antonymes":["final","ultérieur","acquis","dérivé"],"exemplesCorrects":["Le sens originel de ce mot s\'est perdu au fil des siècles.","La doctrine chrétienne enseigne le péché originel.","On a restitué au tableau ses couleurs originelles."],"exemplesIncorrects":["Le notaire m\'a remis l\'exemplaire originel du contrat.","Quel esprit originel : il a toujours des idées surprenantes !","Sa tenue était vraiment originelle, on ne voit ça nulle part ailleurs."],"distracteurs":["ancestral","légendaire","fondateur","immémorial"],"anecdote":"« Originel » (qui remonte à l\'origine) est souvent confondu avec « original » (de la source, ou singulier). On dit le péché originel et le sens originel, mais un esprit original et un document original.","categorie":"piege-sens","piege":{"formeFautive":"original (au sens de primitif, des origines)","explication":"« Originel » signifie « qui remonte à l\'origine, primitif » : le péché originel. À ne pas confondre avec « original », qui veut dire « de la source » ou « singulier, neuf »."}},{"id":"partial","mot":"partial","nature":"adjectif","definitions":["Qui prend parti, qui manque d\'objectivité au profit d\'un camp ; injuste par préférence.","Qui témoigne d\'un parti pris (en parlant d\'un jugement, d\'une attitude)."],"phonetique":"/paʁ.sjal/","etymologie":"Dérivé savant du latin pars, partis (« partie, parti »), avec le suffixe -ial. Il exprime l\'idée de « prendre le parti d\'un côté ».","registre":"soutenu","niveau":3,"themes":["abstrait"],"synonymes":["partisan","injuste","tendancieux","prévenu"],"antonymes":["impartial","objectif","équitable","neutre"],"exemplesCorrects":["Un arbitre partial décrédibilise toute la compétition.","Son compte rendu, manifestement partial, favorisait son ami.","On l\'a récusé pour avoir rendu un jugement partial."],"exemplesIncorrects":["Le remboursement n\'a été que partial, il manque la moitié.","Une éclipse partiale a assombri le ciel cet après-midi.","Il a obtenu un succès partial à son examen."],"distracteurs":["sévère","intransigeant","arbitraire","complaisant"],"anecdote":"« Partial » (qui prend parti) est souvent confondu avec « partiel » (incomplet, qui ne concerne qu\'une partie). Un juge peut être partial ; un remboursement, lui, est partiel. On les prononce d\'ailleurs différemment : /paʁ.sjal/ pour partial, /paʁ.sjɛl/ pour partiel.","categorie":"piege-sens","piege":{"formeFautive":"partiel (au sens de qui prend parti)","explication":"« Partial » signifie « qui manque d\'objectivité, qui prend parti ». À ne pas confondre avec « partiel », qui veut dire « incomplet, qui ne concerne qu\'une partie »."}},{"id":"venerer","mot":"vénérer","nature":"verbe","definitions":["Honorer avec un profond respect mêlé d\'affection ou de dévotion religieuse.","Avoir une admiration extrême pour quelqu\'un ou quelque chose."],"phonetique":"/ve.ne.ʁe/","etymologie":"Emprunté au latin venerari (« honorer, révérer »), dérivé de Venus, Veneris (« Vénus, désir, charme »).","registre":"soutenu","niveau":2,"themes":["abstrait","litteraire"],"synonymes":["révérer","adorer","idolâtrer","honorer"],"antonymes":["mépriser","honnir","bafouer"],"exemplesCorrects":["Les fidèles vénèrent les reliques du saint depuis des siècles.","Il vénérait son vieux maître comme un second père.","On vénère la mémoire des héros disparus."],"exemplesIncorrects":["Le médecin a diagnostiqué une maladie vénérer.","Il a contracté une affection vénérer après son séjour.","Cette infection vénérer se soigne par antibiotiques."],"distracteurs":["célébrer","craindre","côtoyer"],"anecdote":"On confond parfois « vénérer » (honorer) avec l\'adjectif « vénérien » (relatif aux maladies sexuellement transmissibles, « les amours » de Vénus). Les deux mots remontent pourtant à la même déesse Vénus : l\'un en a gardé le culte, l\'autre le revers charnel.","categorie":"piege-sens","piege":{"formeFautive":"vénérien (au sens de honorer)","explication":"« Vénérer » signifie honorer avec respect ; « vénérien » qualifie les maladies liées aux rapports amoureux. Malgré leur racine commune (Vénus), ce sont deux registres opposés."}},{"id":"suggestion","mot":"suggestion","nature":"nom féminin","definitions":["Idée, proposition que l\'on soumet à quelqu\'un pour qu\'il l\'examine ou l\'adopte.","Action de suggérer ; insinuation discrète d\'une pensée dans l\'esprit d\'autrui."],"phonetique":"/syg.ʒɛs.tjɔ̃/","etymologie":"Emprunté au latin suggestio (« action de fournir, suggestion »), du verbe suggerere (« porter sous, fournir, insinuer »).","registre":"courant","niveau":1,"themes":["abstrait","quotidien"],"synonymes":["proposition","conseil","idée","recommandation"],"antonymes":["ordre","injonction","interdiction"],"exemplesCorrects":["Sa suggestion d\'avancer la réunion a été retenue.","Puis-je me permettre une suggestion sur la mise en page ?","La boîte à suggestions déborde de bonnes idées."],"exemplesIncorrects":["Le servage maintenait les paysans dans une suggestion totale au seigneur.","Réduit à la suggestion, il obéissait sans broncher.","Cette dépendance économique crée une suggestion humiliante."],"distracteurs":["allusion","insinuation","ébauche"],"anecdote":"« Suggestion » (idée proposée) est souvent confondue à l\'oral avec « sujétion » (état de dépendance), deux mots de sens très éloignés. La paronymie est trompeuse : seule « sujétion » exprime la contrainte.","categorie":"piege-sens","piege":{"formeFautive":"sujétion (au sens de proposition)","explication":"« Suggestion » est une idée que l\'on propose ; « sujétion » désigne un état de dépendance ou de contrainte. Ne pas employer l\'un pour l\'autre."}},{"id":"sujetion","mot":"sujétion","nature":"nom féminin","definitions":["État de dépendance, de soumission à une autorité, à une domination.","Contrainte, obligation pénible imposée par une situation ou une activité."],"phonetique":"/sy.ʒe.sjɔ̃/","etymologie":"Emprunté au latin subjectio (« action de placer dessous, soumission »), du verbe subicere (« placer sous, assujettir »).","registre":"soutenu","niveau":3,"themes":["abstrait"],"synonymes":["dépendance","soumission","assujettissement","servitude"],"antonymes":["indépendance","liberté","autonomie","affranchissement"],"exemplesCorrects":["La sujétion des colonies pesait lourdement sur leurs économies.","Ce métier impose des sujétions horaires très contraignantes.","Il refusait toute sujétion à un pouvoir arbitraire."],"exemplesIncorrects":["Je vous soumets une sujétion pour améliorer le projet.","Sa sujétion a été notée et adoptée par le comité.","La boîte à sujétions recueille les idées du personnel."],"distracteurs":["tutelle","emprise","contrainte"],"anecdote":"« Sujétion » (dépendance) est constamment confondue avec « suggestion » (idée proposée), à cause de leur sonorité voisine. Pour la distinguer, on peut penser à « sujet » et à « assujettir », qui partagent sa racine de soumission.","categorie":"piege-sens","piege":{"formeFautive":"suggestion (au sens de dépendance)","explication":"« Sujétion » exprime la dépendance ou la contrainte ; « suggestion » est une proposition. La confusion vient de la paronymie, pas du sens."}},{"id":"irruption","mot":"irruption","nature":"nom féminin","definitions":["Entrée soudaine, brusque et souvent violente dans un lieu.","Envahissement subit d\'un espace par une force, un flux ou une foule."],"phonetique":"/i.ʁyp.sjɔ̃/","etymologie":"Emprunté au latin irruptio (« invasion, irruption »), du verbe irrumpere (« se précipiter dans »), composé de in- (« dans ») et rumpere (« rompre »).","registre":"soutenu","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["invasion","incursion","intrusion"],"antonymes":["sortie","retrait","évacuation"],"exemplesCorrects":["L\'irruption des manifestants dans la salle interrompit le discours.","Son irruption inattendue a glacé toute l\'assemblée.","L\'irruption de la mer dans les terres ravagea le village."],"exemplesIncorrects":["L\'irruption du volcan a recouvert la ville de cendres.","Une irruption cutanée est apparue sur ses bras.","La lave jaillit lors de l\'irruption du cratère."],"distracteurs":["effraction","débarquement","raid"],"anecdote":"On écrit souvent « irruption » à la place d\'« éruption » (et inversement). « Irruption » (deux r) évoque une entrée brutale ; « éruption » (un seul r) un jaillissement vers l\'extérieur, comme celui d\'un volcan.","categorie":"piege-sens","piege":{"formeFautive":"éruption (au sens d\'entrée brusque)","explication":"« Irruption » désigne une entrée soudaine dans un lieu ; « éruption » un jaillissement vers l\'extérieur (volcan, boutons). Un volcan entre en éruption, des intrus font irruption."}},{"id":"eruption","mot":"éruption","nature":"nom féminin","definitions":["Jaillissement soudain et violent de matières (lave, gaz) hors d\'un volcan.","Apparition brusque de lésions sur la peau ; poussée subite d\'un phénomène."],"phonetique":"/e.ʁyp.sjɔ̃/","etymologie":"Emprunté au latin eruptio (« sortie, jaillissement »), du verbe erumpere (« sortir avec violence »), composé de ex- (« hors de ») et rumpere (« rompre »).","registre":"courant","niveau":2,"themes":["nature","abstrait"],"synonymes":["jaillissement","explosion","poussée"],"antonymes":["absorption","résorption","extinction"],"exemplesCorrects":["L\'éruption du Vésuve ensevelit Pompéi en 79.","Une éruption de boutons a couvert son visage.","On assista à une éruption soudaine de joie dans la foule."],"exemplesIncorrects":["L\'éruption des cambrioleurs dans la maison réveilla tout le monde.","Son éruption dans le bureau interrompit la réunion.","La foule fit éruption dans le stade par les grilles forcées."],"distracteurs":["coulée","effusion","embrasement"],"anecdote":"« Éruption » (un seul r, jaillissement) est souvent confondue avec « irruption » (deux r, entrée brusque). Truc mnémotechnique : l\'éruption sort (Ex-), l\'irruption entre (In-).","categorie":"piege-sens","piege":{"formeFautive":"irruption (au sens de jaillissement)","explication":"« Éruption » est un jaillissement vers l\'extérieur (volcan, peau) ; « irruption » est une entrée brutale dans un lieu. On ne fait pas « éruption » dans une pièce."}},{"id":"enduire","mot":"enduire","nature":"verbe","definitions":["Couvrir une surface d\'une couche de matière (peinture, graisse, pâte).","Recouvrir uniformément quelque chose d\'un produit qui adhère."],"phonetique":"/ɑ̃.dɥiʁ/","etymologie":"Du latin inducere (« conduire dans, étendre sur, enduire »), composé de in- (« dans, sur ») et ducere (« conduire »).","registre":"courant","niveau":2,"themes":["quotidien"],"synonymes":["badigeonner","recouvrir","tartiner","oindre"],"antonymes":["décaper","gratter","nettoyer"],"exemplesCorrects":["Il faut enduire le mur de plâtre avant de peindre.","Elle enduit la tarte d\'une fine couche de confiture.","Enduisez la poêle d\'huile pour éviter que ça n\'attache."],"exemplesIncorrects":["De ces faits, on peut enduire une conclusion logique.","Le maître a voulu nous enduire en erreur.","Ces indices m\'enduisent à penser qu\'il est coupable."],"distracteurs":["imprégner","vernir","laquer"],"anecdote":"« Enduire » (couvrir d\'une couche) est parfois confondu avec « induire » (amener à conclure). L\'expression piège est « induire en erreur » : c\'est bien « induire », non « enduire », même si l\'on imagine volontiers « enduire d\'erreur ».","categorie":"piege-sens","piege":{"formeFautive":"induire (au sens de couvrir)","explication":"« Enduire » signifie recouvrir d\'une couche de matière ; « induire » signifie amener à une conclusion. On dit « induire en erreur », pas « enduire en erreur »."}},{"id":"induire","mot":"induire","nature":"verbe","definitions":["Amener quelqu\'un à un acte ou à une conclusion ; pousser à.","Conclure, par le raisonnement, du particulier au général (induction).","Avoir pour conséquence, entraîner."],"phonetique":"/ɛ̃.dɥiʁ/","etymologie":"Du latin inducere (« conduire dans, amener à »), composé de in- (« dans ») et ducere (« conduire »).","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["inciter","entraîner","conduire","inférer"],"antonymes":["déduire","dissuader","empêcher"],"exemplesCorrects":["Ces propos trompeurs visaient à l\'induire en erreur.","De ces observations, le savant induit une loi générale.","La hausse des taux induit un ralentissement de la consommation."],"exemplesIncorrects":["Il faut induire le mur avant de poser le papier peint.","Elle induit le gâteau de chocolat fondu.","Induisez la planche de vernis avant de la sécher."],"distracteurs":["suggérer","provoquer","susciter"],"anecdote":"« Induire » (amener à) se confond souvent avec « enduire » (couvrir d\'une couche). On dit « induire en erreur » ; en logique, « induire » (raisonner du particulier au général) s\'oppose à « déduire » (du général au particulier).","categorie":"piege-sens","piege":{"formeFautive":"enduire (au sens d\'amener à)","explication":"« Induire » signifie amener à une conclusion ou un acte ; « enduire » signifie recouvrir d\'une couche. La locution correcte est « induire en erreur »."}},{"id":"fruste","mot":"fruste","nature":"adjectif","definitions":["Qui manque de finesse, de culture ou de raffinement ; grossier, rude.","En parlant d\'une œuvre, d\'une monnaie : usé, dont le relief est effacé."],"phonetique":"/fʁyst/","etymologie":"Emprunté à l\'italien frusto (« usé, élimé »), du latin frustum (« morceau, fragment »). Le sens de « grossier » résulte d\'un croisement avec « rustre ».","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["grossier","rude","inculte","primitif"],"antonymes":["raffiné","délicat","policé","cultivé"],"exemplesCorrects":["C\'était un homme fruste, peu porté aux belles manières.","Ses manières frustes détonnaient dans ce salon élégant.","La médaille, fruste, avait perdu tout son relief."],"exemplesIncorrects":["Il a un caractère frustre et sans nuances.","Ces paysans frustres ignoraient les usages de la cour.","Son style frustre manquait de toute élégance."],"distracteurs":["frivole","fébrile","frêle"],"anecdote":"Beaucoup écrivent « frustre » par contamination avec « frustré » ou « rustre ». La forme correcte est « fruste », sans r après le t.","categorie":"piege-orthographe","piege":{"formeFautive":"frustre","explication":"On écrit « fruste » (sans r interne), et non « frustre ». La faute vient de l\'attraction de « frustré » et « rustre »."}},{"id":"pecuniaire","mot":"pécuniaire","nature":"adjectif","definitions":["Qui a rapport à l\'argent, qui consiste en argent.","Relatif aux ressources, aux intérêts financiers d\'une personne."],"phonetique":"/pe.ky.njɛʁ/","etymologie":"Emprunté au latin pecuniarius (« relatif à l\'argent »), de pecunia (« richesse, argent »), lui-même dérivé de pecus (« bétail »), la richesse antique se comptant en têtes de bétail.","registre":"soutenu","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["financier","monétaire","matériel"],"antonymes":["moral","honorifique","désintéressé"],"exemplesCorrects":["Il connaît de graves difficultés pécuniaires.","Une sanction pécuniaire a été prononcée contre l\'entreprise.","Son intérêt était purement pécuniaire."],"exemplesIncorrects":["Il a des soucis pécuniers en ce moment.","Une amende pécunière lui fut infligée.","Ses ennuis pécuniers l\'empêchent de partir."],"distracteurs":["lucratif","fiscal","onéreux"],"anecdote":"L\'adjectif est « pécuniaire » aux deux genres ; la forme « pécunier » (sur le modèle de « financier ») n\'existe pas. Le mot vient de pecus, le « bétail » qui faisait la richesse des Romains.","categorie":"piege-orthographe","piege":{"formeFautive":"pécunier","explication":"L\'adjectif correct est « pécuniaire », identique au masculin et au féminin. « Pécunier / pécunière » n\'existe pas."}},{"id":"se-targuer","mot":"se targuer","nature":"locution","definitions":["Se vanter, se prévaloir avec ostentation de quelque chose.","Tirer orgueil d\'un avantage, réel ou supposé."],"phonetique":"/sə.taʁ.ɡe/","etymologie":"Dérivé de l\'ancien français targuer, targier (« se couvrir d\'un bouclier »), de targe (« bouclier médiéval »), d\'origine germanique. Se targuer, c\'est au figuré se faire valoir derrière un écu.","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["se vanter","se prévaloir","se piquer","se flatter"],"antonymes":["se déprécier","s\'humilier","minimiser"],"exemplesCorrects":["Il se targue d\'avoir lu tout Proust.","Elle se targuait d\'une ascendance illustre.","Ils se targuent d\'une expérience qu\'ils n\'ont pas."],"exemplesIncorrects":["Il se targe de ses succès passés.","Elle se targait de connaître le ministre.","Ne te targe pas trop vite de ta victoire."],"distracteurs":["se rebiffer","se morfondre","se gausser"],"anecdote":"Le verbe se conjugue avec un u : « il se targue », et non « il se targe ». Il vient de la « targe », un bouclier médiéval : se targuer, c\'est au fond se faire valoir derrière un écu.","categorie":"piege-orthographe","piege":{"formeFautive":"se targer","explication":"Le verbe est « se targuer » (avec u maintenu à toutes les formes : il se targue) et non « se targer »."}},{"id":"remunerer","mot":"rémunérer","nature":"verbe","definitions":["Payer quelqu\'un en contrepartie d\'un travail ou d\'un service.","Récompenser par une somme d\'argent une activité, une peine."],"phonetique":"/ʁe.my.ne.ʁe/","etymologie":"Emprunté au latin remunerari (« récompenser »), composé de re- et munus, muneris (« don, présent, charge »).","registre":"courant","niveau":2,"themes":["abstrait","quotidien"],"synonymes":["payer","rétribuer","salarier","récompenser"],"antonymes":["spolier","exploiter","gruger"],"exemplesCorrects":["L\'entreprise rémunère ses stagiaires correctement.","Ce travail est mal rémunéré au regard de sa pénibilité.","On l\'a rémunéré généreusement pour son expertise."],"exemplesIncorrects":["Il faut rénumérer les heures supplémentaires.","Le club rénumère ses bénévoles en bons d\'achat.","Ce poste est très bien rénuméré."],"distracteurs":["indemniser","gratifier","défrayer"],"anecdote":"On dit et écrit souvent « rénumérer » par métathèse, en croyant y entendre « numéro ». La forme correcte est « rémunérer », de la même famille que « munificence » (du latin munus, le don).","categorie":"piege-orthographe","piege":{"formeFautive":"rénumérer","explication":"On écrit « rémunérer » (mu avant nu), non « rénumérer ». La faute vient d\'une inversion de sons par fausse association avec « numéro »."}},{"id":"denue-de-fondement","mot":"dénué de fondement","nature":"locution","definitions":["Qui ne repose sur rien de solide ; sans justification ni preuve ; injustifié."],"phonetique":"/de.ny də fɔ̃.də.mɑ̃/","etymologie":"De « dénué » (participe passé de l\'ancien verbe « dénuer », du latin « denudare », mettre à nu) et de « fondement ». Littéralement « dépourvu de base ».","registre":"soutenu","niveau":2,"themes":["abstrait","litteraire"],"synonymes":["infondé","injustifié","gratuit","sans fondement"],"antonymes":["fondé","justifié","étayé","avéré"],"exemplesCorrects":["Ces accusations sont totalement dénuées de fondement.","Sa crainte, bien que vive, s\'est révélée dénuée de fondement.","Le tribunal a jugé la plainte dénuée de fondement et l\'a rejetée."],"exemplesIncorrects":["Il marchait pieds nus, dénué de fondement sur le sol.","Ce gâteau est dénué de fondement, il faut rajouter de la farine."],"distracteurs":["spécieux","fallacieux","péremptoire","captieux"],"anecdote":"On entend ou lit parfois « dénudé de fondement », ce qui est fautif : « dénudé » signifie « mis à nu », alors que c\'est « dénué » (privé de) qui convient ici.","categorie":"expression","piege":{"formeFautive":"dénudé de fondement","explication":"« Dénudé » veut dire « mis à nu » ; la forme correcte est « dénué de fondement », c\'est-à-dire « dépourvu de fondement »."}},{"id":"savoir-gre","mot":"savoir gré","nature":"locution","definitions":["Être reconnaissant à quelqu\'un de quelque chose ; lui en avoir de la gratitude."],"phonetique":"/sa.vwaʁ ɡʁe/","etymologie":"De « savoir » (latin « sapere ») et de « gré » (latin « gratum », ce qui est agréable). Le tour signifie littéralement « tenir pour agréable », d\'où « être reconnaissant ».","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["être reconnaissant","savoir bon gré","remercier"],"antonymes":["en vouloir","tenir rigueur","reprocher"],"exemplesCorrects":["Je vous saurais gré de bien vouloir me répondre rapidement.","Elle nous a su gré de notre discrétion.","Nous vous saurions gré de confirmer votre présence."],"exemplesIncorrects":["Je vous serais gré de votre aide.","Il m\'a été gré de mon soutien sans faille."],"distracteurs":["complaire","agréer","obliger","gratifier"],"anecdote":"La faute la plus répandue consiste à écrire « je vous serais gré » (avec le verbe être) au lieu de « je vous saurais gré » : c\'est bien le verbe SAVOIR qu\'il faut conjuguer, « savoir gré » signifiant « être reconnaissant ».","categorie":"expression","piege":{"formeFautive":"je vous serais gré","explication":"La locution est « savoir gré » : il faut conjuguer le verbe savoir (« je vous saurais gré »), et non être."}},{"id":"venal","mot":"vénal","nature":"adjectif","definitions":["Qui se laisse acheter, qui agit par appât du gain au mépris de la morale ; corruptible.","Qui se fait, s\'obtient à prix d\'argent ; qui est l\'objet d\'un commerce."],"phonetique":"/ve.nal/","etymologie":"Emprunté au latin « venalis », « qui est à vendre, qu\'on peut acheter », dérivé de « venum », la vente.","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["corruptible","cupide","intéressé","mercenaire"],"antonymes":["intègre","incorruptible","désintéressé","probe"],"exemplesCorrects":["Ce fonctionnaire vénal monnayait chacune de ses décisions.","Sous l\'Ancien Régime, certaines charges étaient vénales et se transmettaient à prix d\'or.","Une presse vénale ne sert que les intérêts de ceux qui la financent."],"exemplesIncorrects":["Il n\'a commis qu\'un péché vénal, vite pardonné par le prêtre.","Cette petite faute vénale n\'a guère porté à conséquence."],"distracteurs":["servile","obséquieux","rapace","fielleux"],"anecdote":"« Vénal » se confond souvent avec « véniel » : le premier qualifie ce qui est corruptible ou à vendre, le second un péché léger et pardonnable. Un péché est donc « véniel », jamais « vénal ».","categorie":"piege-sens","piege":{"formeFautive":"un péché vénal","explication":"On confond « vénal » (corruptible, qui se vend) avec « véniel » (péché léger). Un péché est « véniel »."}},{"id":"veniel","mot":"véniel","nature":"adjectif","definitions":["Se dit d\'un péché léger, qui n\'entraîne pas la perte de la grâce et que l\'on peut aisément pardonner (par opposition à mortel).","Par extension, qui est sans gravité, excusable."],"phonetique":"/ve.njɛl/","etymologie":"Emprunté au latin chrétien « venialis », « digne de pardon », dérivé de « venia », « grâce, pardon, faveur ».","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["pardonnable","léger","excusable","bénin"],"antonymes":["mortel","grave","impardonnable","capital"],"exemplesCorrects":["Le catéchisme distingue le péché mortel du péché véniel.","Ce n\'était qu\'une faute vénielle, vite oubliée.","Mentir par politesse lui paraissait un manquement tout à fait véniel."],"exemplesIncorrects":["Ce juge véniel acceptait des pots-de-vin sans scrupule.","Une charge vénielle s\'achetait fort cher sous la monarchie."],"distracteurs":["anodin","futile","insignifiant","négligeable"],"anecdote":"« Véniel » (péché léger, du latin « venia », pardon) est sans cesse confondu avec « vénal » (corruptible). Astuce : « véniel » et « pardon » partagent la même racine de bienveillance.","categorie":"piege-sens","piege":{"formeFautive":"un fonctionnaire véniel","explication":"On confond « véniel » (péché léger, pardonnable) avec « vénal » (qui se laisse acheter). Un fonctionnaire corrompu est « vénal »."}},{"id":"litterature","mot":"littérature","nature":"nom féminin","definitions":["Ensemble des œuvres écrites auxquelles on reconnaît une valeur esthétique ; l\'art d\'écrire considéré dans ses productions.","Ensemble des ouvrages publiés sur un sujet donné ; bibliographie."],"phonetique":"/li.te.ʁa.tyʁ/","etymologie":"Emprunté au latin « litteratura », « écriture, grammaire, érudition », dérivé de « littera », la lettre.","registre":"courant","niveau":1,"themes":["litteraire","abstrait"],"synonymes":["lettres","belles-lettres","écrits"],"antonymes":[],"exemplesCorrects":["La littérature française du XIXe siècle l\'avait toujours fasciné.","Il existe une abondante littérature scientifique sur la question.","Elle a consacré sa thèse à la littérature de l\'absurde."],"exemplesIncorrects":["J\'ai lu un beau roman de litérature classique.","Ce litérateur a publié son premier recueil de poèmes."],"distracteurs":["philologie","rhétorique","érudition","poétique"],"anecdote":"Le mot prend deux T (« littérature »), comme « lettre » dont il dérive. L\'orthographe fautive « litérature » avec un seul T est fréquente ; à ne pas confondre non plus avec « littérateur », l\'homme de lettres.","categorie":"piege-orthographe","piege":{"formeFautive":"litérature","explication":"Le mot s\'écrit avec deux T : « littérature », comme « lettre » et « littéraire », tous issus du latin « littera »."}},{"id":"scabreux","mot":"scabreux","nature":"adjectif","definitions":["Qui présente des difficultés, des risques ; délicat, embarrassant à traiter.","Qui choque la décence ; licencieux, osé."],"phonetique":"/ska.bʁø/","etymologie":"Emprunté au bas latin « scabrosus », « rude, raboteux », dérivé de « scaber », « rugueux, âpre ». Le sens propre de « raboteux » a évolué vers « difficile, délicat ».","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["délicat","épineux","périlleux","licencieux"],"antonymes":["aisé","anodin","décent","convenable"],"exemplesCorrects":["Aborder ce sujet scabreux en public exigeait beaucoup de tact.","Il s\'est lancé dans une entreprise scabreuse aux résultats incertains.","Le conteur glissait parfois quelques anecdotes un peu scabreuses."],"exemplesIncorrects":["Le chemin était scabreux et fleuri sous le soleil printanier.","Ce dessert scabreux était d\'une douceur exquise."],"distracteurs":["scrupuleux","scrofuleux","squameux","saugrenu"],"anecdote":"On déforme parfois ce mot en « scrabeux » par métathèse : la forme correcte est « scabreux », de la même famille latine que ce qui est rugueux, raboteux.","categorie":"piege-sens","piege":{"formeFautive":"scrabeux","explication":"La forme correcte est « scabreux » ; « scrabeux » résulte d\'une inversion de lettres et n\'existe pas."}},{"id":"acedie","mot":"acédie","nature":"nom féminin","definitions":["État de mélancolie et de torpeur spirituelle, fait de dégoût et de découragement, qui détourne de l\'effort et de la vie intérieure.","Chez les moines, péché de paresse et d\'indifférence envers les choses de l\'âme."],"phonetique":"/a.se.di/","etymologie":"Emprunté, par le latin chrétien « acedia » (nonchalance, paresse spirituelle), au grec « akêdia », « indifférence, négligence », dérivé de « kêdos », « soin, souci » avec le préfixe privatif a-.","registre":"littéraire","niveau":5,"themes":["emotions","abstrait","litteraire"],"synonymes":["torpeur","apathie","neurasthénie","spleen"],"antonymes":["ferveur","ardeur","entrain","allégresse"],"exemplesCorrects":["Une profonde acédie l\'avait gagné, le détournant de toute occupation.","Les Pères du désert décrivaient l\'acédie comme le démon de midi.","Il sombrait dans une acédie où plus rien ne lui semblait digne d\'effort."],"exemplesIncorrects":["Pris d\'une joyeuse acédie, il dansa toute la nuit.","L\'acédie du moteur l\'obligea à changer la batterie."],"distracteurs":["aboulie","anomie","incurie","atonie"],"anecdote":"L\'acédie figurait parmi les huit pensées mauvaises des moines des premiers siècles ; on l\'appelait « le démon de midi », car elle frappait le moine en plein jour, lui inspirant dégoût de sa cellule et de sa vie.","categorie":"mot-rare"},{"id":"nyctalope","mot":"nyctalope","nature":"adjectif","definitions":["Qui voit, ou est censé voir, dans l\'obscurité ; qui distingue les objets par une faible lumière.","En médecine, qui est atteint de nyctalopie (capacité ou trouble de la vision nocturne selon les acceptions)."],"phonetique":"/nik.ta.lɔp/","etymologie":"Emprunté au bas latin « nyctalops », du grec « nuktalôps », composé de « nux, nuktos » (la nuit) et de « ôps » (l\'œil, la vue).","registre":"soutenu","niveau":4,"themes":["nature","abstrait"],"synonymes":["noctambule"],"antonymes":["héméralope"],"exemplesCorrects":["Le chat est un animal nyctalope, à l\'aise dans la pénombre.","On le disait nyctalope tant il se déplaçait sans peine dans le noir.","Le hibou, nyctalope, chasse avec aisance une fois la nuit tombée."],"exemplesIncorrects":["En plein soleil, le nyctalope voyait mieux que personne à midi.","Ce nyctalope ne supportait que la lumière éclatante du jour."],"distracteurs":["myope","presbyte","daltonien","strabique"],"anecdote":"Curieusement, en français le mot a longtemps désigné le contraire selon les médecins : pour les uns, le nyctalope voit bien la nuit ; pour d\'autres, il n\'y voit pas. L\'usage courant a retenu le sens « qui voit dans l\'obscurité ».","categorie":"piege-sens","piege":{"formeFautive":"nyctalope = qui ne voit que le jour","explication":"Dans l\'usage courant, « nyctalope » désigne celui qui voit dans l\'obscurité, et non l\'inverse. L\'opposé est « héméralope »."}},{"id":"velleitaire","mot":"velléitaire","nature":"adjectif","definitions":["Qui n\'a que des intentions fugitives, sans la volonté ou l\'énergie de les réaliser ; qui veut sans jamais passer à l\'acte.","Se dit d\'une personne dont les résolutions restent sans suite."],"phonetique":"/ve.le.i.tɛʁ/","etymologie":"Dérivé de « velléité », emprunté au latin scolastique « velleitas », formé sur « velle », « vouloir ». La velléité est une volonté faible, à peine ébauchée.","registre":"soutenu","niveau":4,"themes":["emotions","abstrait"],"synonymes":["irrésolu","indécis","hésitant","aboulique"],"antonymes":["volontaire","résolu","déterminé","énergique"],"exemplesCorrects":["Trop velléitaire, il abandonnait chaque projet au premier obstacle.","Ses bonnes résolutions velléitaires ne survivaient jamais à janvier.","Un chef velléitaire finit toujours par lasser ses troupes."],"exemplesIncorrects":["Velléitaire jusqu\'au bout, il mena son entreprise à un succès éclatant.","Sa détermination velléitaire renversa tous les obstacles."],"distracteurs":["versatile","inconstant","atrabilaire","pusillanime"],"anecdote":"Le mot vient de « velléité », ce vouloir si faible qu\'il n\'aboutit jamais ; les scolastiques médiévaux opposaient la « velleitas » (vouloir incomplet) à la « voluntas » (volonté véritable).","categorie":"mot-rare"},{"id":"anhedonie","mot":"anhédonie","nature":"nom féminin","definitions":["Incapacité à éprouver du plaisir, notamment dans des activités ou situations habituellement agréables ; perte de la capacité au plaisir, souvent symptôme dépressif."],"phonetique":"/a.ne.dɔ.ni/","etymologie":"Néologisme forgé en 1896 par le psychologue Théodule Ribot, du grec « hêdonê », « plaisir », précédé du préfixe privatif an-.","registre":"soutenu","niveau":5,"themes":["emotions","abstrait"],"synonymes":["apathie","indifférence"],"antonymes":["hédonisme","jouissance","volupté"],"exemplesCorrects":["L\'anhédonie est l\'un des symptômes majeurs de la dépression.","Frappé d\'anhédonie, il ne ressentait plus aucune joie à ce qu\'il aimait.","Le psychiatre a relevé une anhédonie marquée chez son patient."],"exemplesIncorrects":["Son anhédonie le poussait à savourer chaque instant avec délice.","Quelle anhédonie : il riait à gorge déployée de tout."],"distracteurs":["asthénie","amnésie","aphasie","anosmie"],"anecdote":"Le terme a été créé par Théodule Ribot dans son ouvrage « La Psychologie des sentiments » (1896) ; il le construisit comme l\'exact contraire de l\'« hédonisme », la recherche du plaisir.","categorie":"mot-rare"},{"id":"acrimonie","mot":"acrimonie","nature":"nom féminin","definitions":["Aigreur, hargne qui se manifeste dans l\'humeur, les paroles ou le caractère ; mauvaise humeur agressive et mordante."],"phonetique":"/a.kʁi.mɔ.ni/","etymologie":"Emprunté au latin « acrimonia », « âpreté, vivacité, mordant », dérivé de « acer », « aigu, piquant, âpre ».","registre":"soutenu","niveau":4,"themes":["emotions","abstrait"],"synonymes":["aigreur","hargne","âpreté","fiel"],"antonymes":["douceur","aménité","affabilité","bienveillance"],"exemplesCorrects":["Il répondit avec une acrimonie qui surprit toute l\'assemblée.","Le débat dégénéra vite en échange d\'acrimonie.","Sans la moindre acrimonie, elle exposa pourtant son désaccord."],"exemplesIncorrects":["Il l\'accueillit avec une acrimonie pleine de tendresse et de sourires.","Quelle acrimonie dans ses compliments si chaleureux !"],"distracteurs":["acrobatie","parcimonie","cérémonie","agrimoine"],"anecdote":"« Acrimonie » partage sa racine latine « acer » (piquant) avec « âcre », « acide » et « acéré » : autant de mots qui évoquent quelque chose de mordant, au propre comme au figuré.","categorie":"mot-rare"},{"id":"sybarite","mot":"sybarite","nature":"nom","definitions":["Personne qui mène une vie facile et voluptueuse, amateur raffiné de plaisirs et de luxe.","(Adjectivement) Qui dénote le goût des plaisirs et de la mollesse."],"phonetique":"/si.ba.ʁit/","etymologie":"Emprunté au latin « Sybarita », du grec « Subaritês », « habitant de Sybaris », ville de Grande-Grèce réputée pour le luxe et la mollesse de ses habitants.","registre":"littéraire","niveau":5,"themes":["abstrait","litteraire","emprunts"],"synonymes":["jouisseur","épicurien","voluptueux","bon vivant"],"antonymes":["ascète","stoïcien","anachorète","spartiate"],"exemplesCorrects":["En véritable sybarite, il ne se refusait aucun des plaisirs de la table.","Cette villa au confort raffiné était digne d\'un sybarite.","Loin de l\'austérité, il menait une existence de sybarite."],"exemplesIncorrects":["Ce sybarite jeûnait et dormait sur la pierre nue par mortification.","En sybarite rigoureux, il s\'imposait l\'eau froide et le pain sec."],"distracteurs":["satrape","cénobite","érudit","philistin"],"anecdote":"Le mot vient de Sybaris, cité grecque du sud de l\'Italie si fameuse pour son raffinement que ses habitants, dit-on, bannissaient les coqs pour ne pas être réveillés trop tôt : un luxe poussé jusqu\'à la légende.","categorie":"mot-rare"},{"id":"deliquescent","mot":"déliquescent","nature":"adjectif","definitions":["Qui se décompose, se délite, perd sa consistance ; en pleine décadence, en voie de désagrégation.","(Chimie) Qui absorbe l\'humidité de l\'air au point de se dissoudre dans l\'eau ainsi captée."],"phonetique":"/de.li.kɛ.sɑ̃/","etymologie":"Du latin deliquescere (« se fondre, se liquéfier »), de liquescere (« devenir liquide »), apparenté à liquidus.","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["décadent","moribond","déclinant","putrescent"],"antonymes":["florissant","vigoureux","prospère"],"exemplesCorrects":["Le régime déliquescent ne tenait plus que par la force et la peur.","Il décrivait une aristocratie déliquescente, rongée par l\'oisiveté.","Le chlorure de calcium est une substance déliquescente qui attire l\'humidité."],"exemplesIncorrects":["L\'athlète déliquescent battit tous les records ce matin-là.","Ce vin jeune et déliquescent pétillait de fraîcheur."],"distracteurs":["effervescent","luminescent","évanescent"],"anecdote":"En chimie, un corps déliquescent comme la potasse capte tellement la vapeur d\'eau de l\'air qu\'il finit par se dissoudre dans sa propre humeur : c\'est de cette image de dissolution qu\'est venu le sens figuré de « décadence ».","categorie":"mot-rare"},{"id":"fallacieux","mot":"fallacieux","nature":"adjectif","definitions":["Qui tend à tromper, qui induit en erreur sous une apparence de vérité ou de bon droit.","Qui repose sur un raisonnement spécieux, trompeur."],"phonetique":"/fa.la.sjø/","etymologie":"Du latin fallaciosus, de fallacia (« tromperie, ruse »), dérivé de fallere (« tromper »).","registre":"soutenu","niveau":2,"themes":["abstrait","litteraire"],"synonymes":["trompeur","mensonger","spécieux","captieux"],"antonymes":["sincère","véridique","franc","loyal"],"exemplesCorrects":["Ses arguments fallacieux séduisaient l\'auditoire le moins averti.","Sous un prétexte fallacieux, il obtint la signature du vieil homme.","La publicité usait de promesses fallacieuses pour appâter le client."],"exemplesIncorrects":["Le témoin fallacieux dit toute la vérité sans rien cacher.","Son sourire fallacieux et chaleureux mettait chacun en confiance par sa franchise."],"distracteurs":["audacieux","tenace","sagace"],"anecdote":"Fallacieux partage sa racine latine fallere (« tromper ») avec « faillir », « faute » et même « faux » : toute une famille bâtie sur l\'idée de manquer à la vérité.","categorie":"mot-rare"},{"id":"hagiographie","mot":"hagiographie","nature":"nom féminin","definitions":["Récit de la vie des saints ; ensemble des textes consacrés à la vie des saints.","(Sens figuré, souvent péjoratif) Biographie idéalisée, élogieuse à l\'excès, qui passe sous silence les défauts du personnage."],"phonetique":"/a.ɡjɔ.ɡʁa.fi/","etymologie":"Du grec ancien hagios (« saint ») et graphein (« écrire »).","registre":"soutenu","niveau":3,"themes":["litteraire","abstrait"],"synonymes":["panégyrique","apologie","dithyrambe"],"antonymes":["réquisitoire","pamphlet","libelle"],"exemplesCorrects":["Cette biographie du président tient de l\'hagiographie : pas une ombre au tableau.","Les hagiographies médiévales abondent en miracles édifiants.","Le journaliste reprocha à l\'auteur d\'avoir écrit une hagiographie plutôt qu\'une étude critique."],"exemplesIncorrects":["Son hagiographie féroce démolissait point par point la réputation du ministre.","Cette hagiographie impartiale exposait sans ménagement les scandales du héros."],"distracteurs":["cartographie","lexicographie","monographie"],"anecdote":"On croit souvent qu\'une « hagiographie » désigne n\'importe quelle biographie : c\'est faux. Le mot vient du grec hagios, « saint », et désigne d\'abord le récit de la vie des saints, d\'où, par extension, une biographie excessivement flatteuse. Pour une vie neutre, on dit simplement « biographie ».","piege":{"explication":"Hagiographie n\'est pas synonyme de biographie : le terme implique l\'éloge dévot, l\'absence de tout regard critique. L\'employer pour un récit équilibré ou critique est un contresens."},"categorie":"piege-sens"},{"id":"contrition","mot":"contrition","nature":"nom féminin","definitions":["Regret sincère et profond d\'une faute commise, accompagné de la volonté de ne plus la commettre.","(Religion) Douleur de l\'âme qui déteste le péché par amour de Dieu."],"phonetique":"/kɔ̃.tʁi.sjɔ̃/","etymologie":"Du latin chrétien contritio (« broiement, brisement »), de conterere (« broyer, écraser »), au sens figuré « briser le cœur ».","registre":"soutenu","niveau":3,"themes":["emotions","abstrait","litteraire"],"synonymes":["repentir","remords","componction"],"antonymes":["impénitence","endurcissement","satisfaction"],"exemplesCorrects":["Il avoua sa faute avec une contrition qui désarma ses juges.","Un air de contrition se lisait sur son visage baissé.","La contrition seule ne suffit pas : il faut encore réparer le tort causé."],"exemplesIncorrects":["Elle éprouva une contrition joyeuse en recevant le prix tant convoité.","Sa contrition orgueilleuse le poussait à se vanter de ses exploits."],"distracteurs":["constriction","contraction","contribution"],"anecdote":"Le mot vient du latin conterere, « broyer » : la contrition, c\'est littéralement le cœur « broyé » par le regret. La théologie distingue la contrition parfaite (le regret par amour) de l\'attrition (le regret par crainte du châtiment).","categorie":"mot-rare"},{"id":"irenique","mot":"irénique","nature":"adjectif","definitions":["Qui vise à la paix, à la conciliation, à l\'apaisement des conflits, notamment d\'opinions ou de doctrines.","(Théologie) Qui recherche l\'entente entre confessions ou opinions religieuses divergentes."],"phonetique":"/i.ʁe.nik/","etymologie":"Du latin ecclésiastique irenicus, du grec ancien eirênikos (« de paix »), dérivé de eirênê (« paix »).","registre":"littéraire","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["pacifique","conciliant","apaisant","pacificateur"],"antonymes":["polémique","belliqueux","agressif","querelleur"],"exemplesCorrects":["Il adopta un ton irénique pour réconcilier les deux camps.","Le théologien prônait une démarche irénique entre les Églises.","Sa préface, d\'une rare disposition irénique, désamorçait toute querelle."],"exemplesIncorrects":["L\'orateur irénique attisa la haine et déclencha l\'émeute.","Son pamphlet irénique insultait l\'adversaire à chaque ligne."],"distracteurs":["ironique","onirique","épique"],"anecdote":"Irénique a la même racine grecque eirênê (« paix ») que le prénom Irène, « la pacifique ». Le mot s\'oppose exactement à « polémique », issu du grec polemos, « la guerre ».","categorie":"mot-rare"},{"id":"procusteen","mot":"procustéen","nature":"adjectif","definitions":["Qui force à entrer dans un cadre rigide et arbitraire, au mépris de la réalité ; relatif au lit de Procuste.","Qui mutile ou étire les faits pour les faire correspondre à un modèle préétabli."],"phonetique":"/pʁɔ.kys.te.ɛ̃/","etymologie":"Dérivé de Procuste, brigand de la mythologie grecque (Prokroustês, « celui qui étire »), qui adaptait ses victimes à la taille de son lit.","registre":"littéraire","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["rigide","arbitraire","réducteur"],"antonymes":["souple","adaptable","modulable"],"exemplesCorrects":["Cette grille procustéenne déformait toute œuvre qu\'on prétendait y faire entrer.","Il dénonçait une logique procustéenne qui sacrifiait les nuances à la théorie.","L\'analyse procustéenne, en statistique des formes, ajuste les configurations à un modèle de référence."],"exemplesIncorrects":["Sa méthode procustéenne respectait scrupuleusement chaque particularité du cas.","Un esprit procustéen, accueillant et tolérant, n\'imposait jamais ses cadres."],"distracteurs":["pyrrhonien","sisyphéen","draconien"],"anecdote":"On écrit souvent à tort « procrustéen », avec un r, par contamination de l\'anglais Procrustes. En français, l\'orthographe usuelle est « procustéen », du nom de Procuste, ce brigand qui mutilait ou étirait ses hôtes pour les ajuster à son lit.","piege":{"formeFautive":"procrustéen","explication":"La forme française courante est « procustéen » (sans r après le c). « Procrustéen », plus proche du grec et de l\'anglais, est rare et déconseillé en français."},"categorie":"piege-orthographe"},{"id":"aporetique","mot":"aporétique","nature":"adjectif","definitions":["Qui mène à une aporie, à une impasse logique insoluble ; relatif à l\'aporie.","(Philosophie) Qui procède par mise en évidence de difficultés contradictoires sans les résoudre."],"phonetique":"/a.pɔ.ʁe.tik/","etymologie":"Du grec ancien aporêtikos, de aporia (« absence de passage, embarras »), de a- (privatif) et poros (« passage, issue »).","registre":"littéraire","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["insoluble","indécidable","embarrassant"],"antonymes":["résoluble","concluant","démonstratif"],"exemplesCorrects":["Le dialogue socratique s\'achève souvent sur une situation aporétique.","Sa démonstration, brillante mais aporétique, ne débouchait sur aucune conclusion.","Le débat tournait à une discussion aporétique dont nul ne sortait."],"exemplesIncorrects":["La preuve aporétique trancha enfin la question sans la moindre ambiguïté.","Un raisonnement aporétique, limpide et concluant, leva tous les doutes."],"distracteurs":["apodictique","péremptoire","heuristique"],"anecdote":"Aporie vient du grec poros, « le passage » : une question aporétique est littéralement « sans issue ». Plusieurs dialogues de Platon sont dits aporétiques car ils se concluent sur l\'aveu d\'une impasse.","categorie":"mot-rare"},{"id":"vermiculaire","mot":"vermiculaire","nature":"adjectif","definitions":["Qui a la forme d\'un ver, qui en rappelle l\'aspect mince et sinueux.","(Physiologie) Se dit d\'un mouvement comparable à celui d\'un ver, par contractions successives, comme le péristaltisme intestinal."],"phonetique":"/vɛʁ.mi.ky.lɛʁ/","etymologie":"Du latin vermiculus (« petit ver »), diminutif de vermis (« ver »).","registre":"soutenu","niveau":4,"themes":["nature","abstrait"],"synonymes":["sinueux","ondulant","serpentin"],"antonymes":["rectiligne","droit"],"exemplesCorrects":["L\'appendice vermiculaire prolonge le cæcum chez l\'être humain.","L\'intestin fait progresser les aliments par un mouvement vermiculaire régulier.","La gravure montrait de fines lignes vermiculaires courant sur la pierre."],"exemplesIncorrects":["La règle vermiculaire traçait des traits parfaitement droits.","Sa démarche vermiculaire était raide et anguleuse comme un piquet."],"distracteurs":["vésiculaire","tentaculaire","spiralé"],"anecdote":"L\'appendice « vermiculaire » doit son nom à sa forme de petit ver : c\'est de lui que vient le mot « appendicite ». Le diminutif latin vermiculus a aussi donné « vermine » et, par un détour inattendu, « vermeil ».","categorie":"mot-rare"},{"id":"halieutique","mot":"halieutique","nature":"adjectif","definitions":["Qui concerne la pêche, l\'exploitation des ressources vivantes des eaux.","(Nom féminin) L\'art ou la science de la pêche."],"phonetique":"/a.ljø.tik/","etymologie":"Du grec ancien halieutikos (« relatif à la pêche »), de halieus (« pêcheur »), de hals (« mer, sel »).","registre":"soutenu","niveau":4,"themes":["nature","abstrait"],"synonymes":["piscicole"],"antonymes":["cynégétique"],"exemplesCorrects":["La politique halieutique de l\'Union européenne fixe des quotas de capture.","Les ressources halieutiques de la zone sont menacées par la surpêche.","Il enseigne l\'halieutique dans une école maritime."],"exemplesIncorrects":["La saison halieutique du gibier à plumes s\'ouvre en septembre.","Cette réserve halieutique protège surtout les cerfs et les sangliers de la forêt."],"distracteurs":["sylvicole","cynégétique","vinicole"],"anecdote":"Halieutique remonte au grec hals, « la mer » (ou « le sel »), la même racine qui a donné « halophile » (qui aime le sel). Au cynégétique de la chasse répond l\'halieutique de la pêche.","categorie":"mot-rare"},{"id":"panurgisme","mot":"panurgisme","nature":"nom masculin","definitions":["Comportement moutonnier, tendance à imiter aveuglément les autres, à suivre le groupe sans réflexion.","Conformisme grégaire poussé jusqu\'à l\'absurde."],"phonetique":"/pa.nyʁ.ʒism/","etymologie":"Dérivé de Panurge, personnage de Rabelais dont les moutons, jetés à la mer par le premier, se précipitent tous à sa suite et se noient.","registre":"littéraire","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["conformisme","grégarisme","suivisme","mimétisme"],"antonymes":["indépendance","individualisme","non-conformisme"],"exemplesCorrects":["Le panurgisme des marchés financiers amplifie les krachs comme les bulles.","Par pur panurgisme, toute la classe adopta la même coupe de cheveux.","Elle dénonçait le panurgisme des réseaux sociaux, où chacun relaie ce que relaient les autres."],"exemplesIncorrects":["Son panurgisme farouche le poussait à tout faire à contre-courant des autres.","Quel panurgisme original : il n\'écoutait jamais que sa propre voix."],"distracteurs":["dirigisme","obscurantisme","fatalisme"],"anecdote":"Le mot vient des « moutons de Panurge » de Rabelais : pour se venger d\'un marchand, Panurge jette un mouton à la mer, et tout le troupeau saute à sa suite. L\'expression est devenue le symbole de la bêtise grégaire.","categorie":"mot-rare"},{"id":"billevesee","mot":"billevesée","nature":"nom féminin","definitions":["Propos vide de sens, idée creuse, sornette dépourvue de fondement.","Chose futile à laquelle on accorde une importance injustifiée."],"phonetique":"/bil.və.ze/","etymologie":"De l\'ancien français billevese (« cornemuse »), littéralement « boyau qu\'on gonfle de vent », de beille (« boyau, intestin ») et de l\'ancien verbe veser (« souffler ») ; d\'où l\'idée de propos « gonflés de vent ».","registre":"littéraire","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["sornette","fadaise","balivernes","sottise"],"antonymes":["vérité","évidence","raison"],"exemplesCorrects":["Il balaya leurs objections comme autant de billevesées.","Ne perds pas ton temps à ces billevesées sans fondement.","Tout cela n\'est que billevesées de salon, sans la moindre portée."],"exemplesIncorrects":["Sa billevesée rigoureuse et démontrée fit avancer la science.","Il fonda sa thèse sur des billevesées incontestables et solidement étayées."],"distracteurs":["calembour","bilboquet","billet"],"anecdote":"On écorche souvent ce mot rare en « bille-vesée » ou « billevezée ». L\'orthographe correcte est « billevesée », un seul s, et le tout vient d\'une vieille « cornemuse » médiévale : un boyau gonflé de vent, image parfaite du discours creux qu\'on prend pour du plein.","piege":{"formeFautive":"billevezée","explication":"On écrit « billevesée » avec un s (et non un z), et en un seul mot. Les graphies « billevezée » ou « bille-vesée » sont fautives."},"categorie":"piege-orthographe"},{"id":"prevarication","mot":"prévarication","nature":"nom féminin","definitions":["Manquement grave commis par une personne dans l\'exercice de sa charge ou de ses devoirs, notamment par un fonctionnaire ou un magistrat.","Trahison du devoir d\'une fonction, en abusant de l\'autorité ou de la confiance qu\'elle confère."],"phonetique":"/pʁe.va.ʁi.ka.sjɔ̃/","etymologie":"Du latin praevaricatio, de praevaricari (« marcher de travers, agir de connivence »), de prae- et varicare (« écarter les jambes »).","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["forfaiture","concussion","malversation"],"antonymes":["probité","intégrité","droiture"],"exemplesCorrects":["Le magistrat fut destitué pour prévarication.","On l\'accusa de prévarication pour avoir trahi les intérêts qu\'il devait défendre.","La prévarication d\'un haut fonctionnaire ébranle la confiance des citoyens."],"exemplesIncorrects":["Sa prévarication consista à hésiter longuement avant de répondre.","Il fit preuve de prévarication en tergiversant sans cesse au lieu de décider."],"distracteurs":["procrastination","prévention","tergiversation"],"anecdote":"On confond parfois « prévarication » avec « tergiversation » à cause de leur sonorité : c\'est un contresens. Prévariquer, du latin praevaricari (« marcher de travers »), c\'est trahir gravement les devoirs de sa charge, et non hésiter ou atermoyer.","piege":{"formeFautive":"tergiverser, hésiter","explication":"Prévarication ne signifie pas hésitation ni atermoiement : c\'est un manquement grave et coupable aux devoirs d\'une fonction (trahison, forfaiture). Le confondre avec « tergiversation » est un contresens."},"categorie":"piege-sens"},{"id":"forfaiture","mot":"forfaiture","nature":"nom féminin","definitions":["Crime commis par un fonctionnaire ou un magistrat dans l\'exercice de ses fonctions ; manquement grave aux devoirs de sa charge.","Trahison de la foi jurée, violation d\'un engagement solennel."],"phonetique":"/fɔʁ.fɛ.tyʁ/","etymologie":"De l\'ancien français forfaiture, dérivé de forfaire (« agir contre le devoir »), du bas latin foris facere, « agir en dehors (des règles) ». À l\'origine, en droit féodal, la rupture du serment de fidélité dû au seigneur.","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["prévarication","trahison","félonie","concussion"],"antonymes":["loyauté","probité","fidélité"],"exemplesCorrects":["Le magistrat fut destitué pour forfaiture après avoir monnayé ses jugements.","Livrer la place à l\'ennemi était, de la part de ce capitaine, une véritable forfaiture.","La Constitution prévoit la mise en accusation du chef de l\'État en cas de haute trahison ou de forfaiture."],"exemplesIncorrects":["Il a payé la forfaiture de son billet de train avant de monter.","Quelle belle forfaiture de pâtisserie il a préparée pour le dessert !"],"distracteurs":["forclusion","déchéance","imposture","déloyauté"],"anecdote":"En droit pénal français, la forfaiture désignait jusqu\'en 1992 un crime spécifique des fonctionnaires, puni par la dégradation civique. Le terme a disparu du Code pénal, mais subsiste dans le langage politique pour stigmatiser la trahison d\'un mandat.","categorie":"mot-rare"},{"id":"turpitude","mot":"turpitude","nature":"nom féminin","definitions":["Caractère de ce qui est honteux, ignoble ; bassesse morale.","Action, conduite honteuse et dégradante."],"phonetique":"/tyʁ.pi.tyd/","etymologie":"Emprunté au latin turpitudo, « laideur, honte, infamie », dérivé de turpis, « laid, honteux, déshonorant ».","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["ignominie","infamie","abjection","bassesse"],"antonymes":["dignité","noblesse","honneur","vertu"],"exemplesCorrects":["On découvrit peu à peu toutes les turpitudes que cachait sa respectabilité de façade.","Il dénonçait avec véhémence la turpitude des marchands d\'esclaves.","Se vautrer dans la turpitude ne lui causait aucun remords."],"exemplesIncorrects":["La turpitude du ciel ce matin annonçait une belle journée.","Elle marchait avec une turpitude pleine d\'élégance et de grâce."],"distracteurs":["latitude","platitude","vicissitude","promptitude"],"anecdote":"En droit, l\'adage « nul ne peut se prévaloir de sa propre turpitude » empêche un plaideur de tirer avantage de sa propre faute. Le mot remonte au latin turpis, « laid, honteux », et désigne aussi bien la bassesse morale que l\'acte ignoble qui la révèle.","categorie":"mot-rare"},{"id":"pleutre","mot":"pleutre","nature":"nom masculin","definitions":["Homme sans courage et sans dignité ; lâche méprisable.","(Adjectivement) Qui manifeste une lâcheté vile."],"phonetique":"/pløtʁ/","etymologie":"Probablement emprunté au flamand pleute, « chiffon, haillon ; vaurien », d\'où le sens figuré d\'« homme de rien ». Attesté en français septentrional au XVIIIe siècle.","registre":"littéraire","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["lâche","poltron","couard","capon"],"antonymes":["brave","vaillant","intrépide","courageux"],"exemplesCorrects":["Il s\'enfuit au premier danger, en pleutre qu\'il était.","Je méprise ce pleutre qui n\'a jamais osé défendre ses amis.","Quelle conduite pleutre que d\'abandonner ses compagnons au moment du péril !"],"exemplesIncorrects":["Ce général, par sa pleutre audace, remporta la bataille.","On admirait son geste pleutre et généreux envers les plus démunis."],"distracteurs":["rustre","bélître","maraud","faquin"],"anecdote":"Le mot vient du flamand pleute, « loque, chiffon » : le pleutre est donc, littéralement, un « torchon » humain. L\'image du tissu sans tenue traduit bien le mépris attaché à la lâcheté.","categorie":"mot-rare"},{"id":"goujaterie","mot":"goujaterie","nature":"nom féminin","definitions":["Comportement de goujat ; grossièreté, manque de délicatesse, surtout envers les femmes.","Acte, parole témoignant d\'un manque de savoir-vivre."],"phonetique":"/ɡu.ʒa.tʁi/","etymologie":"Dérivé de goujat (« homme grossier, mufle »), lui-même issu de l\'occitan gojat, « valet, garçon », apparenté à l\'ancien français gouge, « servante ».","registre":"courant","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["muflerie","grossièreté","impolitesse","indélicatesse"],"antonymes":["courtoisie","galanterie","délicatesse","politesse"],"exemplesCorrects":["Partir sans la remercier après une telle soirée relevait de la pure goujaterie.","Il eut la goujaterie de commenter son âge devant tout le monde.","On ne pardonne guère ce genre de goujaterie à un homme de sa réputation."],"exemplesIncorrects":["Sa goujaterie envers les invités les avait tous charmés.","Quelle goujaterie raffinée dans ce compliment délicat !"],"distracteurs":["pingrerie","fourberie","vantardise","forfanterie"],"anecdote":"À l\'origine, le goujat n\'était qu\'un valet d\'armée ou un apprenti maçon. C\'est par mépris pour cette condition subalterne que le mot a glissé vers le sens de « rustre », d\'où la goujaterie moderne.","categorie":"mot-rare"},{"id":"forligner","mot":"forligner","nature":"verbe","definitions":["Dégénérer, déchoir des qualités ou de la vertu de ses ancêtres ; agir de façon indigne de sa lignée.","Par extension, s\'écarter d\'une tradition, d\'une norme dont on est issu."],"phonetique":"/fɔʁ.li.ɲe/","etymologie":"De l\'ancien français forlignier, « sortir du rang, ne pas honorer sa lignée », composé du préfixe for- (idée d\'écart, du latin foris, « dehors ») et de lignier, dérivé de ligne, « lignée ».","registre":"littéraire","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["dégénérer","déchoir","s\'avilir","déroger"],"antonymes":["honorer","perpétuer","s\'élever"],"exemplesCorrects":["Descendant d\'une lignée de savants, il craignait de forligner en abandonnant ses études.","Nul de ses aïeux n\'avait forligné : tous avaient servi l\'État avec honneur.","On l\'accusait de forligner en reniant les valeurs de sa famille."],"exemplesIncorrects":["Il faut forligner ce contrat avant la fin de la semaine.","Le menuisier forligne soigneusement la planche avant de la coller."],"distracteurs":["dévoyer","transiger","renier","s\'affranchir"],"anecdote":"Verbe presque entièrement disparu, forligner relève d\'un imaginaire aristocratique : on « forligne » quand on trahit le sang dont on est issu. Les moralistes classiques l\'employaient pour fustiger les héritiers indignes.","categorie":"mot-rare"},{"id":"impavide","mot":"impavide","nature":"adjectif","definitions":["Que rien n\'effraie ; qui demeure imperturbable devant le danger.","Empreint d\'un calme inébranlable, exempt de toute peur."],"phonetique":"/ɛ̃.pa.vid/","etymologie":"Emprunté au latin impavidus, « sans crainte », composé du préfixe privatif in- et de pavidus, « craintif, effrayé », dérivé de pavere, « être saisi de frayeur ».","registre":"littéraire","niveau":5,"themes":["abstrait","litteraire","emotions"],"synonymes":["imperturbable","intrépide","impassible","stoïque"],"antonymes":["craintif","peureux","pusillanime","effrayé"],"exemplesCorrects":["Impavide sous la mitraille, l\'officier continuait de donner ses ordres.","Elle reçut la nouvelle d\'un air impavide, sans qu\'un trait de son visage ne bougeât.","Le capitaine demeurait impavide tandis que la tempête déchaînait les flots."],"exemplesIncorrects":["Le ciel était impavide et limpide après l\'orage.","Il tremblait, impavide, à l\'idée d\'affronter l\'examen."],"distracteurs":["livide","candide","placide"],"anecdote":"Le mot dérive du latin pavere (« trembler de peur »), qui a aussi donné « épouvante ». L\'impavide est donc, étymologiquement, celui que la peur ne fait pas trembler. Gabriele D\'Annunzio en fit une devise.","categorie":"mot-rare"},{"id":"contempteur","mot":"contempteur","nature":"nom masculin","definitions":["Personne qui méprise ouvertement quelqu\'un ou quelque chose ; détracteur dédaigneux.","(Adjectivement) Qui exprime le mépris."],"phonetique":"/kɔ̃.tɑ̃p.tœʁ/","etymologie":"Emprunté au latin contemptor, « celui qui méprise », dérivé de contemnere, « dédaigner, faire peu de cas de », de cum- et temnere, « mépriser ».","registre":"littéraire","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["détracteur","dénigreur","pourfendeur","censeur"],"antonymes":["admirateur","thuriféraire","panégyriste","laudateur"],"exemplesCorrects":["Ce philosophe se posait en contempteur des modes et des conventions de son siècle.","Les contempteurs du progrès trouvaient toujours matière à critiquer.","Il fut, sa vie durant, un ardent contempteur de l\'hypocrisie bourgeoise."],"exemplesIncorrects":["Le contempteur du musée veillait à la sécurité des œuvres.","Grand contempteur de son maître, il le couvrait d\'éloges sincères."],"distracteurs":["contemplateur","compétiteur","contradicteur","détenteur"],"anecdote":"Contempteur ne doit pas être confondu avec contemplateur, dont il est pourtant proche par la sonorité : l\'un méprise, l\'autre admire. La paronymie a piégé plus d\'un écrivain.","categorie":"mot-rare"},{"id":"laudateur","mot":"laudateur","nature":"nom masculin","definitions":["Personne qui fait l\'éloge de quelqu\'un, souvent avec excès ou complaisance ; flatteur.","(Adjectivement) Qui loue, élogieux."],"phonetique":"/lo.da.tœʁ/","etymologie":"Emprunté au latin laudator, « celui qui loue », dérivé de laudare, « louer, célébrer », de laus, laudis, « louange ».","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["panégyriste","thuriféraire","flatteur","encenseur"],"antonymes":["détracteur","contempteur","censeur","dénigreur"],"exemplesCorrects":["Entouré de laudateurs intéressés, le ministre ne percevait plus aucune critique.","Loin d\'être un laudateur servile, le critique louait l\'œuvre avec discernement.","Les laudateurs du régime saluaient chaque décision comme un trait de génie."],"exemplesIncorrects":["Le laudateur du tribunal rendit son verdict après délibération.","Ce féroce laudateur ne cessait de dénigrer ses rivaux."],"distracteurs":["dilatateur","rénovateur","modérateur","spectateur"],"anecdote":"L\'expression latine laudator temporis acti (« celui qui vante le temps passé »), forgée par Horace, désigne le laudateur nostalgique persuadé que tout était mieux autrefois.","categorie":"mot-rare"},{"id":"cauteleux","mot":"cauteleux","nature":"adjectif","definitions":["Qui agit de façon rusée et sournoise, sous des dehors prudents ou bienveillants ; hypocritement circonspect.","Empreint d\'une méfiance habile et dissimulée."],"phonetique":"/ko.tlø/","etymologie":"Dérivé de cautèle (« ruse, précaution sournoise »), emprunté au latin cautela, « précaution, défiance », de cavere, « prendre garde ».","registre":"littéraire","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["sournois","matois","retors","fourbe"],"antonymes":["franc","candide","loyal","droit"],"exemplesCorrects":["Il avançait ses arguments d\'un ton cauteleux, masquant ses véritables intentions.","Sous ses manières cauteleuses se cachait un calculateur impitoyable.","Le marchand jeta un regard cauteleux avant de proposer son marché douteux."],"exemplesIncorrects":["Son sourire cauteleux et chaleureux mettait tout le monde en confiance.","Le ruisseau coulait, cauteleux, entre les pierres moussues."],"distracteurs":["chatouilleux","scrupuleux","ombrageux","cauchemardeux"],"anecdote":"Cauteleux et la « caution » qu\'on dépose partagent la même racine latine cavere (« prendre garde »). Le cauteleux est, à l\'origine, celui qui prend ses précautions — mais en mauvaise part : sa prudence sert la ruse.","categorie":"mot-rare"},{"id":"madre","mot":"madré","nature":"adjectif","definitions":["Rusé, retors, qui sait plus d\'un tour ; finaud sous des apparences naïves.","(Sens propre, vieilli) Veiné, marbré, tacheté (en parlant du bois)."],"phonetique":"/ma.dʁe/","etymologie":"Dérivé de madre (« bois veiné, tacheté »), de l\'ancien français madrer, « marbrer », d\'origine germanique (francique *maser, « excroissance veinée du bois »). Le sens figuré « rusé » évoque un caractère bigarré, retors.","registre":"littéraire","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["matois","finaud","rusé","roublard"],"antonymes":["candide","naïf","ingénu","simple"],"exemplesCorrects":["Ce paysan madré savait toujours conclure un marché à son avantage.","Sous des airs bonhommes, c\'était un vieux madré qu\'on ne dupait pas.","Elle déjoua le piège avec une habileté de personne madrée."],"exemplesIncorrects":["Il était si madré qu\'il croyait tout ce qu\'on lui racontait.","Le ciel madré annonçait une averse imminente."],"distracteurs":["nacré","ambré","cabré","sacré"],"anecdote":"Avant de désigner un homme rusé, madré qualifiait le bois « madré », joliment veiné et marbré, prisé en ébénisterie. La Fontaine a popularisé le sens figuré du « vieux madré ».","categorie":"mot-rare"},{"id":"proteiforme","mot":"protéiforme","nature":"adjectif","definitions":["Qui change sans cesse de forme ou d\'aspect ; susceptible de prendre des formes très variées.","Au figuré, qui se manifeste sous de multiples apparences."],"phonetique":"/pʁɔ.te.i.fɔʁm/","etymologie":"Composé savant formé du nom de Protée (Proteus), dieu marin de la mythologie grecque capable de changer de forme à volonté, et de l\'élément -forme, du latin forma, « forme ».","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["polymorphe","changeant","multiforme","caméléonesque"],"antonymes":["uniforme","immuable","figé","invariable"],"exemplesCorrects":["La menace terroriste, protéiforme, déjoue les réponses trop rigides.","Son talent protéiforme s\'exprimait aussi bien en peinture qu\'en musique.","L\'angoisse prenait chez lui une forme protéiforme, jamais tout à fait la même."],"exemplesIncorrects":["La table protéiforme était parfaitement carrée et stable.","Sa routine protéiforme ne variait jamais d\'un jour à l\'autre."],"distracteurs":["pyriforme","filiforme","cunéiforme","difforme"],"anecdote":"Le mot doit tout à Protée, le « Vieux de la mer » de l\'Odyssée, qui se métamorphosait en lion, en serpent ou en eau pour échapper à ceux qui voulaient l\'interroger. De là « protéiforme » et l\'adjectif « protéen ».","categorie":"mot-rare"},{"id":"evanescent","mot":"évanescent","nature":"adjectif","definitions":["Qui s\'efface, disparaît progressivement ; sur le point de s\'évanouir.","D\'une délicatesse fugitive, à peine perceptible."],"phonetique":"/e.va.nɛ.sɑ̃/","etymologie":"Emprunté au latin evanescens, participe présent de evanescere, « disparaître, s\'évanouir », de e- (« hors de ») et vanescere, « se dissiper », dérivé de vanus, « vide ».","registre":"littéraire","niveau":4,"themes":["abstrait","litteraire","nature"],"synonymes":["fugace","éphémère","fugitif","impalpable"],"antonymes":["durable","permanent","tangible","persistant"],"exemplesCorrects":["Les dernières lueurs évanescentes du crépuscule s\'effaçaient à l\'horizon.","Elle ne gardait qu\'un souvenir évanescent de cette nuit lointaine.","Un parfum évanescent flottait encore dans la pièce déserte."],"exemplesIncorrects":["Le roc évanescent dominait la vallée depuis des millénaires.","Sa fortune évanescente ne cessait de croître année après année."],"distracteurs":["incandescent","phosphorescent","convalescent","luminescent"],"anecdote":"Évanescent partage sa racine latine vanus (« vide ») avec « vain » et « s\'évanouir ». Les poètes symbolistes, Verlaine en tête, ont fait de l\'évanescent un idéal esthétique : la beauté qui s\'efface au moment où on la saisit.","categorie":"mot-rare"},{"id":"pregnant","mot":"prégnant","nature":"adjectif","definitions":["Qui s\'impose fortement à l\'esprit, à la perception ; qui possède une force organisatrice immédiate (notamment en psychologie de la forme).","Riche de sens, lourd de signification."],"phonetique":"/pʁɛɡ.nɑ̃/","etymologie":"Emprunté au latin praegnans, praegnantis « rempli, gonflé, plein », participe formé sur prae- (« avant ») et la racine de gnasci/nasci (« naître »). Le sens psychologique moderne est repris de l\'allemand prägnant (théorie de la Gestalt).","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["frappant","saisissant","signifiant"],"antonymes":["insignifiant","fade","anodin"],"exemplesCorrects":["Cette image est si prégnante qu\'elle s\'imprime durablement dans la mémoire.","Le silence prégnant qui suivit l\'annonce pesait sur toute l\'assemblée.","En psychologie de la forme, une figure prégnante se détache spontanément du fond."],"exemplesIncorrects":["La jument était prégnante de six mois et devait bientôt mettre bas.","Elle est tombée prégnante au printemps dernier."],"distracteurs":["imminent","latent","criant","manifeste"],"anecdote":"On confond souvent « prégnant » avec un faux ami : sous l\'influence de l\'anglais pregnant (« enceinte »), certains lui prêtent à tort un rapport avec la grossesse. En français, prégnant signifie « qui s\'impose à l\'esprit » ; pour parler d\'une femelle pleine, on dit « gravide » ou « pleine », jamais « prégnante ».","categorie":"piege-sens","piege":{"formeFautive":"prégnante (au sens d\'« enceinte »)","explication":"Sous l\'influence de l\'anglais pregnant, on emploie parfois « prégnant » pour « enceinte/pleine ». En français, prégnant veut dire « qui s\'impose fortement à l\'esprit » ; il n\'a aucun rapport avec la gestation."}},{"id":"liminaire","mot":"liminaire","nature":"adjectif","definitions":["Qui est placé en tête d\'un ouvrage, d\'un texte ; préliminaire, introductif.","Qui se situe au seuil, au commencement de quelque chose."],"phonetique":"/li.mi.nɛʁ/","etymologie":"Dérivé savant du latin limen, liminis (« seuil »), avec le suffixe -aire. Le mot désigne d\'abord ce qui figure au seuil d\'un écrit.","registre":"soutenu","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["préliminaire","introductif","préfatoire"],"antonymes":["final","conclusif","terminal"],"exemplesCorrects":["L\'épître liminaire de l\'ouvrage rend hommage au mécène de l\'auteur.","Dans son propos liminaire, le président a rappelé l\'ordre du jour.","Une note liminaire avertit le lecteur des conventions typographiques adoptées."],"exemplesIncorrects":["Il a rangé les outils dans le tiroir liminaire de l\'établi.","Le coureur a franchi la ligne liminaire en tête du peloton."],"distracteurs":["inaugural","prologue","marginal","didactique"],"anecdote":"« Liminaire » partage sa racine, le latin limen (« seuil »), avec « éliminer » (à l\'origine « mettre hors du seuil ») et avec « subliminal » (« sous le seuil » de la conscience).","categorie":"mot-rare"},{"id":"adventice","mot":"adventice","nature":"adjectif","definitions":["Qui survient accessoirement, qui s\'ajoute de l\'extérieur sans appartenir à l\'essence de la chose ; accidentel.","En botanique, se dit d\'une plante qui croît spontanément, sans avoir été semée, là où on ne la cultive pas (mauvaise herbe)."],"phonetique":"/ad.vɑ̃.tis/","etymologie":"Emprunté au latin adventicius (« qui vient du dehors, étranger »), dérivé de advenire (« arriver, survenir »), de ad- et venire (« venir »).","registre":"soutenu","niveau":4,"themes":["abstrait","nature"],"synonymes":["accidentel","accessoire","surajouté"],"antonymes":["essentiel","inhérent","intrinsèque"],"exemplesCorrects":["Il faut distinguer les causes essentielles du mal de ses facteurs adventices.","Le désherbeur arrache les plantes adventices entre les rangs de légumes.","Cette douleur adventice, étrangère à la maladie principale, disparut d\'elle-même."],"exemplesIncorrects":["Son honnêteté adventice était le trait le plus profond de son caractère.","Le tronc adventice forme l\'axe central et permanent de l\'arbre."],"distracteurs":["fortuit","marginal","parasite","incident"],"anecdote":"En jardinage, une « plante adventice » est le terme savant pour ce qu\'on appelle ordinairement une « mauvaise herbe » : une herbe qui s\'invite « du dehors » là où on ne l\'a pas semée.","categorie":"mot-rare"},{"id":"epiphenomene","mot":"épiphénomène","nature":"nom masculin","definitions":["Phénomène secondaire qui accompagne un phénomène principal sans exercer d\'action propre sur lui.","Fait accessoire, de peu d\'importance par rapport à l\'essentiel."],"phonetique":"/e.pi.fe.nɔ.mɛn/","etymologie":"Composé du préfixe grec epi- (« sur, au-dessus de ») et de « phénomène » (du grec phainomenon, « ce qui apparaît »). Forgé en philosophie pour désigner un phénomène surajouté.","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["accessoire","corollaire","à-côté"],"antonymes":["cause","essentiel","déterminant"],"exemplesCorrects":["Pour certains philosophes, la conscience ne serait qu\'un épiphénomène de l\'activité cérébrale.","Ce conflit n\'est qu\'un épiphénomène d\'une crise économique bien plus profonde.","Réduire la révolte à un épiphénomène, c\'est en méconnaître les causes réelles."],"exemplesIncorrects":["L\'épiphénomène fondamental de cette théorie en constitue le pilier central.","Le moteur est l\'épiphénomène qui fait avancer toute la machine."],"distracteurs":["paradigme","symptôme","incident","avatar"],"anecdote":"L\'« épiphénoménisme » est une thèse philosophique selon laquelle les états mentaux ne sont que des sous-produits du cerveau, comparables à la fumée d\'une locomotive : produits par la machine, mais sans effet sur sa marche.","categorie":"mot-rare"},{"id":"hypostasier","mot":"hypostasier","nature":"verbe","definitions":["Traiter une abstraction, une idée ou une qualité comme si elle était une chose réelle, une substance existant par elle-même.","Ériger un concept en réalité autonome."],"phonetique":"/i.pɔs.ta.zje/","etymologie":"Dérivé de « hypostase », emprunté au grec hupostasis (« ce qui est dessous, substance, fondement »), de hupo- (« sous ») et stasis (« action de se tenir »).","registre":"littéraire","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["réifier","substantialiser","chosifier"],"antonymes":["abstraire","relativiser"],"exemplesCorrects":["On a trop souvent hypostasié la Nation, comme si elle était une personne dotée d\'une volonté.","Le philosophe reproche à ses adversaires d\'hypostasier le hasard en une puissance agissante.","Hypostasier la Raison revient à en faire une divinité plutôt qu\'une faculté."],"exemplesIncorrects":["Le maçon a hypostasié les briques pour monter le mur en une journée.","Elle a hypostasié son café avant de partir travailler."],"distracteurs":["postuler","sublimer","extrapoler","supposer"],"anecdote":"Le terme « hypostase » vient de la théologie : dans le dogme de la Trinité, les trois hypostases (Père, Fils, Esprit) sont les trois substances distinctes d\'une même divinité.","categorie":"mot-rare"},{"id":"reifier","mot":"réifier","nature":"verbe","definitions":["Transformer en chose ; traiter ce qui est abstrait, humain ou vivant comme un objet concret.","En philosophie et en sociologie, considérer des rapports sociaux ou des idées comme des choses figées."],"phonetique":"/ʁe.i.fje/","etymologie":"Dérivé savant du latin res, rei (« chose »), avec le suffixe -ifier (du latin facere, « faire »), littéralement « faire chose ». Concept popularisé par la sociologie marxiste (réification).","registre":"soutenu","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["chosifier","objectiver","hypostasier"],"antonymes":["humaniser","personnifier","abstraire"],"exemplesCorrects":["Le capitalisme tendrait à réifier le travailleur, réduit à sa seule force de travail.","Réifier l\'amour en le mesurant à des cadeaux, c\'est en trahir la nature.","Ce discours réifie les femmes en les réduisant à de simples objets de désir."],"exemplesIncorrects":["Le sculpteur a réifié le marbre pour en faire une émotion pure.","Il a réifié sa promesse en la tenant scrupuleusement."],"distracteurs":["sublimer","matérialiser","instrumentaliser","concrétiser"],"anecdote":"Le concept de « réification » a été développé par le philosophe Georg Lukács dans « Histoire et conscience de classe » (1923), où il décrit comment, sous le capitalisme, les rapports entre les personnes prennent l\'apparence de rapports entre des choses.","categorie":"mot-rare"},{"id":"sublimer","mot":"sublimer","nature":"verbe","definitions":["En psychanalyse, transformer une pulsion (notamment sexuelle ou agressive) en une activité socialement valorisée : art, science, création.","En chimie, faire passer un corps directement de l\'état solide à l\'état gazeux sans phase liquide.","Par extension littéraire, élever, transmuer quelque chose en une réalité supérieure."],"phonetique":"/sy.bli.me/","etymologie":"Emprunté au latin sublimare (« élever, exalter »), de sublimis (« haut, élevé »). Le sens psychanalytique a été fixé par Freud (Sublimierung).","registre":"soutenu","niveau":3,"themes":["abstrait","emotions"],"synonymes":["transmuer","transcender","exalter"],"antonymes":["refouler","ravaler","avilir"],"exemplesCorrects":["L\'artiste sublime ses tourments intimes en une œuvre d\'une rare puissance.","Chauffé doucement, l\'iode se sublime et dégage des vapeurs violettes.","Freud voyait dans la création culturelle une manière de sublimer les pulsions."],"exemplesIncorrects":["Cette robe sublime complètement sa silhouette pour la soirée.","Le chef a sublimé le plat avec une touche de truffe."],"distracteurs":["magnifier","rehausser","épurer","transfigurer"],"anecdote":"Dans l\'usage courant, on emploie de plus en plus « sublimer » au sens de « mettre en valeur, embellir » (« cette coupe sublime votre visage »). Ce sens est critiqué : à l\'origine, sublimer désigne soit le passage solide-gaz en chimie, soit, chez Freud, la conversion d\'une pulsion en activité supérieure — non un simple embellissement.","categorie":"piege-sens","piege":{"formeFautive":"sublimer au sens de « mettre en valeur, embellir »","explication":"L\'emploi très répandu « ce plat sublime la viande » (= la met en valeur) est un affaiblissement du sens. Stricto sensu, sublimer signifie transmuer une réalité en une forme supérieure (pulsion en art, solide en gaz), pas simplement embellir."}},{"id":"theodicee","mot":"théodicée","nature":"nom féminin","definitions":["Justification de la bonté et de la justice de Dieu face à l\'existence du mal dans le monde.","Partie de la philosophie qui traite de Dieu par la seule raison ; théologie naturelle."],"phonetique":"/te.ɔ.di.se/","etymologie":"Mot forgé par Leibniz à partir du grec theos (« dieu ») et dikê (« justice »), littéralement « justice de Dieu ». Titre de son ouvrage « Essais de théodicée » (1710).","registre":"littéraire","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["théologie naturelle"],"antonymes":["athéisme","nihilisme"],"exemplesCorrects":["Le tremblement de terre de Lisbonne a porté un coup rude à la théodicée optimiste de Leibniz.","Sa thèse porte sur la théodicée chez les penseurs du Grand Siècle.","Comment concilier un Dieu bon avec la souffrance des innocents ? Telle est la question de la théodicée."],"exemplesIncorrects":["La théodicée du village rassemble les fidèles chaque dimanche matin.","Il a décoré la théodicée de l\'église avec des cierges."],"distracteurs":["liturgie","exégèse","cosmogonie","patristique"],"anecdote":"Le mot « théodicée » a été inventé de toutes pièces par Leibniz en 1710. C\'est aussi sa « théodicée » optimiste — « tout est pour le mieux dans le meilleur des mondes possibles » — que Voltaire tourne en dérision dans « Candide ».","categorie":"mot-rare"},{"id":"eschatologie","mot":"eschatologie","nature":"nom féminin","definitions":["Doctrine ou ensemble des croyances relatives aux fins dernières de l\'homme et du monde (mort, jugement, au-delà, fin des temps).","Étude des derniers événements de l\'histoire selon une perspective religieuse."],"phonetique":"/ɛs.ka.tɔ.lɔ.ʒi/","etymologie":"Composé du grec eskhatos (« dernier, extrême ») et de -logie (logos, « discours, étude »). Littéralement « discours sur les choses dernières ».","registre":"soutenu","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["apocalyptique"],"antonymes":["cosmogonie","genèse"],"exemplesCorrects":["L\'eschatologie chrétienne annonce la résurrection des morts et le jugement dernier.","Ce roman de science-fiction déploie une véritable eschatologie laïque.","Les prophètes ont nourri une eschatologie où le mal sera finalement vaincu."],"exemplesIncorrects":["L\'eschatologie raconte la création du monde en sept jours.","Le médecin a posé un diagnostic d\'eschatologie aiguë."],"distracteurs":["téléologie","sotériologie","cosmologie","angélologie"],"anecdote":"On confond souvent « eschatologie » (du grec eskhatos, « dernier ») avec « scatologie » (du grec skôr, skatos, « excrément ») : deux mots très proches à l\'oreille mais aux sens radicalement étrangers, l\'un parlant de la fin du monde, l\'autre des matières fécales.","categorie":"mot-rare"},{"id":"soteriologie","mot":"sotériologie","nature":"nom féminin","definitions":["Doctrine, partie de la théologie qui traite du salut de l\'homme et des moyens de l\'obtenir.","Ensemble des conceptions relatives à la rédemption."],"phonetique":"/sɔ.te.ʁjɔ.lɔ.ʒi/","etymologie":"Composé du grec sôtêria (« salut, conservation »), de sôtêr (« sauveur »), et de -logie (logos, « étude »). Littéralement « discours sur le salut ».","registre":"littéraire","niveau":5,"themes":["abstrait","litteraire"],"synonymes":[],"antonymes":[],"exemplesCorrects":["La sotériologie chrétienne place la croix au centre du salut de l\'humanité.","Son cours de théologie distingue la christologie de la sotériologie.","Chaque grande religion développe sa propre sotériologie, sa voie du salut."],"exemplesIncorrects":["La sotériologie étudie la composition chimique des étoiles.","Le garagiste a confié la sotériologie du moteur à son apprenti."],"distracteurs":["eschatologie","christologie","ecclésiologie","hagiographie"],"anecdote":"Le grec sôtêr, « sauveur », racine de « sotériologie », se retrouve dans le prénom Sauveur et dans l\'épithète « Soter » que portaient certains souverains hellénistiques, comme Ptolémée Ier Sôter, « le Sauveur ».","categorie":"mot-rare"},{"id":"apophatique","mot":"apophatique","nature":"adjectif","definitions":["Se dit d\'une théologie qui ne cherche à connaître Dieu que par la négation, en disant ce qu\'il n\'est pas plutôt que ce qu\'il est ; théologie négative.","Qui procède par négation pour approcher l\'indicible."],"phonetique":"/a.pɔ.fa.tik/","etymologie":"Emprunté au grec apophatikos (« négatif »), de apophasis (« négation »), de apo- (« loin de ») et phêmi (« dire »). S\'oppose à cataphatique (théologie affirmative).","registre":"littéraire","niveau":5,"themes":["abstrait","litteraire"],"synonymes":["négatif"],"antonymes":["cataphatique","affirmatif"],"exemplesCorrects":["La voie apophatique affirme que Dieu n\'est ni nommable ni concevable.","Les mystiques rhénans ont cultivé une théologie apophatique de l\'inconnaissance.","Par approche apophatique, on ne dit de l\'absolu que ce qu\'il n\'est pas."],"exemplesIncorrects":["Le professeur a rédigé un compte rendu apophatique, clair et affirmatif.","Sa réponse apophatique énumérait toutes les qualités positives de l\'œuvre."],"distracteurs":["cataphatique","dogmatique","kérygmatique","herméneutique"],"anecdote":"La théologie apophatique, illustrée par le Pseudo-Denys l\'Aréopagite, considère que tout ce qu\'on affirme de Dieu le rabaisse ; on ne peut donc l\'approcher qu\'en niant successivement chaque attribut, jusqu\'au silence.","categorie":"mot-rare"},{"id":"thanatophobie","mot":"thanatophobie","nature":"nom féminin","definitions":["Peur obsédante, angoisse pathologique de la mort ou de tout ce qui s\'y rapporte.","Crainte morbide et persistante de mourir."],"phonetique":"/ta.na.tɔ.fɔ.bi/","etymologie":"Composé du grec thanatos (« mort »), nom du dieu grec personnifiant la mort, et de -phobie (phobos, « peur, effroi »).","registre":"soutenu","niveau":4,"themes":["emotions","abstrait"],"synonymes":[],"antonymes":[],"exemplesCorrects":["Sa thanatophobie l\'empêchait d\'assister au moindre enterrement.","Le thérapeute traite la thanatophobie par une exposition progressive à l\'idée de la mort.","Une thanatophobie sévère peut transformer chaque douleur bénigne en alarme mortelle."],"exemplesIncorrects":["Sa thanatophobie le poussait à adorer les fêtes et les grandes réjouissances.","Atteint de thanatophobie, il collectionnait passionnément les squelettes."],"distracteurs":["nécrophobie","hypocondrie","claustrophobie","agoraphobie"],"anecdote":"Le mot vient de Thanatos, la divinité grecque de la mort, frère jumeau d\'Hypnos, le Sommeil. Sigmund Freud popularisera plus tard « Thanatos » pour désigner la pulsion de mort, opposée à Éros, la pulsion de vie.","categorie":"mot-rare"},{"id":"epanorthose","mot":"épanorthose","nature":"nom féminin","definitions":["Figure de rhétorique consistant à revenir sur ce que l\'on vient de dire pour le corriger, le retrancher ou le renforcer, souvent en feignant de se reprendre."],"phonetique":"/e.pa.nɔʁ.toz/","etymologie":"Du grec ancien ἐπανόρθωσις (epanórthôsis), « action de redresser, correction, amendement », de ἐπανορθόω « redresser, corriger ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["correction","rétractation","autocorrection"],"antonymes":[],"exemplesCorrects":["« J\'espère, que dis-je, je suis certain qu\'il reviendra » : voilà une épanorthose parfaite.","L\'orateur multipliait les épanorthoses pour donner à son propos une intensité croissante.","Par une habile épanorthose, le poète corrige son premier mot pour en choisir un plus juste."],"exemplesIncorrects":["Le médecin a posé une épanorthose au patient après l\'opération.","Cette épanorthose géologique date de plusieurs millions d\'années."],"distracteurs":["anaphore","métaphore","périphrase","hyperbole"],"anecdote":"L\'épanorthose est cousine de la prétérition et de la correction (correctio en latin) : Cicéron en use abondamment dans ses discours pour feindre l\'hésitation tout en renforçant son affirmation.","categorie":"mot-rare"},{"id":"preterition","mot":"prétérition","nature":"nom féminin","definitions":["Figure de rhétorique par laquelle on déclare passer sous silence une chose dont on parle néanmoins, attirant ainsi l\'attention sur elle.","Action d\'omettre, de passer sous silence."],"phonetique":"/pʁe.te.ʁi.sjɔ̃/","etymologie":"Du latin praeteritio, « action de passer, omission », dérivé de praeterire « passer outre, négliger », de praeter « au-delà » et ire « aller ».","registre":"soutenu","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["paralipse","prétermission"],"antonymes":[],"exemplesCorrects":["« Je ne vous parlerai pas de ses dettes ni de ses trahisons » : la prétérition dit tout en feignant de taire.","Par prétérition, l\'avocat évoqua le passé du témoin qu\'il prétendait justement écarter.","Sa lettre n\'était qu\'une longue prétérition : il affirmait ne rien vouloir reprocher tout en accumulant les griefs."],"exemplesIncorrects":["La prétérition de l\'eau a provoqué la sécheresse des champs.","Il a obtenu une prétérition de son loyer pour le mois de mai."],"distracteurs":["digression","allusion","ellipse","litanie"],"anecdote":"La prétérition est l\'arme favorite des polémistes : en annonçant « je ne dirai rien de… », on dit précisément ce que l\'on prétend taire, tout en se donnant l\'air de la discrétion.","categorie":"mot-rare"},{"id":"antiphrase","mot":"antiphrase","nature":"nom féminin","definitions":["Figure de rhétorique consistant à employer un mot ou une expression dans un sens contraire à son sens véritable, le plus souvent par ironie."],"phonetique":"/ɑ̃.ti.fʁɑz/","etymologie":"Du bas latin antiphrasis, emprunté au grec ancien ἀντίφρασις (antíphrasis), de ἀντί « contre » et φράσις « expression, manière de parler ».","registre":"soutenu","niveau":3,"themes":["litteraire","abstrait"],"synonymes":["ironie","contre-vérité"],"antonymes":[],"exemplesCorrects":["Dire « quel temps magnifique ! » sous une averse glaciale est une antiphrase ironique.","Surnommer un géant « Petit Jean » relève de l\'antiphrase.","L\'antiphrase repose sur la complicité : l\'auditeur doit comprendre l\'inverse de ce qui est dit."],"exemplesIncorrects":["Il a souligné cette antiphrase au feutre jaune dans son cahier.","L\'antiphrase du verbe se conjugue à l\'imparfait du subjonctif."],"distracteurs":["paraphrase","périphrase","antithèse","pléonasme"],"anecdote":"C\'est par antiphrase que les Grecs anciens nommaient la mer Noire, redoutable et inhospitalière, « Pont-Euxin », c\'est-à-dire la « mer hospitalière », pour conjurer ses dangers.","categorie":"mot-rare"},{"id":"litote","mot":"litote","nature":"nom féminin","definitions":["Figure de rhétorique consistant à dire moins pour suggérer davantage, souvent au moyen d\'une négation, afin d\'atténuer l\'expression tout en renforçant le sens."],"phonetique":"/li.tɔt/","etymologie":"Du bas latin litotes, emprunté au grec ancien λιτότης (litótês), « simplicité, sobriété », de λιτός (litós) « simple, uni, dépouillé ».","registre":"soutenu","niveau":3,"themes":["litteraire","abstrait"],"synonymes":["atténuation","euphémisme"],"antonymes":["hyperbole","exagération"],"exemplesCorrects":["« Va, je ne te hais point » : la litote de Chimène signifie en réalité un amour brûlant.","Dire d\'un repas qu\'il « n\'était pas mauvais » est une litote pour le louer.","La litote séduit par sa retenue : elle laisse à l\'interlocuteur le soin de mesurer toute la force du propos."],"exemplesIncorrects":["Le chirurgien a retiré la litote du genou du patient.","On a planté une litote au fond du jardin, près des rosiers."],"distracteurs":["métonymie","anaphore","gradation","syllepse"],"anecdote":"La litote la plus célèbre du théâtre français est ce vers du Cid de Corneille : « Va, je ne te hais point », où Chimène avoue son amour à Rodrigue par la voie du moindre dire.","categorie":"mot-rare"},{"id":"prosopopee","mot":"prosopopée","nature":"nom féminin","definitions":["Figure de rhétorique consistant à faire parler ou agir un absent, un mort, un animal, une chose personnifiée ou une abstraction."],"phonetique":"/pʁo.zo.pɔ.pe/","etymologie":"Du bas latin prosopopoeia, emprunté au grec ancien προσωποποιΐα (prosôpopoiía), de πρόσωπον (prósôpon) « visage, personne » et ποιεῖν (poieîn) « faire, créer ».","registre":"littéraire","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["personnification"],"antonymes":[],"exemplesCorrects":["Dans la fable, la prosopopée prête la parole au chêne et au roseau.","Par une prosopopée saisissante, l\'orateur fit parler la Patrie elle-même.","La prosopopée des Lois, chez Platon, met dans leur bouche les arguments qui retiennent Socrate de fuir."],"exemplesIncorrects":["Le maçon a renforcé la prosopopée du mur porteur.","Elle souffre d\'une prosopopée chronique qui lui rougit la peau."],"distracteurs":["allégorie","métaphore","apostrophe","hypallage"],"anecdote":"La plus fameuse prosopopée de la littérature française est sans doute la « Prosopopée de Fabricius » de Rousseau, où ce héros romain ressuscité fustige la corruption des mœurs modernes.","categorie":"mot-rare"},{"id":"hypotypose","mot":"hypotypose","nature":"nom féminin","definitions":["Figure de rhétorique consistant en une description si vive et si frappante qu\'elle semble mettre la chose décrite sous les yeux du lecteur ou de l\'auditeur."],"phonetique":"/i.pɔ.ti.poz/","etymologie":"Du grec ancien ὑποτύπωσις (hupotúpôsis), « ébauche, modèle, esquisse », de ὑποτυπόω « esquisser, modeler ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["description","tableau"],"antonymes":[],"exemplesCorrects":["Le récit de la bataille est une hypotypose : on croit voir les chevaux tomber et entendre les cris.","Par cette hypotypose, le romancier rend la scène si présente qu\'on en oublie qu\'on lit.","Hugo excelle dans l\'hypotypose, peignant la tempête avec une force quasi hallucinatoire."],"exemplesIncorrects":["Le dentiste a soigné une hypotypose au fond de la mâchoire.","On mesure l\'hypotypose d\'un triangle avec un rapporteur."],"distracteurs":["énumération","comparaison","anaphore","périphrase"],"anecdote":"L\'hypotypose la plus citée des classes de français est le récit de la mort d\'Hippolyte dans la Phèdre de Racine, où Théramène fait surgir le monstre marin avec une intensité presque cinématographique.","categorie":"mot-rare"},{"id":"asyndete","mot":"asyndète","nature":"nom féminin","definitions":["Figure de construction consistant à supprimer les mots de liaison (conjonctions, adverbes) entre des termes ou des propositions qui en appelleraient normalement."],"phonetique":"/a.sɛ̃.dɛt/","etymologie":"Du bas latin asyndeton, emprunté au grec ancien ἀσύνδετον (asúndeton), « non lié », de ἀ- privatif et σύνδετος « lié ensemble », de συνδέω « lier ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["dissolution"],"antonymes":["polysyndète"],"exemplesCorrects":["« Je vins, je vis, je vainquis » est une asyndète célèbre, sans la moindre conjonction.","L\'asyndète accélère le rythme de la phrase en supprimant les liaisons attendues.","Par asyndète, le poète juxtapose les images sans les relier, laissant au lecteur le soin du lien."],"exemplesIncorrects":["L\'électricien a remplacé l\'asyndète du compteur défectueux.","On lui a diagnostiqué une asyndète du nerf optique."],"distracteurs":["anacoluthe","ellipse","hyperbate","parataxe"],"anecdote":"L\'asyndète la plus fameuse est la formule attribuée à Jules César, « Veni, vidi, vici », dont l\'absence de liaison donne toute la sécheresse triomphante.","categorie":"mot-rare"},{"id":"zeugme","mot":"zeugme","nature":"nom masculin","definitions":["Figure de construction consistant à rattacher à un même mot (souvent un verbe) deux termes qui ne s\'accordent pas sur le même plan, par exemple un sens propre et un sens figuré, ou un terme concret et un terme abstrait."],"phonetique":"/zøgm/","etymologie":"Du bas latin zeugma, emprunté au grec ancien ζεῦγμα (zeûgma), « lien, joug, attelage », de ζεύγνυμι (zeúgnumi) « joindre, atteler ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["attelage"],"antonymes":[],"exemplesCorrects":["« Vêtu de probité candide et de lin blanc » : Hugo unit par zeugme une vertu et un tissu.","Le zeugme produit un effet plaisant en accolant un terme concret et un terme abstrait sous un même verbe.","« Il prit son chapeau et la porte » : ce zeugme amuse en liant un objet et une expression figurée."],"exemplesIncorrects":["Le menuisier a posé un zeugme entre les deux poutres du toit.","Elle a réglé le zeugme de la machine à laver avant de la lancer."],"distracteurs":["chiasme","anaphore","syllepse","pléonasme"],"anecdote":"Le zeugme le plus cité de la poésie française vient de Booz endormi de Victor Hugo : « Vêtu de probité candide et de lin blanc », où un même participe attelle une qualité morale et une étoffe.","categorie":"mot-rare"},{"id":"anacoluthe","mot":"anacoluthe","nature":"nom féminin","definitions":["Rupture de construction syntaxique dans une phrase, qui rompt avec l\'ordre grammatical attendu, parfois par effet de style, parfois par maladresse."],"phonetique":"/a.na.kɔ.lyt/","etymologie":"Du bas latin anacoluthon, emprunté au grec ancien ἀνακόλουθον (anakólouthon), « qui ne suit pas, sans suite », de ἀ- privatif et ἀκόλουθος « qui suit, conséquent ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["rupture","discordance"],"antonymes":[],"exemplesCorrects":["« Le nez de Cléopâtre : s\'il eût été plus court… » : Pascal use d\'une anacoluthe saisissante.","L\'anacoluthe, en brisant la syntaxe, peut traduire l\'émotion ou le désordre de la pensée.","Cette phrase commence à la première personne puis bascule sans transition : c\'est une anacoluthe."],"exemplesIncorrects":["Le plombier a réparé l\'anacoluthe qui fuyait sous l\'évier.","On cultive l\'anacoluthe dans les jardins humides du sud."],"distracteurs":["asyndète","hyperbate","ellipse","inversion"],"anecdote":"L\'anacoluthe la plus commentée est celle de La Fontaine : « Tandis que ma beauté… » ; chez Racine, « Pour qui sont ces serpents qui sifflent sur vos têtes ? » illustre aussi cette rupture maîtrisée.","categorie":"mot-rare"},{"id":"epexegese","mot":"épexégèse","nature":"nom féminin","definitions":["Ajout explicatif, sous forme d\'apposition ou de glose, qui vient préciser ou développer le sens d\'un terme déjà énoncé."],"phonetique":"/e.pɛk.ze.ʒɛz/","etymologie":"Du grec ancien ἐπεξήγησις (epexḗgêsis), « explication supplémentaire », de ἐπί « sur, en plus » et ἐξήγησις « explication, exégèse ».","registre":"littéraire","niveau":5,"themes":["litteraire","abstrait"],"synonymes":["apposition","glose","explicitation"],"antonymes":[],"exemplesCorrects":["Dans « mon ami, c\'est-à-dire mon plus fidèle allié », la seconde partie est une épexégèse.","L\'épexégèse vient éclairer un mot obscur par une précision ajoutée juste après lui.","Le commentateur multiplie les épexégèses pour ne laisser aucun terme dans l\'ambiguïté."],"exemplesIncorrects":["Le kinésithérapeute a soulagé l\'épexégèse du genou droit.","On a versé une épexégèse de farine dans la pâte à pain."],"distracteurs":["paraphrase","périphrase","digression","incise"],"anecdote":"L\'épexégèse est proche de la formule « c\'est-à-dire » : elle ne corrige pas le terme, contrairement à l\'épanorthose, mais l\'explicite en le doublant d\'une glose.","categorie":"mot-rare"},{"id":"catachrese","mot":"catachrèse","nature":"nom féminin","definitions":["Figure consistant à employer un mot au-delà de son sens propre, faute de terme exact, au point que la métaphore devient figée par l\'usage (les pieds d\'une table, les ailes d\'un moulin)."],"phonetique":"/ka.ta.kʁɛz/","etymologie":"Du latin catachresis, emprunté au grec ancien κατάχρησις (katákhrêsis), « emploi abusif, usage détourné », de καταχράομαι « user à fond, employer abusivement ».","registre":"soutenu","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["métaphore lexicalisée","métaphore figée"],"antonymes":[],"exemplesCorrects":["Parler des « pieds » d\'une table est une catachrèse devenue invisible tant l\'usage l\'a figée.","« Les ailes d\'un moulin » et « la feuille de papier » sont des catachrèses courantes.","La catachrèse comble un manque du lexique : on emprunte une image faute de mot propre."],"exemplesIncorrects":["Le médecin a prescrit une catachrèse à prendre matin et soir.","On a repeint la catachrèse de la façade en bleu."],"distracteurs":["métonymie","synecdoque","antonomase","hypallage"],"anecdote":"On ne perçoit presque jamais une catachrèse comme une figure : dire « les bras d\'un fauteuil » ou « monter à cheval sur une chaise » paraît littéral, alors qu\'il s\'agit de métaphores usées par l\'habitude.","categorie":"mot-rare"},{"id":"crepusculaire","mot":"crépusculaire","nature":"adjectif","definitions":["Qui se rapporte au crépuscule, à la lumière du soir ou de l\'aube.","Au figuré : propre au déclin, à la fin d\'un cycle, d\'une époque ou d\'une vie."],"phonetique":"/kʁe.pys.ky.lɛʁ/","etymologie":"Dérivé savant du latin crepusculum, « crépuscule, lumière incertaine du soir », avec le suffixe -aire.","registre":"littéraire","niveau":3,"themes":["nature","litteraire","abstrait"],"synonymes":["vespéral","déclinant","finissant"],"antonymes":["auroral","matinal","naissant"],"exemplesCorrects":["Une lumière crépusculaire baignait la vallée d\'une teinte orangée.","Ses dernières œuvres ont une beauté crépusculaire, empreinte de mélancolie et de fin.","Certains papillons crépusculaires ne volent qu\'à la tombée du jour."],"exemplesIncorrects":["Il a poussé un cri crépusculaire de joie en gagnant la course.","Le moteur crépusculaire de la voiture ronronnait à plein régime."],"distracteurs":["matinal","estival","nocturne","automnal"],"anecdote":"En zoologie, on qualifie de crépusculaires les animaux actifs surtout à l\'aube et au crépuscule, par opposition aux espèces diurnes et nocturnes ; le terme désigne donc une réalité précise autant qu\'une atmosphère poétique.","categorie":"mot-rare"},{"id":"matutinal","mot":"matutinal","nature":"adjectif","definitions":["Qui a rapport au matin, qui appartient au matin.","Qui se produit ou que l\'on accomplit le matin, de bon matin."],"phonetique":"/ma.ty.ti.nal/","etymologie":"Emprunté au bas latin matutinalis, dérivé de matutinus (« du matin »), lui-même rattaché à Matuta, déesse romaine de l\'aurore.","registre":"littéraire","niveau":4,"themes":["litteraire","quotidien"],"synonymes":["matinal","aurorale","matineux"],"antonymes":["vespéral","nocturne","crépusculaire"],"exemplesCorrects":["La rosée matutinale scintillait encore sur les feuilles du jardin.","Il chérissait ce silence matutinal, avant que la ville ne s\'éveille.","Une fraîcheur matutinale montait du fleuve et engourdissait les promeneurs."],"exemplesIncorrects":["Nous avons admiré le ciel matutinal embrasé par le coucher du soleil.","La fatigue matutinale l\'a tenu éveillé jusqu\'à trois heures de la nuit."],"distracteurs":["vespéral","estival","diurne","hivernal"],"anecdote":"Le mot partage sa racine avec « matines », l\'office religieux chanté avant l\'aube : tous deux remontent à Matuta, l\'antique déesse latine du petit matin.","categorie":"mot-rare"},{"id":"nimbe","mot":"nimbé","nature":"adjectif","definitions":["Entouré d\'un nimbe, d\'une auréole, comme les figures sacrées dans l\'iconographie.","Au sens figuré, environné d\'un halo lumineux, d\'un rayonnement diffus ou d\'une aura."],"phonetique":"/nɛ̃.be/","etymologie":"Participe passé du verbe nimber, dérivé de nimbe, emprunté au latin nimbus (« nuage, nuée », puis « auréole »).","registre":"littéraire","niveau":4,"themes":["litteraire","nature"],"synonymes":["auréolé","ceint","entouré"],"antonymes":["terne","obscurci","dépouillé"],"exemplesCorrects":["Le saint, sur la fresque, apparaissait nimbé d\'or fin.","La colline, nimbée de brume, semblait flotter au-dessus de la vallée.","Nimbée par la lumière du couchant, sa silhouette paraissait irréelle."],"exemplesIncorrects":["Le ciel était nimbé d\'une pluie battante et glaciale.","Il a nimbé la porte d\'un grand coup de pied rageur."],"distracteurs":["voilé","drapé","frangé","constellé"],"anecdote":"Le latin nimbus désignait d\'abord le nuage d\'orage ; c\'est le nuage lumineux qui enveloppait les divinités antiques qui a donné, par glissement, l\'auréole des saints chrétiens.","categorie":"mot-rare"},{"id":"chatoyant","mot":"chatoyant","nature":"adjectif","definitions":["Qui brille de reflets changeants selon l\'orientation de la lumière ou du regard.","Au sens figuré, riche, brillant et varié, qui séduit par son éclat (style, couleurs, descriptions)."],"phonetique":"/ʃa.twa.jɑ̃/","etymologie":"Participe présent du verbe chatoyer, dérivé de chat : allusion à l\'éclat changeant de l\'œil du chat dans la pénombre.","registre":"soutenu","niveau":3,"themes":["nature","litteraire"],"synonymes":["miroitant","moiré","irisé"],"antonymes":["terne","mat","blafard"],"exemplesCorrects":["Elle portait une étoffe de soie chatoyante qui changeait de teinte à chaque pas.","Le plumage chatoyant du paon attirait tous les regards.","Son style chatoyant donnait à la moindre anecdote des airs de conte."],"exemplesIncorrects":["Le mur de béton chatoyant était d\'un gris uniforme et morne.","Sa voix chatoyante résonnait dans le couloir silencieux."],"distracteurs":["bruissant","velouté","diapré","duveteux"],"anecdote":"Le mot vient bien du chat : c\'est l\'œil félin, qui semble luire et changer d\'éclat dans l\'ombre, qui a inspiré le verbe chatoyer au XVIIIe siècle.","categorie":"mot-rare"},{"id":"moire","mot":"moiré","nature":"adjectif","definitions":["Qui présente des reflets ondoyants et changeants, à la manière de la moire (étoffe à reflets).","Qui chatoie, dont la surface offre des ondulations lumineuses et chatoyantes."],"phonetique":"/mwa.ʁe/","etymologie":"Participe passé du verbe moirer, dérivé de moire, lui-même altération de l\'anglais mohair (poil de la chèvre angora), emprunté à l\'arabe muḫayyar.","registre":"soutenu","niveau":4,"themes":["litteraire","nature","emprunts"],"synonymes":["chatoyant","ondoyant","irisé"],"antonymes":["mat","uni","terne"],"exemplesCorrects":["La surface moirée du lac renvoyait des reflets mouvants au clair de lune.","Elle nouait un ruban de taffetas moiré autour de ses cheveux.","Le pelage moiré du cheval ondulait à chaque foulée."],"exemplesIncorrects":["Le tissu moiré était d\'une opacité totale, sans le moindre reflet.","Il a moiré la table d\'un coup d\'éponge pour la nettoyer."],"distracteurs":["damassé","satiné","nacré","tavelé"],"anecdote":"Curieusement, « moire » et « mohair » sont le même mot : l\'étoffe à reflets fut nommée d\'après le poil de chèvre angora, dont le nom arabe muḫayyar a transité par l\'anglais avant de revenir en français.","categorie":"mot-rare"},{"id":"opalescent","mot":"opalescent","nature":"adjectif","definitions":["Qui présente des reflets laiteux et irisés évoquant ceux de l\'opale.","Dont la transparence est trouble, voilée d\'une lueur nacrée."],"phonetique":"/ɔ.pa.le.sɑ̃/","etymologie":"Dérivé savant d\'opale (du latin opalus, lui-même emprunté au grec ou au sanskrit upala, « pierre précieuse »), avec le suffixe -escent marquant le devenir.","registre":"soutenu","niveau":4,"themes":["nature","litteraire"],"synonymes":["irisé","nacré","laiteux"],"antonymes":["limpide","transparent","translucide"],"exemplesCorrects":["Le ciel d\'aube était opalescent, comme baigné de lait et de rose.","Elle versa une liqueur opalescente où dansaient des reflets bleutés.","Une brume opalescente noyait les contours du paysage."],"exemplesIncorrects":["L\'eau opalescente du torrent était d\'une transparence parfaite, sans le moindre voile.","Le charbon opalescent brillait d\'un noir profond et opaque."],"distracteurs":["phosphorescent","fluorescent","translucide","diaphane"],"anecdote":"Le mot évoque l\'opale, dont le jeu de couleurs laiteuses fut longtemps tenu pour porte-malheur ; au XIXe siècle, certains joailliers peinaient à vendre cette pierre pourtant somptueuse à cause de cette superstition.","categorie":"mot-rare"},{"id":"prismatique","mot":"prismatique","nature":"adjectif","definitions":["Qui a la forme d\'un prisme ou qui s\'y rapporte.","Qui décompose la lumière en couleurs comme un prisme ; qui présente les couleurs de l\'arc-en-ciel."],"phonetique":"/pʁis.ma.tik/","etymologie":"Dérivé de prisme, emprunté au bas latin prisma, du grec prisma (« chose sciée »), avec le suffixe -atique.","registre":"soutenu","niveau":3,"themes":["nature","abstrait"],"synonymes":["irisé","spectral","polychrome"],"antonymes":["monochrome","incolore","uni"],"exemplesCorrects":["Le cristal jeta sur le mur des taches prismatiques aux sept couleurs.","La rosée, sous le soleil, prenait des éclats prismatiques.","L\'aile du papillon offrait un chatoiement prismatique éblouissant."],"exemplesIncorrects":["Le brouillard prismatique était d\'un gris parfaitement uniforme.","Il a prismatique la lumière à travers la fenêtre embuée."],"distracteurs":["sphérique","cylindrique","fluorescent","translucide"],"anecdote":"C\'est Newton qui, en faisant passer la lumière du soleil à travers un prisme, démontra qu\'elle se décompose en un spectre coloré : l\'adjectif « prismatique » garde la mémoire de cette expérience fondatrice.","categorie":"mot-rare"},{"id":"saturnien","mot":"saturnien","nature":"adjectif","definitions":["Relatif à la planète Saturne ou au dieu Saturne.","Au sens figuré, d\'un tempérament sombre, mélancolique et taciturne, que l\'astrologie ancienne attribuait à l\'influence de Saturne."],"phonetique":"/sa.tyʁ.njɛ̃/","etymologie":"Dérivé de Saturne, nom du dieu romain de l\'agriculture et de la planète, du latin Saturnus ; le sens mélancolique vient de l\'astrologie médiévale, qui faisait de Saturne l\'astre de la bile noire.","registre":"littéraire","niveau":5,"themes":["emotions","litteraire","abstrait"],"synonymes":["mélancolique","ténébreux","taciturne"],"antonymes":["jovial","enjoué","exubérant"],"exemplesCorrects":["Cet homme saturnien ne souriait jamais et fuyait toute compagnie.","Une humeur saturnienne l\'envahissait dès que tombait le crépuscule.","Le poète cultivait une élégance saturnienne, faite d\'ombre et de silence."],"exemplesIncorrects":["D\'un naturel saturnien, il riait à gorge déployée à la moindre plaisanterie.","La fête saturnienne débordait de joie, de musique et de danses."],"distracteurs":["lunatique","mercuriel","vénusien","jovial"],"anecdote":"Verlaine intitula son premier recueil « Poèmes saturniens » : se disant né sous le signe de Saturne, il revendiquait ainsi un tempérament voué à la mélancolie et au malheur.","categorie":"mot-rare"},{"id":"splenetique","mot":"splénétique","nature":"adjectif","definitions":["En proie au spleen, à une mélancolie profonde, à l\'ennui sans cause et au dégoût de vivre.","Vieilli ou médical : qui a rapport à la rate."],"phonetique":"/sple.ne.tik/","etymologie":"Emprunté au latin médical spleneticus, dérivé du grec splên (« la rate ») ; l\'ancienne médecine attribuait la mélancolie à la bile noire prétendument sécrétée par la rate.","registre":"littéraire","niveau":5,"themes":["emotions","litteraire","abstrait"],"synonymes":["mélancolique","neurasthénique","morose"],"antonymes":["allègre","guilleret","euphorique"],"exemplesCorrects":["Sous la pluie d\'automne, il sombrait dans des humeurs splénétiques.","Une lassitude splénétique le détournait de tout projet.","Le héros splénétique du roman erre sans but dans une ville grise."],"exemplesIncorrects":["Splénétique et débordant d\'entrain, il organisait fête sur fête.","Il a splénétique son discours d\'une voix tonitruante."],"distracteurs":["flegmatique","sanguin","colérique","atrabilaire"],"anecdote":"Le mot dérive de la rate (splên en grec) parce que la médecine antique des humeurs y logeait la « bile noire », source supposée de la mélancolie ; Baudelaire a immortalisé ce spleen dans « Les Fleurs du mal ».","categorie":"mot-rare"},{"id":"nostalgique","mot":"nostalgique","nature":"adjectif","definitions":["Qui éprouve ou exprime la nostalgie, le regret mélancolique d\'un passé révolu ou d\'un lieu lointain.","Qui évoque ce regret, qui en est empreint."],"phonetique":"/nɔs.tal.ʒik/","etymologie":"Dérivé de nostalgie, mot forgé au XVIIe siècle à partir du grec nostos (« retour ») et algos (« douleur »), pour désigner d\'abord le mal du pays.","registre":"courant","niveau":1,"themes":["emotions","abstrait"],"synonymes":["mélancolique","languissant"],"antonymes":["insouciant","détaché","tourné vers l\'avenir"],"exemplesCorrects":["Il feuilletait l\'album de famille d\'un air nostalgique.","Cette chanson nostalgique lui rappelait ses étés d\'enfance.","Elle parlait de son village natal avec une tendresse nostalgique."],"exemplesIncorrects":["Il est nostalgique à l\'idée de partir demain en vacances : il a hâte d\'y être.","Sa lettre nostalgique débordait d\'enthousiasme pour ses projets d\'avenir."],"distracteurs":["anxieux","euphorique","rancunier","fébrile"],"anecdote":"On croit souvent qu\'être « nostalgique » signifie simplement être triste ou maussade : le mot désigne en réalité le regret précis du passé ou d\'un lieu perdu. Forgé en 1688 par un médecin suisse, il nommait d\'abord le mal du pays des mercenaires éloignés de chez eux.","piege":{"formeFautive":"Je suis nostalgique de partir demain (au sens de « impatient »).","explication":"« Nostalgique » exprime le regret d\'un passé ou d\'un lieu perdu, jamais une attente joyeuse de l\'avenir : on ne peut être nostalgique d\'un événement à venir."},"categorie":"piege-sens"},{"id":"ombrageux","mot":"ombrageux","nature":"adjectif","definitions":["D\'un caractère susceptible, méfiant, prompt à se vexer ou à prendre ombrage.","En parlant d\'un cheval, qui s\'effraie et se cabre aisément."],"phonetique":"/ɔ̃.bʁa.ʒø/","etymologie":"Dérivé d\'ombrage, de ombre (latin umbra) ; au sens figuré, « prendre ombrage » signifie concevoir de la défiance ou du soupçon.","registre":"soutenu","niveau":3,"themes":["emotions","abstrait"],"synonymes":["susceptible","méfiant","soupçonneux"],"antonymes":["confiant","accommodant","placide"],"exemplesCorrects":["D\'un naturel ombrageux, il voyait une critique dans le moindre conseil.","Son orgueil ombrageux lui faisait redouter la moindre rivalité.","Le poulain, encore ombrageux, sursautait au moindre bruit."],"exemplesIncorrects":["Ce grand chêne ombrageux protégeait les promeneurs du soleil de midi.","Le sous-bois ombrageux offrait une fraîcheur appréciable en été."],"distracteurs":["taciturne","désinvolte","indolent","chaleureux"],"anecdote":"On confond souvent « ombrageux » avec « ombragé » (qui donne de l\'ombre) : un lieu est ombragé, mais une personne ombrageuse est susceptible. Le mot vient de « prendre ombrage », c\'est-à-dire concevoir de la défiance.","piege":{"formeFautive":"une terrasse ombrageuse (au sens de « qui donne de l\'ombre »)","explication":"« Ombrageux » qualifie un caractère susceptible et méfiant, non un lieu. Ce qui procure de l\'ombre est « ombragé » : on dit une allée ombragée, mais un homme ombrageux."},"categorie":"piege-sens"},{"id":"reveche","mot":"revêche","nature":"adjectif","definitions":["D\'un caractère rude, peu aimable et peu accommodant ; rébarbatif.","Vieilli : âpre au toucher, rugueux (en parlant d\'une matière)."],"phonetique":"/ʁə.vɛʃ/","etymologie":"Origine incertaine ; peut-être issu d\'un latin populaire reconstitué *reversicus (de re-versus, « retourné, rebroussé »), ou bien rattaché à une racine germanique évoquant la rudesse, d\'où le sens d\'« âpre, rêche ».","registre":"soutenu","niveau":4,"themes":["emotions","abstrait"],"synonymes":["rébarbatif","acariâtre","bourru"],"antonymes":["affable","avenant","accommodant"],"exemplesCorrects":["La concierge revêche accueillait les visiteurs d\'un regard glacial.","Il opposa à mes arguments un silence revêche.","Sous ses dehors revêches se cachait pourtant un cœur généreux."],"exemplesIncorrects":["D\'humeur revêche, il distribuait sourires et compliments à la ronde.","Le revêche parfum des roses embaumait tout le salon."],"distracteurs":["affable","loquace","débonnaire","madré"],"anecdote":"« Revêche » a d\'abord qualifié une matière rugueuse et rêche au toucher avant de s\'appliquer, par métaphore, aux humeurs rébarbatives ; on entend encore cette parenté avec l\'adjectif « rêche ».","categorie":"mot-rare"},{"id":"acariatre","mot":"acariâtre","nature":"adjectif","definitions":["D\'un caractère hargneux, désagréable et querelleur ; d\'humeur difficile et chagrine.","Qui manifeste cette mauvaise humeur acerbe et grincheuse."],"phonetique":"/a.ka.ʁjɑtʁ/","etymologie":"Du « mal saint Acaire » (saint Acaire, évêque de Noyon réputé guérir la folie) ; la forme « acariastre » fut ensuite rapprochée, par fausse étymologie, du latin acer (« âpre, aigre »), d\'où l\'accent circonflexe gardant la trace de l\'ancien s.","registre":"courant","niveau":3,"themes":["emotions","abstrait"],"synonymes":["hargneux","grincheux","revêche"],"antonymes":["affable","avenant","débonnaire"],"exemplesCorrects":["Le vieil homme acariâtre rabrouait quiconque osait lui adresser la parole.","Sa voisine acariâtre se plaignait du moindre bruit à toute heure.","L\'âge l\'avait rendu acariâtre, prompt à la querelle pour un rien."],"exemplesIncorrects":["D\'une humeur acariâtre, elle distribuait des sourires à tous les passants.","Le climat acariâtre de cette région offrait des étés doux et ensoleillés."],"distracteurs":["affable","placide","jovial","ombrageux"],"anecdote":"On écrit souvent à tort « acariatre » sans accent, ou « acariâtre » prononcé à l\'anglaise : l\'accent circonflexe garde le souvenir d\'un ancien s (« acariastre »). Le mot vient du « mal saint Acaire », l\'évêque que l\'on invoquait jadis pour guérir la folie.","piege":{"formeFautive":"acariatre","explication":"Le mot prend un accent circonflexe sur le a : « acariâtre ». Cet accent remplace l\'ancien s de « acariastre » et ne doit pas être oublié."},"categorie":"piege-orthographe"},{"id":"bilieux","mot":"bilieux","nature":"adjectif","definitions":["Qui a un tempérament colérique, enclin à la mauvaise humeur et à l\'irritation.","Relatif à la bile ; qui en produit ou en évacue en abondance."],"phonetique":"/bi.ljø/","etymologie":"Emprunté au latin biliosus (« qui abonde en bile »), dérivé de bilis (« bile »), selon l\'ancienne théorie des humeurs qui attribuait le caractère irascible à un excès de bile.","registre":"soutenu","niveau":3,"themes":["emotions","abstrait"],"synonymes":["coléreux","irascible","atrabilaire","ombrageux"],"antonymes":["placide","flegmatique","serein"],"exemplesCorrects":["Cet homme bilieux s\'emportait pour le moindre contretemps.","Son teint jaune et son humeur bilieuse trahissaient un tempérament difficile.","Le vieux comte, bilieux et soupçonneux, voyait des ennemis partout."],"exemplesIncorrects":["Elle était d\'une humeur bilieuse, riant et plaisantant tout l\'après-midi.","Le paysage bilieux du matin nous emplissait de douceur."],"distracteurs":["nébuleux","soyeux","fielleux","laiteux"],"anecdote":"Le mot renvoie à la médecine antique des quatre humeurs : la « bile jaune » était censée gouverner la colère, d\'où l\'idée qu\'un bilieux est naturellement irascible.","categorie":"mot-rare"},{"id":"emphatique","mot":"emphatique","nature":"adjectif","definitions":["Qui s\'exprime ou s\'énonce avec emphase, d\'une solennité exagérée et pompeuse.","Qui met fortement en relief, qui insiste de manière appuyée (notamment en grammaire et en rhétorique)."],"phonetique":"/ɑ̃.fa.tik/","etymologie":"Emprunté au bas latin emphaticus, lui-même du grec emphatikos (« expressif »), dérivé de emphasis (« mise en relief, force expressive »).","registre":"soutenu","niveau":3,"themes":["litteraire","abstrait"],"synonymes":["pompeux","grandiloquent","ampoulé","déclamatoire"],"antonymes":["sobre","simple","dépouillé","mesuré"],"exemplesCorrects":["Son discours emphatique multipliait les grands mots et les envolées creuses.","Il salua l\'assistance d\'un geste emphatique, comme au théâtre.","La tournure « c\'est moi qui l\'ai fait » est une construction emphatique qui détache le sujet."],"exemplesIncorrects":["Sa prose emphatique était d\'une discrétion et d\'une retenue admirables.","Il parlait d\'un ton emphatique, à voix presque inaudible et sans relief."],"distracteurs":["didactique","sympathique","antipathique","lymphatique"],"anecdote":"En grammaire française, on parle de « tournures emphatiques » pour les constructions comme « c\'est… que » ou « ce qui… c\'est », qui servent à mettre un élément en valeur.","categorie":"mot-rare"},{"id":"grandiloquent","mot":"grandiloquent","nature":"adjectif","definitions":["Qui s\'exprime avec une emphase pompeuse et déclamatoire, dans un style enflé.","Qui se caractérise par une solennité prétentieuse et excessive."],"phonetique":"/ɡʁɑ̃.di.lɔ.kɑ̃/","etymologie":"Emprunté au latin grandiloquus, composé de grandis (« grand ») et de loqui (« parler »), littéralement « qui parle haut ».","registre":"soutenu","niveau":3,"themes":["litteraire","abstrait"],"synonymes":["emphatique","pompeux","ampoulé","déclamatoire"],"antonymes":["sobre","modeste","simple","dépouillé"],"exemplesCorrects":["Le tribun déroulait des phrases grandiloquentes pour masquer le vide de son propos.","On se lassa vite de ses promesses grandiloquentes et jamais tenues.","Son style grandiloquent convenait mal à un sujet aussi intime."],"exemplesIncorrects":["Sa lettre grandiloquente tenait en trois mots sobres et nus.","Il prononça un éloge grandiloquent, c\'est-à-dire bref et sans aucune emphase."],"distracteurs":["nonchalant","indolent","véhément","péremptoire"],"anecdote":"Le terme est presque toujours péjoratif : on l\'emploie pour railler un orateur qui prend de grands airs sans que le fond suive.","categorie":"mot-rare"},{"id":"alambique","mot":"alambiqué","nature":"adjectif","definitions":["Excessivement compliqué, subtil jusqu\'à l\'obscurité ; tarabiscoté.","Se dit d\'un raisonnement ou d\'un style alourdi de détours inutiles."],"phonetique":"/a.lɑ̃.bi.ke/","etymologie":"Dérivé de alambic, lui-même de l\'arabe al-anbīq (« le vase à distiller »), via le grec ambix : l\'idée est celle d\'une pensée « distillée » à l\'excès, raffinée jusqu\'à l\'absurde.","registre":"courant","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["tarabiscoté","compliqué","alambiqué","tortueux"],"antonymes":["simple","limpide","clair","direct"],"exemplesCorrects":["Sa démonstration alambiquée perdait l\'auditoire dès la deuxième phrase.","Il a inventé un prétexte alambiqué pour justifier son retard.","Le contrat était rédigé dans un jargon alambiqué, impossible à déchiffrer."],"exemplesIncorrects":["Son explication alambiquée était d\'une simplicité enfantine.","Le mode d\'emploi, alambiqué, tenait en une seule phrase limpide."],"distracteurs":["sophistiqué","amphigourique","biscornu","abscons"],"anecdote":"On écrit alambiqué avec un seul l : la faute fréquente « allambiqué » vient d\'une fausse analogie ; le mot dérive de l\'alambic, l\'appareil de distillation.","piege":{"formeFautive":"allambiqué","explication":"Le mot s\'écrit avec un seul l, comme alambic dont il dérive. La graphie « allambiqué » avec deux l est fautive."},"categorie":"piege-orthographe"},{"id":"oraculaire","mot":"oraculaire","nature":"adjectif","definitions":["Qui a le caractère obscur, ambigu et solennel d\'un oracle.","Relatif aux oracles ; qui rend ou contient un oracle."],"phonetique":"/ɔ.ʁa.ky.lɛʁ/","etymologie":"Emprunté au latin oracularius (« qui rend des oracles »), dérivé de oraculum (« oracle, lieu où la divinité rend ses réponses »), de orare (« parler, prier »).","registre":"littéraire","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["sibyllin","énigmatique","sentencieux","prophétique"],"antonymes":["limpide","clair","explicite","transparent"],"exemplesCorrects":["Le sage répondit par une formule oraculaire que nul ne sut interpréter.","Ses sentences oraculaires impressionnaient autant qu\'elles déroutaient.","Elle prenait un ton oraculaire pour annoncer les choses les plus banales."],"exemplesIncorrects":["Sa réponse oraculaire était d\'une clarté limpide et sans détour.","Le panneau oraculaire indiquait précisément la sortie de l\'autoroute."],"distracteurs":["spectaculaire","vernaculaire","tentaculaire","auriculaire"],"anecdote":"Le mot évoque la Pythie de Delphes, dont les réponses étaient si ambiguës qu\'on pouvait les interpréter dans les deux sens — d\'où la nuance d\'obscurité solennelle.","categorie":"mot-rare"},{"id":"diserte","mot":"disert","nature":"adjectif","definitions":["Qui parle avec aisance, abondance et élégance ; éloquent.","Qui s\'exprime avec facilité et agrément."],"phonetique":"/di.zɛʁ/","etymologie":"Emprunté au latin disertus (« habile à parler, éloquent »), participe lié à disserere (« exposer, disserter »).","registre":"littéraire","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["éloquent","loquace","beau parleur","prolixe"],"antonymes":["taciturne","laconique","muet","silencieux"],"exemplesCorrects":["Disert et brillant, il captivait la table pendant des heures.","Elle se montra particulièrement diserte sur le sujet qui la passionnait.","Le conférencier, fort disert, n\'avait pas besoin de notes."],"exemplesIncorrects":["Il restait disert dans son coin, sans prononcer un seul mot de la soirée.","Diserte et effacée, elle fuyait toute conversation."],"distracteurs":["déserté","discret","désert","expert"],"anecdote":"On confond souvent disert avec discret à cause de leur ressemblance sonore : c\'est presque le contraire, puisque disert signifie « qui parle avec aisance », non « réservé ».","piege":{"formeFautive":"employé au sens de « discret, réservé »","explication":"Disert ne signifie pas « discret » : il qualifie au contraire celui qui parle avec aisance et éloquence. La proximité sonore avec « discret » induit en erreur."},"categorie":"piege-sens"},{"id":"faconde","mot":"faconde","nature":"nom féminin","definitions":["Abondance facile, parfois intarissable, de la parole ; grande facilité à parler, souvent avec une nuance d\'excès.","Éloquence facile et un peu envahissante."],"phonetique":"/fa.kɔ̃d/","etymologie":"Emprunté au latin facundia (« éloquence, facilité d\'élocution »), dérivé de facundus (« qui parle aisément »), apparenté à fari (« parler »).","registre":"littéraire","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["volubilité","loquacité","éloquence","verve"],"antonymes":["mutisme","laconisme","réticence","silence"],"exemplesCorrects":["Sa faconde méridionale emportait toutes les conversations.","Avec une faconde intarissable, il enchaînait les anecdotes.","On admirait sa faconde, sans toujours retenir le fond de ses propos."],"exemplesIncorrects":["Sa faconde se traduisait par de longs silences embarrassés.","D\'une faconde glaciale, il refusa de dire un mot."],"distracteurs":["fécondité","façade","fadeur","faribole"],"anecdote":"Le mot a souvent une nuance légèrement ironique : louer la faconde de quelqu\'un, c\'est admettre qu\'il parle beaucoup, parfois plus qu\'il ne faudrait.","categorie":"mot-rare"},{"id":"peroraison","mot":"péroraison","nature":"nom féminin","definitions":["Conclusion d\'un discours, dernière partie où l\'orateur récapitule et cherche à emporter l\'adhésion.","Par extension péjorative, discours emphatique et long."],"phonetique":"/pe.ʁɔ.ʁɛ.zɔ̃/","etymologie":"Emprunté au latin peroratio, de perorare (« plaider jusqu\'au bout, conclure un discours »), de per- (« jusqu\'au terme ») et orare (« parler »).","registre":"soutenu","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["conclusion","épilogue","conclusion oratoire"],"antonymes":["exorde","introduction","préambule","prologue"],"exemplesCorrects":["Sa péroraison enflammée arracha des applaudissements à toute l\'assemblée.","Il réservait ses meilleurs arguments pour la péroraison.","La péroraison du plaidoyer fit pleurer les jurés."],"exemplesIncorrects":["Dès la péroraison, en ouvrant son discours, il présenta le sujet.","La péroraison, première phrase de l\'exposé, annonçait le plan."],"distracteurs":["digression","réfutation","narration","apostrophe"],"anecdote":"Dans la rhétorique classique, le discours suivait un plan en parties : l\'exorde ouvrait, la péroraison fermait — c\'est le moment où l\'orateur joue ses dernières cartes émotionnelles.","categorie":"mot-rare"},{"id":"exorde","mot":"exorde","nature":"nom masculin","definitions":["Première partie d\'un discours, par laquelle l\'orateur introduit son sujet et cherche à capter la bienveillance de l\'auditoire.","Entrée en matière d\'un développement oratoire."],"phonetique":"/ɛɡ.zɔʁd/","etymologie":"Emprunté au latin exordium (« commencement, début d\'un discours »), de exordiri (« commencer une trame, ourdir »), littéralement « monter la chaîne d\'un tissu ».","registre":"soutenu","niveau":4,"themes":["litteraire","abstrait"],"synonymes":["introduction","préambule","entrée en matière","préface"],"antonymes":["péroraison","conclusion","épilogue","dénouement"],"exemplesCorrects":["Son exorde habile mit aussitôt le public dans sa poche.","Après un bref exorde, il entra dans le vif du sujet.","L\'exorde donnait le ton de tout le plaidoyer."],"exemplesIncorrects":["En guise d\'exorde, il termina son discours par un dernier appel.","L\'exorde, ultime phrase du texte, refermait la démonstration."],"distracteurs":["digression","réfutation","narration","apostrophe"],"anecdote":"Le mot vient du tissage : exordiri, c\'était « monter la chaîne » sur le métier — l\'exorde est donc, au sens propre, le commencement de la trame d\'un discours.","categorie":"mot-rare"},{"id":"apostropher","mot":"apostropher","nature":"verbe","definitions":["Interpeller vivement et brusquement quelqu\'un, souvent sur un ton de reproche ou de défi.","Adresser la parole à quelqu\'un de manière directe et abrupte."],"phonetique":"/a.pɔs.tʁɔ.fe/","etymologie":"Dérivé de apostrophe, emprunté au grec apostrophê (« action de se détourner pour adresser la parole »), de apostrephein (« détourner »).","registre":"soutenu","niveau":3,"themes":["quotidien","abstrait"],"synonymes":["interpeller","héler","invectiver","haranguer"],"antonymes":["ignorer","feindre d\'ignorer"],"exemplesCorrects":["Il apostropha le serveur d\'un ton sec qui gêna toute la salle.","Du fond de la salle, un spectateur apostropha l\'orateur.","Elle se fit apostropher dans la rue par un inconnu furieux."],"exemplesIncorrects":["Il apostropha une virgule au bon endroit dans sa phrase.","Pour apostropher le mot, l\'imprimeur ajouta un petit signe entre les lettres."],"distracteurs":["interloquer","apostiller","catastropher","interpoler"],"anecdote":"Ne pas confondre le verbe apostropher (« interpeller ») avec l\'apostrophe typographique (le signe \') : ce sont deux sens distincts d\'un même mot d\'origine grecque.","categorie":"mot-rare"},{"id":"fustiger","mot":"fustiger","nature":"verbe","definitions":["Critiquer durement, blâmer avec véhémence ; flageller en paroles.","Vieilli : battre à coups de bâton ou de verges."],"phonetique":"/fys.ti.ʒe/","etymologie":"Emprunté au bas latin fustigare (« battre à coups de bâton »), de fustis (« bâton »). Le sens figuré « critiquer durement » s\'est développé par métaphore.","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["vilipender","stigmatiser","blâmer","pourfendre"],"antonymes":["louer","encenser","féliciter","vanter"],"exemplesCorrects":["L\'éditorialiste fustige l\'inaction des pouvoirs publics.","Dans son discours, elle fustigea les privilèges d\'une élite.","Le moraliste fustige les travers de son époque."],"exemplesIncorrects":["Il fustigea chaleureusement son équipe pour son excellent travail.","Le jury fustigea le candidat en lui décernant tous les honneurs."],"distracteurs":["fustanelle","fumiger","instiguer","fulminer"],"anecdote":"Le verbe désignait à l\'origine un châtiment corporel, la bastonnade : c\'est cette violence physique qui survit aujourd\'hui dans le sens figuré d\'une critique cinglante.","categorie":"mot-rare"},{"id":"stigmatiser","mot":"stigmatiser","nature":"verbe","definitions":["Dénoncer publiquement et avec force comme honteux ou condamnable ; flétrir d\'un blâme retentissant.","Marquer d\'un signe d\'infamie ; au sens propre, marquer d\'un stigmate."],"phonetique":"/stiɡ.ma.ti.ze/","etymologie":"Dérivé de stigmate, emprunté au latin stigma, du grec stigma (« marque au fer rouge, piqûre »), marque dont on flétrissait jadis les esclaves et les criminels.","registre":"soutenu","niveau":3,"themes":["abstrait","quotidien"],"synonymes":["flétrir","fustiger","vilipender","blâmer"],"antonymes":["glorifier","louer","réhabiliter","encenser"],"exemplesCorrects":["Le pamphlet stigmatise la lâcheté des dirigeants de l\'époque.","Il fut publiquement stigmatisé pour sa trahison.","L\'historien stigmatise les compromissions de ces années sombres."],"exemplesIncorrects":["Le panneau lumineux stigmatisait la sortie de secours dans le noir.","Pour stigmatiser le document, le notaire y apposa son cachet officiel."],"distracteurs":["systématiser","stipendier","schématiser","estampiller"],"anecdote":"On l\'emploie souvent à tort au sens affaibli de « simplement désigner ou cataloguer » : stigmatiser implique en réalité une dénonciation infamante, l\'idée d\'une marque au fer rouge dont on flétrit publiquement quelqu\'un.","piege":{"formeFautive":"employé au sens neutre de « désigner, mettre en avant »","explication":"Stigmatiser n\'est pas un simple synonyme de « désigner » ou « pointer » : le verbe porte une charge de réprobation infamante (marquer d\'un stigmate). L\'employer pour une mention neutre en affaiblit le sens."},"categorie":"piege-sens"},{"id":"anatheme","mot":"anathème","nature":"nom masculin","definitions":["Sentence de condamnation et d\'excommunication majeure prononcée par l\'Église contre une doctrine ou une personne jugée hérétique.","Par extension, malédiction ou réprobation solennelle et publique."],"phonetique":"/a.na.tɛm/","etymologie":"Emprunté au latin ecclésiastique anathema, lui-même issu du grec ancien ἀνάθεμα (anáthema), « objet voué (à la divinité, puis à la malédiction) », dérivé de ἀνατίθημι, « placer en haut, dédier ».","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["malédiction","condamnation","excommunication","réprobation"],"antonymes":["bénédiction","absolution","louange"],"exemplesCorrects":["Le concile lança l\'anathème contre les partisans de l\'hérésie.","La presse jeta l\'anathème sur ce ministre soupçonné de corruption.","Prononcer l\'anathème, c\'était autrefois retrancher solennellement un fidèle de la communauté."],"exemplesIncorrects":["Il a reçu un anathème de la mairie pour le féliciter de son dévouement.","Elle lui adressa un tendre anathème en guise de remerciement."],"distracteurs":["oukase","réquisitoire","philippique"],"anecdote":"Dans le rite catholique ancien, l\'anathème était la forme la plus solennelle de l\'excommunication ; la formule « anathema sit » (« qu\'il soit anathème ») concluait les canons des conciles.","categorie":"mot-rare"},{"id":"jeremiade","mot":"jérémiade","nature":"nom féminin","definitions":["Plainte continuelle, lamentation interminable et lassante.","Récrimination importune sur ses propres maux, souvent au pluriel."],"phonetique":"/ʒe.ʁe.mjad/","etymologie":"Dérivé du nom propre Jérémie, prophète biblique auteur des Lamentations, avec le suffixe -ade ; le mot évoque par allusion ces longues déplorations.","registre":"courant","niveau":3,"themes":["emotions","quotidien"],"synonymes":["lamentation","plainte","récrimination","doléance"],"antonymes":["félicitation","réjouissance","louange"],"exemplesCorrects":["Épargne-moi tes jérémiades et viens m\'aider à ranger.","Ses éternelles jérémiades sur le temps finissaient par agacer tout le monde.","Au lieu de se lancer dans une jérémiade, il proposa enfin une solution."],"exemplesIncorrects":["Sa jérémiade enthousiaste a galvanisé toute l\'assemblée.","Nous avons éclaté de rire devant cette joyeuse jérémiade de vacances."],"distracteurs":["philippique","panégyrique","tirade"],"anecdote":"Le mot vient du prophète Jérémie, à qui la tradition attribue le livre biblique des Lamentations, suite de plaintes sur la ruine de Jérusalem ; d\'où l\'idée d\'une déploration sans fin.","categorie":"mot-rare"},{"id":"mievre","mot":"mièvre","nature":"adjectif","definitions":["D\'une grâce délicate mais fade, affectée et dépourvue de naturel.","Qui manque de force et de vigueur, d\'une douceur insipide et édulcorée."],"phonetique":"/mjɛvʁ/","etymologie":"D\'origine discutée, probablement issu d\'un ancien français esmievre, lui-même d\'une racine germanique ; le sens a évolué de « vif, espiègle » vers « affecté, fade ».","registre":"soutenu","niveau":3,"themes":["abstrait","litteraire"],"synonymes":["fade","affecté","doucereux","édulcoré"],"antonymes":["vigoureux","robuste","âpre","puissant"],"exemplesCorrects":["Ce poème d\'amour, trop mièvre, sombrait dans la guimauve.","Elle détestait les comédies romantiques mièvres et prévisibles.","Un décor aux teintes pastel d\'une douceur presque mièvre."],"exemplesIncorrects":["Sa charge mièvre et brutale a renversé toute la ligne adverse.","Ce réquisitoire mièvre a frappé l\'auditoire par sa violence."],"distracteurs":["austère","grandiloquent","fruste"],"anecdote":"Avant de signifier « fade et affecté », mièvre a longtemps voulu dire « vif, espiègle, malicieux » : un enfant mièvre était autrefois un enfant remuant et éveillé.","categorie":"mot-rare"},{"id":"suave","mot":"suave","nature":"adjectif","definitions":["D\'une douceur délicieuse qui flatte les sens, en particulier l\'odorat ou le goût.","Dont la grâce et la douceur charment ; agréable et harmonieux."],"phonetique":"/sɥav/","etymologie":"Emprunté au latin suavis, « doux, agréable, qui plaît aux sens », apparenté à suadere (« conseiller, persuader ») et de même racine que l\'anglais sweet.","registre":"soutenu","niveau":2,"themes":["emotions","litteraire"],"synonymes":["doux","délicieux","exquis","onctueux"],"antonymes":["âcre","âpre","rêche","amer"],"exemplesCorrects":["Un parfum suave de jasmin embaumait toute la terrasse.","Sa voix suave berçait l\'auditoire comme une caresse.","Le vin laissait en bouche une rondeur suave et veloutée."],"exemplesIncorrects":["Cette fumée suave d\'essence brûlée nous prit à la gorge.","Le vinaigre, d\'une suavité mordante, fit grimacer tous les convives."],"distracteurs":["capiteux","âcre","vif"],"anecdote":"Suave et l\'anglais sweet remontent à une même racine indo-européenne *swād-, « doux » ; le latin suavis a aussi donné « persuader », littéralement « rendre les choses douces » à l\'esprit de l\'autre.","categorie":"mot-rare"},{"id":"liminal","mot":"liminal","nature":"adjectif","definitions":["Relatif au seuil, à la limite ; qui marque un passage entre deux états ou deux espaces.","En psychologie, qui se situe au seuil de la perception, à peine perceptible."],"phonetique":"/li.mi.nal/","etymologie":"Emprunté au latin liminalis, dérivé de limen, liminis (« seuil, entrée »), avec le suffixe -alis.","registre":"soutenu","niveau":4,"themes":["abstrait","litteraire"],"synonymes":["liminaire","transitionnel","frontalier"],"antonymes":["central","stable","établi"],"exemplesCorrects":["L\'aube est un moment liminal, ni tout à fait nuit ni tout à fait jour.","Les rites de passage explorent cet état liminal entre deux identités.","Un couloir vide, baigné d\'une lumière liminale, donnait une impression d\'entre-deux."],"exemplesIncorrects":["Le cœur liminal de la cité concentre tous les commerces et les administrations.","Cette institution liminale, fondée il y a deux siècles, est parfaitement stable."],"distracteurs":["central","périphérique","primordial"],"anecdote":"Le mot français existe bien avant sa mode contemporaine : on l\'écrit liminal, avec un seul l, dérivé du latin limen, « seuil » ; à ne pas calquer servilement sur l\'anglais liminal space.","categorie":"piege-orthographe","piege":{"formeFautive":"limminal","explication":"« Liminal » s\'écrit avec un seul m et un seul l initial : il vient du latin limen (« seuil »). On voit parfois la graphie fautive « limminal » par confusion phonétique ; aucun redoublement n\'est justifié."}},{"id":"atavique","mot":"atavique","nature":"adjectif","definitions":["Qui relève de l\'atavisme ; hérité d\'ancêtres lointains après être resté latent plusieurs générations.","Par extension, profondément enraciné, ancestral, comme transmis par le sang."],"phonetique":"/a.ta.vik/","etymologie":"Dérivé de atavisme, lui-même formé sur le latin atavus, « aïeul lointain, ancêtre éloigné », avec le suffixe -ique.","registre":"soutenu","niveau":4,"themes":["abstrait","nature"],"synonymes":["ancestral","héréditaire","ataval"],"antonymes":["acquis","récent","novateur"],"exemplesCorrects":["Une méfiance atavique des étrangers se transmettait dans cette vallée isolée.","Ce trait atavique réapparut chez l\'enfant après avoir sauté plusieurs générations.","Il éprouvait une peur atavique de l\'obscurité, héritée de temps immémoriaux."],"exemplesIncorrects":["Il a contracté une grippe atavique lors de son voyage à l\'étranger.","Cette mode atavique vient tout juste d\'apparaître cette saison."],"distracteurs":["congénital","endémique","viscéral"],"anecdote":"On dit souvent « un caractère ataviste » pour désigner un trait hérité des ancêtres : c\'est un glissement fautif. L\'adjectif courant est « atavique » ; « ataviste » est rare et désigne plutôt ce qui se rapporte à la doctrine de l\'atavisme.","categorie":"piege-orthographe","piege":{"formeFautive":"ataviste","explication":"Pour qualifier un trait « hérité d\'ancêtres lointains », l\'adjectif est « atavique » (de atavisme). La forme « ataviste » est rare et renvoie à la doctrine/au partisan de l\'atavisme, non au caractère hérité : on écrit donc « une peur atavique », pas « une peur ataviste »."}},{"id":"prevenance","mot":"prévenance","nature":"nom féminin","definitions":["Disposition à aller au-devant des désirs d\'autrui par délicatesse et bienveillance.","Au pluriel, attentions délicates et gestes attentionnés témoignés à quelqu\'un."],"phonetique":"/pʁev.nɑ̃s/","etymologie":"Dérivé du verbe prévenir au sens de « devancer, aller au-devant de », du latin praevenire (prae-, « devant » + venire, « venir »), avec le suffixe -ance.","registre":"soutenu","niveau":3,"themes":["emotions","quotidien"],"synonymes":["attention","égards","délicatesse","sollicitude"],"antonymes":["négligence","indifférence","désinvolture","rudesse"],"exemplesCorrects":["Il l\'entoura de mille prévenances pendant toute sa convalescence.","Sa prévenance naturelle la poussait à anticiper les besoins de ses invités.","On apprécie chez lui une prévenance discrète, jamais envahissante."],"exemplesIncorrects":["Sa prévenance brutale a blessé tous les convives présents.","Par pure prévenance, il claqua la porte au nez du visiteur."],"distracteurs":["clairvoyance","bienséance","déférence"],"anecdote":"La prévenance tient son sens à l\'idée de « prévenir » au sens ancien de devancer : être prévenant, c\'est aller au-devant du désir de l\'autre avant même qu\'il ne soit exprimé.","categorie":"mot-rare"}]')},57649,e=>{"use strict";let i=e.i(98455).default,r=new Map(i.map(e=>[e.id,e]));e.s(["CORPUS",0,i,"getMotById",0,function(e){return r.get(e)}])}]);